-- Portal Authority
-- Settings panel registration and controls.

PortalAuthority = PortalAuthority or {}

if PortalAuthority.IsSettingsBaselineGateEnabled and PortalAuthority:IsSettingsBaselineGateEnabled() then
    return
end

if not Settings or not Settings.RegisterCanvasLayoutCategory then
    return
end

local settingsEagerBuildGateEnabled = PortalAuthority.IsSettingsEagerBuildGateEnabled and PortalAuthority:IsSettingsEagerBuildGateEnabled() or false
local settingsWindowHostGateEnabled = PortalAuthority.IsSettingsWindowHostEnabled and PortalAuthority:IsSettingsWindowHostEnabled() or false

local DEBUG_SETTINGS = false
local DEBUG_OPTIONS = false
local SHARED_RESET_ANCHOR_SHIFT_X = 10 -- single knob: moves Timers + Combat Alerts Reset Anchor buttons together (horizontal)
local SHARED_RESET_ANCHOR_SHIFT_Y = -7 -- single knob: moves Timers + Combat Alerts Reset Anchor buttons together (vertical; positive goes up)
local createCanonicalDockFontSizeStepperControl = nil
local function debugSettingsLog(...)
    if not DEBUG_SETTINGS then
        return
    end
    local prefix = "[PortalAuthority:Options]"
    if PortalAuthority and PortalAuthority.DebugPrint then
        PortalAuthority:DebugPrint(prefix, ...)
    else
        print(prefix, ...)
    end
end

local function debugOptionsLog(...)
    if not DEBUG_OPTIONS then
        return
    end
    local prefix = "[PortalAuthority:Options:Modules]"
    if PortalAuthority and PortalAuthority.DebugPrint then
        PortalAuthority:DebugPrint(prefix, ...)
    else
        print(prefix, ...)
    end
end

local function trim(text)
    if type(text) ~= "string" then
        return ""
    end
    local cleaned = text:gsub("^%s+", ""):gsub("%s+$", "")
    return cleaned
end

local function rgba255(r, g, b, a)
    return (tonumber(r) or 255) / 255,
        (tonumber(g) or 255) / 255,
        (tonumber(b) or 255) / 255,
        a == nil and 1 or math.max(0, math.min(1, tonumber(a) or 1))
end

local FLAT_SETTINGS_BACKDROP = {
    bgFile = "Interface\\Buttons\\WHITE8x8",
    edgeFile = "Interface\\Buttons\\WHITE8x8",
    edgeSize = 1,
    insets = { left = 0, right = 0, top = 0, bottom = 0 },
}

local SETTINGS_WINDOW_HOSTED_TOP_RHYTHM_NUDGE = 6
local SETTINGS_WINDOW_SCROLLBAR_WIDTH = 8
local SETTINGS_WINDOW_SCROLLBAR_GAP = 10
local SETTINGS_WINDOW_SCROLLBAR_MIN_THUMB_HEIGHT = 24
local SETTINGS_WINDOW_HOST_COLORS = {
    idleBg = { rgba255(26, 28, 36, 0.95) },
    idleBorder = { rgba255(61, 69, 82, 1.0) },
    idleText = { rgba255(200, 200, 210, 1.0) },
    hoverBg = { rgba255(34, 37, 46, 0.97) },
    hoverBorder = { rgba255(88, 98, 112, 1.0) },
    hoverText = { rgba255(222, 224, 230, 1.0) },
    onBg = { rgba255(18, 48, 52, 0.96) },
    onBorder = { rgba255(40, 130, 120, 0.80) },
    onText = { rgba255(170, 240, 230, 1.0) },
    offBg = { rgba255(48, 14, 30, 0.93) },
    offBorder = { rgba255(60, 16, 35, 1.0) },
    offText = { rgba255(220, 185, 200, 1.0) },
    disabledBg = { rgba255(44, 46, 54, 0.92) },
    disabledBorder = { rgba255(86, 92, 102, 0.88) },
    disabledText = { rgba255(150, 154, 164, 0.96) },
    statusGoodBorder = { rgba255(40, 130, 120, 0.90) },
    statusGoodText = { rgba255(170, 240, 230, 1.0) },
}
local SETTINGS_WINDOW_SCROLLBAR_TRACK = { rgba255(10, 10, 18, 1.0) }
local SETTINGS_WINDOW_SCROLLBAR_THUMB = { rgba255(42, 42, 58, 0.5) }
local SETTINGS_WINDOW_SCROLLBAR_THUMB_HOVER = { rgba255(58, 58, 72, 0.6) }

local function unpackColor(color)
    if type(color) ~= "table" then
        return 1, 1, 1, 1
    end
    return color[1] or 1, color[2] or 1, color[3] or 1, color[4] or 1
end

local function frameIsAlive(frame)
    return frame ~= nil and type(frame.GetObjectType) == "function"
end

local function isDescendedFromFrame(frame, ancestor)
    if not frame or not ancestor then
        return false
    end
    local current = frame
    while current do
        if current == ancestor then
            return true
        end
        current = current.GetParent and current:GetParent() or nil
    end
    return false
end

local function markSettingsWindowVisualOptIn(frame)
    if frameIsAlive(frame) then
        frame._paSettingsWindowVisualStyleOptIn = true
    end
    return frame
end

local function isSettingsWindowVisualOptedIn(frame)
    local current = frame
    while current do
        if current._paSettingsWindowVisualStyleOptIn == true then
            return true
        end
        current = current.GetParent and current:GetParent() or nil
    end
    return false
end

local function isUsingCustomSettingsWindowVisualStyle(frame)
    if not frameIsAlive(frame) or not PortalAuthority or not PortalAuthority.IsSettingsWindowHostEnabled then
        return false
    end
    if not PortalAuthority:IsSettingsWindowHostEnabled() then
        return false
    end
    if not isSettingsWindowVisualOptedIn(frame) then
        return false
    end

    local runtime = PortalAuthority._settingsWindowRuntime
    local window = runtime and runtime.window or nil
    if frameIsAlive(window) and isDescendedFromFrame(frame, window) then
        return true
    end

    local current = frame
    while current do
        if current._paHostedBySettingsWindow == true then
            return true
        end
        current = current.GetParent and current:GetParent() or nil
    end

    return false
end

local function registerSettingsWindowVisualRefresh(frame, callback)
    if frameIsAlive(frame) and type(callback) == "function" then
        frame._paSettingsWindowVisualRefresh = callback
    end
end

local function setTextureSolidColor(texture, color)
    if not texture then
        return
    end
    local r, g, b, a = unpackColor(color)
    if texture.SetColorTexture then
        texture:SetColorTexture(r, g, b, a)
    elseif texture.SetVertexColor then
        texture:SetVertexColor(r, g, b, a)
    end
end

local function hideDefaultScrollBarPart(part, scrollFrame)
    if not part then
        return
    end
    if part.SetAlpha then
        part:SetAlpha(0)
    end
    if part.Hide then
        part:Hide()
    end
    if part.EnableMouse then
        part:EnableMouse(false)
    end
    if part.SetSize then
        part:SetSize(1, 1)
    elseif part.SetWidth and part.SetHeight then
        part:SetWidth(1)
        part:SetHeight(1)
    end
    if part.HookScript and not part._paSettingsWindowHideHook then
        part._paSettingsWindowHideHook = true
        part:HookScript("OnShow", function(selfPart)
            if isUsingCustomSettingsWindowVisualStyle(scrollFrame) then
                if selfPart.SetAlpha then
                    selfPart:SetAlpha(0)
                end
                if selfPart.Hide then
                    selfPart:Hide()
                end
            end
        end)
    end
end

local function getTemplateScrollBar(scrollFrame)
    if not frameIsAlive(scrollFrame) then
        return nil
    end
    if frameIsAlive(scrollFrame.ScrollBar) then
        return scrollFrame.ScrollBar
    end
    local frameName = scrollFrame.GetName and scrollFrame:GetName() or nil
    if frameName and _G then
        local named = _G[frameName .. "ScrollBar"]
        if frameIsAlive(named) then
            return named
        end
    end
    return nil
end

local function hideDefaultScrollBarChrome(scrollFrame)
    local scrollBar = getTemplateScrollBar(scrollFrame)
    if not frameIsAlive(scrollBar) then
        return nil
    end

    if scrollBar.SetAlpha then
        scrollBar:SetAlpha(0)
    end
    if scrollBar.Hide then
        scrollBar:Hide()
    end
    if scrollBar.EnableMouse then
        scrollBar:EnableMouse(false)
    end
    scrollBar:ClearAllPoints()
    scrollBar:SetPoint("TOPLEFT", scrollFrame, "TOPRIGHT", SETTINGS_WINDOW_SCROLLBAR_GAP, 0)
    scrollBar:SetPoint("BOTTOMLEFT", scrollFrame, "BOTTOMRIGHT", SETTINGS_WINDOW_SCROLLBAR_GAP, 0)
    scrollBar:SetWidth(SETTINGS_WINDOW_SCROLLBAR_WIDTH)

    if scrollBar.GetRegions then
        for i = 1, select("#", scrollBar:GetRegions()) do
            local region = select(i, scrollBar:GetRegions())
            if region then
                if region.SetTexture then
                    region:SetTexture(nil)
                end
                if region.SetAlpha then
                    region:SetAlpha(0)
                end
                if region.Hide then
                    region:Hide()
                end
            end
        end
    end

    if scrollBar.GetChildren then
        for i = 1, select("#", scrollBar:GetChildren()) do
            hideDefaultScrollBarPart(select(i, scrollBar:GetChildren()), scrollFrame)
        end
    end

    hideDefaultScrollBarPart(scrollBar.ScrollUpButton, scrollFrame)
    hideDefaultScrollBarPart(scrollBar.ScrollDownButton, scrollFrame)
    hideDefaultScrollBarPart(scrollBar.UpButton, scrollFrame)
    hideDefaultScrollBarPart(scrollBar.DownButton, scrollFrame)

    return scrollBar
end

local function refreshCustomSettingsScrollBarThumb(customBar)
    if not frameIsAlive(customBar) then
        return
    end
    local thumb = customBar._paThumb
    if not thumb then
        return
    end

    local color = customBar._paHovered and SETTINGS_WINDOW_SCROLLBAR_THUMB_HOVER or SETTINGS_WINDOW_SCROLLBAR_THUMB
    local r, g, b, a = unpackColor(color)
    local visibility = tonumber(customBar._paVisibilityMultiplier)
    if visibility == nil then
        visibility = 0
    end
    if visibility < 0 then
        visibility = 0
    elseif visibility > 1 then
        visibility = 1
    end
    a = a * visibility
    if thumb.SetColorTexture then
        thumb:SetColorTexture(r, g, b, a)
    elseif thumb.SetVertexColor then
        thumb:SetVertexColor(r, g, b, a)
    end
end

PortalAuthority._settingsScrollRuntime = PortalAuthority._settingsScrollRuntime or {}
local settingsScrollRuntime = PortalAuthority._settingsScrollRuntime
local ACTIVE_PORTAL_PICKER

settingsScrollRuntime.numbersDiffer = function(a, b)
    a = tonumber(a)
    b = tonumber(b)
    if a == nil or b == nil then
        return a ~= b
    end
    return math.abs(a - b) > 0.5
end

settingsScrollRuntime.fadeDelaySeconds = 1.5
settingsScrollRuntime.fadeDurationSeconds = 0.4

settingsScrollRuntime.getAdapter = function(scrollFrame, scrollChild, viewportHeight, contentHeight)
    local adapter = scrollFrame and scrollFrame._paCustomScrollAdapter or nil
    local resolved = {}

    resolved.panelId = type(adapter) == "table" and adapter.panelId or "settings"

    if type(adapter) == "table" and type(adapter.resolveCanonicalMax) == "function" then
        resolved.resolveCanonicalMax = adapter.resolveCanonicalMax
    else
        resolved.resolveCanonicalMax = function()
            return math.max(0, (tonumber(contentHeight) or 0) - (tonumber(viewportHeight) or 0)), "derived"
        end
    end

    if type(adapter) == "table" and type(adapter.getCurrentValue) == "function" then
        resolved.getCurrentValue = adapter.getCurrentValue
    else
        resolved.getCurrentValue = function()
            if not scrollFrame or type(scrollFrame.GetVerticalScroll) ~= "function" then
                return 0
            end
            return math.max(0, tonumber(scrollFrame:GetVerticalScroll()) or 0)
        end
    end

    if type(adapter) == "table" and type(adapter.applyValue) == "function" then
        resolved.applyValue = adapter.applyValue
    else
        resolved.applyValue = function(value)
            if not scrollFrame or type(scrollFrame.SetVerticalScroll) ~= "function" then
                return false
            end
            scrollFrame._paSkipNextCustomScrollBarHookSync = true
            scrollFrame:SetVerticalScroll(math.max(0, tonumber(value) or 0))
            return true
        end
    end

    return resolved
end

settingsScrollRuntime.canReveal = function(customBar)
    if not frameIsAlive(customBar) then
        return false
    end
    if not customBar.IsShown or not customBar:IsShown() then
        return false
    end
    local maxScroll = math.max(
        tonumber(customBar._paBoundMax) or 0,
        tonumber(customBar._paRenderedMaxScroll) or 0
    )
    return maxScroll > 0
end

settingsScrollRuntime.stopFadeTween = function(customBar)
    if not frameIsAlive(customBar) then
        return
    end
    local fadeDriver = customBar._paFadeDriver
    if frameIsAlive(fadeDriver) and fadeDriver.GetScript and fadeDriver:GetScript("OnUpdate") ~= nil then
        fadeDriver:SetScript("OnUpdate", nil)
    end
    customBar._paFadeTweenActive = nil
end

settingsScrollRuntime.cancelFade = function(customBar)
    if not frameIsAlive(customBar) then
        return
    end
    customBar._paFadeToken = (tonumber(customBar._paFadeToken) or 0) + 1
    settingsScrollRuntime.stopFadeTween(customBar)
end

settingsScrollRuntime.setThumbVisibility = function(customBar, alpha)
    if not frameIsAlive(customBar) then
        return
    end
    alpha = tonumber(alpha) or 0
    if alpha < 0 then
        alpha = 0
    elseif alpha > 1 then
        alpha = 1
    end
    customBar._paVisibilityMultiplier = alpha

    local thumbButton = customBar._paThumbButton
    if frameIsAlive(thumbButton) and thumbButton.EnableMouse then
        thumbButton:EnableMouse(customBar._paDragging == true or alpha > 0.01)
    end

    refreshCustomSettingsScrollBarThumb(customBar)
end

settingsScrollRuntime.hideImmediately = function(customBar)
    if not frameIsAlive(customBar) then
        return
    end
    settingsScrollRuntime.cancelFade(customBar)
    settingsScrollRuntime.setThumbVisibility(customBar, 0)
end

settingsScrollRuntime.beginFade = function(customBar, token)
    if not frameIsAlive(customBar) then
        return
    end
    if customBar._paDragging == true or customBar._paThumbHovered == true or customBar._paTrackHovered == true then
        return
    end
    if not settingsScrollRuntime.canReveal(customBar) then
        settingsScrollRuntime.setThumbVisibility(customBar, 0)
        return
    end

    local fadeDriver = customBar._paFadeDriver
    if not frameIsAlive(fadeDriver) then
        settingsScrollRuntime.setThumbVisibility(customBar, 0)
        return
    end

    local startAlpha = tonumber(customBar._paVisibilityMultiplier)
    if startAlpha == nil then
        startAlpha = 0
    end
    if startAlpha <= 0 then
        settingsScrollRuntime.setThumbVisibility(customBar, 0)
        return
    end

    settingsScrollRuntime.stopFadeTween(customBar)
    customBar._paFadeTweenActive = true
    local elapsedTime = 0
    fadeDriver:SetScript("OnUpdate", function(_, elapsed)
        if not frameIsAlive(customBar) then
            return
        end
        if customBar._paFadeToken ~= token then
            settingsScrollRuntime.stopFadeTween(customBar)
            return
        end
        if customBar._paDragging == true or customBar._paThumbHovered == true or customBar._paTrackHovered == true then
            settingsScrollRuntime.stopFadeTween(customBar)
            settingsScrollRuntime.setThumbVisibility(customBar, 1)
            return
        end
        if not settingsScrollRuntime.canReveal(customBar) then
            settingsScrollRuntime.stopFadeTween(customBar)
            settingsScrollRuntime.setThumbVisibility(customBar, 0)
            return
        end

        elapsedTime = elapsedTime + (tonumber(elapsed) or 0)
        local duration = settingsScrollRuntime.fadeDurationSeconds
        local progress = duration > 0 and math.max(0, math.min(1, elapsedTime / duration)) or 1
        settingsScrollRuntime.setThumbVisibility(customBar, startAlpha * (1 - progress))
        if progress >= 1 then
            settingsScrollRuntime.stopFadeTween(customBar)
            settingsScrollRuntime.setThumbVisibility(customBar, 0)
        end
    end)
end

settingsScrollRuntime.armFade = function(customBar)
    if not frameIsAlive(customBar) then
        return
    end
    if customBar._paDragging == true or customBar._paThumbHovered == true or customBar._paTrackHovered == true then
        return
    end
    if not settingsScrollRuntime.canReveal(customBar) then
        settingsScrollRuntime.hideImmediately(customBar)
        return
    end

    settingsScrollRuntime.cancelFade(customBar)
    local token = tonumber(customBar._paFadeToken) or 0
    if not (C_Timer and C_Timer.After) then
        settingsScrollRuntime.beginFade(customBar, token)
        return
    end

    C_Timer.After(settingsScrollRuntime.fadeDelaySeconds, function()
        if not frameIsAlive(customBar) then
            return
        end
        if customBar._paFadeToken ~= token then
            return
        end
        settingsScrollRuntime.beginFade(customBar, token)
    end)
end

settingsScrollRuntime.showThumb = function(customBar)
    if not frameIsAlive(customBar) then
        return
    end
    settingsScrollRuntime.cancelFade(customBar)
    if not settingsScrollRuntime.canReveal(customBar) then
        settingsScrollRuntime.setThumbVisibility(customBar, 0)
        return
    end
    settingsScrollRuntime.setThumbVisibility(customBar, 1)
end

settingsScrollRuntime.noteInteraction = function(customBar)
    if not frameIsAlive(customBar) then
        return
    end
    settingsScrollRuntime.showThumb(customBar)
    if customBar._paDragging ~= true
        and customBar._paThumbHovered ~= true
        and customBar._paTrackHovered ~= true then
        settingsScrollRuntime.armFade(customBar)
    end
end

settingsScrollRuntime.noteFrameInteraction = function(scrollFrame)
    if not frameIsAlive(scrollFrame) then
        return
    end
    local customBar = scrollFrame._paCustomScrollBar
    if not frameIsAlive(customBar) then
        return
    end
    settingsScrollRuntime.noteInteraction(customBar)
end

local function isPointerInsideActivePickerSafeZone()
    if type(MouseIsOver) ~= "function" then
        return false
    end

    local picker = ACTIVE_PORTAL_PICKER
    if not frameIsAlive(picker) or not picker.IsShown or not picker:IsShown() then
        return false
    end

    local function isPointerInside(frame)
        if not frameIsAlive(frame) or not frame.IsShown or not frame:IsShown() then
            return false
        end
        return MouseIsOver(frame) and true or false
    end

    if isPointerInside(picker) then
        return true
    end

    for _, frame in ipairs({
        picker.scroll,
        picker.search,
        picker.clearButton,
        picker.closeButton,
    }) do
        if isPointerInside(frame) then
            return true
        end
    end

    return false
end

settingsScrollRuntime.closeFloatingControlsForParentScroll = function(scrollFrame)
    if not frameIsAlive(scrollFrame) or scrollFrame._paCloseFloatingControlsOnUserScroll ~= true then
        return false
    end

    if isPointerInsideActivePickerSafeZone() then
        return true
    end

    local panel = scrollFrame._paCloseFloatingControlsPanel
        or scrollFrame._paSearchPanel
        or scrollFrame._paOwnerPanel
        or nil

    if ACTIVE_PORTAL_PICKER
        and ACTIVE_PORTAL_PICKER.IsShown
        and ACTIVE_PORTAL_PICKER:IsShown()
        and ACTIVE_PORTAL_PICKER.Close
    then
        ACTIVE_PORTAL_PICKER:Close()
    end

    if type(CloseDropDownMenus) == "function" then
        CloseDropDownMenus()
    end

    if panel and type(panel._paCloseFloatingControlsOnScroll) == "function" then
        panel._paCloseFloatingControlsOnScroll(panel)
    end

    return false
end

settingsScrollRuntime.suppressHoverRevealForCurrentFrame = function(customBar)
    if not frameIsAlive(customBar) then
        return
    end
    customBar._paHoverRevealSuppressed = true
    local token = (tonumber(customBar._paHoverRevealToken) or 0) + 1
    customBar._paHoverRevealToken = token
    if C_Timer and C_Timer.After then
        C_Timer.After(0, function()
            if not frameIsAlive(customBar) then
                return
            end
            if customBar._paHoverRevealToken ~= token then
                return
            end
            customBar._paHoverRevealSuppressed = nil
        end)
    else
        customBar._paHoverRevealSuppressed = nil
    end
end

settingsScrollRuntime.clearDrag = function(customBar)
    if not frameIsAlive(customBar) then
        return
    end

    customBar._paDragSession = nil
    customBar._paDragging = nil
    if customBar.GetScript and customBar:GetScript("OnUpdate") ~= nil then
        customBar:SetScript("OnUpdate", nil)
    end
    customBar._paHovered = customBar._paThumbHovered == true or customBar._paTrackHovered == true
    refreshCustomSettingsScrollBarThumb(customBar)
    if customBar._paHovered == true then
        settingsScrollRuntime.showThumb(customBar)
    else
        settingsScrollRuntime.armFade(customBar)
    end
end

settingsScrollRuntime.setHover = function(customBar, key, isHovered)
    if not frameIsAlive(customBar) then
        return
    end

    if key == "thumb" then
        customBar._paThumbHovered = isHovered and true or nil
    else
        customBar._paTrackHovered = isHovered and true or nil
    end
    customBar._paHovered = customBar._paDragging == true
        or customBar._paThumbHovered == true
        or customBar._paTrackHovered == true
    refreshCustomSettingsScrollBarThumb(customBar)

    if customBar._paHovered == true then
        if settingsScrollRuntime.canReveal(customBar) then
            settingsScrollRuntime.cancelFade(customBar)
            if customBar._paHoverRevealSuppressed ~= true
                or (tonumber(customBar._paVisibilityMultiplier) or 0) > 0 then
                settingsScrollRuntime.setThumbVisibility(customBar, 1)
            end
        end
    elseif customBar._paDragging ~= true then
        settingsScrollRuntime.armFade(customBar)
    end
end

settingsScrollRuntime.layoutThumb = function(customBar, viewportHeight, contentHeight, maxScroll, currentValue)
    if not frameIsAlive(customBar) then
        return
    end

    local thumb = customBar._paThumb
    local thumbButton = customBar._paThumbButton
    if not thumb or not frameIsAlive(thumbButton) then
        return
    end

    local barHeight = math.max(
        tonumber(customBar:GetHeight()) or 0,
        tonumber(viewportHeight) or 0,
        SETTINGS_WINDOW_SCROLLBAR_MIN_THUMB_HEIGHT
    )
    local ratio = (tonumber(contentHeight) or 0) > 0
            and math.max(0, math.min(1, (tonumber(viewportHeight) or 0) / math.max(tonumber(contentHeight) or 1, 1)))
        or 1
    local thumbHeight = math.max(SETTINGS_WINDOW_SCROLLBAR_MIN_THUMB_HEIGHT, math.floor(barHeight * ratio))
    local maxThumbHeight = math.max(1, math.floor(barHeight * 0.60))
    thumbHeight = math.min(barHeight, thumbHeight, maxThumbHeight)

    local clampedMax = math.max(0, tonumber(maxScroll) or 0)
    local clampedValue = math.max(0, math.min(clampedMax, tonumber(currentValue) or 0))
    local usableTravel = math.max(0, barHeight - thumbHeight)
    local pct = clampedMax > 0 and math.max(0, math.min(1, clampedValue / clampedMax)) or 0
    local topOffset = usableTravel * pct
    local roundedOffset = math.floor(topOffset + 0.5)

    if thumb.SetHeight then
        thumb:SetHeight(thumbHeight)
    end
    if thumb.SetWidth then
        thumb:SetWidth(SETTINGS_WINDOW_SCROLLBAR_WIDTH)
    end
    thumb:ClearAllPoints()
    thumb:SetPoint("TOPLEFT", customBar, "TOPLEFT", 0, -roundedOffset)
    thumb:SetPoint("TOPRIGHT", customBar, "TOPRIGHT", 0, -roundedOffset)

    thumbButton:ClearAllPoints()
    thumbButton:SetPoint("TOPLEFT", customBar, "TOPLEFT", 0, -roundedOffset)
    thumbButton:SetSize(SETTINGS_WINDOW_SCROLLBAR_WIDTH, thumbHeight)

    local trackTop = tonumber(customBar.GetTop and customBar:GetTop()) or 0
    local trackBottom = tonumber(customBar.GetBottom and customBar:GetBottom()) or 0
    if settingsScrollRuntime.numbersDiffer(customBar._paGeometryTrackTop, trackTop)
        or settingsScrollRuntime.numbersDiffer(customBar._paGeometryTrackBottom, trackBottom)
        or settingsScrollRuntime.numbersDiffer(customBar._paThumbHeight, thumbHeight)
        or settingsScrollRuntime.numbersDiffer(customBar._paUsableThumbTravel, usableTravel)
        or settingsScrollRuntime.numbersDiffer(customBar._paRenderedMaxScroll, clampedMax) then
        customBar._paGeometryRevision = (tonumber(customBar._paGeometryRevision) or 0) + 1
    end

    customBar._paGeometryTrackTop = trackTop
    customBar._paGeometryTrackBottom = trackBottom
    customBar._paThumbHeight = thumbHeight
    customBar._paUsableThumbTravel = usableTravel
    customBar._paRenderedMaxScroll = clampedMax
    customBar._paRenderedScrollValue = clampedValue
end

settingsScrollRuntime.applyValue = function(customBar, requestedValue, options)
    if not frameIsAlive(customBar) then
        return false
    end

    local scrollFrame = customBar._paOwnerScrollFrame
    if not frameIsAlive(scrollFrame) then
        return false
    end

    local scrollChild = customBar._paOwnerScrollChild
        or (scrollFrame.GetScrollChild and scrollFrame:GetScrollChild())
    local viewportHeight = tonumber(scrollFrame.GetHeight and scrollFrame:GetHeight()) or 0
    local contentHeight = scrollChild and (tonumber(scrollChild.GetHeight and scrollChild:GetHeight()) or 0) or 0
    local adapter = settingsScrollRuntime.getAdapter(scrollFrame, scrollChild, viewportHeight, contentHeight)
    local maxScroll = adapter.resolveCanonicalMax(options, scrollFrame, scrollChild, viewportHeight, contentHeight)
    if type(maxScroll) ~= "number" then
        return false
    end
    maxScroll = math.max(0, maxScroll)
    local currentValue = math.max(0, tonumber(adapter.getCurrentValue(options, scrollFrame, scrollChild, viewportHeight, contentHeight)) or 0)
    local clampedValue = math.max(0, math.min(maxScroll, tonumber(requestedValue) or currentValue))
    if adapter.applyValue(clampedValue, options, scrollFrame, scrollChild, viewportHeight, contentHeight) == false then
        return false
    end

    settingsScrollRuntime.sync(
        scrollFrame,
        scrollChild,
        tonumber(scrollFrame.GetHeight and scrollFrame:GetHeight()) or viewportHeight,
        scrollChild and (tonumber(scrollChild.GetHeight and scrollChild:GetHeight()) or contentHeight) or contentHeight
    )
    return true, clampedValue, maxScroll
end

settingsScrollRuntime.beginThumbDrag = function(customBar)
    if not frameIsAlive(customBar) then
        return
    end

    if settingsScrollRuntime.closeFloatingControlsForParentScroll(customBar._paOwnerScrollFrame) then
        return
    end
    settingsScrollRuntime.clearDrag(customBar)

    local maxScroll = math.max(0, tonumber(customBar._paRenderedMaxScroll) or 0)
    local usableTravel = math.max(0, tonumber(customBar._paUsableThumbTravel) or 0)
    local thumbHeight = math.max(0, tonumber(customBar._paThumbHeight) or 0)
    if maxScroll <= 0 or usableTravel <= 0 or thumbHeight <= 0 then
        return
    end

    local track = customBar._paTrackButton
    local scale = tonumber(track and track.GetEffectiveScale and track:GetEffectiveScale()) or 0
    local trackTop = tonumber(track and track.GetTop and track:GetTop()) or nil
    local trackBottom = tonumber(track and track.GetBottom and track:GetBottom()) or nil
    local cursorY = select(2, GetCursorPosition())
    if not trackTop or not trackBottom or trackTop <= trackBottom or scale <= 0 or not cursorY then
        return
    end

    cursorY = cursorY / scale
    local currentValue = math.max(0, math.min(maxScroll, tonumber(customBar._paRenderedScrollValue) or 0))
    local currentTopOffset = usableTravel * (maxScroll > 0 and (currentValue / maxScroll) or 0)
    local thumbTop = trackTop - currentTopOffset

    customBar._paDragSession = {
        mode = "thumb-drag",
        geometryRevision = tonumber(customBar._paGeometryRevision) or 0,
        trackTop = trackTop,
        usableTravel = usableTravel,
        maxScroll = maxScroll,
        thumbHeight = thumbHeight,
        scale = scale,
        grabOffset = thumbTop - cursorY,
    }
    customBar._paDragging = true
    customBar._paHovered = true
    settingsScrollRuntime.showThumb(customBar)

    customBar:SetScript("OnUpdate", function(selfBar)
        local session = selfBar._paDragSession
        if not session then
            settingsScrollRuntime.clearDrag(selfBar)
            return
        end
        if not IsMouseButtonDown or not IsMouseButtonDown("LeftButton") then
            settingsScrollRuntime.clearDrag(selfBar)
            return
        end
        if session.geometryRevision ~= (tonumber(selfBar._paGeometryRevision) or 0) then
            settingsScrollRuntime.clearDrag(selfBar)
            return
        end

        local dragCursorY = select(2, GetCursorPosition())
        if not dragCursorY or session.scale <= 0 then
            return
        end
        dragCursorY = dragCursorY / session.scale

        local desiredThumbTop = dragCursorY + session.grabOffset
        local topOffset = session.trackTop - desiredThumbTop
        if topOffset < 0 then
            topOffset = 0
        elseif topOffset > session.usableTravel then
            topOffset = session.usableTravel
        end

        local pct = session.usableTravel > 0 and (topOffset / session.usableTravel) or 0
        local targetValue = session.maxScroll * pct
        settingsScrollRuntime.applyValue(selfBar, targetValue, {
            source = "thumb-drag",
            allowFallback = false,
            allowPostRelayoutSync = false,
        })
    end)
end

settingsScrollRuntime.handleTrackClick = function(customBar)
    if not frameIsAlive(customBar) or customBar._paDragSession ~= nil then
        return
    end

    if settingsScrollRuntime.closeFloatingControlsForParentScroll(customBar._paOwnerScrollFrame) then
        return
    end
    local maxScroll = math.max(0, tonumber(customBar._paRenderedMaxScroll) or 0)
    local usableTravel = math.max(0, tonumber(customBar._paUsableThumbTravel) or 0)
    local thumbHeight = math.max(0, tonumber(customBar._paThumbHeight) or 0)
    if maxScroll <= 0 or usableTravel <= 0 or thumbHeight <= 0 then
        return
    end

    local track = customBar._paTrackButton
    local scale = tonumber(track and track.GetEffectiveScale and track:GetEffectiveScale()) or 0
    local trackTop = tonumber(track and track.GetTop and track:GetTop()) or nil
    local cursorY = select(2, GetCursorPosition())
    if not trackTop or scale <= 0 or not cursorY then
        return
    end

    cursorY = cursorY / scale
    local topOffset = trackTop - (cursorY + (thumbHeight * 0.5))
    if topOffset < 0 then
        topOffset = 0
    elseif topOffset > usableTravel then
        topOffset = usableTravel
    end

    local pct = usableTravel > 0 and (topOffset / usableTravel) or 0
    local targetValue = maxScroll * pct
    settingsScrollRuntime.noteInteraction(customBar)
    settingsScrollRuntime.applyValue(customBar, targetValue, {
        source = "track-click",
        allowFallback = false,
        allowPostRelayoutSync = false,
    })
end

settingsScrollRuntime.sync = function(scrollFrame, scrollChild, viewportHeight, contentHeight)
    if not frameIsAlive(scrollFrame) then
        return
    end

    scrollFrame._paOwnerScrollChild = scrollChild
    local isCustomHosted = isUsingCustomSettingsWindowVisualStyle(scrollFrame)
    local customBar = scrollFrame._paCustomScrollBar
    if not isCustomHosted then
        if frameIsAlive(customBar) then
            settingsScrollRuntime.clearDrag(customBar)
            customBar:Hide()
        end
        return
    end

    local defaultScrollBar = hideDefaultScrollBarChrome(scrollFrame)
    if defaultScrollBar then
        scrollFrame.ScrollBar = defaultScrollBar
    end

    if not frameIsAlive(customBar) then
        customBar = CreateFrame("Slider", nil, scrollFrame:GetParent() or scrollFrame)
        customBar:SetOrientation("VERTICAL")
        customBar:SetThumbTexture("Interface\\Buttons\\WHITE8x8")
        customBar:SetPoint("TOPLEFT", scrollFrame, "TOPRIGHT", SETTINGS_WINDOW_SCROLLBAR_GAP, 0)
        customBar:SetPoint("BOTTOMLEFT", scrollFrame, "BOTTOMRIGHT", SETTINGS_WINDOW_SCROLLBAR_GAP, 0)
        customBar:SetWidth(SETTINGS_WINDOW_SCROLLBAR_WIDTH)
        customBar:SetMinMaxValues(0, 0)
        customBar:SetValueStep(1)
        customBar:EnableMouse(false)
        customBar._paOwnerScrollFrame = scrollFrame
        customBar._paOwnerScrollChild = scrollChild
        customBar._paVisibilityMultiplier = 0

        local track = customBar:CreateTexture(nil, "BACKGROUND")
        track:SetAllPoints()
        setTextureSolidColor(track, SETTINGS_WINDOW_SCROLLBAR_TRACK)
        customBar._paTrack = track

        local nativeThumb = customBar:GetThumbTexture()
        if nativeThumb then
            nativeThumb:SetTexture(nil)
            nativeThumb:SetAlpha(0)
            nativeThumb:Hide()
        end

        local thumb = customBar:CreateTexture(nil, "ARTWORK")
        thumb:SetTexture("Interface\\Buttons\\WHITE8x8")
        thumb:SetPoint("TOPLEFT", customBar, "TOPLEFT", 0, 0)
        thumb:SetWidth(SETTINGS_WINDOW_SCROLLBAR_WIDTH)
        customBar._paThumb = thumb

        local trackButton = CreateFrame("Button", nil, customBar)
        trackButton:SetAllPoints()
        trackButton:RegisterForClicks("LeftButtonUp")
        trackButton:EnableMouse(true)
        trackButton:SetFrameLevel((customBar:GetFrameLevel() or 0) + 1)
        customBar._paTrackButton = trackButton

        local thumbButton = CreateFrame("Button", nil, customBar)
        thumbButton:RegisterForClicks("LeftButtonDown", "LeftButtonUp")
        thumbButton:EnableMouse(false)
        thumbButton:SetFrameLevel((customBar:GetFrameLevel() or 0) + 2)
        customBar._paThumbButton = thumbButton
        customBar._paFadeDriver = trackButton

        trackButton:SetScript("OnEnter", function()
            settingsScrollRuntime.setHover(customBar, "track", true)
        end)
        trackButton:SetScript("OnLeave", function()
            settingsScrollRuntime.setHover(customBar, "track", false)
        end)
        trackButton:SetScript("OnClick", function()
            settingsScrollRuntime.handleTrackClick(customBar)
        end)

        thumbButton:SetScript("OnEnter", function()
            settingsScrollRuntime.setHover(customBar, "thumb", true)
        end)
        thumbButton:SetScript("OnLeave", function()
            settingsScrollRuntime.setHover(customBar, "thumb", false)
        end)
        thumbButton:SetScript("OnMouseDown", function(_, mouseButton)
            if mouseButton ~= "LeftButton" then
                return
            end
            settingsScrollRuntime.noteInteraction(customBar)
            settingsScrollRuntime.beginThumbDrag(customBar)
        end)
        thumbButton:SetScript("OnMouseUp", function(_, mouseButton)
            if mouseButton ~= "LeftButton" then
                return
            end
            settingsScrollRuntime.clearDrag(customBar)
        end)

        customBar:SetScript("OnValueChanged", function() end)
        customBar:SetScript("OnHide", function(selfBar)
            selfBar._paThumbHovered = nil
            selfBar._paTrackHovered = nil
            selfBar._paHoverRevealSuppressed = nil
            selfBar._paHoverRevealToken = nil
            settingsScrollRuntime.hideImmediately(selfBar)
            settingsScrollRuntime.clearDrag(selfBar)
        end)

        scrollFrame._paCustomScrollBar = customBar

        if scrollFrame.HookScript and not scrollFrame._paCustomScrollBarHooked then
            scrollFrame._paCustomScrollBarHooked = true
            scrollFrame:HookScript("OnVerticalScroll", function(selfFrame)
                if selfFrame._paSkipNextCustomScrollBarHookSync then
                    selfFrame._paSkipNextCustomScrollBarHookSync = nil
                    return
                end
                local slider = selfFrame._paCustomScrollBar
                if not frameIsAlive(slider) then
                    return
                end
                local child = slider._paOwnerScrollChild or (selfFrame.GetScrollChild and selfFrame:GetScrollChild())
                settingsScrollRuntime.sync(
                    selfFrame,
                    child,
                    tonumber(selfFrame.GetHeight and selfFrame:GetHeight()) or 0,
                    child and (tonumber(child.GetHeight and child:GetHeight()) or 0) or 0
                )
            end)
        end
    end

    customBar._paOwnerScrollChild = scrollChild
    local adapter = settingsScrollRuntime.getAdapter(scrollFrame, scrollChild, viewportHeight, contentHeight)
    local range = adapter.resolveCanonicalMax({
        source = "sync",
        allowFallback = true,
        allowPostRelayoutSync = false,
    }, scrollFrame, scrollChild, viewportHeight, contentHeight)
    range = math.max(0, tonumber(range) or 0)
    if range <= 0 or not scrollFrame.IsShown or not scrollFrame:IsShown() then
        customBar._paThumbHovered = nil
        customBar._paTrackHovered = nil
        customBar._paHoverRevealSuppressed = nil
        customBar._paHoverRevealToken = nil
        settingsScrollRuntime.clearDrag(customBar)
        settingsScrollRuntime.hideImmediately(customBar)
        customBar:Hide()
        customBar._paSyncing = true
        customBar:SetMinMaxValues(0, 0)
        customBar:SetValue(0)
        customBar._paSyncing = false
        customBar._paBoundMax = 0
        settingsScrollRuntime.layoutThumb(customBar, viewportHeight, contentHeight, 0, 0)
        return
    end

    local wasShown = customBar.IsShown and customBar:IsShown()
    customBar:SetShown(true)
    if not wasShown then
        settingsScrollRuntime.suppressHoverRevealForCurrentFrame(customBar)
        settingsScrollRuntime.setThumbVisibility(customBar, 0)
    end
    if settingsScrollRuntime.numbersDiffer(customBar._paBoundMax, range) then
        customBar:SetMinMaxValues(0, range)
        customBar._paBoundMax = range
    end
    local currentScroll = adapter.getCurrentValue({
        source = "sync",
    }, scrollFrame, scrollChild, viewportHeight, contentHeight)
    currentScroll = math.max(0, math.min(range, tonumber(currentScroll) or 0))
    customBar._paSyncing = true
    if settingsScrollRuntime.numbersDiffer(customBar:GetValue(), currentScroll) then
        customBar:SetValue(currentScroll)
    end
    customBar._paSyncing = false
    settingsScrollRuntime.layoutThumb(customBar, viewportHeight, contentHeight, range, currentScroll)
    refreshCustomSettingsScrollBarThumb(customBar)
end

local function refreshManagedFontObject(object)
    if not object or object._paGlobalFontManaged ~= true or not object.SetFont then
        return
    end

    local size = tonumber(object._paGlobalFontSize) or select(2, object:GetFont()) or 12
    local flags = object._paGlobalFontFlags
    if flags == nil then
        flags = ""
    end

    if isUsingCustomSettingsWindowVisualStyle(object)
        and PortalAuthority
        and type(PortalAuthority.ApplyPremiumAuthoredFont) == "function" then
        PortalAuthority:ApplyPremiumAuthoredFont(object, size, flags)
        return
    end

    if PortalAuthority and type(PortalAuthority.ApplyGlobalFont) == "function" then
        PortalAuthority:ApplyGlobalFont(object, size, flags)
    end
end

local function refreshSettingsWindowVisualTree(object, visited)
    if not frameIsAlive(object) then
        return
    end
    visited = visited or {}
    if visited[object] then
        return
    end
    visited[object] = true

    refreshManagedFontObject(object)
    if type(object._paSettingsWindowVisualRefresh) == "function" then
        pcall(object._paSettingsWindowVisualRefresh, object)
    end

    if object.GetRegions then
        for i = 1, select("#", object:GetRegions()) do
            local region = select(i, object:GetRegions())
            if frameIsAlive(region) then
                refreshSettingsWindowVisualTree(region, visited)
            else
                refreshManagedFontObject(region)
                if region and type(region._paSettingsWindowVisualRefresh) == "function" then
                    pcall(region._paSettingsWindowVisualRefresh, region)
                end
            end
        end
    end
    if object.GetChildren then
        for i = 1, select("#", object:GetChildren()) do
            refreshSettingsWindowVisualTree(select(i, object:GetChildren()), visited)
        end
    end
end

if PortalAuthority then
    function PortalAuthority:RefreshSettingsWindowHostVisuals(root)
        refreshSettingsWindowVisualTree(root, {})
    end
end

