local function getPortalMedia()
    local media = PortalAuthority and PortalAuthority.Media
    if type(media) == "table" then
        return media
    end
    return nil
end

local function normalizeSoundChoiceValue(value)
    local media = getPortalMedia()
    if media and media.NormalizeBundledSoundValue then
        return media.NormalizeBundledSoundValue(value)
    end
    return value
end

local function compareChoiceLabels(left, right)
    return tostring(left.label or ""):lower() < tostring(right.label or ""):lower()
end

local function normalizeChoicePathKey(path)
    if type(path) ~= "string" then
        return nil
    end
    local normalized = trim(path):gsub("/", "\\")
    if normalized == "" then
        return "__GLOBAL_FONT__"
    end
    return normalized:lower()
end

local function resolveFontChoicePath(option)
    if type(option) ~= "table" then
        return nil
    end

    local path = option.path
    if type(path) == "string" then
        path = trim(path):gsub("/", "\\")
        if path ~= "" then
            return path
        end
    end

    local value = option.value
    if value == "" then
        return ""
    end
    if type(value) == "string" then
        local normalized = trim(value):gsub("/", "\\")
        if normalized:find("\\", 1, true) then
            return normalized
        end
    end

    return nil
end

local function getSoundChoiceValueKey(value)
    local normalized = normalizeSoundChoiceValue(value)
    if type(normalized) == "number" then
        return "num:" .. tostring(normalized)
    end
    return "str:" .. tostring(normalized or "")
end

local function buildFallbackSoundChoices(currentValue, opts)
    opts = type(opts) == "table" and opts or {}

    local media = getPortalMedia()
    local choices = {}
    local seen = {}

    local function add(label, value)
        if value == nil then
            value = ""
        end

        local key = getSoundChoiceValueKey(value)
        if seen[key] then
            return
        end

        seen[key] = true
        choices[#choices + 1] = {
            label = tostring(label or value or ""),
            value = value,
        }
    end

    if opts.includeNone then
        add("None", "")
    end

    if media and type(media.BundledSounds) == "table" then
        for _, entry in ipairs(media.BundledSounds) do
            add(entry.label, entry.value)
        end
    else
        add("Overclock: Pause", "Overclock: Pause")
        add("Overclock: OOT Press Start", "Overclock: OOT Press Start")
        add("Overclock: MGS", "Overclock: MGS")
    end

    local lsm = LibStub and LibStub("LibSharedMedia-3.0", true)
    if lsm and lsm.List then
        local external = {}
        for _, name in ipairs(lsm:List("sound") or {}) do
            local label = tostring(name or "")
            if label ~= "" and not label:match("^Overclock:%s") and label ~= "None" then
                external[#external + 1] = {
                    label = label,
                    value = label,
                }
            end
        end
        table.sort(external, compareChoiceLabels)
        for _, entry in ipairs(external) do
            add(entry.label, entry.value)
        end
    end

    if opts.includeBuiltinIDs then
        local builtinChoices = (media and type(media.BuiltinSoundChoices) == "table" and media.BuiltinSoundChoices)
            or ((PortalAuthority.GetBuiltinSummonAlertSounds and PortalAuthority:GetBuiltinSummonAlertSounds()) or {})
        for _, entry in ipairs(builtinChoices) do
            add(entry.label, entry.value)
        end
    end

    local normalizedCurrent = normalizeSoundChoiceValue(currentValue)
    if normalizedCurrent ~= nil and normalizedCurrent ~= "" then
        local label = tostring(normalizedCurrent)
        if type(normalizedCurrent) == "string" and normalizedCurrent:find("[/\\]") then
            local basename = normalizedCurrent:match("([^\\]+)$") or normalizedCurrent
            basename = basename:gsub("%.%w+$", "")
            if basename ~= "" then
                label = "Custom: " .. basename
            end
        end
        add(label, normalizedCurrent)
    end

    return choices
end

local function getSummonSoundChoices(currentValue)
    local media = getPortalMedia()
    if media and media.GetChoices then
        return media.GetChoices("sound", {
            includeNone = true,
            includeBuiltinIDs = true,
            currentValue = currentValue,
        }) or {}
    end
    return buildFallbackSoundChoices(currentValue, {
        includeNone = true,
        includeBuiltinIDs = true,
    })
end

