local function getAvailableFontChoices()
    local media = getPortalMedia()
    local seen, choices = {}, {}
    local bundledKeys = {}
    local deferredExternalByPath = {}
    local deferredExternalOrder = {}

    local function add(label, path)
        if type(path) ~= "string" then return end
        local key = normalizeChoicePathKey(path)
        if not key then return end
        if seen[key] then return end
        seen[key] = true
        table.insert(choices, { label = label, value = path })
    end

    local function queueExternal(label, path)
        if type(path) ~= "string" then
            return
        end
        local key = normalizeChoicePathKey(path)
        if not key or key == "__GLOBAL_FONT__" or bundledKeys[key] then
            return
        end

        local entry = deferredExternalByPath[key]
        if not entry then
            entry = {
                label = tostring(label or path or ""),
                value = path,
            }
            deferredExternalByPath[key] = entry
            deferredExternalOrder[#deferredExternalOrder + 1] = key
            return
        end

        local candidateLabel = tostring(label or path or "")
        if candidateLabel ~= "" and candidateLabel:lower() < tostring(entry.label or ""):lower() then
            entry.label = candidateLabel
        end
    end

    add("Global UI Font", "")

    if media and type(media.BundledFonts) == "table" then
        for _, font in ipairs(media.BundledFonts) do
            local path = resolveFontChoicePath(font)
            local key = normalizeChoicePathKey(path)
            if key then
                bundledKeys[key] = true
                add(font.label, path)
            end
        end
    end

    if media and media.GetChoices then
        for _, option in ipairs(media.GetChoices("font", { includeGlobalUi = true }) or {}) do
            local path = resolveFontChoicePath(option)
            queueExternal(tostring(option.label or option.value or path or ""), path)
        end
    end

    for _, font in ipairs(BUILTIN_FONT_CHOICES) do add(font.label, font.value) end

    local lsm = LibStub and LibStub("LibSharedMedia-3.0", true)
    if lsm and lsm.HashTable then
        for label, path in pairs(lsm:HashTable("font") or {}) do
            local normalizedPath = resolveFontChoicePath({ label = label, value = path })
            queueExternal(tostring(label or normalizedPath or ""), normalizedPath)
        end
    end

    local deferredExternal = {}
    for _, key in ipairs(deferredExternalOrder) do
        local entry = deferredExternalByPath[key]
        if entry then
            deferredExternal[#deferredExternal + 1] = entry
        end
    end

    table.sort(deferredExternal, compareChoiceLabels)
    for _, option in ipairs(deferredExternal) do
        add(option.label, option.value)
    end

    return choices
end

local function buildSharedFontPickerChoices()
    local options = {}

    for _, option in ipairs(getAvailableFontChoices() or {}) do
        local value = tostring(option and option.value or "")
        local label = tostring((option and option.label) or value)
        options[#options + 1] = {
            value = value,
            label = label,
            buttonLabel = label,
            secondary = "",
            previewFontPath = (value ~= "") and value or nil,
            aliases = { label },
        }
    end

    if #options == 0 then
        options[1] = {
            value = "",
            label = "Global UI Font",
            buttonLabel = "Global UI Font",
            secondary = "",
            previewFontPath = nil,
            aliases = { "Global UI Font" },
        }
    end

    return options
end

local function restoreColorPickerPrevious(previous, fallback)
    fallback = type(fallback) == "table" and fallback or {}

    local alpha = tonumber(previous and previous.a)
    if alpha == nil then
        local opacity = tonumber(previous and previous.opacity)
        if opacity ~= nil then
            alpha = 1 - opacity
        end
    end
    if alpha == nil then
        alpha = tonumber(fallback.a) or 1
    end

    return {
        r = tonumber(previous and previous.r) or tonumber(fallback.r) or 1,
        g = tonumber(previous and previous.g) or tonumber(fallback.g) or 1,
        b = tonumber(previous and previous.b) or tonumber(fallback.b) or 1,
        a = math.max(0, math.min(1, alpha)),
    }
end

local function openColorPicker(onChanged)
    local c = PortalAuthorityDB.dockFontColor
    if ColorPickerFrame and ColorPickerFrame.SetupColorPickerAndShow then
        ColorPickerFrame:SetupColorPickerAndShow({
            r = c.r,
            g = c.g,
            b = c.b,
            opacity = 1 - c.a,
            hasOpacity = true,
            swatchFunc = function()
                local r, g, b = ColorPickerFrame:GetColorRGB()
                local a = 1 - (OpacitySliderFrame and OpacitySliderFrame:GetValue() or 0)
                PortalAuthorityDB.dockFontColor = { r = r, g = g, b = b, a = a }
                onChanged()
            end,
            opacityFunc = function()
                local r, g, b = ColorPickerFrame:GetColorRGB()
                local a = 1 - (OpacitySliderFrame and OpacitySliderFrame:GetValue() or 0)
                PortalAuthorityDB.dockFontColor = { r = r, g = g, b = b, a = a }
                onChanged()
            end,
            cancelFunc = function(prev)
                PortalAuthorityDB.dockFontColor = restoreColorPickerPrevious(prev, c)
                onChanged()
            end,
        })
    end
end

local function applyGlobalFontToObject(object, size, flags)
    if not object or not object.SetFont then
        return
    end

    object._paGlobalFontManaged = true
    object._paGlobalFontSize = size
    object._paGlobalFontFlags = flags
    refreshManagedFontObject(object)
end

local function createStyledFontString(parent, layer, template, size)
    local fontString = parent:CreateFontString(nil, layer, template)
    applyGlobalFontToObject(fontString, size)
    if parent then
        local current = parent
        local panel = nil
        while current do
            if current._paSearchSectionKey and current._paSearchScrollChild then
                panel = current
                break
            end
            current = current.GetParent and current:GetParent() or nil
        end

        if panel
            and (tonumber(panel._paSearchDescriptorCaptureDepth) or 0) > 0
            and (parent == panel._paSearchScrollChild or parent._paSettingsSearchTextContainer == true)
        then
            panel._paSearchDescriptorState = panel._paSearchDescriptorState or {
                descriptors = {},
                nextOrderIndex = 1,
            }
            local state = panel._paSearchDescriptorState
            local descriptor = {
                kind = "text",
                sectionKey = panel._paSearchSectionKey,
                sectionName = panel._paSearchSectionName or panel.name or "",
                displayRef = fontString,
                anchorRef = fontString,
                controlRef = fontString,
                searchRefs = { fontString },
                searchWidgetRef = nil,
                searchLabelRef = fontString,
                searchHelperRefs = {},
                searchRowFrame = nil,
                orderIndex = state.nextOrderIndex,
                fontSize = tonumber(size) or 0,
                fontTemplate = template,
                parentRef = parent,
            }
            state.nextOrderIndex = state.nextOrderIndex + 1
            state.descriptors[#state.descriptors + 1] = descriptor
            fontString._paSearchDescriptor = descriptor
            panel._paSearchRegistryDirty = true
            if not panel._paSearchTopTarget then
                panel._paSearchTopTarget = fontString
            end
        end
    end
    return fontString
end

local settingsSearchRuntime = {}

function settingsSearchRuntime.markTextContainer(frame)
    if frameIsAlive(frame) then
        frame._paSettingsSearchTextContainer = true
    end
    return frame
end

function settingsSearchRuntime.getPanelFromObject(object)
    local current = object
    while current do
        if current._paSearchSectionKey and current._paSearchScrollChild then
            return current
        end
        current = current.GetParent and current:GetParent() or nil
    end
    return nil
end

function settingsSearchRuntime.ensureDescriptorState(panel)
    if not panel then
        return nil
    end
    panel._paSearchDescriptorState = panel._paSearchDescriptorState or {
        descriptors = {},
        nextOrderIndex = 1,
    }
    return panel._paSearchDescriptorState
end

function settingsSearchRuntime.beginDescriptorCapture(panel)
    if not panel then
        return
    end
    panel._paSearchDescriptorCaptureDepth = (tonumber(panel._paSearchDescriptorCaptureDepth) or 0) + 1
    panel._paSearchRegistryDirty = true
end

function settingsSearchRuntime.endDescriptorCapture(panel)
    if not panel then
        return
    end
    panel._paSearchDescriptorCaptureDepth = math.max((tonumber(panel._paSearchDescriptorCaptureDepth) or 1) - 1, 0)
end

function settingsSearchRuntime.ensureDescriptorForTextRef(textRef, controlRef)
    if not frameIsAlive(textRef) then
        return nil, nil
    end
    local panel = settingsSearchRuntime.getPanelFromObject(textRef)
    if not panel or (tonumber(panel._paSearchDescriptorCaptureDepth) or 0) <= 0 then
        return nil, panel
    end

    local descriptor = textRef._paSearchDescriptor
    if descriptor then
        if frameIsAlive(controlRef) then
            descriptor.controlRef = controlRef
            descriptor.anchorRef = controlRef
            descriptor.searchWidgetRef = controlRef
        end
        descriptor.searchLabelRef = frameIsAlive(textRef) and textRef or descriptor.searchLabelRef
        descriptor.searchHelperRefs = descriptor.searchHelperRefs or {}
        return descriptor, panel
    end

    local state = settingsSearchRuntime.ensureDescriptorState(panel)
    descriptor = {
        kind = "text",
        sectionKey = panel._paSearchSectionKey,
        sectionName = panel._paSearchSectionName or panel.name or "",
        displayRef = textRef,
        anchorRef = frameIsAlive(controlRef) and controlRef or textRef,
        controlRef = frameIsAlive(controlRef) and controlRef or textRef,
        searchRefs = { textRef },
        searchWidgetRef = frameIsAlive(controlRef) and controlRef or nil,
        searchLabelRef = textRef,
        searchHelperRefs = {},
        searchRowFrame = nil,
        orderIndex = state.nextOrderIndex,
        fontSize = tonumber(textRef._paGlobalFontSize) or 0,
        fontTemplate = nil,
        parentRef = textRef.GetParent and textRef:GetParent() or nil,
    }
    state.nextOrderIndex = state.nextOrderIndex + 1
    state.descriptors[#state.descriptors + 1] = descriptor
    textRef._paSearchDescriptor = descriptor
    panel._paSearchRegistryDirty = true
    if not panel._paSearchTopTarget then
        panel._paSearchTopTarget = textRef
    end
    return descriptor, panel
end

function settingsSearchRuntime.resolveExplicitSearchRowFrame(target)
    if type(target) ~= "table" then
        return nil
    end

    local candidates = {
        target.searchRowFrame,
        target.rowFrame,
        target.rowContainer,
        target.row,
    }
    for i = 1, #candidates do
        if frameIsAlive(candidates[i]) then
            return candidates[i]
        end
    end
    return nil
end

function settingsSearchRuntime.appendUniqueSearchRef(refs, ref)
    if type(refs) ~= "table" or not frameIsAlive(ref) then
        return
    end
    for i = 1, #refs do
        if refs[i] == ref then
            return
        end
    end
    refs[#refs + 1] = ref
end

function settingsSearchRuntime.getIconTypeForKind(kind)
    kind = type(kind) == "string" and string.lower(kind) or ""
    if kind == "toggle" or kind == "checkbox" then
        return "toggle"
    end
    if kind == "dropdown" or kind == "picker" or kind == "font_picker" or kind == "sound_picker" or kind == "texture_picker" then
        return "dropdown"
    end
    if kind == "slider" or kind == "premium_slider" or kind == "stepper" then
        return "slider"
    end
    return nil
end

function settingsSearchRuntime.registerControlText(textRef, controlRef, kind, extraRefs, searchRowFrame)
    local descriptor, panel = settingsSearchRuntime.ensureDescriptorForTextRef(textRef, controlRef)
    if not descriptor then
        return nil
    end

    descriptor.kind = kind or descriptor.kind or "control"
    descriptor.controlRef = frameIsAlive(controlRef) and controlRef or descriptor.controlRef
    descriptor.anchorRef = frameIsAlive(controlRef) and controlRef or descriptor.anchorRef
    descriptor.searchWidgetRef = frameIsAlive(controlRef) and controlRef or descriptor.searchWidgetRef
    descriptor.searchLabelRef = frameIsAlive(textRef) and textRef or descriptor.searchLabelRef
    descriptor.searchRowFrame = frameIsAlive(searchRowFrame) and searchRowFrame or descriptor.searchRowFrame
    descriptor.iconType = settingsSearchRuntime.getIconTypeForKind(kind) or descriptor.iconType
    descriptor.searchRefs = descriptor.searchRefs or {}
    descriptor.searchHelperRefs = descriptor.searchHelperRefs or {}
    if frameIsAlive(textRef) then
        descriptor.searchRefs[1] = textRef
    end
    if type(extraRefs) == "table" then
        for i = 1, #extraRefs do
            settingsSearchRuntime.appendUniqueSearchRef(descriptor.searchRefs, extraRefs[i])
            settingsSearchRuntime.appendUniqueSearchRef(descriptor.searchHelperRefs, extraRefs[i])
        end
    end
    if panel then
        panel._paSearchRegistryDirty = true
    end
    return descriptor
end

function settingsSearchRuntime.registerSpec(spec, explicitKind)
    if type(spec) ~= "table" then
        return spec
    end
    local label = spec.label
    local control = spec.control or spec.slider or spec.button or spec.valueButton or nil
    local extraRefs = {}
    local function addExtraRef(ref)
        if frameIsAlive(ref) then
            extraRefs[#extraRefs + 1] = ref
        end
    end
    addExtraRef(spec.helper)
    addExtraRef(spec.description)
    addExtraRef(spec.desc)
    addExtraRef(spec.hint)
    addExtraRef(spec.helperText)
    addExtraRef(spec.secondaryText)
    addExtraRef(spec.subLabel)
    addExtraRef(spec.valueText)
    addExtraRef(spec.valueEdit)
    addExtraRef(spec.text)
    addExtraRef(spec.caret)
    if type(spec.explainers) == "table" then
        for i = 1, #spec.explainers do
            addExtraRef(spec.explainers[i])
        end
    end
    if type(spec.extraSearchRefs) == "table" then
        for i = 1, #spec.extraSearchRefs do
            addExtraRef(spec.extraSearchRefs[i])
        end
    end
    local searchRowFrame = settingsSearchRuntime.resolveExplicitSearchRowFrame(spec)
    if frameIsAlive(label) then
        settingsSearchRuntime.registerControlText(label, control, explicitKind or spec.kind, extraRefs, searchRowFrame)
    elseif control and control.Text then
        settingsSearchRuntime.registerControlText(control.Text, control, explicitKind or spec.kind, extraRefs, searchRowFrame)
    end
    return spec
end

function settingsSearchRuntime.attachExtraSearchRefs(target, extraRefs)
    if type(target) ~= "table" or type(extraRefs) ~= "table" or #extraRefs <= 0 then
        return nil
    end
    local label = target.label
    local control = target.control or target.slider or target.button or target.valueButton or nil
    local searchRowFrame = settingsSearchRuntime.resolveExplicitSearchRowFrame(target)
    if frameIsAlive(label) then
        return settingsSearchRuntime.registerControlText(label, control, target.kind, extraRefs, searchRowFrame)
    end
    if control and control.Text then
        return settingsSearchRuntime.registerControlText(control.Text, control, target.kind, extraRefs, searchRowFrame)
    end
    return nil
end

local function getClassHex(classFile)
    local color = RAID_CLASS_COLORS and RAID_CLASS_COLORS[classFile]
    if color and color.colorStr then
        return color.colorStr
    end
    return "ffffffff"
end

local function createTopRightHeader(parent, yOffset)
    local header = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
    header:SetJustifyH("RIGHT")
    header:SetText("")
    header:SetPoint("TOPRIGHT", parent, "TOPRIGHT", -20, yOffset or -20)
    header:Hide()
    return header
end

local function PA_SafeBool(v)
    local ok, s = pcall(tostring, v)
    if not ok or s == nil then return false end
    local okb, b = pcall(string.byte, s, 1)
    if not okb or b == nil then return false end
    local nb = tonumber(tostring(b)) or 0
    return nb == 116
end

local function createCheckbox(parent, text, key, onApply)
    local check = CreateFrame("CheckButton", nil, parent, "UICheckButtonTemplate")
    check.text:SetText(text)
    applyGlobalFontToObject(check.text, 12)
    check:SetChecked(PA_SafeBool(PortalAuthorityDB and PortalAuthorityDB[key]))
    check:SetScript("OnClick", function(btn)
        if PortalAuthorityDB then
            PortalAuthorityDB[key] = PA_SafeBool(btn:GetChecked())
        end
        if key == "dockHideInCombat" then
            debugSettingsLog("dockHideInCombat updated:", tostring(PortalAuthorityDB[key]))
        end
        if onApply then onApply() end
    end)
    settingsSearchRuntime.registerControlText(check.text, check, "checkbox")
    return check
end

local function createActionButton(parent, text, onClick, width, searchOpts)
    local btn = CreateFrame("Button", nil, parent, "UIPanelButtonTemplate")
    btn:SetText(text)
    applyGlobalFontToObject(btn.Text, 12)
    searchOpts = type(searchOpts) == "table" and searchOpts or nil
    if btn.Text and searchOpts and searchOpts.textOrigin then
        settingsSearchRuntime.markSearchTextOrigin(btn.Text, searchOpts.textOrigin, searchOpts)
    end
    btn:SetSize(width or 120, 22)
    btn:SetScript("OnClick", function() if onClick then onClick() end end)
    settingsSearchRuntime.registerControlText(btn.Text, btn, "button")
    return btn
end

local function styleSecondaryActionButtonShared(btn, styleOpts)
    if not btn then
        return
    end
    styleOpts = type(styleOpts) == "table" and styleOpts or {}
    local CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A = 0.10, 0.11, 0.14, 0.95
    local CONTROL_HOVER_BG_R, CONTROL_HOVER_BG_G, CONTROL_HOVER_BG_B, CONTROL_HOVER_BG_A = 0.16, 0.17, 0.20, 0.95
    local CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A = 0.24, 0.27, 0.32, 1.0
    local CONTROL_HOVER_BORDER_R, CONTROL_HOVER_BORDER_G, CONTROL_HOVER_BORDER_B, CONTROL_HOVER_BORDER_A = 0.30, 0.33, 0.38, 1.0

    local baseBg = styleOpts.baseBg or { CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A }
    local hoverBg = styleOpts.hoverBg or { CONTROL_HOVER_BG_R, CONTROL_HOVER_BG_G, CONTROL_HOVER_BG_B, CONTROL_HOVER_BG_A }
    local pressedBg = styleOpts.pressedBg or { 0.08, 0.09, 0.12, 0.96 }
    local baseBorder = styleOpts.baseBorder or { CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, 0.90 }
    local hoverBorder = styleOpts.hoverBorder or { CONTROL_HOVER_BORDER_R, CONTROL_HOVER_BORDER_G, CONTROL_HOVER_BORDER_B, 0.95 }
    local pressedBorder = styleOpts.pressedBorder or { CONTROL_HOVER_BORDER_R, CONTROL_HOVER_BORDER_G, CONTROL_HOVER_BORDER_B, 0.90 }
    local textColor = styleOpts.textColor or { 0.86, 0.86, 0.89, 1 }

    if not btn._paSecondaryBg then
        btn._paSecondaryBg = btn:CreateTexture(nil, "ARTWORK")
        btn._paSecondaryBg:SetAllPoints(btn)
        btn._paSecondaryBg:SetTexture("Interface\\Buttons\\WHITE8x8")

        btn._paSecondaryBorder = CreateFrame("Frame", nil, btn, "BackdropTemplate")
        btn._paSecondaryBorder:SetPoint("TOPLEFT", btn, "TOPLEFT", -1, 1)
        btn._paSecondaryBorder:SetPoint("BOTTOMRIGHT", btn, "BOTTOMRIGHT", 1, -1)
        btn._paSecondaryBorder:SetBackdrop({
            edgeFile = "Interface\\Buttons\\WHITE8x8",
            edgeSize = 1,
        })
    end

    local function hideTemplateChrome(selfBtn)
        local n = selfBtn.GetNormalTexture and selfBtn:GetNormalTexture() or nil
        local p = selfBtn.GetPushedTexture and selfBtn:GetPushedTexture() or nil
        local h = selfBtn.GetHighlightTexture and selfBtn:GetHighlightTexture() or nil
        local d = selfBtn.GetDisabledTexture and selfBtn:GetDisabledTexture() or nil
        if n then n:SetAlpha(0); if n.Hide then n:Hide() end end
        if p then p:SetAlpha(0); if p.Hide then p:Hide() end end
        if h then h:SetAlpha(0); if h.Hide then h:Hide() end end
        if d then d:SetAlpha(0); if d.Hide then d:Hide() end end
        for _, part in ipairs({
            "Left", "Middle", "Right",
            "LeftDisabled", "MiddleDisabled", "RightDisabled",
            "LeftHighlight", "MiddleHighlight", "RightHighlight",
            "LeftPressed", "MiddlePressed", "RightPressed",
        }) do
            local tex = selfBtn[part]
            if tex and tex.SetAlpha then tex:SetAlpha(0) end
            if tex and tex.Hide then tex:Hide() end
        end
    end

    local function applyVisual(selfBtn)
        hideTemplateChrome(selfBtn)
        local hovered = selfBtn._paSecondaryHover and true or false
        local pressed = selfBtn._paSecondaryPressed and true or false
        if pressed then
            selfBtn._paSecondaryBg:SetVertexColor(pressedBg[1], pressedBg[2], pressedBg[3], pressedBg[4])
            selfBtn._paSecondaryBorder:SetBackdropBorderColor(pressedBorder[1], pressedBorder[2], pressedBorder[3], pressedBorder[4])
        elseif hovered then
            selfBtn._paSecondaryBg:SetVertexColor(hoverBg[1], hoverBg[2], hoverBg[3], hoverBg[4])
            selfBtn._paSecondaryBorder:SetBackdropBorderColor(hoverBorder[1], hoverBorder[2], hoverBorder[3], hoverBorder[4])
        else
            selfBtn._paSecondaryBg:SetVertexColor(baseBg[1], baseBg[2], baseBg[3], baseBg[4])
            selfBtn._paSecondaryBorder:SetBackdropBorderColor(baseBorder[1], baseBorder[2], baseBorder[3], baseBorder[4])
        end
        if selfBtn.Text then
            selfBtn.Text:SetTextColor(textColor[1], textColor[2], textColor[3], textColor[4])
        end
    end

    btn:SetScript("OnEnter", function(selfBtn)
        selfBtn._paSecondaryHover = true
        applyVisual(selfBtn)
    end)
    btn:SetScript("OnLeave", function(selfBtn)
        selfBtn._paSecondaryHover = false
        selfBtn._paSecondaryPressed = false
        applyVisual(selfBtn)
    end)
    btn:SetScript("OnMouseDown", function(selfBtn)
        selfBtn._paSecondaryPressed = true
        applyVisual(selfBtn)
    end)
    btn:SetScript("OnMouseUp", function(selfBtn)
        selfBtn._paSecondaryPressed = false
        applyVisual(selfBtn)
    end)
    btn:HookScript("OnShow", function(selfBtn)
        applyVisual(selfBtn)
    end)
    applyVisual(btn)
end

local function createNumeric(parent, labelText, key, min, max, onApply)
    local label = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
    label:SetText(labelText)

    local box = CreateFrame("EditBox", nil, parent, "InputBoxTemplate")
    box:SetAutoFocus(false)
    box:SetTextInsets(8, 8, 0, 0)
    box:SetTextColor(1, 1, 1, 1)
    box:SetHighlightColor(1, 1, 1, 0.25)
    applyGlobalFontToObject(box, 12)

    local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
    local defaultValue = defaults[key]
    if defaultValue == nil then
        defaultValue = 0
    end

    local isRefreshing = false
    local isProgrammaticSetText = false
    local didUserEdit = false
    local didInitialHydrate = false

    local function setEditBoxText(text)
        if box:GetText() == text then
            return
        end
        isProgrammaticSetText = true
        box:SetText(text)
        isProgrammaticSetText = false
    end

    local function refreshFromDB()
        local value = PortalAuthorityDB[key]
        if value == nil then
            value = defaultValue
        end
        local text = tostring(value or defaultValue)
        isRefreshing = true
        setEditBoxText(text)
        box:ClearFocus()
        box:HighlightText(0, 0)
        box:SetCursorPosition(0)
        didUserEdit = false
        isRefreshing = false
    end

    refreshFromDB()

    local function apply()
        if isRefreshing or isProgrammaticSetText or not didUserEdit then
            return
        end

        local v = tonumber(box:GetText())
        if not v then
            refreshFromDB()
            return
        end
        if min and v < min then v = min end
        if max and v > max then v = max end
        v = math.floor(v)
        local priorValue = tonumber(PortalAuthorityDB[key])
        local changed = priorValue ~= v
        PortalAuthorityDB[key] = v
        refreshFromDB()
        if changed and onApply then onApply() end
    end

    box:SetScript("OnEditFocusGained", function()
        didUserEdit = false
    end)
    box:SetScript("OnTextChanged", function(_, userInput)
        if isRefreshing or isProgrammaticSetText then
            return
        end
        if userInput then
            didUserEdit = true
        end
    end)

    box:SetScript("OnEnterPressed", function(self)
        apply()
        self:ClearFocus()
    end)
    box:SetScript("OnEditFocusLost", apply)
    box:HookScript("OnShow", function()
        if didInitialHydrate then
            return
        end
        didInitialHydrate = true
        refreshFromDB()
    end)

    local spec = {
        kind = "numeric",
        label = label,
        control = box,
        SetValue = function(_, value)
            if box:HasFocus() then return end
            local numericValue = tonumber(value)
            if numericValue == nil then
                refreshFromDB()
                return
            end
            local text = tostring(math.floor(numericValue))
            isRefreshing = true
            setEditBoxText(text)
            box:ClearFocus()
            box:HighlightText(0, 0)
            box:SetCursorPosition(0)
            didUserEdit = false
            isRefreshing = false
        end,
        Refresh = refreshFromDB,
    }
    settingsSearchRuntime.registerSpec(spec)
    return spec
end

local function setSettingsBackdropColors(frame, bgColor, borderColor)
    if frame and frame.SetBackdropColor then
        frame:SetBackdropColor(unpackColor(bgColor))
    end
    if frame and frame.SetBackdropBorderColor then
        frame:SetBackdropBorderColor(unpackColor(borderColor))
    end
end

local function getSettingsWindowSelectVisual(button, hovered, pressed, enabled)
    if not isUsingCustomSettingsWindowVisualStyle(button) then
        return nil
    end
    if not enabled then
        return {
            bg = SETTINGS_WINDOW_HOST_COLORS.disabledBg,
            border = SETTINGS_WINDOW_HOST_COLORS.disabledBorder,
            text = SETTINGS_WINDOW_HOST_COLORS.disabledText,
        }
    end
    if pressed then
        return {
            bg = SETTINGS_WINDOW_HOST_COLORS.hoverBg,
            border = SETTINGS_WINDOW_HOST_COLORS.onBorder,
            text = SETTINGS_WINDOW_HOST_COLORS.hoverText,
        }
    end
    if hovered then
        return {
            bg = SETTINGS_WINDOW_HOST_COLORS.hoverBg,
            border = SETTINGS_WINDOW_HOST_COLORS.hoverBorder,
            text = SETTINGS_WINDOW_HOST_COLORS.hoverText,
        }
    end
    return {
        bg = SETTINGS_WINDOW_HOST_COLORS.idleBg,
        border = SETTINGS_WINDOW_HOST_COLORS.idleBorder,
        text = SETTINGS_WINDOW_HOST_COLORS.idleText,
    }
end

local function getDropdownTemplateButton(dropdown)
    if not dropdown then
        return nil
    end
    if dropdown.Button then
        return dropdown.Button
    end
    local name = dropdown.GetName and dropdown:GetName() or nil
    if type(name) == "string" and name ~= "" then
        return _G[name .. "Button"]
    end
    return nil
end

local function getDropdownTemplateText(dropdown)
    if not dropdown then
        return nil
    end
    if dropdown.Text then
        return dropdown.Text
    end
    local name = dropdown.GetName and dropdown:GetName() or nil
    if type(name) == "string" and name ~= "" then
        return _G[name .. "Text"]
    end
    return nil
end

local function setDropdownTemplateTexturesVisible(dropdown, visible)
    if not dropdown then
        return
    end

    local alpha = visible and 1 or 0
    for _, key in ipairs({
        "Left", "Middle", "Right",
        "LeftHighlight", "MiddleHighlight", "RightHighlight",
        "LeftDisabled", "MiddleDisabled", "RightDisabled",
    }) do
        local tex = dropdown[key]
        if tex and tex.SetAlpha then
            tex:SetAlpha(alpha)
        end
        if tex and tex.SetShown then
            tex:SetShown(visible)
        elseif tex and visible then
            tex:Show()
        elseif tex then
            tex:Hide()
        end
    end

    local button = getDropdownTemplateButton(dropdown)
    if button then
        for _, getterName in ipairs({ "GetNormalTexture", "GetPushedTexture", "GetHighlightTexture", "GetDisabledTexture" }) do
            local getter = button[getterName]
            local tex = getter and getter(button) or nil
            if tex and tex.SetAlpha then
                tex:SetAlpha(alpha)
            end
            if tex and tex.SetShown then
                tex:SetShown(visible)
            elseif tex and visible then
                tex:Show()
            elseif tex then
                tex:Hide()
            end
        end
    end
end

local function ensureSettingsWindowDropdownChrome(dropdown)
    if not dropdown or dropdown._paHostDropdownReady then
        return
    end
    dropdown._paHostDropdownReady = true

    local chrome = CreateFrame("Frame", nil, dropdown, "BackdropTemplate")
    chrome:SetBackdrop(FLAT_SETTINGS_BACKDROP)
    chrome:SetPoint("TOPLEFT", dropdown, "TOPLEFT", 18, -3)
    chrome:SetPoint("BOTTOMRIGHT", dropdown, "BOTTOMRIGHT", -18, 9)
    chrome:SetFrameStrata(dropdown:GetFrameStrata())
    chrome:SetFrameLevel(math.max(1, (dropdown:GetFrameLevel() or 1) - 1))
    dropdown._paHostDropdownChrome = chrome

    local text = getDropdownTemplateText(dropdown)
    if text then
        applyGlobalFontToObject(text, 11)
    end

    local function applyVisual(selfDropdown)
        local button = getDropdownTemplateButton(selfDropdown)
        local hoverSource = button or selfDropdown
        local hovered = hoverSource and hoverSource.IsMouseOver and hoverSource:IsMouseOver() or false
        local enabled = true
        if button and button.IsEnabled then
            enabled = button:IsEnabled()
        end

        local themed = getSettingsWindowSelectVisual(selfDropdown, hovered, false, enabled)
        if not themed then
            chrome:Hide()
            setDropdownTemplateTexturesVisible(selfDropdown, true)
            return
        end

        chrome:Show()
        setDropdownTemplateTexturesVisible(selfDropdown, false)
        setSettingsBackdropColors(chrome, themed.bg, themed.border)
        if text and text.SetTextColor then
            text:SetTextColor(unpackColor(themed.text))
        end
    end

    registerSettingsWindowVisualRefresh(dropdown, applyVisual)
    dropdown:HookScript("OnShow", applyVisual)
    dropdown:HookScript("OnHide", applyVisual)

    local button = getDropdownTemplateButton(dropdown)
    if button then
        button:HookScript("OnEnter", function()
            applyVisual(dropdown)
        end)
        button:HookScript("OnLeave", function()
            applyVisual(dropdown)
        end)
    end

    applyVisual(dropdown)
end

local function applySettingsWindowSelectButtonChrome(button, text, caret, hovered, pressed, enabled, legacyVisual)
    local themed = getSettingsWindowSelectVisual(button, hovered, pressed, enabled)
    if themed then
        setSettingsBackdropColors(button, themed.bg, themed.border)
        if text and text.SetTextColor then
            text:SetTextColor(unpackColor(themed.text))
        end
        if caret and caret.SetTextColor then
            caret:SetTextColor(unpackColor(themed.text))
        end
        return true
    end
    if type(legacyVisual) == "function" then
        legacyVisual()
    end
    return false
end

local function createDropdown(parent, labelText, values, key, onApply)
    local label = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
    label:SetText(labelText)

    local dropdown = CreateFrame("Frame", nil, parent, "UIDropDownMenuTemplate")
    ensureSettingsWindowDropdownChrome(dropdown)

    UIDropDownMenu_Initialize(dropdown, function(_, level)
        for _, option in ipairs(values) do
            local info = UIDropDownMenu_CreateInfo()
            info.text = option.label
            info.checked = PortalAuthorityDB[key] == option.value
            info.func = function()
                PortalAuthorityDB[key] = option.value
                UIDropDownMenu_SetSelectedValue(dropdown, option.value)
                UIDropDownMenu_SetText(dropdown, option.label)
                if onApply then onApply() end
            end
            UIDropDownMenu_AddButton(info, level)
        end
    end)

    local spec = { kind = "dropdown", label = label, control = dropdown }
    spec.Refresh = function()
        local selectedLabel, selectedValue = values[1].label, values[1].value
        for _, option in ipairs(values) do
            if option.value == PortalAuthorityDB[key] then
                selectedLabel, selectedValue = option.label, option.value
                break
            end
        end
        PortalAuthorityDB[key] = selectedValue
        UIDropDownMenu_SetSelectedValue(dropdown, selectedValue)
        UIDropDownMenu_SetText(dropdown, selectedLabel)
    end

    spec.Refresh()
    return settingsSearchRuntime.registerSpec(spec)
end

local function createDynamicDropdown(parent, labelText, optionsProvider, getter, setter, onApply)
    local label = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
    label:SetText(labelText)

    local dropdown = CreateFrame("Frame", nil, parent, "UIDropDownMenuTemplate")
    ensureSettingsWindowDropdownChrome(dropdown)

    local function getOptions()
        local options = optionsProvider and optionsProvider() or {}
        if #options == 0 then
            options = { { label = "None", value = "" } }
        end
        return options
    end

    local function refreshSelection(options)
        local selectedValue = getter and getter() or ""
        local selectedLabel = nil
        for _, option in ipairs(options) do
            if option.value == selectedValue then
                selectedLabel = option.label
                break
            end
        end

        if not selectedLabel then
            local first = options[1]
            selectedValue = first and first.value or ""
            selectedLabel = first and first.label or ""
            if setter then setter(selectedValue) end
        end

        UIDropDownMenu_SetSelectedValue(dropdown, selectedValue)
        UIDropDownMenu_SetText(dropdown, selectedLabel)
    end

    UIDropDownMenu_Initialize(dropdown, function(_, level)
        local options = getOptions()
        local selectedValue = getter and getter() or ""
        for _, option in ipairs(options) do
            local info = UIDropDownMenu_CreateInfo()
            info.text = option.label
            info.checked = selectedValue == option.value
            info.func = function()
                if setter then setter(option.value) end
                UIDropDownMenu_SetSelectedValue(dropdown, option.value)
                UIDropDownMenu_SetText(dropdown, option.label)
                if onApply then onApply() end
            end
            UIDropDownMenu_AddButton(info, level)
        end
    end)

    local spec = { kind = "dropdown", label = label, control = dropdown }
    spec.Refresh = function()
        refreshSelection(getOptions())
    end

    spec.Refresh()
    return settingsSearchRuntime.registerSpec(spec)
end

local function createPremiumSegmentedChoice(parent, labelText, key, choices, onApply, opts)
    opts = type(opts) == "table" and opts or {}
    local semantic = string.lower(trim(tostring(opts.semantic or "")))
    if semantic ~= "toggle" and semantic ~= "selection" then
        semantic = "selection"
    end
    local searchChoiceLabelMode = settingsSearchRuntime.normalizeChoiceLabelMode(opts.searchChoiceLabelMode)
    local selectionVariant = tostring(opts.selectionVariant or "")
    local controlHeight = math.max(16, tonumber(opts.controlHeight) or 22)
    local controlTextSize = math.max(9, tonumber(opts.textSize) or 11)
    local textEllipsis = opts.textEllipsis and true or false
    local controlMinWidth = math.max(0, tonumber(opts.minWidth) or 120)
    local segmentGap = math.max(0, tonumber(opts.segmentGap) or 4)
    local segmentMinWidth = math.max(20, tonumber(opts.segmentMinWidth) or 48)
    local normalizeValue = type(opts.normalizeValue) == "function" and opts.normalizeValue or nil
    local getValue = type(opts.getValue) == "function" and opts.getValue or nil
    local setValue = type(opts.setValue) == "function" and opts.setValue or nil

    local CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A = 0.10, 0.11, 0.14, 0.95
    local CONTROL_HOVER_BG_R, CONTROL_HOVER_BG_G, CONTROL_HOVER_BG_B, CONTROL_HOVER_BG_A = 0.16, 0.17, 0.20, 0.95
    local CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A = 0.24, 0.27, 0.32, 1.0
    local CONTROL_HOVER_BORDER_R, CONTROL_HOVER_BORDER_G, CONTROL_HOVER_BORDER_B, CONTROL_HOVER_BORDER_A = 0.30, 0.33, 0.38, 1.0
    local OFF_RED_BG_R, OFF_RED_BG_G, OFF_RED_BG_B, OFF_RED_BG_A = 0.23, 0.05, 0.075, 0.93
    local OFF_RED_BORDER_SELECTED_R, OFF_RED_BORDER_SELECTED_G, OFF_RED_BORDER_SELECTED_B, OFF_RED_BORDER_SELECTED_A = 0.22, 0.049, 0.074, 1.0
    local OFF_RED_TEXT_R, OFF_RED_TEXT_G, OFF_RED_TEXT_B, OFF_RED_TEXT_A = 0.90, 0.76, 0.76, 1.0
    local OFF_RED_SELECTED_ALPHA = 0.95
    local OFF_RED_TOPSHEEN_ALPHA = 0.14

    local label = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
    label:SetText(labelText or "")
    local container = CreateFrame("Frame", nil, parent)
    local buttons = {}
    local updateButtonVisual
    local controlEnabled = true
    local choiceEnabledByValue = {}
    local function useSettingsWindowHostTheme()
        return isUsingCustomSettingsWindowVisualStyle(container)
    end

    local function setSegmentBorderColor(btn, r, g, b, a)
        if not btn or not btn._paBorder then
            return
        end
        local colorKey = string.format("%.4f:%.4f:%.4f:%.4f", tonumber(r) or 0, tonumber(g) or 0, tonumber(b) or 0, tonumber(a) or 0)
        if btn._paBorder._paLastBorderColorKey ~= colorKey then
            btn._paBorder:SetBackdropBorderColor(r, g, b, a)
            btn._paBorder._paLastBorderColorKey = colorKey
        end
        btn._paBorder:SetAlpha(1)
        btn._paBorder:Show()
    end

    local function normalizeSegmentValue(v)
        if normalizeValue then
            return normalizeValue(v)
        end
        return v
    end

    local function ensureFlatSkin(btn)
        if not btn then
            return
        end
        if not btn._paSkinReady then
            btn._paSkinReady = true
            btn._paBg = btn:CreateTexture(nil, "ARTWORK")
            btn._paBg:SetAllPoints(btn)
            btn._paBg:SetTexture("Interface\\Buttons\\WHITE8x8")
            btn._paBorder = CreateFrame("Frame", nil, btn, "BackdropTemplate")
            btn._paBorder:SetPoint("TOPLEFT", btn, "TOPLEFT", -1, 1)
            btn._paBorder:SetPoint("BOTTOMRIGHT", btn, "BOTTOMRIGHT", 1, -1)
            btn._paBorder:SetBackdrop({
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
            })
            setSegmentBorderColor(btn, CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A)
            btn._paTopSheen = btn:CreateTexture(nil, "OVERLAY")
            btn._paTopSheen:SetAllPoints(btn)
            btn._paTopSheen:SetTexture("Interface\\Buttons\\WHITE8x8")
            if btn._paTopSheen.SetGradientAlpha then
                btn._paTopSheen:SetGradientAlpha("VERTICAL", 1, 1, 1, 0.12, 1, 1, 1, 0.0)
            else
                btn._paTopSheen:SetVertexColor(1, 1, 1, 0.1)
            end
            btn._paGlow = btn:CreateTexture(nil, "BORDER")
            btn._paGlow:SetAllPoints(btn)
            btn._paGlow:SetTexture("Interface\\Buttons\\WHITE8x8")
            btn._paGlow:SetBlendMode("ADD")
        end

        local n = btn.GetNormalTexture and btn:GetNormalTexture() or nil
        local p = btn.GetPushedTexture and btn:GetPushedTexture() or nil
        local h = btn.GetHighlightTexture and btn:GetHighlightTexture() or nil
        local d = btn.GetDisabledTexture and btn:GetDisabledTexture() or nil
        if n then n:SetAlpha(0); if n.Hide then n:Hide() end end
        if p then p:SetAlpha(0); if p.Hide then p:Hide() end end
        if h then h:SetAlpha(0); if h.Hide then h:Hide() end end
        if d then d:SetAlpha(0); if d.Hide then d:Hide() end end

        for _, part in ipairs({
            "Left", "Middle", "Right",
            "LeftDisabled", "MiddleDisabled", "RightDisabled",
            "LeftHighlight", "MiddleHighlight", "RightHighlight",
            "LeftPressed", "MiddlePressed", "RightPressed",
        }) do
            local tex = btn[part]
            if tex and tex.SetAlpha then tex:SetAlpha(0) end
            if tex and tex.Hide then tex:Hide() end
        end

        if btn._paBorder then
            local baseLevel = btn:GetFrameLevel() or 0
            btn._paBorder:SetFrameStrata(btn:GetFrameStrata())
            btn._paBorder:SetFrameLevel(baseLevel + 3)
        end
    end

    local function scalePressOffset(btn, value)
        local v = tonumber(value) or 0
        if v == 0 then
            return 0
        end
        if not btn or not btn.GetEffectiveScale then
            return v
        end
        local scale = btn:GetEffectiveScale() or 1
        if scale == 0 then
            return v
        end
        local absV = math.abs(v)
        if absV < 0.5 then
            absV = 0.5
        end
        local sign = (v < 0) and -1 or 1
        return (absV / scale) * sign
    end

    local function setSegmentTextOffset(btn, x, y)
        if not btn or not btn.Text then
            return
        end
        local offsetX = scalePressOffset(btn, x)
        local offsetY = scalePressOffset(btn, y)
        btn.Text:ClearAllPoints()
        btn.Text:SetPoint("CENTER", btn, "CENTER", offsetX, offsetY)
    end

    local function resolvePressTextOffsetX()
        local override = tonumber(opts.pressTextOffsetX)
        if override then
            return override
        end
        if semantic == "selection" and selectionVariant == "lock_meta" then
            return 0.30
        end
        return 0.30
    end

    local function resolvePressTextOffsetY()
        local override = tonumber(opts.pressTextOffsetY)
        if override then
            return override
        end
        if semantic == "selection" and selectionVariant == "lock_meta" then
            return -0.30
        end
        return -0.30
    end

    local PRESS_TEXT_OFFSET_X = resolvePressTextOffsetX()
    local PRESS_TEXT_OFFSET_Y = resolvePressTextOffsetY()

    local function clearSegmentPressState(selfBtn)
        if not selfBtn then
            return
        end
        selfBtn._paPressed = false
        setSegmentTextOffset(selfBtn, 0, 0)
        if useSettingsWindowHostTheme() and selfBtn.SetPushedTextOffset then
            selfBtn:SetPushedTextOffset(0, 0)
        end
    end

    updateButtonVisual = function(btn, selected)
        if not btn then return end
        local hovered = btn._paHovered and true or false
        local toggleState = btn._toggleState or "on"
        local choiceEnabled = (choiceEnabledByValue[btn._value] ~= false)
        local useHostVisuals = useSettingsWindowHostTheme()
        local useHostToggleTheme = useHostVisuals and semantic == "toggle"
        ensureFlatSkin(btn)

        if useHostToggleTheme then
            local bgColor = hovered and SETTINGS_WINDOW_HOST_COLORS.hoverBg or SETTINGS_WINDOW_HOST_COLORS.idleBg
            local borderColor = hovered and SETTINGS_WINDOW_HOST_COLORS.hoverBorder or SETTINGS_WINDOW_HOST_COLORS.idleBorder
            local textColor = hovered and SETTINGS_WINDOW_HOST_COLORS.hoverText or SETTINGS_WINDOW_HOST_COLORS.idleText

            if (not controlEnabled) or (not choiceEnabled) then
                bgColor = SETTINGS_WINDOW_HOST_COLORS.disabledBg
                borderColor = SETTINGS_WINDOW_HOST_COLORS.disabledBorder
                textColor = SETTINGS_WINDOW_HOST_COLORS.disabledText
                clearSegmentPressState(btn)
                if btn._paGlow then
                    btn._paGlow:SetVertexColor(1, 1, 1, 0)
                end
                if btn._paTopSheen then
                    btn._paTopSheen:SetAlpha(0.05)
                end
                btn:SetAlpha(controlEnabled and 0.72 or 0.58)
            elseif selected then
                if toggleState == "off" then
                    bgColor = SETTINGS_WINDOW_HOST_COLORS.offBg
                    borderColor = SETTINGS_WINDOW_HOST_COLORS.offBorder
                    textColor = SETTINGS_WINDOW_HOST_COLORS.offText
                    if btn._paGlow then
                        btn._paGlow:SetVertexColor(unpackColor(SETTINGS_WINDOW_HOST_COLORS.offBorder))
                        btn._paGlow:SetAlpha(hovered and 0.12 or 0.08)
                    end
                else
                    bgColor = SETTINGS_WINDOW_HOST_COLORS.onBg
                    borderColor = SETTINGS_WINDOW_HOST_COLORS.onBorder
                    textColor = SETTINGS_WINDOW_HOST_COLORS.onText
                    if btn._paGlow then
                        btn._paGlow:SetVertexColor(unpackColor(SETTINGS_WINDOW_HOST_COLORS.onBorder))
                        btn._paGlow:SetAlpha(hovered and 0.16 or 0.10)
                    end
                end
                if btn._paTopSheen then
                    btn._paTopSheen:SetAlpha(hovered and 0.18 or 0.12)
                end
                btn:SetAlpha(1)
            else
                if btn._paGlow then
                    btn._paGlow:SetVertexColor(1, 1, 1, 0)
                end
                if btn._paTopSheen then
                    btn._paTopSheen:SetAlpha(hovered and 0.12 or 0.08)
                end
                btn:SetAlpha(0.98)
            end

            btn._paBg:SetVertexColor(unpackColor(bgColor))
            setSegmentBorderColor(btn, unpackColor(borderColor))
            if btn.Text then
                btn.Text:SetTextColor(unpackColor(textColor))
            end
            return
        end

        if not choiceEnabled then
            clearSegmentPressState(btn)
            btn._paBg:SetVertexColor(CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A)
            if btn._paGlow then
                btn._paGlow:SetVertexColor(1, 1, 1, 0)
            end
            if btn._paTopSheen then
                btn._paTopSheen:SetAlpha(0.04)
            end
            setSegmentBorderColor(btn, CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, 0.72)
            if btn.Text then
                btn.Text:SetTextColor(0.50, 0.50, 0.53, 1)
            end
            btn:SetAlpha(controlEnabled and 0.52 or 0.45)
            return
        end

        if semantic == "toggle" then
            if selected then
                if toggleState == "on" then
                    if hovered then
                        btn._paBg:SetVertexColor(0.13, 0.28, 0.15, 0.98)
                    else
                        btn._paBg:SetVertexColor(0.11, 0.23, 0.13, 0.96)
                    end
                    if btn._paGlow then
                        btn._paGlow:SetVertexColor(0.28, 1.0, 0.36, hovered and 0.14 or 0.1)
                    end
                    if btn.Text then
                        btn.Text:SetTextColor(0.72, 1.0, 0.74, 1)
                    end
                    setSegmentBorderColor(btn, 0.18, 0.55, 0.2, hovered and 0.95 or 0.82)
                    if btn._paTopSheen then
                        btn._paTopSheen:SetAlpha(0.22)
                    end
                else
                    btn._paBg:SetVertexColor(OFF_RED_BG_R, OFF_RED_BG_G, OFF_RED_BG_B, OFF_RED_BG_A)
                    if btn._paGlow then
                        btn._paGlow:SetVertexColor(0.95, 0.22, 0.22, 0)
                    end
                    if btn.Text then
                        btn.Text:SetTextColor(OFF_RED_TEXT_R, OFF_RED_TEXT_G, OFF_RED_TEXT_B, OFF_RED_TEXT_A)
                    end
                    setSegmentBorderColor(btn, OFF_RED_BORDER_SELECTED_R, OFF_RED_BORDER_SELECTED_G, OFF_RED_BORDER_SELECTED_B, OFF_RED_BORDER_SELECTED_A)
                    if btn._paTopSheen then
                        btn._paTopSheen:SetAlpha(OFF_RED_TOPSHEEN_ALPHA)
                    end
                end
            else
                if hovered then
                    btn._paBg:SetVertexColor(CONTROL_HOVER_BG_R, CONTROL_HOVER_BG_G, CONTROL_HOVER_BG_B, CONTROL_HOVER_BG_A)
                else
                    btn._paBg:SetVertexColor(CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A)
                end
                if btn._paGlow then
                    btn._paGlow:SetVertexColor(1, 1, 1, 0)
                end
                if btn.Text then
                    btn.Text:SetTextColor(0.85, 0.85, 0.88, 1)
                end
                if hovered then
                    setSegmentBorderColor(btn, CONTROL_HOVER_BORDER_R, CONTROL_HOVER_BORDER_G, CONTROL_HOVER_BORDER_B, CONTROL_HOVER_BORDER_A)
                else
                    setSegmentBorderColor(btn, CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A)
                end
                if btn._paTopSheen then
                    btn._paTopSheen:SetAlpha(hovered and 0.12 or 0.08)
                end
            end
            if selected and toggleState ~= "on" then
                btn:SetAlpha(OFF_RED_SELECTED_ALPHA)
            else
                btn:SetAlpha(0.98)
            end
        else
            if selected then
                local useLockMetaVariant = (selectionVariant == "lock_meta")
                if useHostVisuals then
                    useLockMetaVariant = false
                end
                if hovered then
                    if useLockMetaVariant then
                        btn._paBg:SetVertexColor(0.28, 0.29, 0.33, 0.98)
                    else
                        btn._paBg:SetVertexColor(0.25, 0.26, 0.30, 0.98)
                    end
                else
                    if useLockMetaVariant then
                        btn._paBg:SetVertexColor(0.25, 0.26, 0.30, 0.96)
                    else
                        btn._paBg:SetVertexColor(0.22, 0.23, 0.27, 0.96)
                    end
                end
                if btn._paGlow then
                    if useLockMetaVariant then
                        btn._paGlow:SetVertexColor(1.0, 0.82, 0.1, 0)
                    else
                        btn._paGlow:SetVertexColor(1.0, 0.82, 0.1, hovered and 0.1 or 0.06)
                    end
                end
                if useLockMetaVariant then
                    if hovered then
                        setSegmentBorderColor(btn, 0.38, 0.41, 0.46, 0.96)
                    else
                        setSegmentBorderColor(btn, 0.34, 0.37, 0.42, 0.90)
                    end
                else
                    setSegmentBorderColor(btn, 0.95, 0.75, 0.2, hovered and 0.95 or 0.82)
                end
                if btn._paTopSheen then
                    if useLockMetaVariant then
                        btn._paTopSheen:SetAlpha(0.28)
                    else
                        btn._paTopSheen:SetAlpha(0.26)
                    end
                end
                btn:SetAlpha(1)
                if btn.Text then
                    if useLockMetaVariant then
                        btn.Text:SetTextColor(0.94, 0.95, 0.97, 1)
                    else
                        btn.Text:SetTextColor(0.99, 0.95, 0.82, 1)
                    end
                end
            else
                if hovered then
                    btn._paBg:SetVertexColor(CONTROL_HOVER_BG_R, CONTROL_HOVER_BG_G, CONTROL_HOVER_BG_B, CONTROL_HOVER_BG_A)
                else
                    btn._paBg:SetVertexColor(CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A)
                end
                if btn._paGlow then
                    btn._paGlow:SetVertexColor(1.0, 0.82, 0.1, 0)
                end
                if hovered then
                    setSegmentBorderColor(btn, CONTROL_HOVER_BORDER_R, CONTROL_HOVER_BORDER_G, CONTROL_HOVER_BORDER_B, CONTROL_HOVER_BORDER_A)
                else
                    setSegmentBorderColor(btn, CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A)
                end
                if btn._paTopSheen then
                    btn._paTopSheen:SetAlpha(hovered and 0.12 or 0.08)
                end
                btn:SetAlpha(0.96)
                if btn.Text then
                    btn.Text:SetTextColor(0.82, 0.83, 0.86, 1)
                end
            end
        end

        if not controlEnabled then
            clearSegmentPressState(btn)
            btn:SetAlpha(0.55)
            if btn.Text then
                btn.Text:SetTextColor(0.62, 0.62, 0.64, 1)
            end
            if btn._paGlow then
                btn._paGlow:SetVertexColor(1, 1, 1, 0)
            end
        end
    end

    local function applySelectionVisual(value)
        local normalizedValue = normalizeSegmentValue(value)
        for _, btn in ipairs(buttons) do
            local selected = (btn._value == normalizedValue)
            btn._selected = selected and true or false
            updateButtonVisual(btn, selected)
        end
    end

    local function setSelectedVisual(value)
        applySelectionVisual(normalizeSegmentValue(value))
    end

    local function setSelected(value, triggerApply)
        local normalizedValue = normalizeSegmentValue(value)
        if setValue then
            setValue(normalizedValue)
        elseif key ~= nil then
            PortalAuthorityDB[key] = normalizedValue
        end
        setSelectedVisual(normalizedValue)
        if triggerApply and onApply then
            onApply(normalizedValue)
        end
    end

    for i, choice in ipairs(choices or {}) do
        local choiceValue = normalizeSegmentValue(choice.value)
        local choiceLabel = choice.label
        local choiceToggleState = choice.toggleState
        local btn = CreateFrame("Button", nil, container)
        btn:SetSize(72, controlHeight)
        btn.Text = createStyledFontString(btn, "ARTWORK", "GameFontHighlightSmall", controlTextSize)
        settingsSearchRuntime.markSearchTextOrigin(btn.Text, "choice_caption", {
            searchChoiceLabelMode = searchChoiceLabelMode,
        })
        btn.Text:SetPoint("CENTER", btn, "CENTER", 0, 0)
        btn.Text:SetJustifyH("CENTER")
        btn.Text:SetJustifyV("MIDDLE")
        btn.Text:SetWordWrap(false)
        if btn.Text.SetMaxLines then
            btn.Text:SetMaxLines(1)
        end
        btn._baseLabel = tostring(choiceLabel or "")
        btn.Text:SetText(btn._baseLabel)
        applyGlobalFontToObject(btn.Text, controlTextSize)
        btn._value = choiceValue
        btn._toggleState = tostring(choiceToggleState or "on")
        btn._paHovered = false
        btn._selected = false
        btn._paPressed = false
        if choiceEnabledByValue[choiceValue] == nil then
            choiceEnabledByValue[choiceValue] = true
        end
        ensureFlatSkin(btn)
        btn:HookScript("OnShow", function(selfBtn)
            ensureFlatSkin(selfBtn)
            clearSegmentPressState(selfBtn)
            updateButtonVisual(selfBtn, selfBtn._selected and true or false)
        end)
        btn:HookScript("OnHide", function(selfBtn)
            clearSegmentPressState(selfBtn)
        end)
        btn:SetScript("OnEnter", function(selfBtn)
            if not controlEnabled or choiceEnabledByValue[selfBtn._value] == false then
                selfBtn._paHovered = false
                updateButtonVisual(selfBtn, selfBtn._selected and true or false)
                return
            end
            selfBtn._paHovered = true
            updateButtonVisual(selfBtn, selfBtn._selected and true or false)
        end)
        btn:SetScript("OnLeave", function(selfBtn)
            selfBtn._paHovered = false
            clearSegmentPressState(selfBtn)
            updateButtonVisual(selfBtn, selfBtn._selected and true or false)
        end)
        btn:SetScript("OnMouseDown", function(selfBtn)
            if not controlEnabled then
                return
            end
            if choiceEnabledByValue[selfBtn._value] == false then
                return
            end
            if not useSettingsWindowHostTheme() then
                return
            end
            selfBtn._paPressed = true
            setSegmentTextOffset(selfBtn, PRESS_TEXT_OFFSET_X, PRESS_TEXT_OFFSET_Y)
            updateButtonVisual(selfBtn, selfBtn._selected and true or false)
        end)
        btn:SetScript("OnMouseUp", function(selfBtn)
            clearSegmentPressState(selfBtn)
            updateButtonVisual(selfBtn, selfBtn._selected and true or false)
        end)
        btn:SetScript("OnClick", function()
            if not controlEnabled then
                return
            end
            if choiceEnabledByValue[choiceValue] == false then
                return
            end
            if btn._selected then
                return
            end
            setSelected(choiceValue, true)
        end)
        buttons[i] = btn
    end

    local spec = { kind = "segmented", label = label, control = container, buttons = buttons }
    spec.Layout = function(_, width)
        local count = #buttons
        if count <= 0 then
            container:SetSize(width or 0, controlHeight)
            return
        end
        local gap = segmentGap
        local w = math.max(controlMinWidth, tonumber(width) or controlMinWidth)
        local btnW = math.max(segmentMinWidth, (w - ((count - 1) * gap)) / count)
        local x = 0
        container:SetSize(w, controlHeight)
        for _, btn in ipairs(buttons) do
            btn:ClearAllPoints()
            btn:SetPoint("TOPLEFT", container, "TOPLEFT", x, 0)
            btn:SetSize(btnW, controlHeight)
            if btn.Text then
                btn.Text:ClearAllPoints()
                btn.Text:SetPoint("CENTER", btn, "CENTER", 0, 0)
                btn.Text:SetJustifyH("CENTER")
                btn.Text:SetJustifyV("MIDDLE")
                btn.Text:SetWidth(math.max(1, btnW - 8))
                if textEllipsis and type(setSingleLineEllipsis) == "function" then
                    setSingleLineEllipsis(btn.Text, btn._baseLabel or "", math.max(1, btnW - 8))
                else
                    btn.Text:SetText(btn._baseLabel or "")
                end
            end
            updateButtonVisual(btn, btn._selected and true or false)
            x = x + btnW + gap
        end
    end
    spec.Refresh = function()
        local selectedRaw
        if getValue then
            selectedRaw = getValue()
        elseif key ~= nil then
            selectedRaw = PortalAuthorityDB[key]
        end
        local selected = normalizeSegmentValue(selectedRaw)
        local valid = false
        local function isChoiceValue(candidate)
            local normalizedCandidate = normalizeSegmentValue(candidate)
            for _, choice in ipairs(choices or {}) do
                if normalizeSegmentValue(choice.value) == normalizedCandidate then
                    return true
                end
            end
            return false
        end
        for _, choice in ipairs(choices or {}) do
            if normalizeSegmentValue(choice.value) == selected then
                valid = true
                break
            end
        end
        if not valid then
            local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
            local fallback = defaults[key]
            if isChoiceValue(fallback) then
                selected = normalizeSegmentValue(fallback)
            else
                selected = choices and choices[1] and normalizeSegmentValue(choices[1].value) or nil
            end
            if selected ~= nil then
                if setValue then
                    setValue(selected)
                elseif key ~= nil then
                    PortalAuthorityDB[key] = selected
                end
            end
        end
        if selected ~= nil then
            setSelectedVisual(selected)
        end
    end
    spec.SetVisualSelectedValue = function(_, value)
        setSelectedVisual(value)
    end
    spec.GetSelectedValue = function()
        for _, btn in ipairs(buttons) do
            if btn and btn._selected then
                return btn._value
            end
        end
        if getValue then
            return normalizeSegmentValue(getValue())
        end
        if key ~= nil then
            return normalizeSegmentValue(PortalAuthorityDB[key])
        end
        return nil
    end
    spec.SetSelectedValue = function(_, value, triggerApply)
        setSelected(value, triggerApply and true or false)
    end
    spec.SetChoiceEnabled = function(_, value, enabled)
        local normalizedValue = normalizeSegmentValue(value)
        choiceEnabledByValue[normalizedValue] = enabled and true or false
        for _, btn in ipairs(buttons) do
            if btn._value == normalizedValue then
                btn._paHovered = false
                clearSegmentPressState(btn)
            end
            updateButtonVisual(btn, btn._selected and true or false)
        end
    end
    spec.IsChoiceEnabled = function(_, value)
        local normalizedValue = normalizeSegmentValue(value)
        return choiceEnabledByValue[normalizedValue] ~= false
    end
    spec.SetEnabled = function(_, enabled)
        controlEnabled = enabled and true or false
        for _, btn in ipairs(buttons) do
            btn:SetEnabled(controlEnabled)
            clearSegmentPressState(btn)
        end
        local selected = nil
        for _, btn in ipairs(buttons) do
            if btn._selected then
                selected = btn._value
                break
            end
        end
        if selected ~= nil then
            setSelectedVisual(selected)
        else
            spec.Refresh()
        end
        label:SetAlpha(controlEnabled and 1 or 0.65)
    end
    spec.IsEnabled = function()
        return controlEnabled
    end
    spec.RefreshVisual = function()
        for _, btn in ipairs(buttons) do
            updateButtonVisual(btn, btn._selected and true or false)
        end
        label:SetAlpha(controlEnabled and 1 or 0.65)
    end
    registerSettingsWindowVisualRefresh(container, function()
        spec:RefreshVisual()
    end)
    spec.Refresh()
    return settingsSearchRuntime.registerSpec(spec, semantic == "toggle" and "toggle" or spec.kind)
end

ACTIVE_PORTAL_PICKER = nil

local function CreatePicker(parent, options, onSelectCallback, uiConfig)
    uiConfig = type(uiConfig) == "table" and uiConfig or {}
    local preserveOrder = uiConfig.preserveOrder and true or false
    local noSearch = uiConfig.noSearch and true or false
    local hideTitle = uiConfig.hideTitle and true or false
    local hideScrollBar = uiConfig.hideScrollBar and true or false
    local showClearButton = uiConfig.showClearButton ~= false
    local showCloseButton = uiConfig.showCloseButton ~= false
    local footerFlowWithRows = uiConfig.footerFlowWithRows and true or false
    local onOptionRightClick = type(uiConfig.onOptionRightClick) == "function" and uiConfig.onOptionRightClick or nil
    local footerHintText = tostring(uiConfig.footerHint or "")
    local minPickerHeight = math.max(120, math.floor(tonumber(uiConfig.minHeight) or 220))

    local picker = CreateFrame("Frame", nil, parent or UIParent, "BackdropTemplate")
    picker:SetFrameStrata("DIALOG")
    picker:SetToplevel(true)
    picker:SetClampedToScreen(true)
    picker:EnableMouseWheel(true)
    picker:SetSize(
        math.max(260, math.floor(tonumber(uiConfig.width) or 520)),
        math.max(minPickerHeight, math.floor(tonumber(uiConfig.height) or 420))
    )
    picker:Hide()
    picker:SetBackdrop({
        bgFile = "Interface\\Buttons\\WHITE8x8",
        edgeFile = "Interface\\Tooltips\\UI-Tooltip-Border",
        edgeSize = 12,
        insets = { left = 3, right = 3, top = 3, bottom = 3 },
    })
    picker:SetBackdropColor(0.05, 0.06, 0.08, 0.98)
    picker:SetBackdropBorderColor(0.32, 0.35, 0.4, 1)

    local title = createStyledFontString(picker, "ARTWORK", "GameFontHighlight", 12)
    title:SetText(tostring(uiConfig.title or "Select Destination"))
    title:SetPoint("TOPLEFT", picker, "TOPLEFT", 16, -12)

    local search = CreateFrame("EditBox", nil, picker, "InputBoxTemplate")
    search:SetAutoFocus(false)
    search:SetTextInsets(8, 8, 0, 0)
    search:SetTextColor(1, 1, 1, 1)
    search:SetHighlightColor(1, 1, 1, 0.25)
    search:SetPoint("TOPLEFT", picker, "TOPLEFT", 14, -34)
    search:SetPoint("TOPRIGHT", picker, "TOPRIGHT", -14, -34)
    search:SetHeight(22)
    search:EnableMouseWheel(true)
    applyGlobalFontToObject(search, 12)

    local searchHint = createStyledFontString(picker, "ARTWORK", "GameFontHighlightSmall", 11)
    searchHint:SetText(tostring(uiConfig.searchHint or "Search destinations (name, short, spell ID)"))
    searchHint:SetTextColor(0.72, 0.72, 0.72, 1)
    searchHint:SetPoint("TOPLEFT", search, "BOTTOMLEFT", 2, -4)

    local footerHint = createStyledFontString(picker, "ARTWORK", "GameFontHighlightSmall", 10)
    footerHint:SetJustifyH("LEFT")
    footerHint:SetTextColor(0.72, 0.72, 0.72, 0.92)
    footerHint:SetWordWrap(false)
    if footerHint.SetMaxLines then
        footerHint:SetMaxLines(1)
    end
    footerHint:SetText(footerHintText)
    if footerHintText == "" then
        footerHint:Hide()
    else
        footerHint:Show()
    end

    local scroll = CreateFrame("ScrollFrame", nil, picker, "UIPanelScrollFrameTemplate")
    local scrollTopOffset = -72
    if noSearch and hideTitle then
        scrollTopOffset = -14
    elseif noSearch then
        scrollTopOffset = -34
    end
    local scrollChildRightInset = hideScrollBar and 4 or 20
    local scrollRightInset = hideScrollBar and 14 or 34
    scroll:SetPoint("TOPLEFT", picker, "TOPLEFT", 14, scrollTopOffset)
    scroll:SetPoint("BOTTOMRIGHT", picker, "BOTTOMRIGHT", -scrollRightInset, 48)
    scroll:EnableMouseWheel(true)
    if hideScrollBar and scroll.ScrollBar then
        scroll.ScrollBar:Hide()
        scroll.ScrollBar:SetAlpha(0)
        scroll.ScrollBar:EnableMouse(false)
        scroll.ScrollBar:SetScript("OnShow", function(selfBar)
            selfBar:Hide()
        end)
    end

    local scrollChild = CreateFrame("Frame", nil, scroll)
    scrollChild:SetSize(1, 1)
    scroll:SetScrollChild(scrollChild)
    scroll:SetScript("OnSizeChanged", function(selfScroll, width)
        local childWidth = math.max(1, math.floor((width or 1) - scrollChildRightInset))
        scrollChild:SetWidth(childWidth)
        if picker and picker.RenderRows then
            picker:RenderRows()
        end
    end)
    scrollChild:SetWidth(math.max(1, math.floor((scroll:GetWidth() or 1) - scrollChildRightInset)))

    local clearButton = createActionButton(picker, tostring(uiConfig.clearButtonText or "Clear"), nil, 80)
    clearButton:SetPoint("BOTTOMLEFT", picker, "BOTTOMLEFT", 14, 14)
    clearButton:EnableMouseWheel(true)
    local closeButton = createActionButton(picker, tostring(uiConfig.closeButtonText or "Close"), nil, 80)
    closeButton:SetPoint("BOTTOMRIGHT", picker, "BOTTOMRIGHT", -14, 14)
    closeButton:EnableMouseWheel(true)

    if not showClearButton then
        clearButton:Hide()
    end
    if not showCloseButton then
        closeButton:Hide()
    end

    local function applyPickerFooterButtonStyle(btn)
        if not btn then
            return
        end
        if not btn._paPickerFooterStyled then
            btn._paPickerFooterStyled = true
            btn._paBg = btn:CreateTexture(nil, "ARTWORK")
            btn._paBg:SetAllPoints(btn)
            btn._paBg:SetTexture("Interface\\Buttons\\WHITE8x8")
            btn._paBg:SetVertexColor(0.11, 0.12, 0.15, 0.95)
            btn._paHovered = false
            btn._paPressed = false

            if btn.Text then
                applyGlobalFontToObject(btn.Text, 11)
                btn.Text:SetTextColor(0.92, 0.92, 0.92, 1)
            end
        end

        local function hideTemplateChrome()
            local n = btn.GetNormalTexture and btn:GetNormalTexture() or nil
            local p = btn.GetPushedTexture and btn:GetPushedTexture() or nil
            local h = btn.GetHighlightTexture and btn:GetHighlightTexture() or nil
            local d = btn.GetDisabledTexture and btn:GetDisabledTexture() or nil
            if n then n:SetAlpha(0); if n.Hide then n:Hide() end end
            if p then p:SetAlpha(0); if p.Hide then p:Hide() end end
            if h then h:SetAlpha(0); if h.Hide then h:Hide() end end
            if d then d:SetAlpha(0); if d.Hide then d:Hide() end end

            local skinParts = {
                "Left", "Middle", "Right",
                "LeftDisabled", "MiddleDisabled", "RightDisabled",
                "LeftHighlight", "MiddleHighlight", "RightHighlight",
                "LeftPressed", "MiddlePressed", "RightPressed",
            }
            for _, part in ipairs(skinParts) do
                local tex = btn[part]
                if tex and tex.SetAlpha then tex:SetAlpha(0) end
                if tex and tex.Hide then tex:Hide() end
            end
        end

        local function refreshVisual()
            hideTemplateChrome()
            if not btn:IsEnabled() then
                btn._paBg:SetVertexColor(0.08, 0.09, 0.11, 0.7)
                if btn.Text then
                    btn.Text:SetTextColor(0.55, 0.55, 0.58, 1)
                end
                return
            end

            if btn._paPressed then
                btn._paBg:SetVertexColor(0.08, 0.09, 0.12, 0.98)
                if btn.Text then
                    btn.Text:SetTextColor(1, 0.85, 0.18, 1)
                end
            elseif btn._paHovered then
                btn._paBg:SetVertexColor(0.14, 0.15, 0.19, 0.98)
                if btn.Text then
                    btn.Text:SetTextColor(1, 0.9, 0.35, 1)
                end
            else
                btn._paBg:SetVertexColor(0.11, 0.12, 0.15, 0.95)
                if btn.Text then
                    btn.Text:SetTextColor(0.92, 0.92, 0.92, 1)
                end
            end
        end

        btn:HookScript("OnEnter", function(selfBtn)
            selfBtn._paHovered = true
            refreshVisual()
        end)
        btn:HookScript("OnLeave", function(selfBtn)
            selfBtn._paHovered = false
            selfBtn._paPressed = false
            refreshVisual()
        end)
        btn:HookScript("OnMouseDown", function(selfBtn)
            selfBtn._paPressed = true
            refreshVisual()
        end)
        btn:HookScript("OnMouseUp", function(selfBtn)
            selfBtn._paPressed = false
            refreshVisual()
        end)
        btn:HookScript("OnShow", function()
            refreshVisual()
        end)
        refreshVisual()
    end

    applyPickerFooterButtonStyle(clearButton)
    applyPickerFooterButtonStyle(closeButton)

    picker.search = search
    picker.scroll = scroll
    picker.scrollChild = scrollChild
    picker.title = title
    picker.searchHint = searchHint
    picker.footerHint = footerHint
    picker.clearButton = clearButton
    picker.closeButton = closeButton
    picker._onSelect = onSelectCallback
    picker._allOptions = {}
    picker._filteredOptions = {}
    picker._rows = {}
    picker._selectedValue = nil
    picker._highlightedIndex = 0
    picker._query = ""
    picker._showSecondary = uiConfig.showSecondary ~= false
    picker._useOptionFontPreview = uiConfig.useOptionFontPreview and true or false
    picker._useOptionTexturePreview = uiConfig.useOptionTexturePreview and true or false
    picker._previewFontSize = math.max(8, math.floor(tonumber(uiConfig.previewFontSize) or 12))
    picker._rowHeight = math.max(20, math.floor(tonumber(uiConfig.rowHeight) or (picker._showSecondary and 34 or 26)))
    picker._minHeight = minPickerHeight
    picker._filterToken = 0
    picker._noSearch = noSearch
    picker._onOptionRightClick = onOptionRightClick
    picker._footerPulseActive = false
    picker._footerPulseElapsed = 0
    picker._footerPulseCycles = 2
    picker._footerPulseCycleDuration = 0.65
    picker._footerPulseMinAlpha = 0.78
    picker._footerPulseMaxAlpha = 1.00
    picker._footerHintIdleAlpha = 0.95
    picker._previewFlashDuration = 0.24
    picker._hasPreviewFlash = false
    picker._transientTickerActive = false
    picker._anchorFrame = nil
    picker._anchorHideHookFrames = {}
    picker._showClearButton = showClearButton
    picker._showCloseButton = showCloseButton
    picker._footerFlowWithRows = footerFlowWithRows
    picker._scrollTopOffset = scrollTopOffset
    picker._scrollRightInset = scrollRightInset
    picker._scrollChildRightInset = scrollChildRightInset
    picker._ellipsizeRows = uiConfig.ellipsizeRows and true or false

    if hideTitle then
        title:SetText("")
        title:Hide()
    else
        title:Show()
    end
    if noSearch then
        search:SetText("")
        search:ClearFocus()
        search:Hide()
        searchHint:Hide()
    else
        search:Show()
        searchHint:Show()
    end

    function picker:LayoutChrome(contentHeight)
        local footerVisible = footerHint and footerHint:IsShown()
        local topOffset = self._scrollTopOffset or -72
        local rightInset = self._scrollRightInset or 34
        local footerGap = 8
        local bottomPad = 14
        local footerHeight = footerVisible and math.max(10, footerHint:GetStringHeight() or 0) or 0
        local hasFooterButtons = self._showClearButton or self._showCloseButton

        scroll:ClearAllPoints()
        scroll:SetPoint("TOPLEFT", picker, "TOPLEFT", 14, topOffset)
        scroll:SetPoint("TOPRIGHT", picker, "TOPRIGHT", -rightInset, topOffset)

        if footerVisible then
            footerHint:ClearAllPoints()
        end

        if footerVisible and self._footerFlowWithRows and not hasFooterButtons then
            local pickerHeight = picker:GetHeight() or minPickerHeight
            local topInset = math.abs(topOffset)
            local maxListHeight = math.max(self._rowHeight, pickerHeight - topInset - bottomPad - footerGap - footerHeight)
            local usedListHeight = math.max(self._rowHeight, math.min(contentHeight or maxListHeight, maxListHeight))
            scroll:SetHeight(usedListHeight)
            footerHint:SetPoint("TOPLEFT", picker, "TOPLEFT", 14, topOffset - usedListHeight - footerGap)
            footerHint:SetPoint("TOPRIGHT", picker, "TOPRIGHT", -14, topOffset - usedListHeight - footerGap)
        else
            local bottomOffset = 14
            if hasFooterButtons then
                bottomOffset = 48
            elseif footerVisible then
                bottomOffset = 32
            end
            scroll:SetPoint("BOTTOMRIGHT", picker, "BOTTOMRIGHT", -rightInset, bottomOffset)
            if footerVisible then
                local footerBottom = hasFooterButtons and 39 or 14
                footerHint:SetPoint("BOTTOMLEFT", picker, "BOTTOMLEFT", 14, footerBottom)
                footerHint:SetPoint("BOTTOMRIGHT", picker, "BOTTOMRIGHT", -14, footerBottom)
            end
        end
    end

    local function clearTable(t)
        for k in pairs(t) do
            t[k] = nil
        end
    end

    local function lowerString(text)
        return string.lower(tostring(text or ""))
    end

    local function trimString(text)
        if type(text) ~= "string" then
            return ""
        end
        local cleaned = text:gsub("^%s+", ""):gsub("%s+$", "")
        return cleaned
    end

    local function minScore(current, nextScore)
        if nextScore == nil then
            return current
        end
        if current == nil or nextScore < current then
            return nextScore
        end
        return current
    end

    local function textMatchScore(haystack, needle, prefixScore, substringScore)
        if haystack == nil or haystack == "" or needle == nil or needle == "" then
            return nil
        end
        if haystack:sub(1, #needle) == needle then
            return prefixScore
        end
        if haystack:find(needle, 1, true) then
            return substringScore
        end
        return nil
    end

    local function highlightMatch(text, query)
        text = tostring(text or "")
        query = tostring(query or "")
        if query == "" then
            return text
        end
        local lowerText = lowerString(text)
        local startPos = lowerText:find(query, 1, true)
        if not startPos then
            return text
        end
        local endPos = startPos + #query - 1
        return string.format("%s|cffffd100%s|r%s", text:sub(1, startPos - 1), text:sub(startPos, endPos), text:sub(endPos + 1))
    end

    local function scoreOption(option, query)
        if query == "" then
            return 0
        end
        local best = nil
        best = minScore(best, textMatchScore(option._labelLower, query, 0, 20))
        best = minScore(best, textMatchScore(option._secondaryLower, query, 30, 45))
        for _, alias in ipairs(option._aliasesLower) do
            best = minScore(best, textMatchScore(alias, query, 10, 25))
        end
        return best
    end

    picker.rowPool = CreateFramePool("Button", scrollChild, nil, function(_, row)
        row:Hide()
        row:ClearAllPoints()
        row._index = nil
        row._option = nil
        row._hovered = false
        row._isNoMatch = false
        row._disabled = false
        row._previewFlashUntil = nil
        row:EnableMouse(true)
        row:SetAlpha(1)
        if row.primary then
            row.primary:SetText("")
            row.primary:SetTextColor(1, 1, 1, 1)
            applyGlobalFontToObject(row.primary, picker._previewFontSize)
        end
        if row.secondary then
            row.secondary:SetText("")
            row.secondary:SetTextColor(0.72, 0.72, 0.72, 1)
            if picker._showSecondary then
                row.secondary:Show()
            else
                row.secondary:Hide()
            end
        end
        if row.previewFrame then
            row.previewFrame:Hide()
        end
        if row.bg then
            row.bg:SetVertexColor(1, 1, 1, 0)
        end
    end)

    local function updateRowVisual(row)
        if not row or not row.bg then
            return
        end
        local now = (GetTime and GetTime()) or 0
        if row._previewFlashUntil and now < row._previewFlashUntil then
            local flashDuration = picker._previewFlashDuration or 0.24
            local remaining = math.max(0, row._previewFlashUntil - now)
            local t = (flashDuration > 0) and (remaining / flashDuration) or 0
            local alpha = 0.10 + (0.18 * t)
            row.bg:SetVertexColor(1.00, 0.82, 0.20, alpha)
            return
        elseif row._previewFlashUntil then
            row._previewFlashUntil = nil
        end
        if row._isNoMatch then
            row.bg:SetVertexColor(1, 1, 1, 0)
            return
        end
        if row._disabled then
            if row._hovered then
                row.bg:SetVertexColor(1, 1, 1, 0.06)
            else
                row.bg:SetVertexColor(1, 1, 1, 0)
            end
            return
        end
        local isSelected = row._index == picker._highlightedIndex
        if isSelected then
            row.bg:SetVertexColor(0.18, 0.55, 1, 0.25)
        elseif row._hovered then
            row.bg:SetVertexColor(1, 1, 1, 0.12)
        else
            row.bg:SetVertexColor(1, 1, 1, 0)
        end
    end

    local function refreshAllRowVisuals()
        for _, row in pairs(picker._rows) do
            updateRowVisual(row)
        end
    end

    local function setFooterHintAlpha(alpha)
        if not footerHint or not footerHint:IsShown() then
            return
        end
        footerHint:SetTextColor(0.72, 0.72, 0.72, alpha or 0.92)
    end

    local function stopFooterPulse()
        picker._footerPulseActive = false
        picker._footerPulseElapsed = 0
        setFooterHintAlpha(picker._footerHintIdleAlpha or 0.95)
    end

    local function ensureTransientTicker()
        if picker._transientTickerActive then
            return
        end
        picker._transientTickerActive = true
        picker:SetScript("OnUpdate", function(selfPicker, elapsed)
            local keepTicking = false

            if selfPicker._footerPulseActive then
                local cycleDuration = selfPicker._footerPulseCycleDuration or 0.65
                local totalCycles = selfPicker._footerPulseCycles or 2
                local totalDuration = math.max(0.01, cycleDuration * totalCycles)
                selfPicker._footerPulseElapsed = (selfPicker._footerPulseElapsed or 0) + (elapsed or 0)
                if selfPicker._footerPulseElapsed >= totalDuration then
                    stopFooterPulse()
                else
                    local inCycle = (selfPicker._footerPulseElapsed % cycleDuration) / cycleDuration
                    local wave = 0.5 - (0.5 * math.cos(inCycle * (math.pi * 2)))
                    local minAlpha = selfPicker._footerPulseMinAlpha or 0.78
                    local maxAlpha = selfPicker._footerPulseMaxAlpha or 1.00
                    local alpha = minAlpha + ((maxAlpha - minAlpha) * wave)
                    setFooterHintAlpha(alpha)
                    keepTicking = true
                end
            end

            if selfPicker._hasPreviewFlash then
                local now = (GetTime and GetTime()) or 0
                local anyFlashActive = false
                for _, row in pairs(selfPicker._rows) do
                    if row and row._previewFlashUntil and now < row._previewFlashUntil then
                        anyFlashActive = true
                        break
                    end
                end
                refreshAllRowVisuals()
                if anyFlashActive then
                    keepTicking = true
                else
                    selfPicker._hasPreviewFlash = false
                end
            end

            if not keepTicking then
                selfPicker._transientTickerActive = false
                selfPicker:SetScript("OnUpdate", nil)
            end
        end)
    end

    local function ensureAnchorHideHook(anchorFrame)
        if not anchorFrame or not anchorFrame.HookScript then
            return
        end
        if picker._anchorHideHookFrames[anchorFrame] then
            return
        end
        picker._anchorHideHookFrames[anchorFrame] = true
        anchorFrame:HookScript("OnHide", function(hiddenAnchor)
            if picker._anchorFrame ~= hiddenAnchor then
                return
            end
            if picker and picker.IsShown and picker:IsShown() and picker.Close then
                picker:Close()
            end
        end)
    end

    local PICKER_TEXTURE_PREVIEW_WIDTH = 92
    local PICKER_TEXTURE_PREVIEW_HEIGHT = 12

    local function layoutPickerRowContent(row, hasTexturePreview)
        if not row or not row.primary or not row.secondary then
            return
        end

        row.primary:ClearAllPoints()
        row.secondary:ClearAllPoints()

        if hasTexturePreview and row.previewFrame then
            row.previewFrame:ClearAllPoints()
            row.previewFrame:SetPoint("RIGHT", row, "RIGHT", -8, 0)
            row.previewFrame:SetSize(PICKER_TEXTURE_PREVIEW_WIDTH, PICKER_TEXTURE_PREVIEW_HEIGHT)
            row.previewFrame:Show()
            row.primary:SetPoint("TOPLEFT", row, "TOPLEFT", 8, picker._showSecondary and -4 or -5)
            row.primary:SetPoint("TOPRIGHT", row.previewFrame, "TOPLEFT", -8, picker._showSecondary and -4 or -5)
        else
            if row.previewFrame then
                row.previewFrame:Hide()
            end
            row.primary:SetPoint("TOPLEFT", row, "TOPLEFT", 8, picker._showSecondary and -4 or -5)
            row.primary:SetPoint("TOPRIGHT", row, "TOPRIGHT", -8, picker._showSecondary and -4 or -5)
        end

        row.secondary:SetPoint("TOPLEFT", row.primary, "BOTTOMLEFT", 0, -2)
        if hasTexturePreview and row.previewFrame then
            row.secondary:SetPoint("TOPRIGHT", row.previewFrame, "TOPLEFT", -8, -2)
        else
            row.secondary:SetPoint("TOPRIGHT", row, "TOPRIGHT", -8, -2)
        end
    end

    local function ensureRowWidgets(row)
        if row._paBuilt then
            return
        end
        row._paBuilt = true
        row:SetHeight(picker._rowHeight)

        row.bg = row:CreateTexture(nil, "BACKGROUND")
        row.bg:SetAllPoints()
        row.bg:SetTexture("Interface\\Buttons\\WHITE8x8")
        row.bg:SetVertexColor(1, 1, 1, 0)

        row.primary = createStyledFontString(row, "ARTWORK", "GameFontHighlight", 12)
        row.primary:SetPoint("TOPLEFT", row, "TOPLEFT", 8, picker._showSecondary and -4 or -5)
        row.primary:SetPoint("TOPRIGHT", row, "TOPRIGHT", -8, picker._showSecondary and -4 or -5)
        row.primary:SetJustifyH("LEFT")
        row.primary:SetMaxLines(1)

        row.secondary = createStyledFontString(row, "ARTWORK", "GameFontHighlightSmall", 10)
        row.secondary:SetPoint("TOPLEFT", row.primary, "BOTTOMLEFT", 0, -2)
        row.secondary:SetPoint("TOPRIGHT", row, "TOPRIGHT", -8, -2)
        row.secondary:SetJustifyH("LEFT")
        row.secondary:SetTextColor(0.72, 0.72, 0.72, 1)
        row.secondary:SetMaxLines(1)
        if not picker._showSecondary then
            row.secondary:Hide()
        end

        row.previewFrame = CreateFrame("Frame", nil, row, "BackdropTemplate")
        row.previewFrame:SetBackdrop({
            bgFile = "Interface\\Buttons\\WHITE8x8",
            edgeFile = "Interface\\Buttons\\WHITE8x8",
            edgeSize = 1,
            insets = { left = 0, right = 0, top = 0, bottom = 0 },
        })
        row.previewFrame:EnableMouse(false)
        row.previewFrame:SetBackdropColor(0.09, 0.10, 0.12, 0.98)
        row.previewFrame:SetBackdropBorderColor(0.25, 0.28, 0.33, 0.92)
        row.previewFrame:Hide()

        row.previewBar = CreateFrame("StatusBar", nil, row.previewFrame)
        row.previewBar:EnableMouse(false)
        row.previewBar:SetPoint("TOPLEFT", row.previewFrame, "TOPLEFT", 1, -1)
        row.previewBar:SetPoint("BOTTOMRIGHT", row.previewFrame, "BOTTOMRIGHT", -1, 1)
        row.previewBar:SetMinMaxValues(0, 1)
        row.previewBar:SetValue(0.72)
        row.previewBar:SetStatusBarColor(1.00, 0.82, 0.20, 0.95)
        if row.previewBar.SetReverseFill then
            row.previewBar:SetReverseFill(false)
        end

        row.previewBarBg = row.previewBar:CreateTexture(nil, "BACKGROUND")
        row.previewBarBg:SetAllPoints(row.previewBar)
        row.previewBarBg:SetTexture("Interface\\Buttons\\WHITE8x8")
        row.previewBarBg:SetVertexColor(0.16, 0.18, 0.22, 0.92)

        layoutPickerRowContent(row, false)

        row:SetScript("OnEnter", function(selfRow)
            selfRow._hovered = true
            if not selfRow._isNoMatch and not selfRow._disabled then
                picker._highlightedIndex = selfRow._index or picker._highlightedIndex
            end
            refreshAllRowVisuals()
        end)
        row:SetScript("OnLeave", function(selfRow)
            selfRow._hovered = false
            refreshAllRowVisuals()
        end)
        row:RegisterForClicks("LeftButtonUp", "RightButtonUp")
        row:SetScript("OnClick", function(selfRow, mouseButton)
            if selfRow._isNoMatch then
                return
            end
            local option = selfRow._option
            if not option or option.disabled then
                return
            end
            if mouseButton == "RightButton" and picker._onOptionRightClick then
                if picker._onOptionRightClick then
                    picker._onOptionRightClick(option.value, option, selfRow)
                end
                local now = (GetTime and GetTime()) or 0
                selfRow._previewFlashUntil = now + (picker._previewFlashDuration or 0.24)
                picker._hasPreviewFlash = true
                refreshAllRowVisuals()
                ensureTransientTicker()
                return
            end
            if picker._onSelect and option then
                picker._onSelect(option.value, option, false)
            end
            picker:Close()
        end)
    end

    function picker:SetOnSelect(callback)
        self._onSelect = callback
    end

    function picker:SetSelectedValue(value)
        if value == nil then
            self._selectedValue = nil
            self._selectedValueKey = nil
        else
            self._selectedValue = value
            self._selectedValueKey = tostring(value)
        end
    end

    function picker:RenderRows()
        self.rowPool:ReleaseAll()
        clearTable(self._rows)

        local rowHeight = self._rowHeight
        local y = 0
        local query = self._query

        if #self._filteredOptions == 0 then
            local row = self.rowPool:Acquire()
            ensureRowWidgets(row)
            row:SetPoint("TOPLEFT", self.scrollChild, "TOPLEFT", 0, -y)
            row:SetPoint("TOPRIGHT", self.scrollChild, "TOPRIGHT", 0, -y)
            row:SetHeight(rowHeight)
            row._isNoMatch = true
            row._disabled = false
            row._index = 0
            row.primary:SetText("|cff9a9a9aNo matches|r")
            row.secondary:SetText("")
            layoutPickerRowContent(row, false)
            row:EnableMouse(false)
            row:Show()
            self._rows[1] = row
            y = y + rowHeight
        else
            for index, option in ipairs(self._filteredOptions) do
                local row = self.rowPool:Acquire()
                ensureRowWidgets(row)
                row:SetPoint("TOPLEFT", self.scrollChild, "TOPLEFT", 0, -y)
                row:SetPoint("TOPRIGHT", self.scrollChild, "TOPRIGHT", 0, -y)
                row:SetHeight(rowHeight)
                row._isNoMatch = false
                row._disabled = option.disabled and true or false
                row._index = index
                row._option = option
                if picker._showSecondary then
                    row.secondary:SetText(option.secondary or "")
                    row.secondary:Show()
                else
                    row.secondary:SetText("")
                    row.secondary:Hide()
                end
                if picker._useOptionFontPreview then
                    local previewPath = type(option.previewFontPath) == "string" and option.previewFontPath or ""
                    local applied = false
                    if row.primary.SetFont then
                        applied = row.primary:SetFont(previewPath, picker._previewFontSize, "")
                    end
                    if not applied then
                        applyGlobalFontToObject(row.primary, picker._previewFontSize)
                    end
                else
                    applyGlobalFontToObject(row.primary, 12)
                end
                local hasTexturePreview = picker._useOptionTexturePreview
                    and type(option.previewTexturePath) == "string"
                    and option.previewTexturePath ~= ""
                layoutPickerRowContent(row, hasTexturePreview)
                if picker._ellipsizeRows and query == "" and type(setSingleLineEllipsis) == "function" then
                    local previewInset = hasTexturePreview and (PICKER_TEXTURE_PREVIEW_WIDTH + 8) or 0
                    local primaryWidth = math.max(20, (self.scrollChild:GetWidth() or 0) - 16 - previewInset)
                    row.primary:SetWidth(primaryWidth)
                    setSingleLineEllipsis(row.primary, option.label or "", primaryWidth)
                else
                    row.primary:SetText(highlightMatch(option.label, query))
                end
                if hasTexturePreview and row.previewBar and row.previewBarBg then
                    row.previewBar:SetStatusBarTexture(option.previewTexturePath)
                    row.previewBarBg:SetTexture(option.previewTexturePath)
                    row.previewBar:SetMinMaxValues(0, 1)
                    row.previewBar:SetValue(0.72)
                    row.previewBar:SetStatusBarColor(1.00, 0.82, 0.20, 0.95)
                    row.previewBarBg:SetVertexColor(0.16, 0.18, 0.22, 0.92)
                    if row.previewBar.SetReverseFill then
                        row.previewBar:SetReverseFill(false)
                    end
                end
                row:EnableMouse(true)
                if row._disabled then
                    row:SetAlpha(0.72)
                    row.primary:SetTextColor(0.6, 0.6, 0.6, 1)
                    if picker._showSecondary then
                        row.secondary:SetTextColor(0.5, 0.5, 0.5, 1)
                    end
                else
                    row:SetAlpha(1)
                    row.primary:SetTextColor(1, 1, 1, 1)
                    if picker._showSecondary then
                        row.secondary:SetTextColor(0.72, 0.72, 0.72, 1)
                    end
                end
                row:Show()
                self._rows[index] = row
                y = y + rowHeight
            end
        end

        self:LayoutChrome(y)
        self.scrollChild:SetHeight(math.max(self.scroll:GetHeight(), y))

        refreshAllRowVisuals()
    end

    function picker:EnsureVisible(index)
        local count = #self._filteredOptions
        if count == 0 or index < 1 or index > count then
            return
        end
        local rowHeight = self._rowHeight
        local top = (index - 1) * rowHeight
        local bottom = top + rowHeight
        local current = self.scroll:GetVerticalScroll()
        local viewport = self.scroll:GetHeight()
        if top < current then
            self.scroll:SetVerticalScroll(top)
        elseif bottom > current + viewport then
            self.scroll:SetVerticalScroll(bottom - viewport)
        end
    end

    function picker:MoveHighlight(delta)
        local count = #self._filteredOptions
        if count == 0 then
            return
        end
        local index = self._highlightedIndex
        if index < 1 then
            index = (delta > 0) and 0 or (count + 1)
        end

        local newIndex = index
        while true do
            newIndex = newIndex + delta
            if newIndex < 1 or newIndex > count then
                break
            end
            local option = self._filteredOptions[newIndex]
            if option and not option.disabled then
                self._highlightedIndex = newIndex
                self:EnsureVisible(newIndex)
                break
            end
        end
        refreshAllRowVisuals()
    end

    function picker:SelectHighlighted()
        local count = #self._filteredOptions
        if count == 0 then
            return
        end
        local index = self._highlightedIndex
        if index < 1 or index > count then
            index = 1
        end
        local option = self._filteredOptions[index]
        if option and option.disabled then
            option = nil
            for i = 1, count do
                local candidate = self._filteredOptions[i]
                if candidate and not candidate.disabled then
                    option = candidate
                    index = i
                    break
                end
            end
        end
        if option and self._onSelect then
            self._highlightedIndex = index
            self._onSelect(option.value, option, false)
            self:Close()
        end
    end

    function picker:ApplyFilter(opts)
        opts = type(opts) == "table" and opts or {}
        local query = lowerString(trimString(self.search:GetText() or ""))
        self._query = query
        local preserveScroll = opts.preserveScroll and true or false
        local previousScroll = preserveScroll and (tonumber(self.scroll:GetVerticalScroll()) or 0) or nil
        local previousHighlightedValueKey = nil
        if preserveScroll and self._highlightedIndex and self._highlightedIndex > 0 then
            local previousOption = self._filteredOptions and self._filteredOptions[self._highlightedIndex] or nil
            previousHighlightedValueKey = previousOption and previousOption._valueKey or nil
        end

        local filtered = {}
        for _, option in ipairs(self._allOptions) do
            local score = scoreOption(option, query)
            if query == "" or score ~= nil then
                option._score = score or 0
                table.insert(filtered, option)
            end
        end

        if query == "" then
            if preserveOrder then
                table.sort(filtered, function(a, b)
                    return a._order < b._order
                end)
            else
                table.sort(filtered, function(a, b)
                    local av = tonumber(a.value)
                    local bv = tonumber(b.value)
                    if av and bv and av ~= bv then
                        return av < bv
                    end
                    if av and not bv then return true end
                    if bv and not av then return false end
                    if a._labelLower ~= b._labelLower then
                        return a._labelLower < b._labelLower
                    end
                    return a._order < b._order
                end)
            end
        else
            table.sort(filtered, function(a, b)
                if a._score ~= b._score then
                    return a._score < b._score
                end
                if a._labelLower ~= b._labelLower then
                    return a._labelLower < b._labelLower
                end
                return a._order < b._order
            end)
        end

        self._filteredOptions = filtered
        self._highlightedIndex = 0
        if #filtered > 0 then
            if previousHighlightedValueKey ~= nil then
                for index, option in ipairs(filtered) do
                    if option._valueKey == previousHighlightedValueKey and not option.disabled then
                        self._highlightedIndex = index
                        break
                    end
                end
            end
            if self._selectedValueKey ~= nil then
                if self._highlightedIndex == 0 then
                    for index, option in ipairs(filtered) do
                        if option._valueKey == self._selectedValueKey and not option.disabled then
                            self._highlightedIndex = index
                            break
                        end
                    end
                end
            end
            if self._highlightedIndex == 0 then
                for index, option in ipairs(filtered) do
                    if not option.disabled then
                        self._highlightedIndex = index
                        break
                    end
                end
            end
        end

        self:RenderRows()
        if preserveScroll then
            local maxScroll = math.max(0, (self.scrollChild:GetHeight() or 0) - (self.scroll:GetHeight() or 0))
            local clamped = math.max(0, math.min(previousScroll or 0, maxScroll))
            self.scroll:SetVerticalScroll(clamped)
        else
            self:EnsureVisible(self._highlightedIndex)
        end
    end

    function picker:QueueFilter()
        self._filterToken = self._filterToken + 1
        local token = self._filterToken
        if C_Timer and C_Timer.After then
            C_Timer.After(0.08, function()
                if not picker or not picker:IsShown() then
                    return
                end
                if picker._filterToken ~= token then
                    return
                end
                picker:ApplyFilter()
            end)
        else
            self:ApplyFilter()
        end
    end

    function picker:SetOptions(newOptions)
        local source = type(newOptions) == "table" and newOptions or {}
        local normalizedOptions = {}
        for index, option in ipairs(source) do
            local aliases = {}
            if type(option.aliases) == "table" then
                for _, alias in ipairs(option.aliases) do
                    if trimString(alias) ~= "" then
                        table.insert(aliases, trimString(alias))
                    end
                end
            end
            local normalized = {
                value = option.value,
                label = trimString(option.label or ""),
                secondary = trimString(option.secondary or ""),
                buttonLabel = trimString(option.buttonLabel or option.label or ""),
                previewFontPath = trimString(option.previewFontPath or ""),
                previewTexturePath = trimString(option.previewTexturePath or option.path or ""),
                aliases = aliases,
                disabled = option.disabled and true or false,
                _order = index,
                _valueKey = tostring(option.value or ""),
            }
            normalized._labelLower = lowerString(normalized.label)
            normalized._secondaryLower = lowerString(normalized.secondary)
            normalized._aliasesLower = {}
            for _, alias in ipairs(normalized.aliases) do
                table.insert(normalized._aliasesLower, lowerString(alias))
            end
            table.insert(normalizedOptions, normalized)
        end

        local unchanged = (#self._allOptions == #normalizedOptions)
        if unchanged then
            for index = 1, #normalizedOptions do
                local previous = self._allOptions[index]
                local current = normalizedOptions[index]
                if not previous or not current
                    or previous._valueKey ~= current._valueKey
                    or previous.label ~= current.label
                    or previous.secondary ~= current.secondary
                    or previous.buttonLabel ~= current.buttonLabel
                    or previous.previewFontPath ~= current.previewFontPath
                    or previous.previewTexturePath ~= current.previewTexturePath
                    or previous.disabled ~= current.disabled
                    or #previous.aliases ~= #current.aliases then
                    unchanged = false
                    break
                end
                for aliasIndex = 1, #current.aliases do
                    if previous.aliases[aliasIndex] ~= current.aliases[aliasIndex] then
                        unchanged = false
                        break
                    end
                end
                if not unchanged then
                    break
                end
            end
        end

        if unchanged then
            return
        end

        clearTable(self._allOptions)
        for index, option in ipairs(normalizedOptions) do
            self._allOptions[index] = option
        end
        if self:IsShown() then
            self:ApplyFilter({ preserveScroll = true })
        end
    end

    function picker:Open(anchorFrame)
        if InCombatLockdown and InCombatLockdown() then
            self._pendingOpenAnchor = anchorFrame
            if not self._combatWaitFrame then
                self._combatWaitFrame = CreateFrame("Frame")
                self._combatWaitFrame:SetScript("OnEvent", function()
                    self._combatWaitFrame:UnregisterEvent("PLAYER_REGEN_ENABLED")
                    local pending = self._pendingOpenAnchor
                    self._pendingOpenAnchor = nil
                    self:Open(pending)
                end)
            end
            self._combatWaitFrame:RegisterEvent("PLAYER_REGEN_ENABLED")
            return
        end

        -- Premium popover rule: never allow overlapping pickers.
        if ACTIVE_PORTAL_PICKER and ACTIVE_PORTAL_PICKER ~= self and ACTIVE_PORTAL_PICKER.Close then
            ACTIVE_PORTAL_PICKER:Close()
        end

        self._anchorFrame = anchorFrame
        ensureAnchorHideHook(anchorFrame)
        self:ClearAllPoints()
        if anchorFrame and anchorFrame.GetCenter and anchorFrame:GetCenter() then
            self:SetPoint("TOPLEFT", anchorFrame, "BOTTOMLEFT", 0, -4)
        else
            self:SetPoint("CENTER", UIParent, "CENTER", 0, 0)
        end

        self:Show()
        ACTIVE_PORTAL_PICKER = self
        self:LayoutChrome()
        self.search:SetText("")
        if not self._noSearch then
            self.search:SetFocus()
            self.search:SetCursorPosition(0)
        else
            self.search:ClearFocus()
        end
        stopFooterPulse()
        self:ApplyFilter()
    end

    function picker:Close()
        if self._combatWaitFrame then
            self._combatWaitFrame:UnregisterEvent("PLAYER_REGEN_ENABLED")
        end
        self._pendingOpenAnchor = nil
        self._anchorFrame = nil
        if ACTIVE_PORTAL_PICKER == self then
            ACTIVE_PORTAL_PICKER = nil
        end
        stopFooterPulse()
        self._hasPreviewFlash = false
        for _, row in pairs(self._rows) do
            if row then
                row._previewFlashUntil = nil
            end
        end
        if self._transientTickerActive then
            self._transientTickerActive = false
            self:SetScript("OnUpdate", nil)
        end
        self.search:ClearFocus()
        self:Hide()
    end

    picker:SetScript("OnMouseWheel", function() end)
    search:SetScript("OnMouseWheel", function() end)
    clearButton:SetScript("OnMouseWheel", function() end)
    closeButton:SetScript("OnMouseWheel", function() end)

    search:SetScript("OnTextChanged", function(_, userInput)
        if userInput then
            picker:QueueFilter()
        end
    end)
    search:SetScript("OnEnterPressed", function()
        picker:SelectHighlighted()
    end)
    search:SetScript("OnEscapePressed", function()
        picker:Close()
    end)
    search:SetScript("OnKeyDown", function(_, key)
        if key == "UP" then
            picker:MoveHighlight(-1)
        elseif key == "DOWN" then
            picker:MoveHighlight(1)
        elseif key == "ENTER" or key == "NUMPADENTER" then
            picker:SelectHighlighted()
        elseif key == "ESCAPE" then
            picker:Close()
        end
    end)
    if search.SetPropagateKeyboardInput then
        search:SetPropagateKeyboardInput(false)
    end

    scroll:SetScript("OnMouseWheel", function(selfScroll, delta)
        local current = selfScroll:GetVerticalScroll()
        local nextValue = current - (delta * 24)
        if nextValue < 0 then nextValue = 0 end
        local maxScroll = math.max(0, (picker.scrollChild:GetHeight() or 0) - (selfScroll:GetHeight() or 0))
        if nextValue > maxScroll then nextValue = maxScroll end
        selfScroll:SetVerticalScroll(nextValue)
    end)

    clearButton:SetScript("OnClick", function()
        if picker._onSelect then
            picker._onSelect(nil, nil, true)
        end
        picker:Close()
    end)
    closeButton:SetScript("OnClick", function()
        picker:Close()
    end)

    picker:SetOptions(options or {})
    return picker
end

local function createTextPlacement(parent, onApply)
    local label = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
    local dropdown = CreateFrame("Frame", nil, parent, "UIDropDownMenuTemplate")
    ensureSettingsWindowDropdownChrome(dropdown)

    local function normalizePlacement()
        if PortalAuthorityDB.dockOrientation == "HORIZONTAL" then
            PortalAuthorityDB.dockUseShortNames = true
            if PortalAuthorityDB.dockHorizontalTextPosition ~= "ABOVE" and PortalAuthorityDB.dockHorizontalTextPosition ~= "BELOW" then
                PortalAuthorityDB.dockHorizontalTextPosition = "ABOVE"
            end
        else
            if PortalAuthorityDB.dockVerticalTextSide ~= "LEFT" and PortalAuthorityDB.dockVerticalTextSide ~= "RIGHT" then
                PortalAuthorityDB.dockVerticalTextSide = "LEFT"
            end
        end
    end

    local function getValues()
        if PortalAuthorityDB.dockOrientation == "HORIZONTAL" then
            return { { label = "Above", value = "ABOVE" }, { label = "Below", value = "BELOW" } }
        end
        return { { label = "Left", value = "LEFT" }, { label = "Right", value = "RIGHT" } }
    end

    UIDropDownMenu_Initialize(dropdown, function(_, level)
        normalizePlacement()
        local active = (PortalAuthorityDB.dockOrientation == "HORIZONTAL") and PortalAuthorityDB.dockHorizontalTextPosition or PortalAuthorityDB.dockVerticalTextSide
        for _, option in ipairs(getValues()) do
            local info = UIDropDownMenu_CreateInfo()
            info.text = option.label
            info.checked = active == option.value
            info.func = function()
                if PortalAuthorityDB.dockOrientation == "HORIZONTAL" then
                    PortalAuthorityDB.dockHorizontalTextPosition = option.value
                else
                    PortalAuthorityDB.dockVerticalTextSide = option.value
                end
                UIDropDownMenu_SetSelectedValue(dropdown, option.value)
                UIDropDownMenu_SetText(dropdown, option.label)
                if onApply then onApply() end
            end
            UIDropDownMenu_AddButton(info, level)
        end
    end)

    local spec = { kind = "dropdown", label = label, control = dropdown }
    spec.Refresh = function()
        normalizePlacement()
        if PortalAuthorityDB.dockOrientation == "HORIZONTAL" then
            label:SetText("Text placement")
            local value = PortalAuthorityDB.dockHorizontalTextPosition
            UIDropDownMenu_SetSelectedValue(dropdown, value)
            UIDropDownMenu_SetText(dropdown, value == "BELOW" and "Below" or "Above")
        else
            label:SetText("Text side")
            local value = PortalAuthorityDB.dockVerticalTextSide
            UIDropDownMenu_SetSelectedValue(dropdown, value)
            UIDropDownMenu_SetText(dropdown, value == "RIGHT" and "Right" or "Left")
        end
    end

    spec.Refresh()
    return spec
end

function PortalAuthority:CreateSettingsWindowSegmentedControl(parent, choices, onApply, opts)
    opts = type(opts) == "table" and opts or {}
    local spec = createPremiumSegmentedChoice(
        parent,
        tostring(opts.labelText or ""),
        nil,
        choices or {},
        onApply,
        opts
    )
    if spec and spec.label and trim(tostring(opts.labelText or "")) == "" then
        spec.label:SetText("")
        spec.label:Hide()
    end
    return spec
end

local function createScrollableChild(panel)
    local scrollFrame = CreateFrame("ScrollFrame", nil, panel, "UIPanelScrollFrameTemplate")
    scrollFrame:SetPoint("TOPLEFT", panel, "TOPLEFT", 12, -12)
    scrollFrame:SetPoint("TOPRIGHT", panel, "TOPRIGHT", -30, -12)
    scrollFrame:SetPoint("BOTTOMLEFT", panel, "BOTTOMLEFT", 12, 14)
    scrollFrame:SetPoint("BOTTOMRIGHT", panel, "BOTTOMRIGHT", -30, 14)

    local scrollChild = CreateFrame("Frame", nil, scrollFrame)
    scrollChild:SetPoint("TOPLEFT")
    scrollChild:SetPoint("TOPRIGHT")
    scrollChild:SetHeight(1)
    scrollFrame:SetScrollChild(scrollChild)

    markSettingsWindowVisualOptIn(panel)
    markSettingsWindowVisualOptIn(scrollFrame)
    markSettingsWindowVisualOptIn(scrollChild)
    panel._paSettingsScrollFrame = scrollFrame
    panel._paSettingsScrollChild = scrollChild
    scrollFrame._paCloseFloatingControlsOnUserScroll = true
    scrollFrame._paCloseFloatingControlsPanel = panel
    scrollFrame._paOwnerPanel = panel
    if panel._paSearchSectionKey then
        panel._paSearchScrollFrame = scrollFrame
        panel._paSearchScrollChild = scrollChild
        scrollFrame._paSearchPanel = panel
        scrollChild._paSearchPanel = panel
        panel._paSearchRegistryDirty = true
    end
    registerSettingsWindowVisualRefresh(scrollFrame, function(selfScroll)
        local child = selfScroll.GetScrollChild and selfScroll:GetScrollChild() or scrollChild
        local viewportHeight = tonumber(selfScroll:GetHeight()) or 0
        local contentHeight = child and (tonumber(child:GetHeight()) or 0) or 0
        settingsScrollRuntime.sync(selfScroll, child, viewportHeight, contentHeight)
    end)
    settingsScrollRuntime.sync(scrollFrame, scrollChild, scrollFrame:GetHeight() or 0, scrollChild:GetHeight() or 0)

    return scrollFrame, scrollChild
end

local function updateScrollBehavior(scrollFrame, scrollChild)
    if not scrollFrame or not scrollChild then
        return
    end

    if scrollFrame.UpdateScrollChildRect then
        scrollFrame:UpdateScrollChildRect()
    end

    local viewportHeight = scrollFrame:GetHeight() or 0
    local contentHeight = scrollChild:GetHeight() or 0
    local needsScroll = contentHeight > (viewportHeight + 1)
    local scrollBar = scrollFrame.ScrollBar

    if scrollBar then
        if isUsingCustomSettingsWindowVisualStyle(scrollFrame) then
            scrollBar:Hide()
        else
            scrollBar:SetShown(needsScroll)
        end
    end

    settingsScrollRuntime.sync(scrollFrame, scrollChild, viewportHeight, contentHeight)

    scrollFrame:EnableMouseWheel(needsScroll)
    if needsScroll then
        scrollFrame:SetScript("OnMouseWheel", function(frame, delta)
            if settingsScrollRuntime.closeFloatingControlsForParentScroll(frame) then
                return
            end
            settingsScrollRuntime.noteFrameInteraction(frame)
            local minScroll, maxScroll = 0, math.max(0, (scrollChild:GetHeight() or 0) - (frame:GetHeight() or 0))
            local current = frame:GetVerticalScroll() or 0
            local nextScroll = current - (delta * 40)
            if nextScroll < minScroll then nextScroll = minScroll end
            if nextScroll > maxScroll then nextScroll = maxScroll end
            frame._paSkipNextCustomScrollBarHookSync = true
            frame:SetVerticalScroll(nextScroll)
            settingsScrollRuntime.sync(frame, scrollChild, frame:GetHeight() or 0, scrollChild:GetHeight() or 0)
        end)
    else
        scrollFrame:SetVerticalScroll(0)
        scrollFrame:SetScript("OnMouseWheel", nil)
    end
end

local function lowerSettingsSearchText(value)
    local text = trim(tostring(value or ""))
    if text == "" then
        return ""
    end
    return string.lower(text)
end

settingsSearchRuntime.SEARCH_NOISE_EXACT = {
    ["death knight only"] = true,
    ["demon hunter only"] = true,
    ["druid only"] = true,
    ["evoker only"] = true,
    ["hunter only"] = true,
    ["mage only"] = true,
    ["monk only"] = true,
    ["paladin only"] = true,
    ["priest only"] = true,
    ["rogue only"] = true,
    ["shaman only"] = true,
    ["warlock only"] = true,
    ["warrior only"] = true,
    ["mythic+ only"] = true,
}

settingsSearchRuntime.GENERIC_CHOICE_CAPTION_EXACT = {
    ["enabled"] = true,
    ["disabled"] = true,
    ["enable"] = true,
    ["disable"] = true,
    ["on"] = true,
    ["off"] = true,
    ["show"] = true,
    ["hide"] = true,
    ["yes"] = true,
    ["no"] = true,
}

function settingsSearchRuntime.normalizeWhitespace(text)
    text = tostring(text or "")
    text = text:gsub("[%c\r\n\t]+", " ")
    text = text:gsub("%s+", " ")
    return trim(text)
end

function settingsSearchRuntime.stripFormatting(text)
    text = tostring(text or "")
    text = text:gsub("|c%x%x%x%x%x%x%x%x", "")
    text = text:gsub("|r", "")
    text = text:gsub("|T.-|t", " ")
    text = text:gsub("|A.-|a", " ")
    return settingsSearchRuntime.normalizeWhitespace(text)
end

function settingsSearchRuntime.stripQualifiers(text)
    text = settingsSearchRuntime.stripFormatting(text)
    if text == "" then
        return ""
    end

    text = text:gsub("%s*%[[^%]]-[Oo][Nn][Ll][Yy]%]%s*", " ")
    text = text:gsub("%s*%([^%)]-[Oo][Nn][Ll][Yy]%)%s*", " ")
    return settingsSearchRuntime.normalizeWhitespace(text)
end

function settingsSearchRuntime.isNoiseText(text)
    local normalized = lowerSettingsSearchText(settingsSearchRuntime.stripFormatting(text))
    if normalized == "" then
        return true
    end

    normalized = normalized:gsub("^%[", ""):gsub("%]$", "")
    normalized = normalized:gsub("^%(", ""):gsub("%)$", "")
    normalized = settingsSearchRuntime.normalizeWhitespace(normalized)
    if normalized == "" then
        return true
    end

    return settingsSearchRuntime.SEARCH_NOISE_EXACT[normalized] == true
end

function settingsSearchRuntime.sanitizeVisibleText(text)
    text = settingsSearchRuntime.stripQualifiers(text)
    if text == "" or settingsSearchRuntime.isNoiseText(text) then
        return ""
    end
    return settingsSearchRuntime.normalizeWhitespace(text)
end

function settingsSearchRuntime.normalizeChoiceLabelMode(mode)
    mode = lowerSettingsSearchText(mode)
    if mode == "index_all" then
        return "index_all"
    end
    return "suppress_generic"
end

function settingsSearchRuntime.markSearchTextOrigin(ref, origin, opts)
    if not frameIsAlive(ref) then
        return ref
    end

    origin = lowerSettingsSearchText(origin)
    if origin == "" then
        ref._paSearchTextOrigin = nil
        ref._paSearchChoiceLabelMode = nil
        return ref
    end

    ref._paSearchTextOrigin = origin
    if origin == "choice_caption" then
        opts = type(opts) == "table" and opts or {}
        ref._paSearchChoiceLabelMode = settingsSearchRuntime.normalizeChoiceLabelMode(
            opts.searchChoiceLabelMode or opts.choiceLabelMode
        )
    else
        ref._paSearchChoiceLabelMode = nil
    end
    return ref
end

function settingsSearchRuntime.shouldSuppressSearchTextRef(ref, text)
    if not frameIsAlive(ref) then
        return false
    end
    if lowerSettingsSearchText(ref._paSearchTextOrigin) ~= "choice_caption" then
        return false
    end
    if settingsSearchRuntime.normalizeChoiceLabelMode(ref._paSearchChoiceLabelMode) ~= "suppress_generic" then
        return false
    end

    local normalized = lowerSettingsSearchText(settingsSearchRuntime.stripFormatting(text))
    normalized = settingsSearchRuntime.normalizeWhitespace(normalized)
    return settingsSearchRuntime.GENERIC_CHOICE_CAPTION_EXACT[normalized] == true
end

local function getSettingsSearchPanelByKey(sectionKey)
    local registry = PortalAuthority and PortalAuthority.settingsPanelRegistry or nil
    local entry = registry and registry[sectionKey] or nil
    return entry and entry.panel or nil
end

local function getSettingsSearchTextFromRef(ref)
    if not ref then
        return ""
    end
    if ref.GetText then
        local ok, value = pcall(ref.GetText, ref)
        if ok then
            local sanitized = settingsSearchRuntime.sanitizeVisibleText(value)
            if sanitized ~= "" and settingsSearchRuntime.shouldSuppressSearchTextRef(ref, value) then
                return ""
            end
            return sanitized
        end
    end
    return ""
end

local function safeSettingsSearchMetric(frame, methodName)
    if not frame then
        return nil
    end
    local method = frame[methodName]
    if type(method) ~= "function" then
        return nil
    end
    local ok, value = pcall(method, frame)
    if not ok then
        return nil
    end
    return tonumber(value) or nil
end

function settingsSearchRuntime.resolveScrollY(panel, targetRef)
    if not panel or not targetRef then
        return 0
    end
    local scrollChild = panel._paSearchScrollChild or panel._paSettingsScrollChild or nil
    local rootTop = safeSettingsSearchMetric(scrollChild, "GetTop")
    local targetTop = safeSettingsSearchMetric(targetRef, "GetTop")
    if rootTop and targetTop then
        local offset = rootTop - targetTop
        if offset >= 0 then
            return math.floor(offset + 0.5)
        end
    end
    local targetBottom = safeSettingsSearchMetric(targetRef, "GetBottom")
    if rootTop and targetBottom then
        local offset = rootTop - targetBottom
        if offset >= 0 then
            return math.floor(offset + 0.5)
        end
    end
    return 0
end

function settingsSearchRuntime.buildHaystack(searchRefs)
    local pieces = {}
    local seen = {}

    local function addPiece(raw)
        local normalized = lowerSettingsSearchText(raw)
        if normalized == "" or seen[normalized] then
            return
        end
        seen[normalized] = true
        pieces[#pieces + 1] = normalized
    end

    if type(searchRefs) == "table" then
        for i = 1, #searchRefs do
            addPiece(getSettingsSearchTextFromRef(searchRefs[i]))
        end
    end
    return table.concat(pieces, " ")
end

function settingsSearchRuntime.isControlDescriptorKind(kind)
    kind = lowerSettingsSearchText(kind)
    return kind ~= "" and kind ~= "text" and kind ~= "group_title" and kind ~= "section_name"
end

function settingsSearchRuntime.getRenderableStandaloneKind(panel, descriptor, labelText)
    if not descriptor then
        return nil
    end

    local kind = lowerSettingsSearchText(descriptor.kind)
    if kind == "group_title" or kind == "section_name" then
        return kind
    end
    if kind ~= "" and kind ~= "text" then
        return nil
    end

    local displayRef = descriptor.displayRef
    local controlRef = descriptor.controlRef or descriptor.anchorRef or displayRef
    local size = tonumber(descriptor.fontSize) or 0
    local matchesSectionTitle = lowerSettingsSearchText(labelText) == lowerSettingsSearchText(panel and (panel._paSearchSectionName or panel.name or "") or "")

    if matchesSectionTitle and displayRef == panel._paSearchTopTarget then
        return nil
    end

    if size >= 12 and displayRef == controlRef then
        return "group_title"
    end

    return nil
end

function settingsSearchRuntime.addEntryHaystackPiece(entry, rawText)
    if not entry then
        return
    end
    local normalized = lowerSettingsSearchText(rawText)
    if normalized == "" then
        return
    end
    entry._haystackSeen = entry._haystackSeen or {}
    if entry._haystackSeen[normalized] then
        return
    end
    entry._haystackSeen[normalized] = true
    entry._haystackParts = entry._haystackParts or {}
    entry._haystackParts[#entry._haystackParts + 1] = normalized
end

function settingsSearchRuntime.appendControlEntryHelperRef(entry, ref)
    if not entry or not frameIsAlive(ref) then
        return
    end
    entry._searchHelperRefs = entry._searchHelperRefs or {}
    settingsSearchRuntime.appendUniqueSearchRef(entry._searchHelperRefs, ref)
end

function settingsSearchRuntime.appendControlEntryNaturalCandidate(entry, ref)
    if not entry or not frameIsAlive(ref) then
        return
    end
    entry._searchNaturalRowCandidates = entry._searchNaturalRowCandidates or {}
    settingsSearchRuntime.appendUniqueSearchRef(entry._searchNaturalRowCandidates, ref)
end

function settingsSearchRuntime.setSearchTargetFramePassThrough(frame)
    if not frameIsAlive(frame) then
        return
    end
    if frame.EnableMouse then
        frame:EnableMouse(false)
    end
    if frame.EnableMouseWheel then
        frame:EnableMouseWheel(false)
    end
    if frame.SetMouseClickEnabled then
        frame:SetMouseClickEnabled(false)
    end
    if frame.SetMouseMotionEnabled then
        frame:SetMouseMotionEnabled(false)
    end
end

function settingsSearchRuntime.collectSearchTargetBounds(refs)
    if type(refs) ~= "table" then
        return nil
    end

    local left, right, top, bottom = nil, nil, nil, nil
    for i = 1, #refs do
        local ref = refs[i]
        if frameIsAlive(ref) then
            local refLeft = safeSettingsSearchMetric(ref, "GetLeft")
            local refRight = safeSettingsSearchMetric(ref, "GetRight")
            local refTop = safeSettingsSearchMetric(ref, "GetTop")
            local refBottom = safeSettingsSearchMetric(ref, "GetBottom")
            if refLeft and refRight and refTop and refBottom and refRight > refLeft and refTop > refBottom then
                if not left or refLeft < left then
                    left = refLeft
                end
                if not right or refRight > right then
                    right = refRight
                end
                if not top or refTop > top then
                    top = refTop
                end
                if not bottom or refBottom < bottom then
                    bottom = refBottom
                end
            end
        end
    end

    if left and right and top and bottom and right > left and top > bottom then
        return {
            left = left,
            right = right,
            top = top,
            bottom = bottom,
            width = right - left,
            height = top - bottom,
        }
    end
    return nil
end

function settingsSearchRuntime.buildSearchTargetBoundsNote(targetBounds, visibleBounds)
    if type(targetBounds) ~= "table" or type(visibleBounds) ~= "table" then
        return "missing-bounds"
    end

    local leftExtra = math.floor((visibleBounds.left - targetBounds.left) + 0.5)
    local rightExtra = math.floor((targetBounds.right - visibleBounds.right) + 0.5)
    local topExtra = math.floor((targetBounds.top - visibleBounds.top) + 0.5)
    local bottomExtra = math.floor((visibleBounds.bottom - targetBounds.bottom) + 0.5)
    return string.format(
        "target=%dx%d visible=%dx%d extra(L%d R%d T%d B%d)",
        math.floor(targetBounds.width + 0.5),
        math.floor(targetBounds.height + 0.5),
        math.floor(visibleBounds.width + 0.5),
        math.floor(visibleBounds.height + 0.5),
        leftExtra,
        rightExtra,
        topExtra,
        bottomExtra
    )
end

function settingsSearchRuntime.evaluateSearchTargetBounds(candidateRef, visibleBounds)
    if not frameIsAlive(candidateRef) then
        return false, nil, "invalid-frame"
    end

    local candidateBounds = settingsSearchRuntime.collectSearchTargetBounds({ candidateRef })
    if type(candidateBounds) ~= "table" then
        return false, nil, "missing-bounds"
    end
    if type(visibleBounds) ~= "table" then
        return false, candidateBounds, "missing-visible-bounds"
    end

    local maxExtraHorizontal = math.max(18, (tonumber(visibleBounds.width) or 0) * 0.35)
    local maxExtraVertical = math.max(10, (tonumber(visibleBounds.height) or 0) * 0.65)
    local tolerance = 2

    local leftDelta = visibleBounds.left - candidateBounds.left
    local rightDelta = candidateBounds.right - visibleBounds.right
    local topDelta = candidateBounds.top - visibleBounds.top
    local bottomDelta = visibleBounds.bottom - candidateBounds.bottom

    if leftDelta < -tolerance or rightDelta < -tolerance or topDelta < -tolerance or bottomDelta < -tolerance then
        return false, candidateBounds, settingsSearchRuntime.buildSearchTargetBoundsNote(candidateBounds, visibleBounds)
    end

    if leftDelta > maxExtraHorizontal or rightDelta > maxExtraHorizontal or topDelta > maxExtraVertical or bottomDelta > maxExtraVertical then
        return false, candidateBounds, settingsSearchRuntime.buildSearchTargetBoundsNote(candidateBounds, visibleBounds)
    end

    return true, candidateBounds, settingsSearchRuntime.buildSearchTargetBoundsNote(candidateBounds, visibleBounds)
end

function settingsSearchRuntime.collectControlEntryVisibleRefs(entry)
    local refs = {}
    if type(entry) ~= "table" then
        return refs
    end

    settingsSearchRuntime.appendUniqueSearchRef(refs, entry._searchLabelRef)
    local helperRefs = entry._searchHelperRefs or {}
    for i = 1, #helperRefs do
        settingsSearchRuntime.appendUniqueSearchRef(refs, helperRefs[i])
    end
    settingsSearchRuntime.appendUniqueSearchRef(refs, entry._searchWidgetRef)
    return refs
end

function settingsSearchRuntime.getSearchTargetSingleBounds(ref)
    return settingsSearchRuntime.collectSearchTargetBounds({ ref })
end

function settingsSearchRuntime.collectControlEntryVisibleBounds(panel, entry)
    local refs = settingsSearchRuntime.collectControlEntryVisibleRefs(entry)
    local filteredRefs = {}
    local rejectedCount = 0
    local scrollChild = panel and (panel._paSearchScrollChild or panel._paSettingsScrollChild) or nil
    local scrollChildBounds = settingsSearchRuntime.getSearchTargetSingleBounds(scrollChild)
    local widgetBounds = settingsSearchRuntime.getSearchTargetSingleBounds(type(entry) == "table" and entry._searchWidgetRef or nil)
    local widgetCenterY = widgetBounds and ((widgetBounds.top + widgetBounds.bottom) * 0.5) or nil
    local maxVerticalDistance = widgetBounds and math.max(160, (tonumber(widgetBounds.height) or 0) * 6) or nil

    for i = 1, #refs do
        local ref = refs[i]
        local refBounds = settingsSearchRuntime.getSearchTargetSingleBounds(ref)
        local keep = type(refBounds) == "table"

        if keep and type(scrollChildBounds) == "table" then
            local nearFullWidth = (tonumber(refBounds.width) or 0) >= ((tonumber(scrollChildBounds.width) or 0) * 0.92)
            local nearFullHeight = (tonumber(refBounds.height) or 0) >= math.max(140, (tonumber(scrollChildBounds.height) or 0) * 0.60)
            if nearFullWidth and nearFullHeight then
                keep = false
            end
        end

        if keep and widgetCenterY and maxVerticalDistance and ref ~= entry._searchWidgetRef then
            local refCenterY = ((tonumber(refBounds.top) or 0) + (tonumber(refBounds.bottom) or 0)) * 0.5
            if math.abs(refCenterY - widgetCenterY) > maxVerticalDistance then
                keep = false
            end
        end

        if keep then
            settingsSearchRuntime.appendUniqueSearchRef(filteredRefs, ref)
        else
            rejectedCount = rejectedCount + 1
        end
    end

    if #filteredRefs == 0 and frameIsAlive(entry and entry._searchWidgetRef or nil) then
        settingsSearchRuntime.appendUniqueSearchRef(filteredRefs, entry._searchWidgetRef)
    end

    return filteredRefs, settingsSearchRuntime.collectSearchTargetBounds(filteredRefs), rejectedCount
end

function settingsSearchRuntime.findSearchCommonAncestor(refs, stopRef)
    if type(refs) ~= "table" or #refs <= 0 then
        return nil
    end

    local ancestryOrder = {}
    local ancestrySeen = {}
    local current = refs[1]
    while current do
        ancestryOrder[#ancestryOrder + 1] = current
        ancestrySeen[current] = true
        if current == stopRef then
            break
        end
        current = current.GetParent and current:GetParent() or nil
    end

    for i = 2, #refs do
        local nextSeen = {}
        local probe = refs[i]
        while probe do
            nextSeen[probe] = true
            if probe == stopRef then
                break
            end
            probe = probe.GetParent and probe:GetParent() or nil
        end
        for j = #ancestryOrder, 1, -1 do
            local candidate = ancestryOrder[j]
            if not nextSeen[candidate] then
                ancestrySeen[candidate] = nil
                table.remove(ancestryOrder, j)
            end
        end
    end

    for i = 1, #ancestryOrder do
        local candidate = ancestryOrder[i]
        if candidate ~= stopRef then
            return candidate
        end
    end
    return nil
end

function settingsSearchRuntime.collectControlEntryNaturalCandidates(panel, entry, visibleRefs)
    local refs = {}
    local scrollChild = panel and (panel._paSearchScrollChild or panel._paSettingsScrollChild) or nil
    if type(entry) ~= "table" then
        return refs
    end

    settingsSearchRuntime.appendUniqueSearchRef(refs, entry._searchExplicitRowFrame)

    local commonAncestor = settingsSearchRuntime.findSearchCommonAncestor(visibleRefs, scrollChild)
    settingsSearchRuntime.appendUniqueSearchRef(refs, commonAncestor)

    local widgetParent = frameIsAlive(entry._searchWidgetRef) and entry._searchWidgetRef.GetParent and entry._searchWidgetRef:GetParent() or nil
    local labelParent = frameIsAlive(entry._searchLabelRef) and entry._searchLabelRef.GetParent and entry._searchLabelRef:GetParent() or nil
    settingsSearchRuntime.appendUniqueSearchRef(refs, widgetParent)
    settingsSearchRuntime.appendUniqueSearchRef(refs, labelParent)

    local helperRefs = entry._searchHelperRefs or {}
    for i = 1, #helperRefs do
        local helperParent = helperRefs[i].GetParent and helperRefs[i]:GetParent() or nil
        settingsSearchRuntime.appendUniqueSearchRef(refs, helperParent)
    end

    local explicitCandidates = entry._searchNaturalRowCandidates or {}
    for i = 1, #explicitCandidates do
        settingsSearchRuntime.appendUniqueSearchRef(refs, explicitCandidates[i])
    end

    return refs
end

function settingsSearchRuntime.acquireSyntheticSearchRowFrame(entry, parent)
    if type(entry) ~= "table" or not frameIsAlive(parent) then
        return nil
    end

    local rowFrame = entry._searchSyntheticRowFrame
    if not frameIsAlive(rowFrame) then
        rowFrame = CreateFrame("Frame", nil, parent)
        entry._searchSyntheticRowFrame = rowFrame
    end
    if rowFrame:GetParent() ~= parent then
        rowFrame:SetParent(parent)
    end
    settingsSearchRuntime.setSearchTargetFramePassThrough(rowFrame)
    return rowFrame
end

function settingsSearchRuntime.hideSyntheticSearchRowFrame(entry)
    local rowFrame = type(entry) == "table" and entry._searchSyntheticRowFrame or nil
    if frameIsAlive(rowFrame) then
        rowFrame:Hide()
    end
end

function settingsSearchRuntime.recordControlEntryTargetClass(entry, targetType, phase)
    if type(entry) ~= "table" or type(targetType) ~= "string" or targetType == "" then
        return
    end

    local history = entry._searchTargetHistory or {}
    if history[#history] ~= targetType then
        history[#history + 1] = targetType
    end
    entry._searchTargetHistory = history
    entry._searchTargetHistorySummary = table.concat(history, " -> ")

    if not entry._searchFirstResolvedPhase then
        entry._searchFirstResolvedPhase = phase
    end
    if phase == "hidden" and not entry._searchHiddenResolvedTargetType then
        entry._searchHiddenResolvedTargetType = targetType
    end
    if phase == "real" then
        entry._searchRealResolvedTargetType = targetType
    end
    entry._searchResolvedPhase = phase
end

function settingsSearchRuntime.buildControlRegistryKey(panel, descriptor, labelText, controlRef, fallbackRef, orderIndex)
    local sectionKey = lowerSettingsSearchText(panel and panel._paSearchSectionKey or "")
    local kindKey = lowerSettingsSearchText(descriptor and descriptor.kind or "control")
    local labelKey = lowerSettingsSearchText(labelText or "")
    local orderKey = math.floor(tonumber(orderIndex) or 0)

    if sectionKey ~= "" and (labelKey ~= "" or orderKey > 0) then
        return table.concat({
            "control",
            sectionKey,
            tostring(orderKey),
            kindKey,
            labelKey,
        }, "|")
    end

    return controlRef or fallbackRef or (descriptor and descriptor.displayRef) or tostring(orderKey)
end

function settingsSearchRuntime.resolveControlEntryTarget(panel, entry)
    if not panel or type(entry) ~= "table" or entry.kind ~= "control" then
        return nil
    end

    local scrollChild = panel._paSearchScrollChild or panel._paSettingsScrollChild or nil
    local visibleRefs, visibleBounds, rejectedVisibleRefs = settingsSearchRuntime.collectControlEntryVisibleBounds(panel, entry)
    local isRealLayout = panel._paSearchRealActivationComplete == true
    local resolvedTarget, resolvedType, resolvedBoundsNote = nil, nil, nil

    if not frameIsAlive(resolvedTarget) and type(visibleBounds) ~= "table" and frameIsAlive(entry._searchExplicitRowFrame) then
        resolvedTarget = entry._searchExplicitRowFrame
        resolvedType = "explicit_row"
        resolvedBoundsNote = "explicit row without visible comparison"
    end

    local naturalCandidates = settingsSearchRuntime.collectControlEntryNaturalCandidates(panel, entry, visibleRefs)
    for i = 1, #naturalCandidates do
        local candidate = naturalCandidates[i]
        local candidateType = candidate == entry._searchExplicitRowFrame and "explicit_row" or "natural_row"
        local ok, _, boundsNote = settingsSearchRuntime.evaluateSearchTargetBounds(candidate, visibleBounds)
        if ok then
            resolvedTarget = candidate
            resolvedType = candidateType
            resolvedBoundsNote = boundsNote
            break
        end
    end

    if not frameIsAlive(resolvedTarget) and frameIsAlive(scrollChild) and type(visibleBounds) == "table" then
        local rootLeft = safeSettingsSearchMetric(scrollChild, "GetLeft")
        local rootTop = safeSettingsSearchMetric(scrollChild, "GetTop")
        if rootLeft and rootTop then
            local rowFrame = settingsSearchRuntime.acquireSyntheticSearchRowFrame(entry, scrollChild)
            if frameIsAlive(rowFrame) then
                rowFrame:ClearAllPoints()
                rowFrame:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", visibleBounds.left - rootLeft, visibleBounds.top - rootTop)
                rowFrame:SetPoint("BOTTOMRIGHT", scrollChild, "TOPLEFT", visibleBounds.right - rootLeft, visibleBounds.bottom - rootTop)
                rowFrame:Show()
                resolvedTarget = rowFrame
                resolvedType = "synthetic_row"
                resolvedBoundsNote = settingsSearchRuntime.buildSearchTargetBoundsNote(visibleBounds, visibleBounds)
            end
        end
    else
        settingsSearchRuntime.hideSyntheticSearchRowFrame(entry)
    end

    if not frameIsAlive(resolvedTarget) then
        settingsSearchRuntime.hideSyntheticSearchRowFrame(entry)
        resolvedTarget = frameIsAlive(entry._searchWidgetRef) and entry._searchWidgetRef
            or (frameIsAlive(entry.controlRef) and entry.controlRef or nil)
        resolvedType = "widget_fallback"
        resolvedBoundsNote = type(visibleBounds) == "table"
            and "widget fallback - no broader visible row target validated"
            or "widget fallback - visible row bounds unavailable"
    end

    local provisional = isRealLayout ~= true
    local currentPhase = isRealLayout and "real" or "hidden"
    local previousType = entry._searchTargetType
    local boundsValid = false
    if frameIsAlive(resolvedTarget) then
        if resolvedType == "synthetic_row" and type(visibleBounds) == "table" then
            boundsValid = true
        else
            boundsValid = select(1, settingsSearchRuntime.evaluateSearchTargetBounds(resolvedTarget, visibleBounds)) == true
        end
    end
    entry._searchRegistryTargetRef = resolvedTarget
    entry._searchRegistryAnchorRef = resolvedTarget
    entry._searchScrollSourceRef = resolvedTarget
    entry._searchTargetType = resolvedType
    entry._searchTargetProvisional = provisional and true or false
    entry._searchVisibleBounds = visibleBounds
    entry._searchVisibleRefCount = #visibleRefs
    entry._searchRejectedVisibleRefCount = rejectedVisibleRefs or 0
    entry._searchTargetBounds = settingsSearchRuntime.collectSearchTargetBounds({ resolvedTarget })
    entry._searchTargetBoundsNote = string.format(
        "%s refs=%d rejected=%d",
        tostring(resolvedBoundsNote or "missing-bounds"),
        tonumber(#visibleRefs) or 0,
        tonumber(rejectedVisibleRefs) or 0
    )
    entry._searchTargetBoundsValid = boundsValid and true or false
    entry._searchTargetSameObject = resolvedTarget == entry._searchRegistryTargetRef
    entry._searchWidgetFallbackReason = resolvedType == "widget_fallback" and resolvedBoundsNote or nil
    if previousType and previousType ~= resolvedType then
        entry._searchTargetChanged = true
    end
    settingsSearchRuntime.recordControlEntryTargetClass(entry, resolvedType, currentPhase)

    entry.controlRef = resolvedTarget
    entry.anchorRef = resolvedTarget
    entry.scrollY = settingsSearchRuntime.resolveScrollY(panel, resolvedTarget)
    entry.skipHighlight = not frameIsAlive(resolvedTarget)
    entry._searchRegistryScrollY = entry.scrollY
    entry._searchAlignedTarget = entry.controlRef == entry.anchorRef and entry.controlRef == entry._searchScrollSourceRef
    if provisional then
        panel._paSearchHasProvisionalControlTargets = true
    end
    return resolvedTarget
end

function settingsSearchRuntime.newControlRegistryEntry(panel, descriptor, labelText, controlRef, fallbackRef, orderIndex, sectionName, registryKey)
    if not panel then
        return nil
    end

    registryKey = registryKey or settingsSearchRuntime.buildControlRegistryKey(panel, descriptor, labelText, controlRef, fallbackRef, orderIndex)
    panel._paSearchLiveControlEntries = panel._paSearchLiveControlEntries or {}
    local entry = panel._paSearchLiveControlEntries[registryKey]
    if type(entry) ~= "table" then
        entry = {}
        panel._paSearchLiveControlEntries[registryKey] = entry
    end

    entry.kind = "control"
    entry.sectionKey = panel._paSearchSectionKey
    entry.sectionName = sectionName
    entry.displayLabel = trim(tostring(labelText or ""))
    entry.displayHelper = nil
    entry.labelText = trim(tostring(labelText or ""))
    entry.helperText = nil
    entry.orderIndex = orderIndex
    entry.searchHaystack = ""
    entry.haystack = ""
    entry.dedupeKey = nil
    entry.iconType = descriptor and descriptor.iconType or nil
    entry._haystackParts = {}
    entry._haystackSeen = {}
    entry._searchRegistryKey = registryKey
    entry._searchWidgetRef = frameIsAlive(descriptor and descriptor.searchWidgetRef or nil) and descriptor.searchWidgetRef
        or (frameIsAlive(controlRef) and controlRef or nil)
    entry._searchLabelRef = frameIsAlive(descriptor and descriptor.searchLabelRef or nil) and descriptor.searchLabelRef
        or (frameIsAlive(descriptor and descriptor.displayRef or nil) and descriptor.displayRef or nil)
    entry._searchHelperRefs = {}
    entry._searchNaturalRowCandidates = {}
    entry._searchExplicitRowFrame = frameIsAlive(descriptor and descriptor.searchRowFrame or nil) and descriptor.searchRowFrame or nil
    entry.controlRef = frameIsAlive(entry._searchWidgetRef) and entry._searchWidgetRef
        or (frameIsAlive(fallbackRef) and fallbackRef or nil)
    entry.anchorRef = entry.controlRef
    entry.scrollY = settingsSearchRuntime.resolveScrollY(panel, entry.controlRef)
    entry.skipHighlight = not frameIsAlive(entry.controlRef)
    entry._searchRegistryTargetRef = nil
    entry._searchRegistryAnchorRef = nil
    entry._searchScrollSourceRef = nil
    entry._searchRegistryScrollY = nil
    entry._searchVisibleBounds = nil
    entry._searchTargetBounds = nil
    entry._searchTargetBoundsNote = nil
    entry._searchTargetBoundsValid = false
    entry._searchTargetType = entry._searchTargetType or nil
    entry._searchTargetProvisional = false
    entry._searchAlignedTarget = false
    entry._searchTargetChanged = false
    entry._searchWidgetFallbackReason = nil
    entry._searchTargetHistory = entry._searchTargetHistory or {}
    return entry
end

function settingsSearchRuntime.absorbDescriptorIntoControlEntry(entry, descriptor, labelText)
    if not entry or not descriptor then
        return
    end

    local displayLabel = trim(tostring(labelText or ""))
    if trim(entry.displayLabel or "") == "" and displayLabel ~= "" then
        entry.displayLabel = displayLabel
        entry.labelText = displayLabel
    end
    if not entry.iconType and descriptor.iconType then
        entry.iconType = descriptor.iconType
    end
    if frameIsAlive(descriptor.searchWidgetRef) then
        entry._searchWidgetRef = descriptor.searchWidgetRef
    end
    if frameIsAlive(descriptor.searchLabelRef) then
        entry._searchLabelRef = descriptor.searchLabelRef
    elseif frameIsAlive(descriptor.displayRef) then
        entry._searchLabelRef = descriptor.displayRef
    end
    if frameIsAlive(descriptor.searchRowFrame) then
        entry._searchExplicitRowFrame = descriptor.searchRowFrame
    end
    settingsSearchRuntime.appendControlEntryNaturalCandidate(entry, descriptor.searchRowFrame)
    settingsSearchRuntime.appendControlEntryNaturalCandidate(entry, descriptor.parentRef)

    local searchRefs = descriptor.searchRefs or {}
    for i = 1, #searchRefs do
        local text = getSettingsSearchTextFromRef(searchRefs[i])
        if i == 1 then
            settingsSearchRuntime.addEntryHaystackPiece(entry, text)
        else
            settingsSearchRuntime.attachHelperTextToControlEntry(entry, text)
        end
    end
    local helperRefs = descriptor.searchHelperRefs or {}
    for i = 1, #helperRefs do
        settingsSearchRuntime.appendControlEntryHelperRef(entry, helperRefs[i])
        settingsSearchRuntime.appendControlEntryNaturalCandidate(entry, helperRefs[i].GetParent and helperRefs[i]:GetParent() or nil)
    end
    settingsSearchRuntime.addEntryHaystackPiece(entry, displayLabel)
end

function settingsSearchRuntime.attachHelperTextToControlEntry(entry, helperText)
    if not entry then
        return
    end
    local text = trim(tostring(helperText or ""))
    if text == "" then
        return
    end
    if lowerSettingsSearchText(text) == lowerSettingsSearchText(entry.displayLabel or entry.labelText or "") then
        return
    end
    if trim(entry.displayHelper or "") == "" then
        entry.displayHelper = text
        entry.helperText = text
    end
    settingsSearchRuntime.addEntryHaystackPiece(entry, text)
end

function settingsSearchRuntime.buildTargetIdentity(controlRef, scrollY, orderIndex)
    if controlRef ~= nil then
        return tostring(controlRef)
    end
    return string.format("scroll:%d:%d", math.floor(tonumber(scrollY) or 0), math.floor(tonumber(orderIndex) or 0))
end

function settingsSearchRuntime.getEntryDedupeKey(entry)
    if type(entry) ~= "table" then
        return nil
    end

    local kind = lowerSettingsSearchText(entry.kind)
    local sectionKey = lowerSettingsSearchText(entry.sectionKey)
    local labelKey = lowerSettingsSearchText(entry.displayLabel or entry.labelText or "")
    local targetKey = settingsSearchRuntime.buildTargetIdentity(entry._searchRegistryKey or entry.controlRef, entry.scrollY, entry.orderIndex)

    if kind == "control" then
        return table.concat({ "control", sectionKey, targetKey }, "|")
    end
    if kind == "group_title" then
        return table.concat({ "group_title", sectionKey, labelKey, targetKey }, "|")
    end
    if kind == "section_name" then
        return table.concat({ "section_name", sectionKey, labelKey }, "|")
    end
    return nil
end

function settingsSearchRuntime.finalizeRegistryEntry(entry)
    if type(entry) ~= "table" then
        return nil
    end

    entry.displayLabel = trim(tostring(entry.displayLabel or entry.labelText or ""))
    entry.displayHelper = trim(tostring(entry.displayHelper or entry.helperText or ""))
    local haystackParts = entry._haystackParts
    if type(haystackParts) == "table" and #haystackParts > 0 then
        entry.searchHaystack = table.concat(haystackParts, " ")
    else
        entry.searchHaystack = trim(tostring(entry.searchHaystack or entry.haystack or ""))
    end
    entry.dedupeKey = settingsSearchRuntime.getEntryDedupeKey(entry)
    entry.labelText = entry.displayLabel
    entry.helperText = entry.displayHelper
    entry.haystack = entry.searchHaystack
    entry.skipHighlight = entry.kind == "section_name" or not frameIsAlive(entry.controlRef)
    entry._haystackParts = nil
    entry._haystackSeen = nil
    return entry
end

function settingsSearchRuntime.attachHelperDescriptorToControlEntry(controlEntries, helperDescriptor)
    if type(controlEntries) ~= "table" or type(helperDescriptor) ~= "table" then
        return false
    end

    local helperText = trim(tostring(helperDescriptor.labelText or ""))
    if helperText == "" then
        return false
    end

    local helperY = tonumber(helperDescriptor.scrollY) or 0
    local helperOrderIndex = tonumber(helperDescriptor.orderIndex) or 0
    local bestEntry, bestScore = nil, nil

    for i = 1, #controlEntries do
        local entry = controlEntries[i]
        if entry then
            local entryY = tonumber(entry.scrollY) or 0
            local yDelta = math.abs(entryY - helperY)
            local orderDelta = math.abs((tonumber(entry.orderIndex) or 0) - helperOrderIndex)
            local score = yDelta + (orderDelta * 6)
            if yDelta <= 140 or orderDelta <= 4 then
                if not bestScore or score < bestScore then
                    bestEntry = entry
                    bestScore = score
                end
            end
        end
    end

    if not bestEntry then
        return false
    end

    settingsSearchRuntime.attachHelperTextToControlEntry(bestEntry, helperText)
    settingsSearchRuntime.appendControlEntryHelperRef(bestEntry, helperDescriptor.displayRef)
    settingsSearchRuntime.appendControlEntryNaturalCandidate(bestEntry, helperDescriptor.displayRef and helperDescriptor.displayRef.GetParent and helperDescriptor.displayRef:GetParent() or nil)
    return true
end

function settingsSearchRuntime.rebuildRegistry(panel)
    if not panel then
        return nil, false
    end

    local state = settingsSearchRuntime.ensureDescriptorState(panel)
    panel._paSearchHasProvisionalControlTargets = false
    panel._paSearchLiveControlEntries = panel._paSearchLiveControlEntries or {}
    local registry = {}
    local sectionName = panel._paSearchSectionName or panel.name or ""
    local syntheticControlRef = panel._paSearchTopTarget
    registry[#registry + 1] = {
        kind = "section_name",
        sectionKey = panel._paSearchSectionKey,
        sectionName = sectionName,
        displayLabel = sectionName,
        displayHelper = nil,
        labelText = sectionName,
        helperText = nil,
        controlRef = syntheticControlRef,
        scrollY = syntheticControlRef and settingsSearchRuntime.resolveScrollY(panel, syntheticControlRef) or 0,
        orderIndex = 0,
        searchHaystack = lowerSettingsSearchText(sectionName),
        haystack = lowerSettingsSearchText(sectionName),
        dedupeKey = nil,
        iconType = nil,
        skipHighlight = not frameIsAlive(syntheticControlRef),
    }

    local controlEntriesByRef = {}
    local orderedControlEntries = {}
    local orderedRenderableEntries = {}
    local orphanTextDescriptors = {}
    local ownedTextRefs = {}
    local seenLiveControlKeys = {}

    for i = 1, #(state.descriptors or {}) do
        local descriptor = state.descriptors[i]
        local displayRef = descriptor and descriptor.displayRef or nil
        local labelText = getSettingsSearchTextFromRef(displayRef)
        local controlRef = descriptor and (descriptor.searchWidgetRef or descriptor.controlRef or descriptor.anchorRef or displayRef) or nil
        local orderIndex = descriptor and (descriptor.orderIndex or i) or i
        local isDuplicateSectionHeader = labelText ~= ""
            and lowerSettingsSearchText(labelText) == lowerSettingsSearchText(sectionName)
            and displayRef == panel._paSearchTopTarget
        if descriptor and not isDuplicateSectionHeader and labelText ~= "" then
            if settingsSearchRuntime.isControlDescriptorKind(descriptor.kind) then
                local entryKey = settingsSearchRuntime.buildControlRegistryKey(
                    panel,
                    descriptor,
                    labelText,
                    controlRef,
                    displayRef,
                    orderIndex
                )
                local entry = controlEntriesByRef[entryKey]
                if not entry then
                    entry = settingsSearchRuntime.newControlRegistryEntry(
                        panel,
                        descriptor,
                        labelText,
                        controlRef,
                        displayRef,
                        orderIndex,
                        sectionName,
                        entryKey
                    )
                    controlEntriesByRef[entryKey] = entry
                    orderedControlEntries[#orderedControlEntries + 1] = entry
                    orderedRenderableEntries[#orderedRenderableEntries + 1] = entry
                end
                seenLiveControlKeys[entryKey] = true
                settingsSearchRuntime.absorbDescriptorIntoControlEntry(entry, descriptor, labelText)
                local searchRefs = descriptor.searchRefs or {}
                for j = 1, #searchRefs do
                    local ref = searchRefs[j]
                    if frameIsAlive(ref) then
                        ownedTextRefs[ref] = true
                    end
                end
            else
                local standaloneKind = settingsSearchRuntime.getRenderableStandaloneKind(panel, descriptor, labelText)
                if standaloneKind then
                    orderedRenderableEntries[#orderedRenderableEntries + 1] = {
                        kind = standaloneKind,
                        sectionKey = panel._paSearchSectionKey,
                        sectionName = sectionName,
                        displayLabel = labelText,
                        displayHelper = nil,
                        labelText = labelText,
                        helperText = nil,
                        controlRef = controlRef,
                        scrollY = settingsSearchRuntime.resolveScrollY(panel, controlRef or displayRef),
                        orderIndex = orderIndex,
                        searchHaystack = lowerSettingsSearchText(labelText),
                        haystack = lowerSettingsSearchText(labelText),
                        dedupeKey = nil,
                        iconType = nil,
                        skipHighlight = standaloneKind == "section_name" or not frameIsAlive(controlRef or displayRef),
                    }
                else
                    orphanTextDescriptors[#orphanTextDescriptors + 1] = {
                        displayRef = displayRef,
                        labelText = labelText,
                        scrollY = settingsSearchRuntime.resolveScrollY(panel, displayRef or controlRef),
                        orderIndex = orderIndex,
                    }
                end
            end
        end
    end

    for i = 1, #orphanTextDescriptors do
        local orphan = orphanTextDescriptors[i]
        local displayRef = orphan and orphan.displayRef or nil
        if not ownedTextRefs[displayRef] then
            settingsSearchRuntime.attachHelperDescriptorToControlEntry(orderedControlEntries, orphan)
        end
    end

    for i = 1, #orderedControlEntries do
        settingsSearchRuntime.resolveControlEntryTarget(panel, orderedControlEntries[i])
    end

    for key, liveEntry in pairs(panel._paSearchLiveControlEntries or {}) do
        if not seenLiveControlKeys[key] and type(liveEntry) == "table" then
            settingsSearchRuntime.hideSyntheticSearchRowFrame(liveEntry)
            panel._paSearchLiveControlEntries[key] = nil
        end
    end

    for i = 1, #orderedRenderableEntries do
        local entry = settingsSearchRuntime.finalizeRegistryEntry(orderedRenderableEntries[i])
        if entry and entry.labelText ~= "" and entry.haystack ~= "" then
            registry[#registry + 1] = entry
        end
    end

    local dedupedRegistry = {}
    local seenKeys = {}
    local seenSectionNames = {}
    for i = 1, #registry do
        local entry = settingsSearchRuntime.finalizeRegistryEntry(registry[i])
        if entry and entry.labelText ~= "" and entry.haystack ~= "" then
            local labelKey = lowerSettingsSearchText(entry.displayLabel or entry.labelText or "")
            local sectionLabelKey = table.concat({
                lowerSettingsSearchText(entry.sectionKey),
                labelKey,
            }, "|")

            if entry.kind == "section_name" then
                seenSectionNames[sectionLabelKey] = true
            end

            local shouldSkip = false
            if entry.kind == "group_title" and seenSectionNames[sectionLabelKey] == true then
                shouldSkip = true
            end

            local dedupeKey = entry.dedupeKey
            if not shouldSkip and dedupeKey and seenKeys[dedupeKey] then
                shouldSkip = true
            end

            if not shouldSkip then
                if dedupeKey then
                    seenKeys[dedupeKey] = true
                end
                dedupedRegistry[#dedupedRegistry + 1] = entry
            end
        end
    end

    panel._paSearchRegistry = dedupedRegistry
    panel._paSearchRegistryVersion = (tonumber(panel._paSearchRegistryVersion) or 0) + 1
    panel._paSearchRegistryDirty = false
    return dedupedRegistry, true
end

function settingsSearchRuntime.ensurePanelRegistry(panel)
    if not panel or not panel._paSearchSectionKey then
        return nil, false
    end

    local changed = false
    if not panel._initialized and type(panel.EnsureBuilt) == "function" then
        panel._paSearchHiddenBuildInProgress = true
        local ok, err = pcall(panel.EnsureBuilt, panel)
        panel._paSearchHiddenBuildInProgress = nil
        if not ok then
            error(err, 0)
        end
        panel._paSearchHiddenIndexBuilt = true
        if panel._paSearchRealActivationComplete ~= true then
            panel._paSearchRealActivationPending = true
        end
        changed = true
    end

    local needsProvisionalRefresh = panel._paSearchHasProvisionalControlTargets == true
        and panel._paSearchRealActivationComplete == true
    if panel._paSearchRegistryDirty or type(panel._paSearchRegistry) ~= "table" or needsProvisionalRefresh then
        settingsSearchRuntime.rebuildRegistry(panel)
        changed = true
    end

    return panel._paSearchRegistry or {}, changed
end

function settingsSearchRuntime.refreshResolvedTargets(panel)
    if not panel or type(panel._paSearchRegistry) ~= "table" then
        return nil, false
    end

    local changed = false
    for i = 1, #panel._paSearchRegistry do
        local entry = panel._paSearchRegistry[i]
        if type(entry) == "table" and entry.kind == "control" then
            local previousTarget = entry.controlRef
            local previousType = entry._searchTargetType
            local previousScrollY = tonumber(entry.scrollY) or 0
            settingsSearchRuntime.resolveControlEntryTarget(panel, entry)
            if entry.controlRef ~= previousTarget
                or entry._searchTargetType ~= previousType
                or math.abs((tonumber(entry.scrollY) or 0) - previousScrollY) > 0.5
            then
                changed = true
            end
        end
    end

    if changed then
        panel._paSearchRegistryVersion = (tonumber(panel._paSearchRegistryVersion) or 0) + 1
    end
    return panel._paSearchRegistry, changed
end

if PortalAuthority then
    function PortalAuthority:SettingsSearch_MarkPanelDirty(panelOrKey)
        local panel = panelOrKey
        if type(panelOrKey) == "string" then
            panel = getSettingsSearchPanelByKey(panelOrKey)
        end
        if panel then
            panel._paSearchRegistryDirty = true
        end
    end

    function PortalAuthority:SettingsSearch_MarkAllDirty()
        local registry = self.settingsPanelRegistry or {}
        for key, entry in pairs(registry) do
            local panel = entry and entry.panel or nil
            if panel and panel._paSearchSectionKey and key ~= "root" then
                panel._paSearchRegistryDirty = true
            end
        end
    end

    function PortalAuthority:SettingsSearch_EnsurePanelRegistry(sectionKey)
        local panel = getSettingsSearchPanelByKey(sectionKey)
        return settingsSearchRuntime.ensurePanelRegistry(panel)
    end

    function PortalAuthority:SettingsSearch_RefreshResolvedTargets(sectionKey)
        local panel = getSettingsSearchPanelByKey(sectionKey)
        return settingsSearchRuntime.refreshResolvedTargets(panel)
    end

    function PortalAuthority:SettingsSearch_GetScrollContext(sectionKey)
        local panel = getSettingsSearchPanelByKey(sectionKey)
        if not panel then
            return nil, nil, nil
        end
        return panel, panel._paSearchScrollFrame or panel._paSettingsScrollFrame, panel._paSearchScrollChild or panel._paSettingsScrollChild
    end

    function PortalAuthority:SettingsWindowRegisterSearchScrollFrame(scrollFrame, scrollChild)
        if not scrollFrame or not scrollChild then
            return
        end
        markSettingsWindowVisualOptIn(scrollFrame)
        markSettingsWindowVisualOptIn(scrollChild)
        registerSettingsWindowVisualRefresh(scrollFrame, function(selfScroll)
            local child = selfScroll.GetScrollChild and selfScroll:GetScrollChild() or scrollChild
            local viewportHeight = tonumber(selfScroll.GetHeight and selfScroll:GetHeight()) or 0
            local contentHeight = child and (tonumber(child.GetHeight and child:GetHeight()) or 0) or 0
            settingsScrollRuntime.sync(selfScroll, child, viewportHeight, contentHeight)
        end)
        settingsScrollRuntime.sync(scrollFrame, scrollChild, scrollFrame:GetHeight() or 0, scrollChild:GetHeight() or 0)
    end

    function PortalAuthority:SettingsWindowApplySearchScroll(scrollFrame, scrollChild, value)
        if not scrollFrame or not scrollChild then
            return 0
        end
        if scrollFrame.UpdateScrollChildRect then
            scrollFrame:UpdateScrollChildRect()
        end
        local viewportHeight = tonumber(scrollFrame:GetHeight()) or 0
        local contentHeight = tonumber(scrollChild:GetHeight()) or 0
        local maxScroll = math.max(0, contentHeight - viewportHeight)
        local nextValue = math.max(0, math.min(maxScroll, tonumber(value) or 0))
        scrollFrame._paSkipNextCustomScrollBarHookSync = true
        scrollFrame:SetVerticalScroll(nextValue)
        settingsScrollRuntime.sync(scrollFrame, scrollChild, viewportHeight, contentHeight)
        return nextValue
    end
end

local function isSettingsControlParkedOffscreen(frame)
    if not frame or not frame.GetNumPoints or not frame.GetPoint then
        return false
    end

    local pointCount = tonumber(frame:GetNumPoints()) or 0
    for i = 1, pointCount do
        local _, _, _, x, y = frame:GetPoint(i)
        if type(x) == "number" and type(y) == "number" then
            if x <= -1000 or y <= -1000 then
                return true
            end
        end
    end

    return false
end

local function measureSettingsVisibleContentExtent(scrollChild, objects)
    if not scrollChild or type(objects) ~= "table" then
        return nil
    end

    local function safeFrameMetric(frame, methodName)
        if not frame then
            return nil
        end
        local method = frame[methodName]
        if type(method) ~= "function" then
            return nil
        end
        local ok, value = pcall(method, frame)
        if not ok then
            return nil
        end
        return tonumber(value) or nil
    end

    local rootTop = safeFrameMetric(scrollChild, "GetTop")
    if not rootTop or rootTop <= 0 then
        return nil
    end

    local maxExtent = nil
    for i = 1, #objects do
        local obj = objects[i]
        if obj and obj.GetBottom and (not obj.IsShown or obj:IsShown()) and not isSettingsControlParkedOffscreen(obj) then
            local objBottom = safeFrameMetric(obj, "GetBottom")
            if objBottom and objBottom > 0 then
                local extent = rootTop - objBottom
                if extent >= 0 and extent < 5000 then
                    if not maxExtent or extent > maxExtent then
                        maxExtent = extent
                    end
                end
            end
        end
    end

    return maxExtent
end

local function PA_PerfBegin(scopeName, explicitState)
    if PortalAuthority and PortalAuthority.PerfBegin then
        return PortalAuthority:PerfBegin(scopeName, explicitState)
    end
    return nil, nil
end

local function PA_PerfEnd(scopeName, startedAt, stateLabel)
    if startedAt ~= nil and PortalAuthority and PortalAuthority.PerfEnd then
        PortalAuthority:PerfEnd(scopeName, startedAt, stateLabel)
    end
end

local MAX_LAYOUT_RETRIES = 10
local function refreshWhenSized(frame, callback, attempt)
    if not frame or not callback then
        return
    end

    attempt = attempt or 0
    local width = frame:GetWidth() or 0
    local height = frame:GetHeight() or 0
    if width > 1 and height > 1 then
        callback()
        return
    end

    if attempt >= MAX_LAYOUT_RETRIES then
        callback()
        return
    end

    C_Timer.After(0, function()
        refreshWhenSized(frame, callback, attempt + 1)
    end)
end

local function withPanelHydration(panel, callback)
    if type(callback) ~= "function" then
        return
    end

    if not panel then
        callback()
        return
    end

    panel._paHydratingControls = (tonumber(panel._paHydratingControls) or 0) + 1
    local ok, err = pcall(callback)
    local remaining = (tonumber(panel._paHydratingControls) or 1) - 1
    if remaining > 0 then
        panel._paHydratingControls = remaining
    else
        panel._paHydratingControls = nil
    end
    if not ok then
        error(err, 0)
    end
end

local function isControlHydrating(frame)
    local current = frame
    while current do
        if (tonumber(current._paHydratingControls) or 0) > 0 then
            return true
        end
        current = current.GetParent and current:GetParent() or nil
    end
    return false
end

local function panelHasSizedViewport(frame)
    if not frame then
        return false
    end
    local width = tonumber(frame:GetWidth()) or 0
    local height = tonumber(frame:GetHeight()) or 0
    return width > 1 and height > 1
end

local function ensureSettingsCanvasPanelAnchored(panel)
    local parent = panel and panel.GetParent and panel:GetParent() or nil
    if not panel or not parent then
        return false
    end
    if panel._paAnchorParent ~= parent or not panel._paAnchored then
        panel:ClearAllPoints()
        panel:SetAllPoints(parent)
        panel._paAnchorParent = parent
    end
    panel._paAnchored = true
    return true
end

local SETTINGS_FIRST_OPEN_SHORT_SETTLE_DELAY = 0.05
local SETTINGS_FIRST_OPEN_VALID_KEYS = {
    root = true,
    announcements = true,
    dock = true,
    timers = true,
    interrupt = true,
    combat = true,
    keystone = true,
    profiles = true,
}
local settingsFirstOpenHost = {
    selectionToken = 0,
    selectedKey = nil,
    selectedPanel = nil,
    selectedGeneration = 0,
}
local function normalizeSettingsFirstOpenKey(key)
    if type(key) == "string" and SETTINGS_FIRST_OPEN_VALID_KEYS[key] then
        return key
    end
    return nil
end

local function setSettingsFirstOpenBootstrapActive(key)
    if PortalAuthority and PortalAuthority.SetSettingsBootstrapActive then
        PortalAuthority:SetSettingsBootstrapActive(normalizeSettingsFirstOpenKey(key) or "none")
    end
end

local function getSettingsFirstOpenGeneration(panel)
    return math.max(0, tonumber(panel and panel._paFirstOpenGeneration) or 0)
end

local function getSettingsFirstOpenState(panel)
    return tostring(panel and panel._paFirstOpenState or "idle")
end

local function isSettingsFirstOpenReady(panel)
    return getSettingsFirstOpenState(panel) == "ready"
end

local function isSettingsFirstOpenSettlePending(panel)
    return getSettingsFirstOpenState(panel) == "pending"
end

local function setSelectedSettingsFirstOpenPanel(panel)
    local key = normalizeSettingsFirstOpenKey(panel and panel._settingsFirstOpenKey)
    settingsFirstOpenHost.selectionToken = (tonumber(settingsFirstOpenHost.selectionToken) or 0) + 1
    settingsFirstOpenHost.selectedPanel = panel
    settingsFirstOpenHost.selectedKey = key
    settingsFirstOpenHost.selectedGeneration = getSettingsFirstOpenGeneration(panel)
    return settingsFirstOpenHost.selectionToken
end

local function clearSelectedSettingsFirstOpenPanel(panel)
    if panel and settingsFirstOpenHost.selectedPanel ~= panel then
        return
    end
    settingsFirstOpenHost.selectionToken = (tonumber(settingsFirstOpenHost.selectionToken) or 0) + 1
    settingsFirstOpenHost.selectedPanel = nil
    settingsFirstOpenHost.selectedKey = nil
    settingsFirstOpenHost.selectedGeneration = 0
    setSettingsFirstOpenBootstrapActive("none")
end

local function resetSettingsFirstOpenPanelState(panel)
    if not panel then
        return 0
    end
    local generation = getSettingsFirstOpenGeneration(panel) + 1
    panel._paFirstOpenGeneration = generation
    panel._paFirstOpenState = "idle"
    panel._paFirstOpenSelectionToken = nil
    panel._paFirstOpenSizeReadyConsumed = nil
    panel._paFirstOpenShortSettleQueued = nil
    panel._paFirstOpenImmediateSizeCheckQueued = nil
    if settingsFirstOpenHost.selectedPanel == panel then
        settingsFirstOpenHost.selectedGeneration = generation
        setSettingsFirstOpenBootstrapActive("none")
    end
    return generation
end

local function shouldBailSettingsFirstOpenSettle(panel, generation, selectionToken)
    if not panel then
        return true
    end
    if getSettingsFirstOpenState(panel) ~= "pending" then
        return true
    end
    if getSettingsFirstOpenGeneration(panel) ~= generation then
        return true
    end
    if panel._paSettingsClosing then
        return true
    end
    if not panel.IsShown or not panel:IsShown() then
        return true
    end
    if settingsFirstOpenHost.selectedPanel ~= panel then
        return true
    end
    if settingsFirstOpenHost.selectedKey ~= normalizeSettingsFirstOpenKey(panel._settingsFirstOpenKey) then
        return true
    end
    if (tonumber(settingsFirstOpenHost.selectionToken) or 0) ~= (tonumber(selectionToken) or 0) then
        return true
    end
    if (tonumber(settingsFirstOpenHost.selectedGeneration) or 0) ~= generation then
        return true
    end
    return false
end

local function evaluateSettingsFirstOpenReady(panel)
    if not panel then
        return false
    end
    local predicate = panel._settingsFirstOpenIsReady
    if type(predicate) == "function" then
        local ok, ready = pcall(predicate, panel)
        return ok and ready == true
    end
    return panelHasSizedViewport(panel._settingsFirstOpenSizeTarget or panel._sizingFrame or panel)
end

local function runSettingsFirstOpenRender(panel, reason)
    if not panel then
        return false
    end
    local render = panel._settingsFirstOpenRender
    if type(render) ~= "function" then
        return false
    end
    withPanelHydration(panel, function()
        render(panel, reason or "on_show")
    end)
    return true
end

local function completeSettingsFirstOpenSettle(panel, generation, ready)
    if not panel then
        return false
    end
    if getSettingsFirstOpenState(panel) ~= "pending" then
        return false
    end
    if getSettingsFirstOpenGeneration(panel) ~= generation then
        return false
    end

    panel._paFirstOpenState = ready and "ready" or "idle"
    panel._paFirstOpenGeneration = generation + 1
    panel._paFirstOpenSelectionToken = nil
    panel._paFirstOpenSizeReadyConsumed = nil
    panel._paFirstOpenShortSettleQueued = nil
    panel._paFirstOpenImmediateSizeCheckQueued = nil
    if settingsFirstOpenHost.selectedPanel == panel then
        settingsFirstOpenHost.selectedGeneration = panel._paFirstOpenGeneration
    end
    setSettingsFirstOpenBootstrapActive("none")
    return true
end

local function queueSettingsFirstOpenShortSettle(panel, generation, selectionToken)
    if not panel or panel._paFirstOpenShortSettleQueued then
        return
    end
    panel._paFirstOpenShortSettleQueued = true

    local function run()
        if panel then
            panel._paFirstOpenShortSettleQueued = nil
        end
        if shouldBailSettingsFirstOpenSettle(panel, generation, selectionToken) then
            return
        end

        if not panel._paFirstOpenSizeReadyConsumed then
            local sizeTarget = panel._settingsFirstOpenSizeTarget or panel._sizingFrame or panel
            if panelHasSizedViewport(sizeTarget) then
                panel._paFirstOpenSizeReadyConsumed = true
                runSettingsFirstOpenRender(panel, "size_changed")
                if evaluateSettingsFirstOpenReady(panel) then
                    completeSettingsFirstOpenSettle(panel, generation, true)
                    return
                end
            else
                completeSettingsFirstOpenSettle(panel, generation, false)
                return
            end
        end

        runSettingsFirstOpenRender(panel, "size_changed")
        if evaluateSettingsFirstOpenReady(panel) then
            completeSettingsFirstOpenSettle(panel, generation, true)
            return
        end
        completeSettingsFirstOpenSettle(panel, generation, false)
    end

    if C_Timer and C_Timer.After then
        C_Timer.After(SETTINGS_FIRST_OPEN_SHORT_SETTLE_DELAY, run)
    else
        run()
    end
end

local function handleSettingsFirstOpenSizeReady(panel, reason)
    if not isSettingsFirstOpenSettlePending(panel) then
        return false
    end

    local generation = getSettingsFirstOpenGeneration(panel)
    local selectionToken = tonumber(panel and panel._paFirstOpenSelectionToken) or 0
    if shouldBailSettingsFirstOpenSettle(panel, generation, selectionToken) then
        return false
    end

    local sizeTarget = panel and (panel._settingsFirstOpenSizeTarget or panel._sizingFrame or panel) or nil
    if not panelHasSizedViewport(sizeTarget) then
        return false
    end
    if panel._paFirstOpenSizeReadyConsumed then
        return true
    end

    panel._paFirstOpenSizeReadyConsumed = true
    runSettingsFirstOpenRender(panel, reason or "size_changed")
    if evaluateSettingsFirstOpenReady(panel) then
        completeSettingsFirstOpenSettle(panel, generation, true)
        return true
    end

    queueSettingsFirstOpenShortSettle(panel, generation, selectionToken)
    return true
end

local function queueSettingsFirstOpenImmediateSizeCheck(panel, generation, selectionToken)
    if not panel or panel._paFirstOpenImmediateSizeCheckQueued then
        return
    end
    panel._paFirstOpenImmediateSizeCheckQueued = true

    local function run()
        if panel then
            panel._paFirstOpenImmediateSizeCheckQueued = nil
        end
        if shouldBailSettingsFirstOpenSettle(panel, generation, selectionToken) then
            return
        end

        local sizeTarget = panel and (panel._settingsFirstOpenSizeTarget or panel._sizingFrame or panel) or nil
        if not panelHasSizedViewport(sizeTarget) then
            return
        end

        if panel._paFirstOpenSizeReadyConsumed then
            runSettingsFirstOpenRender(panel, "size_changed")
            if evaluateSettingsFirstOpenReady(panel) then
                completeSettingsFirstOpenSettle(panel, generation, true)
                return
            end
            queueSettingsFirstOpenShortSettle(panel, generation, selectionToken)
            return
        end

        handleSettingsFirstOpenSizeReady(panel, "size_changed")
    end

    if C_Timer and C_Timer.After then
        C_Timer.After(0, run)
    else
        run()
    end
end

local function startSettingsFirstOpenSettle(panel)
    if not panel or type(panel._settingsFirstOpenRender) ~= "function" then
        return false
    end
    if isSettingsFirstOpenReady(panel) then
        return false
    end

    local generation = getSettingsFirstOpenGeneration(panel) + 1
    panel._paFirstOpenGeneration = generation
    panel._paFirstOpenState = "pending"
    panel._paFirstOpenSelectionToken = nil
    panel._paFirstOpenSizeReadyConsumed = nil
    panel._paFirstOpenShortSettleQueued = nil
    panel._paFirstOpenImmediateSizeCheckQueued = nil
    panel._paSettingsClosing = false

    local selectionToken = setSelectedSettingsFirstOpenPanel(panel)
    panel._paFirstOpenSelectionToken = selectionToken
    setSettingsFirstOpenBootstrapActive(panel._settingsFirstOpenKey)

    runSettingsFirstOpenRender(panel, "on_show")
    if evaluateSettingsFirstOpenReady(panel) then
        completeSettingsFirstOpenSettle(panel, generation, true)
        return true
    end

    queueSettingsFirstOpenImmediateSizeCheck(panel, generation, selectionToken)
    queueSettingsFirstOpenShortSettle(panel, generation, selectionToken)
    return true
end

local function shouldSuppressSettingsFirstOpenExternalRefresh(panel)
    return isSettingsFirstOpenSettlePending(panel)
end

local SETTINGS_WINDOW_CHROME_PARK_X = -5000
local SETTINGS_WINDOW_CHROME_PARK_Y = -5000

local function isPanelUsingCustomSettingsWindowHost(panel)
    if not panel or not PortalAuthority or not PortalAuthority.IsSettingsWindowHostEnabled then
        return false
    end
    if not PortalAuthority:IsSettingsWindowHostEnabled() then
        return false
    end
    if panel._paHostedBySettingsWindow == true then
        return true
    end

    local runtime = PortalAuthority._settingsWindowRuntime
    local body = runtime and runtime.body or nil
    if body and panel.GetParent and panel:GetParent() == body then
        return true
    end

    return false
end

local function setSettingsWindowChromeVisible(widget, visible, anchorParent)
    if not widget then
        return
    end

    if visible then
        if widget.Show then
            widget:Show()
        end
        return
    end

    if widget.Hide then
        widget:Hide()
    end
    if widget.ClearAllPoints then
        widget:ClearAllPoints()
    end
    if anchorParent and widget.SetPoint then
        widget:SetPoint("TOPLEFT", anchorParent, "TOPLEFT", SETTINGS_WINDOW_CHROME_PARK_X, SETTINGS_WINDOW_CHROME_PARK_Y)
    end
end

local function refreshSettingsWindowHeaderAccessoryIfHosted(panel)
    if not panel or not isPanelUsingCustomSettingsWindowHost(panel) then
        return
    end
    if PortalAuthority and PortalAuthority.RefreshSettingsWindowHeaderAccessory then
        PortalAuthority:RefreshSettingsWindowHeaderAccessory()
    end
end

local function handleSettingsFirstOpenPanelShow(panel)
    if not panel then
        return false
    end
    panel._paSettingsClosing = false
    if panel._paSearchSectionKey then
        local hadPendingRealActivation = panel._paSearchRealActivationPending == true
        panel._paSearchRealActivationPending = false
        panel._paSearchRealActivationComplete = true
        if hadPendingRealActivation and (panel._paSearchHiddenIndexBuilt == true or panel._paSearchHasProvisionalControlTargets == true) then
            panel._paSearchRegistryDirty = true
        end
    end
    if isSettingsFirstOpenReady(panel) then
        setSelectedSettingsFirstOpenPanel(panel)
        setSettingsFirstOpenBootstrapActive("none")
        return false
    end
    return startSettingsFirstOpenSettle(panel)
end

local function handleSettingsFirstOpenPanelHide(panel)
    if not panel then
        return
    end
    panel._paSettingsClosing = true
    clearSelectedSettingsFirstOpenPanel(panel)
    if isSettingsFirstOpenSettlePending(panel) then
        resetSettingsFirstOpenPanelState(panel)
    end
end

local function refreshPanel(panel)
    if panel and panel._refresh then
        refreshWhenSized(panel._sizingFrame or panel, function()
            if not panel or not panel:IsShown() then
                return
            end
            withPanelHydration(panel, panel._refresh)
        end)
    end
end

local function createScrollableTextArea(parent)
    local container = CreateFrame("Frame", nil, parent)
    container:SetClipsChildren(true)

    local scrollFrame = CreateFrame("ScrollFrame", nil, container, "UIPanelScrollFrameTemplate")
    scrollFrame:SetPoint("TOPLEFT", container, "TOPLEFT", 6, -6)
    scrollFrame:SetPoint("BOTTOMRIGHT", container, "BOTTOMRIGHT", -26, 6)

    local editBox = CreateFrame("EditBox", nil, scrollFrame)
    editBox:SetAutoFocus(false)
    editBox:SetMultiLine(true)
    editBox:SetWordWrap(true)
    if editBox.SetNonSpaceWrap then
        editBox:SetNonSpaceWrap(true)
    end
    editBox:SetTextInsets(8, 8, 8, 8)
    editBox:SetJustifyH("LEFT")
    editBox:SetJustifyV("TOP")
    editBox:SetWidth(1)
    editBox:SetHeight(1)
    applyGlobalFontToObject(editBox, 12)

    scrollFrame:SetScrollChild(editBox)
    markSettingsWindowVisualOptIn(container)
    markSettingsWindowVisualOptIn(scrollFrame)
    markSettingsWindowVisualOptIn(editBox)
    registerSettingsWindowVisualRefresh(scrollFrame, function(selfScroll)
        local child = selfScroll.GetScrollChild and selfScroll:GetScrollChild() or editBox
        local viewportHeight = tonumber(selfScroll:GetHeight()) or 0
        local contentHeight = child and (tonumber(child:GetHeight()) or 0) or 0
        settingsScrollRuntime.sync(selfScroll, child, viewportHeight, contentHeight)
    end)

    local function updateTextBounds()
        local width = math.max(1, scrollFrame:GetWidth() - 4)
        editBox:SetWidth(width)
        local contentHeight = math.max(scrollFrame:GetHeight(), editBox:GetStringHeight() + 20)
        editBox:SetHeight(contentHeight)
        settingsScrollRuntime.sync(scrollFrame, editBox, scrollFrame:GetHeight() or 0, contentHeight)
    end

    scrollFrame:SetScript("OnSizeChanged", function()
        updateTextBounds()
    end)

    scrollFrame:EnableMouseWheel(true)
    scrollFrame:SetScript("OnMouseWheel", function(frame, delta)
        settingsScrollRuntime.noteFrameInteraction(frame)
        local minScroll, maxScroll = 0, math.max(0, (editBox:GetHeight() or 0) - (frame:GetHeight() or 0))
        local nextScroll = (frame:GetVerticalScroll() or 0) - (delta * 24)
        if nextScroll < minScroll then nextScroll = minScroll end
        if nextScroll > maxScroll then nextScroll = maxScroll end
        frame._paSkipNextCustomScrollBarHookSync = true
        frame:SetVerticalScroll(nextScroll)
        settingsScrollRuntime.sync(frame, editBox, frame:GetHeight() or 0, editBox:GetHeight() or 0)
    end)

    editBox:SetScript("OnTextChanged", function()
        updateTextBounds()
    end)

    container.ScrollFrame = scrollFrame
    container.EditBox = editBox
    container.UpdateLayout = updateTextBounds

    return container
end

local function escapeValue(text)
    return tostring(text):gsub("%%", "%%25"):gsub("|", "%%7C")
end

local function unescapeValue(text)
    return tostring(text):gsub("%%(%x%x)", function(hex)
        return string.char(tonumber(hex, 16) or 0)
    end)
end

local BASE64_ALPHABET = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local BASE64_DECODE_MAP = {}
for i = 1, #BASE64_ALPHABET do
    BASE64_DECODE_MAP[BASE64_ALPHABET:sub(i, i)] = i - 1
end

local function base64Encode(input)
    local bytes = { string.byte(input, 1, #input) }
    local out = {}

    for i = 1, #bytes, 3 do
        local b1 = bytes[i] or 0
        local b2 = bytes[i + 1] or 0
        local b3 = bytes[i + 2] or 0
        local n = b1 * 65536 + b2 * 256 + b3

        local c1 = math.floor(n / 262144) % 64
        local c2 = math.floor(n / 4096) % 64
        local c3 = math.floor(n / 64) % 64
        local c4 = n % 64

        out[#out + 1] = BASE64_ALPHABET:sub(c1 + 1, c1 + 1)
        out[#out + 1] = BASE64_ALPHABET:sub(c2 + 1, c2 + 1)
        out[#out + 1] = (i + 1 <= #bytes) and BASE64_ALPHABET:sub(c3 + 1, c3 + 1) or "="
        out[#out + 1] = (i + 2 <= #bytes) and BASE64_ALPHABET:sub(c4 + 1, c4 + 1) or "="
    end

    return table.concat(out)
end

local function base64Decode(input)
    local clean = trim(input)
    if clean == "" or (#clean % 4 ~= 0) then
        return nil, "invalid base64 length"
    end
    if clean:find("[^A-Za-z0-9%+/%=]") then
        return nil, "invalid base64 characters"
    end
    if clean:find("=[^=]") then
        return nil, "invalid base64 padding"
    end

    local out = {}
    for i = 1, #clean, 4 do
        local c1 = clean:sub(i, i)
        local c2 = clean:sub(i + 1, i + 1)
        local c3 = clean:sub(i + 2, i + 2)
        local c4 = clean:sub(i + 3, i + 3)

        local v1 = BASE64_DECODE_MAP[c1]
        local v2 = BASE64_DECODE_MAP[c2]
        local v3 = (c3 == "=") and 0 or BASE64_DECODE_MAP[c3]
        local v4 = (c4 == "=") and 0 or BASE64_DECODE_MAP[c4]
        if v1 == nil or v2 == nil or v3 == nil or v4 == nil then
            return nil, "invalid base64 sequence"
        end

        local n = v1 * 262144 + v2 * 4096 + v3 * 64 + v4
        local b1 = math.floor(n / 65536) % 256
        local b2 = math.floor(n / 256) % 256
        local b3 = n % 256

        out[#out + 1] = string.char(b1)
        if c3 ~= "=" then
            out[#out + 1] = string.char(b2)
        end
        if c4 ~= "=" then
            out[#out + 1] = string.char(b3)
        end
    end

    return table.concat(out)
end

local DOCK_IMPORT_PREFIX = "PA1:"
local DOCK_IMPORT_NUMERIC_LIMITS = {
    dockX = { min = -3000, max = 3000 },
    dockY = { min = -3000, max = 3000 },
    dockIconWidth = { min = 16, max = 128 },
    dockIconHeight = { min = 16, max = 128 },
    dockRowSpacing = { min = 0, max = 40 },
    dockTextIconSpacing = { min = 0, max = 40 },
    dockFontSize = { min = 8, max = 48 },
    dockShadowOffsetX = { min = -10, max = 10 },
    dockShadowOffsetY = { min = -10, max = 10 },
}

local DOCK_IMPORT_STRING_ENUMS = {
    dockOrientation = { VERTICAL = true, HORIZONTAL = true },
    dockVerticalTextSide = { LEFT = true, RIGHT = true },
    dockHorizontalTextPosition = { ABOVE = true, BELOW = true },
    dockTextOutline = { [""] = true, OUTLINE = true, THICKOUTLINE = true },
}

local function getDockSettingValue(key)
    local db = PortalAuthorityDB or {}
    local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
    local value = db[key]
    if value == nil then
        value = defaults[key]
    end
    return value
end

local function encodeDockValue(entry)
    local value = getDockSettingValue(entry.key)
    if entry.type == "boolean" then
        return value and "1" or "0"
    elseif entry.type == "number" then
        return tostring(math.floor(tonumber(value) or 0))
    elseif entry.type == "color" then
        local c = type(value) == "table" and value or { r = 1, g = 0.82, b = 0, a = 1 }
        return string.format("%.3f,%.3f,%.3f,%.3f", c.r or 1, c.g or 0.82, c.b or 0, c.a or 1)
    end
    return escapeValue(value or "")
end

local function decodeDockValue(entry, raw)
    if entry.type == "boolean" then
        if raw == "1" then return true end
        if raw == "0" then return false end
        return nil, "expected boolean"
    elseif entry.type == "number" then
        local n = tonumber(raw)
        if not n then
            return nil, "expected number"
        end
        return math.floor(n)
    elseif entry.type == "color" then
        local r, g, b, a = raw:match("^([^,]+),([^,]+),([^,]+),([^,]+)$")
        r, g, b, a = tonumber(r), tonumber(g), tonumber(b), tonumber(a)
        if not r or not g or not b or not a then
            return nil, "expected color"
        end
        return {
            r = math.max(0, math.min(1, r)),
            g = math.max(0, math.min(1, g)),
            b = math.max(0, math.min(1, b)),
            a = math.max(0, math.min(1, a)),
        }
    end
    return unescapeValue(raw)
end

local function validateDockValue(entry, value)
    if entry.type == "number" then
        local limits = DOCK_IMPORT_NUMERIC_LIMITS[entry.key]
        if limits and (value < limits.min or value > limits.max) then
            return nil, string.format("%s must be between %d and %d.", entry.key, limits.min, limits.max)
        end
    elseif entry.type == "string" then
        local enumSet = DOCK_IMPORT_STRING_ENUMS[entry.key]
        if enumSet and not enumSet[value] then
            return nil, string.format("%s has an unsupported value.", entry.key)
        end
    end
    return value
end

local function serializeDockSettings()
    local parts = {}
    for _, entry in ipairs(DOCK_IMPORT_EXPORT_KEYS) do
        parts[#parts + 1] = string.format("%s=%s", entry.key, encodeDockValue(entry))
    end
    return DOCK_IMPORT_PREFIX .. base64Encode(table.concat(parts, "|"))
end

local function parseDockSettings(text)
    local payload = trim(text)
    if payload == "" then
        return nil, "Import string is empty."
    end

    if payload:sub(1, #DOCK_IMPORT_PREFIX) ~= DOCK_IMPORT_PREFIX then
        return nil, "Missing PA1 prefix."
    end

    local decodedPayload, decodeErr = base64Decode(payload:sub(#DOCK_IMPORT_PREFIX + 1))
    if not decodedPayload then
        return nil, "Invalid encoded payload (" .. decodeErr .. ")."
    end

    local rawMap = {}
    for segment in decodedPayload:gmatch("([^|]+)") do
        local key, raw = segment:match("^([^=]+)=(.*)$")
        if key and DOCK_IMPORT_EXPORT_KEYSET[key] then
            rawMap[key] = raw
        end
    end

    local values = {}
    for _, entry in ipairs(DOCK_IMPORT_EXPORT_KEYS) do
        local raw = rawMap[entry.key]
        local parsedValue

        if raw == nil then
            parsedValue = getDockSettingValue(entry.key)
        else
            local decoded, err = decodeDockValue(entry, raw)
            if err then
                return nil, string.format("Invalid value for %s (%s).", entry.key, err)
            end
            parsedValue = decoded
        end

        local _, err = validateDockValue(entry, parsedValue)
        if err then
            return nil, err
        end

        values[entry.key] = parsedValue
    end

    return values
end

local function applyDockImport(values)
    for _, entry in ipairs(DOCK_IMPORT_EXPORT_KEYS) do
        PortalAuthorityDB[entry.key] = values[entry.key]
    end

    if PortalAuthority.EnsureDB then
        PortalAuthority:EnsureDB()
    end
    if PortalAuthority.UpdateDockMovableState then
        PortalAuthority:UpdateDockMovableState()
    end
    if PortalAuthority.RebuildDock then
        PortalAuthority:RebuildDock()
    end
    if PortalAuthority.ApplyDockPosition then
        PortalAuthority:ApplyDockPosition()
    end
    if InCombatLockdown() then
        if PortalAuthority.QueueDockVisibilityRefresh then
            PortalAuthority:QueueDockVisibilityRefresh()
        end
        return
    end

    if PortalAuthority.UpdateDockVisibility then
        PortalAuthority:UpdateDockVisibility(true)
    elseif PortalAuthority.RefreshDockVisibility then
        PortalAuthority:RefreshDockVisibility(true)
    end
end

local function isRefreshOwnerVisible(owner)
    return owner and owner.IsShown and owner:IsShown() and true or false
end

local refreshCallbacks = {}
local function registerRefreshCallback(fn, owner)
    if type(fn) ~= "function" then
        return
    end
    refreshCallbacks[#refreshCallbacks + 1] = {
        fn = fn,
        owner = owner,
    }
end

local function refreshAllPanels()
    local perfStart, perfState = PA_PerfBegin("options_refresh_all")
    for _, entry in ipairs(refreshCallbacks) do
        local fn = entry and entry.fn or nil
        local owner = entry and entry.owner or nil
        if fn and (not owner or isRefreshOwnerVisible(owner)) then
            fn()
        end
    end
    PA_PerfEnd("options_refresh_all", perfStart, perfState)
end

if PortalAuthority then
    function PortalAuthority:RefreshOptionsPanels()
        refreshAllPanels()
    end
end

local function ensureDatabase()
    if PortalAuthority and PortalAuthority.EnsureDB then
        PortalAuthority:EnsureDB()
    end
end

local function setSettingsControlEnabled(target, enabled)
    if not target then
        return
    end

    local allow = enabled and true or false
    local control = target.control or target

    if target.SetEnabled then
        target:SetEnabled(allow)
    elseif control and control.SetEnabled then
        control:SetEnabled(allow)
    elseif allow and control and control.Enable then
        control:Enable()
    elseif (not allow) and control and control.Disable then
        control:Disable()
    elseif control and control.EnableMouse then
        control:EnableMouse(allow)
    end

    if target.label and target.label.SetAlpha then
        target.label:SetAlpha(allow and 1 or 0.55)
    end
    if control and control.SetAlpha then
        control:SetAlpha(allow and 1 or 0.55)
    end
    if control and control.Text and control.Text.SetAlpha then
        control.Text:SetAlpha(allow and 1 or 0.7)
    end
end

local function setSettingsTextEnabled(fontString, enabled)
    if fontString and fontString.SetAlpha then
        fontString:SetAlpha((enabled and true or false) and 1 or 0.55)
    end
end

local SETTINGS_SECTION_DESCRIPTOR_FLOOR = 11
local SETTINGS_SECTION_DESCRIPTOR_BOTTOM_GAP = 10

local function createSettingsSectionDescriptor(parent, text)
    local fs = createStyledFontString(parent, "ARTWORK", "GameFontHighlightSmall", 11)
    fs:SetText(tostring(text or ""))
    fs:SetTextColor(0.62, 0.64, 0.68, 0.92)
    fs:SetJustifyH("LEFT")
    fs:SetJustifyV("TOP")
    fs:SetWordWrap(true)
    return fs
end

local function layoutSettingsSectionDescriptor(descriptor, parent, left, topY, width)
    if not descriptor then
        return topY
    end
    local measuredWidth = math.max(1, math.floor(tonumber(width) or 0))
    descriptor:ClearAllPoints()
    descriptor:SetPoint("TOPLEFT", parent, "TOPLEFT", left, topY)
    descriptor:SetWidth(measuredWidth)
    local descriptorH = math.max(
        SETTINGS_SECTION_DESCRIPTOR_FLOOR,
        math.ceil(tonumber((descriptor.GetStringHeight and descriptor:GetStringHeight()) or 0) or 0)
    )
    return topY - descriptorH - SETTINGS_SECTION_DESCRIPTOR_BOTTOM_GAP
end

local function createAnnouncementsPanelLegacy()
    local panel = CreateFrame("Frame")
    panel.name = "Announcements"
    debugSettingsLog("create frame:", panel.name)

    panel.EnsureBuilt = function(self)
        debugSettingsLog("EnsureBuilt:", self.name, "initialized=", self._initialized and "true" or "false")
        if self._initialized then
            return
        end
        self._initialized = true
        ensureDatabase()

        local scrollFrame, scrollChild = createScrollableChild(self)
        self._sizingFrame = scrollFrame
        local widgets = {}

        local function helper(text, r, g, b)
            local fs = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlightSmall", 11)
            fs:SetText(text)
            fs:SetJustifyH("LEFT")
            fs:SetTextColor(r or 0.8, g or 0.8, b or 0.8)
            return fs
        end

        local function sectionHeader(text)
            local fs = createStyledFontString(scrollChild, "ARTWORK", "GameFontNormalLarge", 14)
            fs:SetText(string.format("|cffffd100%s|r", text))
            return fs
        end

        widgets.playerHeader = createTopRightHeader(self, -PAGE.PLAYER_HEADER_PAD)
        widgets.header = sectionHeader("Announcements")
        widgets.sectionDescriptor = createSettingsSectionDescriptor(scrollChild, "Customize your utility alerts.")
        widgets.routingHint = helper("Routing: RAID in raids, PARTY in parties.")

        local function createMessageBlock(titleText, enabledKey, textKey, defaultText, showDestinationHelper)
            local block = {}
            block.title = createStyledFontString(scrollChild, "ARTWORK", "GameFontNormal", 12)
            block.title:SetText(titleText)
            block.enabled = createCheckbox(scrollChild, "Enable", enabledKey)
            block.messageLabel = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlight", 12)
            block.messageLabel:SetText("Message")
            block.edit = CreateFrame("EditBox", nil, scrollChild, "InputBoxTemplate")
            block.edit:SetAutoFocus(false)
            block.edit:SetTextInsets(8, 8, 0, 0)
            block.edit:SetText(PortalAuthorityDB[textKey])
            applyGlobalFontToObject(block.edit, 12)

            local function save(box)
                local text = trim(box:GetText())
                if text == "" then text = defaultText end
                PortalAuthorityDB[textKey] = text
                box:SetText(text)
            end
            block.edit:SetScript("OnEnterPressed", function(box) save(box); box:ClearFocus() end)
            block.edit:SetScript("OnEditFocusLost", save)

            if showDestinationHelper then
                block.destinationHint = helper("Use [destination] in your message to insert the destination name.", 1, 0.35, 0.35)
            end

            return block
        end

        local function registerAnnouncementToggleBlockSearch(block)
            if type(block) ~= "table" or not frameIsAlive(block.title) or not frameIsAlive(block.enabled) then
                return nil
            end

            if frameIsAlive(block.enabled.text) then
                settingsSearchRuntime.markSearchTextOrigin(block.enabled.text, "choice_caption", {
                    searchChoiceLabelMode = "suppress_generic",
                })
            end

            local extraRefs = {}
            local function addExtraRef(ref)
                if frameIsAlive(ref) then
                    extraRefs[#extraRefs + 1] = ref
                end
            end

            addExtraRef(block.description)
            addExtraRef(block.destinationHint)
            return settingsSearchRuntime.registerControlText(block.title, block.enabled, "checkbox", extraRefs)
        end

        local function createSummonRequestsBlock()
            local block = {}
            block.title = createStyledFontString(scrollChild, "ARTWORK", "GameFontNormal", 12)
            local warlockOnlyLabel = string.format("|c%sWarlock only|r", getClassHex("WARLOCK"))
            block.title:SetText(string.format("Summon Requests (%s)", warlockOnlyLabel))
            block.enabled = createCheckbox(scrollChild, "Enable", "summonRequestsEnabled")
            block.description = helper("Popup alert for Party, Raid, Whisper, and Battle.net summon asks (e.g., '1', 'sum', 'summon', '123 plz'). It is flexible in understanding intent.", 0.72, 0.72, 0.72)
            block.soundChannel = createDropdown(scrollChild, "Channel |cff7f7f7f(recommended: Master)|r", SUMMON_SOUND_CHANNEL_CHOICES, "summonRequestSoundChannel")
            block.sound = createDynamicDropdown(
                scrollChild,
                "Alert sound |cff7f7f7f(select NONE for visual only)|r",
                function()
                    return getSummonSoundChoices(PortalAuthorityDB and PortalAuthorityDB.summonRequestSound or "")
                end,
                function()
                    return normalizeSoundChoiceValue(PortalAuthorityDB and PortalAuthorityDB.summonRequestSound or "")
                end,
                function(value)
                    PortalAuthorityDB.summonRequestSound = value
                end
            )
            return block
        end

        local function createSummonStoneRequestsBlock()
            local block = {}
            block.title = createStyledFontString(scrollChild, "ARTWORK", "GameFontNormal", 12)
            local warlockOnlyLabel = string.format("|c%sWarlock only|r", getClassHex("WARLOCK"))
            block.title:SetText(string.format("Summon Stone Requests (%s)", warlockOnlyLabel))
            block.enabled = createCheckbox(scrollChild, "Enable", "summonStoneRequestsEnabled")
            block.description = helper("Popup alert for Party, Raid, Whisper, and Battle.net closet requests stone (e.g., 'closet','stone plz').", 0.72, 0.72, 0.72)
            block.soundChannel = createDropdown(scrollChild, "Channel |cff7f7f7f(recommended: Master)|r", SUMMON_SOUND_CHANNEL_CHOICES, "summonStoneRequestSoundChannel")
            block.sound = createDynamicDropdown(
                scrollChild,
                "Alert sound |cff7f7f7f(select NONE for visual only)|r",
                function()
                    return getSummonSoundChoices(PortalAuthorityDB and PortalAuthorityDB.summonStoneRequestSound or "")
                end,
                function()
                    return normalizeSoundChoiceValue(PortalAuthorityDB and PortalAuthorityDB.summonStoneRequestSound or "")
                end,
                function(value)
                    PortalAuthorityDB.summonStoneRequestSound = value
                end
            )
            return block
        end

        widgets.portals = createMessageBlock("Portals", "portalsEnabled", "portalsText", PortalAuthority.defaults.portalsText, true)
        widgets.teleports = createMessageBlock("Teleports", "teleportsEnabled", "teleportsText", PortalAuthority.defaults.teleportsText, true)
        widgets.mplus = createMessageBlock("Mythic+ Teleports", "mplusEnabled", "mplusText", PortalAuthority.defaults.mplusText, true)
        widgets.warlockSummoning = createMessageBlock("Summoning Stone", "warlockSummoningEnabled", "warlockSummoningText", PortalAuthority.defaults.warlockSummoningText)
        if widgets.warlockSummoning and widgets.warlockSummoning.messageLabel then
            widgets.warlockSummoning.messageLabel:SetText("Message")
        end
        widgets.summonRequests = createSummonRequestsBlock()
        widgets.summonStoneRequests = createSummonStoneRequestsBlock()
        registerAnnouncementToggleBlockSearch(widgets.portals)
        registerAnnouncementToggleBlockSearch(widgets.teleports)
        registerAnnouncementToggleBlockSearch(widgets.mplus)
        registerAnnouncementToggleBlockSearch(widgets.warlockSummoning)
        registerAnnouncementToggleBlockSearch(widgets.summonRequests)
        registerAnnouncementToggleBlockSearch(widgets.summonStoneRequests)

        local function layoutCheckboxRow(check, y, checkX, labelX)
            check:ClearAllPoints()
            check:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", checkX, y)
            check.text:ClearAllPoints()
            check.text:SetPoint("LEFT", check, "RIGHT", 10, 0)
            check.text:SetJustifyH("LEFT")
        end

        local function layoutMessageBlock(block, y, contentW, left, right, checkX, labelX, controlX)
            block.title:ClearAllPoints()
            block.title:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", left, y)
            y = y - 18

            layoutCheckboxRow(block.enabled, y, checkX, labelX)

            block.messageLabel:ClearAllPoints()
            block.messageLabel:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", controlX, y)

            y = y - 16
            block.edit:ClearAllPoints()
            block.edit:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", controlX, y)
            block.edit:SetSize(contentW - right - controlX, 22)

            y = y - 27
            if block.destinationHint then
                block.destinationHint:ClearAllPoints()
                block.destinationHint:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", controlX, y)
                block.destinationHint:SetWidth(contentW - right - controlX)
                y = y - 18
            end

            return y - 4
        end

        local function layoutInlineDropdown(spec, x, y, width)
            spec.label:ClearAllPoints()
            spec.label:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", x, y)
            spec.control:ClearAllPoints()
            spec.control:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", x - 20, y - 14)
            UIDropDownMenu_SetWidth(spec.control, width)
        end

        local function layoutSummonRequestsBlock(block, y, contentW, left, right, checkX, labelX, controlX)
            block.title:ClearAllPoints()
            block.title:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", left, y)
            y = y - 18

            layoutCheckboxRow(block.enabled, y, checkX, labelX)

            block.description:ClearAllPoints()
            block.description:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", controlX, y - 2)
            block.description:SetWidth(contentW - controlX - right)
            block.description:SetWordWrap(true)

            y = y - 30
            local gap = 20
            local dropdownWidth = math.max(120, math.floor((contentW - controlX - right - gap) / 2))
            layoutInlineDropdown(block.soundChannel, controlX, y, dropdownWidth)
            layoutInlineDropdown(block.sound, controlX + dropdownWidth + gap, y, dropdownWidth)

            return y - 54
        end

        local function relayout()
            local contentW = math.max(320, scrollFrame:GetWidth() - 24)
            local left, right = 16, 16
            local CHECK_X = left
            local CHECKBOX_WIDTH = 24
            local LABEL_X = CHECK_X + CHECKBOX_WIDTH + 10
            local CONTROL_X = LABEL_X + 88

            scrollChild:SetWidth(contentW)

            widgets.playerHeader:ClearAllPoints()
            widgets.playerHeader:SetPoint("TOPRIGHT", self, "TOPRIGHT", -20, -20)

            local y = -8
            widgets.header:ClearAllPoints(); widgets.header:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", left, y)
            y = y - 24
            y = layoutSettingsSectionDescriptor(widgets.sectionDescriptor, scrollChild, left, y, contentW - left - right)

            widgets.routingHint:ClearAllPoints(); widgets.routingHint:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", left, y)
            widgets.routingHint:SetWidth(contentW - left - right)
            y = y - 20
            y = y - 14

            y = layoutMessageBlock(widgets.portals, y, contentW, left, right, CHECK_X, LABEL_X, CONTROL_X)
            y = layoutMessageBlock(widgets.teleports, y, contentW, left, right, CHECK_X, LABEL_X, CONTROL_X)
            y = layoutMessageBlock(widgets.mplus, y, contentW, left, right, CHECK_X, LABEL_X, CONTROL_X)
            y = layoutMessageBlock(widgets.warlockSummoning, y, contentW, left, right, CHECK_X, LABEL_X, CONTROL_X)
            y = layoutSummonRequestsBlock(widgets.summonRequests, y, contentW, left, right, CHECK_X, LABEL_X, CONTROL_X)
            y = layoutSummonRequestsBlock(widgets.summonStoneRequests, y, contentW, left, right, CHECK_X, LABEL_X, CONTROL_X)

            scrollChild:SetHeight(math.max(scrollFrame:GetHeight(), -y + 20))
            updateScrollBehavior(scrollFrame, scrollChild)
        end

        self._refresh = function()
            widgets.portals.enabled:SetChecked(PortalAuthorityDB.portalsEnabled)
            widgets.teleports.enabled:SetChecked(PortalAuthorityDB.teleportsEnabled)
            widgets.mplus.enabled:SetChecked(PortalAuthorityDB.mplusEnabled)
            widgets.warlockSummoning.enabled:SetChecked(PortalAuthorityDB.warlockSummoningEnabled)
            widgets.summonRequests.enabled:SetChecked(PortalAuthorityDB.summonRequestsEnabled)
            widgets.summonRequests.soundChannel.Refresh()
            widgets.summonRequests.sound.Refresh()
            widgets.summonStoneRequests.enabled:SetChecked(PortalAuthorityDB.summonStoneRequestsEnabled)
            widgets.summonStoneRequests.soundChannel.Refresh()
            widgets.summonStoneRequests.sound.Refresh()
            relayout()
        end

        registerRefreshCallback(self._refresh, self)
        scrollFrame:SetScript("OnSizeChanged", relayout)
    end

    panel:SetScript("OnShow", function(self)
        debugSettingsLog("OnShow:", self.name)
        self:EnsureBuilt()
        refreshPanel(self)
    end)

    return panel
end

local function createAnnouncementsPanel()
    local panel = CreateFrame("Frame")
    panel.name = "Announcements"
    panel._paSearchSectionKey = "announcements"
    panel._paSearchSectionName = panel.name
    debugSettingsLog("create frame:", panel.name)
    ensureDatabase()

    panel.EnsureBuilt = function(self)
        debugSettingsLog("EnsureBuilt:", self.name, "initialized=", self._initialized and "true" or "false")
        if self._initialized then
            return
        end
        self._initialized = true
        resetSettingsFirstOpenPanelState(self)
        local panelOwner = self
        settingsSearchRuntime.beginDescriptorCapture(self)

        local scrollFrame, scrollChild = createScrollableChild(self)
        if not scrollFrame or not scrollChild then
            settingsSearchRuntime.endDescriptorCapture(self)
            return
        end
        self._sizingFrame = scrollFrame

        local st = {
            panel = self,
            scrollFrame = scrollFrame,
            scrollChild = scrollChild,
            rows = {},
            rowsById = {},
            cards = {},
            templateRows = {},
            pickerSpecs = {},
            expandedRowId = nil,
        }
        self._annState = st

        local function buildAnnouncementsLayoutTokens()
            return {
                HEADER_LEFT = 16,
                LEFT = 20,
                RIGHT = 20,
                CARD_TO_CARD_GAP = 12,
                CARD_PAD = 10,
                CARD_HEADER_H = 18,
                CARD_HEADER_TO_ROWS_GAP = 8,
                CARD_TITLE_TO_QUALIFIER_GAP = 8,
                CARD_BOTTOM_PAD = 10,
                ROW_GAP = 6,
                ROW_PAD_TOP = 8,
                ROW_PAD_BOTTOM = 8,
                ROW_HEADER_H = 22,
                ROW_HEADER_TO_PREVIEW_GAP = 4,
                ROW_PREVIEW_LINE_H = 12,
                ROW_BODY_TOP_GAP = 8,
                ENABLE_SEGMENT_W = 136,
                CHEVRON_LANE_W = 16,
                CHEVRON_GAP = 8,
                PREVIEW_TO_CHEVRON_GAP = 8,
                PREVIEW_TEST_W = 20,
                PREVIEW_TEST_GAP = 6,
                ACCENT_GUTTER_W = 3,
                TOKEN_CHIP_H = 19,
                TOKEN_CHIP_PAD_X = 6,
                TOKEN_CHIP_TEXT_SLACK = 8,
                TOKEN_CHIP_GAP = 5,
                MESSAGE_EDIT_H = 22,
                TEST_BUTTON_W = 62,
                SOUND_PICKER_MIN_W = 164,
                SUBGROUP_LABEL_H = 13,
                SUBGROUP_TO_CONTENT_GAP = 5,
                SUBGROUP_DIVIDER_GAP_TOP = 8,
                SUBGROUP_DIVIDER_GAP_BOTTOM = 8,
                ROW_TITLE_TO_RIGHT_CLUSTER_GAP = 8,
                INLINE_BODY_CONTROL_GAP = 8,
                SECTION_HEADER_TO_FIRST_CARD_GAP = 6,
                PREVIEW_PREFIX_TO_VALUE_GAP = 4,
                ROW_CONTENT_AFTER_ACCENT_GAP = 6,
                ROW_TITLE_TOP_NUDGE = 2,
                ROW_PREVIEW_TOP_NUDGE = 1,
                ROW_PREVIEW_TEST_TOP_NUDGE = 2,
                ROW_CHEVRON_TOP_NUDGE = 2,
                ROW_HEADER_BAND_EXTRA = 6,
                ROW_EXPANDED_INFO_TOP_GAP = 4,
                FIELD_LABEL_H = 14,
                LABEL_TO_CONTROL_GAP = 3,
                CONTROL_H = 22,
                CONTROL_TO_HINT_GAP = 5,
                HELPER_LINE_H = 12,
                HELPER_TO_CHIP_GAP = 4,
                CHIP_TO_RESET_GAP = 6,
                UNAVAILABLE_HINT_TOP_GAP = 2,
                UNAVAILABLE_HINT_BLOCK_H = 16,
                SECTION_TOP = 20,
                SECTION_HEADER_H = 28,
                SECTION_BOTTOM_PAD = 20,
                MIN_CONTENT_W = 560,
                SCROLL_WIDTH_FUDGE = 8,
                MIN_ROW_W = 120,
                MIN_TITLE_W = 80,
                MIN_BODY_W = 80,
                MIN_PREVIEW_PREFIX_W = 40,
                MAX_PREVIEW_PREFIX_W = 92,
                MIN_PREVIEW_VALUE_W = 20,
                PREVIEW_PREFIX_MEASURE_FALLBACK_W = 42,
                PREVIEW_PREFIX_MEASURE_PAD = 2,
                TOKEN_CHIP_MIN_W = 56,
                DIVIDER_H = 1,
                MIN_CARD_H = 80,
            }
        end

        local T = buildAnnouncementsLayoutTokens()
        local C = T
        local function getCurrentPlayerClass()
            local classFile = nil
            if UnitClass then
                _, classFile = UnitClass("player")
            end
            return tostring(classFile or "")
        end

        local function isCurrentClass(classFile)
            return getCurrentPlayerClass() == tostring(classFile or "")
        end

        local function helperTone(fs)
            if not fs then
                return
            end
            fs:SetTextColor(0.58, 0.58, 0.58, 0.92)
        end

        local function contextualHelperTone(fs)
            if not fs then
                return
            end
            fs:SetTextColor(0.52, 0.52, 0.54, 0.88)
        end

        local function elevateInteractiveFrame(frame, parent, extraLevel)
            if not frame or not parent or not frame.SetFrameLevel or not parent.GetFrameLevel then
                return
            end
            frame:SetFrameLevel((parent:GetFrameLevel() or 0) + (extraLevel or 5))
        end

        local function setSingleLineEllipsis(fs, fullText, maxWidth)
            if not fs then
                return
            end
            local text = tostring(fullText or "")
            local width = math.max(1, math.floor(tonumber(maxWidth) or 0))
            fs:SetWordWrap(false)
            if fs.SetMaxLines then
                fs:SetMaxLines(1)
            end
            fs:SetWidth(width)
            fs:SetText(text)
            if fs:GetStringWidth() <= width then
                return
            end
            local cut = string.len(text)
            while cut > 0 do
                local candidate = string.sub(text, 1, cut) .. "..."
                fs:SetText(candidate)
                if fs:GetStringWidth() <= width then
                    return
                end
                cut = cut - 1
            end
            fs:SetText("...")
        end

        local announcementsMeasureStrings = {}
        local function getAnnouncementsMeasureString(template, size)
            local key = string.format("%s:%s", tostring(template or ""), tostring(size or ""))
            local fs = announcementsMeasureStrings[key]
            if fs then
                return fs
            end
            fs = scrollChild:CreateFontString(nil, "ARTWORK", template)
            applyGlobalFontToObject(fs, size)
            fs:SetWordWrap(false)
            if fs.SetMaxLines then
                fs:SetMaxLines(1)
            end
            fs:Hide()
            announcementsMeasureStrings[key] = fs
            return fs
        end

        local function measureAnnouncementsSingleLineWidth(text, template, size, floor)
            local fs = getAnnouncementsMeasureString(template, size)
            fs:SetText(tostring(text or ""))
            local measured = math.ceil(tonumber((fs.GetStringWidth and fs:GetStringWidth()) or 0) or 0)
            return math.max(math.floor(tonumber(floor) or 0), measured)
        end

        local function getAnnouncementsEffectiveTextHeight(fs, floor)
            local minimum = math.max(0, math.floor(tonumber(floor) or 0))
            if not fs or not fs.GetStringHeight then
                return minimum
            end
            local measured = math.ceil(tonumber(fs:GetStringHeight() or 0) or 0)
            return math.max(minimum, measured)
        end

        local function getAnnouncementsEffectiveControlHeight(control, floor)
            local minimum = math.max(0, math.floor(tonumber(floor) or 0))
            local measured = 0
            if control and control.GetHeight then
                measured = math.ceil(tonumber(control:GetHeight() or 0) or 0)
            end
            local label = control and control.Text or nil
            if label and label.GetStringHeight then
                measured = math.max(measured, math.ceil(tonumber(label:GetStringHeight() or 0) or 0) + 8)
            end
            return math.max(minimum, measured)
        end

        local function layoutAnnouncementsContainedText(fs, fullText, width, floor)
            if not fs then
                return math.max(0, math.floor(tonumber(floor) or 0))
            end
            setSingleLineEllipsis(fs, fullText, width)
            return getAnnouncementsEffectiveTextHeight(fs, floor)
        end

        local function layoutAnnouncementsContainedButtonText(button, fullText, insetX, floor)
            if not button or not button.Text then
                return getAnnouncementsEffectiveControlHeight(button, floor)
            end
            local padding = math.max(0, math.floor(tonumber(insetX) or 8))
            local textW = math.max(1, math.floor((button:GetWidth() or 0) - (padding * 2)))
            setSingleLineEllipsis(button.Text, fullText, textW)
            return getAnnouncementsEffectiveControlHeight(button, floor)
        end

        local function setAnnouncementsSingleLineWidth(fs, width)
            if not fs then
                return
            end
            fs:SetWordWrap(false)
            if fs.SetMaxLines then
                fs:SetMaxLines(1)
            end
            fs:SetWidth(math.max(1, math.floor(tonumber(width) or 0)))
        end

        local function getAnnouncementsSegmentedHeight(spec, floor)
            local measured = getAnnouncementsEffectiveControlHeight(spec and spec.control or nil, floor)
            for _, btn in ipairs((spec and spec.buttons) or {}) do
                local btnHeight = getAnnouncementsEffectiveControlHeight(btn, floor)
                measured = math.max(measured, btnHeight)
            end
            return math.max(math.floor(tonumber(floor) or 0), measured)
        end

        local function setAnnouncementsSegmentedHeight(spec, height)
            local targetH = math.max(1, math.floor(tonumber(height) or 0))
            if not spec or not spec.control then
                return
            end
            spec.control:SetHeight(targetH)
            for _, btn in ipairs(spec.buttons or {}) do
                btn:SetHeight(targetH)
            end
        end

        local function createSubtleCard(parent)
            local card = CreateFrame("Frame", nil, parent, "BackdropTemplate")
            card:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
                insets = { left = 0, right = 0, top = 0, bottom = 0 },
            })
            card:SetBackdropColor(0.06, 0.07, 0.09, 0.42)
            card:SetBackdropBorderColor(0.20, 0.23, 0.29, 0.50)
            return card
        end

        local function createInterruptCardBody(card)
            local body = CreateFrame("Frame", nil, card)
            body:SetAllPoints(card)
            body:SetFrameStrata(card:GetFrameStrata())
            body:SetFrameLevel((card:GetFrameLevel() or 0) + 1)
            return body
        end

        local function syncInterruptCardBody(card, body)
            if not card or not body then
                return
            end
            body:ClearAllPoints()
            body:SetAllPoints(card)
            body:SetFrameStrata(card:GetFrameStrata())
            body:SetFrameLevel((card:GetFrameLevel() or 0) + 1)
        end

        local function styleMicroChip(button)
            styleSecondaryActionButtonShared(button, {
                baseBg = { 0.09, 0.10, 0.12, 0.90 },
                hoverBg = { 0.12, 0.13, 0.16, 0.94 },
                pressedBg = { 0.07, 0.08, 0.10, 0.95 },
                baseBorder = { 0.20, 0.23, 0.28, 0.56 },
                hoverBorder = { 0.26, 0.29, 0.34, 0.65 },
                pressedBorder = { 0.23, 0.26, 0.31, 0.62 },
                textColor = { 0.74, 0.76, 0.80, 0.96 },
            })
            button:SetHeight(C.TOKEN_CHIP_H)
            if button.Text then
                applyGlobalFontToObject(button.Text, 10)
            end
        end

        local function getTemplateStoredValue(row)
            local value = trim((PortalAuthorityDB and PortalAuthorityDB[row.textKey]) or "")
            if value == "" then
                value = trim(row.defaultText or "")
            end
            return value
        end

        local function normalizeTemplateInput(text)
            local normalized = trim(tostring(text or ""))
            if normalized == "" then
                return nil
            end
            return normalized
        end

        local function resolveSummonSoundLabel(value)
            local selected = normalizeSoundChoiceValue(value)
            for _, option in ipairs(getSummonSoundChoices(value) or {}) do
                if tostring(option.value or "") == tostring(selected or "") then
                    return tostring(option.label or selected)
                end
            end
            if selected == "" or selected == nil then
                return "None"
            end
            return tostring(selected)
        end

        local function previewSummonSoundValue(value)
            if value == nil or value == "" then
                return
            end
            local soundFile = value
            if PortalAuthority and PortalAuthority.GetDeathAlertSoundFile then
                soundFile = PortalAuthority:GetDeathAlertSoundFile(value) or value
            end
            if not soundFile or soundFile == "" then
                return
            end
            if type(soundFile) == "number" and PlaySound then
                PlaySound(soundFile, "Master")
            elseif PlaySoundFile then
                PlaySoundFile(soundFile, "Master")
            end
        end

        local function playCurrentSummonPreview(row)
            if not row or not row.soundKey then
                return
            end
            previewSummonSoundValue(PortalAuthorityDB and PortalAuthorityDB[row.soundKey] or "")
        end

        local function makeEnableSegment(parent, row)
            row._enabledVisualValue = PA_SafeBool((PortalAuthorityDB and PortalAuthorityDB[row.enabledKey]) or false)
            local segmented = createPremiumSegmentedChoice(parent, "", nil, {
                { label = "Disabled", value = false, toggleState = "off" },
                { label = "Enabled", value = true, toggleState = "on" },
            }, function(v)
                local newValue = PA_SafeBool(v)
                row._enabledVisualValue = newValue
                if PortalAuthorityDB then
                    PortalAuthorityDB[row.enabledKey] = newValue
                end
                if row.kind == "template" then
                    st:ClearTemplateBatchFeedback()
                end
                if st.panel and st.panel._refresh then
                    st.panel._refresh()
                end
            end, {
                semantic = "toggle",
                textEllipsis = true,
                normalizeValue = function(v)
                    return PA_SafeBool(v)
                end,
                getValue = function()
                    return PA_SafeBool(row._enabledVisualValue)
                end,
                setValue = function(v)
                    row._enabledVisualValue = PA_SafeBool(v)
                end,
            })
            if segmented and segmented.label then
                segmented.label:SetText("")
                segmented.label:Hide()
            end
            return segmented
        end

        local function registerAnnouncementRowSearch(row, extraRefs)
            if type(row) ~= "table" or not frameIsAlive(row.title) then
                return nil
            end

            local controlRef = row.enabledControl
                or (row.enabled and row.enabled.control)
                or row.container
            local refs = {}
            if type(extraRefs) == "table" then
                for i = 1, #extraRefs do
                    if frameIsAlive(extraRefs[i]) then
                        refs[#refs + 1] = extraRefs[i]
                    end
                end
            end
            return settingsSearchRuntime.registerControlText(
                row.title,
                controlRef,
                "toggle",
                refs,
                row.container
            )
        end

        local function createPickerButton(parent, cfg)
            cfg = type(cfg) == "table" and cfg or {}
            local button = CreateFrame("Button", nil, parent, "BackdropTemplate")
            button:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
                insets = { left = 0, right = 0, top = 0, bottom = 0 },
            })
            button:SetBackdropColor(0.10, 0.11, 0.14, 0.95)
            button:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
            button:SetHeight(22)
            button:SetWidth(math.max(C.SOUND_PICKER_MIN_W, math.floor(tonumber(cfg.width) or 200)))

            local text = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 11)
            button.Text = text
            text:SetPoint("LEFT", button, "LEFT", 8, 0)
            text:SetPoint("RIGHT", button, "RIGHT", -18, 0)
            text:SetJustifyH("LEFT")
            text:SetTextColor(0.92, 0.92, 0.92, 1)
            text:SetWordWrap(false)
            if text.SetMaxLines then
                text:SetMaxLines(1)
            end

            local caret = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 10)
            caret:SetPoint("RIGHT", button, "RIGHT", -7, 0)
            caret:SetText("v")
            caret:SetTextColor(0.76, 0.76, 0.78, 1)
            button._paSelectEnabled = true

            local picker = CreatePicker(UIParent, {}, function(value)
                if cfg.setter then
                    cfg.setter(value)
                end
                if cfg.onApply then
                    cfg.onApply()
                end
            end, {
                title = tostring(cfg.title or "Select Option"),
                searchHint = tostring(cfg.searchHint or "Search"),
                width = tonumber(cfg.pickerWidth) or 430,
                height = tonumber(cfg.pickerHeight) or 360,
                minHeight = tonumber(cfg.minHeight),
                showSecondary = false,
                useOptionTexturePreview = cfg.useOptionTexturePreview and true or false,
                showClearButton = false,
                noSearch = cfg.noSearch and true or false,
                hideTitle = cfg.hideTitle and true or false,
                hideScrollBar = cfg.hideScrollBar and true or false,
                onOptionRightClick = type(cfg.onOptionRightClick) == "function" and cfg.onOptionRightClick or nil,
            })

            local currentLabel = ""
            local function setLabel(labelText)
                currentLabel = tostring(labelText or "")
                setSingleLineEllipsis(text, currentLabel, math.max(20, (button:GetWidth() or 0) - 26))
            end

            local function applyVisual(hovered)
                applySettingsWindowSelectButtonChrome(
                    button,
                    text,
                    caret,
                    hovered,
                    false,
                    button._paSelectEnabled ~= false,
                    function()
                        if hovered then
                            button:SetBackdropColor(0.16, 0.17, 0.20, 0.95)
                            button:SetBackdropBorderColor(0.30, 0.33, 0.38, 1.0)
                            caret:SetTextColor(0.88, 0.88, 0.90, 1)
                        else
                            button:SetBackdropColor(0.10, 0.11, 0.14, 0.95)
                            button:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
                            caret:SetTextColor(0.76, 0.76, 0.78, 1)
                        end
                    end
                )
            end

            local function buildOptions()
                local built = {}
                for _, option in ipairs(cfg.optionsProvider and cfg.optionsProvider() or {}) do
                    local value = option.value
                    if value == nil then
                        value = ""
                    end
                    built[#built + 1] = {
                        value = value,
                        label = tostring(option.label or value),
                        buttonLabel = tostring(option.buttonLabel or option.label or value),
                        secondary = tostring(option.secondary or ""),
                        previewTexturePath = option.previewTexturePath or option.path,
                    }
                end
                if #built == 0 then
                    built[1] = { value = "", label = "None", buttonLabel = "None", secondary = "" }
                end
                return built
            end

            local function resolveSelected(options)
                local selected = tostring(cfg.getter and cfg.getter() or "")
                local labelText = nil
                for _, option in ipairs(options or {}) do
                    if tostring(option.value or "") == selected then
                        labelText = tostring(option.buttonLabel or option.label or selected)
                        break
                    end
                end
                if not labelText then
                    for _, option in ipairs(options or {}) do
                        if tostring(option.value or "") == "" then
                            labelText = tostring(option.buttonLabel or option.label or "None")
                            break
                        end
                    end
                end
                if not labelText then
                    local first = options and options[1] or nil
                    labelText = first and tostring(first.buttonLabel or first.label or "None") or "None"
                end
                return selected, labelText
            end

            local spec = { control = button, picker = picker }
            spec.SetWidth = function(_, width)
                button:SetWidth(math.max(C.SOUND_PICKER_MIN_W, math.floor(tonumber(width) or C.SOUND_PICKER_MIN_W)))
                setLabel(currentLabel)
            end
            spec.SetEnabled = function(_, enabled)
                local allow = enabled and true or false
                button._paSelectEnabled = allow
                button:EnableMouse(allow)
                button:SetAlpha(allow and 1 or 0.55)
                text:SetAlpha(allow and 1 or 0.65)
                caret:SetAlpha(allow and 1 or 0.65)
                applyVisual(false)
            end
            spec.ClosePicker = function()
                if picker and picker.IsShown and picker:IsShown() then
                    picker:Close()
                end
            end
            spec.Refresh = function()
                local options = buildOptions()
                picker:SetOptions(options)
                local selected, selectedLabel = resolveSelected(options)
                picker:SetSelectedValue(selected)
                setLabel(selectedLabel)
            end

            button:SetScript("OnEnter", function()
                applyVisual(true)
            end)
            button:SetScript("OnLeave", function()
                applyVisual(false)
            end)
            button:SetScript("OnClick", function()
                if picker and picker.IsShown and picker:IsShown() then
                    picker:Close()
                    return
                end
                spec:Refresh()
                picker:Open(button)
            end)
            button:HookScript("OnSizeChanged", function()
                setLabel(currentLabel)
            end)
            registerSettingsWindowVisualRefresh(button, function()
                applyVisual(button.IsMouseOver and button:IsMouseOver() or false)
            end)

            spec:Refresh()
            st.pickerSpecs[#st.pickerSpecs + 1] = spec
            return spec
        end

        local function createMessageEdit(parent)
            local edit = CreateFrame("EditBox", nil, parent, "InputBoxTemplate")
            edit:SetAutoFocus(false)
            edit:SetTextInsets(8, 8, 0, 0)
            applyGlobalFontToObject(edit, 12)
            if not edit._paPremiumBg then
                edit._paPremiumBg = edit:CreateTexture(nil, "BACKGROUND")
                edit._paPremiumBg:SetAllPoints(edit)
                edit._paPremiumBg:SetTexture("Interface\\Buttons\\WHITE8x8")
                edit._paPremiumBorder = CreateFrame("Frame", nil, edit, "BackdropTemplate")
                edit._paPremiumBorder:SetPoint("TOPLEFT", edit, "TOPLEFT", -1, 1)
                edit._paPremiumBorder:SetPoint("BOTTOMRIGHT", edit, "BOTTOMRIGHT", 1, -1)
                edit._paPremiumBorder:SetBackdrop({ edgeFile = "Interface\\Buttons\\WHITE8x8", edgeSize = 1 })
            end

            local function refreshVisual()
                if edit.Left then edit.Left:SetAlpha(0) end
                if edit.Middle then edit.Middle:SetAlpha(0) end
                if edit.Right then edit.Right:SetAlpha(0) end
                if edit:HasFocus() then
                    edit._paPremiumBg:SetVertexColor(0.12, 0.13, 0.17, 0.95)
                    edit._paPremiumBorder:SetBackdropBorderColor(0.30, 0.33, 0.38, 1.0)
                else
                    edit._paPremiumBg:SetVertexColor(0.10, 0.11, 0.14, 0.95)
                    edit._paPremiumBorder:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
                end
            end
            edit:HookScript("OnShow", refreshVisual)
            edit:HookScript("OnEditFocusGained", refreshVisual)
            edit:HookScript("OnEditFocusLost", refreshVisual)
            refreshVisual()
            return edit
        end

