            row._lastAvailable = true
            row._syncChrome = nil
            local function setRowHover(entering)
                local delta = entering and 1 or -1
                row._hoverCount = math.max(0, (row._hoverCount or 0) + delta)
                row._hovered = row._hoverCount > 0
                if row._syncChrome then
                    row._syncChrome(row)
                end
            end
            row.collapsedClickCatcher:SetScript("OnEnter", function()
