        local function isRowAvailable(row)
            if not row or not row.classLock then
                return true
            end
            if row.classLock == "MAGE" then
                return isCurrentClass("MAGE")
            end
            if row.classLock == "WARLOCK" then
                return isCurrentClass("WARLOCK")
            end
            return true
        end

