            -- Batch template actions removed by design.
        end

        local function commitTemplateEdit(row)
            if not row or row.kind ~= "template" then
                return false
            end
            local stored = getTemplateStoredValue(row)
            local candidate = normalizeTemplateInput(row.messageEdit and row.messageEdit:GetText() or "")
            if not candidate then
                if row.messageEdit then
                    row.messageEdit:SetText(stored)
                end
                return false
            end
            if candidate ~= stored then
                if PortalAuthorityDB then
                    PortalAuthorityDB[row.textKey] = candidate
                end
                if row.messageEdit then
                    row.messageEdit:SetText(candidate)
                end
                return true
            end
            if row.messageEdit then
                row.messageEdit:SetText(stored)
            end
            return false
        end

        local function applyExpandedRowState(targetRowId)
            local resolved = nil
            if targetRowId then
                local targetRow = st.rowsById and st.rowsById[targetRowId] or nil
                if targetRow and targetRow.available then
                    resolved = targetRow.id
                end
            end
            st.expandedRowId = resolved
            for _, entry in ipairs(st.rows or {}) do
                entry.isExpanded = (resolved ~= nil and entry.id == resolved) and true or false
            end
        end

        local function commitFocusedExpandedTemplate()
            local row = st.expandedRowId and st.rowsById[st.expandedRowId] or nil
            if not row or row.kind ~= "template" or not row.messageEdit then
                return
            end
            if row.messageEdit.HasFocus and row.messageEdit:HasFocus() then
                st:ClearTemplateBatchFeedback()
                commitTemplateEdit(row)
                row.messageEdit:ClearFocus()
            end
        end

        st.SetExpandedRow = function(targetRowId)
            local nextRowId = targetRowId
            if st.expandedRowId == targetRowId then
                nextRowId = nil
            end
            commitFocusedExpandedTemplate()
            applyExpandedRowState(nextRowId)
            if st.panel and st.panel._refresh then
                st.panel._refresh()
            end
        end
        local function onRowHeaderClick(row)
            if not row or not row.available then
                return
            end
            local willExpand = st.expandedRowId ~= row.id
            if row.kind == "template" then
                st:ClearTemplateBatchFeedback()
                st.pendingFocusRowId = willExpand and row.id or nil
            else
                st.pendingFocusRowId = nil
            end
            st.SetExpandedRow(row.id)
        end

        local function applyRowChrome(row)
            if not row then
                return
            end
            local available = row.available and true or false
            local expanded = row.isExpanded and available
            local hovered = row._hovered and available
            local disabledByUser = available and (not row._enabledVisualValue)
            local rowBgAlpha = 0.02
            local borderR, borderG, borderB, borderA = 0.20, 0.23, 0.29, 0.60
            local accentA = 0
            local headerBandA = 0
            local headerDividerA = 0

            if not available then
                rowBgAlpha = 0.015
                borderA = 0.34
            elseif disabledByUser then
                rowBgAlpha = hovered and 0.028 or 0.018
                borderA = hovered and 0.68 or 0.52
                accentA = hovered and 0.60 or 0.30
            elseif expanded then
                rowBgAlpha = 0.048
                borderR, borderG, borderB, borderA = 0.95, 0.78, 0.24, 0.78
                accentA = 0.95
            elseif hovered then
                rowBgAlpha = 0.034
                borderR, borderG, borderB, borderA = 0.30, 0.33, 0.39, 0.78
                accentA = 0.46
            end

            if expanded then
                if disabledByUser then
                    headerBandA = hovered and 0.07 or 0.055
                    headerDividerA = hovered and 0.38 or 0.30
                else
                    headerBandA = hovered and 0.10 or 0.08
                    headerDividerA = hovered and 0.46 or 0.36
                end
            end

            row.bg:SetVertexColor(1, 1, 1, rowBgAlpha)
            if row.border and row.border.SetBackdropBorderColor then
                row.border:SetBackdropBorderColor(borderR, borderG, borderB, borderA)
            end
            if row.accent then
                if row._accentColor then
                    row.accent:SetVertexColor(row._accentColor[1], row._accentColor[2], row._accentColor[3], accentA)
                else
                    row.accent:SetVertexColor(1, 1, 1, 0)
                end
            end
            if row.headerBandBg then
                row.headerBandBg:SetShown(expanded)
                row.headerBandBg:SetVertexColor(0.12, 0.13, 0.16, headerBandA)
            end
            if row.headerDivider then
                row.headerDivider:SetShown(expanded)
                row.headerDivider:SetVertexColor(0.22, 0.25, 0.30, headerDividerA)
            end
            if row.title then
                if not available then
                    row.title:SetAlpha(0.52)
                elseif disabledByUser then
                    row.title:SetAlpha(hovered and 0.66 or 0.54)
                else
                    row.title:SetAlpha(0.96)
                end
            end
            if row.previewPrefix then
                if not available then
                    row.previewPrefix:SetAlpha(0.50)
                elseif disabledByUser then
                    row.previewPrefix:SetAlpha(hovered and 0.58 or 0.48)
                else
                    row.previewPrefix:SetAlpha(hovered and 0.94 or 0.88)
                end
            end
            if row.previewValue then
                if not available then
                    row.previewValue:SetAlpha(0.56)
                elseif disabledByUser then
                    row.previewValue:SetAlpha(hovered and 0.66 or 0.56)
                else
                    row.previewValue:SetAlpha(hovered and 0.88 or 0.78)
                end
            end
            if row.chevron then
                if not available then
                    row.chevron:SetAlpha(0)
                elseif disabledByUser then
                    row.chevron:SetAlpha(hovered and 0.60 or 0.35)
                else
                    row.chevron:SetAlpha(hovered and 1.0 or 0.55)
                end
            end
            if row.previewTestButton then
                if not available then
                    row.previewTestButton:SetAlpha(0.45)
                else
                    row.previewTestButton:SetAlpha(hovered and 0.96 or 0.86)
                end
            end
        end

        for _, row in ipairs(st.rows or {}) do
            row._syncChrome = applyRowChrome
            row.collapsedClickCatcher:SetScript("OnClick", function()
                onRowHeaderClick(row)
            end)
            row.expandedHeaderClickCatcher:SetScript("OnClick", function()
                onRowHeaderClick(row)
            end)
            if row.kind == "template" then
                row.messageEdit:SetScript("OnEnterPressed", function(box)
                    st:ClearTemplateBatchFeedback()
                    commitTemplateEdit(row)
                    box:ClearFocus()
                    if st.panel and st.panel._refresh then
                        st.panel._refresh()
                    end
                end)
                row.messageEdit:SetScript("OnEditFocusLost", function()
                    st:ClearTemplateBatchFeedback()
                    if commitTemplateEdit(row) and st.panel and st.panel._refresh then
                        st.panel._refresh()
                    end
                end)
                row.resetButton:SetScript("OnClick", function()
                    st:ClearTemplateBatchFeedback()
                    local fallback = trim(row.defaultText or "")
                    if fallback == "" then
                        fallback = getTemplateStoredValue(row)
                    end
                    row.messageEdit:SetText(fallback)
                    if PortalAuthorityDB and fallback ~= getTemplateStoredValue(row) then
                        PortalAuthorityDB[row.textKey] = fallback
                    end
                    if st.panel and st.panel._refresh then
                        st.panel._refresh()
                    end
                end)
                row.destinationChip:SetScript("OnClick", function()
                    st:ClearTemplateBatchFeedback()
                    local token = "[destination]"
                    local current = tostring(row.messageEdit:GetText() or "")
                    local left = row.messageEdit:GetCursorPosition() or string.len(current)
                    left = math.max(0, math.min(left, string.len(current)))
                    local newValue = string.sub(current, 1, left) .. token .. string.sub(current, left + 1)
                    row.messageEdit:SetText(newValue)
                    row.messageEdit:SetCursorPosition(left + string.len(token))
                    row.messageEdit:SetFocus()
                end)
            else
                row.previewTestButton:SetScript("OnClick", function()
                    if row.available then
                        playCurrentSummonPreview(row)
                    end
                end)
                row.testButton:SetScript("OnClick", function()
                    if row.available then
                        playCurrentSummonPreview(row)
                    end
                end)
            end
        end

        local function refreshCardState(card, available, suffixText)
            card.available = available and true or false
            local baseText = tostring(card.titleBase or "")
            if card.titleColorCode then
                baseText = string.format("|c%s%s|r", tostring(card.titleColorCode), baseText)
            end
            local qualifierText = ""
            if (not card.available) and tostring(suffixText or "") ~= "" then
                qualifierText = tostring(suffixText or "")
            end
            card.titleText = baseText
            card.titleQualifierText = qualifierText
            card.title:SetText(baseText)
            if card.titleQualifier then
                card.titleQualifier:SetText(qualifierText)
                card.titleQualifier:SetShown(qualifierText ~= "")
            end
            for _, row in ipairs(card.rows or {}) do
                row.available = card.available and isRowAvailable(row)
            end
        end

        local function refreshAllCardStates()
            local isMage = isCurrentClass("MAGE")
            local isWarlock = isCurrentClass("WARLOCK")
            refreshCardState(cardA, true, "")
            refreshCardState(cardB, isMage, "Mage only")
            refreshCardState(cardC, isWarlock, "Warlock only")
            applyExpandedRowState(st.expandedRowId)
        end

        local function syncAnnouncementsVisualState()
            for _, row in ipairs(st.rows or {}) do
                row._enabledVisualValue = PA_SafeBool((PortalAuthorityDB and PortalAuthorityDB[row.enabledKey]) or false)
                if row.enabled and row.enabled.Refresh then
                    row.enabled:Refresh()
                end
                if row.enabled and row.enabled.SetEnabled then
                    row.enabled:SetEnabled(row.available)
                end

                local previewValueText
                if row.kind == "template" then
                    previewValueText = getTemplateStoredValue(row)
                    if row.messageEdit and not (row.messageEdit.HasFocus and row.messageEdit:HasFocus()) then
                        row.messageEdit:SetText(previewValueText)
                    end
                else
                    previewValueText = resolveSummonSoundLabel((PortalAuthorityDB and PortalAuthorityDB[row.soundKey]) or "")
                    if row.soundPicker and row.soundPicker.Refresh then
                        row.soundPicker:Refresh()
                    end
                end

                row._previewRawText = previewValueText
                row._previewPrefixRawText = tostring(row.previewPrefixText or "Message:")
                if row.previewPrefix then
                    row.previewPrefix:SetText(row._previewPrefixRawText)
                end
                if row.previewValue then
                    row.previewValue:SetText(previewValueText or "")
                end

                row.container:SetAlpha(row.available and 1 or 0.82)
                if (row._lastExpanded ~= row.isExpanded) or (row._lastAvailable ~= row.available) then
                    row._hoverCount = 0
                    row._hovered = false
                end
                row._lastExpanded = row.isExpanded
                row._lastAvailable = row.available

                if row.collapsedClickCatcher then
                    local collapsedActive = row.available and (not row.isExpanded)
                    row.collapsedClickCatcher:SetShown(collapsedActive)
                    row.collapsedClickCatcher:EnableMouse(collapsedActive)
                end
                if row.expandedHeaderClickCatcher then
                    local expandedActive = row.available and row.isExpanded
                    row.expandedHeaderClickCatcher:SetShown(expandedActive)
                    row.expandedHeaderClickCatcher:EnableMouse(expandedActive)
                end
                if row.chevron then
                    row.chevron:SetText(row.isExpanded and "v" or ">")
                    row.chevron:SetShown(row.available)
                end
                if row.previewTestButton then
                    row.previewTestButton:SetEnabled(row.available and (not row.isExpanded))
                end
                if row.testButton then
                    row.testButton:SetEnabled(row.available and row.isExpanded)
                end
                applyRowChrome(row)
            end
        end

        local function applyPendingAnnouncementsFocus()
            local targetRowId = st.pendingFocusRowId
            if not targetRowId then
                return
            end
            local row = st.rowsById and st.rowsById[targetRowId] or nil
            if not row or row.kind ~= "template" or not row.available or not row.isExpanded then
                st.pendingFocusRowId = nil
                return
            end
            if not row.messageEdit or not row.messageEdit.IsShown or not row.messageEdit:IsShown() then
                return
            end
            st.pendingFocusRowId = nil
        end

        self._refresh = function()
            refreshAllCardStates()
            syncAnnouncementsVisualState()
            if panelOwner and panelOwner._layout then
                panelOwner._layout()
            end
            applyPendingAnnouncementsFocus()
        end

        local function computeAnnouncementsGeometry(contentW)
            local cardW = math.max(0, (contentW - T.RIGHT) - T.LEFT)
            local rowW = math.max(T.MIN_ROW_W, cardW - (T.CARD_PAD * 2))
            local rowContentLeft = T.CARD_PAD + T.ACCENT_GUTTER_W + T.ROW_CONTENT_AFTER_ACCENT_GAP
            local rowContentRight = T.CARD_PAD
            local rowEnableX = rowW - rowContentRight - T.ENABLE_SEGMENT_W
            local rowChevronX = rowEnableX - T.CHEVRON_GAP - T.CHEVRON_LANE_W
            return {
                contentLeft = T.LEFT,
                contentRight = T.RIGHT,
                contentSpan = cardW,
                sectionHeaderX = T.HEADER_LEFT,
                sectionHeaderY = -T.SECTION_TOP,
                sectionHeaderW = math.max(T.MIN_TITLE_W, contentW - T.HEADER_LEFT - T.RIGHT),
                cardX = T.LEFT,
                cardW = cardW,
                cardTitleW = math.max(T.MIN_TITLE_W, cardW - (T.CARD_PAD * 2)),
                cardContentLeft = rowContentLeft,
                cardContentRight = rowContentRight,
                cardContentW = math.max(T.MIN_BODY_W, cardW - rowContentLeft - rowContentRight),
                rowX = T.CARD_PAD,
                rowW = rowW,
                rowContentLeft = rowContentLeft,
                rowContentRight = rowContentRight,
                rowEnableX = rowEnableX,
                rowChevronX = rowChevronX,
                rowBodyLeft = rowContentLeft,
                rowBodyRight = rowContentRight,
                rowBodyW = math.max(T.MIN_BODY_W, rowW - rowContentLeft - rowContentRight),
            }
        end

        local function computeAnnouncementCardHeaderGeometry(card, G)
            local titleRowX = T.CARD_PAD
            local titleRowW = math.max(1, G.cardTitleW)
            local qualifierText = tostring(card.titleQualifierText or "")
            local qualifierVisible = qualifierText ~= ""
            local qualifierMeasuredW = 0
            if qualifierVisible then
                qualifierMeasuredW = measureAnnouncementsSingleLineWidth(qualifierText, "GameFontHighlight", 12, 0)
            end
            local qualifierW = qualifierVisible and math.min(qualifierMeasuredW, math.max(0, titleRowW - 1)) or 0
            local qualifierGap = 0
            if qualifierVisible and qualifierW > 0 and qualifierW < titleRowW then
                qualifierGap = math.min(T.CARD_TITLE_TO_QUALIFIER_GAP, math.max(0, titleRowW - qualifierW - 1))
            end
            local titleW = qualifierVisible and math.max(1, titleRowW - qualifierGap - qualifierW) or titleRowW
            local titleMeasuredW = measureAnnouncementsSingleLineWidth(tostring(card.titleBase or ""), "GameFontHighlight", 12, 0)
            local titleDisplayW = math.min(titleW, math.max(0, titleMeasuredW))
            local qualifierX = titleRowX + titleW
            if qualifierVisible then
                qualifierX = titleRowX + titleDisplayW + qualifierGap
            end
            return {
                titleX = titleRowX,
                titleW = titleW,
                qualifierX = qualifierX,
                qualifierW = qualifierW,
                qualifierVisible = qualifierVisible and qualifierW > 0,
            }
        end

        local function computeAnnouncementRowGeometry(row, G)
            local prefixText = row._previewPrefixRawText or tostring(row.previewPrefixText or "Message:")
            local prefixMeasure = measureAnnouncementsSingleLineWidth(prefixText, "GameFontHighlightSmall", 10, T.PREVIEW_PREFIX_MEASURE_FALLBACK_W)
            local prefixW = math.max(T.MIN_PREVIEW_PREFIX_W, math.min(T.MAX_PREVIEW_PREFIX_W, math.floor(prefixMeasure + T.PREVIEW_PREFIX_MEASURE_PAD)))
            local previewTestX = nil
            if row.kind == "summon" then
                previewTestX = G.rowChevronX - T.PREVIEW_TEST_GAP - T.PREVIEW_TEST_W
            end
            local previewRight = (previewTestX or G.rowChevronX) - T.PREVIEW_TO_CHEVRON_GAP
            local previewValueX = G.rowContentLeft + prefixW + T.PREVIEW_PREFIX_TO_VALUE_GAP
            local soundPickerW = math.max(T.SOUND_PICKER_MIN_W, G.rowBodyW - T.TEST_BUTTON_W - T.INLINE_BODY_CONTROL_GAP)
            return {
                rowTitleX = G.rowContentLeft,
                rowTitleW = math.max(T.MIN_TITLE_W, G.rowChevronX - G.rowContentLeft - T.ROW_TITLE_TO_RIGHT_CLUSTER_GAP),
                rowPreviewPrefixX = G.rowContentLeft,
                rowPreviewPrefixW = prefixW,
                rowPreviewValueX = previewValueX,
                rowPreviewValueW = math.max(T.MIN_PREVIEW_VALUE_W, previewRight - previewValueX),
                rowPreviewTestX = previewTestX,
                soundPickerX = G.rowBodyLeft,
                soundPickerW = soundPickerW,
                testButtonX = G.rowBodyLeft + soundPickerW + T.INLINE_BODY_CONTROL_GAP,
            }
        end

        local function layoutAnnouncementRow(row, y, G)
            local rowG = computeAnnouncementRowGeometry(row, G)

            row.container:ClearAllPoints()
            row.container:SetPoint("TOPLEFT", row.container:GetParent(), "TOPLEFT", G.rowX, y)
            row.container:SetWidth(G.rowW)

            row.title:ClearAllPoints()
            row.title:SetPoint("TOPLEFT", row.container, "TOPLEFT", rowG.rowTitleX, -T.ROW_PAD_TOP - T.ROW_TITLE_TOP_NUDGE)
            local titleH = layoutAnnouncementsContainedText(row.title, row.titleText or "", rowG.rowTitleW, T.ROW_HEADER_H)

            local enableH = T.ROW_HEADER_H
            if row.enabled and row.enabled.Layout then
                row.enabled:Layout(T.ENABLE_SEGMENT_W)
                enableH = getAnnouncementsSegmentedHeight(row.enabled, T.ROW_HEADER_H)
                setAnnouncementsSegmentedHeight(row.enabled, enableH)
            end
            if row.enabledControl then
                row.enabledControl:ClearAllPoints()
                row.enabledControl:SetPoint("TOPLEFT", row.container, "TOPLEFT", G.rowEnableX, -T.ROW_PAD_TOP)
            else
                enableH = T.ROW_HEADER_H
            end

            row.chevron:ClearAllPoints()
            row.chevron:SetPoint("TOPLEFT", row.container, "TOPLEFT", G.rowChevronX, -T.ROW_PAD_TOP + T.ROW_CHEVRON_TOP_NUDGE)
            row.chevron:SetWidth(T.CHEVRON_LANE_W)
            local chevronH = getAnnouncementsEffectiveTextHeight(row.chevron, T.ROW_HEADER_H)
            local headerLineH = math.max(T.ROW_HEADER_H, titleH, enableH, chevronH)
            local previewY = T.ROW_PAD_TOP + headerLineH + T.ROW_HEADER_TO_PREVIEW_GAP + T.ROW_PREVIEW_TOP_NUDGE

            row.previewPrefix:ClearAllPoints()
            row.previewPrefix:SetPoint("TOPLEFT", row.container, "TOPLEFT", rowG.rowPreviewPrefixX, -previewY)
            local previewPrefixH = layoutAnnouncementsContainedText(row.previewPrefix, row._previewPrefixRawText or tostring(row.previewPrefixText or "Message:"), rowG.rowPreviewPrefixW, T.ROW_PREVIEW_LINE_H)

            row.previewValue:ClearAllPoints()
            row.previewValue:SetPoint("TOPLEFT", row.container, "TOPLEFT", rowG.rowPreviewValueX, -previewY)
            local previewValueH = layoutAnnouncementsContainedText(row.previewValue, row._previewRawText or "", rowG.rowPreviewValueW, T.ROW_PREVIEW_LINE_H)
            local previewTextLaneH = math.max(T.ROW_PREVIEW_LINE_H, previewPrefixH, previewValueH)
            local previewLineH = previewTextLaneH

            if row.kind == "summon" and row.previewTestButton then
                local previewTestH = getAnnouncementsEffectiveControlHeight(row.previewTestButton, math.max(18, T.ROW_PREVIEW_LINE_H))
                row.previewTestButton:SetHeight(previewTestH)
                previewTestH = layoutAnnouncementsContainedButtonText(row.previewTestButton, "|>", 4, previewTestH)
                if row.isExpanded then
                    row.previewTestButton:Hide()
                else
                    previewLineH = math.max(previewLineH, previewTestH)
                    local previewTestTopY = -(previewY + math.floor((previewTextLaneH - previewTestH) * 0.5))
                    row.previewTestButton:Show()
                    row.previewTestButton:ClearAllPoints()
                    row.previewTestButton:SetPoint("TOPLEFT", row.container, "TOPLEFT", rowG.rowPreviewTestX, previewTestTopY)
                end
            end

            local collapsedH = T.ROW_PAD_TOP + headerLineH + T.ROW_HEADER_TO_PREVIEW_GAP + previewLineH + T.ROW_PAD_BOTTOM
            local headerBandH = T.ROW_PAD_TOP + headerLineH + T.ROW_HEADER_TO_PREVIEW_GAP + previewLineH + T.ROW_HEADER_BAND_EXTRA
            local bodyStartY = T.ROW_PAD_TOP + headerLineH + T.ROW_HEADER_TO_PREVIEW_GAP + previewLineH + T.ROW_BODY_TOP_GAP
            local rowH = collapsedH

            if row.isExpanded and row.available then
                local cursorY = bodyStartY
                if row.kind == "template" then
                    local expandedInfoText = tostring(row.expandedInfoText or "")
                    if expandedInfoText ~= "" and row.expandedInfo then
                        cursorY = cursorY + T.ROW_EXPANDED_INFO_TOP_GAP
                        row.expandedInfo:Show()
                        row.expandedInfo:ClearAllPoints()
                        row.expandedInfo:SetPoint("TOPLEFT", row.container, "TOPLEFT", G.rowBodyLeft, -cursorY)
                        local expandedInfoH = layoutAnnouncementsContainedText(row.expandedInfo, expandedInfoText, G.rowBodyW, T.HELPER_LINE_H)
                        cursorY = cursorY + expandedInfoH + T.CONTROL_TO_HINT_GAP
                    elseif row.expandedInfo then
                        row.expandedInfo:Hide()
                    end
                    row.messageLabel:Show()
                    row.messageEdit:Show()
                    row.resetButton:Show()
                    row.messageLabel:ClearAllPoints()
                    row.messageLabel:SetPoint("TOPLEFT", row.container, "TOPLEFT", G.rowBodyLeft, -cursorY)
                    local messageLabelH = layoutAnnouncementsContainedText(row.messageLabel, row.messageLabelText or "", G.rowBodyW, T.FIELD_LABEL_H)
                    cursorY = cursorY + messageLabelH + T.LABEL_TO_CONTROL_GAP

                    local messageEditH = getAnnouncementsEffectiveControlHeight(row.messageEdit, T.MESSAGE_EDIT_H)
                    row.messageEdit:ClearAllPoints()
                    row.messageEdit:SetPoint("TOPLEFT", row.container, "TOPLEFT", G.rowBodyLeft, -cursorY)
                    row.messageEdit:SetSize(G.rowBodyW, messageEditH)
                    cursorY = cursorY + messageEditH

                    local routingHintText = tostring(row.routingHintText or "")
                    if routingHintText ~= "" then
                        row.routingHint:Show()
                        cursorY = cursorY + T.CONTROL_TO_HINT_GAP
                        row.routingHint:ClearAllPoints()
                        row.routingHint:SetPoint("TOPLEFT", row.container, "TOPLEFT", G.rowBodyLeft, -cursorY)
                        local routingHintH = layoutAnnouncementsContainedText(row.routingHint, routingHintText, G.rowBodyW, T.HELPER_LINE_H)
                        cursorY = cursorY + routingHintH
                    else
                        row.routingHint:Hide()
                    end

                    if row.showDestinationToken then
                        local destinationHelperText = tostring(row.destinationHelperText or "")
                        local showDestinationHelper = destinationHelperText ~= ""
                        if showDestinationHelper then
                            row.destinationHelper:Show()
                        else
                            row.destinationHelper:Hide()
                        end
                        row.destinationChip:Show()
                        if showDestinationHelper then
                            cursorY = cursorY + T.CONTROL_TO_HINT_GAP
                            row.destinationHelper:ClearAllPoints()
                            row.destinationHelper:SetPoint("TOPLEFT", row.container, "TOPLEFT", G.rowBodyLeft, -cursorY)
                            local destinationHelperH = layoutAnnouncementsContainedText(row.destinationHelper, destinationHelperText, G.rowBodyW, T.HELPER_LINE_H)
                            cursorY = cursorY + destinationHelperH + T.HELPER_TO_CHIP_GAP
                        else
                            cursorY = cursorY + T.CONTROL_TO_HINT_GAP
                        end

                        local chipTextW = measureAnnouncementsSingleLineWidth(row.destinationChipText or "[destination]", "GameFontHighlightSmall", 10, 0)
                        local chipW = math.max(T.TOKEN_CHIP_MIN_W, math.floor(chipTextW + (T.TOKEN_CHIP_PAD_X * 2) + T.TOKEN_CHIP_TEXT_SLACK))
                        local chipH = getAnnouncementsEffectiveControlHeight(row.destinationChip, T.TOKEN_CHIP_H)
                        row.destinationChip:SetWidth(chipW)
                        row.destinationChip:SetHeight(chipH)
                        chipH = layoutAnnouncementsContainedButtonText(row.destinationChip, row.destinationChipText or "[destination]", T.TOKEN_CHIP_PAD_X, chipH)
                        row.destinationChip:ClearAllPoints()
                        row.destinationChip:SetPoint("TOPLEFT", row.container, "TOPLEFT", G.rowBodyLeft, -cursorY)
                        cursorY = cursorY + chipH
                    else
                        row.destinationHelper:Hide()
                        row.destinationChip:Hide()
                    end

                    cursorY = cursorY + T.CHIP_TO_RESET_GAP
                    local resetButtonH = getAnnouncementsEffectiveControlHeight(row.resetButton, T.CONTROL_H)
                    row.resetButton:SetHeight(resetButtonH)
                    resetButtonH = layoutAnnouncementsContainedButtonText(row.resetButton, "Reset", 8, resetButtonH)
                    row.resetButton:ClearAllPoints()
                    row.resetButton:SetPoint("TOPRIGHT", row.container, "TOPRIGHT", -G.rowContentRight, -cursorY)
                    cursorY = cursorY + resetButtonH
                    rowH = math.max(collapsedH, cursorY + T.ROW_PAD_BOTTOM)
                else
                    row.soundLabel:Show()
                    if row.soundPicker and row.soundPicker.control then
                        row.soundPicker.control:Show()
                    end
                    row.testButton:Show()
                    row.masterHint:Show()
                    row.soundLabel:ClearAllPoints()
                    row.soundLabel:SetPoint("TOPLEFT", row.container, "TOPLEFT", G.rowBodyLeft, -cursorY)
                    local soundLabelH = layoutAnnouncementsContainedText(row.soundLabel, row.soundLabelText or "", G.rowBodyW, T.FIELD_LABEL_H)
                    cursorY = cursorY + soundLabelH + T.LABEL_TO_CONTROL_GAP

                    local soundPickerControl = row.soundPicker and row.soundPicker.control or nil
                    local soundPickerH = getAnnouncementsEffectiveControlHeight(soundPickerControl, T.CONTROL_H)
                    local testButtonH = getAnnouncementsEffectiveControlHeight(row.testButton, T.CONTROL_H)
                    row.testButton:SetHeight(testButtonH)
                    testButtonH = layoutAnnouncementsContainedButtonText(row.testButton, "Test", 8, testButtonH)
                    local inlineControlH = math.max(T.CONTROL_H, soundPickerH, testButtonH)
                    if row.soundPicker and row.soundPicker.SetWidth then
                        row.soundPicker:SetWidth(rowG.soundPickerW)
                    end
                    if soundPickerControl then
                        soundPickerControl:SetHeight(inlineControlH)
                        soundPickerControl:ClearAllPoints()
                        soundPickerControl:SetPoint("TOPLEFT", row.container, "TOPLEFT", rowG.soundPickerX, -cursorY)
                    end
                    row.testButton:SetHeight(inlineControlH)
                    layoutAnnouncementsContainedButtonText(row.testButton, "Test", 8, inlineControlH)
                    row.testButton:ClearAllPoints()
                    if soundPickerControl then
                        row.testButton:SetPoint("LEFT", soundPickerControl, "RIGHT", T.INLINE_BODY_CONTROL_GAP, 0)
                    else
                        row.testButton:SetPoint("TOPLEFT", row.container, "TOPLEFT", rowG.testButtonX, -cursorY)
                    end
                    cursorY = cursorY + inlineControlH + T.CONTROL_TO_HINT_GAP

                    row.masterHint:ClearAllPoints()
                    row.masterHint:SetPoint("TOPLEFT", row.container, "TOPLEFT", G.rowBodyLeft, -cursorY)
                    local masterHintH = layoutAnnouncementsContainedText(row.masterHint, row.masterHintText or "", G.rowBodyW, T.HELPER_LINE_H)
                    cursorY = cursorY + masterHintH
                    rowH = math.max(collapsedH, cursorY + T.ROW_PAD_BOTTOM)
                end
            else
                if row.kind == "template" then
                    if row.expandedInfo then
                        row.expandedInfo:Hide()
                    end
                    row.messageLabel:Hide()
                    row.messageEdit:Hide()
                    row.resetButton:Hide()
                    row.routingHint:Hide()
                    row.destinationHelper:Hide()
                    row.destinationChip:Hide()
                else
                    row.soundLabel:Hide()
                    if row.soundPicker and row.soundPicker.control then
                        row.soundPicker.control:Hide()
                    end
                    row.testButton:Hide()
                    row.masterHint:Hide()
                end
            end

            row.container:SetHeight(rowH)
            row.headerBandBg:ClearAllPoints()
            row.headerBandBg:SetPoint("TOPLEFT", row.container, "TOPLEFT", 0, 0)
            row.headerBandBg:SetPoint("TOPRIGHT", row.container, "TOPRIGHT", 0, 0)
            row.headerBandBg:SetHeight(headerBandH)
            row.headerDivider:ClearAllPoints()
            row.headerDivider:SetPoint("TOPLEFT", row.container, "TOPLEFT", 0, -headerBandH)
            row.headerDivider:SetPoint("TOPRIGHT", row.container, "TOPRIGHT", 0, -headerBandH)
            row.headerDivider:SetHeight(T.DIVIDER_H)
            row.collapsedClickCatcher:ClearAllPoints()
            row.collapsedClickCatcher:SetPoint("TOPLEFT", row.container, "TOPLEFT", 0, 0)
            row.collapsedClickCatcher:SetPoint("BOTTOMRIGHT", row.container, "BOTTOMRIGHT", 0, 0)
            row.expandedHeaderClickCatcher:ClearAllPoints()
            row.expandedHeaderClickCatcher:SetPoint("TOPLEFT", row.container, "TOPLEFT", 0, 0)
            row.expandedHeaderClickCatcher:SetPoint("TOPRIGHT", row.container, "TOPRIGHT", 0, 0)
            row.expandedHeaderClickCatcher:SetHeight(headerBandH)
            return y - rowH - T.ROW_GAP
        end

        local function layoutAnnouncementCard(card, y, G)
            card.frame:ClearAllPoints()
            card.frame:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", G.cardX, y)
            card.frame:SetWidth(G.cardW)

            local headerG = computeAnnouncementCardHeaderGeometry(card, G)
            card.title:ClearAllPoints()
            card.title:SetPoint("TOPLEFT", card.frame, "TOPLEFT", headerG.titleX, -T.CARD_PAD)
            setAnnouncementsSingleLineWidth(card.title, headerG.titleW)
            card.title:SetText(card.titleText or tostring(card.titleBase or ""))
            local cardTitleH = getAnnouncementsEffectiveTextHeight(card.title, T.CARD_HEADER_H)

            local qualifierH = 0
            if card.titleQualifier then
                card.titleQualifier:ClearAllPoints()
                card.titleQualifier:SetPoint("TOPLEFT", card.frame, "TOPLEFT", headerG.qualifierX, -T.CARD_PAD)
                if headerG.qualifierVisible then
                    qualifierH = layoutAnnouncementsContainedText(card.titleQualifier, card.titleQualifierText or "", headerG.qualifierW, T.CARD_HEADER_H)
                else
                    setAnnouncementsSingleLineWidth(card.titleQualifier, 1)
                end
            end
            local titleRowH = math.max(T.CARD_HEADER_H, cardTitleH, qualifierH)

            local rowY = -(T.CARD_PAD + titleRowH + T.CARD_HEADER_TO_ROWS_GAP)
            if card.available then
                card.unavailableHint:Hide()
            else
                card.unavailableHint:Show()
                card.unavailableHint:ClearAllPoints()
                card.unavailableHint:SetPoint("TOPLEFT", card.frame, "TOPLEFT", T.CARD_PAD, -(T.CARD_PAD + titleRowH + T.UNAVAILABLE_HINT_TOP_GAP))
                local unavailableHintH = layoutAnnouncementsContainedText(card.unavailableHint, card.unavailableHintText or "", G.cardTitleW, T.HELPER_LINE_H)
                local unavailableBlockH = math.max(T.UNAVAILABLE_HINT_BLOCK_H, T.UNAVAILABLE_HINT_TOP_GAP + unavailableHintH)
                rowY = rowY - unavailableBlockH
            end
            local subgroupW = math.max(T.MIN_TITLE_W, G.cardW - G.cardContentLeft - T.CARD_PAD)
            if card == cardC then
                if card.subgroupAnnouncements then
                    card.subgroupAnnouncements:Show()
                    card.subgroupAnnouncements:SetTextColor(0.58, 0.51, 0.79, 0.70)
                    card.subgroupAnnouncements:ClearAllPoints()
                    card.subgroupAnnouncements:SetPoint("TOPLEFT", card.frame, "TOPLEFT", G.cardContentLeft, rowY)
                    local subgroupAnnouncementsH = layoutAnnouncementsContainedText(card.subgroupAnnouncements, card.subgroupAnnouncementsText or "", subgroupW, T.SUBGROUP_LABEL_H)
                    rowY = rowY - subgroupAnnouncementsH - T.SUBGROUP_TO_CONTENT_GAP
                end

                local templateRow = card.rows and card.rows[1] or nil
                local summonRow1 = card.rows and card.rows[2] or nil
                local summonRow2 = card.rows and card.rows[3] or nil
                if templateRow then
                    rowY = layoutAnnouncementRow(templateRow, rowY, G)
                end

                rowY = rowY - T.SUBGROUP_DIVIDER_GAP_TOP
                if card.subgroupDivider then
                    card.subgroupDivider:Show()
                    card.subgroupDivider:ClearAllPoints()
                    card.subgroupDivider:SetPoint("TOPLEFT", card.frame, "TOPLEFT", G.cardContentLeft, rowY)
                    card.subgroupDivider:SetPoint("TOPRIGHT", card.frame, "TOPRIGHT", -T.CARD_PAD, rowY)
                    card.subgroupDivider:SetHeight(T.DIVIDER_H)
                end
                rowY = rowY - T.DIVIDER_H - T.SUBGROUP_DIVIDER_GAP_BOTTOM

                if card.subgroupIncoming then
                    card.subgroupIncoming:Show()
                    card.subgroupIncoming:SetTextColor(0.58, 0.51, 0.79, 0.70)
                    card.subgroupIncoming:ClearAllPoints()
                    card.subgroupIncoming:SetPoint("TOPLEFT", card.frame, "TOPLEFT", G.cardContentLeft, rowY)
                    local subgroupIncomingH = layoutAnnouncementsContainedText(card.subgroupIncoming, card.subgroupIncomingText or "", subgroupW, T.SUBGROUP_LABEL_H)
                    rowY = rowY - subgroupIncomingH - T.SUBGROUP_TO_CONTENT_GAP
                end

                if summonRow1 then
                    rowY = layoutAnnouncementRow(summonRow1, rowY, G)
                end
                if summonRow2 then
                    rowY = layoutAnnouncementRow(summonRow2, rowY, G)
                end
            else
                if card.subgroupAnnouncements then card.subgroupAnnouncements:Hide() end
                if card.subgroupIncoming then card.subgroupIncoming:Hide() end
                if card.subgroupDivider then card.subgroupDivider:Hide() end
                for _, row in ipairs(card.rows or {}) do
                    rowY = layoutAnnouncementRow(row, rowY, G)
                end
            end

            local cardH = math.max(T.MIN_CARD_H, -rowY + T.CARD_BOTTOM_PAD)
            card.frame:SetHeight(cardH)
            return y - cardH - T.CARD_TO_CARD_GAP
        end

        local function layoutAnnouncements()
            if not scrollFrame or not scrollChild then
                return
            end
            local contentW = math.max((scrollFrame:GetWidth() or 0) - T.SCROLL_WIDTH_FUDGE, T.MIN_CONTENT_W)
            scrollChild:SetWidth(contentW)
            local G = computeAnnouncementsGeometry(contentW)
            local useHostedChrome = isPanelUsingCustomSettingsWindowHost(panelOwner)

            st.playerHeader:ClearAllPoints()
            st.playerHeader:SetPoint("TOPRIGHT", panelOwner, "TOPRIGHT", -20, -20)

            local y = -T.SECTION_TOP
            if useHostedChrome then
                y = y - SETTINGS_WINDOW_HOSTED_TOP_RHYTHM_NUDGE
            end
            if useHostedChrome then
                setSettingsWindowChromeVisible(header, false, scrollChild)
                setSettingsWindowChromeVisible(st.sectionDescriptor, false, scrollChild)
            else
                setSettingsWindowChromeVisible(header, true)
                setSettingsWindowChromeVisible(st.sectionDescriptor, true, scrollChild)
                header:ClearAllPoints()
                header:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", G.sectionHeaderX, G.sectionHeaderY)
                setAnnouncementsSingleLineWidth(header, G.sectionHeaderW)
                local sectionHeaderH = getAnnouncementsEffectiveTextHeight(header, T.SECTION_HEADER_H)
                y = y - sectionHeaderH - T.SECTION_HEADER_TO_FIRST_CARD_GAP
                y = layoutSettingsSectionDescriptor(st.sectionDescriptor, scrollChild, G.sectionHeaderX, y, G.sectionHeaderW)
            end
            y = layoutAnnouncementCard(cardA, y, G)
            y = layoutAnnouncementCard(cardB, y, G)
            y = layoutAnnouncementCard(cardC, y, G)

            scrollChild:SetHeight(math.max(scrollFrame:GetHeight(), -y + T.SECTION_BOTTOM_PAD))
            updateScrollBehavior(scrollFrame, scrollChild)
        end

        self._layout = layoutAnnouncements

        registerRefreshCallback(function()
            if shouldSuppressSettingsFirstOpenExternalRefresh(panelOwner) then
                return
            end
            if panelOwner and panelOwner._refresh then
                panelOwner._refresh()
            end
        end, panelOwner)
        scrollFrame:SetScript("OnSizeChanged", function()
            if handleSettingsFirstOpenSizeReady(panelOwner, "size_changed") then
                return
            end
            if shouldSuppressSettingsFirstOpenExternalRefresh(panelOwner) then
                return
            end
            if panelOwner and panelOwner._layout then
                panelOwner._layout()
            end
        end)

        self._settingsFirstOpenKey = "announcements"
        self._settingsFirstOpenSizeTarget = scrollFrame
        self._settingsFirstOpenRender = function(panel)
            if panel and panel._layout then
                panel._layout()
            end
            if panel and panel._refresh then
                panel._refresh()
            end
        end
        self._settingsFirstOpenIsReady = function(panel)
            local state = panel and panel._annState or nil
            local scroll = panel and panel._sizingFrame or nil
            local child = state and state.scrollChild or nil
            local firstRow = state and state.cardA and state.cardA.rows and state.cardA.rows[1] or nil
            local useHostedChrome = isPanelUsingCustomSettingsWindowHost(panel)
            return panelHasSizedViewport(scroll)
                and state ~= nil
                and state.header ~= nil
                and (useHostedChrome or state.header:IsShown())
                and state.cardA ~= nil and state.cardA.frame ~= nil and state.cardA.frame:IsShown()
                and state.cardB ~= nil and state.cardB.frame ~= nil and state.cardB.frame:IsShown()
                and state.cardC ~= nil and state.cardC.frame ~= nil and state.cardC.frame:IsShown()
                and firstRow ~= nil and firstRow.container ~= nil and firstRow.container:IsShown()
                and child ~= nil
                and (tonumber(child:GetHeight()) or 0) >= math.max(tonumber(scroll and scroll:GetHeight()) or 0, 1)
        end
        settingsSearchRuntime.endDescriptorCapture(self)
    end
    panel:SetScript("OnShow", function(selfPanel)
        debugSettingsLog("OnShow:", selfPanel.name)
        ensureSettingsCanvasPanelAnchored(selfPanel)
        selfPanel:EnsureBuilt()
        if not handleSettingsFirstOpenPanelShow(selfPanel) then
            withPanelHydration(selfPanel, function()
                if selfPanel._layout then
                    selfPanel._layout()
                end
                if selfPanel._refresh then
                    selfPanel._refresh()
                end
            end)
        end
    end)

    panel:SetScript("OnHide", function(selfPanel)
        handleSettingsFirstOpenPanelHide(selfPanel)
        local st = selfPanel and selfPanel._annState
        if not st then
            return
        end
        for _, spec in ipairs(st.pickerSpecs or {}) do
            if spec and spec.ClosePicker then
                spec:ClosePicker()
            end
        end
    end)

    return panel
end

local function createDockPanel()
    local panel = CreateFrame("Frame")
    panel.name = "Mythic+ Dock"
    panel._paSearchSectionKey = "dock"
    panel._paSearchSectionName = panel.name
    local DEBUG_XY = false
    local ensureDockPanelAnchored
    local renderDockPanel
    debugSettingsLog("create frame:", panel.name)

    panel.EnsureBuilt = function(self)
        debugSettingsLog("EnsureBuilt:", self.name, "initialized=", self._initialized and "true" or "false")
        if self._initialized and self._layout and self._refresh then
            return
        end
        resetSettingsFirstOpenPanelState(self)
        ensureDatabase()
        settingsSearchRuntime.beginDescriptorCapture(self)

        local scrollFrame, scrollChild = createScrollableChild(self)
        if not scrollFrame or not scrollChild then
            settingsSearchRuntime.endDescriptorCapture(self)
            return
        end
        self._sizingFrame = scrollFrame
        local panelFrame = self
        local widgets, relayout = {}, nil
        local slotRows = {}

        local function safeDockMetric(object, methodName)
            if not object then
                return nil
            end
            local method = object[methodName]
            if type(method) ~= "function" then
                return nil
            end
            local ok, value = pcall(method, object)
            if not ok then
                return nil
            end
            return tonumber(value) or nil
        end

        local function dockNumbersDiffer(a, b)
            a = tonumber(a)
            b = tonumber(b)
            if a == nil or b == nil then
                return a ~= b
            end
            return math.abs(a - b) > 0.5
        end

        local function isDockInteractionVisible()
            return panelFrame
                and panelFrame.IsShown and panelFrame:IsShown()
                and scrollFrame
                and scrollFrame.IsShown and scrollFrame:IsShown()
        end

        local function getDockObservedScrollMax()
            local observed = 0

            local function absorbRange(owner)
                if not owner or type(owner.GetMinMaxValues) ~= "function" then
                    return
                end
                local ok, _, maxValue = pcall(owner.GetMinMaxValues, owner)
                if ok and type(maxValue) == "number" then
                    observed = math.max(observed, maxValue)
                end
            end

            local nativeRange = safeDockMetric(scrollFrame, "GetVerticalScrollRange")
            if nativeRange ~= nil then
                observed = math.max(observed, nativeRange)
            end

            absorbRange(scrollFrame and scrollFrame.ScrollBar or nil)
            absorbRange(scrollFrame and scrollFrame._paCustomScrollBar or nil)
            return observed
        end

        local function getDockFallbackScrollMax()
            local childHeight = safeDockMetric(scrollChild, "GetHeight") or 0
            local frameHeight = safeDockMetric(scrollFrame, "GetHeight") or 0
            return math.max(0, childHeight - frameHeight)
        end

        local function getDockNativeScrollMax()
            if not isDockInteractionVisible() then
                return nil
            end
            local nativeRange = safeDockMetric(scrollFrame, "GetVerticalScrollRange")
            if nativeRange == nil then
                return nil
            end
            nativeRange = math.max(0, nativeRange)
            if nativeRange <= 0 and getDockFallbackScrollMax() > 1 then
                return nil
            end
            return nativeRange
        end

        local function resolveDockCanonicalScrollMax(options)
            options = type(options) == "table" and options or {}
            local passToken = tonumber(panelFrame._dockScrollLayoutPassToken) or 0
            if panelFrame._dockResolvedNativeScrollPassToken == passToken then
                local cachedNativeMax = tonumber(panelFrame._dockResolvedNativeScrollMax)
                if cachedNativeMax ~= nil then
                    return cachedNativeMax, "native"
                end
            end

            local nativeMax = getDockNativeScrollMax()
            if nativeMax ~= nil then
                panelFrame._dockResolvedNativeScrollPassToken = passToken
                panelFrame._dockResolvedNativeScrollMax = nativeMax
                return nativeMax, "native"
            end

            if options.allowFallback == true then
                return getDockFallbackScrollMax(), "fallback"
            end

            return nil, "unavailable"
        end

        local applyDockScrollState
        local function armDockPostRelayoutSync(passToken)
            passToken = tonumber(passToken) or 0
            if passToken <= 0 or not (C_Timer and C_Timer.After) then
                return false
            end
            if panelFrame._dockPendingPostRelayoutSyncPassToken == passToken then
                return false
            end

            panelFrame._dockPendingPostRelayoutSyncPassToken = passToken
            C_Timer.After(0, function()
                if panelFrame._dockPendingPostRelayoutSyncPassToken ~= passToken then
                    return
                end
                panelFrame._dockPendingPostRelayoutSyncPassToken = nil
                if not isDockInteractionVisible() then
                    return
                end
                if (tonumber(panelFrame._dockScrollLayoutPassToken) or 0) ~= passToken then
                    return
                end
                if applyDockScrollState then
                    applyDockScrollState(nil, {
                        allowFallback = false,
                        allowPostRelayoutSync = false,
                    })
                end
            end)
            return true
        end

        local function ensureDockScrollInteractionBindings()
            panelFrame._dockMouseWheelHandler = panelFrame._dockMouseWheelHandler or function(frame, delta)
                local wheelDelta = tonumber(delta) or 0
                if wheelDelta == 0 then
                    return
                end
                if settingsScrollRuntime.closeFloatingControlsForParentScroll(frame) then
                    return
                end
                settingsScrollRuntime.noteFrameInteraction(frame)
                local currentScroll = safeDockMetric(frame, "GetVerticalScroll") or 0
                local nextScroll = currentScroll - (wheelDelta * 40)
                if applyDockScrollState then
                    applyDockScrollState(nextScroll, {
                        allowFallback = false,
                        allowPostRelayoutSync = false,
                    })
                end
            end

            local needsScroll = (safeDockMetric(scrollChild, "GetHeight") or 0) > ((safeDockMetric(scrollFrame, "GetHeight") or 0) + 1)
            scrollFrame:EnableMouseWheel(needsScroll)
            if scrollFrame.GetScript and scrollFrame.SetScript then
                if needsScroll then
                    if scrollFrame:GetScript("OnMouseWheel") ~= panelFrame._dockMouseWheelHandler then
                        scrollFrame:SetScript("OnMouseWheel", panelFrame._dockMouseWheelHandler)
                    end
                elseif scrollFrame:GetScript("OnMouseWheel") ~= nil then
                    scrollFrame:SetScript("OnMouseWheel", nil)
                end
            end
        end

        applyDockScrollState = function(requestedScroll, options)
            options = type(options) == "table" and options or {}
            if panelFrame._dockScrollSyncActive then
                return false
            end

            local maxScroll, maxSource = resolveDockCanonicalScrollMax({
                allowFallback = options.allowFallback == true,
            })
            if maxScroll == nil then
                if options.allowPostRelayoutSync == true then
                    armDockPostRelayoutSync(tonumber(panelFrame._dockScrollLayoutPassToken) or 0)
                end
                return false
            end

            local currentScroll = safeDockMetric(scrollFrame, "GetVerticalScroll") or 0
            local nextScroll = tonumber(requestedScroll)
            if nextScroll == nil then
                nextScroll = currentScroll
            end
            nextScroll = math.max(0, math.min(maxScroll, nextScroll))

            panelFrame._dockScrollSyncActive = true
            local ok = pcall(function()
                if dockNumbersDiffer(currentScroll, nextScroll) and scrollFrame.SetVerticalScroll then
                    scrollFrame._paSkipNextCustomScrollBarHookSync = true
                    scrollFrame:SetVerticalScroll(nextScroll)
                end
                settingsScrollRuntime.sync(
                    scrollFrame,
                    scrollChild,
                    safeDockMetric(scrollFrame, "GetHeight") or 0,
                    safeDockMetric(scrollChild, "GetHeight") or 0
                )
            end)
            panelFrame._dockScrollSyncActive = nil
            if not ok then
                return false
            end

            if maxSource == "native" then
                panelFrame._dockPendingPostRelayoutSyncPassToken = nil
            end
            panelFrame._dockLastCanonicalScrollMax = maxScroll
            panelFrame._dockLastCanonicalScrollSource = maxSource
            panelFrame._dockExpectedScrollMax = getDockFallbackScrollMax()
            panelFrame._dockObservedScrollMax = math.max(getDockObservedScrollMax(), maxScroll)
            return true
        end

        scrollFrame._paCustomScrollAdapter = {
            panelId = "dock",
            resolveCanonicalMax = function(adapterOptions)
                return resolveDockCanonicalScrollMax(adapterOptions)
            end,
            getCurrentValue = function()
                return safeDockMetric(scrollFrame, "GetVerticalScroll") or 0
            end,
            applyValue = function(value, adapterOptions)
                return applyDockScrollState(value, {
                    allowFallback = adapterOptions and adapterOptions.allowFallback == true,
                    allowPostRelayoutSync = adapterOptions and adapterOptions.allowPostRelayoutSync == true,
                })
            end,
        }

        local function sectionHeader(text)
            local fs = createStyledFontString(scrollChild, "ARTWORK", "GameFontNormalLarge", 14)
            fs:SetText(string.format("|cffffd100%s|r", text))
            return fs
        end

        local function buildDockLayoutTokens()
            return {
                PAGE = {
                    MIN_CONTENT_W = 340,
                    SCROLL_WIDTH_FUDGE = 24,
                    LEFT = 16,
                    RIGHT = 16,
                    NARROW_BREAKPOINT = 700,
                    WIDE_COLUMN_GAP = 26,
                    CHECK_LEFT = 20,
                    LABEL_X = 34,
                    CONTROL_X = 202,
                    PLAYER_HEADER_PAD = 20,
                    OFFSCREEN_X = -5000,
                    OFFSCREEN_Y = -5000,
                    BOTTOM_PAD = 20,
                    ROW_H = 24,
                    ROW_GAP = 4,
                    PAIR_ROW_STEP = 30,
                    DROPDOWN_MIN_W = 120,
                    DROPDOWN_MAX_W = 260,
                    NUMERIC_MIN_W = 74,
                    NUMERIC_MAX_W = 120,
                    SLIDER_MIN_W = 120,
                    SLIDER_MAX_W = 220,
                    CONTROL_WIDTH_RIGHT_PAD = 16,
                    SLIDER_WIDTH_RIGHT_PAD = 36,
                    CONTROL_PLACEMENT = {
                        DROPDOWN_X_SHIFT = -16,
                        DROPDOWN_Y_SHIFT = 4,
                        COMPACT_CONTROL_Y_SHIFT = -1,
                        SLIDER_Y_SHIFT = -2,
                        VALUE_TEXT_GAP = 8,
                    },
                },
                TOP_BLOCK = {
                    TOP_PAD = 20,
                    HEADER_LEFT = 16,
                    CONTENT_RIGHT = 20,
                    HEADER_FLOOR = 16,
                    HEADER_BOTTOM_GAP = 14,
                    LABEL_TO_TOGGLE_GAP = 12,
                    TOGGLE_TO_RESET_GAP = 12,
                    LOCK_ROW_FLOOR = 22,
                    HELPER_GAP_RATIO = 0.625,
                    DIVIDER_GAP_RATIO = 1.25,
                    DIVIDER_OFFSET_RATIO = 0.5,
                    PRESET_HEADER_GAP_RATIO = 1.5,
                    LOCK_STACK_NUDGE_Y = -0.5,
                    PRESERVED_HEADER_ADVANCE = 30,
                    LOCK_TOGGLE_MIN_W = 96,
                    LOCK_BUTTON_MIN_TEXT_W = 36,
                    LOCK_BUTTON_PAD_X = 20,
                    LOCK_SEGMENT_INNER_GAP = 4,
                },
                PRESET_AND_TABLE = {
                    LOADOUT_ROW_SHIFT_Y = 8,
                    PRESET_DIVIDER_FALLBACK_GAP = 4,
                    LOADOUT_PRESET_MIN_W = 260,
                    LOADOUT_PRESET_MAX_W = 360,
                    LOADOUT_RIGHT_PAD = 6,
                    MATCH_STATUS_GAP = 2,
                    TABLE_BLOCK_SHIFT_Y = 50,
                    DESTINATION_COLUMN_Y_SHIFT = 40,
                    NAME_SPELL_COLUMNS_Y_SHIFT = 40,
                    RESULT_COLUMN_Y_SHIFT = 46,
                    STATUS_TEXT_Y_SHIFT = 33,
                    SLOT_ENABLE_CHECKBOX_Y_SHIFT = 41,
                    SLOT_HEADER_TEXT_X_SHIFT = 5,
                    TABLE_HEADER_BOTTOM_GAP = 18,
                    SLOT_ENABLE_GAP = 12,
                    SLOT_DEST_MIN_W = 170,
                    SLOT_DEST_RATIO = 0.34,
                    SLOT_NAME_MIN_W = 120,
                    SLOT_SPELL_W = 68,
                    SLOT_RESULT_W = 30,
                    TABLE_COLUMN_GAP = 14,
                    SLOT_ROW_TOP_NUDGE = 2,
                    SLOT_RESULT_TOP_NUDGE = 4,
                    SLOT_ROW_STEP = 34,
                },
                LOWER_SECTIONS = {
                    BLOCK_OFFSET_Y = 30,
                    TABLE_TO_DIVIDER_GAP = 4,
                    DIVIDER_TO_LAYOUT_GAP = 24,
                    SEGMENTED_MIN_W = 220,
                    SEGMENTED_MAX_W = 360,
                    CONTROL_RIGHT_PAD = 12,
                    SLIDER_CONTROL_MIN_W = 162,
                    SLIDER_CONTROL_MAX_W = 230,
                    LAYOUT_STEPPER_MIN_W = 132,
                    LAYOUT_STEPPER_MAX_W = 154,
                    FONT_SIZE_STEPPER_MIN_W = 56,
                    FONT_SIZE_STEPPER_MAX_W = 68,
                    OUTLINE_ROW_MIN_W = 120,
                    OUTLINE_ROW_MAX_W = 150,
                    SECTION_HEADER_STEP = 26,
                    ROW_STEP = 34,
                    WRAP_PRESENT_TIGHTEN = 5,
                    LAYOUT_HINT_TOP_NUDGE = 3,
                    LAYOUT_HINT_STEP = 18,
                    SECTION_GAP_TIGHT = 4,
                    SECTION_GAP_LOOSE = 6,
                    VISIBILITY_DIVIDER_TOP_GAP = 4,
                    VISIBILITY_DIVIDER_STEP = 12,
                    VISIBILITY_BLOCK_SHIFT_Y = 16,
                    VISIBILITY_LABELS_SHIFT_Y = 5,
                    VISIBILITY_HEADER_STEP = 24,
                    FONT_TO_SIZE_GAP = 5,
                    SIZE_TO_SWATCH_GAP = 1,
                    FONT_ROW_CONTROL_MIN_W = 260,
                    FONT_PICKER_MIN_W = 118,
                    FONT_ROW_STEP = 36,
                },
