        local function rebuildDock()
            if PortalAuthority.RebuildDock then PortalAuthority:RebuildDock() end
            if PortalAuthority.ApplyDockPosition then PortalAuthority:ApplyDockPosition() end
        end

        local function refreshDockVisibility()
            if PortalAuthority.ApplyDockCombatVisibilityDriver then
                PortalAuthority:ApplyDockCombatVisibilityDriver()
            end

            if InCombatLockdown() then
                if PortalAuthority.QueueDockVisibilityRefresh then
                    PortalAuthority:QueueDockVisibilityRefresh()
                end
                return
            end

            if PortalAuthority.UpdateDockVisibility then
                PortalAuthority:UpdateDockVisibility(true)
            elseif PortalAuthority.RefreshDockVisibility then
                PortalAuthority:RefreshDockVisibility(true)
            end
        end

        local function queueDockPanelRefresh()
            if not panel or panel._paDockRefreshQueued then
                return
            end
            panel._paDockRefreshQueued = true
            if C_Timer and C_Timer.After then
                C_Timer.After(0, function()
                    if panel then
                        panel._paDockRefreshQueued = nil
                    end
                    if not panel or not panel.IsShown or not panel:IsShown() or not panel._refresh then
                        return
                    end
                    if isControlHydrating(panel) then
                        return
                    end
                    panel:_refresh()
                end)
                return
            end
            panel._paDockRefreshQueued = nil
            if panel and panel.IsShown and panel:IsShown() and panel._refresh and not isControlHydrating(panel) then
                panel:_refresh()
            end
        end

