        local function getSpellNameByID(spellID)
            if type(spellID) ~= "number" or spellID <= 0 then
                return ""
            end
            if C_Spell and C_Spell.GetSpellInfo then
                local info = C_Spell.GetSpellInfo(spellID)
                if type(info) == "table" and type(info.name) == "string" and info.name ~= "" then
                    return info.name
                end
            end
            if C_Spell and C_Spell.GetSpellName then
                local name = C_Spell.GetSpellName(spellID)
                if type(name) == "string" then
                    return name
                end
            end
            if GetSpellInfo then
                local name = GetSpellInfo(spellID)
                if type(name) == "string" then
                    return name
                end
            end
            return ""
        end

        local function getSpellTextureByID(spellID)
            if type(spellID) ~= "number" or spellID <= 0 then
                return nil
            end
            if C_Spell and C_Spell.GetSpellInfo then
                local info = C_Spell.GetSpellInfo(spellID)
                if type(info) == "table" and info.iconID then
                    return info.iconID
                end
            end
            if C_Spell and C_Spell.GetSpellTexture then
                return C_Spell.GetSpellTexture(spellID)
            end
            if GetSpellTexture then
                return GetSpellTexture(spellID)
            end
            if GetSpellInfo then
                local _, _, texture = GetSpellInfo(spellID)
                return texture
            end
            return nil
        end

        local DOCK_NAME_MAX_LEN = 10
        local getDockSlot
        local resolveSlotName
        local resolveSlotDefaultLabel
        local setDockSlotDefaultName
        local normalizeDockSlotRenameState
        local setDockSlotCustomName
        local getDockSlotDisplayName
        local pendingSpellLoads = {}
        local function requestSpellDataRefresh(slotIndex, spellID)
            if type(spellID) ~= "number" or spellID <= 0 then
                return
            end
            if pendingSpellLoads[slotIndex] == spellID then
                return
            end
            pendingSpellLoads[slotIndex] = spellID

            if C_Spell and C_Spell.RequestLoadSpellData then
                pcall(C_Spell.RequestLoadSpellData, spellID)
            end

            local attempts = 0
            local function tryResolve()
                if pendingSpellLoads[slotIndex] ~= spellID then
                    return
                end

                local slot = getDockSlot(slotIndex)
                if slot.spellID ~= spellID then
                    pendingSpellLoads[slotIndex] = nil
                    return
                end

                if slot.renamed ~= true then
                    setDockSlotDefaultName(slot, spellID)
                end
                local resolved = trim(slot.name or "")
                local texture = getSpellTextureByID(spellID)
                if texture then
                    pendingSpellLoads[slotIndex] = nil
                    queueDockPanelRefresh()
                    if PortalAuthority and PortalAuthority.RebuildDock then
                        PortalAuthority:RebuildDock()
                    end
                    return
                end
                if resolved ~= "" then
                    pendingSpellLoads[slotIndex] = nil
                    return
                end

                attempts = attempts + 1
                if attempts >= 10 or not (C_Timer and C_Timer.After) then
                    pendingSpellLoads[slotIndex] = nil
                    return
                end
                C_Timer.After(0.12, tryResolve)
            end

            tryResolve()
        end

        getDockSlot = function(index)
            PortalAuthorityDB.dockSlots = PortalAuthorityDB.dockSlots or {}
            local slot = PortalAuthorityDB.dockSlots[index]
            if type(slot) ~= "table" then
                slot = {}
                PortalAuthorityDB.dockSlots[index] = slot
            end
            if slot.enabled == nil then slot.enabled = false end
            if slot.selection == nil or slot.selection == "" then
                local spellID = math.floor(tonumber(slot.spellID) or 0)
                slot.selection = (spellID > 0) and tostring(spellID) or "CUSTOM"
            end
            slot.enabled = PA_SafeBool(slot.enabled)
            slot.selection = tostring(slot.selection or "CUSTOM")
            slot.spellID = math.max(0, math.floor(tonumber(slot.spellID) or 0))
            slot.name = tostring(slot.name or "")
            normalizeDockSlotRenameState(slot)
            return slot
        end

        resolveSlotName = function(spellID, fallback)
            local spellName = trim(getSpellNameByID(spellID))
            if spellName ~= "" then
                return spellName
            end
            local map = PortalAuthority and PortalAuthority.SpellMap
            local mapEntry = map and map[spellID]
            if mapEntry and trim(mapEntry.dest) ~= "" then
                return trim(mapEntry.dest)
            end
            return trim(fallback or "")
        end

        resolveSlotDefaultLabel = function(spellID, fallback)
            local map = PortalAuthority and PortalAuthority.SpellMap
            local mapEntry = map and map[spellID]
            local short = trim((mapEntry and mapEntry.short) or "")
            if short ~= "" then
                return short
            end
            local fallbackText = trim(fallback or "")
            if fallbackText ~= "" then
                return fallbackText
            end
            local spellName = trim(getSpellNameByID(spellID))
            if spellName ~= "" then
                return spellName
            end
            if mapEntry and trim(mapEntry.dest) ~= "" then
                return trim(mapEntry.dest)
            end
            return ""
        end

        local function getDockSlotCanonicalDefaultName(spellID)
            local sid = math.max(0, math.floor(tonumber(spellID) or 0))
            if sid <= 0 then
                return ""
            end
            return (resolveSlotDefaultLabel and resolveSlotDefaultLabel(sid, "")) or resolveSlotName(sid, "")
        end

        setDockSlotDefaultName = function(slot, spellID)
            if type(slot) ~= "table" then
                return ""
            end
            local sid = math.max(0, math.floor(tonumber(spellID ~= nil and spellID or slot.spellID) or 0))
            local defaultName = getDockSlotCanonicalDefaultName(sid)
            slot.name = defaultName
            slot.renamed = false
            return defaultName
        end

        normalizeDockSlotRenameState = function(slot)
            if type(slot) ~= "table" then
                return slot
            end
            slot.name = tostring(slot.name or "")
            slot.renamed = slot.renamed == true
            if slot.renamed then
                if trim(slot.name or "") == "" then
                    setDockSlotDefaultName(slot, slot.spellID)
                end
            else
                setDockSlotDefaultName(slot, slot.spellID)
            end
            return slot
        end

        setDockSlotCustomName = function(slot, text)
            if type(slot) ~= "table" then
                return ""
            end
            local customName = trim(text or "")
            if string.len(customName) > DOCK_NAME_MAX_LEN then
                customName = customName:sub(1, DOCK_NAME_MAX_LEN)
            end
            local defaultName = getDockSlotCanonicalDefaultName(slot.spellID)
            if customName == "" or customName == defaultName then
                return setDockSlotDefaultName(slot, slot.spellID)
            end
            slot.name = customName
            slot.renamed = true
            return customName
        end

        getDockSlotDisplayName = function(slot)
            if type(slot) ~= "table" then
                return ""
            end
            normalizeDockSlotRenameState(slot)
            return trim(slot.name or "")
        end

        local function getSpellMapEntryBySpellID(spellID)
            local map = PortalAuthority and PortalAuthority.SpellMap
            return map and map[spellID] or nil
        end

        local function getVisualDockIDForSpell(spellID)
            local sid = math.max(0, math.floor(tonumber(spellID) or 0))
            if sid <= 0 then
                return 0
            end
            local entry = getSpellMapEntryBySpellID(sid)
            local itemID = entry and math.floor(tonumber(entry.useItemID) or 0) or 0
            if itemID > 0 then
                return itemID
            end
            return sid
        end

        local function resolveSpellIDFromVisualDockID(rawValue)
            local visualID = math.max(0, math.floor(tonumber(rawValue) or 0))
            if visualID <= 0 then
                return 0
            end
            local map = PortalAuthority and PortalAuthority.SpellMap
            if type(map) == "table" then
                for sid, entry in pairs(map) do
                    local itemID = entry and math.floor(tonumber(entry.useItemID) or 0) or 0
                    if itemID > 0 and itemID == visualID then
                        local spellID = math.floor(tonumber(sid) or 0)
                        if spellID > 0 then
                            return spellID
                        end
                    end
                end
            end
            return visualID
        end

