        local function getDockExpansionKey(spellID, info)
            local sid = math.floor(tonumber(spellID) or 0)
            if sid <= 0 then
                return nil
            end
            local mapExpansion = trim((info and info.expansion) or "")
            if mapExpansion ~= "" then
                return mapExpansion:upper()
            end
            return DOCK_EXPANSION_BY_SPELL_ID[sid]
        end

        local function getDockExpansionBadgeMarkup(expansionKey)
            local key = trim(tostring(expansionKey or "")):upper()
            if key == "" then
                return ""
            end
            local style = DOCK_EXPANSION_BADGE_STYLE[key]
            if not style then
                return ""
            end
            local rgb = style.rgb or { 0.75, 0.75, 0.75 }
            local r = math.max(0, math.min(255, math.floor((tonumber(rgb[1]) or 0.75) * 255 + 0.5)))
            local g = math.max(0, math.min(255, math.floor((tonumber(rgb[2]) or 0.75) * 255 + 0.5)))
            local b = math.max(0, math.min(255, math.floor((tonumber(rgb[3]) or 0.75) * 255 + 0.5)))
            local icon = string.format("|TInterface\\Buttons\\WHITE8x8:10:10:0:0:8:8:0:8:0:8:%d:%d:%d:255|t", r, g, b)
            return string.format("%s |cffb8b8b8%s|r", icon, style.abbr or key)
        end

        local function getDestinationChoices()
            if destinationChoicesCache and destinationChoiceByValue then
                return destinationChoicesCache
            end

            local options = {}
            local mapByValue = {}
            local entries = {}
            local categoryOrder = { portals = 1, teleports = 2, mplus = 3, raid = 3 }
            local categoryLabel = { portals = "Portal", teleports = "Teleport", mplus = "Mythic+", raid = "Raid" }
            local spellMap = (PortalAuthority and PortalAuthority.SpellMap) or {}
            local playerClass = nil
            local playerFaction = nil
            if UnitClass then
                _, playerClass = UnitClass("player")
            end
            if UnitFactionGroup then
                playerFaction = UnitFactionGroup("player")
            end
            local function getClassLabel(classFile)
                if type(classFile) ~= "string" or classFile == "" then
                    return ""
                end
                return tostring((LOCALIZED_CLASS_NAMES_MALE and LOCALIZED_CLASS_NAMES_MALE[classFile]) or (LOCALIZED_CLASS_NAMES_FEMALE and LOCALIZED_CLASS_NAMES_FEMALE[classFile]) or classFile)
            end
            local function normalizeCityKey(name)
                local key = tostring(name or "")
                key = key:gsub("?", "'")
                key = key:gsub("`", "'")
                return key:lower()
            end
            local ALLIANCE_CITY_DESTS = {
                [normalizeCityKey("Stormwind")] = true,
                [normalizeCityKey("Ironforge")] = true,
                [normalizeCityKey("Darnassus")] = true,
                [normalizeCityKey("Exodar")] = true,
                [normalizeCityKey("Theramore")] = true,
                [normalizeCityKey("Stormshield")] = true,
                [normalizeCityKey("Boralus")] = true,
            }
            local HORDE_CITY_DESTS = {
                [normalizeCityKey("Orgrimmar")] = true,
                [normalizeCityKey("Undercity")] = true,
                [normalizeCityKey("Thunder Bluff")] = true,
                [normalizeCityKey("Silvermoon")] = true,
                [normalizeCityKey("Silvermoon (TBC)")] = true,
                [normalizeCityKey("Stonard")] = true,
                [normalizeCityKey("Warspear")] = true,
                [normalizeCityKey("Dazar'alor")] = true,
            }

            local custom = {
                label = "Custom",
                secondary = "Use Spell ID for manual assignment",
                buttonLabel = "Custom",
                value = "CUSTOM",
                aliases = { "custom", "manual", "spell id" },
            }
            table.insert(options, custom)
            mapByValue[custom.value] = custom

            for spellID, info in pairs(spellMap) do
                local sid = tonumber(spellID)
                local category = info and info.category or nil
                if sid and categoryOrder[category] then
                    local visualID = getVisualDockIDForSpell(sid)
                    local displayCategory = trim((info and info.displayCategory) or "")
                    if displayCategory == "" then
                        displayCategory = category
                    end
                    local displayOrder = categoryOrder[displayCategory] or categoryOrder[category]
                    local displayLabel = categoryLabel[displayCategory] or categoryLabel[category] or tostring(category or "")
                    local displayName = trim((info and info.dest) or "")
                    if displayName == "" then
                        displayName = trim(resolveSlotName(sid, ""))
                    end
                    if displayName == "" then
                        displayName = "Spell " .. sid
                    end
                    local spellName = trim(getSpellNameByID(sid))
                    if spellName == "" then
                        spellName = displayName
                    end
                    local shortName = trim((info and info.short) or "")
                    local requiredClass = trim((info and info.class) or "")
                    if requiredClass == "" and (category == "portals" or category == "teleports") then
                        requiredClass = "MAGE"
                    end
                    if requiredClass == "ANY" then
                        requiredClass = ""
                    end
                    local classLocked = requiredClass ~= "" and playerClass ~= requiredClass
                    local factionLocked = false
                    if playerClass == "MAGE" and (playerFaction == "Alliance" or playerFaction == "Horde") then
                        local cityKey = normalizeCityKey(displayName)
                        if playerFaction == "Alliance" and HORDE_CITY_DESTS[cityKey] then
                            factionLocked = true
                        elseif playerFaction == "Horde" and ALLIANCE_CITY_DESTS[cityKey] then
                            factionLocked = true
                        end
                    end
                    local optionLocked = classLocked or factionLocked
                    local classLabel = getClassLabel(requiredClass)
                    local secondary = string.format("%s  |  ID %d  |  %s", displayLabel, visualID, spellName)
                    local expansionBadge = getDockExpansionBadgeMarkup(getDockExpansionKey(sid, info))
                    if expansionBadge ~= "" then
                        secondary = string.format("%s  |  %s", secondary, expansionBadge)
                    end
                    if classLabel ~= "" then
                        secondary = string.format("%s  |  %s only", secondary, classLabel)
                    end
                    if classLocked then
                        secondary = string.format("%s  |  Unavailable on this class", secondary)
                    end
                    if factionLocked then
                        secondary = string.format("%s  |  Unavailable for your faction", secondary)
                    end
                    local aliases = {
                        tostring(sid),
                        displayName,
                        spellName,
                        shortName,
                        buildAcronym(displayName),
                    }
                    if visualID ~= sid then
                        table.insert(aliases, tostring(visualID))
                    end
                    if classLabel ~= "" then
                        table.insert(aliases, classLabel)
                    end
                    table.insert(entries, {
                        order = displayOrder,
                        name = displayName,
                        value = tostring(sid),
                        label = displayName ~= "" and displayName or ("Spell " .. sid),
                        buttonLabel = string.format("%s: %s", displayLabel, displayName ~= "" and displayName or ("Spell " .. sid)),
                        secondary = string.format("%s  ?  ID %d", categoryLabel[category], sid),
                        aliases = aliases,
                    })
                    local added = entries[#entries]
                    if added then
                        added.secondary = secondary
                        added.disabled = optionLocked
                    end
                end
            end

            table.sort(entries, function(a, b)
                if a.order ~= b.order then
                    return a.order < b.order
                end
                local an = a.name:lower()
                local bn = b.name:lower()
                if an ~= bn then
                    return an < bn
                end
                return tonumber(a.value) < tonumber(b.value)
            end)

            for _, entry in ipairs(entries) do
                table.insert(options, entry)
                mapByValue[entry.value] = entry
            end

            destinationChoicesCache = options
            destinationChoiceByValue = mapByValue
            return options
        end

        local function getDestinationOptionByValue(value)
            getDestinationChoices()
            return destinationChoiceByValue and destinationChoiceByValue[tostring(value or "CUSTOM")] or nil
        end

        local function setDropdownEnabled(spec, enabled)
            if not spec or not spec.control then
                return
            end
            if UIDropDownMenu_EnableDropDown and UIDropDownMenu_DisableDropDown then
                if enabled then
                    UIDropDownMenu_EnableDropDown(spec.control)
                else
                    UIDropDownMenu_DisableDropDown(spec.control)
                end
            end
            spec.control:SetAlpha(enabled and 1 or 0.6)
        end

        local function applyDockChanges(reposition)
            rebuildDock()
            if reposition and PortalAuthority.ApplyDockPosition then
                PortalAuthority:ApplyDockPosition()
            end
            refreshDockVisibility()
        end

        local function onUIChanged(reposition)
            applyDockChanges(reposition)
            local dockSearchPanel = settingsSearchRuntime.getPanelFromObject(scrollChild)
            if dockSearchPanel then
                dockSearchPanel._paSearchRegistryDirty = true
            end
            if relayout then relayout() end
        end

        local function ApplyDockLayoutSettings(reposition)
            if PortalAuthority and PortalAuthority.ApplyDockLayoutSettings then
                PortalAuthority:ApplyDockLayoutSettings(reposition and true or false)
            else
                applyDockChanges(reposition)
            end
            if relayout then relayout() end
        end

        local function ApplyDockAppearanceSettings()
            if PortalAuthority and PortalAuthority.ApplyDockAppearanceSettings then
                PortalAuthority:ApplyDockAppearanceSettings()
            else
                applyDockChanges(false)
            end
            if relayout then relayout() end
        end

        local function normalizeDockSimpleLayoutModeValue(value)
            local mode = string.upper(trim(tostring(value or "GRID")))
            if mode == "HORIZONTAL" then
                mode = "HORIZONTAL_ROW"
            elseif mode == "VERTICAL" then
                mode = "VERTICAL_COLUMN"
            end
            if mode ~= "HORIZONTAL_ROW" and mode ~= "VERTICAL_COLUMN" and mode ~= "GRID" then
                mode = "GRID"
            end
            return mode
        end

        local function normalizeDockLabelModeValue(value)
            if value == false then
                return "OFF"
            end
            if value == true then
                return "OUTSIDE"
            end
            local mode = string.upper(trim(tostring(value or "OUTSIDE")))
            if mode ~= "OFF" and mode ~= "OUTSIDE" and mode ~= "INSIDE" then
                mode = "OUTSIDE"
            end
            return mode
        end

        local function normalizeDockLabelSideValue(value)
            local side = string.upper(trim(tostring(value or "BOTTOM")))
            if side ~= "BOTTOM" and side ~= "TOP" and side ~= "LEFT" and side ~= "RIGHT" and side ~= "CENTER" then
                side = "BOTTOM"
            end
            return side
        end

        local function isOutsideDockLabelSideValue(value)
            return value == "BOTTOM" or value == "TOP" or value == "LEFT" or value == "RIGHT"
        end

        local function normalizeDockOutsideLabelSideValue(value, fallback)
            local resolvedFallback = string.upper(trim(tostring(fallback or "BOTTOM")))
            if resolvedFallback ~= "BOTTOM" and resolvedFallback ~= "TOP" and resolvedFallback ~= "LEFT" and resolvedFallback ~= "RIGHT" then
                resolvedFallback = "BOTTOM"
            end

            local side = string.upper(trim(tostring(value or resolvedFallback)))
            if side ~= "BOTTOM" and side ~= "TOP" and side ~= "LEFT" and side ~= "RIGHT" then
                side = resolvedFallback
            end
            if side ~= "BOTTOM" and side ~= "TOP" and side ~= "LEFT" and side ~= "RIGHT" then
                side = "BOTTOM"
            end
            return side
        end

        local function normalizeOutlineToggleValue(value)
            if type(value) == "string" then
                local upper = string.upper(trim(value))
                if upper == "OUTLINE" or upper == "THICKOUTLINE" then
                    return "OUTLINE"
                end
            end
            return ""
        end

        local function normalizeHoverGlowToggleValue(value)
            if value == true then
                return true
            end
            if value == false or value == nil then
                return false
            end
            if type(value) == "number" then
                return value ~= 0
            end
            if type(value) == "string" then
                local lower = string.lower(trim(value))
                if lower == "true" or lower == "1" then
                    return true
                end
                return false
            end
            return PA_SafeBool(value)
        end

        local function getDockSimpleLayoutModeForSettings(defaults)
            local db = PortalAuthorityDB or {}
            local fallback = (defaults and defaults.dockSimpleLayoutMode) or "GRID"

            -- Runtime effective mode is authoritative for what the dock is currently rendering.
            if PortalAuthority and PortalAuthority._dockEffectiveLayoutMode ~= nil then
                local runtimeMode = normalizeDockSimpleLayoutModeValue(PortalAuthority._dockEffectiveLayoutMode)
                db.dockSimpleLayoutMode = runtimeMode
                db.dockSimpleLayoutModePersist = runtimeMode
                return runtimeMode
            end

            if db.dockSimpleLayoutMode ~= nil then
                local persistedMode = normalizeDockSimpleLayoutModeValue(db.dockSimpleLayoutMode)
                db.dockSimpleLayoutMode = persistedMode
                db.dockSimpleLayoutModePersist = persistedMode
                return persistedMode
            end

            if db.dockSimpleLayoutModePersist ~= nil then
                local fallbackPersistMode = normalizeDockSimpleLayoutModeValue(db.dockSimpleLayoutModePersist)
                db.dockSimpleLayoutMode = fallbackPersistMode
                db.dockSimpleLayoutModePersist = fallbackPersistMode
                return fallbackPersistMode
            end

            local normalizedFallback = normalizeDockSimpleLayoutModeValue(fallback)
            db.dockSimpleLayoutMode = normalizedFallback
            db.dockSimpleLayoutModePersist = normalizedFallback
            return normalizedFallback
        end

        local function syncLayoutModeSegmentSelection(forceVisualOnly)
            local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
            local resolvedMode = getDockSimpleLayoutModeForSettings(defaults)
            if widgets.layoutModeSegment and widgets.layoutModeSegment.Refresh and not forceVisualOnly then
                widgets.layoutModeSegment:Refresh()
            end
            if widgets.layoutModeSegment and widgets.layoutModeSegment.SetVisualSelectedValue then
                widgets.layoutModeSegment:SetVisualSelectedValue(resolvedMode)
            end
        end

        local function getDockLabelModeForSettings(defaults)
            if ensureDatabase then
                ensureDatabase()
            end
            local db = PortalAuthorityDB or {}
            local fallback = (defaults and defaults.dockLabelMode) or "OUTSIDE"
            local liveRaw = db.dockLabelMode
            local persistRaw = db.dockLabelModePersist
            if normalizeDockLabelModeValue(liveRaw or "") == "OFF" or normalizeDockLabelModeValue(persistRaw or "") == "OFF" then
                db.dockHideDungeonName = true
            end
            if db.dockHideDungeonName then
                db.dockLabelMode = "OFF"
                db.dockLabelModePersist = "OFF"
                return "OFF"
            end
            local live = db.dockLabelMode
            local persisted = db.dockLabelModePersist
            local resolvedLive = (live ~= nil) and normalizeDockLabelModeValue(live) or nil
            local resolvedPersist = (persisted ~= nil) and normalizeDockLabelModeValue(persisted) or nil
            local resolved
            if resolvedLive == "OFF" or resolvedPersist == "OFF" then
                resolved = "OFF"
            elseif resolvedLive ~= nil then
                resolved = resolvedLive
            elseif resolvedPersist ~= nil then
                resolved = resolvedPersist
            else
                resolved = normalizeDockLabelModeValue(fallback)
            end
            db.dockLabelMode = resolved
            db.dockLabelModePersist = resolved
            return resolved
        end

        local function getDockStoredLabelSideForSettings(defaults)
            if ensureDatabase then
                ensureDatabase()
            end
            local db = PortalAuthorityDB or {}
            local fallback = (defaults and defaults.dockLabelSide) or "BOTTOM"
            local source = db.dockLabelSide
            if source == nil then
                source = db.dockLabelSidePersist
            end
            return normalizeDockLabelSideValue(source or fallback)
        end

        local function getDockOutsideLabelSideForSettings(defaults)
            local db = PortalAuthorityDB or {}
            local mode = getDockLabelModeForSettings(defaults)
            local fallback = (defaults and defaults.dockLabelSideOutsidePersist) or (defaults and defaults.dockLabelSide) or "BOTTOM"
            local resolved = getDockStoredLabelSideForSettings(defaults)
            if mode == "OUTSIDE" and isOutsideDockLabelSideValue(resolved) then
                db.dockLabelSideOutsidePersist = resolved
            end
            if mode == "OUTSIDE" and isOutsideDockLabelSideValue(resolved) then
                return resolved
            end
            return normalizeDockOutsideLabelSideValue(db.dockLabelSideOutsidePersist, fallback)
        end

        local function getDockInsideLabelSideForSettings(defaults)
            local resolved = getDockStoredLabelSideForSettings(defaults)
            if resolved == "TOP" or resolved == "BOTTOM" then
                return resolved
            end
            return "CENTER"
        end

        local function setDockLabelSideForSettings(side, modeOverride)
            local db = PortalAuthorityDB or {}
            local resolvedSide = normalizeDockLabelSideValue(side)
            local resolvedMode = normalizeDockLabelModeValue(modeOverride or db.dockLabelMode or db.dockLabelModePersist or "OUTSIDE")
            db.dockLabelSide = resolvedSide
            db.dockLabelSidePersist = resolvedSide
            if resolvedMode == "OUTSIDE" and isOutsideDockLabelSideValue(resolvedSide) then
                db.dockLabelSideOutsidePersist = resolvedSide
            end
            return resolvedSide
        end

        local setLabelStyleRowsVisible

        local function forceDockLabelUiState()
            local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
            local resolvedMode = getDockLabelModeForSettings(defaults)
            local resolvedOutsideSide = getDockOutsideLabelSideForSettings(defaults)
            local resolvedInsideSide = getDockInsideLabelSideForSettings(defaults)
            if PortalAuthorityDB and resolvedMode == "OFF" then
                PortalAuthorityDB.dockHideDungeonName = true
                PortalAuthorityDB.dockLabelMode = "OFF"
                PortalAuthorityDB.dockLabelModePersist = "OFF"
            end
            if widgets.labelMode and widgets.labelMode.SetVisualSelectedValue then
                widgets.labelMode:SetVisualSelectedValue(resolvedMode)
            end
            if widgets.labelSide and widgets.labelSide.SetVisualSelectedValue then
                widgets.labelSide:SetVisualSelectedValue(resolvedOutsideSide)
            end
            if widgets.labelSideInside and widgets.labelSideInside.SetVisualSelectedValue then
                widgets.labelSideInside:SetVisualSelectedValue(resolvedInsideSide)
            end
            local showSide = (resolvedMode ~= "OFF")
            if widgets.labelSide and widgets.labelSide.control and widgets.labelSide.label then
                if resolvedMode == "OUTSIDE" then
                    widgets.labelSide.control:Show()
                    widgets.labelSide.label:Show()
                else
                    widgets.labelSide.control:Hide()
                    widgets.labelSide.label:Hide()
                end
            end
            if widgets.labelSideInside and widgets.labelSideInside.control and widgets.labelSideInside.label then
                if resolvedMode == "INSIDE" then
                    widgets.labelSideInside.control:Show()
                    widgets.labelSideInside.label:Show()
                else
                    widgets.labelSideInside.control:Hide()
                    widgets.labelSideInside.label:Hide()
                end
            end
            setLabelStyleRowsVisible(showSide)
        end

        setLabelStyleRowsVisible = function(show)
            local visible = show and true or false

            local function setSpecVisible(spec, specVisible)
                if not spec then
                    return
                end
                if spec.label and spec.label.SetShown then
                    spec.label:SetShown(specVisible)
                end
                if spec.control and spec.control.SetShown then
                    spec.control:SetShown(specVisible)
                end
            end

            setSpecVisible(widgets.font, visible)
            if widgets.fontSize and widgets.fontSize.control and widgets.fontSize.control.SetShown then
                widgets.fontSize.control:SetShown(visible)
            end
            if widgets.color and widgets.color.swatch and widgets.color.swatch.SetShown then
                widgets.color.swatch:SetShown(visible)
            end
            if widgets.color and widgets.color.inlineLabel and widgets.color.inlineLabel.SetShown then
                widgets.color.inlineLabel:SetShown(false)
            end
            setSpecVisible(widgets.outlineToggle, visible)

            if not visible and widgets.font and widgets.font.picker and widgets.font.picker.Close then
                widgets.font.picker:Close()
            end
        end

        local function forceStyleToggleUiState()
            local db = PortalAuthorityDB or {}
            local outlineValue = normalizeOutlineToggleValue(db.dockTextOutline)
            local hoverValue = normalizeHoverGlowToggleValue(db.dockHoverGlow)

            -- Canonicalize persisted values so visual state and runtime state cannot drift.
            db.dockTextOutline = outlineValue
            db.dockHoverGlow = hoverValue and true or false

            if widgets.outlineToggle and widgets.outlineToggle.SetVisualSelectedValue then
                widgets.outlineToggle:SetVisualSelectedValue(outlineValue)
            end
            if widgets.hoverGlowSegment and widgets.hoverGlowSegment.SetVisualSelectedValue then
                widgets.hoverGlowSegment:SetVisualSelectedValue(hoverValue and true or false)
            end
        end

        local function forceDockFontUiState()
            local db = PortalAuthorityDB or {}
            local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
            local selectedFontPath = db.dockFontPath
            if selectedFontPath == nil then
                selectedFontPath = defaults.dockFontPath or ""
            end
            if widgets.font and widgets.font.SetVisualSelectedValue then
                widgets.font:SetVisualSelectedValue(selectedFontPath)
            elseif widgets.font and widgets.font.Refresh then
                widgets.font:Refresh()
            end
        end

        local function forceDockFontSizeUiState()
            local db = PortalAuthorityDB or {}
            local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
            local rawValue = tonumber(db.dockFontSizeUI or db.dockFontSize or defaults.dockFontSize or 12)
            local n = math.floor((rawValue or 12) + 0.5)
            if n < 8 then n = 8 end
            if n > 48 then n = 48 end
            db.dockFontSize = n
            db.dockFontSizeUI = n

            if widgets.fontSize and widgets.fontSize.SetVisualValue then
                widgets.fontSize:SetVisualValue(n)
            elseif widgets.fontSize and widgets.fontSize.Refresh then
                widgets.fontSize:Refresh()
            end
        end

        local function syncLabelModeSegmentSelection(forceVisualOnly)
            forceDockLabelUiState()
        end

        local function syncLabelSideSegmentSelection(forceVisualOnly)
            forceDockLabelUiState()
        end

        local updateLabelModeApplicability

        local function updateLayoutModeApplicability()
            local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
            local mode = getDockSimpleLayoutModeForSettings(defaults)
            local isGrid = (mode == "GRID")

            if widgets.iconsPerRow and widgets.iconsPerRow.SetEnabled then
                widgets.iconsPerRow:SetEnabled(isGrid)
            end

            if widgets.iconsPerRow and widgets.iconsPerRow.control and widgets.iconsPerRow.label then
                if isGrid then
                    widgets.iconsPerRow.control:Show()
                    widgets.iconsPerRow.label:Show()
                else
                    widgets.iconsPerRow.control:Hide()
                    widgets.iconsPerRow.label:Hide()
                end
            end

            if widgets.iconsPerRowGridOnlyHint then
                widgets.iconsPerRowGridOnlyHint:SetShown(false)
            end
        end

        updateLabelModeApplicability = function()
            if not widgets.labelMode then
                return
            end

            local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
            local mode = getDockLabelModeForSettings(defaults)
            local showSide = (mode ~= "OFF")

            if widgets.labelSide and widgets.labelSide.control and widgets.labelSide.label then
                if mode == "OUTSIDE" then
                    widgets.labelSide.control:Show()
                    widgets.labelSide.label:Show()
                else
                    widgets.labelSide.control:Hide()
                    widgets.labelSide.label:Hide()
                end
            end
            if widgets.labelSideInside and widgets.labelSideInside.control and widgets.labelSideInside.label then
                if mode == "INSIDE" then
                    widgets.labelSideInside.control:Show()
                    widgets.labelSideInside.label:Show()
                else
                    widgets.labelSideInside.control:Hide()
                    widgets.labelSideInside.label:Hide()
                end
            end
            setLabelStyleRowsVisible(showSide)
        end

        local function getSeason01PresetSpellIDs()
            if PortalAuthority and PortalAuthority.GetMPlusDockPresetSpellIDs then
                local spellIDs = PortalAuthority:GetMPlusDockPresetSpellIDs("SEASON_01")
                if type(spellIDs) == "table" and #spellIDs > 0 then
                    return spellIDs
                end
            end

            return {
                1254400, -- Windrunner Spire
                159898,  -- Skyreach
                1254551, -- Seat of the Triumvirate
                1254555, -- Pit of Saron
                1254563, -- Nexus-Point Xenas
                1254559, -- Maisara Caverns
                1254572, -- Magister's Terrace
                393273,  -- Algeth'ar Academy
            }
        end

        local season01PresetSpellIDs = getSeason01PresetSpellIDs()

        local function getCustomSeason01MatchState()
            local enabledSpellIDs = {}
            for i = 1, 10 do
                local slot = getDockSlot(i)
                if PA_SafeBool(slot.enabled) then
                    table.insert(enabledSpellIDs, math.max(0, math.floor(tonumber(slot.spellID) or 0)))
                end
            end

            if #enabledSpellIDs ~= #season01PresetSpellIDs then
                return false, false
            end

            local counts = {}
            for _, spellID in ipairs(season01PresetSpellIDs) do
                counts[spellID] = (counts[spellID] or 0) + 1
            end
            for _, spellID in ipairs(enabledSpellIDs) do
                if spellID <= 0 then
                    return false, false
                end
                local remaining = counts[spellID] or 0
                if remaining <= 0 then
                    return false, false
                end
                counts[spellID] = remaining - 1
            end

            local orderMatches = true
            for idx, spellID in ipairs(season01PresetSpellIDs) do
                if enabledSpellIDs[idx] ~= spellID then
                    orderMatches = false
                    break
                end
            end

            return true, orderMatches
        end

        local function applySeason01Loadout()
            -- Midnight Season 01 loadout slots 1-8; slots 9-10 remain editable but disabled.
            local presetSpellIDs = season01PresetSpellIDs

            for i = 1, 10 do
                local slot = getDockSlot(i)
                local presetSpellID = presetSpellIDs[i]
                if presetSpellID and presetSpellID > 0 then
                    slot.spellID = presetSpellID
                    slot.selection = tostring(presetSpellID)
                    setDockSlotDefaultName(slot, presetSpellID)
                    slot.enabled = true
                else
                    setDockSlotDefaultName(slot, 0)
                    slot.enabled = false
                end
            end

            onUIChanged(false)
        end

        local function normalizeLoadoutPresetValue(value)
            local preset = string.upper(trim(tostring(value or "CUSTOM")))
            if preset == "SEASON_02" then
                preset = "SEASON_01"
            end
            if preset ~= "SEASON_01" and preset ~= "CUSTOM" then
                preset = "CUSTOM"
            end
            return preset
        end

        PortalAuthorityDB.dockLoadoutPreset = normalizeLoadoutPresetValue(PortalAuthorityDB.dockLoadoutPreset)

        local function buildCustomLoadoutSnapshot()
            local snapshot = {}
            for i = 1, 10 do
                local slot = getDockSlot(i)
                local spellID = math.max(0, math.floor(tonumber(slot.spellID) or 0))
                local selection = tostring(slot.selection or "")
                if selection == "" then
                    selection = (spellID > 0) and tostring(spellID) or "CUSTOM"
                end
                snapshot[i] = {
                    enabled = PA_SafeBool(slot.enabled),
                    selection = selection,
                    spellID = spellID,
                    name = tostring(slot.name or ""),
                    renamed = slot.renamed == true,
                }
            end
            return snapshot
        end

        local function saveCustomLoadoutSnapshot()
            PortalAuthorityDB.dockCustomLoadoutSlots = buildCustomLoadoutSnapshot()
        end

        local function restoreCustomLoadoutSnapshot()
            local snapshot = PortalAuthorityDB and PortalAuthorityDB.dockCustomLoadoutSlots
            if type(snapshot) ~= "table" then
                return false
            end

            local changed = false
            for i = 1, 10 do
                local source = snapshot[i]
                if type(source) == "table" then
                    local slot = getDockSlot(i)
                    local enabled = PA_SafeBool(source.enabled)
                    local spellID = math.max(0, math.floor(tonumber(source.spellID) or 0))
                    local selection = tostring(source.selection or "")
                    if selection == "" then
                        selection = (spellID > 0) and tostring(spellID) or "CUSTOM"
                    end
                    local name = tostring(source.name or "")
                    local renamed = source.renamed == true

                    if slot.enabled ~= enabled
                        or slot.spellID ~= spellID
                        or tostring(slot.selection or "") ~= selection
                        or tostring(slot.name or "") ~= name
                        or (slot.renamed == true) ~= renamed then
                        changed = true
                    end

                    slot.enabled = enabled
                    slot.spellID = spellID
                    slot.selection = selection
                    slot.name = name
                    slot.renamed = renamed
                    normalizeDockSlotRenameState(slot)
                end
            end
            return changed
        end

        local lastLoadoutPresetSelection = normalizeLoadoutPresetValue(PortalAuthorityDB.dockLoadoutPreset)
        PortalAuthorityDB.dockLoadoutPreset = lastLoadoutPresetSelection
        if lastLoadoutPresetSelection == "CUSTOM" and type(PortalAuthorityDB.dockCustomLoadoutSlots) ~= "table" then
            saveCustomLoadoutSnapshot()
        end

        local suppressLoadoutPresetAutoCustom = false
        local function refreshLoadoutPresetControl()
            lastLoadoutPresetSelection = normalizeLoadoutPresetValue(PortalAuthorityDB.dockLoadoutPreset)
            if widgets.loadoutPresetSegment and widgets.loadoutPresetSegment.Refresh then
                widgets.loadoutPresetSegment:Refresh()
            end
        end
        local function setLoadoutPresetCustom()
            if suppressLoadoutPresetAutoCustom then
                return
            end
            saveCustomLoadoutSnapshot()
            lastLoadoutPresetSelection = "CUSTOM"
            if PortalAuthorityDB.dockLoadoutPreset ~= "CUSTOM" then
                PortalAuthorityDB.dockLoadoutPreset = "CUSTOM"
                refreshLoadoutPresetControl()
            end
        end

        local function createSliderControl(labelText, key, min, max, step, isFloat, onApply)
            local label = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlight", 12)
            label:SetText(labelText)
            local slider = CreateFrame("Slider", nil, scrollChild, "OptionsSliderTemplate")
            slider:SetMinMaxValues(min, max)
            slider:SetValueStep(step)
            if slider.SetObeyStepOnDrag then
                slider:SetObeyStepOnDrag(true)
            end
            if slider.Low then slider.Low:SetText("") end
            if slider.High then slider.High:SetText("") end
            if slider.Text then slider.Text:SetText("") end
            local valueText = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlightSmall", 11)

            local suppress = false
            local function normalize(v)
                local n = tonumber(v) or min
                if n < min then n = min end
                if n > max then n = max end
                if isFloat then
                    return tonumber(string.format("%.2f", n))
                end
                return math.floor(n + 0.5)
            end
            local function fmt(v)
                if isFloat then
                    return string.format("%.2f", v)
                end
                return tostring(math.floor(v + 0.5))
            end

            slider:SetScript("OnValueChanged", function(selfSlider, value)
                if suppress or isControlHydrating(selfSlider) then return end
                local n = normalize(value)
                if not isFloat and selfSlider:GetValue() ~= n then
                    suppress = true
                    selfSlider:SetValue(n)
                    suppress = false
                end
                PortalAuthorityDB[key] = n
                valueText:SetText(fmt(n))
                if onApply then onApply() end
            end)

            local spec = { kind = "slider", label = label, control = slider, valueText = valueText }
            spec.Refresh = function()
                local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
                local n = normalize(PortalAuthorityDB[key] or defaults[key] or min)
                PortalAuthorityDB[key] = n
                suppress = true
                slider:SetValue(n)
                suppress = false
                valueText:SetText(fmt(n))
            end
            spec.Refresh()
            return settingsSearchRuntime.registerSpec(spec)
        end

        local CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A = 0.10, 0.11, 0.14, 0.95
        local CONTROL_HOVER_BG_R, CONTROL_HOVER_BG_G, CONTROL_HOVER_BG_B, CONTROL_HOVER_BG_A = 0.16, 0.17, 0.20, 0.95
        local CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A = 0.24, 0.27, 0.32, 1.0
        local CONTROL_HOVER_BORDER_R, CONTROL_HOVER_BORDER_G, CONTROL_HOVER_BORDER_B, CONTROL_HOVER_BORDER_A = 0.30, 0.33, 0.38, 1.0

        local function CreatePremiumSlider(parent, labelText, min, max, step, settingKey, width, onApply, isFloat, tooltipText)
            local label = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
            label:SetText(labelText)

            local sliderMin = tonumber(min) or 0
            local sliderMax = tonumber(max) or 100
            if sliderMax < sliderMin then
                sliderMin, sliderMax = sliderMax, sliderMin
            end

            local container = CreateFrame("Frame", nil, parent)
            container:SetHeight(22)
            container:SetWidth(math.max(120, tonumber(width) or 220))

            local valueButton = CreateFrame("Button", nil, container)
            valueButton:SetSize(44, 16)
            valueButton:SetPoint("RIGHT", container, "RIGHT", 0, 0)

            local valueText = createStyledFontString(valueButton, "ARTWORK", "GameFontHighlightSmall", 11)
            valueText:SetPoint("RIGHT", valueButton, "RIGHT", 0, 0)
            valueText:SetJustifyH("RIGHT")
            valueText:SetTextColor(0.76, 0.76, 0.78, 1)

            local valueEdit = CreateFrame("EditBox", nil, valueButton)
            valueEdit:SetAllPoints(valueButton)
            valueEdit:SetAutoFocus(false)
            valueEdit:SetJustifyH("RIGHT")
            valueEdit:SetTextInsets(0, 0, 0, 0)
            valueEdit:SetTextColor(1, 1, 1, 1)
            valueEdit:SetHighlightColor(1, 1, 1, 0.25)
            applyGlobalFontToObject(valueEdit, 11)
            valueEdit:Hide()

            local slider = CreateFrame("Slider", nil, container)
            slider:SetPoint("TOPLEFT", container, "TOPLEFT", 0, 0)
            slider:SetPoint("BOTTOMRIGHT", valueButton, "BOTTOMLEFT", -8, 0)
            slider:SetMinMaxValues(sliderMin, sliderMax)
            slider:SetValueStep(step)
            if slider.SetObeyStepOnDrag then
                slider:SetObeyStepOnDrag(true)
            end
            slider:SetThumbTexture("Interface\\Buttons\\WHITE8x8")
            local inputThumb = slider:GetThumbTexture()
            if inputThumb then
                inputThumb:SetSize(16, 16)
                -- Keep native thumb almost invisible while preserving drag mechanics.
                inputThumb:SetVertexColor(1, 1, 1, 0.01)
            end
            slider:EnableMouse(true)
            slider:SetOrientation("HORIZONTAL")

            local trackBg = slider:CreateTexture(nil, "BACKGROUND")
            trackBg:SetTexture("Interface\\Buttons\\WHITE8x8")
            trackBg:SetPoint("LEFT", slider, "LEFT", 0, 0)
            trackBg:SetPoint("RIGHT", slider, "RIGHT", 0, 0)
            trackBg:SetHeight(2)
            trackBg:SetVertexColor(0.18, 0.18, 0.19, 0.95)

            local trackActive = slider:CreateTexture(nil, "ARTWORK")
            trackActive:SetTexture("Interface\\Buttons\\WHITE8x8")
            trackActive:SetPoint("LEFT", slider, "LEFT", 0, 0)
            trackActive:SetHeight(2)
            trackActive:SetWidth(0)
            trackActive:SetVertexColor(1.0, 0.82, 0.0, 0.75)

            local thumb = slider:CreateTexture(nil, "OVERLAY")
            thumb:SetTexture("Interface\\Buttons\\WHITE8x8")
            thumb:SetSize(8, 8)
            thumb:SetVertexColor(1.0, 0.84, 0.08, 0.98)
            if thumb.SetMask then
                thumb:SetMask("Interface\\CharacterFrame\\TempPortraitAlphaMask")
            end

            local thumbGlow = slider:CreateTexture(nil, "ARTWORK")
            thumbGlow:SetTexture("Interface\\Buttons\\WHITE8x8")
            thumbGlow:SetSize(14, 14)
            thumbGlow:SetVertexColor(1.0, 0.82, 0.0, 0)
            if thumbGlow.SetMask then
                thumbGlow:SetMask("Interface\\CharacterFrame\\TempPortraitAlphaMask")
            end
            thumbGlow:SetBlendMode("ADD")

            local suppress = false
            local currentValue = nil
            local dragging = false
            local hovering = false

            local function normalize(v)
                local n = tonumber(v) or sliderMin
                if n < sliderMin then n = sliderMin end
                if n > sliderMax then n = sliderMax end
                if step and step > 0 then
                    n = sliderMin + (math.floor(((n - sliderMin) / step) + 0.5) * step)
                end
                if isFloat then
                    return tonumber(string.format("%.2f", n))
                end
                return math.floor(n + 0.5)
            end

            local function fmt(v)
                if isFloat then
                    return string.format("%.2f", tonumber(v) or 0)
                end
                return tostring(math.floor((tonumber(v) or 0) + 0.5))
            end

            local function resolveApply()
                if onApply then
                    onApply()
                    return
                end
                if settingKey == "dockIconsPerLine" or settingKey == "dockIconSpacing" then
                    ApplyDockLayoutSettings(false)
                else
                    ApplyDockAppearanceSettings()
                end
            end

            local function applyVisualState()
                local minV, maxV = slider:GetMinMaxValues()
                local value = normalize(slider:GetValue())
                local span = math.max(0.0001, (maxV - minV))
                local pct = (value - minV) / span
                pct = math.max(0, math.min(1, pct))
                local widthNow = slider:GetWidth() or 0
                local x = pct * widthNow

                thumb:ClearAllPoints()
                thumb:SetPoint("CENTER", slider, "LEFT", x, 0)
                thumbGlow:ClearAllPoints()
                thumbGlow:SetPoint("CENTER", thumb, "CENTER", 0, 0)

                trackActive:ClearAllPoints()
                trackActive:SetPoint("LEFT", slider, "LEFT", 0, 0)
                trackActive:SetPoint("RIGHT", thumb, "CENTER", 0, 0)

                local glowAlpha = 0
                if dragging then
                    glowAlpha = 0.34
                    trackActive:SetVertexColor(1.0, 0.86, 0.16, 0.9)
                    thumb:SetVertexColor(1.0, 0.9, 0.22, 1)
                elseif hovering then
                    glowAlpha = 0.22
                    trackActive:SetVertexColor(1.0, 0.85, 0.12, 0.85)
                    thumb:SetVertexColor(1.0, 0.88, 0.18, 1)
                else
                    trackActive:SetVertexColor(1.0, 0.82, 0.0, 0.75)
                    thumb:SetVertexColor(1.0, 0.84, 0.08, 0.98)
                end
                thumbGlow:SetVertexColor(1.0, 0.82, 0.0, glowAlpha)
            end

            local function setValueFromCursor()
                local minV, maxV = slider:GetMinMaxValues()
                local left = slider:GetLeft()
                local right = slider:GetRight()
                if not left or not right or right <= left then
                    return
                end
                local cx = GetCursorPosition()
                local scale = slider:GetEffectiveScale() or 1
                if not cx or scale <= 0 then
                    return
                end
                cx = cx / scale
                local pct = (cx - left) / (right - left)
                if pct < 0 then pct = 0 end
                if pct > 1 then pct = 1 end
                local raw = minV + ((maxV - minV) * pct)
                slider:SetValue(normalize(raw))
            end

            local function setValueFromInput(text)
                local normalizedText = (text or ""):gsub(",", ".")
                local parsed = tonumber(normalizedText)
                if parsed == nil then
                    return
                end
                local n = normalize(parsed)
                suppress = true
                slider:SetValue(n)
                suppress = false
                if currentValue ~= n then
                    currentValue = n
                    PortalAuthorityDB[settingKey] = n
                    if settingKey == "dockIconSize" then
                        PortalAuthorityDB.dockIconSizeUI = n
                        PortalAuthorityDB.dockIconWidth = n
                        PortalAuthorityDB.dockIconHeight = n
                    end
                    resolveApply()
                end
                valueText:SetText(fmt(n))
                applyVisualState()
            end

            local function beginEdit()
                valueText:Hide()
                valueEdit:SetText(fmt(slider:GetValue()))
                valueEdit:Show()
                valueEdit:SetFocus()
                valueEdit:HighlightText()
            end

            local function endEdit(commit)
                if commit then
                    setValueFromInput(valueEdit:GetText())
                end
                valueEdit:Hide()
                valueText:Show()
                valueEdit:ClearFocus()
                valueText:SetText(fmt(slider:GetValue()))
            end

            valueButton:SetScript("OnClick", function()
                beginEdit()
            end)
            valueEdit:SetScript("OnEnterPressed", function(edit)
                endEdit(true)
                edit:ClearFocus()
            end)
            valueEdit:SetScript("OnEscapePressed", function(edit)
                endEdit(false)
                edit:ClearFocus()
            end)
            valueEdit:SetScript("OnEditFocusLost", function()
                endEdit(true)
            end)

            slider:SetScript("OnValueChanged", function(selfSlider, value)
                local n = normalize(value)
                if selfSlider:GetValue() ~= n then
                    suppress = true
                    selfSlider:SetValue(n)
                    suppress = false
                end
                valueText:SetText(fmt(n))
                applyVisualState()
                if suppress or isControlHydrating(selfSlider) then
                    return
                end
                if currentValue == n then
                    return
                end
                currentValue = n
                PortalAuthorityDB[settingKey] = n
                if settingKey == "dockIconSize" then
                    PortalAuthorityDB.dockIconSizeUI = n
                    PortalAuthorityDB.dockIconWidth = n
                    PortalAuthorityDB.dockIconHeight = n
                end
                resolveApply()
            end)
            slider:SetScript("OnMouseDown", function()
                dragging = true
                setValueFromCursor()
                applyVisualState()
                slider:SetScript("OnUpdate", function()
                    if dragging then
                        setValueFromCursor()
                    end
                end)
            end)
            slider:SetScript("OnMouseUp", function()
                dragging = false
                slider:SetScript("OnUpdate", nil)
                applyVisualState()
            end)
            slider:SetScript("OnEnter", function(selfSlider)
                hovering = true
                applyVisualState()
                if tooltipText and tooltipText ~= "" then
                    GameTooltip:SetOwner(selfSlider, "ANCHOR_TOP")
                    GameTooltip:SetText(tooltipText, 1, 0.82, 0, 1)
                    GameTooltip:Show()
                end
            end)
            slider:SetScript("OnLeave", function()
                hovering = false
                dragging = false
                slider:SetScript("OnUpdate", nil)
                applyVisualState()
                GameTooltip:Hide()
            end)

            if tooltipText and tooltipText ~= "" then
                label:SetScript("OnEnter", function(selfLabel)
                    GameTooltip:SetOwner(selfLabel, "ANCHOR_TOPLEFT")
                    GameTooltip:SetText(tooltipText, 1, 0.82, 0, 1)
                    GameTooltip:Show()
                end)
                label:SetScript("OnLeave", function()
                    GameTooltip:Hide()
                end)
            end

            local spec = { kind = "premium_slider", label = label, control = container, slider = slider, valueText = valueText, valueEdit = valueEdit }
            spec.SetWidth = function(_, newWidth)
                local fullW = math.max(140, math.floor(tonumber(newWidth) or width or 220))
                container:SetWidth(fullW)
                applyVisualState()
            end
            spec.SetRange = function(_, newMin, newMax)
                local a = tonumber(newMin)
                local b = tonumber(newMax)
                if a == nil or b == nil then
                    return
                end
                if b < a then
                    a, b = b, a
                end
                sliderMin = a
                sliderMax = b
                slider:SetMinMaxValues(sliderMin, sliderMax)
                local n = normalize(PortalAuthorityDB[settingKey] or currentValue or slider:GetValue())
                suppress = true
                slider:SetValue(n)
                suppress = false
                currentValue = n
                PortalAuthorityDB[settingKey] = n
                if settingKey == "dockIconSize" then
                    PortalAuthorityDB.dockIconSizeUI = n
                    PortalAuthorityDB.dockIconWidth = n
                    PortalAuthorityDB.dockIconHeight = n
                end
                valueText:SetText(fmt(n))
                applyVisualState()
            end
            spec.Refresh = function()
                local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
                local storedValue = nil
                if PortalAuthorityDB then
                    if settingKey == "dockIconSize" then
                        storedValue = tonumber(PortalAuthorityDB.dockIconSizeUI or PortalAuthorityDB[settingKey])
                    else
                        storedValue = tonumber(PortalAuthorityDB[settingKey])
                    end
                end
                local n = normalize(storedValue or defaults[settingKey] or sliderMin)
                suppress = true
                slider:SetValue(n)
                suppress = false
                currentValue = n
                valueEdit:SetText(fmt(n))
                valueEdit:Hide()
                valueText:Show()
                valueText:SetText(fmt(n))
                applyVisualState()
            end
            container:SetScript("OnSizeChanged", function()
                applyVisualState()
            end)
            spec.Refresh()
            return settingsSearchRuntime.registerSpec(spec)
        end

        local function CreateStepperControl(parent, labelText, min, max, step, settingKey, width, onApply, tooltipText, opts)
            opts = type(opts) == "table" and opts or {}
            local isMicro = opts.micro and true or false
            local microShiftMultiplier = math.max(1, math.floor(tonumber(opts.shiftMultiplier) or 5))
            local customGetValue = type(opts.getValue) == "function" and opts.getValue or nil
            local customSetValue = type(opts.setValue) == "function" and opts.setValue or nil
            local label = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
            label:SetText(labelText)

            local container = CreateFrame("Frame", nil, parent)
            container:SetHeight(22)
            container:SetWidth(math.max(isMicro and 52 or 120, tonumber(width) or 160))

            local function createStepperButton(symbol)
                local button = CreateFrame("Button", nil, container, isMicro and nil or "BackdropTemplate")
                if not isMicro then
                    button:SetBackdrop({
                        bgFile = "Interface\\Buttons\\WHITE8x8",
                    })
                    button:SetBackdropColor(CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A)
                    button:SetSize(18, 18)
                else
                    button:SetSize(10, 16)
                end

                local text = createStyledFontString(button, "ARTWORK", "GameFontHighlight", 12)
                text:SetPoint("CENTER", button, "CENTER", 0, 0)
                text:SetText(symbol)
                text:SetTextColor(isMicro and 0.74 or 0.9, isMicro and 0.74 or 0.9, isMicro and 0.76 or 0.92, 1)
                button._text = text
                button._hovered = false
                button._pressed = false

                local function applyVisual(selfBtn)
                    if isMicro then
                        if selfBtn._pressed then
                            selfBtn._text:SetTextColor(0.95, 0.95, 0.98, 1)
                            selfBtn:SetAlpha(0.82)
                        elseif selfBtn._hovered then
                            selfBtn._text:SetTextColor(0.95, 0.95, 0.98, 1)
                            selfBtn:SetAlpha(1)
                        else
                            selfBtn._text:SetTextColor(0.74, 0.74, 0.76, 1)
                            selfBtn:SetAlpha(1)
                        end
                    else
                        if selfBtn._hovered then
                            selfBtn:SetBackdropColor(CONTROL_HOVER_BG_R, CONTROL_HOVER_BG_G, CONTROL_HOVER_BG_B, CONTROL_HOVER_BG_A)
                            selfBtn._text:SetTextColor(1, 0.92, 0.38, 1)
                        else
                            selfBtn:SetBackdropColor(CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A)
                            selfBtn._text:SetTextColor(0.9, 0.9, 0.92, 1)
                        end
                    end
                end

                button:SetScript("OnEnter", function(selfBtn)
                    selfBtn._hovered = true
                    applyVisual(selfBtn)
                end)
                button:SetScript("OnLeave", function(selfBtn)
                    selfBtn._hovered = false
                    selfBtn._pressed = false
                    applyVisual(selfBtn)
                end)
                button:SetScript("OnMouseDown", function(selfBtn)
                    selfBtn._pressed = true
                    applyVisual(selfBtn)
                end)
                button:SetScript("OnMouseUp", function(selfBtn)
                    selfBtn._pressed = false
                    applyVisual(selfBtn)
                end)
                return button
            end

            local minusButton = createStepperButton(isMicro and "<" or "-")
            local plusButton = createStepperButton(isMicro and ">" or "+")

            if not isMicro then
                minusButton:SetPoint("LEFT", container, "LEFT", 0, 0)
                plusButton:SetPoint("RIGHT", container, "RIGHT", 0, 0)
            end

            local valueButton = CreateFrame("Button", nil, container)
            local microLayout = nil
            if not isMicro then
                valueButton:SetPoint("LEFT", minusButton, "RIGHT", 6, 0)
                valueButton:SetPoint("RIGHT", plusButton, "LEFT", -6, 0)
                valueButton:SetHeight(18)
            else
                valueButton:SetHeight(16)
                microLayout = function()
                    local gap = 3
                    local buttonW = minusButton:GetWidth() or 10
                    local containerW = container:GetWidth() or 52
                    local valueW = math.max(20, math.min(28, containerW - (buttonW * 2) - (gap * 2)))
                    local clusterW = (buttonW * 2) + valueW + (gap * 2)
                    local startX = math.floor((containerW - clusterW) / 2)
                    if startX < 0 then
                        startX = 0
                    end

                    minusButton:ClearAllPoints()
                    minusButton:SetPoint("LEFT", container, "LEFT", startX, 0)

                    valueButton:ClearAllPoints()
                    valueButton:SetPoint("LEFT", minusButton, "RIGHT", gap, 0)
                    valueButton:SetWidth(valueW)

                    plusButton:ClearAllPoints()
                    plusButton:SetPoint("LEFT", valueButton, "RIGHT", gap, 0)
                end
                microLayout()
                container:HookScript("OnSizeChanged", function()
                    if microLayout then
                        microLayout()
                    end
                end)
            end

            local valueText = createStyledFontString(valueButton, "ARTWORK", "GameFontHighlightSmall", 11)
            valueText:SetPoint("CENTER", valueButton, "CENTER", 0, 0)
            if isMicro then
                valueText:SetTextColor(0.86, 0.86, 0.9, 1)
            else
                valueText:SetTextColor(0.76, 0.76, 0.78, 1)
            end

            local valueEdit = CreateFrame("EditBox", nil, valueButton)
            valueEdit:SetAllPoints(valueButton)
            valueEdit:SetAutoFocus(false)
            valueEdit:SetJustifyH("CENTER")
            valueEdit:SetTextInsets(0, 0, 0, 0)
            valueEdit:SetTextColor(1, 1, 1, 1)
            valueEdit:SetHighlightColor(1, 1, 1, 0.25)
            valueEdit:SetNumeric(true)
            applyGlobalFontToObject(valueEdit, 11)
            valueEdit:Hide()

            local stepValue = tonumber(step) or 1
            if stepValue <= 0 then
                stepValue = 1
            end

            local currentValue = nil
            local editingValue = false
            local controlEnabled = true

            local function normalize(v)
                local n = tonumber(v) or min
                if n < min then n = min end
                if n > max then n = max end
                n = min + (math.floor(((n - min) / stepValue) + 0.5) * stepValue)
                if n < min then n = min end
                if n > max then n = max end
                return math.floor(n + 0.5)
            end

            local function fmt(v)
                return tostring(math.floor((tonumber(v) or 0) + 0.5))
            end

            local function setValue(newValue, triggerApply)
                local n = normalize(newValue)
                if currentValue == n then
                    valueText:SetText(fmt(n))
                    return
                end
                currentValue = n
                if customSetValue then
                    customSetValue(n)
                else
                    PortalAuthorityDB[settingKey] = n
                    if settingKey == "dockFontSize" then
                        PortalAuthorityDB.dockFontSizeUI = n
                    end
                end
                valueText:SetText(fmt(n))
                if triggerApply and onApply then
                    onApply()
                end
            end

            local function beginEdit()
                editingValue = true
                valueText:Hide()
                valueEdit:SetText(fmt(currentValue or min))
                valueEdit:Show()
                valueEdit:SetFocus()
                valueEdit:HighlightText()
            end

            local function endEdit(commit)
                if not editingValue then
                    return
                end
                editingValue = false
                if commit then
                    local parsed = tonumber(valueEdit:GetText())
                    if parsed ~= nil then
                        setValue(parsed, true)
                    end
                end
                valueEdit:Hide()
                valueText:Show()
                valueEdit:ClearFocus()
                valueText:SetText(fmt(currentValue or min))
            end

            local function applyEnabledState()
                local enabledAlpha = controlEnabled and 1 or 0.5
                container:SetAlpha(enabledAlpha)
                label:SetAlpha(enabledAlpha)
                minusButton:SetEnabled(controlEnabled)
                plusButton:SetEnabled(controlEnabled)
                valueButton:SetEnabled(controlEnabled)
                if not controlEnabled and editingValue then
                    endEdit(false)
                end
            end

            minusButton:SetScript("OnClick", function()
                if not controlEnabled then
                    return
                end
                local mult = 1
                if isMicro and IsShiftKeyDown and IsShiftKeyDown() then
                    mult = microShiftMultiplier
                end
                setValue((currentValue or min) - (stepValue * mult), true)
            end)
            plusButton:SetScript("OnClick", function()
                if not controlEnabled then
                    return
                end
                local mult = 1
                if isMicro and IsShiftKeyDown and IsShiftKeyDown() then
                    mult = microShiftMultiplier
                end
                setValue((currentValue or min) + (stepValue * mult), true)
            end)
            valueButton:SetScript("OnClick", function()
                if not controlEnabled then
                    return
                end
                beginEdit()
            end)
            valueEdit:SetScript("OnEnterPressed", function(edit)
                endEdit(true)
                edit:ClearFocus()
            end)
            valueEdit:SetScript("OnEscapePressed", function(edit)
                endEdit(false)
                edit:ClearFocus()
            end)
            valueEdit:SetScript("OnEditFocusLost", function()
                endEdit(true)
            end)

            if tooltipText and tooltipText ~= "" then
                label:SetScript("OnEnter", function(selfLabel)
                    GameTooltip:SetOwner(selfLabel, "ANCHOR_TOPLEFT")
                    GameTooltip:SetText(tooltipText, 1, 0.82, 0, 1)
                    GameTooltip:Show()
                end)
                label:SetScript("OnLeave", function()
                    GameTooltip:Hide()
                end)
            end

            local spec = {
                kind = "stepper",
                label = label,
                control = container,
                valueButton = valueButton,
                valueText = valueText,
                valueEdit = valueEdit,
                minus = minusButton,
                plus = plusButton,
            }
            spec.SetWidth = function(_, newWidth)
                local minWidth = isMicro and 52 or 120
                container:SetWidth(math.max(minWidth, math.floor(tonumber(newWidth) or width or 160)))
            end
            spec.SetEnabled = function(_, enabled)
                controlEnabled = enabled and true or false
                applyEnabledState()
            end
            spec.IsEnabled = function()
                return controlEnabled
            end
            spec.SetVisualValue = function(_, value)
                local n = normalize(value)
                currentValue = n
                valueText:SetText(fmt(n))
                if valueEdit:IsShown() then
                    valueEdit:SetText(fmt(n))
                end
                applyEnabledState()
            end
            spec.Refresh = function()
                local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
                local storedValue = nil
                if customGetValue then
                    storedValue = customGetValue()
                else
                    storedValue = PortalAuthorityDB[settingKey]
                    if settingKey == "dockFontSize" then
                        storedValue = tonumber(PortalAuthorityDB.dockFontSizeUI or PortalAuthorityDB.dockFontSize)
                    end
                end
                local n = normalize(storedValue or defaults[settingKey] or min)
                currentValue = n
                if not customGetValue and not customSetValue then
                    PortalAuthorityDB[settingKey] = n
                    if settingKey == "dockFontSize" then
                        PortalAuthorityDB.dockFontSizeUI = n
                    end
                end
                valueText:SetText(fmt(n))
                if valueEdit:IsShown() then
                    valueEdit:SetText(fmt(n))
                end
                applyEnabledState()
            end
            spec.Refresh()
            return settingsSearchRuntime.registerSpec(spec)
        end
        createCanonicalDockFontSizeStepperControl = CreateStepperControl

        local function CreateFontPicker(parent, labelText, settingKey, width, onApply)
            local label = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
            label:SetText(labelText)

            local function normalizeFontPathKey(path)
                local value = trim(tostring(path or ""))
                value = value:gsub("/", "\\")
                return string.lower(value)
            end

            local function fallbackFontLabelForPath(path)
                local value = trim(tostring(path or ""))
                value = value:gsub("/", "\\")
                if value == "" then
                    return "Global UI Font"
                end
                local name = value:match("([^\\]+)$")
                if name and name ~= "" then
                    return name
                end
                return value
            end

            local function resolveFontSelection(rawValue, options)
                local selectedValue = tostring(rawValue or "")
                local selectedKey = normalizeFontPathKey(selectedValue)
                local selectedLabel = nil
                local matchedValue = selectedValue

                for _, option in ipairs(options or {}) do
                    local optionValue = tostring(option.value or "")
                    if normalizeFontPathKey(optionValue) == selectedKey then
                        matchedValue = optionValue
                        selectedLabel = option.buttonLabel or option.label
                        break
                    end
                end

                if not selectedLabel then
                    selectedLabel = fallbackFontLabelForPath(selectedValue)
                end

                return tostring(matchedValue or ""), tostring(selectedLabel or "")
            end

            local button = CreateFrame("Button", nil, parent, "BackdropTemplate")
            button:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
                insets = { left = 0, right = 0, top = 0, bottom = 0 },
            })
            button:SetBackdropColor(CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A)
            button:SetBackdropBorderColor(CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A)
            button:SetHeight(22)
            button:SetWidth(math.max(140, tonumber(width) or 220))

            local text = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 11)
            text:SetPoint("LEFT", button, "LEFT", 8, 0)
            text:SetPoint("RIGHT", button, "RIGHT", -18, 0)
            text:SetJustifyH("LEFT")
            text:SetTextColor(0.92, 0.92, 0.92, 1)

            local caret = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 10)
            caret:SetPoint("RIGHT", button, "RIGHT", -7, 0)
            caret:SetText("v")
            caret:SetTextColor(0.76, 0.76, 0.78, 1)

            local picker
            picker = CreatePicker(UIParent, {}, function(value, option, wasClear)
                local selectedValue = value
                if wasClear then
                    selectedValue = ""
                end
                selectedValue = tostring(selectedValue or "")
                PortalAuthorityDB[settingKey] = selectedValue
                local activeOptions = picker and picker._allOptions or {}
                local visualValue, visualLabel = resolveFontSelection(selectedValue, activeOptions)
                text:SetText(visualLabel ~= "" and visualLabel or "Global UI Font")
                if picker then
                    picker:SetSelectedValue(visualValue)
                end
                if onApply then
                    onApply()
                end
            end, {
                title = "Select Font Face",
                searchHint = "Search fonts by name",
                width = 420,
                height = 380,
                showSecondary = false,
                useOptionFontPreview = true,
                previewFontSize = 13,
                rowHeight = 26,
            })

            local function buildFontOptions()
                return buildSharedFontPickerChoices()
            end

            local function applyButtonVisual(hovered)
                if hovered then
                    button:SetBackdropColor(CONTROL_HOVER_BG_R, CONTROL_HOVER_BG_G, CONTROL_HOVER_BG_B, CONTROL_HOVER_BG_A)
                    button:SetBackdropBorderColor(CONTROL_HOVER_BORDER_R, CONTROL_HOVER_BORDER_G, CONTROL_HOVER_BORDER_B, CONTROL_HOVER_BORDER_A)
                    caret:SetTextColor(0.88, 0.88, 0.90, 1)
                else
                    button:SetBackdropColor(CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A)
                    button:SetBackdropBorderColor(CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A)
                    caret:SetTextColor(0.76, 0.76, 0.78, 1)
                end
            end

            button:SetScript("OnEnter", function()
                applyButtonVisual(true)
            end)
            button:SetScript("OnLeave", function()
                applyButtonVisual(false)
            end)

            local spec = {
                kind = "font_picker",
                label = label,
                control = button,
                picker = picker,
                text = text,
            }

            spec.SetWidth = function(_, newWidth)
                button:SetWidth(math.max(140, math.floor(tonumber(newWidth) or width or 220)))
            end

            spec.SetVisualSelectedValue = function(_, rawValue)
                local options = picker and picker._allOptions or buildFontOptions()
                if picker and (not picker._allOptions or #picker._allOptions == 0) then
                    picker:SetOptions(options)
                    options = picker._allOptions or options
                end
                local selectedValue, selectedLabel = resolveFontSelection(rawValue, options)
                if picker then
                    picker:SetSelectedValue(selectedValue)
                end
                text:SetText(selectedLabel ~= "" and selectedLabel or "Global UI Font")
            end

            spec.Refresh = function()
                local options = buildFontOptions()
                picker:SetOptions(options)

                local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
                local rawValue = PortalAuthorityDB[settingKey]
                if rawValue == nil then
                    rawValue = defaults[settingKey] or ""
                end

                local selectedValue, selectedLabel = resolveFontSelection(rawValue, options)

                picker:SetSelectedValue(selectedValue)
                text:SetText(selectedLabel ~= "" and selectedLabel or "Global UI Font")
                button:SetEnabled(#options > 0)
                button:SetAlpha(#options > 0 and 1 or 0.6)
            end

            button:SetScript("OnClick", function()
                if picker and picker.IsShown and picker:IsShown() then
                    picker:Close()
                    return
                end
                spec.Refresh()
                picker:Open(button)
            end)

            spec.Refresh()
            return settingsSearchRuntime.registerSpec(spec, "font_picker")
        end

        local OFF_RED_BG_R, OFF_RED_BG_G, OFF_RED_BG_B, OFF_RED_BG_A = 0.23, 0.05, 0.075, 0.93
        local OFF_RED_BORDER_R, OFF_RED_BORDER_G, OFF_RED_BORDER_B, OFF_RED_BORDER_A = 0.21, 0.045, 0.068, 0.88
        local OFF_RED_BORDER_SELECTED_R, OFF_RED_BORDER_SELECTED_G, OFF_RED_BORDER_SELECTED_B, OFF_RED_BORDER_SELECTED_A = 0.22, 0.049, 0.074, 1.0
        local OFF_RED_TEXT_R, OFF_RED_TEXT_G, OFF_RED_TEXT_B, OFF_RED_TEXT_A = 0.90, 0.76, 0.76, 1.0
        local OFF_RED_SELECTED_ALPHA = 0.95
        local OFF_RED_TOPSHEEN_ALPHA = 0.14

        local function setSegmentBorderColor(btn, r, g, b, a)
            if not btn then
                return
            end
            if btn._paBorder then
                local rr = tonumber(r) or CONTROL_BASE_BORDER_R
                local gg = tonumber(g) or CONTROL_BASE_BORDER_G
                local bb = tonumber(b) or CONTROL_BASE_BORDER_B
                local aa = tonumber(a) or CONTROL_BASE_BORDER_A
                local colorKey = string.format("%.4f:%.4f:%.4f:%.4f", rr, gg, bb, aa)
                if btn._paBorder._paLastBorderColorKey ~= colorKey then
                    btn._paBorder:SetBackdropBorderColor(rr, gg, bb, aa)
                    btn._paBorder._paLastBorderColorKey = colorKey
                end
                btn._paBorder:SetAlpha(1)
                btn._paBorder:Show()
            end
        end
        local function createSegmentedChoice(labelText, key, choices, onApply, opts)
            return createPremiumSegmentedChoice(scrollChild, labelText, key, choices, onApply, opts)
        end

        local function styleSecondaryActionButton(btn, styleOpts)
            styleSecondaryActionButtonShared(btn, styleOpts)
        end

