        end

        -- Gizmo Mode temporarily overrides these three controls visually and at runtime
        -- without rewriting the user's saved DB preferences underneath.
        local function setDockVisibilityControlGizmoLocked(spec, locked, moduleEnabled)
            if not spec then
                return
            end

            if spec.SetEnabled then
                spec:SetEnabled(moduleEnabled and true or false)
            end

            if spec.buttons then
                for _, btn in ipairs(spec.buttons) do
                    if btn then
                        btn._paHovered = false
                        btn._paPressed = false
                        if btn.SetPushedTextOffset then
                            btn:SetPushedTextOffset(0, 0)
                        end
                        if btn.EnableMouse then
                            btn:EnableMouse((moduleEnabled and true or false) and (not locked))
                        end
                    end
                end
            end

            if spec.label and spec.label.SetAlpha then
                spec.label:SetAlpha(locked and moduleEnabled and 0.54 or (moduleEnabled and 1 or 0.55))
            end
            if spec.control and spec.control.SetAlpha then
                spec.control:SetAlpha(locked and moduleEnabled and 0.56 or (moduleEnabled and 1 or 0.55))
            end
            if spec.control and spec.control.Text and spec.control.Text.SetAlpha then
                spec.control.Text:SetAlpha(locked and moduleEnabled and 0.56 or (moduleEnabled and 1 or 0.7))
            end
        end

        applyDockGizmoVisibilityOverrideState = function()
            local moduleEnabled = isDockModuleEnabled()
            local gizmoModeEnabled = moduleEnabled and PA_SafeBool(PortalAuthorityDB and PortalAuthorityDB.dockGizmoMode)

            local function syncVisibilityControl(spec)
                if not spec then
                    return
                end
                if spec.Refresh then
                    spec:Refresh()
                end
                if gizmoModeEnabled then
                    if spec.SetVisualSelectedValue then
                        spec:SetVisualSelectedValue(false)
                    elseif spec.SetSelectedValue then
                        spec:SetSelectedValue(false, false)
                    end
                    setDockVisibilityControlGizmoLocked(spec, true, moduleEnabled)
                else
                    setSettingsControlEnabled(spec, moduleEnabled)
                    setDockVisibilityControlGizmoLocked(spec, false, moduleEnabled)
                end
            end

            syncVisibilityControl(widgets.hideCity)
            syncVisibilityControl(widgets.hideDungeon)
            syncVisibilityControl(widgets.hideCombat)
        end

        for _, spec in ipairs({ widgets.dockEnabled, widgets.hideCity, widgets.hideCombat, widgets.hideDungeon, widgets.gizmoMode }) do
            if spec and spec.label then
                spec.label:SetWordWrap(false)
                if spec.label.SetMaxLines then
                    spec.label:SetMaxLines(1)
                end
            end
        end

        styleSecondaryActionButton(widgets.resetDockAnchor, {
