                end,
                setValue = function(side)
                    setDockLabelSideForSettings(side, "OUTSIDE")
                end,
            })

            do
                local insideContainer = CreateFrame("Frame", nil, scrollChild)
                local topBottom = createPremiumSegmentedChoice(insideContainer, "", nil, {
                    { label = "Top", value = "TOP" },
                    { label = "Bottom", value = "BOTTOM" },
                }, function(value)
                    applyDockLabelSideSelection(value, "INSIDE")
                end, {
                    semantic = "selection",
                    normalizeValue = normalizeDockLabelSideValue,
                    minWidth = 0,
                })
                local center = createPremiumSegmentedChoice(insideContainer, "", nil, {
                    { label = "Center", value = "CENTER" },
                }, function(value)
                    applyDockLabelSideSelection(value, "INSIDE")
                end, {
                    semantic = "selection",
                    normalizeValue = normalizeDockLabelSideValue,
                    minWidth = 0,
                })

                if topBottom.label then
                    topBottom.label:Hide()
                end
                if center.label then
                    center.label:Hide()
                end

                widgets.labelSideInside = {
                    kind = "segmented_composite",
                    label = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlight", 12),
                    control = insideContainer,
                    topBottom = topBottom,
                    center = center,
                }
                widgets.labelSideInside.label:SetText("Label Side")

                widgets.labelSideInside.Layout = function(_, width)
                    local totalWidth = math.max(120, tonumber(width) or 120)
                    local groupGap = 4
                    local halfWidth = math.max(58, (totalWidth - groupGap) / 2)

                    insideContainer:SetSize(totalWidth, 22)

                    topBottom.control:ClearAllPoints()
                    topBottom.control:SetPoint("TOPLEFT", insideContainer, "TOPLEFT", 0, 0)
                    topBottom:Layout(halfWidth)

                    center.control:ClearAllPoints()
                    center.control:SetPoint("TOPLEFT", topBottom.control, "TOPRIGHT", groupGap, 0)
                    center:Layout(halfWidth)

                    if topBottom.label then
                        topBottom.label:Hide()
                    end
                    if center.label then
                        center.label:Hide()
                    end
                end

                widgets.labelSideInside.Refresh = function(self)
                    local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
                    self:SetVisualSelectedValue(getDockInsideLabelSideForSettings(defaults))
