        local function captureDockPopoverTemplateChromeRegions(edit)
            if not edit or edit._paDockPopoverTemplateChromeRegions then
                return
            end

            local regions = {}
            local seen = {}
            local function capture(region)
                if not region or seen[region] then
                    return
                end
                if not region.GetObjectType or region:GetObjectType() ~= "Texture" then
                    return
                end
                seen[region] = true
                regions[#regions + 1] = region
            end

            capture(edit.Left)
            capture(edit.Middle)
            capture(edit.Right)

            if edit.GetRegions then
                for i = 1, select("#", edit:GetRegions()) do
                    capture(select(i, edit:GetRegions()))
                end
            end

            edit._paDockPopoverTemplateChromeRegions = regions
        end

        local function suppressDockPopoverTemplateChrome(edit)
            if not edit then
                return
            end

            captureDockPopoverTemplateChromeRegions(edit)
            for _, region in ipairs(edit._paDockPopoverTemplateChromeRegions or {}) do
                if region.SetAlpha then
                    region:SetAlpha(0)
                end
                if region.Hide then
                    region:Hide()
                end
            end
        end

        local function ensureDockPopoverEditSkin(edit, textSize)
            if not edit then
                return
            end

            captureDockPopoverTemplateChromeRegions(edit)
            applyGlobalFontToObject(edit, tonumber(textSize) or 11)
            edit:SetTextColor(1, 1, 1, 1)
            edit:SetTextInsets(8, 8, 0, 0)
            edit:SetJustifyH("LEFT")

            if not edit._paPremiumBg then
                edit._paPremiumBg = edit:CreateTexture(nil, "BACKGROUND")
                edit._paPremiumBg:SetAllPoints(edit)
                edit._paPremiumBg:SetTexture("Interface\\Buttons\\WHITE8x8")
                edit._paPremiumBorder = CreateFrame("Frame", nil, edit, "BackdropTemplate")
                edit._paPremiumBorder:SetBackdrop({
                    edgeFile = "Interface\\Buttons\\WHITE8x8",
                    edgeSize = 1,
                })
            end

            local function refreshDockPopoverEditSkin()
                suppressDockPopoverTemplateChrome(edit)
                local parent = edit:GetParent()
                local parentStrata = parent and parent.GetFrameStrata and parent:GetFrameStrata() or "DIALOG"
                local parentLevel = parent and parent.GetFrameLevel and parent:GetFrameLevel() or 1
                edit:SetFrameStrata(parentStrata)
                edit:SetFrameLevel(math.max(parentLevel + 10, edit:GetFrameLevel() or 1))
                if edit._paPremiumBorder then
                    edit._paPremiumBorder:SetPoint("TOPLEFT", edit, "TOPLEFT", -1, 1)
                    edit._paPremiumBorder:SetPoint("BOTTOMRIGHT", edit, "BOTTOMRIGHT", 1, -1)
                    edit._paPremiumBorder:SetFrameStrata(parentStrata)
                    edit._paPremiumBorder:SetFrameLevel(math.max(parentLevel + 9, 1))
                end
                if edit:HasFocus() then
                    edit._paPremiumBg:SetVertexColor(0.12, 0.13, 0.17, 0.95)
                    edit._paPremiumBorder:SetBackdropBorderColor(0.30, 0.33, 0.38, 1.0)
                else
                    edit._paPremiumBg:SetVertexColor(0.10, 0.11, 0.14, 0.95)
                    edit._paPremiumBorder:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
                end
            end

            if not edit._paDockPopoverSkinInitialized then
                edit:HookScript("OnShow", refreshDockPopoverEditSkin)
                edit:HookScript("OnEditFocusGained", refreshDockPopoverEditSkin)
                edit:HookScript("OnEditFocusLost", refreshDockPopoverEditSkin)
                edit._paDockPopoverSkinInitialized = true
                edit._paDockPopoverRefreshVisual = refreshDockPopoverEditSkin
            end

            refreshDockPopoverEditSkin()
        end

        local function restoreDockPopoverAnchorLabel(popover, anchorRow)
            if not popover then
                return
            end

            local label = popover._paSuppressedAnchorLabel
            if label then
                if popover._paSuppressedAnchorLabelWasShown then
                    if label.Show then
                        label:Show()
                    end
                else
                    if label.Hide then
                        label:Hide()
                    end
                end
                if label.SetAlpha then
                    label:SetAlpha(popover._paSuppressedAnchorLabelAlpha or 1)
                end
            end

            popover._paSuppressedAnchorLabel = nil
            popover._paSuppressedAnchorLabelAlpha = nil
            popover._paSuppressedAnchorLabelWasShown = nil

            anchorRow = anchorRow or popover.anchorRow
            if type(popover._paReleaseAnchorVisual) == "function" then
                popover._paReleaseAnchorVisual(anchorRow)
            end
        end

        local function suppressDockPopoverAnchorLabel(popover, row)
            if not popover then
                return
            end

            restoreDockPopoverAnchorLabel(popover)

            local anchorLabelKey = popover._paAnchorLabelKey
            local anchorLabel = anchorLabelKey and row and row[anchorLabelKey] and row[anchorLabelKey].label or nil
            if anchorLabel and anchorLabel.GetAlpha and anchorLabel.SetAlpha then
                popover._paSuppressedAnchorLabel = anchorLabel
                popover._paSuppressedAnchorLabelAlpha = anchorLabel:GetAlpha()
                popover._paSuppressedAnchorLabelWasShown = anchorLabel.IsShown and anchorLabel:IsShown() or true
                if anchorLabel.Hide then
                    anchorLabel:Hide()
                else
                    anchorLabel:SetAlpha(0)
                end
            end

            if type(popover._paApplyAnchorVisual) == "function" then
                popover._paApplyAnchorVisual(row)
            end
        end

