        local function updateRenameHint()
            local pop = widgets.renamePopover
            if not pop or not pop.edit or not pop.hint then
                return
            end
            local text = tostring(pop.edit:GetText() or "")
            local n = string.len(text)
            local over = n > DOCK_NAME_MAX_LEN
            pop.hint:SetText(string.format("%d/%d", n, DOCK_NAME_MAX_LEN))
            if over then
                pop.hint:SetTextColor(1, 0.36, 0.36, 1)
            else
                pop.hint:SetTextColor(0.72, 0.72, 0.72, 1)
            end
        end

        function widgets.renamePopover:Close(save)
            local slotIndex = self.slotIndex
            local edit = self.edit
            local anchorRow = self.anchorRow
            if not self:IsShown() then
                self.slotIndex = nil
                self.anchorRow = nil
                self.originalText = ""
                restoreDockPopoverAnchorLabel(self, anchorRow)
                return
            end

            local changed = false
            if save and slotIndex then
                local slot = getDockSlot(slotIndex)
                local previousName = tostring(slot.name or "")
                local previousRenamed = slot.renamed == true
                local text = trim(edit:GetText() or "")
                setDockSlotCustomName(slot, text)
                if tostring(slot.name or "") ~= previousName or (slot.renamed == true) ~= previousRenamed then
                    changed = true
                end
            end

            self.slotIndex = nil
            self.anchorRow = nil
            self.originalText = ""
            restoreDockPopoverAnchorLabel(self, anchorRow)
            self:Hide()
            if edit then
                edit:ClearFocus()
            end
            if changed then
                setLoadoutPresetCustom()
                onUIChanged(false)
            end
        end

        function widgets.renamePopover:OpenForRow(slotIndex, row)
            if not row or not row.namePill then
                return
