            if widgets.spellIDPopover and widgets.spellIDPopover:IsShown() and widgets.spellIDPopover.Close then
                widgets.spellIDPopover:Close(false)
            end
            if self.anchorRow and self.anchorRow ~= row then
                restoreDockPopoverAnchorLabel(self, self.anchorRow)
            end
            local slot = getDockSlot(slotIndex)
            if not slot.enabled then
                return
            end

            local current = getDockSlotDisplayName(slot)

            self:ClearAllPoints()
            self:SetFrameLevel(math.max((row.namePill:GetFrameLevel() or 1) + 20, self:GetFrameLevel() or 1))
            self:SetPoint("TOPLEFT", row.namePill, "TOPLEFT", -2, 2)
            self:SetPoint("TOPRIGHT", row.namePill, "TOPRIGHT", 2, 2)
            self:SetHeight(44)
            self.edit:ClearAllPoints()
            self.edit:SetPoint("TOPLEFT", self, "TOPLEFT", 6, -6)
            self.edit:SetPoint("TOPRIGHT", self, "TOPRIGHT", -6, -6)
            self.edit:SetHeight(20)
            self.hint:ClearAllPoints()
            self.hint:SetPoint("TOPLEFT", self.edit, "BOTTOMLEFT", 2, -2)

            self.slotIndex = slotIndex
            self.anchorRow = row
            self.originalText = current
            suppressDockPopoverAnchorLabel(self, row)
            self.edit:SetText(current)
            updateRenameHint()
            self:Show()
            self:Raise()
            if self.edit._paDockPopoverRefreshVisual then
                self.edit._paDockPopoverRefreshVisual()
            end
            self.edit:SetFocus()
            if self.edit.HighlightText then
                self.edit:HighlightText(0, 0)
            end
            if self.edit.SetCursorPosition then
                self.edit:SetCursorPosition(string.len(current or ""))
            end
        end

