        local function updateSpellIDHint()
            local pop = widgets.spellIDPopover
            if not pop or not pop.edit or not pop.hint then
                return
            end
            local text = trim(tostring(pop.edit:GetText() or ""))
            local n = string.len(text)
            local over = n > DOCK_SPELLID_MAX_LEN
            local numeric = (text == "" or text:match("^%d+$") ~= nil)
            pop.hint:SetText(string.format("%d/%d", n, DOCK_SPELLID_MAX_LEN))
            if over or not numeric then
                pop.hint:SetTextColor(1, 0.36, 0.36, 1)
            else
                pop.hint:SetTextColor(0.72, 0.72, 0.72, 1)
            end
        end

        function widgets.spellIDPopover:Close(save)
            local slotIndex = self.slotIndex
            local edit = self.edit
            local anchorRow = self.anchorRow
            if not self:IsShown() then
                self.slotIndex = nil
                self.anchorRow = nil
                self.originalText = ""
                restoreDockPopoverAnchorLabel(self, anchorRow)
                return
            end

            local changed = false
            if save and slotIndex then
                local slot = getDockSlot(slotIndex)
                local rawValue = tonumber(edit:GetText() or "")
                if rawValue ~= nil then
                    local spellID = resolveSpellIDFromVisualDockID(rawValue)
                    if slot.spellID ~= spellID then
                        changed = true
                    end
                    slot.spellID = spellID
                    if spellID > 0 and getDestinationOptionByValue(tostring(spellID)) then
                        slot.selection = tostring(spellID)
                    else
                        slot.selection = "CUSTOM"
                    end
                    setDockSlotDefaultName(slot, spellID)
                    if spellID > 0 and trim(slot.name or "") == "" then
                        requestSpellDataRefresh(slotIndex, spellID)
                    end
                end
            end

            self.slotIndex = nil
            self.anchorRow = nil
            self.originalText = ""
            restoreDockPopoverAnchorLabel(self, anchorRow)
            self:Hide()
            if edit then
                edit:ClearFocus()
            end
            if changed then
                setLoadoutPresetCustom()
                onUIChanged(false)
            end
        end

