        local function setPillCursor(mode)
            if not SetCursor and not ResetCursor then
                return
            end

            local function trySet(path)
                if not SetCursor or not path or path == "" then
                    return false
                end
                local ok = pcall(SetCursor, path)
                return ok and true or false
            end

            if mode == "ibeam" then
                if trySet("Interface\\Cursor\\UI-Cursor-Chat") then
                    return
                end
                if trySet("Interface\\CURSOR\\UI-Cursor-Chat") then
                    return
                end
            elseif mode == "hand" then
                if trySet("Interface\\Cursor\\UI-Cursor-Move") then
                    return
                end
                if trySet("Interface\\CURSOR\\UI-Cursor-Move") then
                    return
                end
            end

            if ResetCursor then
                pcall(ResetCursor)
            end
        end

        local function SetPillState(frame, state)
            if not frame then
                return
            end
            local s = tostring(state or "normal")
            frame._disabled = (s == "disabled")
            frame._focused = (s == "focus")
            frame._open = (s == "open")
            frame._pressed = (s == "pressed")
            frame._hovered = (s == "hover")
            if frame._disabled then
                frame._focused = false
                frame._open = false
                frame._pressed = false
                frame._hovered = false
            end
            if frame.UpdateVisual then
                frame:UpdateVisual()
            end
        end

        local function styleRowPill(frame, palette, pillKind)
            frame:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Tooltips\\UI-Tooltip-Border",
                edgeSize = 8,
                insets = { left = 1, right = 1, top = 1, bottom = 1 },
            })
            frame._palette = palette or {}
            frame._pillKind = pillKind or "readonly"
            frame._hovered = false
            frame._pressed = false
            frame._focused = false
            frame._open = false
            frame._disabled = false

            if not frame.glow then
                frame.glow = frame:CreateTexture(nil, "BORDER")
                frame.glow:SetAllPoints()
                frame.glow:SetTexture("Interface\\Buttons\\WHITE8x8")
                frame.glow:SetBlendMode("ADD")
            end

            function frame:SetPillState(state)
                SetPillState(self, state)
            end

            function frame:UpdateVisual()
                local p = self._palette or {}
                local state = "base"
                if self._disabled then
                    state = "disabled"
                elseif self._focused then
                    state = "focus"
                elseif self._open then
                    state = "open"
                elseif self._pressed then
                    state = "pressed"
                elseif self._hovered then
                    state = "hover"
                end
                local c = p[state] or p.base or { 0.08, 0.09, 0.12, 0.95, 0.24, 0.27, 0.32, 1, 0 }
                self:SetBackdropColor(c[1], c[2], c[3], c[4])
                self:SetBackdropBorderColor(c[5], c[6], c[7], c[8])
                if self.glow then
                    self.glow:SetVertexColor(1, 0.82, 0.1, c[9] or 0)
                end
                if self.label then
                    local tc = p.text or { 1, 1, 1, 1 }
                    local td = p.textDisabled or { 0.62, 0.62, 0.64, 1 }
                    if self._disabled then
                        self.label:SetTextColor(td[1], td[2], td[3], td[4])
                    else
                        self.label:SetTextColor(tc[1], tc[2], tc[3], tc[4])
                    end
                end
                if self.chevron then
                    local cc = p.chevron or { 0.78, 0.78, 0.82, 1 }
                    local cd = p.chevronDisabled or { 0.45, 0.45, 0.48, 1 }
                    if self._disabled then
                        self.chevron:SetTextColor(cd[1], cd[2], cd[3], cd[4])
                    else
                        self.chevron:SetTextColor(cc[1], cc[2], cc[3], cc[4])
                    end
                end
                if self.editGlyph then
                    self.editGlyph:SetShown((not self._disabled) and self._hovered and (not self._focused))
                end
            end

            frame:SetScript("OnEnter", function(selfFrame)
                if selfFrame._disabled then
                    selfFrame._hovered = false
                    selfFrame:UpdateVisual()
                    return
                end
                selfFrame._hovered = true
                selfFrame:UpdateVisual()
            end)
            frame:SetScript("OnLeave", function(selfFrame)
                selfFrame._hovered = false
                selfFrame._pressed = false
                selfFrame:UpdateVisual()
            end)
            frame:SetScript("OnMouseDown", function(selfFrame)
                if selfFrame._disabled then
                    return
                end
                selfFrame._pressed = true
                selfFrame:UpdateVisual()
            end)
            frame:SetScript("OnMouseUp", function(selfFrame)
                selfFrame._pressed = false
                selfFrame:UpdateVisual()
            end)
            frame:UpdateVisual()
        end

        local function ApplyPillStyle_Editable(frame)
            styleRowPill(frame, {
                base = { CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A, CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A, 0.00 },
                hover = { CONTROL_HOVER_BG_R, CONTROL_HOVER_BG_G, CONTROL_HOVER_BG_B, CONTROL_HOVER_BG_A, CONTROL_HOVER_BORDER_R, CONTROL_HOVER_BORDER_G, CONTROL_HOVER_BORDER_B, CONTROL_HOVER_BORDER_A, 0.03 },
                pressed = { CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A, CONTROL_HOVER_BORDER_R, CONTROL_HOVER_BORDER_G, CONTROL_HOVER_BORDER_B, CONTROL_HOVER_BORDER_A, 0.02 },
                focus = { CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A, 1.00, 0.82, 0.10, 0.95, 0.08 },
                disabled = { 0.05, 0.06, 0.08, 0.86, 0.16, 0.18, 0.22, 0.85, 0.00 },
                text = { 0.90, 0.90, 0.92, 1 },
                textDisabled = { 0.58, 0.58, 0.61, 1 },
            }, "editable")
            if not frame.editGlyph then
                frame.editGlyph = createStyledFontString(frame, "ARTWORK", "GameFontHighlightSmall", 10)
                frame.editGlyph:SetPoint("RIGHT", frame, "RIGHT", -6, 0)
                frame.editGlyph:SetText("...")
                frame.editGlyph:SetTextColor(0.72, 0.72, 0.76, 0.9)
                frame.editGlyph:Hide()
            end
        end

        local function ApplyPillStyle_Dropdown(frame)
            styleRowPill(frame, {
                base = { CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A, CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A, 0.00 },
                hover = { CONTROL_HOVER_BG_R, CONTROL_HOVER_BG_G, CONTROL_HOVER_BG_B, CONTROL_HOVER_BG_A, CONTROL_HOVER_BORDER_R, CONTROL_HOVER_BORDER_G, CONTROL_HOVER_BORDER_B, CONTROL_HOVER_BORDER_A, 0.04 },
                pressed = { CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A, CONTROL_HOVER_BORDER_R, CONTROL_HOVER_BORDER_G, CONTROL_HOVER_BORDER_B, CONTROL_HOVER_BORDER_A, 0.03 },
                open = { CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A, 1.00, 0.82, 0.10, 0.82, 0.07 },
                focus = { CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A, CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A, 0.00 },
                disabled = { 0.05, 0.06, 0.08, 0.86, 0.16, 0.18, 0.22, 0.85, 0.00 },
                text = { 0.95, 0.95, 0.97, 1 },
                textDisabled = { 0.56, 0.56, 0.60, 1 },
                chevron = { 0.78, 0.78, 0.82, 1 },
                chevronDisabled = { 0.45, 0.45, 0.48, 1 },
            }, "dropdown")
        end

        local function ApplyPillStyle_Readonly(frame)
            styleRowPill(frame, {
                base = { 0.05, 0.06, 0.08, 0.90, 0.17, 0.19, 0.24, 0.9, 0.00 },
                hover = { 0.05, 0.06, 0.08, 0.90, 0.17, 0.19, 0.24, 0.9, 0.00 },
                pressed = { 0.05, 0.06, 0.08, 0.90, 0.17, 0.19, 0.24, 0.9, 0.00 },
                focus = { 0.05, 0.06, 0.08, 0.90, 0.17, 0.19, 0.24, 0.9, 0.00 },
                disabled = { 0.04, 0.05, 0.07, 0.82, 0.14, 0.16, 0.21, 0.82, 0.00 },
                text = { 0.78, 0.78, 0.82, 1 },
                textDisabled = { 0.52, 0.52, 0.55, 1 },
            }, "readonly")
        end

        local function registerDockSlotRowSearch(row)
            if type(row) ~= "table" or not frameIsAlive(row.enabled) then
                return nil
            end

            local primaryRef = row.destination and row.destination.label or nil
            if not frameIsAlive(primaryRef) then
                primaryRef = row.namePill and row.namePill.label or nil
            end
            if not frameIsAlive(primaryRef) then
                return nil
            end

            local extraRefs = {}
            local candidateRefs = {
                row.namePill and row.namePill.label or nil,
                row.spellIDPill and row.spellIDPill.label or nil,
                row.destination and row.destination.label or nil,
            }
            for i = 1, #candidateRefs do
                local ref = candidateRefs[i]
                if frameIsAlive(ref) and ref ~= primaryRef then
                    extraRefs[#extraRefs + 1] = ref
                end
            end

            return settingsSearchRuntime.registerControlText(primaryRef, row.enabled, "toggle", extraRefs)
        end

        local function createRowEnableToggle(parent, slotIndex)
            local holder = CreateFrame("Frame", nil, parent)
            holder:SetSize(FIXED_FOOTPRINTS.ROW_ENABLE_HOLDER_W, FIXED_FOOTPRINTS.ROW_ENABLE_HOLDER_H)
            holder._checked = false

            local PRESS_TEXT_OFFSET_X = 0.30
            local PRESS_TEXT_OFFSET_Y = -0.30

            local function isDockRowHost(selfBtn)
                return isUsingCustomSettingsWindowVisualStyle(selfBtn)
            end

            local function setDockRowNativeOffset(selfBtn, offsetX, offsetY)
                if not selfBtn or not selfBtn.SetPushedTextOffset then
                    return
                end
                local scale = selfBtn.GetEffectiveScale and selfBtn:GetEffectiveScale() or 1
                if scale == 0 then
                    scale = 1
                end
                local ox = tonumber(offsetX) or 0
                local oy = tonumber(offsetY) or 0
                if math.abs(ox) < 0.5 and ox ~= 0 then
                    ox = (ox < 0) and -0.5 or 0.5
                end
                if math.abs(oy) < 0.5 and oy ~= 0 then
                    oy = (oy < 0) and -0.5 or 0.5
                end
                ox = ox / scale
                oy = oy / scale
                selfBtn:SetPushedTextOffset(ox, oy)
            end

            local function clearDockRowNativeOffset(selfBtn)
                if isDockRowHost(selfBtn) then
                    setDockRowNativeOffset(selfBtn, 0, 0)
                end
            end

            local function createToggleButton(text)
                local btn = createActionButton(holder, text, nil, FIXED_FOOTPRINTS.ROW_ENABLE_BUTTON_W, {
                    textOrigin = "choice_caption",
                    searchChoiceLabelMode = "suppress_generic",
                })
                if btn.Text then
                    applyGlobalFontToObject(btn.Text, 10)
                end
                btn._hovered = false
                btn._selected = false
                btn._kind = "off"

                local function ensureFlatSkin(selfBtn)
                    if not selfBtn then
                        return
                    end
                    if not selfBtn._paSkinReady then
                        selfBtn._paSkinReady = true
                        selfBtn._paBg = selfBtn:CreateTexture(nil, "ARTWORK")
                        selfBtn._paBg:SetAllPoints(selfBtn)
                        selfBtn._paBg:SetTexture("Interface\\Buttons\\WHITE8x8")
                        selfBtn._paBorder = CreateFrame("Frame", nil, selfBtn, "BackdropTemplate")
                        selfBtn._paBorder:SetPoint("TOPLEFT", selfBtn, "TOPLEFT", -1, 1)
                        selfBtn._paBorder:SetPoint("BOTTOMRIGHT", selfBtn, "BOTTOMRIGHT", 1, -1)
                        selfBtn._paBorder:SetBackdrop({
                            edgeFile = "Interface\\Buttons\\WHITE8x8",
                            edgeSize = 1,
                        })
                        selfBtn._paBorder:SetBackdropBorderColor(CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A)
                        setSegmentBorderColor(selfBtn, CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A)
                        selfBtn._paTopSheen = selfBtn:CreateTexture(nil, "OVERLAY")
                        selfBtn._paTopSheen:SetAllPoints(selfBtn)
                        selfBtn._paTopSheen:SetTexture("Interface\\Buttons\\WHITE8x8")
                        if selfBtn._paTopSheen.SetGradientAlpha then
                            selfBtn._paTopSheen:SetGradientAlpha("VERTICAL", 1, 1, 1, 0.12, 1, 1, 1, 0.0)
                        elseif selfBtn._paTopSheen.SetGradient and CreateColor then
                            selfBtn._paTopSheen:SetGradient("VERTICAL", CreateColor(1, 1, 1, 0.12), CreateColor(1, 1, 1, 0.0))
                        else
                            selfBtn._paTopSheen:SetVertexColor(1, 1, 1, 0.1)
                        end
                        selfBtn._paGlow = selfBtn:CreateTexture(nil, "BORDER")
                        selfBtn._paGlow:SetAllPoints(selfBtn)
                        selfBtn._paGlow:SetTexture("Interface\\Buttons\\WHITE8x8")
                        selfBtn._paGlow:SetBlendMode("ADD")
                    end

                    local n = selfBtn.GetNormalTexture and selfBtn:GetNormalTexture() or nil
                    local p = selfBtn.GetPushedTexture and selfBtn:GetPushedTexture() or nil
                    local h = selfBtn.GetHighlightTexture and selfBtn:GetHighlightTexture() or nil
                    local d = selfBtn.GetDisabledTexture and selfBtn:GetDisabledTexture() or nil
                    if n then n:SetAlpha(0); if n.Hide then n:Hide() end end
                    if p then p:SetAlpha(0); if p.Hide then p:Hide() end end
                    if h then h:SetAlpha(0); if h.Hide then h:Hide() end end
                    if d then d:SetAlpha(0); if d.Hide then d:Hide() end end

                    local skinParts = {
                        "Left", "Middle", "Right",
                        "LeftDisabled", "MiddleDisabled", "RightDisabled",
                        "LeftHighlight", "MiddleHighlight", "RightHighlight",
                        "LeftPressed", "MiddlePressed", "RightPressed",
                    }
                    for _, part in ipairs(skinParts) do
                        local tex = selfBtn[part]
                        if tex and tex.SetAlpha then
                            tex:SetAlpha(0)
                        end
                        if tex and tex.Hide then
                            tex:Hide()
                        end
                    end

                    if selfBtn._paBorder then
                        local baseLevel = selfBtn:GetFrameLevel() or 0
                        selfBtn._paBorder:SetFrameStrata(selfBtn:GetFrameStrata())
                        selfBtn._paBorder:SetFrameLevel(baseLevel + 3)
                    end
                end

                function btn:ApplyVisual()
                    ensureFlatSkin(self)
                    local useHostToggleTheme = isUsingCustomSettingsWindowVisualStyle(self)
                    local enabled = self._disabled ~= true
                    if useHostToggleTheme then
                        local bgColor = self._hovered and SETTINGS_WINDOW_HOST_COLORS.hoverBg or SETTINGS_WINDOW_HOST_COLORS.idleBg
                        local borderColor = self._hovered and SETTINGS_WINDOW_HOST_COLORS.hoverBorder or SETTINGS_WINDOW_HOST_COLORS.idleBorder
                        local textColor = self._hovered and SETTINGS_WINDOW_HOST_COLORS.hoverText or SETTINGS_WINDOW_HOST_COLORS.idleText

                        if not enabled then
                            bgColor = SETTINGS_WINDOW_HOST_COLORS.disabledBg
                            borderColor = SETTINGS_WINDOW_HOST_COLORS.disabledBorder
                            textColor = SETTINGS_WINDOW_HOST_COLORS.disabledText
                            if self._paGlow then
                                self._paGlow:SetVertexColor(1, 1, 1, 0)
                            end
                            if self._paTopSheen then
                                self._paTopSheen:SetAlpha(0.05)
                            end
                            self:SetAlpha(0.58)
                        elseif self._selected then
                            if self._kind == "on" then
                                bgColor = SETTINGS_WINDOW_HOST_COLORS.onBg
                                borderColor = SETTINGS_WINDOW_HOST_COLORS.onBorder
                                textColor = SETTINGS_WINDOW_HOST_COLORS.onText
                                if self._paGlow then
                                    self._paGlow:SetVertexColor(unpackColor(SETTINGS_WINDOW_HOST_COLORS.onBorder))
                                    self._paGlow:SetAlpha(self._hovered and 0.16 or 0.10)
                                end
                            else
                                bgColor = SETTINGS_WINDOW_HOST_COLORS.offBg
                                borderColor = SETTINGS_WINDOW_HOST_COLORS.offBorder
                                textColor = SETTINGS_WINDOW_HOST_COLORS.offText
                                if self._paGlow then
                                    self._paGlow:SetVertexColor(unpackColor(SETTINGS_WINDOW_HOST_COLORS.offBorder))
                                    self._paGlow:SetAlpha(self._hovered and 0.12 or 0.08)
                                end
                            end
                            if self._paTopSheen then
                                self._paTopSheen:SetAlpha(self._hovered and 0.18 or 0.12)
                            end
                            self:SetAlpha(1)
                        else
                            if self._paGlow then
                                self._paGlow:SetVertexColor(1, 1, 1, 0)
                            end
                            if self._paTopSheen then
                                self._paTopSheen:SetAlpha(self._hovered and 0.12 or 0.08)
                            end
                            self:SetAlpha(0.98)
                        end

                        self._paBg:SetVertexColor(unpackColor(bgColor))
                        if self._paBorder then
                            setSegmentBorderColor(self, unpackColor(borderColor))
                        end
                        if self.Text then
                            self.Text:SetTextColor(unpackColor(textColor))
                        end
                        return
                    end

                    if not enabled then
                        self._paBg:SetVertexColor(CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A)
                        if self._paGlow then
                            self._paGlow:SetVertexColor(1, 1, 1, 0)
                        end
                        if self._paBorder then
                            setSegmentBorderColor(self, CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, 0.72)
                        end
                        if self._paTopSheen then
                            self._paTopSheen:SetAlpha(0.04)
                        end
                        if self.Text then
                            self.Text:SetTextColor(0.50, 0.50, 0.53, 1)
                        end
                        self:SetAlpha(0.45)
                        return
                    end

                    if self._selected then
                        if self._kind == "on" then
                            if self._hovered then
                                self._paBg:SetVertexColor(0.13, 0.28, 0.15, 0.98)
                            else
                                self._paBg:SetVertexColor(0.11, 0.23, 0.13, 0.96)
                            end
                            if self._paGlow then
                                self._paGlow:SetVertexColor(0.28, 1.0, 0.36, self._hovered and 0.14 or 0.1)
                            end
                            if self._paBorder then
                                setSegmentBorderColor(self, 0.18, 0.55, 0.2, self._hovered and 0.95 or 0.82)
                            end
                            if self.Text then
                                self.Text:SetTextColor(0.72, 1, 0.74, 1)
                            end
                        else
                            self._paBg:SetVertexColor(OFF_RED_BG_R, OFF_RED_BG_G, OFF_RED_BG_B, OFF_RED_BG_A)
                            if self._paGlow then
                                self._paGlow:SetVertexColor(0.95, 0.22, 0.22, 0)
                            end
                            if self._paBorder then
                                setSegmentBorderColor(
                                    self,
                                    OFF_RED_BORDER_SELECTED_R,
                                    OFF_RED_BORDER_SELECTED_G,
                                    OFF_RED_BORDER_SELECTED_B,
                                    OFF_RED_BORDER_SELECTED_A
                                )
                            end
                            if self.Text then
                                self.Text:SetTextColor(OFF_RED_TEXT_R, OFF_RED_TEXT_G, OFF_RED_TEXT_B, OFF_RED_TEXT_A)
                            end
                        end
                        if self._paTopSheen then
                            if self._kind == "on" then
                                self._paTopSheen:SetAlpha(0.22)
                            else
                                self._paTopSheen:SetAlpha(OFF_RED_TOPSHEEN_ALPHA)
                            end
                        end
                        if self._kind == "on" then
                            self:SetAlpha(0.98)
                        else
                            self:SetAlpha(OFF_RED_SELECTED_ALPHA)
                        end
                    else
                        if self._hovered then
                            self._paBg:SetVertexColor(CONTROL_HOVER_BG_R, CONTROL_HOVER_BG_G, CONTROL_HOVER_BG_B, CONTROL_HOVER_BG_A)
                            if self._paBorder then
                                setSegmentBorderColor(self, CONTROL_HOVER_BORDER_R, CONTROL_HOVER_BORDER_G, CONTROL_HOVER_BORDER_B, CONTROL_HOVER_BORDER_A)
                            end
                        else
                            self._paBg:SetVertexColor(CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A)
                            if self._paBorder then
                                setSegmentBorderColor(self, CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A)
                            end
                        end
                        if self._paGlow then
                            self._paGlow:SetVertexColor(1, 1, 1, 0)
                        end
                        if self._paTopSheen then
                            self._paTopSheen:SetAlpha(self._hovered and 0.12 or 0.08)
                        end
                        if self.Text then
                            self.Text:SetTextColor(0.85, 0.85, 0.88, 1)
                        end
                        self:SetAlpha(0.96)
                    end
                end

                btn:SetScript("OnEnter", function(selfBtn)
                    selfBtn._hovered = true
                    selfBtn:ApplyVisual()
                end)
                btn:SetScript("OnLeave", function(selfBtn)
                    selfBtn._hovered = false
                    clearDockRowNativeOffset(selfBtn)
                    selfBtn:ApplyVisual()
                end)
                btn:HookScript("OnShow", function(selfBtn)
                    clearDockRowNativeOffset(selfBtn)
                end)
                btn:SetScript("OnMouseDown", function(selfBtn)
                    if selfBtn._disabled then
                        return
                    end
                    if not isDockRowHost(selfBtn) then
                        return
                    end
                    setDockRowNativeOffset(selfBtn, PRESS_TEXT_OFFSET_X, PRESS_TEXT_OFFSET_Y)
                end)
                btn:SetScript("OnMouseUp", function(selfBtn)
                    clearDockRowNativeOffset(selfBtn)
                end)
                function btn:SetEnabled(enabled)
                    local allow = enabled and true or false
                    self._disabled = not allow
                    self._hovered = false
                    self._pressed = false
                    clearDockRowNativeOffset(self)
                    self:EnableMouse(allow)
                    self:ApplyVisual()
                end
                btn:ApplyVisual()
                if isDockRowHost(btn) then
                    setDockRowNativeOffset(btn, 0, 0)
                end
                return btn
            end

            holder.disabledBtn = createToggleButton("Disabled")
            holder.disabledBtn._kind = "off"
            holder.enabledBtn = createToggleButton("Enabled")
            holder.enabledBtn._kind = "on"

            holder.disabledBtn:SetPoint("TOPLEFT", holder, "TOPLEFT", 0, 0)
            holder.enabledBtn:SetPoint("TOPRIGHT", holder, "TOPRIGHT", 0, 0)
            holder.disabledBtn:SetSize(FIXED_FOOTPRINTS.ROW_ENABLE_BUTTON_W, FIXED_FOOTPRINTS.ROW_ENABLE_BUTTON_H)
            holder.enabledBtn:SetSize(FIXED_FOOTPRINTS.ROW_ENABLE_BUTTON_W, FIXED_FOOTPRINTS.ROW_ENABLE_BUTTON_H)

            function holder:SetChecked(v)
                self._checked = PA_SafeBool(v)
                self.disabledBtn._selected = not self._checked
                self.enabledBtn._selected = self._checked
                self.disabledBtn:ApplyVisual()
                self.enabledBtn:ApplyVisual()
            end

            function holder:GetChecked()
                return self._checked
            end

            function holder:SetEnabled(enabled)
                local allow = enabled and true or false
                self._enabled = allow
                if self.disabledBtn and self.disabledBtn.SetEnabled then
                    self.disabledBtn:SetEnabled(allow)
                end
                if self.enabledBtn and self.enabledBtn.SetEnabled then
                    self.enabledBtn:SetEnabled(allow)
                end
                self:SetAlpha(allow and 1 or 0.55)
            end

            holder.disabledBtn:SetScript("OnClick", function()
                local slot = getDockSlot(slotIndex)
                if not slot.enabled then
                    return
                end
                slot.enabled = false
                setLoadoutPresetCustom()
                onUIChanged(false)
            end)
            holder.enabledBtn:SetScript("OnClick", function()
                local slot = getDockSlot(slotIndex)
                if slot.enabled then
                    return
                end
                slot.enabled = true
                setLoadoutPresetCustom()
                onUIChanged(false)
            end)

            holder:SetChecked(false)
            holder:SetEnabled(true)
            registerSettingsWindowVisualRefresh(holder, function(selfHolder)
                if selfHolder.disabledBtn and selfHolder.disabledBtn.ApplyVisual then
                    selfHolder.disabledBtn:ApplyVisual()
                end
                if selfHolder.enabledBtn and selfHolder.enabledBtn.ApplyVisual then
                    selfHolder.enabledBtn:ApplyVisual()
                end
            end)
            return holder
        end

        for i = 1, 10 do
            local slotIndex = i
            local row = { index = slotIndex }
            row.enabled = createRowEnableToggle(scrollChild, slotIndex)
            row.status = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlightSmall", 11)
            row.status:SetJustifyH("LEFT")
            row.status:SetText("")
            row.status:Hide()
            row.namePill = CreateFrame("Button", nil, scrollChild, "BackdropTemplate")
            ApplyPillStyle_Editable(row.namePill)
            row.namePill.label = createStyledFontString(row.namePill, "ARTWORK", "GameFontHighlightSmall", 11)
            row.namePill.label:SetPoint("LEFT", row.namePill, "LEFT", 8, 0)
            row.namePill.label:SetPoint("RIGHT", row.namePill, "RIGHT", -20, 0)
            row.namePill.label:SetJustifyH("LEFT")
            row.namePill.label:SetWordWrap(false)
            local function openNameEditor()
                if widgets.renamePopover and widgets.renamePopover.OpenForRow then
                    widgets.renamePopover:OpenForRow(slotIndex, row)
                end
            end
            row.namePill:SetScript("OnClick", openNameEditor)
            row.nameIBeam = CreateFrame("EditBox", nil, row.namePill)
            row.nameIBeam:SetAllPoints(row.namePill)
            row.nameIBeam:SetAutoFocus(false)
            row.nameIBeam:EnableMouse(true)
            if row.nameIBeam.SetMouseClickEnabled then
                row.nameIBeam:SetMouseClickEnabled(true)
            end
            if row.nameIBeam.SetMouseMotionEnabled then
                row.nameIBeam:SetMouseMotionEnabled(true)
            end
            if row.nameIBeam.EnableKeyboard then
                row.nameIBeam:EnableKeyboard(false)
            end
            row.nameIBeam:SetFrameLevel((row.namePill:GetFrameLevel() or 1) + 5)
            row.nameIBeam:SetText(" ")
            row.nameIBeam:SetTextInsets(0, 0, 0, 0)
            row.nameIBeam:SetAlpha(0)
            row.nameIBeam:SetScript("OnEditFocusGained", nil)
            row.nameIBeam:SetScript("OnEnterPressed", nil)
            row.nameIBeam:SetScript("OnEscapePressed", nil)
            row.nameIBeam:SetScript("OnMouseUp", function()
                openNameEditor()
            end)
            row.nameIBeam:SetScript("OnEnter", function()
                if row.namePill and row.namePill.SetPillState and not row.namePill._disabled then
                    row.namePill:SetPillState(row.namePill._focused and "focus" or "hover")
                end
            end)
            row.nameIBeam:SetScript("OnLeave", function()
                if row.namePill and row.namePill.SetPillState then
                    row.namePill:SetPillState(row.namePill._focused and "focus" or "normal")
                end
            end)
            row.spellIDPill = CreateFrame("Button", nil, scrollChild, "BackdropTemplate")
            row.spellIDPill:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Tooltips\\UI-Tooltip-Border",
                edgeSize = 8,
                insets = { left = 1, right = 1, top = 1, bottom = 1 },
            })
            row.spellIDPill:SetBackdropColor(CONTROL_BASE_BG_R, CONTROL_BASE_BG_G, CONTROL_BASE_BG_B, CONTROL_BASE_BG_A)
            row.spellIDPill:SetBackdropBorderColor(CONTROL_BASE_BORDER_R, CONTROL_BASE_BORDER_G, CONTROL_BASE_BORDER_B, CONTROL_BASE_BORDER_A)
            row.spellIDPill.hover = row.spellIDPill:CreateTexture(nil, "HIGHLIGHT")
            row.spellIDPill.hover:SetAllPoints()
            row.spellIDPill.hover:SetTexture("Interface\\Buttons\\WHITE8x8")
            row.spellIDPill.hover:SetVertexColor(1, 1, 1, 0.06)
            row.spellIDPill.label = createStyledFontString(row.spellIDPill, "ARTWORK", "GameFontHighlightSmall", 11)
            row.spellIDPill.label:SetPoint("LEFT", row.spellIDPill, "LEFT", 8, 0)
            row.spellIDPill.label:SetPoint("RIGHT", row.spellIDPill, "RIGHT", -8, 0)
            row.spellIDPill.label:SetJustifyH("LEFT")
            row.spellIDPill.label:SetWordWrap(false)
            row.spellIDPill:SetScript("OnClick", function()
                if widgets.spellIDPopover and widgets.spellIDPopover.OpenForRow then
                    widgets.spellIDPopover:OpenForRow(slotIndex, row)
                end
            end)
            row.destination = CreateFrame("Button", nil, scrollChild, "BackdropTemplate")
            row.destination:SetHeight(FIXED_FOOTPRINTS.STANDARD_CONTROL_H)
            ApplyPillStyle_Dropdown(row.destination)
            row.destination.label = createStyledFontString(row.destination, "ARTWORK", "GameFontHighlightSmall", 11)
            row.destination.label:SetPoint("LEFT", row.destination, "LEFT", 8, 0)
            row.destination.label:SetPoint("RIGHT", row.destination, "RIGHT", -18, 0)
            row.destination.label:SetJustifyH("LEFT")
            row.destination.label:SetWordWrap(false)
            row.destination.chevron = createStyledFontString(row.destination, "ARTWORK", "GameFontHighlightSmall", 10)
            row.destination.chevron:SetPoint("RIGHT", row.destination, "RIGHT", -7, 0)
            row.destination.chevron:SetText("v")
            row.destination:SetScript("OnMouseDown", function(selfButton)
                selfButton._pressed = true
                selfButton:UpdateVisual()
            end)
            row.destination:SetScript("OnMouseUp", function(selfButton)
                selfButton._pressed = false
                selfButton:UpdateVisual()
            end)
            row.destination:UpdateVisual()
            row.destination:SetScript("OnClick", function(selfButton)
                if not selfButton:IsEnabled() then
                    return
                end
                if widgets.destinationPicker and widgets.destinationPicker.IsShown and widgets.destinationPicker:IsShown() and widgets.destinationPicker._ownerButton == selfButton then
                    widgets.destinationPicker:Close()
                    return
                end
                local slot = getDockSlot(slotIndex)
                local destinationChoices = getDestinationChoices()
                if widgets.destinationPicker._sourceOptionsRef ~= destinationChoices then
                    widgets.destinationPicker:SetOptions(destinationChoices)
                    widgets.destinationPicker._sourceOptionsRef = destinationChoices
                end
                widgets.destinationPicker:SetSelectedValue(slot.selection)
                widgets.destinationPicker:SetOnSelect(function(value, option, isClear)
                    if isClear then
                        slot.selection = "CUSTOM"
                        slot.spellID = 0
                        setDockSlotDefaultName(slot, 0)
                    elseif value == "CUSTOM" then
                        slot.selection = "CUSTOM"
                        setDockSlotDefaultName(slot, slot.spellID)
                    else
                        local spellID = math.floor(tonumber(value) or 0)
                        if spellID > 0 then
                            slot.selection = tostring(spellID)
                            slot.spellID = spellID
                            setDockSlotDefaultName(slot, spellID)
                        else
                            slot.selection = "CUSTOM"
                            slot.spellID = 0
                            setDockSlotDefaultName(slot, 0)
                        end
                    end
                    setLoadoutPresetCustom()
                    onUIChanged(false)
                end)
                if widgets.destinationPicker then
                    widgets.destinationPicker._ownerButton = selfButton
                end
                if selfButton.SetPillState then
                    selfButton:SetPillState("open")
                else
                    selfButton._open = true
                    selfButton:UpdateVisual()
                end
                widgets.destinationPicker:Open(selfButton)
            end)

            row.result = CreateFrame("Button", nil, scrollChild, "BackdropTemplate")
            row.result:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Tooltips\\UI-Tooltip-Border",
                edgeSize = 10,
                insets = { left = 2, right = 2, top = 2, bottom = 2 },
            })
            row.result:SetBackdropColor(0, 0, 0, 0.45)
            row.result:SetBackdropBorderColor(0.25, 0.25, 0.25, 1)
            row.result.icon = row.result:CreateTexture(nil, "ARTWORK")
            row.result.icon:SetAllPoints()
            row.result:SetScript("OnEnter", function()
                local slot = getDockSlot(slotIndex)
                if slot.spellID <= 0 then
                    return
                end
                GameTooltip:SetOwner(row.result, "ANCHOR_RIGHT")
                if GameTooltip.SetSpellByID then
                    GameTooltip:SetSpellByID(slot.spellID)
                else
                    GameTooltip:SetText(resolveSlotName(slot.spellID, "Unknown"))
                end
                GameTooltip:Show()
            end)
            row.result:SetScript("OnLeave", function()
                GameTooltip:Hide()
            end)
            registerDockSlotRowSearch(row)
            slotRows[slotIndex] = row
        end

        local function refreshSwatch()
            local c = PortalAuthorityDB.dockFontColor
            widgets.color.swatch:SetBackdropColor(c.r, c.g, c.b, c.a)
        end
        widgets.color.swatch:SetScript("OnClick", function()
            openColorPicker(function()
                refreshSwatch()
                ApplyDockAppearanceSettings()
            end)
        end)

        local function syncCheckboxes()
            if widgets.lockDock and widgets.lockDock.Refresh then widgets.lockDock:Refresh() end
            if refreshLockDockVisualText then refreshLockDockVisualText() end
            if widgets.loadoutPresetSegment and widgets.loadoutPresetSegment.Refresh then widgets.loadoutPresetSegment:Refresh() end
            if widgets.dockEnabled and widgets.dockEnabled.Refresh then widgets.dockEnabled:Refresh() end
            if widgets.hideNames and widgets.hideNames.Refresh then widgets.hideNames:Refresh() end
            if widgets.gizmoMode and widgets.gizmoMode.Refresh then widgets.gizmoMode:Refresh() end
            if applyDockGizmoVisibilityOverrideState then applyDockGizmoVisibilityOverrideState() end
        end

        local function setDockObjectVisible(obj, visible)
            if not obj then
                return
            end
            if visible then
                if obj.Show then
                    obj:Show()
                end
            else
                if obj.Hide then
                    obj:Hide()
                end
            end
        end

        local function placeControl(spec, xLabel, xControl, y, controlW, anchorFrame)
            local anchorParent = anchorFrame or scrollChild
            local placement = PAGE.CONTROL_PLACEMENT
            setDockObjectVisible(spec.label, true)
            setDockObjectVisible(spec.control, true)
            spec.label:ClearAllPoints()
            spec.label:SetPoint("TOPLEFT", anchorParent, "TOPLEFT", xLabel, y)
            if spec.kind == "dropdown" then
                spec.control:ClearAllPoints()
                spec.control:SetPoint("TOPLEFT", anchorParent, "TOPLEFT", xControl + placement.DROPDOWN_X_SHIFT, y + placement.DROPDOWN_Y_SHIFT)
                UIDropDownMenu_SetWidth(spec.control, controlW)
            elseif spec.kind == "font_picker" then
                spec.control:ClearAllPoints()
                spec.control:SetPoint("TOPLEFT", anchorParent, "TOPLEFT", xControl, y + placement.COMPACT_CONTROL_Y_SHIFT)
                if spec.SetWidth then
                    spec:SetWidth(controlW)
                else
                    spec.control:SetWidth(controlW)
                end
            elseif spec.kind == "premium_slider" then
                spec.control:ClearAllPoints()
                spec.control:SetPoint("TOPLEFT", anchorParent, "TOPLEFT", xControl, y + placement.COMPACT_CONTROL_Y_SHIFT)
                if spec.SetWidth then
                    spec:SetWidth(controlW)
                else
                    spec.control:SetWidth(controlW)
                end
            elseif spec.kind == "stepper" then
                spec.control:ClearAllPoints()
                spec.control:SetPoint("TOPLEFT", anchorParent, "TOPLEFT", xControl, y + placement.COMPACT_CONTROL_Y_SHIFT)
                if spec.SetWidth then
                    spec:SetWidth(controlW)
                else
                    spec.control:SetWidth(controlW)
                end
            elseif spec.kind == "segmented" then
                spec.control:ClearAllPoints()
                spec.control:SetPoint("TOPLEFT", anchorParent, "TOPLEFT", xControl, y + placement.COMPACT_CONTROL_Y_SHIFT)
                if spec.Layout then
                    spec:Layout(controlW)
                else
                    spec.control:SetWidth(controlW)
                    spec.control:SetHeight(FIXED_FOOTPRINTS.STANDARD_CONTROL_H)
                end
            elseif spec.kind == "slider" then
                spec.control:ClearAllPoints()
                spec.control:SetPoint("TOPLEFT", anchorParent, "TOPLEFT", xControl, y + placement.SLIDER_Y_SHIFT)
                spec.control:SetWidth(controlW)
                if spec.valueText then
                    setDockObjectVisible(spec.valueText, true)
                    spec.valueText:ClearAllPoints()
                    spec.valueText:SetPoint("LEFT", spec.control, "RIGHT", placement.VALUE_TEXT_GAP, 0)
                end
            else
                spec.control:ClearAllPoints()
                spec.control:SetPoint("TOPLEFT", anchorParent, "TOPLEFT", xControl, y)
                spec.control:SetSize(controlW, FIXED_FOOTPRINTS.STANDARD_CONTROL_H)
            end
        end
        local function setSlotRowEnabledVisuals(row, slotEnabled, moduleEnabled)
            local allowModuleInteraction = moduleEnabled and true or false
            local allowSlotInteraction = allowModuleInteraction and (slotEnabled and true or false)

            setSettingsControlEnabled(row.enabled, allowModuleInteraction)

            if not allowSlotInteraction
                and widgets.destinationPicker
                and widgets.destinationPicker.Close
                and widgets.destinationPicker.IsShown
                and widgets.destinationPicker:IsShown()
                and widgets.destinationPicker._ownerButton == row.destination then
                widgets.destinationPicker:Close()
            end

            row.destination:SetEnabled(allowSlotInteraction)
            row.destination:SetAlpha(allowSlotInteraction and 1 or 0.86)
            if not allowSlotInteraction then
                if row.destination.SetPillState then
                    row.destination:SetPillState("disabled")
                else
                    row.destination._disabled = true
                    row.destination._hovered = false
                    row.destination._pressed = false
                    if row.destination.UpdateVisual then
                        row.destination:UpdateVisual()
                    end
                end
            else
                if row.destination.SetPillState and row.destination._disabled then
                    row.destination:SetPillState(row.destination._open and "open" or "normal")
                elseif row.destination.UpdateVisual then
                    row.destination._disabled = false
                    row.destination:UpdateVisual()
                end
            end

            row.spellIDPill:SetEnabled(allowSlotInteraction)
            row.spellIDPill:SetAlpha(allowSlotInteraction and 1 or 0.75)
            row.spellIDPill.label:SetTextColor(1, 1, 1, allowSlotInteraction and 1 or 0.6)

            row.namePill:SetEnabled(allowSlotInteraction)
            row.namePill:SetAlpha(allowSlotInteraction and 1 or 0.86)
            if row.nameIBeam then
                row.nameIBeam:EnableMouse(allowSlotInteraction)
                if row.nameIBeam.SetEnabled then
                    row.nameIBeam:SetEnabled(allowSlotInteraction)
                end
                if row.nameIBeam.SetMouseClickEnabled then
                    row.nameIBeam:SetMouseClickEnabled(allowSlotInteraction)
                end
                if not allowSlotInteraction and row.nameIBeam.ClearFocus then
                    row.nameIBeam:ClearFocus()
                end
            end
            if not allowSlotInteraction then
                if row.namePill.SetPillState then
                    row.namePill:SetPillState("disabled")
                else
                    row.namePill._disabled = true
                    row.namePill._hovered = false
                    row.namePill._pressed = false
                    if row.namePill.UpdateVisual then
                        row.namePill:UpdateVisual()
                    end
                end
            else
                if row.namePill.SetPillState and row.namePill._disabled then
                    row.namePill:SetPillState(row.namePill._focused and "focus" or "normal")
                elseif row.namePill.UpdateVisual then
                    row.namePill._disabled = false
                    row.namePill:UpdateVisual()
                else
                    row.namePill.label:SetTextColor(1, 1, 1, 1)
                end
            end

            row.result:EnableMouse(allowSlotInteraction)
            row.result:SetAlpha(allowSlotInteraction and 1 or 0.6)
            row.result.icon:SetDesaturated(not allowSlotInteraction)

            row.status:SetAlpha(0)
        end

        local function refreshSlotRows()
            local moduleEnabled = isDockModuleEnabled()
            for i = 1, 10 do
                local row = slotRows[i]
                local slot = getDockSlot(i)

                row.enabled:SetChecked(slot.enabled)
                local selected = getDestinationOptionByValue(slot.selection)
                if slot.selection == "CUSTOM" then
                    if slot.spellID > 0 then
                        row.destination.label:SetText(string.format("Custom (%d)", getVisualDockIDForSpell(slot.spellID)))
                    else
                        row.destination.label:SetText("Custom")
                    end
                else
                    row.destination.label:SetText((selected and selected.buttonLabel) or ("Spell " .. tostring(slot.selection)))
                end

                local displayName = getDockSlotDisplayName(slot)
                row.namePill.label:SetText(displayName ~= "" and displayName or "-")
                row.spellIDPill.label:SetText(tostring(getVisualDockIDForSpell(slot.spellID or 0)))

                local texture = getSpellTextureByID(slot.spellID) or "Interface\\ICONS\\INV_Misc_QuestionMark"
                row.result.icon:SetTexture(texture)
                row.result.icon:SetTexCoord(0, 1, 0, 1)
                if slot.spellID > 0 and (texture == nil or texture == "Interface\\ICONS\\INV_Misc_QuestionMark") then
                    requestSpellDataRefresh(i, slot.spellID)
                end

                row.status:SetText("")

                setSlotRowEnabledVisuals(row, slot.enabled, moduleEnabled)
                if widgets.renamePopover and widgets.renamePopover:IsShown() and widgets.renamePopover.slotIndex == i and not slot.enabled then
                    widgets.renamePopover:Close(false)
                end
                if widgets.spellIDPopover and widgets.spellIDPopover:IsShown() and widgets.spellIDPopover.slotIndex == i and not slot.enabled then
                    widgets.spellIDPopover:Close(false)
                end
            end
        end

        applyDockModuleEnabledState = function()
            local moduleEnabled = isDockModuleEnabled()

            setSettingsControlEnabled(widgets.lockDock, moduleEnabled)
            setSettingsControlEnabled(widgets.resetDockAnchor, moduleEnabled)
            setSettingsControlEnabled(widgets.loadoutPresetSegment, moduleEnabled)
            setSettingsControlEnabled(widgets.hideNames, moduleEnabled)
            setSettingsControlEnabled(widgets.gizmoMode, moduleEnabled)
            setSettingsControlEnabled(widgets.layoutModeSegment, moduleEnabled)
            setSettingsControlEnabled(widgets.iconsPerRow, moduleEnabled)
            setSettingsControlEnabled(widgets.layoutIconSize, moduleEnabled)
            setSettingsControlEnabled(widgets.labelMode, moduleEnabled)
            setSettingsControlEnabled(widgets.labelSide, moduleEnabled)
            setSettingsControlEnabled(widgets.labelSideInside, moduleEnabled)
            setSettingsControlEnabled(widgets.font, moduleEnabled)
            setSettingsControlEnabled(widgets.fontSize, moduleEnabled)
            setSettingsControlEnabled(widgets.color and widgets.color.swatch or nil, moduleEnabled)
            setSettingsControlEnabled(widgets.outlineToggle, moduleEnabled)
            setSettingsControlEnabled(widgets.hoverGlowSegment, moduleEnabled)
            if applyDockGizmoVisibilityOverrideState then
                applyDockGizmoVisibilityOverrideState()
            end

            if widgets.lowerSectionsContainer and widgets.lowerSectionsContainer.SetAlpha then
                widgets.lowerSectionsContainer:SetAlpha(moduleEnabled and 1 or 0.55)
            end
            if widgets.loadoutPresetSegment and widgets.loadoutPresetSegment.label and widgets.loadoutPresetSegment.label.SetAlpha then
                widgets.loadoutPresetSegment.label:SetAlpha(moduleEnabled and 1 or 0.55)
            end
            if widgets.lockRowContainer and widgets.lockRowContainer.SetAlpha then
                widgets.lockRowContainer:SetAlpha(moduleEnabled and 1 or 0.55)
            end

            for _, textWidget in ipairs({
                widgets.lockStateHelper,
                widgets.dockCustomizationHelper,
                widgets.dockCustomizationMatchStatus,
                widgets.enableLabel,
                widgets.layoutSectionHeader,
                widgets.labelsSectionHeader,
                widgets.styleSectionHeader,
                widgets.layoutSpacingHint,
                widgets.iconsPerRowGridOnlyHint,
                widgets.slotColDestination,
                widgets.slotColName,
                widgets.slotColSpellID,
                widgets.slotColResult,
            }) do
                setSettingsTextEnabled(textWidget, moduleEnabled)
            end

            if widgets.color and widgets.color.inlineLabel then
                setSettingsTextEnabled(widgets.color.inlineLabel, moduleEnabled)
            end

            if not moduleEnabled then
                if widgets.destinationPicker and widgets.destinationPicker.Close then
                    widgets.destinationPicker:Close()
                end
                if widgets.renamePopover and widgets.renamePopover.Close then
                    widgets.renamePopover:Close(false)
                end
                if widgets.spellIDPopover and widgets.spellIDPopover.Close then
                    widgets.spellIDPopover:Close(false)
                end
            end
        end

        relayout = function()
            syncCheckboxes()
            forceDockFontUiState()
            forceDockFontSizeUiState()
            forceStyleToggleUiState()
            do
                local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
                local resolvedLayoutMode = getDockSimpleLayoutModeForSettings(defaults)
                if widgets.layoutModeSegment and widgets.layoutModeSegment.SetVisualSelectedValue then
                    widgets.layoutModeSegment:SetVisualSelectedValue(resolvedLayoutMode)
                end
                forceDockLabelUiState()
            end
            refreshSwatch()
            refreshSlotRows()

            local viewportW = scrollFrame:GetWidth()
            local contentW = math.max(PAGE.MIN_CONTENT_W, viewportW - PAGE.SCROLL_WIDTH_FUDGE)
            local left, right = PAGE.LEFT, PAGE.RIGHT
            local narrow = contentW < PAGE.NARROW_BREAKPOINT
            local ROW_H, ROW_GAP = PAGE.ROW_H, PAGE.ROW_GAP
            local ROW_STEP = ROW_H + ROW_GAP

            local pairContent = contentW - left - right
            local colGap = narrow and 0 or PAGE.WIDE_COLUMN_GAP
            local colW = narrow and pairContent or math.floor((pairContent - colGap) / 2)
            local CHECK_X = PAGE.CHECK_LEFT - left
            local LOADOUT_ROW_SHIFT_Y = PRESET_AND_TABLE.LOADOUT_ROW_SHIFT_Y -- single knob: positive moves the Midnight Loadout row down
            local TABLE_BLOCK_SHIFT_Y = PRESET_AND_TABLE.TABLE_BLOCK_SHIFT_Y -- single knob: positive moves the entire destination table down (preset row is unaffected)
            local LOWER_SECTIONS_BLOCK_OFFSET_Y = LOWER_SECTIONS.BLOCK_OFFSET_Y -- single knob: positive moves divider above Layout + everything below up
            local DESTINATION_COLUMN_Y_SHIFT = PRESET_AND_TABLE.DESTINATION_COLUMN_Y_SHIFT -- single knob: positive moves the entire Destination column up
            local NAME_SPELL_COLUMNS_Y_SHIFT = PRESET_AND_TABLE.NAME_SPELL_COLUMNS_Y_SHIFT -- single knob: positive moves Name + Spell ID columns up together
            local RESULT_COLUMN_Y_SHIFT = PRESET_AND_TABLE.RESULT_COLUMN_Y_SHIFT -- single knob: positive moves the entire Result column up
            local STATUS_TEXT_Y_SHIFT = PRESET_AND_TABLE.STATUS_TEXT_Y_SHIFT -- single knob: positive moves ENABLED/DISABLED status text up
            local SLOT_ENABLE_CHECKBOX_Y_SHIFT = PRESET_AND_TABLE.SLOT_ENABLE_CHECKBOX_Y_SHIFT -- single knob: positive moves all slot-row enable checkboxes up
            local SLOT_HEADER_TEXT_X_SHIFT = PRESET_AND_TABLE.SLOT_HEADER_TEXT_X_SHIFT -- single knob: positive moves Destination/Name/Spell ID header text right
            local VISIBILITY_BLOCK_SHIFT_Y = LOWER_SECTIONS.VISIBILITY_BLOCK_SHIFT_Y -- single knob: positive moves Visibility Rules + everything below it down (divider stays fixed)
            local VISIBILITY_LABELS_SHIFT_Y = LOWER_SECTIONS.VISIBILITY_LABELS_SHIFT_Y -- single knob: positive moves only visibility labels down (toggles stay fixed)
            local LABEL_X = PAGE.LABEL_X
            local CONTROL_X = PAGE.CONTROL_X
            local presetDividerReferenceGap = PRESET_AND_TABLE.PRESET_DIVIDER_FALLBACK_GAP

            local dropdownW = math.max(PAGE.DROPDOWN_MIN_W, math.min(PAGE.DROPDOWN_MAX_W, colW - CONTROL_X - PAGE.CONTROL_WIDTH_RIGHT_PAD))
            local numericW = math.max(PAGE.NUMERIC_MIN_W, math.min(PAGE.NUMERIC_MAX_W, colW - CONTROL_X - PAGE.CONTROL_WIDTH_RIGHT_PAD))
            local sliderW = math.max(PAGE.SLIDER_MIN_W, math.min(PAGE.SLIDER_MAX_W, colW - CONTROL_X - PAGE.SLIDER_WIDTH_RIGHT_PAD))

            local function columnBase(col)
                if col == 2 then
                    return left + colW + colGap
                end
                return left
            end

            local function pair(leftSpec, rightSpec, rowY, leftWidth, rightWidth)
                local leftBase = columnBase(1)
                if narrow then
                    placeControl(leftSpec, leftBase + LABEL_X, leftBase + CONTROL_X, rowY, leftWidth or dropdownW)
                    rowY = rowY - PAGE.PAIR_ROW_STEP
                    placeControl(rightSpec, leftBase + LABEL_X, leftBase + CONTROL_X, rowY, rightWidth or dropdownW)
                    return rowY - PAGE.PAIR_ROW_STEP
                end
                local rightBase = columnBase(2)
                placeControl(leftSpec, leftBase + LABEL_X, leftBase + CONTROL_X, rowY, leftWidth or dropdownW)
                placeControl(rightSpec, rightBase + LABEL_X, rightBase + CONTROL_X, rowY, rightWidth or dropdownW)
                return rowY - PAGE.PAIR_ROW_STEP
            end

            scrollChild:SetWidth(contentW)
            widgets.playerHeader:ClearAllPoints()
            widgets.playerHeader:SetPoint("TOPRIGHT", self, "TOPRIGHT", -PAGE.PLAYER_HEADER_PAD, -PAGE.PLAYER_HEADER_PAD)

            local leftBase = columnBase(1)
            local tableLeft = leftBase + CHECK_X
            local dividerLeftX = tableLeft
            local loadoutPresetW = math.max(
                PRESET_AND_TABLE.LOADOUT_PRESET_MIN_W,
                math.min(PRESET_AND_TABLE.LOADOUT_PRESET_MAX_W, contentW - tableLeft - right - PRESET_AND_TABLE.LOADOUT_RIGHT_PAD)
            )

            widgets.positionLabel:ClearAllPoints()
            setDockObjectVisible(widgets.positionLabel, false)
            widgets.positionLabel:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)

            local lockRowLeft = tableLeft
            local lockLabelToToggleGap = TOP_BLOCK.LABEL_TO_TOGGLE_GAP
            local lockToggleToResetGap = TOP_BLOCK.TOGGLE_TO_RESET_GAP
            local resetW, resetH = FIXED_FOOTPRINTS.RESET_ANCHOR_W, FIXED_FOOTPRINTS.RESET_ANCHOR_H
            local lockLabel = widgets.lockDock and widgets.lockDock.label or nil
            local lockLabelW = 0
            local lockLabelH = 0
            if lockLabel then
                lockLabelW = math.ceil(lockLabel:GetStringWidth() or 0)
                lockLabelH = math.ceil(lockLabel:GetStringHeight() or 0)
            end
            local masterLabel = widgets.dockEnabled and widgets.dockEnabled.label or nil
            local masterLabelH = 0
            if masterLabel then
                masterLabelH = math.ceil(masterLabel:GetStringHeight() or 0)
            end
            local referenceLabelH = lockLabelH
            if referenceLabelH <= 0 then
                referenceLabelH = masterLabelH
            end
            if referenceLabelH <= 0 and widgets.enableLabel and widgets.enableLabel.GetStringHeight then
                referenceLabelH = widgets.enableLabel:GetStringHeight() or 0
            end
            local U = math.max(1, referenceLabelH)
            local spacingAB = U * TOP_BLOCK.HELPER_GAP_RATIO -- A -> B and C -> D
            local spacingBC = U * TOP_BLOCK.DIVIDER_GAP_RATIO -- B -> C
            local spacingDHeader = U * TOP_BLOCK.PRESET_HEADER_GAP_RATIO -- D -> Destination header
            local useHostedChrome = isPanelUsingCustomSettingsWindowHost(self)
            local lockBtnTextW = 0
            if widgets.lockDock and type(widgets.lockDock.buttons) == "table" then
                for _, btn in ipairs(widgets.lockDock.buttons) do
                    if btn and btn.Text then
                        lockBtnTextW = math.max(lockBtnTextW, math.ceil(btn.Text:GetStringWidth() or 0))
                    end
                end
            end
            lockBtnTextW = math.max(lockBtnTextW, TOP_BLOCK.LOCK_BUTTON_MIN_TEXT_W)
            local lockPerBtnPad = TOP_BLOCK.LOCK_BUTTON_PAD_X
            local lockToggleWFromContent = ((lockBtnTextW + (lockPerBtnPad * 2)) * 2) + TOP_BLOCK.LOCK_SEGMENT_INNER_GAP
            local lockToggleWMax = math.max(
                TOP_BLOCK.LOCK_TOGGLE_MIN_W,
                (contentW - TOP_BLOCK.CONTENT_RIGHT) - (lockRowLeft + lockLabelW + lockLabelToToggleGap + lockToggleToResetGap + resetW)
            )
            local lockToggleW = math.max(TOP_BLOCK.LOCK_TOGGLE_MIN_W, math.min(lockToggleWFromContent, lockToggleWMax))
            local sharedToggleX = (lockLabelW > 0) and (lockLabelW + lockLabelToToggleGap) or 0
            if widgets.dockEnabled and widgets.dockEnabled.Layout then
                widgets.dockEnabled:Layout(math.max(lockToggleW, 150))
            end
            local masterToggleH = (widgets.dockEnabled and widgets.dockEnabled.control and math.floor(widgets.dockEnabled.control:GetHeight() or FIXED_FOOTPRINTS.STANDARD_CONTROL_H)) or FIXED_FOOTPRINTS.STANDARD_CONTROL_H
            local masterRowH = math.max(TOP_BLOCK.LOCK_ROW_FLOOR, masterToggleH, masterLabelH)
            local masterRowGap = 4
            if widgets.lockDock and widgets.lockDock.Layout then
                widgets.lockDock:Layout(lockToggleW)
            end
            local lockToggleH = (widgets.lockDock and widgets.lockDock.control and math.floor(widgets.lockDock.control:GetHeight() or FIXED_FOOTPRINTS.STANDARD_CONTROL_H)) or FIXED_FOOTPRINTS.STANDARD_CONTROL_H
            local lockRowH = math.max(TOP_BLOCK.LOCK_ROW_FLOOR, resetH, lockToggleH, lockLabelH)
            local lockRowW = math.max(1, contentW - TOP_BLOCK.CONTENT_RIGHT - lockRowLeft)
            local lockHelperLineH = math.max(1, (widgets.lockStateHelper and widgets.lockStateHelper.GetStringHeight and widgets.lockStateHelper:GetStringHeight()) or U)
            local topBlockHelperGap = U * TOP_BLOCK.HELPER_GAP_RATIO
            local topBlockDividerGap = U * TOP_BLOCK.DIVIDER_GAP_RATIO
            local topBlockDividerOffset = topBlockDividerGap * TOP_BLOCK.DIVIDER_OFFSET_RATIO
            -- Preserve the accepted handoff below the top block; only the top-block rhythm changes.
            local hostedTopNudge = useHostedChrome and SETTINGS_WINDOW_HOSTED_TOP_RHYTHM_NUDGE or 0
            local y = (-TOP_BLOCK.TOP_PAD - hostedTopNudge)
                - (useHostedChrome and 0 or TOP_BLOCK.PRESERVED_HEADER_ADVANCE)
                - (useHostedChrome and 0 or (masterRowH + masterRowGap))
                - lockRowH
                - spacingAB
                - lockHelperLineH
                - spacingBC
            local topBlockY = -TOP_BLOCK.TOP_PAD - hostedTopNudge

            if useHostedChrome then
                setDockObjectVisible(widgets.header, false)
                widgets.header:ClearAllPoints()
                widgets.header:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                setDockObjectVisible(widgets.sectionDescriptor, false)
                widgets.sectionDescriptor:ClearAllPoints()
                widgets.sectionDescriptor:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                setDockObjectVisible(widgets.masterRowContainer, false)
                widgets.masterRowContainer:ClearAllPoints()
                widgets.masterRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                if masterLabel then
                    setDockObjectVisible(masterLabel, false)
                    masterLabel:ClearAllPoints()
                    masterLabel:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                end
                if widgets.dockEnabled and widgets.dockEnabled.control then
                    setDockObjectVisible(widgets.dockEnabled.control, false)
                    widgets.dockEnabled.control:ClearAllPoints()
                    widgets.dockEnabled.control:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                end
            else
                setDockObjectVisible(widgets.header, true)
                setDockObjectVisible(widgets.sectionDescriptor, true)
                widgets.header:ClearAllPoints()
                widgets.header:SetWidth(math.max(1, contentW - TOP_BLOCK.HEADER_LEFT - TOP_BLOCK.CONTENT_RIGHT))
                widgets.header:SetWordWrap(false)
                if widgets.header.SetMaxLines then
                    widgets.header:SetMaxLines(1)
                end
                if widgets.header.SetJustifyH then
                    widgets.header:SetJustifyH("LEFT")
                end
                local headerH = math.max(
                    TOP_BLOCK.HEADER_FLOOR,
                    math.ceil(tonumber((widgets.header.GetStringHeight and widgets.header:GetStringHeight()) or 0) or 0)
                )
                widgets.header:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", TOP_BLOCK.HEADER_LEFT, topBlockY)
                topBlockY = topBlockY - headerH - TOP_BLOCK.HEADER_BOTTOM_GAP
                local topBlockAfterHeaderY = topBlockY
                topBlockY = layoutSettingsSectionDescriptor(
                    widgets.sectionDescriptor,
                    scrollChild,
                    TOP_BLOCK.HEADER_LEFT,
                    topBlockY,
                    math.max(1, contentW - TOP_BLOCK.HEADER_LEFT - TOP_BLOCK.CONTENT_RIGHT)
                )
                y = y - (topBlockAfterHeaderY - topBlockY)

                setDockObjectVisible(widgets.masterRowContainer, true)
                widgets.masterRowContainer:ClearAllPoints()
                widgets.masterRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", lockRowLeft, topBlockY + TOP_BLOCK.LOCK_STACK_NUDGE_Y)
                widgets.masterRowContainer:SetSize(lockRowW, masterRowH)
                if masterLabel then
                    setDockObjectVisible(masterLabel, true)
                    masterLabel:ClearAllPoints()
                    masterLabel:SetPoint("LEFT", widgets.masterRowContainer, "LEFT", 0, 0)
                end
                if widgets.dockEnabled and widgets.dockEnabled.control then
                    setDockObjectVisible(widgets.dockEnabled.control, true)
                    widgets.dockEnabled.control:ClearAllPoints()
                    widgets.dockEnabled.control:SetPoint("LEFT", widgets.masterRowContainer, "LEFT", sharedToggleX, 0)
                end
                topBlockY = topBlockY - masterRowH - masterRowGap
            end

            widgets.lockRowContainer:ClearAllPoints()
            widgets.lockRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", lockRowLeft, topBlockY + TOP_BLOCK.LOCK_STACK_NUDGE_Y)
            widgets.lockRowContainer:SetSize(lockRowW, lockRowH)

            if lockLabel then
                lockLabel:ClearAllPoints()
                lockLabel:SetPoint("LEFT", widgets.lockRowContainer, "LEFT", 0, 0)
            end
            widgets.lockDock.control:ClearAllPoints()
            widgets.lockDock.control:SetPoint("LEFT", widgets.lockRowContainer, "LEFT", sharedToggleX, 0)
            widgets.resetDockAnchor:ClearAllPoints()
            widgets.resetDockAnchor:SetSize(resetW, resetH)
            widgets.resetDockAnchor:SetPoint("LEFT", widgets.lockDock.control, "RIGHT", lockToggleToResetGap, 0)

            topBlockY = topBlockY - lockRowH
            widgets.lockStateHelper:ClearAllPoints()
            if widgets.lockStateHelper.SetJustifyH then
                widgets.lockStateHelper:SetJustifyH("LEFT")
            end
            widgets.lockStateHelper:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", lockRowLeft, topBlockY - topBlockHelperGap + TOP_BLOCK.LOCK_STACK_NUDGE_Y)
            topBlockY = topBlockY - topBlockHelperGap - lockHelperLineH

            widgets.lockDockDivider:ClearAllPoints()
            local lockDockDividerY = topBlockY - topBlockDividerOffset + TOP_BLOCK.LOCK_STACK_NUDGE_Y
            widgets.lockDockDivider:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", dividerLeftX, lockDockDividerY)
            widgets.lockDockDivider:SetPoint("TOPRIGHT", scrollChild, "TOPRIGHT", -TOP_BLOCK.CONTENT_RIGHT, lockDockDividerY)
            widgets.lockDockDivider:SetHeight(FIXED_FOOTPRINTS.DIVIDER_H)
            topBlockY = topBlockY - topBlockDividerGap

            widgets.dockCustomizationLabel:ClearAllPoints()
            setDockObjectVisible(widgets.dockCustomizationLabel, false)
            widgets.dockCustomizationLabel:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
            widgets.loadoutPresetSegment.label:ClearAllPoints()
            setDockObjectVisible(widgets.loadoutPresetSegment.label, false)
            widgets.loadoutPresetSegment.label:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
            widgets.loadoutPresetSegment.control:ClearAllPoints()
            setDockObjectVisible(widgets.loadoutPresetSegment.control, true)
            local presetRowTopY = y - LOADOUT_ROW_SHIFT_Y
            widgets.loadoutPresetSegment.control:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", tableLeft, presetRowTopY)
            presetDividerReferenceGap = math.max(0, math.floor((lockDockDividerY - presetRowTopY) + 0.5))
            if presetDividerReferenceGap <= 0 then
                presetDividerReferenceGap = PRESET_AND_TABLE.PRESET_DIVIDER_FALLBACK_GAP
            end
            if widgets.loadoutPresetSegment.Layout then
                widgets.loadoutPresetSegment:Layout(loadoutPresetW)
            end
            local presetRowH = math.max(
                1,
                (widgets.loadoutPresetSegment and widgets.loadoutPresetSegment.control and widgets.loadoutPresetSegment.control:GetHeight())
                or FIXED_FOOTPRINTS.STANDARD_CONTROL_H
            )
            widgets.dockCustomizationHelper:ClearAllPoints()
            widgets.dockCustomizationHelper:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", tableLeft, y - presetRowH - spacingAB - LOADOUT_ROW_SHIFT_Y)
            local presetHelperH = math.max(1, (widgets.dockCustomizationHelper and widgets.dockCustomizationHelper.GetStringHeight and widgets.dockCustomizationHelper:GetStringHeight()) or U)

            local matchStatusText = ""
            local showMatchStatus = false
            local matchStatusVariant = nil
            local activePreset = normalizeLoadoutPresetValue(PortalAuthorityDB and PortalAuthorityDB.dockLoadoutPreset)
            if activePreset == "CUSTOM" then
                local matchesSeason01, canonicalOrder = getCustomSeason01MatchState()
                if matchesSeason01 then
                    showMatchStatus = true
                    if canonicalOrder then
                        matchStatusVariant = "season01_exact"
                        matchStatusText = "• Matches Midnight Season 01"
                    else
                        matchStatusVariant = "season01_custom_order"
                        matchStatusText = "• Matches Midnight Season 01 (custom order)"
                    end
                end
            end

            local tableWidth = contentW - tableLeft - right - PRESET_AND_TABLE.LOADOUT_RIGHT_PAD
            local matchStatusGap = PRESET_AND_TABLE.MATCH_STATUS_GAP
            local matchStatusLaneH = math.max(
                1,
                math.floor(
                    (widgets.dockCustomizationHelper and widgets.dockCustomizationHelper.GetStringHeight and widgets.dockCustomizationHelper:GetStringHeight())
                    or U
                )
            )
            if widgets.dockCustomizationMatchStatus then
                local statusLabel = widgets.dockCustomizationMatchStatus
                local originalText = tostring(statusLabel:GetText() or "")
                if statusLabel.SetWidth then
                    statusLabel:SetWidth(math.max(1, tableWidth))
                end
                for _, candidateText in ipairs({
                    "",
                    "• Matches Midnight Season 01",
                    "• Matches Midnight Season 01 (custom order)",
                }) do
                    statusLabel:SetText(candidateText)
                    matchStatusLaneH = math.max(
                        matchStatusLaneH,
                        math.ceil(tonumber((statusLabel.GetStringHeight and statusLabel:GetStringHeight()) or 0) or 0)
                    )
                end
                statusLabel:SetText(originalText)

                local function setMatchStatusTone(variantKey, pulse)
                    if variantKey == "season01_exact" or variantKey == "season01_custom_order" then
                        if pulse then
                            statusLabel:SetTextColor(1.00, 0.90, 0.62, 1.00)
                        else
                            statusLabel:SetTextColor(0.90, 0.78, 0.52, 0.98)
                        end
                    else
                        statusLabel:SetTextColor(0.66, 0.66, 0.66, 0.94)
                    end
                end

                statusLabel:ClearAllPoints()
                statusLabel:SetPoint(
                    "TOPLEFT",
                    scrollChild,
                    "TOPLEFT",
                    tableLeft,
                    y - presetRowH - spacingAB - presetHelperH - matchStatusGap - LOADOUT_ROW_SHIFT_Y
                )
                if statusLabel.SetWidth then
                    statusLabel:SetWidth(math.max(1, tableWidth))
                end
                if showMatchStatus then
                    local shouldPulse = (widgets._dockMatchStatusVisible ~= true) or (widgets._dockMatchStatusVariant ~= matchStatusVariant)
                    statusLabel:SetText(matchStatusText)
                    statusLabel:Show()
                    widgets._dockMatchStatusVisible = true
                    widgets._dockMatchStatusVariant = matchStatusVariant
                    if shouldPulse then
                        local pulseToken = (widgets._dockMatchStatusPulseToken or 0) + 1
                        widgets._dockMatchStatusPulseToken = pulseToken
                        setMatchStatusTone(matchStatusVariant, true)
                        if C_Timer and C_Timer.After then
                            local settleVariant = matchStatusVariant
                            C_Timer.After(0.22, function()
                                if not widgets or not widgets.dockCustomizationMatchStatus then
                                    return
                                end
                                if widgets._dockMatchStatusPulseToken ~= pulseToken then
                                    return
                                end
                                if not widgets.dockCustomizationMatchStatus:IsShown() then
                                    return
                                end
                                setMatchStatusTone(settleVariant, false)
                            end)
                        else
                            setMatchStatusTone(matchStatusVariant, false)
                        end
                    else
                        setMatchStatusTone(matchStatusVariant, false)
                    end
                else
                    statusLabel:SetText("")
                    statusLabel:Hide()
                    widgets._dockMatchStatusVisible = false
                    widgets._dockMatchStatusVariant = nil
                    widgets._dockMatchStatusPulseToken = (widgets._dockMatchStatusPulseToken or 0) + 1
                    setMatchStatusTone(nil, false)
                end
            end

            -- Reserve a fixed match-status lane so the table baseline never depends on label visibility.
            local matchStatusBlockH = matchStatusGap + matchStatusLaneH
            y = y - presetRowH - spacingAB - presetHelperH - matchStatusBlockH - spacingDHeader

            widgets.loadoutDivider:ClearAllPoints()
            setDockObjectVisible(widgets.loadoutDivider, false)
            widgets.loadoutDivider:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
            widgets.loadoutDivider:SetPoint("TOPRIGHT", scrollChild, "TOPRIGHT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
            widgets.loadoutDivider:SetHeight(FIXED_FOOTPRINTS.DIVIDER_H)

            y = y - TABLE_BLOCK_SHIFT_Y

            widgets.portalSlotsLabel:ClearAllPoints()
            setDockObjectVisible(widgets.portalSlotsLabel, false)
            widgets.portalSlotsLabel:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)

            local slotSpellW = PRESET_AND_TABLE.SLOT_SPELL_W
            local slotResultW = PRESET_AND_TABLE.SLOT_RESULT_W
            local slotEnableW = FIXED_FOOTPRINTS.ROW_ENABLE_HOLDER_W
            local slotEnableGap = PRESET_AND_TABLE.SLOT_ENABLE_GAP
            local slotDestW = math.max(PRESET_AND_TABLE.SLOT_DEST_MIN_W, math.floor(tableWidth * PRESET_AND_TABLE.SLOT_DEST_RATIO))
            local slotNameW = math.max(
                PRESET_AND_TABLE.SLOT_NAME_MIN_W,
                tableWidth - slotEnableW - slotEnableGap - slotDestW - slotSpellW - slotResultW - (PRESET_AND_TABLE.TABLE_COLUMN_GAP * 2)
            )

            local colEnableX = tableLeft
            local colDestX = colEnableX + slotEnableW + slotEnableGap
            local colNameX = colDestX + slotDestW + PRESET_AND_TABLE.TABLE_COLUMN_GAP
            local colSpellX = colNameX + slotNameW + PRESET_AND_TABLE.TABLE_COLUMN_GAP
            local colResultX = colSpellX + slotSpellW + PRESET_AND_TABLE.TABLE_COLUMN_GAP

            widgets.slotColStatus:ClearAllPoints()
            setDockObjectVisible(widgets.slotColStatus, false)
            widgets.slotColStatus:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
            widgets.slotColDestination:ClearAllPoints()
            setDockObjectVisible(widgets.slotColDestination, true)
            widgets.slotColDestination:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", colDestX + SLOT_HEADER_TEXT_X_SHIFT, y + DESTINATION_COLUMN_Y_SHIFT)
            widgets.slotColName:ClearAllPoints()
            setDockObjectVisible(widgets.slotColName, true)
            widgets.slotColName:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", colNameX + SLOT_HEADER_TEXT_X_SHIFT, y + NAME_SPELL_COLUMNS_Y_SHIFT)
            widgets.slotColSpellID:ClearAllPoints()
            setDockObjectVisible(widgets.slotColSpellID, true)
            widgets.slotColSpellID:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", colSpellX + SLOT_HEADER_TEXT_X_SHIFT, y + NAME_SPELL_COLUMNS_Y_SHIFT)
            widgets.slotColResult:ClearAllPoints()
            setDockObjectVisible(widgets.slotColResult, true)
            widgets.slotColResult:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", colResultX, y + RESULT_COLUMN_Y_SHIFT)
            y = y - PRESET_AND_TABLE.TABLE_HEADER_BOTTOM_GAP

            for i = 1, 10 do
                local row = slotRows[i]
                row.enabled:ClearAllPoints()
                row.enabled:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", colEnableX, y - PRESET_AND_TABLE.SLOT_ROW_TOP_NUDGE + SLOT_ENABLE_CHECKBOX_Y_SHIFT)
                row.status:ClearAllPoints()
                row.status:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", PAGE.OFFSCREEN_X, y + STATUS_TEXT_Y_SHIFT)
                row.destination:ClearAllPoints()
                row.destination:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", colDestX, y - PRESET_AND_TABLE.SLOT_ROW_TOP_NUDGE + DESTINATION_COLUMN_Y_SHIFT)
                row.destination:SetSize(slotDestW, FIXED_FOOTPRINTS.STANDARD_CONTROL_H)
                row.namePill:ClearAllPoints()
                row.namePill:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", colNameX, y - PRESET_AND_TABLE.SLOT_ROW_TOP_NUDGE + NAME_SPELL_COLUMNS_Y_SHIFT)
                row.namePill:SetSize(slotNameW, FIXED_FOOTPRINTS.STANDARD_CONTROL_H)
                row.spellIDPill:ClearAllPoints()
                row.spellIDPill:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", colSpellX, y - PRESET_AND_TABLE.SLOT_ROW_TOP_NUDGE + NAME_SPELL_COLUMNS_Y_SHIFT)
                row.spellIDPill:SetSize(slotSpellW, FIXED_FOOTPRINTS.STANDARD_CONTROL_H)
                row.result:ClearAllPoints()
                row.result:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", colResultX, y - PRESET_AND_TABLE.SLOT_RESULT_TOP_NUDGE + RESULT_COLUMN_Y_SHIFT)
                row.result:SetSize(slotResultW, slotResultW)
                y = y - PRESET_AND_TABLE.SLOT_ROW_STEP
            end

            local lowerBlockBaseY = y + LOWER_SECTIONS_BLOCK_OFFSET_Y
            widgets.lowerSectionsContainer:ClearAllPoints()
            widgets.lowerSectionsContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", 0, lowerBlockBaseY)
            widgets.lowerSectionsContainer:SetPoint("TOPRIGHT", scrollChild, "TOPRIGHT", 0, lowerBlockBaseY)
            widgets.lowerSectionsContainer:SetHeight(FIXED_FOOTPRINTS.LOWER_SECTIONS_SEED_H)

            local lowerParent = widgets.lowerSectionsContainer
            local lowerY = 0
            local tableToDividerGap = LOWER_SECTIONS.TABLE_TO_DIVIDER_GAP
            local dividerToLayoutGap = LOWER_SECTIONS.DIVIDER_TO_LAYOUT_GAP

            widgets.hideDungeonDivider:ClearAllPoints()
            widgets.hideDungeonDivider:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", dividerLeftX, lowerY - tableToDividerGap)
            widgets.hideDungeonDivider:SetPoint("TOPRIGHT", lowerParent, "TOPRIGHT", -right, lowerY - tableToDividerGap)
            widgets.hideDungeonDivider:SetHeight(FIXED_FOOTPRINTS.DIVIDER_H)
            lowerY = lowerY - tableToDividerGap - dividerToLayoutGap

            local sectionLabelX = leftBase + LABEL_X
            local sectionControlX = leftBase + CONTROL_X
            local segmentedW = math.max(LOWER_SECTIONS.SEGMENTED_MIN_W, math.min(LOWER_SECTIONS.SEGMENTED_MAX_W, contentW - sectionControlX - right - LOWER_SECTIONS.CONTROL_RIGHT_PAD))
            local sliderControlW = math.max(LOWER_SECTIONS.SLIDER_CONTROL_MIN_W, math.min(LOWER_SECTIONS.SLIDER_CONTROL_MAX_W, segmentedW))
            local layoutStepperW = math.max(LOWER_SECTIONS.LAYOUT_STEPPER_MIN_W, math.min(LOWER_SECTIONS.LAYOUT_STEPPER_MAX_W, segmentedW))
            local fontSizeStepperW = math.max(LOWER_SECTIONS.FONT_SIZE_STEPPER_MIN_W, math.min(LOWER_SECTIONS.FONT_SIZE_STEPPER_MAX_W, segmentedW))
            local outlineRowW = math.max(LOWER_SECTIONS.OUTLINE_ROW_MIN_W, math.min(LOWER_SECTIONS.OUTLINE_ROW_MAX_W, segmentedW))
            local fontColorSwatchSize = FIXED_FOOTPRINTS.FONT_COLOR_SWATCH_SIZE

            local function placeSegment(spec, rowY, controlW, anchorFrame)
                local anchorParent = anchorFrame or scrollChild
                spec.label:ClearAllPoints()
                spec.label:SetPoint("TOPLEFT", anchorParent, "TOPLEFT", sectionLabelX, rowY)
                spec.control:ClearAllPoints()
                spec.control:SetPoint("TOPLEFT", anchorParent, "TOPLEFT", sectionControlX, rowY)
                if spec.Layout then
                    spec:Layout(controlW)
                end
                return rowY - LOWER_SECTIONS.ROW_STEP
            end

            local function moveSpecOffscreen(spec, anchorFrame)
                if not spec or not spec.control or not spec.label then
                    return
                end
                local anchorParent = anchorFrame or scrollChild
                setDockObjectVisible(spec.control, false)
                setDockObjectVisible(spec.label, false)
                if spec.valueText then
                    setDockObjectVisible(spec.valueText, false)
                end
                spec.control:ClearAllPoints()
                spec.control:SetPoint("TOPLEFT", anchorParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                spec.label:ClearAllPoints()
                spec.label:SetPoint("TOPLEFT", anchorParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
            end

            local function placeDropdownRow(spec, rowY, controlW, anchorFrame)
                placeControl(spec, sectionLabelX, sectionControlX, rowY, controlW, anchorFrame)
                return rowY - LOWER_SECTIONS.ROW_STEP
            end

            local function placeSliderRow(spec, rowY, controlW, anchorFrame)
                placeControl(spec, sectionLabelX, sectionControlX, rowY, controlW, anchorFrame)
                return rowY - LOWER_SECTIONS.ROW_STEP
            end

            local function placeStepperRow(spec, rowY, controlW, anchorFrame)
                placeControl(spec, sectionLabelX, sectionControlX, rowY, controlW, anchorFrame)
                return rowY - LOWER_SECTIONS.ROW_STEP
            end

            widgets.layoutSectionHeader:ClearAllPoints()
            widgets.layoutSectionHeader:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", leftBase + CHECK_X, lowerY)
            lowerY = lowerY - LOWER_SECTIONS.SECTION_HEADER_STEP

            lowerY = placeSegment(widgets.layoutModeSegment, lowerY, segmentedW, lowerParent)
            local currentLayoutMode = getDockSimpleLayoutModeForSettings((PortalAuthority and PortalAuthority.defaults) or {})
            local showWrap = (currentLayoutMode == "GRID")
            if showWrap then
                setDockObjectVisible(widgets.iconsPerRowGridOnlyHint, true)
                lowerY = placeStepperRow(widgets.iconsPerRow, lowerY, layoutStepperW, lowerParent)
            else
                setDockObjectVisible(widgets.iconsPerRowGridOnlyHint, false)
                if widgets.iconsPerRow and widgets.iconsPerRow.control and widgets.iconsPerRow.label then
                    setDockObjectVisible(widgets.iconsPerRow.control, false)
                    setDockObjectVisible(widgets.iconsPerRow.label, false)
                    widgets.iconsPerRow.control:ClearAllPoints()
                    widgets.iconsPerRow.control:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                    widgets.iconsPerRow.label:ClearAllPoints()
                    widgets.iconsPerRow.label:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                end
            end
            if widgets.iconsPerRowGridOnlyHint and widgets.iconsPerRow and widgets.iconsPerRow.control then
                widgets.iconsPerRowGridOnlyHint:ClearAllPoints()
                widgets.iconsPerRowGridOnlyHint:SetPoint("LEFT", widgets.iconsPerRow.control, "RIGHT", PAGE.CONTROL_PLACEMENT.VALUE_TEXT_GAP, 0)
            end
            lowerY = lowerY + (showWrap and LOWER_SECTIONS.WRAP_PRESENT_TIGHTEN or 0) -- tighten only when wrap row is present
            if widgets.layoutIconSize and widgets.layoutIconSize.Refresh then
                widgets.layoutIconSize.Refresh()
            end
            lowerY = placeSliderRow(widgets.layoutIconSize, lowerY, sliderControlW, lowerParent)
            widgets.layoutSpacingHint:ClearAllPoints()
            widgets.layoutSpacingHint:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", sectionControlX, lowerY + LOWER_SECTIONS.LAYOUT_HINT_TOP_NUDGE)
            lowerY = lowerY - LOWER_SECTIONS.LAYOUT_HINT_STEP

            lowerY = lowerY - LOWER_SECTIONS.SECTION_GAP_TIGHT
            widgets.labelsSectionHeader:ClearAllPoints()
            widgets.labelsSectionHeader:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", leftBase + CHECK_X, lowerY)
            lowerY = lowerY - LOWER_SECTIONS.SECTION_HEADER_STEP

            lowerY = placeSegment(widgets.labelMode, lowerY, segmentedW, lowerParent)
            if widgets.labelSide and widgets.labelSide.control and widgets.labelSide.control:IsShown() then
                lowerY = placeSegment(widgets.labelSide, lowerY, segmentedW, lowerParent)
                moveSpecOffscreen(widgets.labelSideInside, lowerParent)
            elseif widgets.labelSideInside and widgets.labelSideInside.control and widgets.labelSideInside.control:IsShown() then
                lowerY = placeSegment(widgets.labelSideInside, lowerY, segmentedW, lowerParent)
                moveSpecOffscreen(widgets.labelSide, lowerParent)
            else
                moveSpecOffscreen(widgets.labelSide, lowerParent)
                moveSpecOffscreen(widgets.labelSideInside, lowerParent)
            end

            lowerY = lowerY - LOWER_SECTIONS.SECTION_GAP_TIGHT
            widgets.styleSectionHeader:ClearAllPoints()
            widgets.styleSectionHeader:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", leftBase + CHECK_X, lowerY)
            lowerY = lowerY - LOWER_SECTIONS.SECTION_HEADER_STEP

            local labelsEnabled = (getDockLabelModeForSettings((PortalAuthority and PortalAuthority.defaults) or {}) ~= "OFF")
            setLabelStyleRowsVisible(labelsEnabled)

            if labelsEnabled then
                local fontRowY = lowerY
                local fontToSizeGap = LOWER_SECTIONS.FONT_TO_SIZE_GAP
                local sizeToSwatchGap = LOWER_SECTIONS.SIZE_TO_SWATCH_GAP
                local availableForControls = math.max(LOWER_SECTIONS.FONT_ROW_CONTROL_MIN_W, contentW - sectionControlX - right - LOWER_SECTIONS.CONTROL_RIGHT_PAD)
                local reservedForInline = fontSizeStepperW + fontToSizeGap + sizeToSwatchGap + fontColorSwatchSize
                local fontPickerW = math.max(LOWER_SECTIONS.FONT_PICKER_MIN_W, availableForControls - reservedForInline)

                placeControl(widgets.font, sectionLabelX, sectionControlX, fontRowY, fontPickerW, lowerParent)
                local fontRowAnchor = widgets.font.control

                widgets.fontSize.label:ClearAllPoints()
                setDockObjectVisible(widgets.fontSize.label, false)
                widgets.fontSize.label:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                widgets.fontSize.control:ClearAllPoints()
                setDockObjectVisible(widgets.fontSize.control, true)
                widgets.fontSize.control:SetPoint("LEFT", fontRowAnchor, "RIGHT", fontToSizeGap, 0)
                if widgets.fontSize.SetWidth then
                    widgets.fontSize:SetWidth(fontSizeStepperW)
                else
                    widgets.fontSize.control:SetWidth(fontSizeStepperW)
                end

                local sizeAnchor = widgets.fontSize.control

                widgets.color.inlineLabel:ClearAllPoints()
                setDockObjectVisible(widgets.color.inlineLabel, false)
                widgets.color.inlineLabel:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                widgets.color.swatch:ClearAllPoints()
                setDockObjectVisible(widgets.color.swatch, true)
                widgets.color.swatch:SetPoint("LEFT", sizeAnchor, "RIGHT", sizeToSwatchGap, 0)
                widgets.color.swatch:SetSize(fontColorSwatchSize, fontColorSwatchSize)

                lowerY = lowerY - LOWER_SECTIONS.FONT_ROW_STEP
                lowerY = placeSegment(widgets.outlineToggle, lowerY, outlineRowW, lowerParent)
            else
                if widgets.font and widgets.font.control and widgets.font.label then
                    setDockObjectVisible(widgets.font.control, false)
                    setDockObjectVisible(widgets.font.label, false)
                    widgets.font.control:ClearAllPoints()
                    widgets.font.control:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                    widgets.font.label:ClearAllPoints()
                    widgets.font.label:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                end
                if widgets.fontSize and widgets.fontSize.control then
                    setDockObjectVisible(widgets.fontSize.control, false)
                    widgets.fontSize.control:ClearAllPoints()
                    widgets.fontSize.control:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                end
                if widgets.color and widgets.color.swatch then
                    setDockObjectVisible(widgets.color.swatch, false)
                    widgets.color.swatch:ClearAllPoints()
                    widgets.color.swatch:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                end
                if widgets.outlineToggle and widgets.outlineToggle.control and widgets.outlineToggle.label then
                    setDockObjectVisible(widgets.outlineToggle.control, false)
                    setDockObjectVisible(widgets.outlineToggle.label, false)
                    widgets.outlineToggle.control:ClearAllPoints()
                    widgets.outlineToggle.control:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                    widgets.outlineToggle.label:ClearAllPoints()
                    widgets.outlineToggle.label:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                end
            end

            lowerY = placeSegment(widgets.hoverGlowSegment, lowerY, outlineRowW, lowerParent)
            lowerY = lowerY - LOWER_SECTIONS.SECTION_GAP_LOOSE
            widgets.visibilityDivider:ClearAllPoints()
            widgets.visibilityDivider:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", dividerLeftX, lowerY - LOWER_SECTIONS.VISIBILITY_DIVIDER_TOP_GAP)
            widgets.visibilityDivider:SetPoint("TOPRIGHT", lowerParent, "TOPRIGHT", -right, lowerY - LOWER_SECTIONS.VISIBILITY_DIVIDER_TOP_GAP)
            widgets.visibilityDivider:SetHeight(FIXED_FOOTPRINTS.DIVIDER_H)
            lowerY = lowerY - LOWER_SECTIONS.VISIBILITY_DIVIDER_STEP
            lowerY = lowerY - VISIBILITY_BLOCK_SHIFT_Y

            widgets.enableLabel:ClearAllPoints()
            widgets.enableLabel:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", leftBase + CHECK_X, lowerY)
            lowerY = lowerY - LOWER_SECTIONS.VISIBILITY_HEADER_STEP

            local visibilityToggleW = outlineRowW
            local visibilityRows = {
                widgets.hideCombat,
                widgets.hideCity,
                widgets.hideDungeon,
                widgets.gizmoMode,
            }
            for _, spec in ipairs(visibilityRows) do
                placeControl(spec, sectionLabelX, sectionControlX, lowerY, visibilityToggleW, lowerParent)
                if spec and spec.label then
                    spec.label:ClearAllPoints()
                    spec.label:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", sectionLabelX, lowerY - VISIBILITY_LABELS_SHIFT_Y)
                end
                lowerY = lowerY - LOWER_SECTIONS.ROW_STEP
            end
            lowerY = lowerY + math.max(0, LOWER_SECTIONS.ROW_STEP - FIXED_FOOTPRINTS.STANDARD_CONTROL_H)
            if widgets.hideNames and widgets.hideNames.control and widgets.hideNames.label then
                setDockObjectVisible(widgets.hideNames.control, false)
                setDockObjectVisible(widgets.hideNames.label, false)
                widgets.hideNames.control:ClearAllPoints()
                widgets.hideNames.control:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
                widgets.hideNames.label:ClearAllPoints()
                widgets.hideNames.label:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
            end
            widgets.visibilityLabelSpacer:ClearAllPoints()
            setDockObjectVisible(widgets.visibilityLabelSpacer, false)
            widgets.visibilityLabelSpacer:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
            widgets.visibilitySpacer:ClearAllPoints()
            setDockObjectVisible(widgets.visibilitySpacer, false)
            widgets.visibilitySpacer:SetPoint("TOPLEFT", lowerParent, "TOPLEFT", PAGE.OFFSCREEN_X, PAGE.OFFSCREEN_Y)
            local lowerSectionObjects = {
                widgets.layoutSectionHeader,
                widgets.layoutModeSegment and widgets.layoutModeSegment.control or nil,
                widgets.iconsPerRow and widgets.iconsPerRow.control or nil,
                widgets.iconsPerRowGridOnlyHint,
                widgets.layoutIconSize and widgets.layoutIconSize.control or nil,
                widgets.layoutSpacingHint,
                widgets.labelsSectionHeader,
                widgets.labelMode and widgets.labelMode.control or nil,
                widgets.labelSide and widgets.labelSide.control or nil,
                widgets.labelSideInside and widgets.labelSideInside.control or nil,
                widgets.styleSectionHeader,
                widgets.font and widgets.font.control or nil,
                widgets.fontSize and widgets.fontSize.control or nil,
                widgets.color and widgets.color.swatch or nil,
                widgets.outlineToggle and widgets.outlineToggle.control or nil,
                widgets.hoverGlowSegment and widgets.hoverGlowSegment.control or nil,
                widgets.visibilityDivider,
                widgets.enableLabel,
                widgets.hideCombat and widgets.hideCombat.control or nil,
                widgets.hideCombat and widgets.hideCombat.label or nil,
                widgets.hideCity and widgets.hideCity.control or nil,
                widgets.hideCity and widgets.hideCity.label or nil,
                widgets.hideDungeon and widgets.hideDungeon.control or nil,
                widgets.hideDungeon and widgets.hideDungeon.label or nil,
                widgets.gizmoMode and widgets.gizmoMode.control or nil,
                widgets.gizmoMode and widgets.gizmoMode.label or nil,
            }
            local lowerSectionExtent = measureSettingsVisibleContentExtent(lowerParent, lowerSectionObjects)
            local explicitLowerSectionH = math.max(FIXED_FOOTPRINTS.LOWER_SECTIONS_SEED_H, math.ceil(-lowerY))
            local measuredLowerSectionH = lowerSectionExtent and math.ceil(lowerSectionExtent) or nil
            local lowerSectionH = math.max(explicitLowerSectionH, measuredLowerSectionH or 0)
            widgets.lowerSectionsContainer:SetHeight(lowerSectionH)

            y = lowerBlockBaseY - lowerSectionH

            local panelExtentObjects = {
                widgets.header,
                widgets.masterRowContainer,
                widgets.lockRowContainer,
                widgets.lockStateHelper,
                widgets.lockDockDivider,
                widgets.loadoutPresetSegment and widgets.loadoutPresetSegment.control or nil,
                widgets.dockCustomizationHelper,
                widgets.dockCustomizationMatchStatus,
                widgets.slotColDestination,
                widgets.slotColName,
                widgets.slotColSpellID,
                widgets.slotColResult,
                slotRows[10] and slotRows[10].enabled or nil,
                slotRows[10] and slotRows[10].destination or nil,
                slotRows[10] and slotRows[10].namePill or nil,
                slotRows[10] and slotRows[10].spellIDPill or nil,
                slotRows[10] and slotRows[10].result or nil,
                widgets.lowerSectionsContainer,
            }
            local panelMeasuredExtent = measureSettingsVisibleContentExtent(scrollChild, panelExtentObjects)
            local explicitPanelExtent = math.max(0, -y)
            local measuredPanelExtent = (panelMeasuredExtent and math.ceil(panelMeasuredExtent)) or nil
            local used = math.max(explicitPanelExtent, measuredPanelExtent or 0) + PAGE.BOTTOM_PAD
            local contentHeight = math.max(scrollFrame:GetHeight(), used)
            panelFrame._dockScrollLayoutPassToken = (tonumber(panelFrame._dockScrollLayoutPassToken) or 0) + 1
            panelFrame._dockResolvedNativeScrollPassToken = nil
            panelFrame._dockResolvedNativeScrollMax = nil
            panelFrame._dockPendingPostRelayoutSyncPassToken = nil
            scrollChild:SetHeight(contentHeight)
            updateScrollBehavior(scrollFrame, scrollChild)
            ensureDockScrollInteractionBindings()
            self._dockExpectedScrollMax = math.max(0, contentHeight - (scrollFrame:GetHeight() or 0))
            self._dockObservedScrollMax = getDockObservedScrollMax()
            applyDockScrollState(nil, {
                allowFallback = false,
                allowPostRelayoutSync = true,
            })
        end

        self._refresh = function()
            if ensureDatabase then
                ensureDatabase()
            end
            refreshDockXYDisplay()
            relayout()
            applyDockModuleEnabledState()
            if applyDockGizmoVisibilityOverrideState then
                applyDockGizmoVisibilityOverrideState()
            end
            refreshSettingsWindowHeaderAccessoryIfHosted(self)
        end

        PortalAuthority.onDockPositionChanged = function(x, y)
            if widgets.x and widgets.x.SetValue then
                widgets.x:SetValue(x)
            end
            if widgets.y and widgets.y.SetValue then
                widgets.y:SetValue(y)
            end
        end
        PortalAuthority.lockTipText = nil

        self._refreshDockXYDisplay = refreshDockXYDisplay
        self._destinationPicker = widgets.destinationPicker
        self._fontPicker = widgets.font and widgets.font.picker or nil
        self._renamePopover = widgets.renamePopover
        self._spellIDPopover = widgets.spellIDPopover
        self._paCloseFloatingControlsOnScroll = function(panel)
            if panel and panel._renamePopover and panel._renamePopover.IsShown and panel._renamePopover:IsShown() and panel._renamePopover.Close then
                panel._renamePopover:Close(false)
            end
            if panel and panel._spellIDPopover and panel._spellIDPopover.IsShown and panel._spellIDPopover:IsShown() and panel._spellIDPopover.Close then
                panel._spellIDPopover:Close(false)
            end
        end
        self._layout = relayout
        self._forceDockFontUiState = forceDockFontUiState
        self._forceDockFontSizeUiState = forceDockFontSizeUiState
        self._forceStyleToggleUiState = forceStyleToggleUiState
        self._forceDockIconSizeVisual = function()
            if not widgets.layoutIconSize then
                return
            end
            local dbValue = tonumber(PortalAuthorityDB and PortalAuthorityDB.dockIconSize)
            local uiValue = tonumber(PortalAuthorityDB and PortalAuthorityDB.dockIconSizeUI)
            if uiValue == nil and PortalAuthority and PortalAuthority.ApplyDockLayoutSettings and (not InCombatLockdown or not InCombatLockdown()) then
                pcall(function()
                    PortalAuthority:ApplyDockLayoutSettings(false)
                end)
                uiValue = tonumber(PortalAuthorityDB and PortalAuthorityDB.dockIconSizeUI)
            end
            local defaultValue = tonumber(PortalAuthority and PortalAuthority.defaults and PortalAuthority.defaults.dockIconSize) or 36
            local n = math.floor((uiValue or dbValue or defaultValue) + 0.5)
            if n < 16 then n = 16 end
            if n > 72 then n = 72 end
            if PortalAuthorityDB then
                PortalAuthorityDB.dockIconSizeUI = n
            end
            local slider = widgets.layoutIconSize.slider
            if slider then
                slider:SetValue(n)
            end
            if widgets.layoutIconSize.valueEdit then
                widgets.layoutIconSize.valueEdit:SetText(tostring(n))
                widgets.layoutIconSize.valueEdit:Hide()
            end
            if widgets.layoutIconSize.valueText then
                widgets.layoutIconSize.valueText:SetText(tostring(n))
                widgets.layoutIconSize.valueText:Show()
            end
        end

        registerRefreshCallback(function()
            if self._refresh then
                self._refresh()
            end
        end, self)
        scrollFrame:SetScript("OnSizeChanged", function()
            local useHostedFirstOpen = isPanelUsingCustomSettingsWindowHost(self)
            if useHostedFirstOpen and handleSettingsFirstOpenSizeReady(self, "size_changed") then
                return
            end
            if useHostedFirstOpen and shouldSuppressSettingsFirstOpenExternalRefresh(self) then
                return
            end
            relayout()
        end)
        self._settingsFirstOpenKey = "dock"
        self._settingsFirstOpenSizeTarget = scrollFrame
        self._settingsFirstOpenRender = function(panel)
            local selectionToken = tonumber(panel and panel._paFirstOpenSelectionToken) or 0
            if selectionToken ~= (tonumber(panel and panel._dockFirstOpenRenderToken) or 0) then
                panel._dockFirstOpenRenderToken = selectionToken
                panel._dockFirstOpenRenderPasses = 0
            end
            panel._dockFirstOpenRenderPasses = (tonumber(panel._dockFirstOpenRenderPasses) or 0) + 1
            renderDockPanel(panel)
        end
        self._settingsFirstOpenIsReady = function(panel)
            local viewportHeight = tonumber(scrollFrame and scrollFrame:GetHeight()) or 0
            local contentHeight = tonumber(scrollChild and scrollChild:GetHeight()) or 0
            local expectedMax = math.max(0, contentHeight - viewportHeight)
            local observedMax = math.max(
                tonumber(panel and panel._dockObservedScrollMax) or 0,
                getDockObservedScrollMax()
            )
            return isPanelUsingCustomSettingsWindowHost(panel)
                and panelHasSizedViewport(panel and panel._settingsFirstOpenSizeTarget or nil)
                and panel ~= nil
                and panel._initialized == true
                and type(panel._layout) == "function"
                and type(panel._refresh) == "function"
                and (tonumber(panel and panel._dockFirstOpenRenderPasses) or 0) >= 2
                and contentHeight >= math.max(viewportHeight, 1)
                and observedMax >= (expectedMax - 1)
        end
        settingsSearchRuntime.endDescriptorCapture(self)
        self._initialized = true
    end

    ensureDockPanelAnchored = function(self)
        local p = self:GetParent()
        if not p then
            return false
        end
        if self._paAnchorParent ~= p or not self._paAnchored then
            self:ClearAllPoints()
            self:SetAllPoints(p)
            self._paAnchorParent = p
        end
        self._paAnchored = true
        return true
    end

    renderDockPanel = function(self)
        ensureDockPanelAnchored(self)
        if self._refresh then
            self._refresh()
        end
    end

    panel:SetScript("OnShow", function(self)
        debugSettingsLog("OnShow:", self.name)
        if ensureDatabase then
            ensureDatabase()
        end
        self:EnsureBuilt()
        local useHostedFirstOpen = isPanelUsingCustomSettingsWindowHost(self)
        if useHostedFirstOpen and self._paFirstOpenState == "pending" then
            resetSettingsFirstOpenPanelState(self)
        end
        if useHostedFirstOpen and handleSettingsFirstOpenPanelShow(self) then
            return
        end
        withPanelHydration(self, function()
            renderDockPanel(self)
        end)
    end)
    panel:SetScript("OnHide", function(self)
        self._dockPendingPostRelayoutSyncPassToken = nil
        if isPanelUsingCustomSettingsWindowHost(self) or isSettingsFirstOpenSettlePending(self) then
            handleSettingsFirstOpenPanelHide(self)
        end
        if self._destinationPicker and self._destinationPicker.Close then
            self._destinationPicker:Close()
        end
        if self._fontPicker and self._fontPicker.Close then
            self._fontPicker:Close()
        end
        if self._renamePopover and self._renamePopover.Close then
            self._renamePopover:Close(false)
        end
        if self._spellIDPopover and self._spellIDPopover.Close then
            self._spellIDPopover:Close(false)
        end
    end)

    return panel
end


local function createTimersPanel()
    local panel = CreateFrame("Frame")
    panel.name = "Timers"
    panel._paSearchSectionKey = "timers"
    panel._paSearchSectionName = panel.name

    panel.EnsureBuilt = function(self)
        if self._initialized then return end
        self._initialized = true
        resetSettingsFirstOpenPanelState(self)
        ensureDatabase()
        settingsSearchRuntime.beginDescriptorCapture(self)

        local function getModulesApi()
            return PortalAuthority and PortalAuthority.Modules or nil
        end
        local stack = nil
        local widgets = {}
        local pickerSpecs = {}
        self._timersPickerSpecs = pickerSpecs
        local function isModuleAvailable(moduleId)
            return true, nil
        end
        local function getStack()
            local api = getModulesApi()
            if api and api.registry then
                stack = api.registry.timers
            end
            return stack
        end
        local function ensureTimersStorage()
            PortalAuthorityDB = PortalAuthorityDB or {}
            PortalAuthorityDB.modules = PortalAuthorityDB.modules or {}
            PortalAuthorityDB.modules.timers = PortalAuthorityDB.modules.timers or {}
            return PortalAuthorityDB.modules.timers
        end
        local fallbackTimersDb = ensureTimersStorage()
        local function getLegacyTimersDb()
            if PortalAuthorityDB and PortalAuthorityDB.modules and type(PortalAuthorityDB.modules.modules2Stack) == "table" then
                return PortalAuthorityDB.modules.modules2Stack
            end
            return nil
        end
        local function getPersistedTimersDb()
            if PortalAuthorityDB and PortalAuthorityDB.modules and PortalAuthorityDB.modules.timers then
                return PortalAuthorityDB.modules.timers
            end
            return fallbackTimersDb
        end
        local function readTimerSetting(db, key, defaultValue)
            if db and db[key] ~= nil then
                return db[key]
            end
            local persisted = getPersistedTimersDb()
            if persisted and persisted[key] ~= nil then
                return persisted[key]
            end
            local legacy = getLegacyTimersDb()
            if legacy and legacy[key] ~= nil then
                return legacy[key]
            end
            return defaultValue
        end
        local function writeTimerSetting(db, key, value)
            if db then
                db[key] = value
            end
            local persisted = getPersistedTimersDb()
            if persisted then
                persisted[key] = value
            end
        end
        local function getTimersLockedState()
            local activeStack = getStack()
            if activeStack and activeStack.GetDB then
                local db = activeStack:GetDB()
                if db and db.locked ~= nil then
                    return db.locked and true or false
                end
            end

            local persisted = getPersistedTimersDb()
            if persisted and persisted.locked ~= nil then
                return persisted.locked and true or false
            end

            if widgets and widgets.unlock and widgets.unlock.GetChecked then
                return widgets.unlock:GetChecked() and true or false
            end

            return true
        end
        local function getTimersDBSnapshot()
            local activeStack = getStack()
            local db = nil
            if activeStack and activeStack.GetDB then
                db = activeStack:GetDB()
            else
                db = fallbackTimersDb
            end
            return activeStack, db
        end
        local function getTimersDisplayPosition(activeStack, db)
            local fallbackX = math.floor(tonumber(readTimerSetting(db, "x", 0)) or 0)
            local fallbackY = math.floor(tonumber(readTimerSetting(db, "y", 0)) or 0)
            if not activeStack or not activeStack.frame or not activeStack.frame.GetCenter or not UIParent or not UIParent.GetCenter then
                return fallbackX, fallbackY
            end
            local cx, cy = activeStack.frame:GetCenter()
            local ux, uy = UIParent:GetCenter()
            if not cx or not cy or not ux or not uy then
                return fallbackX, fallbackY
            end
            return math.floor((cx - ux) + 0.5), math.floor((cy - uy) + 0.5)
        end

        local scrollFrame, scrollChild = createScrollableChild(self)
        if not scrollFrame or not scrollChild then
            settingsSearchRuntime.endDescriptorCapture(self)
            return
        end
        self._sizingFrame = scrollFrame
        self._kuScrollFrame = scrollFrame
        self._kuScrollChild = scrollChild

        local header = createStyledFontString(scrollChild, "ARTWORK", "GameFontNormalLarge", 14)
        header:SetText("|cffffd100Timers|r")
        header:SetJustifyH("LEFT")
        local headerDescriptor = createSettingsSectionDescriptor(scrollChild, "Configure your M+ timers.")

        local TIMERS_LAYOUT = {
            MIN_CONTENT_W = 560,
            TOP_PAD = 20,
            BOTTOM_PAD = 20,
            HEADER_LEFT = 16,
            CONTENT_LEFT = 20,
            CONTENT_RIGHT = 20,
            HIDDEN_X = -5000,
            HIDDEN_Y = -5000,
            TOGGLE_COL_X = 220,
            APPEAR_CONTROL_SHIFT_X = -12,
            LABEL_TO_CONTROL_GAP = 12,
            LOCK_TOGGLE_TO_RESET_GAP = 12,
            LOCK_TOGGLE_PREF_W = 140,
            LOCK_TOGGLE_MIN_W = 96,
            MODULE_TOGGLE_PREF_W = 150,
            MIN_PICKER_W = 140,
            MIN_SEGMENT_W = 140,
            MAIN_CONTROL_TARGET_W = 202,
            MAIN_CONTROL_MIN_W = 196,
            PICKER_DEFAULT_W = 180,
            ASPECT_PICKER_W = 186,
            PICKER_CONTROL_H = 22,
            LOCK_ROW_SEED_H = 22,
            SLIDER_CONTROL_W = 260,
            SLIDER_VALUE_BUTTON_W = 44,
            SLIDER_VALUE_BUTTON_H = 16,
            SLIDER_VALUE_GAP = 8,
            SLIDER_TRACK_H = 2,
            SLIDER_THUMB_HIT_SIZE = 16,
            SLIDER_THUMB_SIZE = 8,
            SLIDER_GLOW_SIZE = 14,
            ICON_EDGE_SEGMENT_MIN_W = 82,
            RESET_BUTTON_SEED_W = 104,
            RESET_BUTTON_PREF_W = 102,
            RESET_BUTTON_MIN_W = 102,
            BATCH_BUTTON_COMPRESS_MIN_W = 80,
            ACTION_BUTTON_TEXT_PAD_X = 22,
            SEGMENT_BUTTON_TEXT_PAD_X = 20,
            MEASURE_SINGLE_LINE_W = 4096,
            HEADER_FLOOR = 16,
            SECTION_HEADER_FLOOR = 12,
            LABEL_FLOOR = 12,
            HELPER_FLOOR = 10,
            MINI_LABEL_FLOOR = 10,
            CONTROL_FLOOR = 22,
            LOCK_ROW_FLOOR = 22,
            ROW_FLOOR = 36,
            OFFSET_ROW_FLOOR = 56,
            HEADER_BOTTOM_GAP = 14,
            LOCK_HELPER_GAP_RATIO = 0.625,
            LOCK_DIVIDER_GAP_RATIO = 1.25,
            LOCK_DIVIDER_OFFSET_RATIO = 0.5,
            SECTION_HEADER_BOTTOM_GAP = 4,
            MODULE_CARD_TO_ROWS_GAP = 12,
            MODULE_CHILD_INDENT = 16,
            MODULE_CHILD_ROW_GAP = 4,
            MODULE_ROW_TO_HELPER_GAP = 4,
            MODULE_ROW_TO_EXPLAIN_GAP = 4,
            MODULE_HELPER_TO_EXPLAIN_GAP = 4,
            MODULE_EXPLAIN_LINE_GAP = 5,
            MODULE_EXPLAIN_BLOCK_GAP = 12,
            SECTION_TO_NEXT_DIVIDER_GAP = 24,
            CARD_PADDING = 8,
            CARD_LABEL_TO_BUTTONS_GAP = 8,
            CARD_BUTTONS_TO_STATUS_GAP = 4,
            BATCH_BUTTON_GAP = 8,
            BATCH_BUTTON_H = 22,
            BATCH_BUTTON_PREF_W = 156,
            BATCH_BUTTON_MIN_W = 120,
            BATCH_SCOPE_GAP = 6,
            FONT_SIZE_W = 52,
            FONT_SIZE_GAP = 8,
            FONT_STACK_GAP = 4,
            AXIS_LABEL_MIN_W = 10,
            AXIS_TO_CONTROL_GAP = 6,
            AXIS_LINE_GAP = 8,
        }

        widgets.unlock = CreateFrame("CheckButton", nil, scrollChild, "UICheckButtonTemplate")
        widgets.unlock.text:SetText("Lock Position")
        applyGlobalFontToObject(widgets.unlock.text, 12)
        local unlockLabelNormalColor = { widgets.unlock.text:GetTextColor() }
        local function updateUnlockLabelColor(isLocked)
            if isLocked then
                widgets.unlock.text:SetTextColor(unlockLabelNormalColor[1], unlockLabelNormalColor[2], unlockLabelNormalColor[3], unlockLabelNormalColor[4])
            else
                widgets.unlock.text:SetTextColor(1, 0.2, 0.2)
            end
        end
        widgets.unlock:SetScript("OnClick", function(btn)
            local isLocked = not not btn:GetChecked()
            local desiredUnlocked = not isLocked
            local activeStack = getStack()
            local actualUnlocked = not getTimersLockedState()
            if InCombatLockdown and InCombatLockdown() and actualUnlocked ~= nil and desiredUnlocked ~= not not actualUnlocked then
                local actualLocked = not not (not actualUnlocked)
                btn:SetChecked(actualLocked)
                updateUnlockLabelColor(actualLocked)
                return
            end

            -- Force immediate visual response for lock/unlock so frame + drag handle
            -- appear without waiting for external events/tickers.
            activeStack = getStack()
            if activeStack then
                if desiredUnlocked and activeStack.Initialize and not (activeStack.frame or activeStack.mainFrame) then
                    activeStack:Initialize()
                end
                if activeStack.SetUnlocked then
                    activeStack:SetUnlocked(desiredUnlocked)
                end
                if activeStack.ApplyPosition then
                    activeStack:ApplyPosition()
                end
                if activeStack.EvaluateVisibility and (activeStack.frame or activeStack.mainFrame) then
                    activeStack:EvaluateVisibility("options-lock-toggle")
                end
                if desiredUnlocked and activeStack.Tick then
                    activeStack:Tick()
                end
            end

            local authoritativeLocked = getTimersLockedState()
            btn:SetChecked(authoritativeLocked)
            updateUnlockLabelColor(authoritativeLocked)
            if self._refresh then self._refresh() end
        end)

        local applyStackSettings

        local function mkCheck(parent, text, key)
            local c = CreateFrame("CheckButton", nil, parent, "UICheckButtonTemplate")
            c.text:SetText(text)
            applyGlobalFontToObject(c.text, 12)
            c.text:SetTextColor(1, 0.82, 0, 1)
            c:SetScript("OnClick", function(btn)
                local activeStack = getStack()
                if not activeStack then return end
                activeStack:GetDB()[key] = not not btn:GetChecked()
                activeStack:ApplySettings()
                local api = getModulesApi()
                if api and api.timersTestMode then
                    if activeStack.EvaluateVisibility then
                        activeStack:EvaluateVisibility()
                    end
                    if activeStack.Tick then
                        activeStack:Tick()
                    end
                end
                if self._refresh then self._refresh() end
            end)
            return c
        end

        local function mkPickerButton(parent, opts)
            opts = type(opts) == "table" and opts or {}
            local optionsProvider = type(opts.optionsProvider) == "function" and opts.optionsProvider or function() return {} end
            local getter = type(opts.getter) == "function" and opts.getter or function() return "" end
            local setter = type(opts.setter) == "function" and opts.setter or function() end
            local onApply = type(opts.onApply) == "function" and opts.onApply or nil
            local fallbackLabel = type(opts.fallbackLabel) == "function" and opts.fallbackLabel or nil

            local button = CreateFrame("Button", nil, parent, "BackdropTemplate")
            button:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
                insets = { left = 0, right = 0, top = 0, bottom = 0 },
            })
            button:SetBackdropColor(0.10, 0.11, 0.14, 0.95)
            button:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
            button:SetHeight(TIMERS_LAYOUT.PICKER_CONTROL_H)
            button:SetWidth(math.max(0, tonumber(opts.width) or TIMERS_LAYOUT.PICKER_DEFAULT_W))

            local text = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 11)
            text:SetPoint("LEFT", button, "LEFT", 8, 0)
            text:SetPoint("RIGHT", button, "RIGHT", -18, 0)
            text:SetJustifyH("LEFT")
            text:SetTextColor(0.92, 0.92, 0.92, 1)

            local caret = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 10)
            caret:SetPoint("RIGHT", button, "RIGHT", -7, 0)
            caret:SetText("v")
            caret:SetTextColor(0.76, 0.76, 0.78, 1)

            local spec = { kind = "picker_button", control = button, text = text, caret = caret }
            local picker = CreatePicker(UIParent, {}, function(value)
                local selectedValue = tostring(value or "")
                setter(selectedValue)
                if onApply then
                    onApply()
                end
                if spec.Refresh then
                    spec.Refresh()
                end
            end, {
                title = tostring(opts.title or "Select Option"),
                searchHint = tostring(opts.searchHint or "Search"),
                width = tonumber(opts.pickerWidth) or 420,
                height = tonumber(opts.pickerHeight) or 360,
                showSecondary = opts.showSecondary and true or false,
                useOptionFontPreview = opts.useOptionFontPreview and true or false,
                previewFontSize = tonumber(opts.previewFontSize) or 12,
                rowHeight = tonumber(opts.rowHeight) or 26,
                showClearButton = false,
                noSearch = opts.noSearch and true or false,
                hideTitle = opts.hideTitle and true or false,
                hideScrollBar = opts.hideScrollBar and true or false,
            })
            spec.picker = picker

            local function applyVisual(hovered)
                if hovered then
                    button:SetBackdropColor(0.16, 0.17, 0.20, 0.95)
                    button:SetBackdropBorderColor(0.30, 0.33, 0.38, 1.0)
                    caret:SetTextColor(0.88, 0.88, 0.90, 1)
                else
                    button:SetBackdropColor(0.10, 0.11, 0.14, 0.95)
                    button:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
                    caret:SetTextColor(0.76, 0.76, 0.78, 1)
                end
            end

            button:SetScript("OnEnter", function()
                applyVisual(true)
            end)
            button:SetScript("OnLeave", function()
                applyVisual(false)
            end)

            local function buildPickerOptions()
                local built = {}
                for _, option in ipairs(optionsProvider() or {}) do
                    local value = tostring(option.value or "")
                    built[#built + 1] = {
                        value = value,
                        label = tostring(option.label or value),
                        buttonLabel = tostring(option.buttonLabel or option.label or value),
                        secondary = tostring(option.secondary or ""),
                        previewFontPath = option.previewFontPath,
                        aliases = option.aliases,
                    }
                end
                if #built == 0 then
                    built[1] = { value = "", label = "None", buttonLabel = "None", secondary = "" }
                end
                return built
            end

            local function resolveSelection(rawValue, options)
                local selected = tostring(rawValue or "")
                local selectedLabel = nil
                for _, option in ipairs(options or {}) do
                    if tostring(option.value or "") == selected then
                        selected = tostring(option.value or "")
                        selectedLabel = tostring(option.buttonLabel or option.label or selected)
                        break
                    end
                end
                if not selectedLabel then
                    if fallbackLabel then
                        selectedLabel = tostring(fallbackLabel(selected) or "")
                    end
                    if selectedLabel == "" then
                        local first = options and options[1] or nil
                        if first then
                            selected = tostring(first.value or "")
                            selectedLabel = tostring(first.buttonLabel or first.label or selected)
                            setter(selected)
                        else
                            selectedLabel = "None"
                        end
                    end
                end
                return selected, selectedLabel
            end

            spec.SetWidth = function(_, newWidth)
                button:SetWidth(math.max(0, math.floor(tonumber(newWidth) or opts.width or TIMERS_LAYOUT.PICKER_DEFAULT_W)))
            end
            spec.ClosePicker = function()
                if picker and picker.IsShown and picker:IsShown() then
                    picker:Close()
                end
            end

            spec.Refresh = function()
                local options = buildPickerOptions()
                picker:SetOptions(options)
                local selectedValue, selectedLabel = resolveSelection(getter(), options)
                picker:SetSelectedValue(selectedValue)
                text:SetText(selectedLabel ~= "" and selectedLabel or "None")
            end

            button:SetScript("OnClick", function()
                if picker and picker.IsShown and picker:IsShown() then
                    picker:Close()
                    return
                end
                spec.Refresh()
                picker:Open(button)
            end)

            pickerSpecs[#pickerSpecs + 1] = spec
            spec.Refresh()
            return spec
        end

        local function mkFontDropdown(parent, getter, setter)
            local function fontFallbackLabel(path)
                local value = trim(tostring(path or ""))
                if value == "" then
                    return "Global UI Font"
                end
                value = value:gsub("/", "\\")
                return value:match("([^\\]+)$") or value
            end
            return mkPickerButton(parent, {
                width = TIMERS_LAYOUT.PICKER_DEFAULT_W,
                title = "Select Font Face",
                searchHint = "Search fonts by name",
                pickerWidth = 420,
                pickerHeight = 380,
