                e._paTimersBg:SetVertexColor(0.10, 0.11, 0.14, 0.95)

                e._paTimersBorder = CreateFrame("Frame", nil, e, "BackdropTemplate")
                e._paTimersBorder:SetPoint("TOPLEFT", e, "TOPLEFT", -1, 1)
                e._paTimersBorder:SetPoint("BOTTOMRIGHT", e, "BOTTOMRIGHT", 1, -1)
                e._paTimersBorder:SetBackdrop({
                    edgeFile = "Interface\\Buttons\\WHITE8x8",
                    edgeSize = 1,
                })
                e._paTimersBorder:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
            end

            local function hideTemplateChrome()
                local left = e.Left
                local mid = e.Middle
                local right = e.Right
                if left then left:SetAlpha(0) end
                if mid then mid:SetAlpha(0) end
                if right then right:SetAlpha(0) end
            end

            local function applyEditVisual()
                hideTemplateChrome()
                if e:HasFocus() then
                    e._paTimersBg:SetVertexColor(0.12, 0.13, 0.17, 0.95)
                    e._paTimersBorder:SetBackdropBorderColor(0.30, 0.33, 0.38, 1.0)
                else
                    e._paTimersBg:SetVertexColor(0.10, 0.11, 0.14, 0.95)
                    e._paTimersBorder:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
                end
            end

            e:SetScript("OnShow", function()
                applyEditVisual()
            end)
            e:SetScript("OnEditFocusGained", function()
                applyEditVisual()
            end)
            e:SetScript("OnEditFocusLost", function(edit)
                applyEditVisual()
                if onApply then
                    onApply(edit)
                end
            end)
            e:SetScript("OnEnterPressed", function(edit)
                if onApply then
                    onApply(edit)
                end
                edit:ClearFocus()
            end)
            e:SetScript("OnEscapePressed", function(edit)
                edit:ClearFocus()
            end)
            return e
        end

