        local lustEnable = mkCheck(scrollChild, "Bloodlust Timer", "lustEnabled")
        local healerEnable = mkCheck(scrollChild, "Healer Status", "healerEnabled")
        local cooldownSweepEnable = mkCheck(scrollChild, "Cooldown Sweep", "cooldownSweepEnabled")
        local enableLabel = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlight", 12)
        enableLabel:SetText("Enable")
