        divider:SetColorTexture(1, 1, 1, 0.15)
        local dividerFont = scrollChild:CreateTexture(nil, "ARTWORK")
        dividerFont:SetColorTexture(1, 1, 1, 0.15)
        local TIMER_HELPER_R, TIMER_HELPER_G, TIMER_HELPER_B, TIMER_HELPER_A = 0.58, 0.58, 0.58, 0.92
        local function applyHelperTone(fs)
            if fs and fs.SetTextColor then
                fs:SetTextColor(TIMER_HELPER_R, TIMER_HELPER_G, TIMER_HELPER_B, TIMER_HELPER_A)
            end
        end
        local function setTimerSingleLineEllipsis(fs, fullText, maxWidth)
            if not fs then
                return
            end
            local text = tostring(fullText or "")
            fs:SetWordWrap(false)
            if fs.SetMaxLines then
                fs:SetMaxLines(1)
            end
            if maxWidth and maxWidth > 0 then
                fs:SetWidth(maxWidth)
            end
            fs:SetText(text)
            if not maxWidth or maxWidth <= 0 or not fs.GetStringWidth then
                return
            end
            if fs:GetStringWidth() <= maxWidth then
                return
            end
            local suffix = "..."
            local low, high = 0, #text
            local best = suffix
            while low <= high do
                local mid = math.floor((low + high) / 2)
                local candidate = text:sub(1, mid) .. suffix
                fs:SetText(candidate)
                if fs:GetStringWidth() <= maxWidth then
                    best = candidate
                    low = mid + 1
                else
                    high = mid - 1
                end
            end
            fs:SetText(best)
        end


        local function parkTimersControl(control)
            if not control then
                return
            end
            if control.Hide then
                control:Hide()
            end
            control:ClearAllPoints()
            control:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", TIMERS_LAYOUT.HIDDEN_X, TIMERS_LAYOUT.HIDDEN_Y)
        end

        local function showTimersControl(control)
            if control and control.Show then
                control:Show()
            end
        end

        local function rememberTimersText(fs, text)
            if not fs then
                return
            end
            if text == nil then
                text = (fs.GetText and fs:GetText()) or ""
            end
            fs._paTimersRawText = tostring(text or "")
        end

        local function setTimersText(fs, text)
            if not fs then
                return
            end
            local value = tostring(text or "")
            fs._paTimersRawText = value
            fs:SetText(value)
        end

        local function getTimersText(fs)
            if not fs then
                return ""
            end
            local raw = fs._paTimersRawText
            if raw == nil then
                raw = (fs.GetText and fs:GetText()) or ""
                fs._paTimersRawText = tostring(raw or "")
            end
            return tostring(raw or "")
        end

        local function isTimersTextActive(fs)
            return trim(getTimersText(fs)) ~= ""
        end

        local function applyTimersSingleLine(fs, width)
            if not fs then
                return
            end
            local clampedWidth = math.max(1, math.floor(tonumber(width) or 0))
            setTimerSingleLineEllipsis(fs, getTimersText(fs), clampedWidth)
        end

        local function measureTimersSingleLineHeight(fs, width, floorValue, isActive)
            if not fs or isActive == false then
                return 0
            end
            applyTimersSingleLine(fs, width)
            return math.max(
                math.floor(tonumber(floorValue) or 0),
                math.ceil(tonumber((fs.GetStringHeight and fs:GetStringHeight()) or 0) or 0)
            )
        end

        local function measureTimersSingleLineWidth(fs, floorValue, isActive)
            if not fs or isActive == false then
                return 0
            end
            local raw = getTimersText(fs)
            fs:SetWordWrap(false)
            if fs.SetMaxLines then
                fs:SetMaxLines(1)
            end
            fs:SetWidth(TIMERS_LAYOUT.MEASURE_SINGLE_LINE_W)
            fs:SetText(raw)
            return math.max(
                math.floor(tonumber(floorValue) or 0),
                math.ceil(tonumber((fs.GetStringWidth and fs:GetStringWidth()) or 0) or 0)
            )
        end

        local function computeTimersLockRhythm(labelHeight)
            local T = TIMERS_LAYOUT
            local measuredLabelH = math.max(1, tonumber(labelHeight) or 0)
            local helperGap = math.max(1, math.floor((measuredLabelH * T.LOCK_HELPER_GAP_RATIO) + 0.5))
            local dividerGap = math.max(1, math.floor((measuredLabelH * T.LOCK_DIVIDER_GAP_RATIO) + 0.5))
            local dividerOffset = math.max(1, math.floor((dividerGap * T.LOCK_DIVIDER_OFFSET_RATIO) + 0.5))
            return helperGap, dividerGap, dividerOffset
        end
        local function measureTimersWrappedTextHeight(fs, width, floorValue, isActive)
            if not fs or isActive == false then
                return 0
            end
            local clampedWidth = math.max(1, math.floor(tonumber(width) or 0))
            fs:SetWidth(clampedWidth)
            fs:SetText(getTimersText(fs))
            return math.max(
                math.floor(tonumber(floorValue) or 0),
                math.ceil(tonumber((fs.GetStringHeight and fs:GetStringHeight()) or 0) or 0)
            )
        end

        local function measureTimersControlHeight(control, floorValue, isActive)
            if not control or isActive == false then
                return 0
            end
            return math.max(
                math.floor(tonumber(floorValue) or 0),
                math.ceil(tonumber((control.GetHeight and control:GetHeight()) or 0) or 0)
            )
        end

        local function measureTimersButtonLabelWidth(button)
            if not button or not button.Text or not button.Text.GetStringWidth then
                return 0
            end
            return math.ceil(tonumber(button.Text:GetStringWidth() or 0) or 0)
        end

        local function computeTimersSegmentWidth(spec, preferredWidth, availableWidth, perButtonPad, minWidth)
            local widestText = 0
            if spec and spec.offBtn then
                widestText = math.max(widestText, measureTimersButtonLabelWidth(spec.offBtn))
            end
            if spec and spec.onBtn then
                widestText = math.max(widestText, measureTimersButtonLabelWidth(spec.onBtn))
            end
            widestText = math.max(widestText, 36)
            local pad = math.max(0, tonumber(perButtonPad) or 0)
            local desiredWidth = ((widestText + (pad * 2)) * 2) + 4
            local preferred = math.max(math.floor(tonumber(minWidth) or 0), math.floor(tonumber(preferredWidth) or desiredWidth))
            local maxWidth = math.max(math.floor(tonumber(minWidth) or 0), math.floor(tonumber(availableWidth) or 0))
            return math.max(math.floor(tonumber(minWidth) or 0), math.min(maxWidth, math.max(desiredWidth, preferred)))
        end

        local function computeTimersActionButtonWidth(button, preferredWidth, availableWidth, minWidth)
            local desiredWidth = measureTimersButtonLabelWidth(button) + (TIMERS_LAYOUT.ACTION_BUTTON_TEXT_PAD_X * 2)
            local preferred = math.max(math.floor(tonumber(minWidth) or 0), math.floor(tonumber(preferredWidth) or desiredWidth))
            local maxWidth = math.max(math.floor(tonumber(minWidth) or 0), math.floor(tonumber(availableWidth) or 0))
            return math.max(math.floor(tonumber(minWidth) or 0), math.min(maxWidth, math.max(desiredWidth, preferred)))
        end

        local function computeTimersGeometry(contentW)
            local T = TIMERS_LAYOUT
            local G = {}
            G.contentW = math.max(math.floor(tonumber(contentW) or 0), T.MIN_CONTENT_W)
            G.contentLeft = T.CONTENT_LEFT
            G.contentRight = G.contentW - T.CONTENT_RIGHT
            G.contentSpan = math.max(1, G.contentRight - G.contentLeft)
            G.labelColX = G.contentLeft
            G.toggleColX = T.TOGGLE_COL_X
            G.helperColX = G.labelColX
            G.settingsLabelX = G.labelColX
            G.settingsControlX = G.toggleColX
            G.appearanceControlX = G.settingsControlX + T.APPEAR_CONTROL_SHIFT_X
            return G
        end

        local function computeTimersLockRowGeometry(G, lockRowRef, resetButton)
            local T = TIMERS_LAYOUT
            local L = {}
            local labelWidth = measureTimersSingleLineWidth(lockRowRef and lockRowRef.label or nil, 0, lockRowRef and lockRowRef.label ~= nil)
            L.labelX = G.labelColX
            L.labelW = math.max(1, labelWidth)
            L.controlX = L.labelX + L.labelW + T.LABEL_TO_CONTROL_GAP
            L.resetH = T.CONTROL_FLOOR
            L.resetW = T.RESET_BUTTON_PREF_W
            local toggleAvailW = math.max(T.LOCK_TOGGLE_MIN_W, G.contentRight - L.controlX - T.LOCK_TOGGLE_TO_RESET_GAP - L.resetW)
            L.controlW = computeTimersSegmentWidth(lockRowRef, T.LOCK_TOGGLE_PREF_W, toggleAvailW, T.SEGMENT_BUTTON_TEXT_PAD_X, T.LOCK_TOGGLE_MIN_W)
            L.resetX = L.controlX + L.controlW + T.LOCK_TOGGLE_TO_RESET_GAP
            L.rowW = math.max(1, G.contentRight - G.labelColX)
            return L
        end

        local function computeTimersModuleGeometry(G, sampleRow)
            local T = TIMERS_LAYOUT
            local M = {}
            M.labelX = G.labelColX
            M.labelW = math.max(1, G.toggleColX - G.labelColX - T.LABEL_TO_CONTROL_GAP)
            M.controlX = G.toggleColX
            M.helperX = G.helperColX
            M.helperW = math.max(1, G.contentRight - G.helperColX)
            local toggleAvailW = math.max(0, G.contentRight - M.controlX)
            M.controlW = computeTimersSegmentWidth(sampleRow, T.MODULE_TOGGLE_PREF_W, toggleAvailW, T.SEGMENT_BUTTON_TEXT_PAD_X, T.MIN_SEGMENT_W)
            return M
        end

        local function computeTimersBatchCardGeometry(G, batchScopeRef, batchEnableRef, batchDisableRef)
            local T = TIMERS_LAYOUT
            local B = {}
            B.cardX = G.labelColX
            B.cardW = G.contentSpan
            B.innerW = math.max(1, B.cardW - (T.CARD_PADDING * 2))
            local scopeText = getTimersText(batchScopeRef)
            if trim(scopeText) ~= "" then
                batchScopeRef:SetText(scopeText)
                B.scopeW = math.min(B.innerW, math.ceil(tonumber((batchScopeRef.GetStringWidth and batchScopeRef:GetStringWidth()) or 0) or 0))
            else
                B.scopeW = 0
            end
            B.scopeX = T.CARD_PADDING + math.max(0, B.innerW - B.scopeW)
            B.titleW = math.max(1, B.innerW - B.scopeW - ((B.scopeW > 0) and T.BATCH_SCOPE_GAP or 0))
            local perButtonAvailW = math.max(T.BATCH_BUTTON_MIN_W, math.floor((B.innerW - T.BATCH_BUTTON_GAP) / 2))
            local desiredButtonW = math.max(
                computeTimersActionButtonWidth(batchEnableRef, T.BATCH_BUTTON_PREF_W, perButtonAvailW, T.BATCH_BUTTON_MIN_W),
                computeTimersActionButtonWidth(batchDisableRef, T.BATCH_BUTTON_PREF_W, perButtonAvailW, T.BATCH_BUTTON_MIN_W)
            )
            B.buttonW = math.max(T.BATCH_BUTTON_MIN_W, math.min(perButtonAvailW, desiredButtonW))
            if ((B.buttonW * 2) + T.BATCH_BUTTON_GAP) > B.innerW then
                B.buttonW = math.max(T.BATCH_BUTTON_COMPRESS_MIN_W, math.floor((B.innerW - T.BATCH_BUTTON_GAP) / 2))
            end
            B.buttonsLeft = T.CARD_PADDING + math.max(0, B.innerW - ((B.buttonW * 2) + T.BATCH_BUTTON_GAP))
            B.enableX = B.buttonsLeft
            B.disableX = B.enableX + B.buttonW + T.BATCH_BUTTON_GAP
            B.statusW = B.innerW
            return B
        end

        local function computeTimersAppearanceGeometry(G, axisXMini, axisYMini)
            local T = TIMERS_LAYOUT
            local A = {}
            A.labelX = G.settingsLabelX
            A.labelW = math.max(1, G.appearanceControlX - G.settingsLabelX - T.LABEL_TO_CONTROL_GAP)
            A.controlX = G.appearanceControlX
            A.controlAvailW = math.max(0, G.contentRight - A.controlX)
            if A.controlAvailW >= T.MAIN_CONTROL_MIN_W then
                A.mainControlW = math.min(T.MAIN_CONTROL_TARGET_W, A.controlAvailW)
            else
                A.mainControlW = A.controlAvailW
            end
            A.valueColX = A.controlX + A.mainControlW
            A.rowContainerW = math.max(1, G.contentRight - G.settingsLabelX)
            A.fontPickerW = math.max(0, A.mainControlW - T.FONT_SIZE_W - T.FONT_SIZE_GAP)
            A.fontDropSizeBelow = (A.fontPickerW < T.MIN_PICKER_W)
            if A.fontDropSizeBelow then
                A.fontPickerW = A.mainControlW
            end
            A.fontSizeW = T.FONT_SIZE_W
            A.fontSizeX = A.controlX + (A.fontDropSizeBelow and 0 or (A.fontPickerW + T.FONT_SIZE_GAP))
            local axisTextW = math.max(
                math.ceil(tonumber((axisXMini and axisXMini.GetStringWidth and axisXMini:GetStringWidth()) or 0) or 0),
                math.ceil(tonumber((axisYMini and axisYMini.GetStringWidth and axisYMini:GetStringWidth()) or 0) or 0)
            )
            A.axisLabelW = math.max(T.AXIS_LABEL_MIN_W, axisTextW)
            A.offsetSliderX = A.controlX + A.axisLabelW + T.AXIS_TO_CONTROL_GAP
            A.offsetSliderW = math.max(0, A.valueColX - A.offsetSliderX)
            return A
        end

