        local coordsLabel = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlight", 12)
        coordsLabel:SetText("Coordinates")
        coordsLabel:SetJustifyH("LEFT")
        local function normalizeTimersCoordsEdit(edit)
            if not edit then
                return
            end
            edit:SetJustifyH("CENTER")
            if edit.HasFocus and edit:HasFocus() then
                edit:SetTextColor(1, 1, 1, 1)
                edit:SetAlpha(1)
            else
                edit:SetTextColor(0.86, 0.86, 0.88, 1)
                edit:SetAlpha(0.90)
            end
            if edit.SetCursorPosition and not (edit.HasFocus and edit:HasFocus()) then
                edit:SetCursorPosition(0)
            end
            if edit.HighlightText and not (edit.HasFocus and edit:HasFocus()) then
                edit:HighlightText(0, 0)
            end
        end
        local function setTimersCoordsDisplay(edit, x, y)
            if not edit then
                return
            end
            edit:SetText(string.format("%d,%d", math.floor(tonumber(x) or 0), math.floor(tonumber(y) or 0)))
            normalizeTimersCoordsEdit(edit)
        end
        local function placeTimersCoordsCursorAtEnd(edit)
            if not edit or not edit.SetCursorPosition then
                return
            end
            edit:SetCursorPosition(string.len(tostring(edit:GetText() or "")))
        end
        local function queueTimersCoordsCursorAtEnd(edit)
            local function applyIfFocused()
                if edit and edit.HasFocus and edit:HasFocus() then
                    placeTimersCoordsCursorAtEnd(edit)
                end
            end
            applyIfFocused()
            if C_Timer and C_Timer.After then
                C_Timer.After(0, applyIfFocused)
                C_Timer.After(0.02, applyIfFocused)
            end
        end
        local coords = mkNumeric(scrollChild, function(edit)
            local activeStack = getStack()
            if not activeStack then return end
            local db = activeStack:GetDB()
            local text = trim(edit:GetText() or "")
            local xText, yText = text:match("^([%+%-]?%d+)%s*,%s*([%+%-]?%d+)$")
            if xText and yText then
                db.x = math.floor(tonumber(xText) or db.x or 0)
                db.y = math.floor(tonumber(yText) or db.y or 0)
                if not InCombatLockdown or not InCombatLockdown() then activeStack:ApplySettings() end
            end
            setTimersCoordsDisplay(edit, db.x or 0, db.y or 0)
        end)
        coords:SetTextColor(0.86, 0.86, 0.88, 1)
        coords:SetAlpha(0.90)
        coords:SetNumeric(false)
        setReadableNumericText(coords)
        coords:HookScript("OnEditFocusGained", function(edit)
            edit:SetJustifyH("CENTER")
            normalizeTimersCoordsEdit(edit)
            queueTimersCoordsCursorAtEnd(edit)
        end)
        coords:HookScript("OnMouseUp", function(edit)
            queueTimersCoordsCursorAtEnd(edit)
        end)
        coords:HookScript("OnShow", function(edit) normalizeTimersCoordsEdit(edit) end)
        coords:HookScript("OnEditFocusLost", function(edit) normalizeTimersCoordsEdit(edit) end)

        local resetAnchorButton = createActionButton(scrollChild, "Reset Anchor", function()
            local activeStack = getStack()
            if not activeStack then return end
            if activeStack.Initialize and not (activeStack.frame or activeStack.mainFrame) then
                activeStack:Initialize()
            end
            if activeStack.SetUnlocked then
                activeStack:SetUnlocked(true)
            end

            if activeStack.ResetPositionToCenter then
                activeStack:ResetPositionToCenter()
            else
                local db = activeStack:GetDB()
                db.x = 0
                db.y = 0
                if activeStack.ApplyPosition then
                    activeStack:ApplyPosition()
                end
                if activeStack.EvaluateVisibility then
                    activeStack:EvaluateVisibility("reset-anchor-fallback")
                elseif activeStack.Tick then
                    activeStack:Tick()
                end
            end

            if activeStack.frame then
                activeStack.frame:SetFrameStrata("HIGH")
                activeStack.frame:Raise()
            end

            if self._refresh then
                self._refresh()
            end
        end, TIMERS_LAYOUT.RESET_BUTTON_SEED_W)

        styleSecondaryActionButtonShared(resetAnchorButton, {
            baseBg = { 0.06, 0.07, 0.09, 0.95 },
            hoverBg = { 0.08, 0.09, 0.11, 0.95 },
            pressedBg = { 0.05, 0.06, 0.08, 0.96 },
            baseBorder = { 0.21, 0.24, 0.28, 0.62 },
            hoverBorder = { 0.25, 0.28, 0.33, 0.68 },
            pressedBorder = { 0.23, 0.26, 0.30, 0.66 },
            textColor = { 0.82, 0.83, 0.86, 1 },
        })
        local function createTimersToggleRow(parent, labelText, opts)
            opts = type(opts) == "table" and opts or {}
            local semantic = tostring(opts.semantic or "toggle")
            local onChanged = type(opts.onChanged) == "function" and opts.onChanged or nil
            local rowValue = false

            local row = createPremiumSegmentedChoice(parent, labelText, nil, {
                { label = tostring(opts.offLabel or "Off"), value = false, toggleState = "off" },
                { label = tostring(opts.onLabel or "On"), value = true, toggleState = "on" },
            }, function(selectedValue)
                local nextValue = PA_SafeBool(selectedValue)
                rowValue = nextValue
                if onChanged then
                    onChanged(nextValue)
                end
            end, {
                semantic = (semantic == "meta") and "selection" or "toggle",
                selectionVariant = (semantic == "meta") and "lock_meta" or "",
                textEllipsis = true,
                normalizeValue = function(v)
                    return PA_SafeBool(v)
                end,
                getValue = function()
                    return rowValue
                end,
                setValue = function(v)
                    rowValue = PA_SafeBool(v)
                end,
            })

            row.value = false
            row.enabled = true
            if row.label then
                row.label:SetJustifyH("LEFT")
            end
            row.offBtn = row.buttons and row.buttons[1] or nil
            row.onBtn = row.buttons and row.buttons[2] or nil

            local baseSetEnabled = row.SetEnabled
            row.SetEnabled = function(self, enabled)
                self.enabled = enabled and true or false
                if baseSetEnabled then
                    baseSetEnabled(self, self.enabled)
                end
            end

            local baseLayout = row.Layout
            row.Layout = function(self, width)
                if baseLayout then
                    baseLayout(self, math.max(TIMERS_LAYOUT.MIN_SEGMENT_W, tonumber(width) or TIMERS_LAYOUT.LOCK_TOGGLE_PREF_W))
                end
            end

            if row.offBtn then
                row.offBtn:SetScript("OnClick", function()
                    if not row.enabled or not rowValue then
                        return
                    end
                    row:SetSelectedValue(false, true)
                end)
            end
            if row.onBtn then
                row.onBtn:SetScript("OnClick", function()
                    if not row.enabled or rowValue then
                        return
                    end
                    row:SetSelectedValue(true, true)
                end)
            end

            row.SetValue = function(self, v, trigger)
                local nextValue = PA_SafeBool(v)
                rowValue = nextValue
                self.value = nextValue
                self:SetVisualSelectedValue(nextValue)
                if trigger and onChanged then
                    onChanged(nextValue)
                end
            end
            row.GetValue = function()
                return rowValue
            end

            row:SetValue(false, false)
            return row
        end

        local function createTimersPremiumSlider(parent, labelText, minV, maxV, stepV, onApplyValue)
            local spec = {}
            local sliderMin = tonumber(minV) or 0
            local sliderMax = tonumber(maxV) or 100
            if sliderMax < sliderMin then
                sliderMin, sliderMax = sliderMax, sliderMin
            end
            local stepValue = tonumber(stepV) or 1
            if stepValue <= 0 then
                stepValue = 1
            end

            spec.label = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
            spec.label:SetText(labelText or "")
            spec.label:SetJustifyH("LEFT")
            spec.control = CreateFrame("Frame", nil, parent)
            spec.control:SetHeight(TIMERS_LAYOUT.CONTROL_FLOOR)
            spec.control:SetWidth(TIMERS_LAYOUT.SLIDER_CONTROL_W)

            local valueButton = CreateFrame("Button", nil, spec.control)
            valueButton:SetSize(TIMERS_LAYOUT.SLIDER_VALUE_BUTTON_W, TIMERS_LAYOUT.SLIDER_VALUE_BUTTON_H)
            valueButton:SetPoint("RIGHT", spec.control, "RIGHT", 0, 0)

            local valueText = createStyledFontString(valueButton, "ARTWORK", "GameFontHighlightSmall", 11)
            valueText:SetPoint("RIGHT", valueButton, "RIGHT", 0, 0)
            valueText:SetJustifyH("RIGHT")
            valueText:SetTextColor(0.76, 0.76, 0.78, 1)

            local valueEdit = CreateFrame("EditBox", nil, valueButton)
            valueEdit:SetAllPoints(valueButton)
            valueEdit:SetAutoFocus(false)
            valueEdit:SetJustifyH("RIGHT")
            valueEdit:SetTextInsets(0, 0, 0, 0)
            valueEdit:SetTextColor(1, 1, 1, 1)
            valueEdit:SetHighlightColor(1, 1, 1, 0.25)
            valueEdit:SetNumeric(false)
            applyGlobalFontToObject(valueEdit, 11)
            valueEdit:Hide()

            spec.slider = CreateFrame("Slider", nil, spec.control)
            spec.slider:SetPoint("TOPLEFT", spec.control, "TOPLEFT", 0, 0)
            spec.slider:SetPoint("BOTTOMRIGHT", valueButton, "BOTTOMLEFT", -TIMERS_LAYOUT.SLIDER_VALUE_GAP, 0)
            spec.slider:SetMinMaxValues(sliderMin, sliderMax)
            spec.slider:SetValueStep(stepValue)
            if spec.slider.SetObeyStepOnDrag then
                spec.slider:SetObeyStepOnDrag(true)
            end
            spec.slider:SetThumbTexture("Interface\\Buttons\\WHITE8x8")
            local inputThumb = spec.slider:GetThumbTexture()
            if inputThumb then
                inputThumb:SetSize(16, 16)
                inputThumb:SetVertexColor(1, 1, 1, 0.01)
            end
            spec.slider:EnableMouse(true)
            spec.slider:SetOrientation("HORIZONTAL")

            local trackBg = spec.slider:CreateTexture(nil, "BACKGROUND")
            trackBg:SetTexture("Interface\\Buttons\\WHITE8x8")
            trackBg:SetPoint("LEFT", spec.slider, "LEFT", 0, 0)
            trackBg:SetPoint("RIGHT", spec.slider, "RIGHT", 0, 0)
            trackBg:SetHeight(2)
            trackBg:SetVertexColor(0.18, 0.18, 0.19, 0.95)

            local trackActive = spec.slider:CreateTexture(nil, "ARTWORK")
            trackActive:SetTexture("Interface\\Buttons\\WHITE8x8")
            trackActive:SetPoint("LEFT", spec.slider, "LEFT", 0, 0)
            trackActive:SetHeight(2)
            trackActive:SetWidth(0)
            trackActive:SetVertexColor(1.0, 0.82, 0.0, 0.75)

            local thumb = spec.slider:CreateTexture(nil, "OVERLAY")
            thumb:SetTexture("Interface\\Buttons\\WHITE8x8")
            thumb:SetSize(8, 8)
            thumb:SetVertexColor(1.0, 0.84, 0.08, 0.98)
            if thumb.SetMask then
                thumb:SetMask("Interface\\CharacterFrame\\TempPortraitAlphaMask")
            end

            local thumbGlow = spec.slider:CreateTexture(nil, "ARTWORK")
            thumbGlow:SetTexture("Interface\\Buttons\\WHITE8x8")
            thumbGlow:SetSize(14, 14)
            thumbGlow:SetVertexColor(1.0, 0.82, 0.0, 0)
            if thumbGlow.SetMask then
                thumbGlow:SetMask("Interface\\CharacterFrame\\TempPortraitAlphaMask")
            end
            thumbGlow:SetBlendMode("ADD")

            local suppress = false
            local controlEnabled = true
            local currentValue = nil
            local dragging = false
            local hovering = false
            local editingValue = false
            local dragLeft = nil
            local dragRight = nil
            local dragScale = nil
            local lastDragCursorX = nil

            local function resetDragTracking()
                dragLeft = nil
                dragRight = nil
                dragScale = nil
                lastDragCursorX = nil
            end

            local function captureDragBounds()
                dragLeft = spec.slider:GetLeft()
                dragRight = spec.slider:GetRight()
                dragScale = spec.slider:GetEffectiveScale() or 1
                lastDragCursorX = nil
                if not dragLeft or not dragRight or dragRight <= dragLeft or dragScale <= 0 then
                    resetDragTracking()
                end
            end

            local function normalize(n)
                local v = tonumber(n) or sliderMin
                if v < sliderMin then v = sliderMin end
                if v > sliderMax then v = sliderMax end
                v = sliderMin + (math.floor(((v - sliderMin) / stepValue) + 0.5) * stepValue)
                if v < sliderMin then v = sliderMin end
                if v > sliderMax then v = sliderMax end
                return math.floor(v + 0.5)
            end

            local function applyVisualState()
                local minVNow, maxVNow = spec.slider:GetMinMaxValues()
                local value = normalize(spec.slider:GetValue())
                local span = math.max(0.0001, (maxVNow - minVNow))
                local pct = (value - minVNow) / span
                if pct < 0 then pct = 0 end
                if pct > 1 then pct = 1 end
                local widthNow = spec.slider:GetWidth() or 0
                local x = pct * widthNow

                thumb:ClearAllPoints()
                thumb:SetPoint("CENTER", spec.slider, "LEFT", x, 0)
                thumbGlow:ClearAllPoints()
                thumbGlow:SetPoint("CENTER", thumb, "CENTER", 0, 0)

                trackActive:ClearAllPoints()
                trackActive:SetPoint("LEFT", spec.slider, "LEFT", 0, 0)
                trackActive:SetPoint("RIGHT", thumb, "CENTER", 0, 0)

                local glowAlpha = 0
                if not controlEnabled then
                    trackActive:SetVertexColor(0.48, 0.48, 0.50, 0.35)
                    thumb:SetVertexColor(0.62, 0.62, 0.64, 0.65)
                elseif dragging then
                    glowAlpha = 0.34
                    trackActive:SetVertexColor(1.0, 0.86, 0.16, 0.9)
                    thumb:SetVertexColor(1.0, 0.9, 0.22, 1)
                elseif hovering then
                    glowAlpha = 0.22
                    trackActive:SetVertexColor(1.0, 0.85, 0.12, 0.85)
                    thumb:SetVertexColor(1.0, 0.88, 0.18, 1)
                else
                    trackActive:SetVertexColor(1.0, 0.82, 0.0, 0.75)
                    thumb:SetVertexColor(1.0, 0.84, 0.08, 0.98)
                end
                thumbGlow:SetVertexColor(1.0, 0.82, 0.0, glowAlpha)
                spec.label:SetAlpha(controlEnabled and 1 or 0.55)
                spec.control:SetAlpha(controlEnabled and 1 or 0.55)
            end

            local function setValueVisualOnly(v, keepCurrentValue)
                local n = normalize(v)
                if not keepCurrentValue then
                    currentValue = n
                end
                suppress = true
                spec.slider:SetValue(n)
                suppress = false
                valueText:SetText(tostring(n))
                if valueEdit:IsShown() then
                    valueEdit:SetText(tostring(n))
                end
                applyVisualState()
            end

            local function applyValue(v)
                local n = normalize(v)
                if currentValue == n then
                    valueText:SetText(tostring(n))
                    applyVisualState()
                    return
                end
                currentValue = n
                valueText:SetText(tostring(n))
                if valueEdit:IsShown() then
                    valueEdit:SetText(tostring(n))
                end
                if onApplyValue then
                    onApplyValue(n)
                end
                applyVisualState()
            end

            local function beginEdit()
                editingValue = true
                valueText:Hide()
                valueEdit:SetText(tostring(normalize(currentValue or spec.slider:GetValue())))
                valueEdit:Show()
                valueEdit:SetFocus()
                valueEdit:HighlightText()
            end

            local function endEdit(commit)
                if not editingValue then
                    return
                end
                editingValue = false
                if commit then
                    local parsed = tonumber(trim(valueEdit:GetText() or ""))
                    if parsed ~= nil then
                        local n = normalize(parsed)
                        setValueVisualOnly(n, true)
                        applyValue(n)
                    else
                        setValueVisualOnly(currentValue or spec.slider:GetValue())
                    end
                end
                valueEdit:Hide()
                valueText:Show()
                valueEdit:ClearFocus()
                valueText:SetText(tostring(normalize(currentValue or spec.slider:GetValue())))
            end

            local function setValueFromCursor()
                local left = (dragging and dragLeft) or spec.slider:GetLeft()
                local right = (dragging and dragRight) or spec.slider:GetRight()
                if not left or not right or right <= left then
                    return
                end
                local cx = GetCursorPosition()
                local scale = (dragging and dragScale) or (spec.slider:GetEffectiveScale() or 1)
                if not cx or scale <= 0 then
                    return
                end
                cx = cx / scale
                if dragging and lastDragCursorX ~= nil and math.abs(cx - lastDragCursorX) < 0.25 then
                    return
                end
                if dragging then
                    lastDragCursorX = cx
                end
                local pct = (cx - left) / (right - left)
                if pct < 0 then pct = 0 end
                if pct > 1 then pct = 1 end
                local raw = sliderMin + ((sliderMax - sliderMin) * pct)
                local n = normalize(raw)
                if currentValue == n then
                    applyVisualState()
                    return
                end
                setValueVisualOnly(n, true)
                applyValue(n)
            end

            spec.slider:SetScript("OnValueChanged", function(selfSlider, value)
                local n = normalize(value)
                if selfSlider:GetValue() ~= n then
                    suppress = true
                    selfSlider:SetValue(n)
                    suppress = false
                end
                valueText:SetText(tostring(n))
                applyVisualState()
                if suppress or isControlHydrating(selfSlider) then
                    return
                end
                applyValue(n)
            end)
            spec.slider:SetScript("OnMouseDown", function()
                if not controlEnabled then
                    return
                end
                dragging = true
                captureDragBounds()
                setValueFromCursor()
                spec.slider:SetScript("OnUpdate", function()
                    if dragging then
                        setValueFromCursor()
                    end
                end)
                applyVisualState()
            end)
            spec.slider:SetScript("OnMouseUp", function()
                dragging = false
                resetDragTracking()
                spec.slider:SetScript("OnUpdate", nil)
                applyVisualState()
            end)
            spec.slider:SetScript("OnEnter", function()
                if not controlEnabled then
                    return
                end
                hovering = true
                applyVisualState()
            end)
            spec.slider:SetScript("OnLeave", function()
                hovering = false
                dragging = false
                resetDragTracking()
                spec.slider:SetScript("OnUpdate", nil)
                applyVisualState()
            end)

            valueButton:SetScript("OnClick", function()
                if not controlEnabled then
                    return
                end
                beginEdit()
            end)
            valueEdit:SetScript("OnEnterPressed", function(edit)
                endEdit(true)
                edit:ClearFocus()
            end)
            valueEdit:SetScript("OnEscapePressed", function(edit)
                endEdit(false)
                edit:ClearFocus()
            end)
            valueEdit:SetScript("OnEditFocusLost", function()
                endEdit(true)
            end)

            function spec:SetVisualValue(v)
                setValueVisualOnly(v)
            end
            function spec:Refresh(v)
                setValueVisualOnly(v)
            end
            function spec:IsInteracting()
                return dragging or editingValue
            end
            function spec:SetWidth(newWidth)
                local fullW = math.max(0, math.floor(tonumber(newWidth) or TIMERS_LAYOUT.SLIDER_CONTROL_W))
                self.control:SetWidth(fullW)
                applyVisualState()
            end
            function spec:SetEnabled(enabled)
                controlEnabled = enabled and true or false
                if not controlEnabled then
                    dragging = false
                    hovering = false
                    endEdit(false)
                    resetDragTracking()
                    spec.slider:SetScript("OnUpdate", nil)
                end
                spec.slider:EnableMouse(controlEnabled)
                valueButton:EnableMouse(controlEnabled)
                valueEdit:EnableMouse(controlEnabled)
                applyVisualState()
            end
            spec.control:SetScript("OnSizeChanged", function()
                applyVisualState()
            end)

            spec.valueButton = valueButton
            spec.valueText = valueText
            spec.valueEdit = valueEdit
            setValueVisualOnly(sliderMin)
            return spec
        end

