        local function resolveBatchStatusText()
            if batchAvailableCount <= 0 then
                return BATCH_STATUS_NONE_AVAILABLE_TEXT
            end
            if batchStatusMode == "feedback" and batchStatusFeedbackText ~= "" then
                return batchStatusFeedbackText
            end
            return BATCH_STATUS_BASELINE_TEXT
        end

        local function refreshBatchStatusLine()
            local text = resolveBatchStatusText()
            setTimersText(batchStatus, text)
