        applyBatchModules = function(desiredEnabled)
            local activeStack, db = getTimersDBSnapshot()
            if not db then
                return 0
            end
            local targetValue = PA_SafeBool(desiredEnabled)
            local changedCount = 0
            for _, module in ipairs(moduleRows) do
                if not module.excludeFromBatch then
                local available = isModuleAvailable(module.id)
                if available then
                    local currentValue = PA_SafeBool(readTimerSetting(db, module.key, true))
                    if currentValue ~= targetValue then
                        writeTimerSetting(db, module.key, targetValue)
                        changedCount = changedCount + 1
                    end
                end
                end
            end
            if changedCount > 0 and activeStack and activeStack.ApplySettings then
                applyStackSettings()
            end
            return changedCount
        end

