            local db = activeStack:GetDB()
            db.iconSize = math.floor(math.min(64, math.max(12, tonumber(v) or db.iconSize or 18)))
            applyStackSettings()
        end)
        local iconOffsetXSlider = createTimersPremiumSlider(scrollChild, "Icon Offset X", -50, 50, 1, function(v)
            local activeStack = getStack()
            if not activeStack then return end
            local db = activeStack:GetDB()
            db.iconOffsetX = math.floor(math.min(50, math.max(-50, tonumber(v) or db.iconOffsetX or 0)))
            applyStackSettings()
        end)
        local iconOffsetYSlider = createTimersPremiumSlider(scrollChild, "Icon Offset Y", -50, 50, 1, function(v)
            local activeStack = getStack()
