            db.iconOffsetY = math.floor(math.min(50, math.max(-50, tonumber(v) or db.iconOffsetY or 0)))
            applyStackSettings()
        end)

        local function syncModuleVisuals(db)
            local availableCount = 0
            for _, module in ipairs(moduleRows) do
                local visibilityOverride = module.visibilityOverride
                local isVisible = (type(visibilityOverride) ~= "function") or visibilityOverride(db)
                local available, unavailableReason = isModuleAvailable(module.id)
                if visibilityOverride then
                    available = available and isVisible
                    if not isVisible then
                        unavailableReason = nil
                    end
                end
                local defaultValue = (module.key == "lustSatedEndSound") and false or true
                local moduleValue = PA_SafeBool(readTimerSetting(db, module.key, defaultValue))
                if module.check then
                    module.check:SetChecked(moduleValue)
                    if available then
                        module.check:Enable()
                        if module.check.text then
                            module.check.text:SetTextColor(1, 0.82, 0, 1)
                        end
                    else
                        module.check:Disable()
                        if module.check.text then
                            module.check.text:SetTextColor(0.6, 0.6, 0.6, 1)
                        end
                    end
                end
                if module.row then
                    module.row:SetEnabled(available)
                    module.row:SetValue(moduleValue, false)
                end
                if module.unavailableHelper then
                    setTimersText(module.unavailableHelper, available and "" or tostring(unavailableReason or "Unavailable"))
                end
                if module.row and visibilityOverride and not isVisible then
                    parkTimersControl(module.row.label)
                    parkTimersControl(module.row.control)
                end
                for _, child in ipairs(module.childRows or {}) do
                    local childValue = PA_SafeBool(readTimerSetting(db, child.key, false))
                    local childEnabled = available and (not child.isVisible or child.isVisible(db))
                    if child.row then
                        child.row:SetEnabled(childEnabled)
                        child.row:SetValue(childValue, false)
                    end
                end
                if available and not module.excludeFromBatch then
                    availableCount = availableCount + 1
                end
            end
            batchAvailableCount = availableCount
            local hasAvailable = availableCount > 0
            if batchEnableButton then
                batchEnableButton:SetEnabled(hasAvailable)
                batchEnableButton:SetAlpha(hasAvailable and 1 or 0.55)
            end
            if batchDisableButton then
                batchDisableButton:SetEnabled(hasAvailable)
                batchDisableButton:SetAlpha(hasAvailable and 1 or 0.55)
            end
            refreshBatchStatusLine()
        end

        local function syncLockStateHelperText(isLocked, moduleEnabled)
            if not lockStateHelper then
                return
            end
            if not moduleEnabled then
                setTimersText(lockStateHelper, "Timers are disabled. Re-enable to edit settings.")
            elseif isLocked then
                setTimersText(lockStateHelper, "Timers are locked.")
            else
                setTimersText(lockStateHelper, "Timers are unlocked - drag to reposition.")
            end
        end

        local function applyTimersModuleEnabledState(moduleEnabled)
            setSettingsControlEnabled(widgets.unlock, moduleEnabled)
            if lockRow then
                lockRow:SetEnabled(moduleEnabled)
            end
            setSettingsControlEnabled(resetAnchorButton, moduleEnabled)

            for _, module in ipairs(moduleRows) do
                if module and module.row and not moduleEnabled then
                    module.row:SetEnabled(false)
                end
                for _, child in ipairs(module and module.childRows or {}) do
                    if child and child.row and not moduleEnabled then
                        child.row:SetEnabled(false)
                    end
                end
            end

            if not moduleEnabled then
                if batchEnableButton then
                    batchEnableButton:SetEnabled(false)
                    batchEnableButton:SetAlpha(0.55)
                end
                if batchDisableButton then
                    batchDisableButton:SetEnabled(false)
                    batchDisableButton:SetAlpha(0.55)
                end
            end

            setSettingsControlEnabled(fontDropdown, moduleEnabled)
            setSettingsControlEnabled(aspectDropdown, moduleEnabled)
            setSettingsControlEnabled(iconEdgeControl, moduleEnabled)
            setSettingsControlEnabled(sizeStepper or sizeEdit, moduleEnabled)
            setSettingsControlEnabled(coords, moduleEnabled)
            setSettingsControlEnabled(iconSizeSlider, moduleEnabled)
            setSettingsControlEnabled(iconOffsetXSlider, moduleEnabled)
            setSettingsControlEnabled(iconOffsetYSlider, moduleEnabled)

            if lockRowContainer and lockRowContainer.SetAlpha then
                lockRowContainer:SetAlpha(moduleEnabled and 1 or 0.55)
            end
            if batchActionsCard and batchActionsCard.SetAlpha then
                batchActionsCard:SetAlpha(moduleEnabled and 1 or 0.55)
            end

            for _, textWidget in ipairs({
                modulesHeader,
                appearanceLayoutHeader,
                batchActionsTitle,
                batchActionsScope,
                batchStatus,
                fontLabel,
                coordsLabel,
                iconEdgeLabel,
                aspectLabel,
                iconOffsetPairLabel,
                iconOffsetAxisXMini,
                iconOffsetAxisYMini,
                brezExplain,
                lustExplain,
                healerExplain,
                cooldownSweepExplain,
            }) do
                setSettingsTextEnabled(textWidget, moduleEnabled)
            end
        end

        local function refresh()
            local activeStack, db = getTimersDBSnapshot()
            local isLocked = getTimersLockedState()
            local moduleEnabled = PA_SafeBool(readTimerSetting(db, "enabled", true))
            widgets.unlock:SetChecked(isLocked)
            updateUnlockLabelColor(isLocked)
            if masterEnabledRow then
                masterEnabledRow:SetValue(moduleEnabled, false)
            end
            if lockRow then
                lockRow:SetValue(isLocked, false)
            end
            syncLockStateHelperText(isLocked, moduleEnabled)

            syncModuleVisuals(db)
            local fontSizeValue = math.floor(tonumber(readTimerSetting(db, "fontSize", 12)) or 12)
            local iconSizeValue = math.floor(tonumber(readTimerSetting(db, "iconSize", 18)) or 18)
            local iconOffsetXValue = math.floor(tonumber(readTimerSetting(db, "iconOffsetX", 0)) or 0)
            local iconOffsetYValue = math.floor(tonumber(readTimerSetting(db, "iconOffsetY", 0)) or 0)
            if fontDropdown.Refresh then fontDropdown.Refresh() end
            if iconEdgeControl and iconEdgeControl.Refresh then iconEdgeControl:Refresh() end
            if aspectDropdown.Refresh then aspectDropdown.Refresh() end
            if sizeStepper and sizeStepper.SetVisualValue then
                local fontSizeEditing = sizeStepper.valueEdit and sizeStepper.valueEdit.IsShown and sizeStepper.valueEdit:IsShown()
                if not fontSizeEditing then
                    sizeStepper:SetVisualValue(fontSizeValue)
                end
            elseif sizeEdit and not sizeEdit:HasFocus() then
                sizeEdit:SetText(tostring(fontSizeValue))
            end
            if not iconSizeEdit:HasFocus() then iconSizeEdit:SetText(tostring(iconSizeValue)) end
            if not iconOffsetXEdit:HasFocus() then iconOffsetXEdit:SetText(tostring(iconOffsetXValue)) end
            if not iconOffsetYEdit:HasFocus() then iconOffsetYEdit:SetText(tostring(iconOffsetYValue)) end
            local liveX, liveY = getTimersDisplayPosition(activeStack, db)
            if not coords:HasFocus() then setTimersCoordsDisplay(coords, liveX, liveY) else normalizeTimersCoordsEdit(coords) end
            if iconSizeSlider and (not iconSizeSlider.IsInteracting or not iconSizeSlider:IsInteracting()) then
                iconSizeSlider:Refresh(iconSizeValue)
            end
            if iconOffsetXSlider and (not iconOffsetXSlider.IsInteracting or not iconOffsetXSlider:IsInteracting()) then
                iconOffsetXSlider:Refresh(iconOffsetXValue)
            end
            if iconOffsetYSlider and (not iconOffsetYSlider.IsInteracting or not iconOffsetYSlider:IsInteracting()) then
                iconOffsetYSlider:Refresh(iconOffsetYValue)
            end
            applyTimersModuleEnabledState(moduleEnabled)
            if self._layout then self._layout() end
            refreshSettingsWindowHeaderAccessoryIfHosted(self)
        end
        local function syncTimersLiveFields()
            local activeStack, db = getTimersDBSnapshot()
            local isLocked = getTimersLockedState()
            local moduleEnabled = PA_SafeBool(readTimerSetting(db, "enabled", true))
            widgets.unlock:SetChecked(isLocked)
            updateUnlockLabelColor(isLocked)
            syncModuleVisuals(db)
            if masterEnabledRow then
                masterEnabledRow:SetValue(moduleEnabled, false)
            end
            if lockRow then
                lockRow:SetValue(isLocked, false)
            end
            syncLockStateHelperText(isLocked, moduleEnabled)

            local fontSizeValue = math.floor(tonumber(readTimerSetting(db, "fontSize", 12)) or 12)
            local iconSizeValue = math.floor(tonumber(readTimerSetting(db, "iconSize", 18)) or 18)
            local iconOffsetXValue = math.floor(tonumber(readTimerSetting(db, "iconOffsetX", 0)) or 0)
            local iconOffsetYValue = math.floor(tonumber(readTimerSetting(db, "iconOffsetY", 0)) or 0)
            if sizeStepper and sizeStepper.SetVisualValue then
                local fontSizeEditing = sizeStepper.valueEdit and sizeStepper.valueEdit.IsShown and sizeStepper.valueEdit:IsShown()
                if not fontSizeEditing then
                    sizeStepper:SetVisualValue(fontSizeValue)
                end
            elseif sizeEdit and not sizeEdit:HasFocus() then
                sizeEdit:SetText(tostring(fontSizeValue))
            end
            if not iconSizeEdit:HasFocus() then iconSizeEdit:SetText(tostring(iconSizeValue)) end
            if not iconOffsetXEdit:HasFocus() then iconOffsetXEdit:SetText(tostring(iconOffsetXValue)) end
            if not iconOffsetYEdit:HasFocus() then iconOffsetYEdit:SetText(tostring(iconOffsetYValue)) end
            local liveX, liveY = getTimersDisplayPosition(activeStack, db)
            if not coords:HasFocus() then setTimersCoordsDisplay(coords, liveX, liveY) else normalizeTimersCoordsEdit(coords) end
            if iconSizeSlider and (not iconSizeSlider.IsInteracting or not iconSizeSlider:IsInteracting()) then
                iconSizeSlider:SetVisualValue(iconSizeValue)
            end
            if iconOffsetXSlider and (not iconOffsetXSlider.IsInteracting or not iconOffsetXSlider:IsInteracting()) then
                iconOffsetXSlider:SetVisualValue(iconOffsetXValue)
            end
            if iconOffsetYSlider and (not iconOffsetYSlider.IsInteracting or not iconOffsetYSlider:IsInteracting()) then
                iconOffsetYSlider:SetVisualValue(iconOffsetYValue)
            end
            applyTimersModuleEnabledState(moduleEnabled)
        end

        self._refresh = refresh
        self._syncTimersLiveFields = syncTimersLiveFields

        local timersLayoutRefs = {
            widgetsUnlock = widgets.unlock,
            brezEnable = brezEnable,
            lustEnable = lustEnable,
            healerEnable = healerEnable,
            cooldownSweepEnable = cooldownSweepEnable,
            enableLabel = enableLabel,
            sizeLabel = sizeLabel,
            iconSizeLabel = iconSizeLabel,
            iconOffsetXLabel = iconOffsetXLabel,
            iconOffsetYLabel = iconOffsetYLabel,
            iconSizeEdit = iconSizeEdit,
            iconOffsetXEdit = iconOffsetXEdit,
            iconOffsetYEdit = iconOffsetYEdit,
            header = header,
            masterRow = masterEnabledRow,
            masterRowContainer = masterRowContainer,
            lockRow = lockRow,
            lockRowContainer = lockRowContainer,
            resetAnchorButton = resetAnchorButton,
            lockStateHelper = lockStateHelper,
            divider = divider,
            modulesHeader = modulesHeader,
            batchActionsCard = batchActionsCard,
            batchActionsTitle = batchActionsTitle,
            batchActionsScope = batchActionsScope,
            batchEnableButton = batchEnableButton,
            batchDisableButton = batchDisableButton,
            batchStatus = batchStatus,
            dividerFont = dividerFont,
            appearanceLayoutHeader = appearanceLayoutHeader,
            fontDropdown = fontDropdown,
            aspectDropdown = aspectDropdown,
            iconEdgeControl = iconEdgeControl,
            sizeStepper = sizeStepper,
            sizeEdit = sizeEdit,
            coords = coords,
            coordsLabel = coordsLabel,
            fontRowContainer = fontRowContainer,
            fontLabel = fontLabel,
            iconSizeSlider = iconSizeSlider,
            iconOffsetXSlider = iconOffsetXSlider,
            iconOffsetYSlider = iconOffsetYSlider,
            lustSoundRow = lustSoundRow,
            cooldownSweepRow = cooldownSweepRow,
            iconOffsetPairLabel = iconOffsetPairLabel,
            iconOffsetAxisXMini = iconOffsetAxisXMini,
            iconOffsetAxisYMini = iconOffsetAxisYMini,
            iconOffsetRowContainer = iconOffsetRowContainer,
            iconEdgeLabel = iconEdgeLabel,
            aspectLabel = aspectLabel,
        }

        local function layout()
            local R = timersLayoutRefs
            local T = TIMERS_LAYOUT
            local _, layoutDb = getTimersDBSnapshot()
            local contentW = math.max((scrollFrame:GetWidth() or 0) - 8, T.MIN_CONTENT_W)
            local useHostedChrome = isPanelUsingCustomSettingsWindowHost(self)
            local G = computeTimersGeometry(contentW)
            local lockG = computeTimersLockRowGeometry(G, R.lockRow, R.resetAnchorButton)
            local moduleG = computeTimersModuleGeometry(G, R.cooldownSweepRow or R.lockRow)
            local batchG = computeTimersBatchCardGeometry(G, R.batchActionsScope, R.batchEnableButton, R.batchDisableButton)
            local appearanceG = computeTimersAppearanceGeometry(G, R.iconOffsetAxisXMini, R.iconOffsetAxisYMini)
            scrollChild:SetWidth(G.contentW)

            for _, control in ipairs({
                R.header,
                R.masterRowContainer,
                R.masterRow and R.masterRow.label or nil,
                R.masterRow and R.masterRow.control or nil,
                R.lockRowContainer,
                R.lockRow and R.lockRow.label or nil,
                R.lockRow and R.lockRow.control or nil,
                R.resetAnchorButton,
                R.lockStateHelper,
                R.divider,
                R.modulesHeader,
                R.batchActionsCard,
                R.batchActionsTitle,
                R.batchActionsScope,
                R.batchEnableButton,
                R.batchDisableButton,
                R.batchStatus,
                R.dividerFont,
                R.appearanceLayoutHeader,
                R.fontRowContainer,
                R.fontLabel,
                R.fontDropdown and R.fontDropdown.control or nil,
                (R.sizeStepper and R.sizeStepper.control) or R.sizeEdit,
                R.coordsLabel,
                R.coords,
                R.iconSizeSlider and R.iconSizeSlider.label or nil,
                R.iconSizeSlider and R.iconSizeSlider.control or nil,
                R.iconOffsetRowContainer,
                R.iconOffsetPairLabel,
                R.iconOffsetAxisXMini,
                R.iconOffsetXSlider and R.iconOffsetXSlider.control or nil,
                R.iconOffsetAxisYMini,
                R.iconOffsetYSlider and R.iconOffsetYSlider.control or nil,
                R.iconEdgeLabel,
                R.iconEdgeControl and R.iconEdgeControl.control or nil,
                R.aspectLabel,
                R.aspectDropdown and R.aspectDropdown.control or nil,
            }) do
                showTimersControl(control)
            end
            for _, module in ipairs(moduleRows) do
                if module and module.row then
                    showTimersControl(module.row.label)
                    showTimersControl(module.row.control)
                end
                for _, child in ipairs(module and module.childRows or {}) do
                    if child and child.row then
                        showTimersControl(child.row.label)
                        showTimersControl(child.row.control)
                    end
                end
                showTimersControl(module and module.unavailableHelper or nil)
                for _, fs in ipairs(module and module.explainers or {}) do
                    showTimersControl(fs)
                end
            end

            local function setPickerWidth(picker, width)
                local w = math.max(0, math.floor(tonumber(width) or 0))
                if picker and picker.SetWidth then
                    picker:SetWidth(w)
                elseif picker and picker.control then
                    picker.control:SetWidth(w)
                end
            end

            parkTimersControl(R.widgetsUnlock)
            parkTimersControl(R.brezEnable)
            parkTimersControl(R.lustEnable)
            parkTimersControl(R.healerEnable)
            parkTimersControl(R.cooldownSweepEnable)
            parkTimersControl(R.enableLabel)
            parkTimersControl(R.sizeLabel)
            parkTimersControl(R.iconSizeLabel)
            parkTimersControl(R.iconOffsetXLabel)
            parkTimersControl(R.iconOffsetYLabel)
            parkTimersControl(R.iconSizeEdit)
            parkTimersControl(R.iconOffsetXEdit)
            parkTimersControl(R.iconOffsetYEdit)

            local y = -T.TOP_PAD
            if useHostedChrome then
                y = y - SETTINGS_WINDOW_HOSTED_TOP_RHYTHM_NUDGE
            end

            if useHostedChrome then
                parkTimersControl(R.header)
                parkTimersControl(headerDescriptor)
                parkTimersControl(R.masterRowContainer)
                parkTimersControl(R.masterRow and R.masterRow.label or nil)
                parkTimersControl(R.masterRow and R.masterRow.control or nil)
            else
                showTimersControl(R.header)
                showTimersControl(headerDescriptor)
                showTimersControl(R.masterRowContainer)
                showTimersControl(R.masterRow and R.masterRow.label or nil)
                showTimersControl(R.masterRow and R.masterRow.control or nil)
                R.header:ClearAllPoints()
                R.header:SetWidth(math.max(1, G.contentRight - T.HEADER_LEFT))
                R.header:SetWordWrap(false)
                if R.header.SetMaxLines then
                    R.header:SetMaxLines(1)
                end
                R.header:SetText(getTimersText(R.header))
                local headerH = math.max(T.HEADER_FLOOR, math.ceil(tonumber((R.header.GetStringHeight and R.header:GetStringHeight()) or 0) or 0))
                R.header:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", T.HEADER_LEFT, y)
                y = y - headerH - T.HEADER_BOTTOM_GAP
                y = layoutSettingsSectionDescriptor(headerDescriptor, scrollChild, T.HEADER_LEFT, y, math.max(1, G.contentRight - T.HEADER_LEFT))

                R.masterRow:Layout(math.max(T.MODULE_TOGGLE_PREF_W, lockG.controlW))
                local masterLabelH = measureTimersSingleLineHeight(R.masterRow.label, lockG.labelW, T.LABEL_FLOOR, true)
                local masterToggleH = measureTimersControlHeight(R.masterRow.control, T.CONTROL_FLOOR, true)
                local masterRowH = math.max(T.LOCK_ROW_FLOOR or T.CONTROL_FLOOR, masterLabelH, masterToggleH)
                R.masterRowContainer:ClearAllPoints()
                R.masterRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", lockG.labelX, y)
                R.masterRowContainer:SetSize(lockG.rowW, masterRowH)
                R.masterRow.label:ClearAllPoints()
                R.masterRow.label:SetPoint("LEFT", R.masterRowContainer, "LEFT", 0, 0)
                R.masterRow.control:ClearAllPoints()
                R.masterRow.control:SetPoint("LEFT", R.masterRow.label, "RIGHT", T.LABEL_TO_CONTROL_GAP, 0)
                y = y - masterRowH - T.SECTION_HEADER_BOTTOM_GAP
            end

            R.lockRow:Layout(lockG.controlW)
            R.resetAnchorButton:SetSize(lockG.resetW, lockG.resetH)
            local lockLabelH = measureTimersSingleLineHeight(R.lockRow.label, lockG.labelW, T.LABEL_FLOOR, true)
            local lockToggleH = measureTimersControlHeight(R.lockRow.control, T.CONTROL_FLOOR, true)
            local lockRowH = math.max(T.LOCK_ROW_FLOOR or T.CONTROL_FLOOR, lockLabelH, lockToggleH, lockG.resetH)
            local lockHelperGap, lockDividerGap, lockDividerOffset = computeTimersLockRhythm(lockLabelH)

            R.lockRowContainer:ClearAllPoints()
            R.lockRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", lockG.labelX, y)
            R.lockRowContainer:SetSize(lockG.rowW, lockRowH)
            R.lockRow.label:ClearAllPoints()
            R.lockRow.label:SetPoint("LEFT", R.lockRowContainer, "LEFT", 0, 0)
            R.lockRow.control:ClearAllPoints()
            R.lockRow.control:SetPoint("LEFT", R.lockRow.label, "RIGHT", T.LABEL_TO_CONTROL_GAP, 0)
            R.resetAnchorButton:ClearAllPoints()
            R.resetAnchorButton:SetPoint("LEFT", R.lockRow.control, "RIGHT", T.LOCK_TOGGLE_TO_RESET_GAP, 0)
            y = y - lockRowH

            if isTimersTextActive(R.lockStateHelper) then
                local lockHelperH = measureTimersSingleLineHeight(R.lockStateHelper, G.contentSpan, T.HELPER_FLOOR, true)
                y = y - lockHelperGap
                R.lockStateHelper:ClearAllPoints()
                R.lockStateHelper:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", G.labelColX, y)
                y = y - lockHelperH
            else
                parkTimersControl(R.lockStateHelper)
            end

            local dividerY = y - lockDividerOffset
            R.divider:ClearAllPoints()
            R.divider:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", G.labelColX, dividerY)
            R.divider:SetPoint("TOPRIGHT", scrollChild, "TOPRIGHT", -T.CONTENT_RIGHT, dividerY)
            R.divider:SetHeight(1)
            R.divider:SetColorTexture(0.24, 0.27, 0.32, 0.10)
            y = y - lockDividerGap

            local modulesHeaderH = measureTimersSingleLineHeight(R.modulesHeader, G.contentSpan, T.SECTION_HEADER_FLOOR, true)
            R.modulesHeader:ClearAllPoints()
            R.modulesHeader:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", G.labelColX, y)
            y = y - modulesHeaderH - T.SECTION_HEADER_BOTTOM_GAP

            R.batchEnableButton:SetSize(batchG.buttonW, T.BATCH_BUTTON_H)
            R.batchDisableButton:SetSize(batchG.buttonW, T.BATCH_BUTTON_H)
            batchStatusMaxWidth = batchG.statusW
            local batchTitleH = measureTimersSingleLineHeight(R.batchActionsTitle, batchG.titleW, T.SECTION_HEADER_FLOOR, true)
            local batchScopeActive = isTimersTextActive(R.batchActionsScope)
            local batchScopeH = measureTimersSingleLineHeight(R.batchActionsScope, math.max(1, batchG.scopeW), T.HELPER_FLOOR, batchScopeActive)
            local batchTitleRowH = math.max(batchTitleH, batchScopeH)
            local batchStatusActive = isTimersTextActive(R.batchStatus)
            local batchStatusH = measureTimersSingleLineHeight(R.batchStatus, batchG.statusW, T.HELPER_FLOOR, batchStatusActive)
            local batchStatusGap = batchStatusActive and T.CARD_BUTTONS_TO_STATUS_GAP or 0
            local batchCardH = T.CARD_PADDING + batchTitleRowH + T.CARD_LABEL_TO_BUTTONS_GAP + T.BATCH_BUTTON_H + batchStatusGap + batchStatusH + T.CARD_PADDING
            local batchButtonsTop = T.CARD_PADDING + batchTitleRowH + T.CARD_LABEL_TO_BUTTONS_GAP

            R.batchActionsCard:ClearAllPoints()
            R.batchActionsCard:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", batchG.cardX, y)
            R.batchActionsCard:SetSize(batchG.cardW, batchCardH)
            R.batchActionsTitle:ClearAllPoints()
            R.batchActionsTitle:SetPoint("TOPLEFT", R.batchActionsCard, "TOPLEFT", T.CARD_PADDING, -T.CARD_PADDING)
            if batchScopeActive then
                R.batchActionsScope:ClearAllPoints()
                R.batchActionsScope:SetPoint("TOPLEFT", R.batchActionsCard, "TOPLEFT", batchG.scopeX, -T.CARD_PADDING)
            else
                parkTimersControl(R.batchActionsScope)
            end
            R.batchEnableButton:ClearAllPoints()
            R.batchEnableButton:SetPoint("TOPLEFT", R.batchActionsCard, "TOPLEFT", batchG.enableX, -batchButtonsTop)
            R.batchDisableButton:ClearAllPoints()
            R.batchDisableButton:SetPoint("TOPLEFT", R.batchActionsCard, "TOPLEFT", batchG.disableX, -batchButtonsTop)
            if batchStatusActive then
                R.batchStatus:ClearAllPoints()
                R.batchStatus:SetPoint("TOPLEFT", R.batchActionsCard, "TOPLEFT", T.CARD_PADDING, -(batchButtonsTop + T.BATCH_BUTTON_H + batchStatusGap))
            else
                parkTimersControl(R.batchStatus)
            end
            y = y - batchCardH - T.MODULE_CARD_TO_ROWS_GAP

            local function layoutModuleRow(spec, topY)
                if not spec or not spec.row then
                    return topY
                end
                if type(spec.visibilityOverride) == "function" and not spec.visibilityOverride(layoutDb) then
                    parkTimersControl(spec.row.label)
                    parkTimersControl(spec.row.control)
                    if spec.unavailableHelper then
                        parkTimersControl(spec.unavailableHelper)
                    end
                    for _, fs in ipairs(spec.explainers or {}) do
                        parkTimersControl(fs)
                    end
                    return topY
                end

                spec.row:Layout(moduleG.controlW)
                local labelH = measureTimersSingleLineHeight(spec.row.label, moduleG.labelW, T.LABEL_FLOOR, true)
                local controlH = measureTimersControlHeight(spec.row.control, T.CONTROL_FLOOR, true)
                local rowH = math.max(T.ROW_FLOOR, labelH, controlH)
                local labelTop = math.floor((rowH - labelH) / 2)
                local controlTop = math.floor((rowH - controlH) / 2)

                spec.row.label:ClearAllPoints()
                spec.row.label:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", moduleG.labelX, topY - labelTop)
                spec.row.control:ClearAllPoints()
                spec.row.control:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", moduleG.controlX, topY - controlTop)

                local nextY = topY - rowH

                local function layoutExplainersBlock(startY, gapBefore)
                    local activeExplainers = {}
                    for _, fs in ipairs(spec.explainers or {}) do
                        if isTimersTextActive(fs) then
                            activeExplainers[#activeExplainers + 1] = fs
                        else
                            parkTimersControl(fs)
                        end
                    end
                    if #activeExplainers == 0 then
                        return startY
                    end

                    local nextExplainerY = startY - math.max(0, tonumber(gapBefore) or 0)
                    for idx, fs in ipairs(activeExplainers) do
                        local explainH = measureTimersWrappedTextHeight(fs, moduleG.helperW, T.HELPER_FLOOR, true)
                        fs:ClearAllPoints()
                        fs:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", moduleG.helperX, nextExplainerY)
                        nextExplainerY = nextExplainerY - explainH
                        if idx < #activeExplainers then
                            nextExplainerY = nextExplainerY - T.MODULE_EXPLAIN_LINE_GAP
                        end
                    end

                    return nextExplainerY - math.max(0, tonumber(spec.explainBlockGap) or T.MODULE_EXPLAIN_BLOCK_GAP)
                end

                if spec.explainBeforeChildren then
                    nextY = layoutExplainersBlock(nextY, T.MODULE_ROW_TO_EXPLAIN_GAP)
                end

                local childRowsLaidOut = 0
                for _, child in ipairs(spec.childRows or {}) do
                    local childVisible = child.row and (not child.isVisible or child.isVisible(layoutDb))
                    if childVisible then
                        child.row:Layout(moduleG.controlW)
                        local childLabelW = math.max(1, moduleG.labelW - T.MODULE_CHILD_INDENT)
                        local childLabelH = measureTimersSingleLineHeight(child.row.label, childLabelW, T.LABEL_FLOOR, true)
                        local childControlH = measureTimersControlHeight(child.row.control, T.CONTROL_FLOOR, true)
                        local childRowH = math.max(T.ROW_FLOOR, childLabelH, childControlH)
                        local childLabelTop = math.floor((childRowH - childLabelH) / 2)
                        local childControlTop = math.floor((childRowH - childControlH) / 2)

                        nextY = nextY - T.MODULE_CHILD_ROW_GAP
                        child.row.label:ClearAllPoints()
                        child.row.label:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", moduleG.labelX + T.MODULE_CHILD_INDENT, nextY - childLabelTop)
                        child.row.control:ClearAllPoints()
                        child.row.control:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", moduleG.controlX, nextY - childControlTop)
                        nextY = nextY - childRowH
                        childRowsLaidOut = childRowsLaidOut + 1
                    elseif child.row then
                        parkTimersControl(child.row.label)
                        parkTimersControl(child.row.control)
                    end
                end
                if childRowsLaidOut > 0 then
                    nextY = nextY - T.MODULE_CHILD_ROW_GAP
                end
                local helperActive = isTimersTextActive(spec.unavailableHelper)
                if helperActive then
                    local helperH = measureTimersSingleLineHeight(spec.unavailableHelper, moduleG.helperW, T.HELPER_FLOOR, true)
                    nextY = nextY - T.MODULE_ROW_TO_HELPER_GAP
                    spec.unavailableHelper:ClearAllPoints()
                    spec.unavailableHelper:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", moduleG.helperX, nextY)
                    nextY = nextY - helperH
                elseif spec.unavailableHelper then
                    parkTimersControl(spec.unavailableHelper)
                end

                if not spec.explainBeforeChildren then
                    nextY = layoutExplainersBlock(
                        nextY,
                        helperActive and T.MODULE_HELPER_TO_EXPLAIN_GAP or T.MODULE_ROW_TO_EXPLAIN_GAP
                    )
                end
                return nextY
            end

            for _, module in ipairs(moduleRows) do
                y = layoutModuleRow(module, y)
            end

            R.dividerFont:ClearAllPoints()
            R.dividerFont:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", G.labelColX, y)
            R.dividerFont:SetPoint("TOPRIGHT", scrollChild, "TOPRIGHT", -T.CONTENT_RIGHT, y)
            R.dividerFont:SetHeight(1)
            R.dividerFont:SetColorTexture(0.24, 0.27, 0.32, 0.58)
            y = y - T.SECTION_TO_NEXT_DIVIDER_GAP

            local appearanceHeaderH = measureTimersSingleLineHeight(R.appearanceLayoutHeader, G.contentSpan, T.SECTION_HEADER_FLOOR, true)
            R.appearanceLayoutHeader:ClearAllPoints()
            R.appearanceLayoutHeader:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", G.labelColX, y)
            y = y - appearanceHeaderH - T.SECTION_HEADER_BOTTOM_GAP

            setPickerWidth(R.fontDropdown, appearanceG.fontPickerW)
            setPickerWidth(R.aspectDropdown, appearanceG.mainControlW)
            if R.iconEdgeControl and R.iconEdgeControl.Layout then
                R.iconEdgeControl:Layout(appearanceG.mainControlW)
            end
            if R.sizeStepper and R.sizeStepper.SetWidth then
                R.sizeStepper:SetWidth(appearanceG.fontSizeW)
            elseif R.sizeEdit then
                R.sizeEdit:SetSize(appearanceG.fontSizeW, T.CONTROL_FLOOR)
            end
            R.iconSizeSlider:SetWidth(appearanceG.mainControlW)
            R.iconOffsetXSlider:SetWidth(appearanceG.offsetSliderW)
            R.iconOffsetYSlider:SetWidth(appearanceG.offsetSliderW)
            R.iconOffsetAxisXMini:SetWidth(appearanceG.axisLabelW)
            R.iconOffsetAxisYMini:SetWidth(appearanceG.axisLabelW)
            R.coords:SetSize(appearanceG.mainControlW, T.CONTROL_FLOOR)

            local fontLabelH = measureTimersSingleLineHeight(R.fontLabel, appearanceG.labelW, T.LABEL_FLOOR, true)
            local fontPickerH = measureTimersControlHeight(R.fontDropdown.control, T.CONTROL_FLOOR, true)
            local fontSizeControl = (R.sizeStepper and R.sizeStepper.control) or R.sizeEdit
            local fontSizeH = measureTimersControlHeight(fontSizeControl, T.CONTROL_FLOOR, fontSizeControl ~= nil)
            local fontStackH = appearanceG.fontDropSizeBelow and (fontPickerH + T.FONT_STACK_GAP + fontSizeH) or math.max(fontPickerH, fontSizeH)
            local fontRowH = math.max(T.ROW_FLOOR, fontLabelH, fontStackH)
            local fontLabelTop = math.floor((fontRowH - fontLabelH) / 2)
            local fontStackTop = appearanceG.fontDropSizeBelow and math.floor((fontRowH - fontStackH) / 2) or 0
            local fontControlTop = appearanceG.fontDropSizeBelow and fontStackTop or math.floor((fontRowH - fontPickerH) / 2)
            local fontSizeTop = appearanceG.fontDropSizeBelow and (fontStackTop + fontPickerH + T.FONT_STACK_GAP) or math.floor((fontRowH - fontSizeH) / 2)

            R.fontRowContainer:ClearAllPoints()
            R.fontRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", appearanceG.labelX, y)
            R.fontRowContainer:SetSize(appearanceG.rowContainerW, fontRowH)
            R.fontLabel:ClearAllPoints()
            R.fontLabel:SetPoint("TOPLEFT", R.fontRowContainer, "TOPLEFT", 0, -fontLabelTop)
            R.fontDropdown.control:ClearAllPoints()
            R.fontDropdown.control:SetPoint("TOPLEFT", R.fontRowContainer, "TOPLEFT", appearanceG.controlX - appearanceG.labelX, -fontControlTop)
            if fontSizeControl then
                fontSizeControl:ClearAllPoints()
                fontSizeControl:SetPoint("TOPLEFT", R.fontRowContainer, "TOPLEFT", appearanceG.fontSizeX - appearanceG.labelX, -fontSizeTop)
            end
            y = y - fontRowH

            local coordsLabelH = measureTimersSingleLineHeight(R.coordsLabel, appearanceG.labelW, T.LABEL_FLOOR, true)
            local coordsH = measureTimersControlHeight(R.coords, T.CONTROL_FLOOR, true)
            local coordsRowH = math.max(T.ROW_FLOOR, coordsLabelH, coordsH)
            local coordsLabelTop = math.floor((coordsRowH - coordsLabelH) / 2)
            local coordsTop = math.floor((coordsRowH - coordsH) / 2)
            R.coordsLabel:ClearAllPoints()
            R.coordsLabel:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", appearanceG.labelX, y - coordsLabelTop)
            R.coords:ClearAllPoints()
            R.coords:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", appearanceG.controlX, y - coordsTop)
            y = y - coordsRowH

            local iconSizeLabelH = measureTimersSingleLineHeight(R.iconSizeSlider.label, appearanceG.labelW, T.LABEL_FLOOR, true)
            local iconSizeControlH = measureTimersControlHeight(R.iconSizeSlider.control, T.CONTROL_FLOOR, true)
            local iconSizeRowH = math.max(T.ROW_FLOOR, iconSizeLabelH, iconSizeControlH)
            local iconSizeLabelTop = math.floor((iconSizeRowH - iconSizeLabelH) / 2)
            local iconSizeControlTop = math.floor((iconSizeRowH - iconSizeControlH) / 2)
            R.iconSizeSlider.label:ClearAllPoints()
            R.iconSizeSlider.label:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", appearanceG.labelX, y - iconSizeLabelTop)
            R.iconSizeSlider.control:ClearAllPoints()
            R.iconSizeSlider.control:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", appearanceG.controlX, y - iconSizeControlTop)
            y = y - iconSizeRowH

            parkTimersControl(R.iconOffsetXSlider.label)
            parkTimersControl(R.iconOffsetYSlider.label)
            local offsetPairLabelH = measureTimersSingleLineHeight(R.iconOffsetPairLabel, appearanceG.labelW, T.LABEL_FLOOR, true)
            local axisXH = measureTimersSingleLineHeight(R.iconOffsetAxisXMini, appearanceG.axisLabelW, T.MINI_LABEL_FLOOR, true)
            local axisYH = measureTimersSingleLineHeight(R.iconOffsetAxisYMini, appearanceG.axisLabelW, T.MINI_LABEL_FLOOR, true)
            local offsetXControlH = measureTimersControlHeight(R.iconOffsetXSlider.control, T.CONTROL_FLOOR, true)
            local offsetYControlH = measureTimersControlHeight(R.iconOffsetYSlider.control, T.CONTROL_FLOOR, true)
            local offsetLine1H = math.max(axisXH, offsetXControlH)
            local offsetLine2H = math.max(axisYH, offsetYControlH)
            local offsetStackH = offsetLine1H + T.AXIS_LINE_GAP + offsetLine2H
            local offsetRowH = math.max(T.OFFSET_ROW_FLOOR, offsetPairLabelH, offsetStackH)
            local offsetLabelTop = math.floor((offsetRowH - offsetPairLabelH) / 2)
            local offsetStackTop = math.floor((offsetRowH - offsetStackH) / 2)
            local offsetLine2Top = offsetStackTop + offsetLine1H + T.AXIS_LINE_GAP

            R.iconOffsetRowContainer:ClearAllPoints()
            R.iconOffsetRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", appearanceG.labelX, y)
            R.iconOffsetRowContainer:SetSize(appearanceG.rowContainerW, offsetRowH)
            R.iconOffsetPairLabel:ClearAllPoints()
            R.iconOffsetPairLabel:SetPoint("TOPLEFT", R.iconOffsetRowContainer, "TOPLEFT", 0, -offsetLabelTop)
            R.iconOffsetAxisXMini:ClearAllPoints()
            R.iconOffsetAxisXMini:SetPoint("TOPLEFT", R.iconOffsetRowContainer, "TOPLEFT", appearanceG.controlX - appearanceG.labelX, -(offsetStackTop + math.floor((offsetLine1H - axisXH) / 2)))
            R.iconOffsetXSlider.control:ClearAllPoints()
            R.iconOffsetXSlider.control:SetPoint("TOPLEFT", R.iconOffsetRowContainer, "TOPLEFT", appearanceG.offsetSliderX - appearanceG.labelX, -(offsetStackTop + math.floor((offsetLine1H - offsetXControlH) / 2)))
            R.iconOffsetAxisYMini:ClearAllPoints()
            R.iconOffsetAxisYMini:SetPoint("TOPLEFT", R.iconOffsetRowContainer, "TOPLEFT", appearanceG.controlX - appearanceG.labelX, -(offsetLine2Top + math.floor((offsetLine2H - axisYH) / 2)))
            R.iconOffsetYSlider.control:ClearAllPoints()
            R.iconOffsetYSlider.control:SetPoint("TOPLEFT", R.iconOffsetRowContainer, "TOPLEFT", appearanceG.offsetSliderX - appearanceG.labelX, -(offsetLine2Top + math.floor((offsetLine2H - offsetYControlH) / 2)))
            y = y - offsetRowH

            local iconEdgeLabelH = measureTimersSingleLineHeight(R.iconEdgeLabel, appearanceG.labelW, T.LABEL_FLOOR, true)
            local iconEdgeControlH = measureTimersControlHeight(R.iconEdgeControl and R.iconEdgeControl.control or nil, T.CONTROL_FLOOR, R.iconEdgeControl and R.iconEdgeControl.control ~= nil)
            local iconEdgeRowH = math.max(T.ROW_FLOOR, iconEdgeLabelH, iconEdgeControlH)
            local iconEdgeLabelTop = math.floor((iconEdgeRowH - iconEdgeLabelH) / 2)
            local iconEdgeControlTop = math.floor((iconEdgeRowH - iconEdgeControlH) / 2)
            R.iconEdgeLabel:ClearAllPoints()
            R.iconEdgeLabel:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", appearanceG.labelX, y - iconEdgeLabelTop)
            if R.iconEdgeControl and R.iconEdgeControl.control then
                R.iconEdgeControl.control:ClearAllPoints()
                R.iconEdgeControl.control:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", appearanceG.controlX, y - iconEdgeControlTop)
            end
            y = y - iconEdgeRowH

            local aspectLabelH = measureTimersSingleLineHeight(R.aspectLabel, appearanceG.labelW, T.LABEL_FLOOR, true)
            local aspectControlH = measureTimersControlHeight(R.aspectDropdown.control, T.CONTROL_FLOOR, true)
            local aspectRowH = math.max(T.ROW_FLOOR, aspectLabelH, aspectControlH)
            local aspectLabelTop = math.floor((aspectRowH - aspectLabelH) / 2)
            local aspectControlTop = math.floor((aspectRowH - aspectControlH) / 2)
            R.aspectLabel:ClearAllPoints()
            R.aspectLabel:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", appearanceG.labelX, y - aspectLabelTop)
            R.aspectDropdown.control:ClearAllPoints()
            R.aspectDropdown.control:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", appearanceG.controlX, y - aspectControlTop)
            y = y - aspectRowH

            local extentObjects = {
                R.header,
                R.masterRowContainer,
                R.lockRowContainer,
                R.lockStateHelper,
                R.divider,
                R.modulesHeader,
                R.batchActionsCard,
                R.dividerFont,
                R.appearanceLayoutHeader,
                R.fontRowContainer,
                R.coordsLabel,
                R.coords,
                R.iconSizeSlider and R.iconSizeSlider.label or nil,
                R.iconSizeSlider and R.iconSizeSlider.control or nil,
                R.iconOffsetRowContainer,
                R.iconEdgeLabel,
                R.iconEdgeControl and R.iconEdgeControl.control or nil,
                R.aspectLabel,
                R.aspectDropdown and R.aspectDropdown.control or nil,
            }
            for _, module in ipairs(moduleRows) do
                if module and module.row then
                    extentObjects[#extentObjects + 1] = module.row.label
                    extentObjects[#extentObjects + 1] = module.row.control
                end
                for _, child in ipairs(module and module.childRows or {}) do
                    if child and child.row then
                        extentObjects[#extentObjects + 1] = child.row.label
                        extentObjects[#extentObjects + 1] = child.row.control
                    end
                end
                if module and module.unavailableHelper then
                    extentObjects[#extentObjects + 1] = module.unavailableHelper
                end
                for _, fs in ipairs(module and module.explainers or {}) do
                    extentObjects[#extentObjects + 1] = fs
                end
            end
            local measuredExtent = measureSettingsVisibleContentExtent(scrollChild, extentObjects)
            local visibleExtent = (measuredExtent and math.ceil(measuredExtent)) or nil
            local fallbackExtent = math.abs(y)
            local used = (visibleExtent or fallbackExtent) + T.BOTTOM_PAD
            local contentHeight = math.max(scrollFrame:GetHeight(), used)
            scrollChild:SetHeight(contentHeight)
            updateScrollBehavior(scrollFrame, scrollChild)
        end

        self._layout = layout

        local registeredHooksApi = nil
        local function ensureOptionsHooksRegistered()
            local hooksApi = getModulesApi()
            if not hooksApi or not hooksApi.RegisterOptionsHooks then
                return
            end
            if registeredHooksApi == hooksApi then
                return
            end

            hooksApi:RegisterOptionsHooks({
                onTimersPositionChanged = function(x, y)
                    if coords and not coords:HasFocus() then
                        setTimersCoordsDisplay(coords, x, y)
                    end
                end,
            })
            registeredHooksApi = hooksApi
        end

        ensureOptionsHooksRegistered()
        self._ensureOptionsHooksRegistered = ensureOptionsHooksRegistered

        registerRefreshCallback(function()
            if shouldSuppressSettingsFirstOpenExternalRefresh(self) then
                return
            end
            if self._refresh then
                self._refresh()
            end
        end, self)
        scrollFrame:SetScript("OnSizeChanged", function()
            if handleSettingsFirstOpenSizeReady(self, "size_changed") then
                return
            end
            if shouldSuppressSettingsFirstOpenExternalRefresh(self) then
                return
            end
            if self._layout then self._layout() end
        end)
        self._settingsFirstOpenKey = "timers"
        self._settingsFirstOpenSizeTarget = scrollFrame
        self._settingsFirstOpenRender = function(panel)
            if panel._ensureOptionsHooksRegistered then
                panel._ensureOptionsHooksRegistered()
            end
            if panel._layout then
                panel._layout()
            end
            if panel._refresh then
                panel._refresh()
            end
        end
        self._settingsFirstOpenIsReady = function(panel)
            local sizeControl = (sizeStepper and sizeStepper.control) or sizeEdit
            local useHostedChrome = isPanelUsingCustomSettingsWindowHost(panel)
            return panelHasSizedViewport(scrollFrame)
                and header ~= nil
                and (useHostedChrome or header:IsShown())
                and lockRowContainer ~= nil and lockRowContainer:IsShown()
                and batchActionsCard ~= nil and batchActionsCard:IsShown()
                and sizeControl ~= nil and sizeControl:IsShown()
                and coords ~= nil and coords:IsShown()
                and (tonumber(scrollChild:GetHeight()) or 0) >= math.max(tonumber(scrollFrame:GetHeight()) or 0, 1)
        end
        settingsSearchRuntime.endDescriptorCapture(self)
        refresh()
    end

    panel:SetScript("OnShow", function(self)
        ensureSettingsCanvasPanelAnchored(self)
        self:EnsureBuilt()
        if not handleSettingsFirstOpenPanelShow(self) then
            withPanelHydration(self, function()
                if self._ensureOptionsHooksRegistered then
                    self._ensureOptionsHooksRegistered()
                end
                if self._layout then self._layout() end
                if self._refresh then self._refresh() end
            end)
        end
        self._timersLiveSyncElapsed = 0
    end)
    panel:HookScript("OnHide", function(self)
        handleSettingsFirstOpenPanelHide(self)
    end)
    panel:HookScript("OnUpdate", function(self, elapsed)
        if not self:IsShown() then return end
        self._timersLiveSyncElapsed = (self._timersLiveSyncElapsed or 0) + (elapsed or 0)
        if self._timersLiveSyncElapsed < 0.15 then
            return
        end
        self._timersLiveSyncElapsed = 0
        if self._syncTimersLiveFields then
            self._syncTimersLiveFields()
        end
    end)

    return panel
end

local function createInterruptTrackerPanel()
    local panel = CreateFrame("Frame")
    panel.name = "Interrupt Tracker"
    panel._paSearchSectionKey = "interrupt"
    panel._paSearchSectionName = panel.name
    local INTERRUPT_FIRST_OPEN_DEFERRED_DELAYS = { 0, 0.05 }

    local function interruptTrackerHasFullContent(self)
        if not self then
            return false
        end
        local scrollFrame = self._interruptTrackerScrollFrame
        local scrollChild = self._interruptTrackerScrollChild
        local widgets = self._interruptTrackerWidgets
        if not scrollFrame or not scrollChild or not widgets then
            return false
        end
        if not panelHasSizedViewport(scrollFrame) then
            return false
        end

        local appearanceCard = widgets.appearanceCard
        local guidedPreviewCard = widgets.guidedPreviewCard
        local alertCard = widgets.alertCard
        local widthLabel = widgets.widthLabel
        local widthControl = widgets.widthStepper and widgets.widthStepper.control or nil
        local guidedPreviewSample = widgets.guidedPreviewSample
        local guidedPreviewLegend = widgets.guidedPreviewLegend
        local guidedPreviewRow = widgets.guidedPreviewRows and widgets.guidedPreviewRows[1] or nil
        local alertSoundControl = widgets.alertSound and widgets.alertSound.control or nil
        local alertScopeControl = widgets.alertScope and widgets.alertScope.control or nil
        if not appearanceCard or not guidedPreviewCard or not alertCard or not widthLabel or not widthControl or not guidedPreviewSample or not guidedPreviewLegend or not guidedPreviewRow or not alertSoundControl or not alertScopeControl then
            return false
        end
        if not appearanceCard:IsShown() or not guidedPreviewCard:IsShown() or not alertCard:IsShown() then
            return false
        end
        if not widthLabel:IsShown() or not widthControl:IsShown() or not guidedPreviewSample:IsShown() or not guidedPreviewLegend:IsShown() or not guidedPreviewRow:IsShown() or not alertSoundControl:IsShown() or not alertScopeControl:IsShown() then
            return false
        end

        local appearanceH = tonumber(appearanceCard:GetHeight()) or 0
        local guidedH = tonumber(guidedPreviewCard:GetHeight()) or 0
        local alertH = tonumber(alertCard:GetHeight()) or 0
        local lockRowH = tonumber(widgets.lockRowContainer and widgets.lockRowContainer:GetHeight()) or 0
        local contentH = tonumber(scrollChild:GetHeight()) or 0
        local viewportH = tonumber(scrollFrame:GetHeight()) or 0
        local requiredContentH = appearanceH + guidedH + alertH + lockRowH

        if appearanceH <= 1 or guidedH <= 1 or alertH <= 1 or lockRowH <= 1 then
            return false
        end
        if contentH < math.max(viewportH, requiredContentH) then
            return false
        end

        local appearanceBottom = tonumber(appearanceCard:GetBottom()) or 0
        local guidedTop = tonumber(guidedPreviewCard:GetTop()) or 0
        local guidedBottom = tonumber(guidedPreviewCard:GetBottom()) or 0
        local alertTop = tonumber(alertCard:GetTop()) or 0
        local alertBottom = tonumber(alertCard:GetBottom()) or 0
        if appearanceBottom <= 0 or guidedTop <= 0 or guidedBottom <= 0 or alertTop <= 0 or alertBottom <= 0 then
            return false
        end
        if appearanceBottom <= guidedTop then
            return false
        end
        if guidedBottom <= alertTop then
            return false
        end

        return true
    end

    local function setInterruptTrackerBootstrapActive(state)
        if PortalAuthority and PortalAuthority.SetSettingsBootstrapActive then
            PortalAuthority:SetSettingsBootstrapActive(state)
        end
    end

    local function getInterruptTrackerFirstOpenGeneration(self)
        return math.max(0, tonumber(self and self._interruptFirstOpenGeneration) or 0)
    end

    local function resetInterruptTrackerFirstOpenState(self)
        if not self then
            return 0
        end
        if self.StopGuidedPreviewTicker then
            self:StopGuidedPreviewTicker()
        end
        local generation = getInterruptTrackerFirstOpenGeneration(self) + 1
        self._interruptFirstOpenGeneration = generation
        self._interruptFirstOpenState = "idle"
        self._interruptQueuedPreviewReason = nil
        self._interruptPreviewRefreshPending = nil
        self._interruptPreviewRefreshToken = (tonumber(self._interruptPreviewRefreshToken) or 0) + 1
        setInterruptTrackerBootstrapActive("none")
        return generation
    end

    local function completeInterruptTrackerFirstOpen(self, generation, ready)
        if not self then
            return false
        end
        if self._interruptFirstOpenState ~= "pending" then
            return false
        end
        if getInterruptTrackerFirstOpenGeneration(self) ~= generation then
            return false
        end
        self._interruptFirstOpenState = ready and "ready" or "idle"
        self._interruptFirstOpenGeneration = generation + 1
        setInterruptTrackerBootstrapActive("none")
        return true
    end

    local function interruptTrackerBootstrapShouldBail(self, generation)
        if not self then
            return true
        end
        if getInterruptTrackerFirstOpenGeneration(self) ~= generation then
            return true
        end
        if self._interruptFirstOpenState ~= "pending" then
            return true
        end
        if self._interruptClosing then
            resetInterruptTrackerFirstOpenState(self)
            return true
        end
        if not self.IsShown or not self:IsShown() then
            resetInterruptTrackerFirstOpenState(self)
            return true
        end
        return false
    end

    local function runInterruptTrackerFirstOpenPass(self, generation, source)
        if interruptTrackerBootstrapShouldBail(self, generation) then
            return false
        end

        if self._runInterruptTrackerVisibleFullLayout then
            withPanelHydration(self, function()
                self._runInterruptTrackerVisibleFullLayout(source or "on_show")
            end)
        elseif self._routeInterruptTrackerRefresh then
            withPanelHydration(self, function()
                self._routeInterruptTrackerRefresh(source or "on_show")
            end)
        end

        return interruptTrackerHasFullContent(self)
    end

    local function queueInterruptTrackerFirstOpenFollowUp(self, generation, passIndex)
        local attemptIndex = math.max(0, tonumber(passIndex) or 0)
        local delay = INTERRUPT_FIRST_OPEN_DEFERRED_DELAYS[attemptIndex + 1]
        if delay == nil then
            completeInterruptTrackerFirstOpen(self, generation, false)
            return
        end

        local function run()
            if interruptTrackerBootstrapShouldBail(self, generation) then
                return
            end

            local sized = panelHasSizedViewport(self and self._interruptTrackerScrollFrame)
            local ready = runInterruptTrackerFirstOpenPass(self, generation, sized and "size_changed" or "on_show")
            if ready then
                completeInterruptTrackerFirstOpen(self, generation, true)
                return
            end

            queueInterruptTrackerFirstOpenFollowUp(self, generation, attemptIndex + 1)
        end

        if C_Timer and C_Timer.After then
            C_Timer.After(delay, run)
        else
            run()
        end
    end

    local function startInterruptTrackerFirstOpenBootstrap(self)
        if not self then
            return
        end
        if self._interruptFirstOpenState == "ready" or self._interruptFirstOpenState == "pending" then
            return
        end

        local generation = getInterruptTrackerFirstOpenGeneration(self) + 1
        self._interruptFirstOpenGeneration = generation
        self._interruptFirstOpenState = "pending"
        setInterruptTrackerBootstrapActive("interrupt")
        if runInterruptTrackerFirstOpenPass(self, generation, "on_show") then
            completeInterruptTrackerFirstOpen(self, generation, true)
            return
        end
        queueInterruptTrackerFirstOpenFollowUp(self, generation, 0)
    end

    panel.EnsureBuilt = function(self)
        if self._initialized and self._layout and self._refresh then
            return
        end

        resetInterruptTrackerFirstOpenState(self)
        resetSettingsFirstOpenPanelState(self)
        ensureDatabase()
        settingsSearchRuntime.beginDescriptorCapture(self)
        local scrollFrame, scrollChild = createScrollableChild(self)
        self._sizingFrame = scrollFrame
        self._interruptTrackerScrollFrame = scrollFrame
        self._interruptTrackerScrollChild = scrollChild
        if not scrollFrame or not scrollChild then
            settingsSearchRuntime.endDescriptorCapture(self)
            return
        end

        local widgets = {}
        self._interruptTrackerWidgets = widgets
        local panelRef = self
        local INTERRUPT_ROUTE_HIDDEN_FULL = "hidden_full_refresh"
        local INTERRUPT_ROUTE_VISIBLE_FULL = "visible_full_layout"
        local INTERRUPT_ROUTE_PASSIVE = "passive_sync"
        local GUIDED_PREVIEW_TICK_INTERVAL = 0.1
        local INTERRUPT_RUNTIME_BG_BAR = { 0.09, 0.10, 0.13 }
        local INTERRUPT_TRIGGER_ROUTE_MAP = {
            on_show = { visible = INTERRUPT_ROUTE_VISIBLE_FULL, hidden = INTERRUPT_ROUTE_HIDDEN_FULL },
            apply_setting = { visible = INTERRUPT_ROUTE_VISIBLE_FULL, hidden = INTERRUPT_ROUTE_HIDDEN_FULL },
            apply_visual_setting = { visible = INTERRUPT_ROUTE_PASSIVE, hidden = INTERRUPT_ROUTE_HIDDEN_FULL },
            size_changed = { visible = INTERRUPT_ROUTE_VISIBLE_FULL, hidden = INTERRUPT_ROUTE_HIDDEN_FULL },
            registered_refresh = { visible = INTERRUPT_ROUTE_VISIBLE_FULL, hidden = INTERRUPT_ROUTE_HIDDEN_FULL },
            passive_tick = { visible = INTERRUPT_ROUTE_PASSIVE, hidden = nil },
            hidden_refresh = { visible = INTERRUPT_ROUTE_HIDDEN_FULL, hidden = INTERRUPT_ROUTE_HIDDEN_FULL },
            guided_preview_relayout = { visible = INTERRUPT_ROUTE_VISIBLE_FULL, hidden = INTERRUPT_ROUTE_HIDDEN_FULL },
            guided_preview_repaint = { visible = INTERRUPT_ROUTE_PASSIVE, hidden = INTERRUPT_ROUTE_HIDDEN_FULL },
        }
        local refreshInterruptTrackerPanel = nil
        local layoutInterruptTrackerPanel = nil
        local passiveSyncInterruptTrackerPanel = nil
        local routeInterruptTrackerRefresh = nil
        local previewInterruptTrackerBackgroundOpacity = nil

        -- Module / DB adapter
        local moduleAdapter = {}

        function moduleAdapter:GetModule()
            return PortalAuthority and PortalAuthority.Modules and PortalAuthority.Modules.registry and PortalAuthority.Modules.registry.interruptTracker or nil
        end

        function moduleAdapter:GetDB()
            local module = self:GetModule()
            local shared = module and module._shared or nil
            if shared and shared.EnsureDB then
                local ok, moduleDb = pcall(shared.EnsureDB)
                if ok and type(moduleDb) == "table" then
                    return moduleDb
                end
            end
            if module and module.GetDB then
                local ok, moduleDb = pcall(module.GetDB, module)
                if ok and type(moduleDb) == "table" then
                    return moduleDb
                end
            end
            PortalAuthorityDB = PortalAuthorityDB or {}
            PortalAuthorityDB.modules = PortalAuthorityDB.modules or {}
            PortalAuthorityDB.modules.interruptTracker = PortalAuthorityDB.modules.interruptTracker or {}
            return PortalAuthorityDB.modules.interruptTracker
        end

        function moduleAdapter:EnsureModule(initialize)
            local module = self:GetModule()
            if module and initialize and module.Initialize and not module.frame then
                local ok, err = pcall(module.Initialize, module)
                if not ok then
                    if type(debugSettingsLog) == "function" then
                        debugSettingsLog("interrupt tracker module init failed:", tostring(err))
                    end
                    return nil
                end
            end
            return module
        end

        function moduleAdapter:ApplySettings(refreshSource)
            refreshSource = tostring(refreshSource or "apply_setting")
            local module = self:EnsureModule(true)
            if module then
                if module.ApplySettings then
                    pcall(module.ApplySettings, module)
                elseif module.EvaluateVisibility then
                    pcall(module.EvaluateVisibility, module, "options-apply")
                end
            end
            if routeInterruptTrackerRefresh then
                routeInterruptTrackerRefresh(refreshSource)
            end
        end

        local function getModule()
            return moduleAdapter:GetModule()
        end

        local function getDB()
            return moduleAdapter:GetDB()
        end

        local function ensureModule(initialize)
            return moduleAdapter:EnsureModule(initialize)
        end

        local function applyModuleSettings(refreshSource)
            moduleAdapter:ApplySettings(refreshSource)
        end

        local function previewInterruptTrackerAlertSoundValue(value)
            local selected = normalizeSoundChoiceValue(value)
            if selected == nil or selected == "" then
                return
            end

            local soundFile = selected
            local media = getPortalMedia()
            if media and media.ResolveSoundFile then
                soundFile = media.ResolveSoundFile(selected)
            end
            if type(soundFile) == "string" then
                local asNum = tonumber(soundFile)
                if asNum then
                    soundFile = asNum
                end
            end
            if not soundFile or soundFile == "" then
                return
            end

            if type(soundFile) == "number" and PlaySound then
                PlaySound(soundFile, "Master")
            elseif PlaySoundFile then
                PlaySoundFile(soundFile, "Master")
            end
        end

        local function createPickerButton(parent, labelText, optionsProvider, getter, setter, onApplyCallback, pickerOpts)
            pickerOpts = type(pickerOpts) == "table" and pickerOpts or {}
            local label = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
            label:SetText(labelText or "")

            local button = CreateFrame("Button", nil, parent, "BackdropTemplate")
            button:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
                insets = { left = 0, right = 0, top = 0, bottom = 0 },
            })
            button:SetBackdropColor(0.10, 0.11, 0.14, 0.95)
            button:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
            button:SetHeight(22)
            button:SetWidth(math.max(132, math.floor(tonumber(pickerOpts.width) or 180)))
            button:EnableMouse(true)
            if type(pickerOpts.onRightClick) == "function" then
                button:RegisterForClicks("LeftButtonUp", "RightButtonUp")
            else
                button:RegisterForClicks("LeftButtonUp")
            end
            button:SetFrameStrata(parent and parent.GetFrameStrata and parent:GetFrameStrata() or "MEDIUM")
            button:SetFrameLevel((parent and parent.GetFrameLevel and parent:GetFrameLevel() or 0) + 10)

            local text = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 11)
            text:SetPoint("LEFT", button, "LEFT", 8, 0)
            text:SetPoint("RIGHT", button, "RIGHT", -18, 0)
            text:SetJustifyH("LEFT")
            text:SetTextColor(0.92, 0.92, 0.92, 1)

            local caret = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 10)
            caret:SetPoint("RIGHT", button, "RIGHT", -7, 0)
            caret:SetText("v")
            caret:SetTextColor(0.76, 0.76, 0.78, 1)
            button._paSelectEnabled = true
            local setVisualSelectedValue = nil

            local picker = CreatePicker(UIParent, {}, function(value)
                local selectedValue = value == nil and "" or value
                if setter then
                    setter(selectedValue)
                end
                setVisualSelectedValue(selectedValue)
                if onApplyCallback then
                    onApplyCallback()
                end
            end, {
                title = tostring(pickerOpts.title or "Select Option"),
                searchHint = tostring(pickerOpts.searchHint or "Search"),
                width = tonumber(pickerOpts.pickerWidth) or 420,
                height = tonumber(pickerOpts.pickerHeight) or 360,
                showSecondary = false,
                useOptionFontPreview = pickerOpts.useOptionFontPreview and true or false,
                useOptionTexturePreview = pickerOpts.useOptionTexturePreview and true or false,
                previewFontSize = tonumber(pickerOpts.previewFontSize) or 12,
                onOptionRightClick = pickerOpts.onOptionRightClick,
                showClearButton = false,
                footerHint = tostring(pickerOpts.footerHint or ""),
            })

            local currentLabel = ""
            local function setButtonLabel(labelTextValue)
                currentLabel = tostring(labelTextValue or "")
                text:SetWordWrap(false)
                if text.SetMaxLines then
                    text:SetMaxLines(1)
                end
                local maxWidth = math.max(20, (button:GetWidth() or 0) - 26)
                text:SetWidth(maxWidth)
                text:SetText(currentLabel)
                if pickerOpts and pickerOpts.ellipsis == false then
                    return
                end
                if text:GetStringWidth() <= maxWidth then
                    return
                end
                local cut = string.len(currentLabel)
                while cut > 0 do
                    local candidate = string.sub(currentLabel, 1, cut) .. "..."
                    text:SetText(candidate)
                    if text:GetStringWidth() <= maxWidth then
                        return
                    end
                    cut = cut - 1
                end
                text:SetText("...")
            end

            local function applyVisual(hovered)
                applySettingsWindowSelectButtonChrome(
                    button,
                    text,
                    caret,
                    hovered,
                    false,
                    button._paSelectEnabled ~= false,
                    function()
                        if hovered then
                            button:SetBackdropColor(0.16, 0.17, 0.20, 0.95)
                            button:SetBackdropBorderColor(0.30, 0.33, 0.38, 1.0)
                            caret:SetTextColor(0.88, 0.88, 0.90, 1)
                        else
                            button:SetBackdropColor(0.10, 0.11, 0.14, 0.95)
                            button:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
                            caret:SetTextColor(0.76, 0.76, 0.78, 1)
                        end
                    end
                )
            end

            local function buildOptions()
                local built = {}
                for _, option in ipairs(optionsProvider and optionsProvider() or {}) do
                    local value = option.value
                    if value == nil then
                        value = ""
                    end
                    built[#built + 1] = {
                        value = value,
                        label = tostring(option.label or value),
                        buttonLabel = tostring(option.buttonLabel or option.label or value),
                        secondary = tostring(option.secondary or ""),
                        previewFontPath = option.previewFontPath,
                        previewTexturePath = option.previewTexturePath or option.path,
                        aliases = option.aliases,
                    }
                end
                if #built == 0 then
                    built[1] = { value = "", label = "None", buttonLabel = "None", secondary = "" }
                end
                return built
            end

            local function resolveSelection(rawValue, options, allowRepair)
                if allowRepair == nil then
                    allowRepair = true
                end
                local selected = rawValue
                if selected == nil then
                    selected = ""
                end
                local selectedKey = tostring(selected)
                local selectedLabel = nil
                local emptyFallbackLabel = tostring(pickerOpts.emptyLabel or "None")
                for _, option in ipairs(options or {}) do
                    if tostring(option.value or "") == selectedKey then
                        selected = option.value
                        selectedLabel = tostring(option.buttonLabel or option.label or selectedKey)
                        break
                    end
                end
                if not selectedLabel then
                    if selectedKey == "" then
                        selected = ""
                        selectedLabel = emptyFallbackLabel
                    else
                        local first = options and options[1] or nil
                        if first then
                            selected = first.value
                            selectedLabel = tostring(first.buttonLabel or first.label or tostring(selected or ""))
                            if allowRepair and setter then
                                setter(selected)
                            end
                        else
                            selected = ""
                            selectedLabel = "None"
                        end
                    end
                end
                return selected, selectedLabel
            end

            setVisualSelectedValue = function(rawValue)
                local options = buildOptions()
                local selectedValue, labelTextValue = resolveSelection(rawValue, options, false)
                picker:SetSelectedValue(selectedValue)
                setButtonLabel(labelTextValue)
            end

            button:SetScript("OnEnter", function()
                applyVisual(true)
            end)
            button:SetScript("OnLeave", function()
                applyVisual(false)
            end)
            button:SetScript("OnClick", function(_, mouseButton)
                if mouseButton == "RightButton" then
                    if type(pickerOpts.onRightClick) == "function" then
                        pickerOpts.onRightClick(getter and getter() or "")
                    end
                    return
                end
                if picker and picker.IsShown and picker:IsShown() then
                    picker:Close()
                    return
                end
                local options = buildOptions()
                picker:SetOptions(options)
                picker:SetSelectedValue(getter and getter() or "")
                picker:Open(button)
            end)
            button:HookScript("OnShow", function()
                local options = buildOptions()
                local _, labelTextValue = resolveSelection(getter and getter() or "", options, false)
                setButtonLabel(labelTextValue)
            end)
            button:HookScript("OnSizeChanged", function()
                setButtonLabel(currentLabel)
            end)
            registerSettingsWindowVisualRefresh(button, function()
                applyVisual(button.IsMouseOver and button:IsMouseOver() or false)
            end)

            return {
                label = label,
                control = button,
                picker = picker,
                SetVisualSelectedValue = function(_, value)
                    setVisualSelectedValue(value)
                end,
                SetEnabled = function(_, enabled)
                    local allow = enabled and true or false
                    button._paSelectEnabled = allow
                    button:EnableMouse(allow)
                    button:SetAlpha(allow and 1 or 0.6)
                    text:SetAlpha(allow and 1 or 0.65)
                    caret:SetAlpha(allow and 1 or 0.65)
                    applyVisual(false)
                end,
                Refresh = function()
                    local options = buildOptions()
                    picker:SetOptions(options)
                    local selectedValue, labelTextValue = resolveSelection(getter and getter() or "", options, true)
                    picker:SetSelectedValue(selectedValue)
                    setButtonLabel(labelTextValue)
                end,
            }
        end

        local function createToggleRow(parent, labelText, getter, setter, refreshSource)
            return createPremiumSegmentedChoice(parent, labelText, nil, {
                { label = "Off", value = false, toggleState = "off" },
                { label = "On", value = true, toggleState = "on" },
            }, function(value)
                setter(value)
                applyModuleSettings(refreshSource or "apply_setting")
            end, {
                semantic = "toggle",
                normalizeValue = function(value)
                    return value and true or false
                end,
                getValue = getter,
                setValue = setter,
            })
        end

        local function createLockRow(parent, getter, setter, refreshSource)
            return createPremiumSegmentedChoice(parent, "Lock Position", nil, {
                { label = "Unlocked", value = false },
                { label = "Locked", value = true },
            }, function(value)
                setter(value)
                local module = ensureModule(true)
                if module and module.SetUnlocked then
                    pcall(module.SetUnlocked, module, not value)
                end
                applyModuleSettings(refreshSource or "apply_setting")
            end, {
                semantic = "selection",
                selectionVariant = "lock_meta",
                normalizeValue = function(value)
                    return value and true or false
                end,
                getValue = getter,
                setValue = setter,
            })
        end

        local function createStepper(parent, minValue, maxValue, getter, setter, onApplyCallback)
            if type(createCanonicalDockFontSizeStepperControl) == "function" then
                local control = createCanonicalDockFontSizeStepperControl(
                    parent,
                    "",
                    minValue,
                    maxValue,
                    1,
                    nil,
                    58,
                    onApplyCallback,
                    nil,
                    {
                        micro = true,
                        shiftMultiplier = 5,
                        getValue = function()
                            return getter()
                        end,
                        setValue = function(value)
                            setter(value)
                        end,
                    }
                )
                if control and control.label then
                    control.label:SetText("")
                    control.label:Hide()
                end
                return control
            end

            local label = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
            label:SetText("")
            label:Hide()

            local container = CreateFrame("Frame", nil, parent)
            container:SetHeight(22)
            container:SetWidth(58)

            local function createStepperButton(symbol)
                local button = CreateFrame("Button", nil, container)
                button:SetSize(10, 16)

                local text = createStyledFontString(button, "ARTWORK", "GameFontHighlight", 12)
                text:SetPoint("CENTER", button, "CENTER", 0, 0)
                text:SetText(symbol)
                text:SetTextColor(0.74, 0.74, 0.76, 1)
                button._text = text
                button._hovered = false
                button._pressed = false

                local function applyVisual(selfBtn)
                    if selfBtn._pressed then
                        selfBtn._text:SetTextColor(0.95, 0.95, 0.98, 1)
                        selfBtn:SetAlpha(0.82)
                    elseif selfBtn._hovered then
                        selfBtn._text:SetTextColor(0.95, 0.95, 0.98, 1)
                        selfBtn:SetAlpha(1)
                    else
                        selfBtn._text:SetTextColor(0.74, 0.74, 0.76, 1)
                        selfBtn:SetAlpha(1)
                    end
                end

                button:SetScript("OnEnter", function(selfBtn)
                    selfBtn._hovered = true
                    applyVisual(selfBtn)
                end)
                button:SetScript("OnLeave", function(selfBtn)
                    selfBtn._hovered = false
                    selfBtn._pressed = false
                    applyVisual(selfBtn)
                end)
                button:SetScript("OnMouseDown", function(selfBtn)
                    selfBtn._pressed = true
                    applyVisual(selfBtn)
                end)
                button:SetScript("OnMouseUp", function(selfBtn)
                    selfBtn._pressed = false
                    applyVisual(selfBtn)
                end)

                return button
            end

            local minusButton = createStepperButton("<")
            local plusButton = createStepperButton(">")
            local valueButton = CreateFrame("Button", nil, container)
            valueButton:SetHeight(16)

            local function layoutMicro()
                local gap = 3
                local buttonW = minusButton:GetWidth() or 10
                local containerW = container:GetWidth() or 58
                local valueW = math.max(20, math.min(28, containerW - (buttonW * 2) - (gap * 2)))
                local clusterW = (buttonW * 2) + valueW + (gap * 2)
                local startX = math.floor((containerW - clusterW) / 2)
                if startX < 0 then
                    startX = 0
                end

                minusButton:ClearAllPoints()
                minusButton:SetPoint("LEFT", container, "LEFT", startX, 0)

                valueButton:ClearAllPoints()
                valueButton:SetPoint("LEFT", minusButton, "RIGHT", gap, 0)
                valueButton:SetWidth(valueW)

                plusButton:ClearAllPoints()
                plusButton:SetPoint("LEFT", valueButton, "RIGHT", gap, 0)
            end

            layoutMicro()
            container:HookScript("OnSizeChanged", layoutMicro)

            local valueText = createStyledFontString(valueButton, "ARTWORK", "GameFontHighlightSmall", 11)
            valueText:SetPoint("CENTER", valueButton, "CENTER", 0, 0)
            valueText:SetTextColor(0.86, 0.86, 0.9, 1)

            local valueEdit = CreateFrame("EditBox", nil, valueButton)
            valueEdit:SetAllPoints(valueButton)
            valueEdit:SetAutoFocus(false)
            valueEdit:SetJustifyH("CENTER")
            valueEdit:SetTextInsets(0, 0, 0, 0)
            valueEdit:SetTextColor(1, 1, 1, 1)
            valueEdit:SetHighlightColor(1, 1, 1, 0.25)
            valueEdit:SetNumeric(true)
            applyGlobalFontToObject(valueEdit, 11)
            valueEdit:Hide()

            local currentValue = nil
            local editingValue = false
            local controlEnabled = true
            local stepValue = 1
            local microShiftMultiplier = 5

            local function normalize(v)
                local n = tonumber(v) or tonumber(minValue) or 0
                local minN = tonumber(minValue) or 0
                local maxN = tonumber(maxValue) or minN
                if maxN < minN then
                    minN, maxN = maxN, minN
                end
                if n < minN then n = minN end
                if n > maxN then n = maxN end
                n = minN + (math.floor(((n - minN) / stepValue) + 0.5) * stepValue)
                if n < minN then n = minN end
                if n > maxN then n = maxN end
                return math.floor(n + 0.5)
            end

            local function fmt(v)
                return tostring(math.floor((tonumber(v) or 0) + 0.5))
            end

            local function setValue(newValue, triggerApply)
                local n = normalize(newValue)
                currentValue = n
                if setter then
                    setter(n)
                end
                valueText:SetText(fmt(n))
                if valueEdit:IsShown() then
                    valueEdit:SetText(fmt(n))
                end
                if triggerApply and onApplyCallback then
                    onApplyCallback()
                end
            end

            local function beginEdit()
                editingValue = true
                valueText:Hide()
                valueEdit:SetText(fmt(currentValue or minValue))
                valueEdit:Show()
                valueEdit:SetFocus()
                valueEdit:HighlightText()
            end

            local function endEdit(commit)
                if not editingValue then
                    return
                end
                editingValue = false
                if commit then
                    local parsed = tonumber(valueEdit:GetText())
                    if parsed ~= nil then
                        setValue(parsed, true)
                    end
                end
                valueEdit:Hide()
                valueText:Show()
                valueEdit:ClearFocus()
                valueText:SetText(fmt(currentValue or minValue))
            end

            local function applyEnabledState()
                local alpha = controlEnabled and 1 or 0.5
                container:SetAlpha(alpha)
                label:SetAlpha(alpha)
                minusButton:SetEnabled(controlEnabled)
                plusButton:SetEnabled(controlEnabled)
                valueButton:SetEnabled(controlEnabled)
                if not controlEnabled and editingValue then
                    endEdit(false)
                end
            end

            minusButton:SetScript("OnClick", function()
                if not controlEnabled then
                    return
                end
                local mult = 1
                if IsShiftKeyDown and IsShiftKeyDown() then
                    mult = microShiftMultiplier
                end
                setValue((currentValue or minValue) - (stepValue * mult), true)
            end)
            plusButton:SetScript("OnClick", function()
                if not controlEnabled then
                    return
                end
                local mult = 1
                if IsShiftKeyDown and IsShiftKeyDown() then
                    mult = microShiftMultiplier
                end
                setValue((currentValue or minValue) + (stepValue * mult), true)
            end)
            valueButton:SetScript("OnClick", function()
                if not controlEnabled then
                    return
                end
                beginEdit()
            end)
            valueEdit:SetScript("OnEnterPressed", function(edit)
                endEdit(true)
                edit:ClearFocus()
            end)
            valueEdit:SetScript("OnEscapePressed", function(edit)
                endEdit(false)
                edit:ClearFocus()
            end)
            valueEdit:SetScript("OnEditFocusLost", function()
                endEdit(true)
            end)

            local spec = {
                kind = "stepper",
                label = label,
                control = container,
                valueButton = valueButton,
                valueText = valueText,
                valueEdit = valueEdit,
                minus = minusButton,
                plus = plusButton,
            }
            spec.SetWidth = function(_, newWidth)
                container:SetWidth(math.max(52, math.floor(tonumber(newWidth) or 58)))
            end
            spec.SetEnabled = function(_, enabled)
                controlEnabled = enabled and true or false
                applyEnabledState()
            end
            spec.IsEnabled = function()
                return controlEnabled
            end
            spec.SetVisualValue = function(_, value)
                local n = normalize(value)
                currentValue = n
                valueText:SetText(fmt(n))
                if valueEdit:IsShown() then
                    valueEdit:SetText(fmt(n))
                end
                applyEnabledState()
            end
            spec.Refresh = function()
                local n = normalize(getter and getter() or minValue)
                currentValue = n
                valueText:SetText(fmt(n))
                if valueEdit:IsShown() then
                    valueEdit:SetText(fmt(n))
                end
                applyEnabledState()
            end
            spec.Refresh()
            return spec
        end

        local INTERRUPT_LAYOUT = {
            panel = {
                TOP_PAD = 20,
                CONTENT_LEFT = 20,
                CONTENT_RIGHT = 20,
                HEADER_LEFT = 16,
                HEADER_FLOOR = 16,
                HEADER_MIN_W = 220,
                FALLBACK_CONTENT_W = 620,
                MIN_CONTENT_W = 560,
                BOTTOM_PAD = 60,
            },
            top = {
                HEADER_BOTTOM_GAP = 14,
                LOCK_LABEL_TO_TOGGLE_GAP = 12,
                LOCK_TOGGLE_TO_RESET_GAP = 12,
                LOCK_HELPER_MULTIPLIER = 0.625,
                LOCK_DIVIDER_MULTIPLIER = 1.25,
                LOCK_ROW_FLOOR = 22,
                LOCK_SEGMENT_BUTTON_TEXT_PAD_X = 20,
                RESET_W = 102,
                RESET_H = 22,
                LOCK_BUTTON_TEXT_FALLBACK_W = 36,
                LOCK_TOGGLE_MIN_W = 96,
                HELPER_FLOOR = 10,
                LABEL_FLOOR = 12,
                HELPER_MIN_W = 120,
                DIVIDER_H = 1,
            },
            cards = {
                MIN_W = 320,
                PAD = 12,
                TITLE_H = 16,
                TITLE_TO_CONTENT_GAP = 10,
                SECTION_GAP = 12,
            },
            rows = {
                STRIDE = 34,
                LABEL_X = 12,
                CONTROL_X = 180,
                CONTROL_FLOOR_H = 18,
                DEFAULT_CONTROL_H = 22,
                CONTENT_H = 24,
            },
            appearance = {
                ROW_COUNT = 8,
                ROW_SLOTS = {
                    BACKGROUND_OPACITY = 2,
                    FONT = 3,
                    BAR_TEXTURE = 4,
                    USE_CLASS_COLORS = 5,
                    SHOW_CLASS_ICON = 6,
                    SHOW_SPELL_ICON = 7,
                    RIGHT_DISPLAY = 8,
                },
                PICKER_W = 186,
                SEGMENTED_W = 150,
                RIGHT_DISPLAY_W = 236,
                FIRST_STEPPER_W = 78,
                INLINE_LABEL_TO_CONTROL_GAP = 12,
                FIRST_ROW_GROUP_GAP = 24,
                FONT_AUX_GAP = 10,
                FONT_PICKER_MIN_W = 140,
                FONT_PICKER_RIGHT_RESERVE = 96,
                FONT_SWATCH_FALLBACK_SIZE = 18,
            },
            preview = {
                SAMPLE_GAP = 16,
                SAMPLE_WIDTH_MIN = 160,
                STACKED_SAMPLE_MIN_W = 120,
                ROW_H_MIN = 18,
                ROW_H_MAX = 34,
                ROW_GAP_MAX = 8,
                CARD_MIN_H = 192,
                TICK = 0.05,
                CYCLE = 6.0,
                ACCENT_WIDTH = 6,
                ACCENT_ALPHA = 0.24,
                ICON_SEPARATOR_W = 2,
                ICON_SEPARATOR_GAP = 6,
                ICON_SEPARATOR_VERTICAL_INSET = 1,
                TIMER_VALUE_W = 52,
                COUNT_VALUE_W = 42,
                NAME_LEFT_INSET = 8,
                VALUE_RIGHT_INSET = 8,
                NAME_RIGHT_GAP = 10,
            },
            legend = {
                MIN_W = 140,
                SEED_H = 100,
                SWATCH_SIZE = 10,
                SWATCH_ROW_GAP = 8,
                SWATCH_TEXT_GAP = 8,
                SWATCH_TEXT_Y = 2,
                PRIMARY_TEXT_MIN_W = 96,
                SECONDARY_SECTION_GAP = 12,
                SECONDARY_TEXT_RIGHT_PAD = 20,
                CHIP_W = 12,
                CHIP_H = 2,
                CHIP_TEXT_GAP = 8,
            },
            notes = {
                HELPER_GAP = 10,
                LIMIT_NOTE_GAP = 8,
                BOTTOM_PAD = 4,
                FLOOR = 18,
            },
            alert = {
                ROW_SLOTS = {
                    SOUND = 1,
                },
                PICKER_W = 186,
                PICKER_MIN_W = 136,
                SCOPE_CONTROL_W = 108,
                SCOPE_CLUSTER_GAP = 18,
                SCOPE_LABEL_TO_CONTROL_GAP = 10,
            },
        }

        local function measureInterruptFontStringHeight(fs, floor)
            local measured = 0
            if fs and fs.GetStringHeight then
                measured = math.ceil(fs:GetStringHeight() or 0)
            end
            return math.max(tonumber(floor) or 0, measured)
        end

        local function measureInterruptControlHeight(widget, floor)
            local measured = 0
            if widget and widget.GetHeight then
                measured = math.ceil(widget:GetHeight() or 0)
            end
            return math.max(tonumber(floor) or 0, measured)
        end

        local function setInterruptSingleLineEllipsis(fs, fullText, maxWidth)
            if not fs then
                return
            end
            local source = tostring(fullText or "")
            fs:SetWordWrap(false)
            if fs.SetMaxLines then
                fs:SetMaxLines(1)
            end
            fs:SetWidth(maxWidth or 0)
            fs:SetText(source)
            if (maxWidth or 0) <= 0 then
                return
            end
            if (fs.GetStringWidth and fs:GetStringWidth() or 0) <= maxWidth then
                return
            end
            local cut = string.len(source)
            while cut > 0 do
                local candidate = string.sub(source, 1, cut) .. "..."
                fs:SetText(candidate)
                if (fs.GetStringWidth and fs:GetStringWidth() or 0) <= maxWidth then
                    return
                end
                cut = cut - 1
            end
            fs:SetText("...")
        end

        local function computeInterruptTopBlockLockGeometry(contentW, lockLabel)
            local panelTokens = INTERRUPT_LAYOUT.panel
            local topTokens = INTERRUPT_LAYOUT.top
            local lockLabelW = lockLabel and math.ceil(lockLabel:GetStringWidth() or 0) or 0
            local lockLabelH = lockLabel and math.ceil(lockLabel:GetStringHeight() or 0) or topTokens.LABEL_FLOOR
            local unit = math.max(1, lockLabelH)
            local lockBtnTextW = 0
            if widgets.lockPosition and type(widgets.lockPosition.buttons) == "table" then
                for _, btn in ipairs(widgets.lockPosition.buttons) do
                    if btn and btn.Text then
                        lockBtnTextW = math.max(lockBtnTextW, math.ceil(btn.Text:GetStringWidth() or 0))
                    end
                end
            end
            lockBtnTextW = math.max(lockBtnTextW, topTokens.LOCK_BUTTON_TEXT_FALLBACK_W)
            local lockToggleWFromContent = ((lockBtnTextW + (topTokens.LOCK_SEGMENT_BUTTON_TEXT_PAD_X * 2)) * 2) + 4
            local lockToggleWMax = math.max(
                topTokens.LOCK_TOGGLE_MIN_W,
                (contentW - panelTokens.CONTENT_RIGHT) - (panelTokens.CONTENT_LEFT + lockLabelW + topTokens.LOCK_LABEL_TO_TOGGLE_GAP + topTokens.LOCK_TOGGLE_TO_RESET_GAP + topTokens.RESET_W)
            )
            local lockToggleW = math.max(topTokens.LOCK_TOGGLE_MIN_W, math.min(lockToggleWFromContent, lockToggleWMax))
            local toggleX = (lockLabelW > 0) and (lockLabelW + topTokens.LOCK_LABEL_TO_TOGGLE_GAP) or 0
            local resetX = toggleX + lockToggleW + topTokens.LOCK_TOGGLE_TO_RESET_GAP
            return {
                labelW = lockLabelW,
                labelH = lockLabelH,
                helperGap = unit * topTokens.LOCK_HELPER_MULTIPLIER,
                dividerGap = unit * topTokens.LOCK_DIVIDER_MULTIPLIER,
                toggleW = lockToggleW,
                toggleX = toggleX,
                resetX = resetX,
                rowW = math.max(1, contentW - panelTokens.CONTENT_RIGHT - panelTokens.CONTENT_LEFT),
            }
        end

        local function computeInterruptContentWidth(frameWidth, panelWidth)
            local panelTokens = INTERRUPT_LAYOUT.panel
            local contentW = tonumber(frameWidth)
            if not contentW or contentW <= 1 then
                contentW = tonumber(panelWidth)
            end
            if not contentW or contentW <= 1 then
                contentW = panelTokens.FALLBACK_CONTENT_W
            end
            return math.max(panelTokens.MIN_CONTENT_W, contentW)
        end

        local function computeInterruptCardFrameGeometry(contentW)
            local panelTokens = INTERRUPT_LAYOUT.panel
            local cardTokens = INTERRUPT_LAYOUT.cards
            local cardX = panelTokens.CONTENT_LEFT
            local cardW = math.max(cardTokens.MIN_W, contentW - panelTokens.CONTENT_LEFT - panelTokens.CONTENT_RIGHT)
            return {
                x = cardX,
                width = cardW,
                innerWidth = cardW - (cardTokens.PAD * 2),
            }
        end

        local function computeInterruptHeaderWidth(contentW)
            local panelTokens = INTERRUPT_LAYOUT.panel
            return math.max(panelTokens.HEADER_MIN_W, contentW - panelTokens.HEADER_LEFT - panelTokens.CONTENT_RIGHT)
        end

        local function getInterruptCardRowTop(rowIndex)
            local cardTokens = INTERRUPT_LAYOUT.cards
            local rowTokens = INTERRUPT_LAYOUT.rows
            return -(cardTokens.PAD + cardTokens.TITLE_H + cardTokens.TITLE_TO_CONTENT_GAP + ((rowIndex - 1) * rowTokens.STRIDE))
        end

        local function computeInterruptCardHeight(rowCount, finalRowHeight)
            local cardTokens = INTERRUPT_LAYOUT.cards
            local rowTokens = INTERRUPT_LAYOUT.rows
            local terminalRowH = tonumber(finalRowHeight) or rowTokens.CONTENT_H
            return (cardTokens.PAD * 2) + cardTokens.TITLE_H + cardTokens.TITLE_TO_CONTENT_GAP + (rowCount * rowTokens.STRIDE) - (rowTokens.STRIDE - terminalRowH)
        end

        local function layoutInterruptCardHeader(card, headerWidget)
            if not (card and headerWidget) then
                return
            end
            local cardTokens = INTERRUPT_LAYOUT.cards
            headerWidget:ClearAllPoints()
            headerWidget:SetPoint("TOPLEFT", card, "TOPLEFT", cardTokens.PAD, -cardTokens.PAD)
        end

        local function layoutInterruptCardRow(card, rowIndex, labelWidget, controlWidget, opts)
            opts = type(opts) == "table" and opts or {}
            local rowTokens = INTERRUPT_LAYOUT.rows
            local rowTop = tonumber(opts.rowTop) or getInterruptCardRowTop(rowIndex)
            local labelX = tonumber(opts.labelX) or rowTokens.LABEL_X
            local controlX = tonumber(opts.controlX) or rowTokens.CONTROL_X
            local targetControl = controlWidget and (controlWidget.control or controlWidget) or nil
            if targetControl then
                targetControl:ClearAllPoints()
                targetControl:SetPoint("TOPLEFT", card, "TOPLEFT", controlX, rowTop)
                if opts.layoutWidth and controlWidget and controlWidget.Layout then
                    controlWidget:Layout(opts.layoutWidth)
                elseif opts.width and targetControl.SetWidth then
                    targetControl:SetWidth(opts.width)
                end
            end
            if labelWidget then
                labelWidget:ClearAllPoints()
                if targetControl then
                    local controlH = math.max(rowTokens.CONTROL_FLOOR_H, targetControl:GetHeight() or rowTokens.DEFAULT_CONTROL_H)
                    labelWidget:SetPoint("LEFT", card, "TOPLEFT", labelX, rowTop - math.floor(controlH * 0.5))
                else
                    labelWidget:SetPoint("TOPLEFT", card, "TOPLEFT", labelX, rowTop)
                end
            end
            return rowTop
        end

        local function computeInterruptAppearanceFirstRowGeometry(widthLabelW, rowHeightLabelW)
            local rowTokens = INTERRUPT_LAYOUT.rows
            local appearanceTokens = INTERRUPT_LAYOUT.appearance
            local widthLabelX = rowTokens.LABEL_X
            local widthControlX = widthLabelX + widthLabelW + appearanceTokens.INLINE_LABEL_TO_CONTROL_GAP
            local rowHeightLabelX = widthControlX + appearanceTokens.FIRST_STEPPER_W + appearanceTokens.FIRST_ROW_GROUP_GAP
            local rowHeightControlX = rowHeightLabelX + rowHeightLabelW + appearanceTokens.INLINE_LABEL_TO_CONTROL_GAP
            return {
                widthLabelX = widthLabelX,
                widthControlX = widthControlX,
                rowHeightLabelX = rowHeightLabelX,
                rowHeightControlX = rowHeightControlX,
                stepperW = appearanceTokens.FIRST_STEPPER_W,
            }
        end

        local function computeInterruptAppearanceFontRowGeometry(cardInnerW, fontSizeControlW)
            local rowTokens = INTERRUPT_LAYOUT.rows
            local appearanceTokens = INTERRUPT_LAYOUT.appearance
            local fontPickerW = math.max(appearanceTokens.FONT_PICKER_MIN_W, math.min(appearanceTokens.PICKER_W, cardInnerW - rowTokens.CONTROL_X - appearanceTokens.FONT_PICKER_RIGHT_RESERVE))
            local fontControlX = rowTokens.CONTROL_X
            local fontSizeX = fontControlX + fontPickerW + appearanceTokens.FONT_AUX_GAP
            local swatchX = fontSizeX + (tonumber(fontSizeControlW) or 0) + appearanceTokens.FONT_AUX_GAP
            return {
                pickerW = fontPickerW,
                fontControlX = fontControlX,
                fontSizeX = fontSizeX,
                swatchX = swatchX,
            }
        end

        local function computeInterruptAlertRowGeometry(cardInnerW, scopeLabelWidth)
            local rowTokens = INTERRUPT_LAYOUT.rows
            local alertTokens = INTERRUPT_LAYOUT.alert
            local pickerW = math.max(
                alertTokens.PICKER_MIN_W,
                cardInnerW - rowTokens.CONTROL_X - (scopeLabelWidth + alertTokens.SCOPE_CONTROL_W + alertTokens.SCOPE_CLUSTER_GAP + alertTokens.SCOPE_LABEL_TO_CONTROL_GAP)
            )
            local scopeLabelX = rowTokens.CONTROL_X + pickerW + alertTokens.SCOPE_CLUSTER_GAP
            local scopeControlX = scopeLabelX + scopeLabelWidth + alertTokens.SCOPE_LABEL_TO_CONTROL_GAP
            return {
                pickerW = pickerW,
                scopeLabelX = scopeLabelX,
                scopeControlX = scopeControlX,
            }
        end

        local function createInterruptSlider(parent, labelText, minValue, maxValue, stepValue, getter, setter, onApplyCallback, opts)
            opts = type(opts) == "table" and opts or {}
            local label = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
            label:SetText(labelText or "")

            local minV = tonumber(minValue) or 0
            local maxV = tonumber(maxValue) or 100
            local stepV = tonumber(stepValue) or 1
            if maxV < minV then
                minV, maxV = maxV, minV
            end

            local container = CreateFrame("Frame", nil, parent)
            container:SetHeight(22)
            container:SetWidth(math.max(140, tonumber(opts.width) or 220))

            local valueText = createStyledFontString(container, "ARTWORK", "GameFontHighlightSmall", 11)
            valueText:SetPoint("RIGHT", container, "RIGHT", 0, 0)
            valueText:SetJustifyH("RIGHT")
            valueText:SetTextColor(0.76, 0.76, 0.78, 1)

            local slider = CreateFrame("Slider", nil, container)
            slider:SetPoint("TOPLEFT", container, "TOPLEFT", 0, 0)
            slider:SetPoint("BOTTOMRIGHT", container, "BOTTOMRIGHT", -52, 0)
            slider:SetMinMaxValues(minV, maxV)
            slider:SetValueStep(stepV)
            local useManualDragTracking = opts.useManualDragTracking ~= false
            if slider.SetObeyStepOnDrag then
                slider:SetObeyStepOnDrag(true)
            end
            slider:SetThumbTexture("Interface\\Buttons\\WHITE8x8")
            local inputThumb = slider:GetThumbTexture()
            if inputThumb then
                inputThumb:SetSize(16, 16)
                inputThumb:SetVertexColor(1, 1, 1, 0.01)
            end
            slider:EnableMouse(not useManualDragTracking)
            slider:SetOrientation("HORIZONTAL")

            local trackBg = slider:CreateTexture(nil, "BACKGROUND")
            trackBg:SetTexture("Interface\\Buttons\\WHITE8x8")
            trackBg:SetPoint("LEFT", slider, "LEFT", 0, 0)
            trackBg:SetPoint("RIGHT", slider, "RIGHT", 0, 0)
            trackBg:SetHeight(2)
            trackBg:SetVertexColor(0.18, 0.18, 0.19, 0.95)

            local trackActive = slider:CreateTexture(nil, "ARTWORK")
            trackActive:SetTexture("Interface\\Buttons\\WHITE8x8")
            trackActive:SetPoint("LEFT", slider, "LEFT", 0, 0)
            trackActive:SetHeight(2)
            trackActive:SetWidth(0)
            trackActive:SetVertexColor(1.0, 0.82, 0.0, 0.75)

            local thumb = slider:CreateTexture(nil, "OVERLAY")
            thumb:SetTexture("Interface\\Buttons\\WHITE8x8")
            thumb:SetSize(8, 8)
            thumb:SetVertexColor(1.0, 0.84, 0.08, 0.98)
            if thumb.SetMask then
                thumb:SetMask("Interface\\CharacterFrame\\TempPortraitAlphaMask")
            end

            local thumbGlow = slider:CreateTexture(nil, "ARTWORK")
            thumbGlow:SetTexture("Interface\\Buttons\\WHITE8x8")
            thumbGlow:SetSize(14, 14)
            thumbGlow:SetVertexColor(1.0, 0.82, 0.0, 0)
            if thumbGlow.SetMask then
                thumbGlow:SetMask("Interface\\CharacterFrame\\TempPortraitAlphaMask")
            end
            thumbGlow:SetBlendMode("ADD")

            local inputLayer = nil
            if useManualDragTracking then
                inputLayer = CreateFrame("Button", nil, container)
                inputLayer:SetPoint("TOPLEFT", slider, "TOPLEFT", 0, 0)
                inputLayer:SetPoint("BOTTOMRIGHT", slider, "BOTTOMRIGHT", 0, 0)
                inputLayer:SetFrameStrata(slider:GetFrameStrata())
                inputLayer:SetFrameLevel((slider:GetFrameLevel() or 0) + 5)
                inputLayer:RegisterForClicks("LeftButtonDown", "LeftButtonUp")
                inputLayer:EnableMouse(true)
            end

            local suppress = false
            local currentValue = nil
            local dragging = false
            local hovering = false
            local pendingCommit = false
            local deferApplyUntilMouseUp = opts.deferApplyUntilMouseUp and true or false
            local previewCallback = type(opts.previewCallback) == "function" and opts.previewCallback or nil
            local commitCallback = type(opts.commitCallback) == "function" and opts.commitCallback or onApplyCallback
            local dragLeft = nil
            local dragRight = nil
            local dragScale = nil
            local lastDragCursorX = nil
            local dragCursorDeadzone = math.max(0.5, tonumber(opts.dragCursorDeadzone) or 0.75)

            local function normalize(v)
                local n = tonumber(v) or minV
                if n < minV then n = minV end
                if n > maxV then n = maxV end
                if stepV > 0 then
                    n = minV + (math.floor(((n - minV) / stepV) + 0.5) * stepV)
                end
                return math.floor(n + 0.5)
            end

            local function formatValue(v)
                if type(opts.formatter) == "function" then
                    return tostring(opts.formatter(v))
                end
                return tostring(math.floor((tonumber(v) or 0) + 0.5))
            end

            local function applyVisualState()
                local minSlider, maxSlider = slider:GetMinMaxValues()
                local value = normalize(slider:GetValue())
                local span = math.max(0.0001, (maxSlider - minSlider))
                local pct = math.max(0, math.min(1, (value - minSlider) / span))
                local widthNow = slider:GetWidth() or 0
                local x = pct * widthNow

                thumb:ClearAllPoints()
                thumb:SetPoint("CENTER", slider, "LEFT", x, 0)
                thumbGlow:ClearAllPoints()
                thumbGlow:SetPoint("CENTER", thumb, "CENTER", 0, 0)

                trackActive:ClearAllPoints()
                trackActive:SetPoint("LEFT", slider, "LEFT", 0, 0)
                trackActive:SetPoint("RIGHT", thumb, "CENTER", 0, 0)

                local glowAlpha = 0
                if dragging then
                    glowAlpha = 0.34
                    trackActive:SetVertexColor(1.0, 0.86, 0.16, 0.9)
                    thumb:SetVertexColor(1.0, 0.9, 0.22, 1)
                elseif hovering then
                    glowAlpha = 0.22
                    trackActive:SetVertexColor(1.0, 0.85, 0.12, 0.85)
                    thumb:SetVertexColor(1.0, 0.88, 0.18, 1)
                else
                    trackActive:SetVertexColor(1.0, 0.82, 0.0, 0.75)
                    thumb:SetVertexColor(1.0, 0.84, 0.08, 0.98)
                end
                thumbGlow:SetVertexColor(1.0, 0.82, 0.0, glowAlpha)
            end

            local function resetDragTracking()
                dragLeft = nil
                dragRight = nil
                dragScale = nil
                lastDragCursorX = nil
            end

            local function captureDragBounds()
                dragLeft = slider:GetLeft()
                dragRight = slider:GetRight()
                dragScale = slider:GetEffectiveScale() or 1
                lastDragCursorX = nil
                if not dragLeft or not dragRight or dragRight <= dragLeft or dragScale <= 0 then
                    resetDragTracking()
                end
            end

            local function setValueVisualOnly(v, keepCurrentValue)
                local n = normalize(v)
                if not keepCurrentValue then
                    currentValue = n
                end
                suppress = true
                slider:SetValue(n)
                suppress = false
                valueText:SetText(formatValue(n))
                applyVisualState()
            end

            local function applyValue(v)
                local n = normalize(v)
                if currentValue == n then
                    valueText:SetText(formatValue(n))
                    applyVisualState()
                    return
                end
                currentValue = n
                valueText:SetText(formatValue(n))
                if setter then
                    setter(n)
                end
                if deferApplyUntilMouseUp and dragging then
                    pendingCommit = true
                    if previewCallback then
                        previewCallback(n)
                    end
                    applyVisualState()
                    return
                end
                if commitCallback then
                    pendingCommit = false
                    commitCallback(n)
                elseif onApplyCallback then
                    onApplyCallback()
                end
                applyVisualState()
            end

            local function setValueFromCursor()
                local minSlider, maxSlider = slider:GetMinMaxValues()
                local left = (dragging and dragLeft) or slider:GetLeft()
                local right = (dragging and dragRight) or slider:GetRight()
                if not left or not right or right <= left then
                    return
                end
                local cx = GetCursorPosition()
                local scale = (dragging and dragScale) or (slider:GetEffectiveScale() or 1)
                if not cx or scale <= 0 then
                    return
                end
                cx = cx / scale
                if dragging and lastDragCursorX ~= nil and math.abs(cx - lastDragCursorX) < dragCursorDeadzone then
                    return
                end
                if dragging then
                    lastDragCursorX = cx
                end
                local pct = (cx - left) / (right - left)
                if pct < 0 then pct = 0 end
                if pct > 1 then pct = 1 end
                local raw = minSlider + ((maxSlider - minSlider) * pct)
                local n = normalize(raw)
                if currentValue == n then
                    applyVisualState()
                    return
                end
                setValueVisualOnly(n, true)
                applyValue(n)
            end

            local function commitPendingInteraction()
                if not deferApplyUntilMouseUp or not pendingCommit then
                    return
                end
                pendingCommit = false
                if commitCallback then
                    commitCallback(currentValue)
                end
            end

            local function finishDrag(shouldCommit)
                if not dragging then
                    return
                end
                dragging = false
                resetDragTracking()
                if inputLayer then
                    inputLayer:SetScript("OnUpdate", nil)
                else
                    slider:SetScript("OnUpdate", nil)
                end
                applyVisualState()
                if shouldCommit then
                    commitPendingInteraction()
                end
            end

            slider:SetScript("OnValueChanged", function(selfSlider, value)
                local n = normalize(value)
                if selfSlider:GetValue() ~= n then
                    suppress = true
                    selfSlider:SetValue(n)
                    suppress = false
                end
                valueText:SetText(formatValue(n))
                applyVisualState()
                if suppress or isControlHydrating(selfSlider) or currentValue == n then
                    return
                end
                applyValue(n)
            end)
            local function beginDrag()
                dragging = true
                pendingCommit = false
                if useManualDragTracking then
                    captureDragBounds()
                    setValueFromCursor()
                    inputLayer:SetScript("OnUpdate", function()
                        if dragging then
                            if IsMouseButtonDown and not IsMouseButtonDown("LeftButton") then
                                finishDrag(true)
                                return
                            end
                            setValueFromCursor()
                        end
                    end)
                end
                applyVisualState()
            end

            local function handleEnter()
                hovering = true
                applyVisualState()
            end

            local function handleLeave()
                hovering = false
                applyVisualState()
            end

            if inputLayer then
                inputLayer:SetScript("OnMouseDown", function(_, mouseButton)
                    if mouseButton == "LeftButton" then
                        beginDrag()
                    end
                end)
                inputLayer:SetScript("OnMouseUp", function(_, mouseButton)
                    if mouseButton == "LeftButton" then
                        finishDrag(true)
                    end
                end)
                inputLayer:SetScript("OnEnter", handleEnter)
                inputLayer:SetScript("OnLeave", handleLeave)
                inputLayer:SetScript("OnHide", function()
                    finishDrag(true)
                end)
            else
                slider:SetScript("OnMouseDown", function()
                    beginDrag()
                end)
                slider:SetScript("OnMouseUp", function()
                    finishDrag(true)
                end)
                slider:SetScript("OnEnter", handleEnter)
                slider:SetScript("OnLeave", function()
                    local wasDragging = dragging
                    handleLeave()
                    if wasDragging then
                        finishDrag(true)
                    end
                end)
            end

            container:SetScript("OnHide", function()
                if dragging then
                    finishDrag(true)
                end
            end)

            local spec = {
                label = label,
                control = container,
                slider = slider,
                SetWidth = function(_, width)
                    container:SetWidth(math.max(140, math.floor(tonumber(width) or 220)))
                end,
                Refresh = function()
                    local value = normalize(getter and getter() or minV)
                    currentValue = value
                    pendingCommit = false
                    setValueVisualOnly(value)
                end,
                IsInteracting = function()
                    return dragging
                end,
                CommitPendingInteraction = function()
                    commitPendingInteraction()
                end,
            }
            spec:Refresh()
            return settingsSearchRuntime.registerSpec(spec, "slider")
        end

        local function openInterruptFontColorPicker(onChanged)
            local db = getDB()
            local color = db.fontColor or { r = 1, g = 1, b = 1, a = 1 }
            if ColorPickerFrame and ColorPickerFrame.SetupColorPickerAndShow then
                ColorPickerFrame:SetupColorPickerAndShow({
                    r = color.r,
                    g = color.g,
                    b = color.b,
                    opacity = 1 - color.a,
                    hasOpacity = true,
                    swatchFunc = function()
                        local nr, ng, nb = ColorPickerFrame:GetColorRGB()
                        local alpha = 1 - (OpacitySliderFrame and OpacitySliderFrame:GetValue() or 0)
                        db.fontColor = { r = nr, g = ng, b = nb, a = alpha }
                        if onChanged then onChanged() end
                    end,
                    opacityFunc = function()
                        local nr, ng, nb = ColorPickerFrame:GetColorRGB()
                        local alpha = 1 - (OpacitySliderFrame and OpacitySliderFrame:GetValue() or 0)
                        db.fontColor = { r = nr, g = ng, b = nb, a = alpha }
                        if onChanged then onChanged() end
                    end,
                    cancelFunc = function(previous)
                        db.fontColor = restoreColorPickerPrevious(previous, color)
                        if onChanged then onChanged() end
                    end,
                })
            end
        end

        local function createSubtleCard(parent)
            local card = CreateFrame("Frame", nil, parent, "BackdropTemplate")
            card:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
                insets = { left = 0, right = 0, top = 0, bottom = 0 },
            })
            card:SetBackdropColor(0.06, 0.07, 0.09, 0.42)
            card:SetBackdropBorderColor(0.20, 0.23, 0.29, 0.50)
            return card
        end

        local function createInterruptCardBody(card)
            local body = CreateFrame("Frame", nil, card)
            body:SetAllPoints(card)
            body:SetFrameStrata(card:GetFrameStrata())
            body:SetFrameLevel((card:GetFrameLevel() or 0) + 1)
            return body
        end

        local function syncInterruptCardBody(card, body)
            if not card or not body then
                return
            end
            body:ClearAllPoints()
            body:SetAllPoints(card)
            body:SetFrameStrata(card:GetFrameStrata())
            body:SetFrameLevel((card:GetFrameLevel() or 0) + 1)
        end

        local GUIDED_PREVIEW_ADDON = { 111 / 255, 174 / 255, 107 / 255, 1.0 }
        local GUIDED_PREVIEW_FALLBACK = { 242 / 255, 201 / 255, 76 / 255, 1.0 }
        local GUIDED_PREVIEW_BG_BAR = { 0.09, 0.10, 0.13, 0.88 }
        local GUIDED_PREVIEW_NEUTRAL_BAR = { 0.23, 0.56, 0.88, 0.92 }
        local GUIDED_PREVIEW_ROW_BORDER = { 0.18, 0.21, 0.25, 0.70 }

        local GUIDED_PREVIEW_ROWS = {
            { name = "Yetw", class = "WARRIOR", spellIcon = 132938, accent = "addon", ready = true, count = 9, baseCd = 15, startRemaining = 0, endRemaining = 0 },
            { name = "Artyrka", class = "MAGE", spellIcon = 135856, accent = "addon", ready = false, count = 4, baseCd = 25, startRemaining = 8.4, endRemaining = 3.2 },
            { name = "Deneroc", class = "DEATHKNIGHT", spellIcon = 237527, accent = "fallback", ready = false, count = 2, baseCd = 15, startRemaining = 13.2, endRemaining = 7.6 },
        }

        local clampPreviewNumber = nil

        local function computeInterruptGuidedPreviewGeometry(cardWidth, db)
            local cardTokens = INTERRUPT_LAYOUT.cards
            local previewTokens = INTERRUPT_LAYOUT.preview
            local legendTokens = INTERRUPT_LAYOUT.legend
            local cardInnerW = math.max(0, cardWidth - (cardTokens.PAD * 2))
            local previewTopY = cardTokens.PAD + cardTokens.TITLE_H + cardTokens.TITLE_TO_CONTENT_GAP
            local sampleRowHeight = clampPreviewNumber(db.rowHeight, 30, previewTokens.ROW_H_MIN, previewTokens.ROW_H_MAX)
            local sampleRowGap = clampPreviewNumber(db.rowGap, db.rowGap or 4, 0, previewTokens.ROW_GAP_MAX)
            local sampleDesiredW = clampPreviewNumber(db.width, 198, previewTokens.SAMPLE_WIDTH_MIN, 999)
            local sampleHeight = (sampleRowHeight * #GUIDED_PREVIEW_ROWS) + (sampleRowGap * (#GUIDED_PREVIEW_ROWS - 1))
            local rightDisplay = db.rightDisplay == "timer" and "timer" or "count"
            local valueWidth = rightDisplay == "timer" and previewTokens.TIMER_VALUE_W or previewTokens.COUNT_VALUE_W
            local sideBySideMaxSampleW = math.max(0, cardInnerW - previewTokens.SAMPLE_GAP - legendTokens.MIN_W)
            local legendStacked = sideBySideMaxSampleW < previewTokens.SAMPLE_WIDTH_MIN
            local sampleWidth
            local legendWidth
            if legendStacked then
                sampleWidth = math.max(previewTokens.STACKED_SAMPLE_MIN_W, math.min(sampleDesiredW, cardInnerW))
                legendWidth = cardInnerW
            else
                sampleWidth = math.max(previewTokens.SAMPLE_WIDTH_MIN, math.min(sampleDesiredW, sideBySideMaxSampleW))
                legendWidth = math.max(legendTokens.MIN_W, cardInnerW - sampleWidth - previewTokens.SAMPLE_GAP)
            end
            return {
                cardInnerW = cardInnerW,
                previewTopY = previewTopY,
                sampleRowHeight = sampleRowHeight,
                sampleRowGap = sampleRowGap,
                sampleHeight = sampleHeight,
                sampleWidth = sampleWidth,
                legendWidth = legendWidth,
                legendStacked = legendStacked,
                rightDisplay = rightDisplay,
                valueWidth = valueWidth,
                separatorGap = previewTokens.ICON_SEPARATOR_GAP,
                separatorWidth = previewTokens.ICON_SEPARATOR_W,
            }
        end

        clampPreviewNumber = function(value, defaultValue, minValue, maxValue)
            local numeric = tonumber(value)
            if numeric == nil then
                numeric = tonumber(defaultValue) or 0
            end
            if minValue ~= nil and numeric < minValue then
                numeric = minValue
            end
            if maxValue ~= nil and numeric > maxValue then
                numeric = maxValue
            end
            return numeric
        end

        local function getGuidedPreviewFontPath(db)
            local path = trim(tostring((db and db.fontPath) or ""))
            if path ~= "" then
                return path
            end
            return STANDARD_TEXT_FONT or "Fonts\\FRIZQT__.TTF"
        end

        local function applyGuidedPreviewFont(fontString, db, size, r, g, b, a)
            if not fontString then
                return
            end
            local fontPath = getGuidedPreviewFontPath(db)
            local targetSize = math.max(8, math.floor(tonumber(size) or 12))
            if fontString.SetFont then
                local ok = pcall(fontString.SetFont, fontString, fontPath, targetSize, "")
                if not ok then
                    applyGlobalFontToObject(fontString, targetSize)
                end
            else
                applyGlobalFontToObject(fontString, targetSize)
            end
            fontString:SetTextColor(r or 1, g or 1, b or 1, a or 1)
        end

        local function resolveGuidedPreviewStatusbarPath(value)
            local media = getPortalMedia()
            if media and media.GetChoices then
                for _, option in ipairs(media.GetChoices("statusbar", { currentValue = value }) or {}) do
                    if tostring(option.value or "") == tostring(value or "") then
                        local path = trim(tostring(option.path or ""))
                        if path ~= "" then
                            return path
                        end
                    end
                end
            end
            local raw = trim(tostring(value or ""))
            if raw ~= "" then
                return raw
            end
            return "Interface\\TARGETINGFRAME\\UI-StatusBar"
        end

        local function applyGuidedPreviewClassIcon(texture, classFile)
            if not texture or not classFile or not CLASS_ICON_TCOORDS or not CLASS_ICON_TCOORDS[classFile] then
                return false
            end
            local coords = CLASS_ICON_TCOORDS[classFile]
            texture:SetTexture("Interface\\GLUES\\CHARACTERCREATE\\UI-CHARACTERCREATE-CLASSES")
            texture:SetTexCoord(coords[1] + (4 / 256), coords[2] - (4 / 256), coords[3] + (6 / 256), coords[4] - (4 / 256))
            return true
        end

        local function getGuidedPreviewClassColor(classFile)
            local color = RAID_CLASS_COLORS and RAID_CLASS_COLORS[classFile]
            if color then
                return color.r or 1, color.g or 1, color.b or 1
            end
            return GUIDED_PREVIEW_NEUTRAL_BAR[1], GUIDED_PREVIEW_NEUTRAL_BAR[2], GUIDED_PREVIEW_NEUTRAL_BAR[3]
        end

        local function createGuidedPreviewRow(parent)
            local row = CreateFrame("Frame", nil, parent, "BackdropTemplate")
            row:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
                insets = { left = 0, right = 0, top = 0, bottom = 0 },
            })
            row:SetBackdropColor(GUIDED_PREVIEW_BG_BAR[1], GUIDED_PREVIEW_BG_BAR[2], GUIDED_PREVIEW_BG_BAR[3], GUIDED_PREVIEW_BG_BAR[4])
            row:SetBackdropBorderColor(GUIDED_PREVIEW_ROW_BORDER[1], GUIDED_PREVIEW_ROW_BORDER[2], GUIDED_PREVIEW_ROW_BORDER[3], GUIDED_PREVIEW_ROW_BORDER[4])

            row.barBg = row:CreateTexture(nil, "BACKGROUND")
            row.barBg:SetTexture("Interface\\Buttons\\WHITE8x8")

            row.bar = row:CreateTexture(nil, "ARTWORK")
            row.bar:SetTexture("Interface\\Buttons\\WHITE8x8")

            row.accent = row:CreateTexture(nil, "OVERLAY")
            row.accent:SetColorTexture(1, 1, 1, INTERRUPT_LAYOUT.preview.ACCENT_ALPHA)

            row.classIcon = row:CreateTexture(nil, "ARTWORK")
            row.classIcon:SetTexCoord(0.07, 0.93, 0.07, 0.93)

            row.spellIcon = row:CreateTexture(nil, "ARTWORK")
            row.spellIcon:SetTexCoord(0.08, 0.92, 0.08, 0.92)

            row.separator = row:CreateTexture(nil, "OVERLAY")

            row.nameText = createStyledFontString(row, "OVERLAY", "GameFontHighlight", 12)
            row.nameText:SetJustifyH("LEFT")
            row.nameText:SetWordWrap(false)
            if row.nameText.SetMaxLines then
                row.nameText:SetMaxLines(1)
            end

            row.valueText = createStyledFontString(row, "OVERLAY", "GameFontHighlight", 12)
            row.valueText:SetJustifyH("RIGHT")
            row.valueText:SetWordWrap(false)
            if row.valueText.SetMaxLines then
                row.valueText:SetMaxLines(1)
            end

            return row
        end

        local function styleGuidedPreviewHelperText(fontString, size, r, g, b, a)
            if not fontString then
                return
            end
            applyGlobalFontToObject(fontString, size)
            fontString:SetTextColor(r, g, b, a)
            fontString:SetJustifyH("LEFT")
            fontString:SetJustifyV("TOP")
            fontString:SetWordWrap(true)
        end

