        header:SetText("|cffffd100Interrupt Tracker|r")
        widgets.sectionDescriptor = createSettingsSectionDescriptor(scrollChild, "Tune interrupt visibility and preview behavior.")

        widgets.lockRowContainer = CreateFrame("Frame", nil, scrollChild)
