        widgets.guidedPreviewValueChip:SetColorTexture(0.38, 0.42, 0.48, 0.95)

        local GUIDED_PREVIEW_RELAYOUT_SOURCES = {
            hidden_refresh = true,
            on_show = true,
            size_changed = true,
            registered_refresh = true,
            guided_preview_relayout = true,
        }

        local function isGuidedPreviewRelayoutSource(source)
            return GUIDED_PREVIEW_RELAYOUT_SOURCES[tostring(source or "")] and true or false
        end

        local INTERRUPT_PREVIEW_DIRECT_EDIT_SOURCES = {
            apply_setting = true,
            apply_visual_setting = true,
            guided_preview_relayout = true,
            guided_preview_repaint = true,
        }

        local function isInterruptPreviewDirectEditSource(source)
            return INTERRUPT_PREVIEW_DIRECT_EDIT_SOURCES[tostring(source or "")] and true or false
        end

        local function mergeInterruptPreviewRefreshSource(current, incoming)
            local incomingKey = tostring(incoming or "")
            if incomingKey == "" then
                return tostring(current or "")
            end
            if isGuidedPreviewRelayoutSource(incomingKey) then
                return incomingKey
            end
            local currentKey = tostring(current or "")
            if isGuidedPreviewRelayoutSource(currentKey) then
                return currentKey
            end
            return incomingKey
        end

        local function invalidateInterruptPreviewRefresh()
            panelRef._interruptQueuedPreviewReason = nil
            panelRef._interruptPreviewRefreshPending = nil
            panelRef._interruptPreviewRefreshToken = (tonumber(panelRef._interruptPreviewRefreshToken) or 0) + 1
        end

        local function canRunGuidedPreviewTicker()
            if not panelRef or not panelRef._initialized then
                return false
            end
            if panelRef._interruptClosing or panelRef._paSettingsClosing then
                return false
            end
            if not panelRef.IsShown or not panelRef:IsShown() then
                return false
            end
            if settingsFirstOpenHost.selectedPanel ~= panelRef then
                return false
            end
            if settingsFirstOpenHost.selectedKey ~= "interrupt" then
                return false
            end
            if getDB().enabled == false then
                return false
            end
            return interruptTrackerHasFullContent(panelRef)
        end

        local function isGuidedPreviewTickerActive()
            return panelRef and panelRef._guidedPreviewTicker ~= nil
        end

        local function queueInterruptTrackerPreviewRefresh(source)
            local sourceKey = tostring(source or "guided_preview_repaint")
            if panelRef._interruptClosing or not panelRef:IsShown() then
                return
            end
            if isControlHydrating(panelRef) then
                return
            end

            panelRef._interruptQueuedPreviewReason = mergeInterruptPreviewRefreshSource(panelRef._interruptQueuedPreviewReason, sourceKey)
            if panelRef._interruptPreviewRefreshPending then
                return
            end

            panelRef._interruptPreviewRefreshPending = true
            local token = (tonumber(panelRef._interruptPreviewRefreshToken) or 0) + 1
            panelRef._interruptPreviewRefreshToken = token
            C_Timer.After(0, function()
                if not panelRef or panelRef._interruptPreviewRefreshToken ~= token then
                    return
                end
                panelRef._interruptPreviewRefreshPending = nil
                local queuedReason = tostring(panelRef._interruptQueuedPreviewReason or sourceKey)
                panelRef._interruptQueuedPreviewReason = nil
                if panelRef._interruptClosing or not panelRef:IsShown() then
                    return
                end
                if isControlHydrating(panelRef) then
                    return
                end
                if panelRef.RefreshGuidedPreview then
                    panelRef:RefreshGuidedPreview(GetTime(), queuedReason)
                end
            end)
        end

        local function StopGuidedPreviewTicker()
            if panelRef._guidedPreviewTicker then
                panelRef._guidedPreviewTicker:Cancel()
                panelRef._guidedPreviewTicker = nil
            end
            panelRef._guidedPreviewTickerToken = (tonumber(panelRef._guidedPreviewTickerToken) or 0) + 1
            panelRef._guidedPreviewCycleStart = nil
        end

        local function StartGuidedPreviewTicker()
            if isGuidedPreviewTickerActive() then
                return true
            end
            if not canRunGuidedPreviewTicker() then
                StopGuidedPreviewTicker()
                return false
            end
            if not (C_Timer and C_Timer.NewTicker) then
                return false
            end

            panelRef._guidedPreviewCycleStart = GetTime()
            local token = (tonumber(panelRef._guidedPreviewTickerToken) or 0) + 1
            panelRef._guidedPreviewTickerToken = token

            local ticker = nil
            ticker = C_Timer.NewTicker(GUIDED_PREVIEW_TICK_INTERVAL, function()
                if not panelRef or panelRef._guidedPreviewTicker ~= ticker then
                    return
                end
                if (tonumber(panelRef._guidedPreviewTickerToken) or 0) ~= token then
                    return
                end
                if not canRunGuidedPreviewTicker() then
                    StopGuidedPreviewTicker()
                    return
                end
                if panelRef.RefreshGuidedPreview then
                    panelRef:RefreshGuidedPreview(GetTime(), "passive_tick")
                end
            end)
            panelRef._guidedPreviewTicker = ticker
            return ticker ~= nil
        end

        local function syncGuidedPreviewTickerState()
            if canRunGuidedPreviewTicker() then
                StartGuidedPreviewTicker()
            else
                StopGuidedPreviewTicker()
            end
        end

        local function RelayoutGuidedPreviewCard()
            if not widgets.guidedPreviewCard then
                return
            end

            local db = getDB()
            local cardTokens = INTERRUPT_LAYOUT.cards
            local previewTokens = INTERRUPT_LAYOUT.preview
            local legendTokens = INTERRUPT_LAYOUT.legend
            local noteTokens = INTERRUPT_LAYOUT.notes
            widgets.guidedPreviewGreenText:SetText("Portal Authority in use \226\128\148 most accurate tracking.")
            widgets.guidedPreviewGoldText:SetText("Tracked without Portal Authority \226\128\148 still works, less precise.")
            widgets.guidedPreviewIconNote:SetText("Icons show class and tracked interrupt.")
            widgets.guidedPreviewValueNote:SetText("Right side shows timer or count from Row Value.")
            widgets.guidedPreviewSortNote:SetText("Rows sort automatically by availability, then remaining cooldown.")
            widgets.guidedPreviewLimitNote:SetText("Permanent cooldown changes from spec/talents are tracked. Conditional reductions are not currently displayed due to WoW API restrictions. Solar Beam shows 60s. Mind Freeze shows 15s.")
            local cardWidth = math.max(0, widgets.guidedPreviewCard:GetWidth() or 0)
            local previewGeo = computeInterruptGuidedPreviewGeometry(cardWidth, db)
            local cardInnerW = previewGeo.cardInnerW
            local sampleHeight = previewGeo.sampleHeight
            local showClassIcon = db.showClassIcon and true or false
            local showSpellIcon = db.showSpellIcon and true or false
            local rightDisplay = previewGeo.rightDisplay
            local iconSize = previewGeo.sampleRowHeight
            local valueWidth = previewGeo.valueWidth
            local separatorGap = previewGeo.separatorGap
            local separatorWidth = previewGeo.separatorWidth
            local legendStacked = previewGeo.legendStacked
            local legendWidth = previewGeo.legendWidth
            local sampleWidth = previewGeo.sampleWidth

            widgets.guidedPreviewSample:ClearAllPoints()
            widgets.guidedPreviewSample:SetPoint("TOPLEFT", widgets.guidedPreviewCard, "TOPLEFT", cardTokens.PAD, -previewGeo.previewTopY)
            widgets.guidedPreviewSample:SetSize(sampleWidth, sampleHeight)

            widgets.guidedPreviewLegend:ClearAllPoints()
            if legendStacked then
                widgets.guidedPreviewLegend:SetPoint("TOPLEFT", widgets.guidedPreviewSample, "BOTTOMLEFT", 0, -previewTokens.SAMPLE_GAP)
            else
                widgets.guidedPreviewLegend:SetPoint("TOPLEFT", widgets.guidedPreviewSample, "TOPRIGHT", previewTokens.SAMPLE_GAP, 0)
            end
            widgets.guidedPreviewLegend:SetSize(math.max(0, legendWidth), legendTokens.SEED_H)

            widgets.guidedPreviewGreenSwatch:ClearAllPoints()
            widgets.guidedPreviewGreenSwatch:SetPoint("TOPLEFT", widgets.guidedPreviewLegend, "TOPLEFT", 0, 0)
            widgets.guidedPreviewGreenSwatch:SetSize(legendTokens.SWATCH_SIZE, legendTokens.SWATCH_SIZE)
            local primaryTextW = math.max(legendTokens.PRIMARY_TEXT_MIN_W, legendWidth - (legendTokens.SWATCH_SIZE + legendTokens.SWATCH_TEXT_GAP))
            widgets.guidedPreviewGreenText:ClearAllPoints()
            widgets.guidedPreviewGreenText:SetPoint("TOPLEFT", widgets.guidedPreviewGreenSwatch, "TOPRIGHT", legendTokens.SWATCH_TEXT_GAP, legendTokens.SWATCH_TEXT_Y)
            widgets.guidedPreviewGreenText:SetWidth(primaryTextW)
            local greenBlockH = math.max(legendTokens.SWATCH_SIZE, measureInterruptFontStringHeight(widgets.guidedPreviewGreenText, legendTokens.SWATCH_SIZE))

            widgets.guidedPreviewGoldSwatch:ClearAllPoints()
            widgets.guidedPreviewGoldSwatch:SetPoint("TOPLEFT", widgets.guidedPreviewLegend, "TOPLEFT", 0, -(greenBlockH + legendTokens.SWATCH_ROW_GAP))
            widgets.guidedPreviewGoldSwatch:SetSize(legendTokens.SWATCH_SIZE, legendTokens.SWATCH_SIZE)
            widgets.guidedPreviewGoldText:ClearAllPoints()
            widgets.guidedPreviewGoldText:SetPoint("TOPLEFT", widgets.guidedPreviewGoldSwatch, "TOPRIGHT", legendTokens.SWATCH_TEXT_GAP, legendTokens.SWATCH_TEXT_Y)
            widgets.guidedPreviewGoldText:SetWidth(primaryTextW)
            local goldBlockH = math.max(legendTokens.SWATCH_SIZE, measureInterruptFontStringHeight(widgets.guidedPreviewGoldText, legendTokens.SWATCH_SIZE))

            local secondaryTop = greenBlockH + legendTokens.SWATCH_ROW_GAP + goldBlockH + legendTokens.SECONDARY_SECTION_GAP
            local secondaryTextW = math.max(legendTokens.PRIMARY_TEXT_MIN_W, legendWidth - legendTokens.SECONDARY_TEXT_RIGHT_PAD)

            widgets.guidedPreviewIconChip:ClearAllPoints()
            widgets.guidedPreviewIconChip:SetPoint("TOPLEFT", widgets.guidedPreviewLegend, "TOPLEFT", 0, -secondaryTop)
            widgets.guidedPreviewIconChip:SetSize(legendTokens.CHIP_W, legendTokens.CHIP_H)
            widgets.guidedPreviewIconNote:ClearAllPoints()
            widgets.guidedPreviewIconNote:SetPoint("LEFT", widgets.guidedPreviewIconChip, "RIGHT", legendTokens.CHIP_TEXT_GAP, 0)
            widgets.guidedPreviewIconNote:SetWidth(secondaryTextW)
            local iconNoteH = math.max(legendTokens.CHIP_H, measureInterruptFontStringHeight(widgets.guidedPreviewIconNote, legendTokens.CHIP_W))

            widgets.guidedPreviewValueChip:ClearAllPoints()
            widgets.guidedPreviewValueChip:SetPoint("TOPLEFT", widgets.guidedPreviewLegend, "TOPLEFT", 0, -(secondaryTop + iconNoteH + noteTokens.LIMIT_NOTE_GAP))
            widgets.guidedPreviewValueChip:SetSize(legendTokens.CHIP_W, legendTokens.CHIP_H)
            widgets.guidedPreviewValueNote:ClearAllPoints()
            widgets.guidedPreviewValueNote:SetPoint("LEFT", widgets.guidedPreviewValueChip, "RIGHT", legendTokens.CHIP_TEXT_GAP, 0)
            widgets.guidedPreviewValueNote:SetWidth(secondaryTextW)
            local valueNoteH = math.max(legendTokens.CHIP_H, measureInterruptFontStringHeight(widgets.guidedPreviewValueNote, legendTokens.CHIP_W))

            local legendHeight = secondaryTop + iconNoteH + noteTokens.LIMIT_NOTE_GAP + valueNoteH
            widgets.guidedPreviewLegend:SetHeight(legendHeight)
            local bodyHeight = legendStacked and (sampleHeight + previewTokens.SAMPLE_GAP + legendHeight) or math.max(sampleHeight, legendHeight)
            local helperTop = previewGeo.previewTopY + bodyHeight + noteTokens.HELPER_GAP

            widgets.guidedPreviewSortNote:ClearAllPoints()
            widgets.guidedPreviewSortNote:SetPoint("TOPLEFT", widgets.guidedPreviewCard, "TOPLEFT", cardTokens.PAD, -helperTop)
            widgets.guidedPreviewSortNote:SetWidth(cardInnerW)
            local sortNoteH = measureInterruptFontStringHeight(widgets.guidedPreviewSortNote, noteTokens.FLOOR)
            widgets.guidedPreviewLimitNote:ClearAllPoints()
            widgets.guidedPreviewLimitNote:SetPoint("TOPLEFT", widgets.guidedPreviewSortNote, "BOTTOMLEFT", 0, -noteTokens.LIMIT_NOTE_GAP)
            widgets.guidedPreviewLimitNote:SetWidth(cardInnerW)
            local limitNoteH = measureInterruptFontStringHeight(widgets.guidedPreviewLimitNote, noteTokens.FLOOR)

            for index, rowDef in ipairs(GUIDED_PREVIEW_ROWS) do
                local row = widgets.guidedPreviewRows[index]
                local topOffset = -((index - 1) * (previewGeo.sampleRowHeight + previewGeo.sampleRowGap))
                local laneX = 0
                local classIconGap = showSpellIcon and 0 or separatorGap
                local spellIconGap = separatorGap
                local separatorStartX, separatorLaneWidth = nil, 0

                row:ClearAllPoints()
                row:SetPoint("TOPLEFT", widgets.guidedPreviewSample, "TOPLEFT", 0, topOffset)
                row:SetSize(sampleWidth, previewGeo.sampleRowHeight)
                row.accent:Hide()

                if showClassIcon then
                    row.classIcon:Show()
                    row.classIcon:ClearAllPoints()
                    row.classIcon:SetPoint("TOPLEFT", row, "TOPLEFT", 0, 0)
                    row.classIcon:SetSize(iconSize, iconSize)
                    applyGuidedPreviewClassIcon(row.classIcon, rowDef.class)
                    laneX = iconSize + classIconGap
                    if classIconGap > 0 then
                        separatorStartX = laneX - classIconGap
                        separatorLaneWidth = classIconGap
                    end
                else
                    row.classIcon:Hide()
                end

                if showSpellIcon then
                    row.spellIcon:Show()
                    row.spellIcon:ClearAllPoints()
                    row.spellIcon:SetPoint("TOPLEFT", row, "TOPLEFT", laneX, 0)
                    row.spellIcon:SetSize(iconSize, iconSize)
                    row.spellIcon:SetTexture(rowDef.spellIcon)
                    row.spellIcon:SetDesaturated(not rowDef.ready)
                    laneX = laneX + iconSize + spellIconGap
                    if spellIconGap > 0 then
                        separatorStartX = laneX - spellIconGap
                        separatorLaneWidth = spellIconGap
                    end
                else
                    row.spellIcon:Hide()
                end

                if separatorStartX and separatorLaneWidth > 0 then
                    local separatorX = separatorStartX + math.floor(((separatorLaneWidth - separatorWidth) * 0.5) + 0.5)
                    row.separator:Show()
                    row.separator:ClearAllPoints()
                    row.separator:SetPoint("TOPLEFT", row, "TOPLEFT", separatorX, -previewTokens.ICON_SEPARATOR_VERTICAL_INSET)
                    row.separator:SetPoint("BOTTOMLEFT", row, "BOTTOMLEFT", separatorX, previewTokens.ICON_SEPARATOR_VERTICAL_INSET)
                    row.separator:SetWidth(separatorWidth)
                    if rowDef.accent == "fallback" then
                        row.separator:SetColorTexture(GUIDED_PREVIEW_FALLBACK[1], GUIDED_PREVIEW_FALLBACK[2], GUIDED_PREVIEW_FALLBACK[3], 1)
                    else
                        row.separator:SetColorTexture(GUIDED_PREVIEW_ADDON[1], GUIDED_PREVIEW_ADDON[2], GUIDED_PREVIEW_ADDON[3], 1)
                    end
                else
                    row.separator:Hide()
                end

                row._barLeft = laneX
                row._barAreaWidth = math.max(0, sampleWidth - laneX)
                row._valueWidth = valueWidth

                row.barBg:ClearAllPoints()
                row.barBg:SetPoint("TOPLEFT", row, "TOPLEFT", laneX, 0)
                row.barBg:SetPoint("BOTTOMRIGHT", row, "BOTTOMRIGHT", 0, 0)
                row.barBg:SetShown(row._barAreaWidth > 0)

                row.bar:ClearAllPoints()
                row.bar:SetPoint("TOPLEFT", row, "TOPLEFT", laneX, 0)
                row.bar:SetPoint("BOTTOMLEFT", row, "BOTTOMLEFT", laneX, 0)

                row.nameText:ClearAllPoints()
                row.nameText:SetPoint("LEFT", row, "LEFT", laneX + previewTokens.NAME_LEFT_INSET, 0)
                row.nameText:SetPoint("RIGHT", row, "RIGHT", -(valueWidth + previewTokens.NAME_RIGHT_GAP), 0)

                row.valueText:ClearAllPoints()
                row.valueText:SetPoint("RIGHT", row, "RIGHT", -previewTokens.VALUE_RIGHT_INSET, 0)
                row.valueText:SetWidth(valueWidth)
            end

            panelRef._guidedPreviewMetrics = {
                sampleWidth = sampleWidth,
                rowHeight = previewGeo.sampleRowHeight,
                rowGap = previewGeo.sampleRowGap,
                legendWidth = legendWidth,
                legendStacked = legendStacked,
                rightDisplay = rightDisplay,
                showClassIcon = showClassIcon,
                showSpellIcon = showSpellIcon,
                iconSize = iconSize,
                valueWidth = valueWidth,
                requiredHeight = math.ceil(previewGeo.previewTopY + bodyHeight + noteTokens.HELPER_GAP + sortNoteH + noteTokens.LIMIT_NOTE_GAP + limitNoteH + noteTokens.BOTTOM_PAD),
            }
        end

        local function RefreshGuidedPreview(now, source)
            local refreshSource = tostring(source or "guided_preview_repaint")
            if isGuidedPreviewRelayoutSource(refreshSource) or not panelRef._guidedPreviewMetrics then
                RelayoutGuidedPreviewCard()
            end

            local db = getDB()
            local metrics = panelRef._guidedPreviewMetrics or {}
            local rightDisplay = metrics.rightDisplay or (db.rightDisplay == "timer" and "timer" or "count")
            local fontColor = db.fontColor or { r = 1, g = 1, b = 1, a = 1 }
            local bgAlpha = math.max(0, math.min(1, tonumber(db.backgroundOpacity) or 0.88))
            local useClassColors = db.useClassColors and true or false
            local barTexturePath = resolveGuidedPreviewStatusbarPath(db.barTexture)
            local cycleStart = panelRef._guidedPreviewCycleStart or now or GetTime()
            local progress = (((now or GetTime()) - cycleStart) % INTERRUPT_LAYOUT.preview.CYCLE) / INTERRUPT_LAYOUT.preview.CYCLE
            local tickerOnly = refreshSource == "passive_tick"

            for index, rowDef in ipairs(GUIDED_PREVIEW_ROWS) do
                local row = widgets.guidedPreviewRows[index]
                if not row then
                    break
                end

                local remaining = 0
                if not rowDef.ready then
                    remaining = rowDef.startRemaining + ((rowDef.endRemaining - rowDef.startRemaining) * progress)
                    if remaining < 0 then
                        remaining = 0
                    end
                end

                local ratio = rowDef.ready and 1 or math.max(0, math.min(1, remaining / math.max(1, tonumber(rowDef.baseCd) or 1)))
                local barWidth = math.max(0, math.floor(((row._barAreaWidth or 0) * ratio) + 0.5))

                if not tickerOnly then
                    local barR, barG, barB = GUIDED_PREVIEW_NEUTRAL_BAR[1], GUIDED_PREVIEW_NEUTRAL_BAR[2], GUIDED_PREVIEW_NEUTRAL_BAR[3]
                    if useClassColors then
                        barR, barG, barB = getGuidedPreviewClassColor(rowDef.class)
                    end
                    row:SetBackdropColor(GUIDED_PREVIEW_BG_BAR[1], GUIDED_PREVIEW_BG_BAR[2], GUIDED_PREVIEW_BG_BAR[3], bgAlpha)
                    row:SetBackdropBorderColor(GUIDED_PREVIEW_ROW_BORDER[1], GUIDED_PREVIEW_ROW_BORDER[2], GUIDED_PREVIEW_ROW_BORDER[3], GUIDED_PREVIEW_ROW_BORDER[4])
                    row.barBg:SetColorTexture(0.02, 0.03, 0.05, math.max(0.24, bgAlpha * 0.82))
                    row.barBg:SetShown((row._barAreaWidth or 0) > 0)
                    row.bar:SetTexture(barTexturePath)
                    row.bar:SetVertexColor(barR, barG, barB, 0.92)
                    row.nameText:SetText(rowDef.name)
                    applyGuidedPreviewFont(row.nameText, db, db.fontSize, fontColor.r, fontColor.g, fontColor.b, fontColor.a)
                    applyGuidedPreviewFont(row.valueText, db, db.fontSize, fontColor.r, fontColor.g, fontColor.b, fontColor.a)
                end

                row.bar:SetWidth(barWidth)
                row.bar:SetShown(barWidth > 0)
                row.valueText:SetText(rightDisplay == "timer" and (rowDef.ready and "" or string.format("%.1f", remaining)) or tostring(rowDef.count))
            end
        end

        previewInterruptTrackerBackgroundOpacity = function()
            local bgAlpha = math.max(0, math.min(1, tonumber(getDB().backgroundOpacity) or 0.88))

            local module = getModule()
            if module then
                local function previewRuntimeRow(row)
                    if not row or not row.IsShown or not row:IsShown() or not row._displayMember then
                        return
                    end
                    row:SetBackdropColor(INTERRUPT_RUNTIME_BG_BAR[1], INTERRUPT_RUNTIME_BG_BAR[2], INTERRUPT_RUNTIME_BG_BAR[3], bgAlpha)
                    if row.barBg and row.barBg.GetVertexColor and row.barBg.SetVertexColor then
                        local r, g, b = row.barBg:GetVertexColor()
                        row.barBg:SetVertexColor(r or INTERRUPT_RUNTIME_BG_BAR[1], g or INTERRUPT_RUNTIME_BG_BAR[2], b or INTERRUPT_RUNTIME_BG_BAR[3], bgAlpha)
                    elseif row.barBg and row.barBg.SetVertexColor then
                        row.barBg:SetVertexColor(INTERRUPT_RUNTIME_BG_BAR[1], INTERRUPT_RUNTIME_BG_BAR[2], INTERRUPT_RUNTIME_BG_BAR[3], bgAlpha)
                    end
                end

                previewRuntimeRow(module.selfRow)
                for _, row in ipairs(module.rows or {}) do
                    previewRuntimeRow(row)
                end
            end

            for _, row in ipairs(widgets.guidedPreviewRows or {}) do
                if row then
                    row:SetBackdropColor(GUIDED_PREVIEW_BG_BAR[1], GUIDED_PREVIEW_BG_BAR[2], GUIDED_PREVIEW_BG_BAR[3], bgAlpha)
                    if row.barBg and (tonumber(row._barAreaWidth) or 0) > 0 then
                        row.barBg:SetColorTexture(0.02, 0.03, 0.05, math.max(0.24, bgAlpha * 0.82))
                    end
                end
            end
        end

        -- Guided preview controller
        local guidedPreviewController = {
            IsRelayoutSource = isGuidedPreviewRelayoutSource,
            StartTicker = StartGuidedPreviewTicker,
            StopTicker = StopGuidedPreviewTicker,
            RelayoutCard = RelayoutGuidedPreviewCard,
            Refresh = RefreshGuidedPreview,
        }

        panelRef.RefreshGuidedPreview = function(_, now, source)
            guidedPreviewController.Refresh(now or GetTime(), source or "guided_preview_repaint")
        end
        panelRef.StartGuidedPreviewTicker = function()
            return guidedPreviewController.StartTicker()
        end
        panelRef.StopGuidedPreviewTicker = function()
            guidedPreviewController.StopTicker()
        end

        local function syncInterruptStepperVisual(stepper, value)
            if not stepper then
                return
            end
            if stepper.valueEdit and stepper.valueEdit.IsShown and stepper.valueEdit:IsShown() then
                return
            end
            if stepper.SetVisualValue then
                stepper:SetVisualValue(value)
            elseif stepper.Refresh then
                stepper:Refresh()
            end
        end

        local function refreshInterruptSliderVisual(sliderSpec)
            if not sliderSpec then
                return
            end
            if sliderSpec.IsInteracting and sliderSpec:IsInteracting() then
                return
            end
            if sliderSpec.Refresh then
                sliderSpec:Refresh()
            end
        end

        local function refreshInterruptPickerVisual(spec, value, allowFullRefresh)
            if not spec then
                return
            end
            if allowFullRefresh and spec.Refresh then
                spec.Refresh()
                return
            end
            if spec.SetVisualSelectedValue then
                spec:SetVisualSelectedValue(value)
            end
        end

        local function syncInterruptSelectionControl(spec, value, syncLogicalValue)
            if not spec then
                return
            end
            if spec.SetVisualSelectedValue then
                spec:SetVisualSelectedValue(value)
            end
            if syncLogicalValue and spec.SetSelectedValue then
                spec:SetSelectedValue(value, false)
            end
        end

        local function applyInterruptModuleEnabledState(moduleEnabled, soundScopeEnabled)
            setSettingsControlEnabled(widgets.lockPosition, moduleEnabled)
            setSettingsControlEnabled(widgets.resetAnchor, moduleEnabled)
            setSettingsControlEnabled(widgets.widthStepper, moduleEnabled)
            setSettingsControlEnabled(widgets.rowHeightStepper, moduleEnabled)
            setSettingsControlEnabled(widgets.backgroundOpacity, moduleEnabled)
            setSettingsControlEnabled(widgets.font, moduleEnabled)
            setSettingsControlEnabled(widgets.fontSize, moduleEnabled)
            setSettingsControlEnabled(widgets.fontColorSwatch, moduleEnabled)
            setSettingsControlEnabled(widgets.barTexture, moduleEnabled)
            setSettingsControlEnabled(widgets.useClassColors, moduleEnabled)
            setSettingsControlEnabled(widgets.showClassIcon, moduleEnabled)
            setSettingsControlEnabled(widgets.showSpellIcon, moduleEnabled)
            setSettingsControlEnabled(widgets.rightDisplay, moduleEnabled)
            setSettingsControlEnabled(widgets.alertSound, moduleEnabled)
            setSettingsControlEnabled(widgets.alertScope, moduleEnabled and soundScopeEnabled)

            if widgets.lockRowContainer and widgets.lockRowContainer.SetAlpha then
                widgets.lockRowContainer:SetAlpha(moduleEnabled and 1 or 0.55)
            end
            if widgets.appearanceCard and widgets.appearanceCard.SetAlpha then
                widgets.appearanceCard:SetAlpha(moduleEnabled and 1 or 0.55)
            end
            if widgets.guidedPreviewCard and widgets.guidedPreviewCard.SetAlpha then
                widgets.guidedPreviewCard:SetAlpha(moduleEnabled and 1 or 0.55)
            end
            if widgets.alertCard and widgets.alertCard.SetAlpha then
                widgets.alertCard:SetAlpha(moduleEnabled and 1 or 0.55)
            end

            for _, textWidget in ipairs({
                widgets.lockHelper,
                widgets.appearanceHeader,
                widgets.alertHeader,
                widgets.guidedPreviewHeader,
                widgets.widthLabel,
                widgets.rowHeightLabel,
            }) do
                setSettingsTextEnabled(textWidget, moduleEnabled)
            end
        end

        refreshInterruptTrackerPanel = function(reason, opts)
            opts = type(opts) == "table" and opts or {}
            local db = getDB()
            local isFullRefresh = opts.full and true or false
            local guidedPreviewRefreshSource = tostring(opts.guidedPreviewRefreshSource or reason or "guided_preview_repaint")
            local moduleEnabled = db.enabled ~= false

            syncInterruptSelectionControl(widgets.moduleEnabled, moduleEnabled, true)
            syncInterruptSelectionControl(widgets.lockPosition, db.locked, true)
            if moduleEnabled then
                widgets.lockHelper:SetText(db.locked and "Interrupt Tracker is locked." or "Interrupt Tracker is unlocked - drag to reposition.")
            else
                widgets.lockHelper:SetText("Interrupt Tracker is disabled. Re-enable to edit settings.")
            end

            syncInterruptStepperVisual(widgets.widthStepper, math.floor(tonumber(db.width) or 220))
            syncInterruptStepperVisual(widgets.rowHeightStepper, math.floor(tonumber(db.rowHeight) or 22))
            syncInterruptStepperVisual(widgets.fontSize, math.floor(tonumber(db.fontSize) or 12))
            refreshInterruptSliderVisual(widgets.backgroundOpacity)
            refreshInterruptPickerVisual(widgets.font, tostring(db.fontPath or ""), isFullRefresh)
            refreshInterruptPickerVisual(widgets.barTexture, tostring(db.barTexture or ""), isFullRefresh)
            refreshInterruptPickerVisual(widgets.alertSound, db.alertSound, isFullRefresh)

            syncInterruptSelectionControl(widgets.useClassColors, db.useClassColors)
            syncInterruptSelectionControl(widgets.showClassIcon, db.showClassIcon)
            syncInterruptSelectionControl(widgets.showSpellIcon, db.showSpellIcon)
            syncInterruptSelectionControl(widgets.rightDisplay, db.rightDisplay)
            syncInterruptSelectionControl(widgets.alertScope, db.selfOnlyAlert)

            local soundEnabled = trim(tostring(db.alertSound or "")) ~= ""
            if widgets.alertScope and widgets.alertScope.SetEnabled then
                widgets.alertScope:SetEnabled(moduleEnabled and soundEnabled)
            end
            if widgets.alertScope and widgets.alertScope.label and widgets.alertScope.label.SetAlpha then
                widgets.alertScope.label:SetAlpha((moduleEnabled and soundEnabled) and 1 or 0.55)
            end
            applyInterruptModuleEnabledState(moduleEnabled, soundEnabled)

            local color = db.fontColor or { r = 1, g = 1, b = 1, a = 1 }
            widgets.fontColorSwatch:SetBackdropColor(color.r, color.g, color.b, color.a)

            if panelRef and panelRef.RefreshGuidedPreview then
                if isInterruptPreviewDirectEditSource(guidedPreviewRefreshSource) and not isControlHydrating(panelRef) then
                    if isGuidedPreviewTickerActive() and canRunGuidedPreviewTicker() then
                        invalidateInterruptPreviewRefresh()
                        panelRef:RefreshGuidedPreview(GetTime(), guidedPreviewRefreshSource)
                    else
                        queueInterruptTrackerPreviewRefresh(guidedPreviewRefreshSource)
                    end
                else
                    panelRef:RefreshGuidedPreview(GetTime(), guidedPreviewRefreshSource)
                end
            end

            if not moduleEnabled and panelRef and panelRef.StopGuidedPreviewTicker then
                panelRef:StopGuidedPreviewTicker()
            end
            syncGuidedPreviewTickerState()
            refreshSettingsWindowHeaderAccessoryIfHosted(panelRef)
        end

        passiveSyncInterruptTrackerPanel = function(reason)
            if not panelRef:IsShown() then
                return
            end
            refreshInterruptTrackerPanel(reason or "passive_tick", { full = false })
        end

        local function getInterruptRefreshRoute(source)
            local sourceKey = tostring(source or "")
            local isVisible = panelRef:IsShown()
            if sourceKey == "passive_tick" and not isVisible then
                return nil, sourceKey
            end
            if shouldSuppressSettingsFirstOpenExternalRefresh(panelRef) and (sourceKey == "size_changed" or sourceKey == "registered_refresh") then
                return nil, sourceKey
            end

            local mapping = INTERRUPT_TRIGGER_ROUTE_MAP[sourceKey]
            if not mapping then
                if type(debugSettingsLog) == "function" then
                    debugSettingsLog("interrupt tracker unknown refresh trigger:", sourceKey)
                end
                return isVisible and INTERRUPT_ROUTE_VISIBLE_FULL or INTERRUPT_ROUTE_HIDDEN_FULL, sourceKey
            end

            return isVisible and mapping.visible or mapping.hidden, sourceKey
        end

        local function clampInterruptScrollOffset(offset)
            local maxScroll = math.max(0, (scrollChild:GetHeight() or 0) - (scrollFrame:GetHeight() or 0))
            return math.max(0, math.min(tonumber(offset) or 0, maxScroll))
        end

        layoutInterruptTrackerPanel = function(reason, opts)
            opts = type(opts) == "table" and opts or {}
            local panelTokens = INTERRUPT_LAYOUT.panel
            local topTokens = INTERRUPT_LAYOUT.top
            local cardTokens = INTERRUPT_LAYOUT.cards
            local rowTokens = INTERRUPT_LAYOUT.rows
            local appearanceTokens = INTERRUPT_LAYOUT.appearance
            local previewTokens = INTERRUPT_LAYOUT.preview
            local alertTokens = INTERRUPT_LAYOUT.alert
            local db = getDB()
            local useHostedChrome = isPanelUsingCustomSettingsWindowHost(panelRef)
            local contentW = computeInterruptContentWidth(scrollFrame:GetWidth(), self:GetWidth())
            local surfaceGeo = computeInterruptCardFrameGeometry(contentW)
            scrollChild:SetWidth(contentW)

            local headerWidth = computeInterruptHeaderWidth(contentW)
            local y = -panelTokens.TOP_PAD
            if useHostedChrome then
                y = y - SETTINGS_WINDOW_HOSTED_TOP_RHYTHM_NUDGE
            end

            if useHostedChrome then
                setSettingsWindowChromeVisible(header, false, scrollChild)
                setSettingsWindowChromeVisible(widgets.sectionDescriptor, false, scrollChild)
            else
                setSettingsWindowChromeVisible(header, true)
                setSettingsWindowChromeVisible(widgets.sectionDescriptor, true, scrollChild)
                header:ClearAllPoints()
                header:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", panelTokens.HEADER_LEFT, y)
                header:SetWidth(headerWidth)
                if header.SetJustifyH then
                    header:SetJustifyH("LEFT")
                end
                y = y - measureInterruptFontStringHeight(header, panelTokens.HEADER_FLOOR) - topTokens.HEADER_BOTTOM_GAP
                y = layoutSettingsSectionDescriptor(
                    widgets.sectionDescriptor,
                    scrollChild,
                    panelTokens.HEADER_LEFT,
                    y,
                    headerWidth
                )
            end

            widgets.lockHelper:SetText(db.locked and "Interrupt Tracker is locked." or "Interrupt Tracker is unlocked - drag to reposition.")
            local lockLabel = widgets.lockPosition and widgets.lockPosition.label or nil
            local lockGeom = computeInterruptTopBlockLockGeometry(contentW, lockLabel)
            if useHostedChrome then
                setSettingsWindowChromeVisible(widgets.masterRowContainer, false, scrollChild)
                setSettingsWindowChromeVisible(widgets.moduleEnabled and widgets.moduleEnabled.label or nil, false, scrollChild)
                setSettingsWindowChromeVisible(widgets.moduleEnabled and widgets.moduleEnabled.control or nil, false, scrollChild)
            else
                setSettingsWindowChromeVisible(widgets.masterRowContainer, true)
                setSettingsWindowChromeVisible(widgets.moduleEnabled and widgets.moduleEnabled.label or nil, true)
                setSettingsWindowChromeVisible(widgets.moduleEnabled and widgets.moduleEnabled.control or nil, true)
                if widgets.moduleEnabled and widgets.moduleEnabled.Layout then
                    widgets.moduleEnabled:Layout(math.max(lockGeom.toggleW, 150))
                end
                local masterLabel = widgets.moduleEnabled and widgets.moduleEnabled.label or nil
                local masterLabelH = measureInterruptFontStringHeight(masterLabel, topTokens.LABEL_FLOOR)
                local masterToggleH = measureInterruptControlHeight(widgets.moduleEnabled and widgets.moduleEnabled.control, topTokens.LOCK_ROW_FLOOR)
                local masterRowH = math.max(topTokens.LOCK_ROW_FLOOR, masterLabelH, masterToggleH)
                widgets.masterRowContainer:ClearAllPoints()
                widgets.masterRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", panelTokens.CONTENT_LEFT, y)
                widgets.masterRowContainer:SetSize(lockGeom.rowW, masterRowH)
                if masterLabel then
                    masterLabel:ClearAllPoints()
                    masterLabel:SetPoint("LEFT", widgets.masterRowContainer, "LEFT", 0, 0)
                end
                if widgets.moduleEnabled and widgets.moduleEnabled.control then
                    widgets.moduleEnabled.control:ClearAllPoints()
                    widgets.moduleEnabled.control:SetPoint("LEFT", widgets.masterRowContainer, "LEFT", lockGeom.toggleX, 0)
                end
                y = y - masterRowH - 4
            end

            if widgets.lockPosition and widgets.lockPosition.Layout then
                widgets.lockPosition:Layout(lockGeom.toggleW)
            end
            local lockToggleH = measureInterruptControlHeight(widgets.lockPosition and widgets.lockPosition.control, topTokens.LOCK_ROW_FLOOR)
            local lockRowH = math.max(topTokens.LOCK_ROW_FLOOR, lockGeom.labelH, lockToggleH, topTokens.RESET_H)

            widgets.lockRowContainer:ClearAllPoints()
            widgets.lockRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", panelTokens.CONTENT_LEFT, y)
            widgets.lockRowContainer:SetSize(lockGeom.rowW, lockRowH)
            if lockLabel then
                lockLabel:ClearAllPoints()
                lockLabel:SetPoint("LEFT", widgets.lockRowContainer, "LEFT", 0, 0)
            end
            if widgets.lockPosition and widgets.lockPosition.control then
                widgets.lockPosition.control:ClearAllPoints()
                widgets.lockPosition.control:SetPoint("LEFT", widgets.lockRowContainer, "LEFT", lockGeom.toggleX, 0)
            end
            widgets.resetAnchor:ClearAllPoints()
            widgets.resetAnchor:SetSize(topTokens.RESET_W, topTokens.RESET_H)
            widgets.resetAnchor:SetPoint("LEFT", widgets.lockRowContainer, "LEFT", lockGeom.resetX, 0)
            y = y - lockRowH

            widgets.lockHelper:ClearAllPoints()
            widgets.lockHelper:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", panelTokens.CONTENT_LEFT, y - lockGeom.helperGap)
            widgets.lockHelper:SetWidth(math.max(topTokens.HELPER_MIN_W, contentW - panelTokens.CONTENT_LEFT - panelTokens.CONTENT_RIGHT))
            if widgets.lockHelper.SetJustifyH then widgets.lockHelper:SetJustifyH("LEFT") end
            setInterruptSingleLineEllipsis(widgets.lockHelper, widgets.lockHelper:GetText() or "", math.max(topTokens.HELPER_MIN_W, contentW - panelTokens.CONTENT_LEFT - panelTokens.CONTENT_RIGHT))
            local lockHelperH = measureInterruptFontStringHeight(widgets.lockHelper, topTokens.HELPER_FLOOR)
            y = y - lockGeom.helperGap - lockHelperH

            widgets.settingsDivider:ClearAllPoints()
            local dividerY = y - (lockGeom.dividerGap * 0.5)
            widgets.settingsDivider:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", panelTokens.CONTENT_LEFT, dividerY)
            widgets.settingsDivider:SetPoint("TOPRIGHT", scrollChild, "TOPRIGHT", -panelTokens.CONTENT_RIGHT, dividerY)
            widgets.settingsDivider:SetHeight(topTokens.DIVIDER_H)
            y = y - lockGeom.dividerGap

            local cardX = surfaceGeo.x
            local cardW = surfaceGeo.width
            local cardInnerW = surfaceGeo.innerWidth

            local appearanceH = computeInterruptCardHeight(appearanceTokens.ROW_COUNT, rowTokens.CONTENT_H)
            widgets.appearanceCard:ClearAllPoints()
            widgets.appearanceCard:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", cardX, y)
            widgets.appearanceCard:SetSize(cardW, appearanceH)
            layoutInterruptCardHeader(widgets.appearanceCard, widgets.appearanceHeader)

            local widthRowTop = getInterruptCardRowTop(1)
            local widthControlH = math.max(rowTokens.CONTROL_FLOOR_H, (widgets.widthStepper and widgets.widthStepper.control and widgets.widthStepper.control:GetHeight()) or rowTokens.DEFAULT_CONTROL_H)
            local widthLabelW = math.ceil(widgets.widthLabel:GetStringWidth() or 0)
            local rowHeightLabelW = math.ceil(widgets.rowHeightLabel:GetStringWidth() or 0)
            local appearanceFirstRowGeo = computeInterruptAppearanceFirstRowGeometry(widthLabelW, rowHeightLabelW)
            widgets.widthStepper.control:ClearAllPoints()
            widgets.widthStepper.control:SetPoint("TOPLEFT", widgets.appearanceCard, "TOPLEFT", appearanceFirstRowGeo.widthControlX, widthRowTop)
            widgets.widthStepper.control:SetWidth(appearanceFirstRowGeo.stepperW)
            widgets.widthLabel:ClearAllPoints()
            widgets.widthLabel:SetPoint("LEFT", widgets.appearanceCard, "TOPLEFT", appearanceFirstRowGeo.widthLabelX, widthRowTop - math.floor(widthControlH * 0.5))

            widgets.rowHeightLabel:ClearAllPoints()
            widgets.rowHeightLabel:SetPoint("LEFT", widgets.appearanceCard, "TOPLEFT", appearanceFirstRowGeo.rowHeightLabelX, widthRowTop - math.floor(widthControlH * 0.5))
            widgets.rowHeightStepper.control:ClearAllPoints()
            widgets.rowHeightStepper.control:SetPoint("TOPLEFT", widgets.appearanceCard, "TOPLEFT", appearanceFirstRowGeo.rowHeightControlX, widthRowTop)
            widgets.rowHeightStepper.control:SetWidth(appearanceFirstRowGeo.stepperW)

            layoutInterruptCardRow(widgets.appearanceCard, appearanceTokens.ROW_SLOTS.BACKGROUND_OPACITY, widgets.backgroundOpacity.label, widgets.backgroundOpacity.control, {
                width = appearanceTokens.PICKER_W,
            })
            if widgets.backgroundOpacity.SetWidth then
                widgets.backgroundOpacity:SetWidth(appearanceTokens.PICKER_W)
            end

            local fontSizeControlW = math.max(0, (widgets.fontSize and widgets.fontSize.control and widgets.fontSize.control:GetWidth()) or 0)
            local fontSizeControlH = math.max(rowTokens.CONTROL_FLOOR_H, (widgets.fontSize and widgets.fontSize.control and widgets.fontSize.control:GetHeight()) or rowTokens.DEFAULT_CONTROL_H)
            local fontRowTop = getInterruptCardRowTop(appearanceTokens.ROW_SLOTS.FONT)
            local fontRowGeo = computeInterruptAppearanceFontRowGeometry(cardInnerW, fontSizeControlW)
            layoutInterruptCardRow(widgets.appearanceCard, appearanceTokens.ROW_SLOTS.FONT, widgets.font.label, widgets.font, {
                width = fontRowGeo.pickerW,
                controlX = fontRowGeo.fontControlX,
            })
            if widgets.fontSize and widgets.fontSize.control then
                widgets.fontSize.control:ClearAllPoints()
                widgets.fontSize.control:SetPoint("TOPLEFT", widgets.appearanceCard, "TOPLEFT", fontRowGeo.fontSizeX, fontRowTop)
            end
            widgets.fontColorSwatch:ClearAllPoints()
            widgets.fontColorSwatch:SetPoint("LEFT", widgets.appearanceCard, "TOPLEFT", fontRowGeo.swatchX, fontRowTop - math.floor(fontSizeControlH * 0.5))
            widgets.fontColorSwatch:SetSize(
                (FIXED_FOOTPRINTS and FIXED_FOOTPRINTS.FONT_COLOR_SWATCH_SIZE) or appearanceTokens.FONT_SWATCH_FALLBACK_SIZE,
                (FIXED_FOOTPRINTS and FIXED_FOOTPRINTS.FONT_COLOR_SWATCH_SIZE) or appearanceTokens.FONT_SWATCH_FALLBACK_SIZE
            )

            layoutInterruptCardRow(widgets.appearanceCard, appearanceTokens.ROW_SLOTS.BAR_TEXTURE, widgets.barTexture.label, widgets.barTexture, {
                width = appearanceTokens.PICKER_W,
            })
            layoutInterruptCardRow(widgets.appearanceCard, appearanceTokens.ROW_SLOTS.USE_CLASS_COLORS, widgets.useClassColors.label, widgets.useClassColors, {
                layoutWidth = appearanceTokens.SEGMENTED_W,
            })
            layoutInterruptCardRow(widgets.appearanceCard, appearanceTokens.ROW_SLOTS.SHOW_CLASS_ICON, widgets.showClassIcon.label, widgets.showClassIcon, {
                layoutWidth = appearanceTokens.SEGMENTED_W,
            })
            layoutInterruptCardRow(widgets.appearanceCard, appearanceTokens.ROW_SLOTS.SHOW_SPELL_ICON, widgets.showSpellIcon.label, widgets.showSpellIcon, {
                layoutWidth = appearanceTokens.SEGMENTED_W,
            })
            layoutInterruptCardRow(widgets.appearanceCard, appearanceTokens.ROW_SLOTS.RIGHT_DISPLAY, widgets.rightDisplay.label, widgets.rightDisplay, {
                layoutWidth = appearanceTokens.RIGHT_DISPLAY_W,
            })
            y = y - appearanceH - cardTokens.SECTION_GAP

            widgets.guidedPreviewCard:ClearAllPoints()
            widgets.guidedPreviewCard:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", cardX, y)
            widgets.guidedPreviewCard:SetSize(cardW, previewTokens.CARD_MIN_H)
            layoutInterruptCardHeader(widgets.guidedPreviewCard, widgets.guidedPreviewHeader)
            if isGuidedPreviewRelayoutSource(reason) or not panelRef._guidedPreviewMetrics or math.abs((tonumber(panelRef._guidedPreviewCardWidth) or 0) - cardW) > 0.5 then
                guidedPreviewController.RelayoutCard()
            end
            panelRef._guidedPreviewCardWidth = cardW
            local guidedCardH = math.max((panelRef._guidedPreviewMetrics and panelRef._guidedPreviewMetrics.requiredHeight) or previewTokens.CARD_MIN_H, previewTokens.CARD_MIN_H)
            widgets.guidedPreviewCard:SetHeight(guidedCardH)
            y = y - guidedCardH - cardTokens.SECTION_GAP

            local alertH = computeInterruptCardHeight(1, rowTokens.CONTENT_H)
            widgets.alertCard:ClearAllPoints()
            widgets.alertCard:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", cardX, y)
            widgets.alertCard:SetSize(cardW, alertH)
            layoutInterruptCardHeader(widgets.alertCard, widgets.alertHeader)

            local alertRowTop = getInterruptCardRowTop(alertTokens.ROW_SLOTS.SOUND)
            if widgets.alertScope and widgets.alertScope.Layout then
                widgets.alertScope:Layout(alertTokens.SCOPE_CONTROL_W)
            end
            local scopeLabelWidth = math.ceil((widgets.alertScope and widgets.alertScope.label and widgets.alertScope.label:GetStringWidth()) or 0)
            local alertRowGeo = computeInterruptAlertRowGeometry(cardInnerW, scopeLabelWidth)
            layoutInterruptCardRow(widgets.alertCard, alertTokens.ROW_SLOTS.SOUND, widgets.alertSound.label, widgets.alertSound, {
                width = alertRowGeo.pickerW,
            })
            local alertControlH = math.max(rowTokens.CONTROL_FLOOR_H, widgets.alertSound.control:GetHeight() or rowTokens.DEFAULT_CONTROL_H)
            if widgets.alertScope then
                widgets.alertScope.label:ClearAllPoints()
                widgets.alertScope.label:SetPoint("LEFT", widgets.alertCard, "TOPLEFT", alertRowGeo.scopeLabelX, alertRowTop - math.floor(alertControlH * 0.5))
                widgets.alertScope.control:ClearAllPoints()
                widgets.alertScope.control:SetPoint("TOPLEFT", widgets.alertCard, "TOPLEFT", alertRowGeo.scopeControlX, alertRowTop)
            end
            y = y - alertH - cardTokens.SECTION_GAP

            local used = math.abs(y) + panelTokens.BOTTOM_PAD
            scrollChild:SetHeight(math.max(scrollFrame:GetHeight(), used))
            updateScrollBehavior(scrollFrame, scrollChild)

            if opts.preserveScroll then
                scrollFrame:SetVerticalScroll(clampInterruptScrollOffset(opts.previousScroll))
            elseif tostring(reason or "") == "on_show" then
                scrollFrame:SetVerticalScroll(0)
            end
        end

        local function runInterruptTrackerHiddenFullRefresh(source)
            layoutInterruptTrackerPanel(source or "hidden_refresh")
            refreshInterruptTrackerPanel(source or "hidden_refresh", {
                full = true,
                afterLayout = true,
            })
        end

        local function runInterruptTrackerVisibleFullLayout(source)
            local sourceKey = tostring(source or "on_show")
            local preserveScroll = sourceKey ~= "on_show"
            local previousScroll = preserveScroll and (tonumber(scrollFrame:GetVerticalScroll()) or 0) or 0
            layoutInterruptTrackerPanel(sourceKey, {
                preserveScroll = preserveScroll,
                previousScroll = previousScroll,
            })
            refreshInterruptTrackerPanel(sourceKey, {
                full = true,
                afterLayout = true,
            })
        end

        routeInterruptTrackerRefresh = function(source)
            local route, sourceKey = getInterruptRefreshRoute(source)
            if not route then
                return
            end
            if route == INTERRUPT_ROUTE_PASSIVE then
                passiveSyncInterruptTrackerPanel(sourceKey)
            elseif route == INTERRUPT_ROUTE_VISIBLE_FULL then
                if panelRef:IsShown() then
                    runInterruptTrackerVisibleFullLayout(sourceKey)
                else
                    runInterruptTrackerHiddenFullRefresh(sourceKey)
                end
            else
                runInterruptTrackerHiddenFullRefresh(sourceKey)
            end
        end

        -- Layout / refresh controllers
        local layoutController = {
            ClampScrollOffset = clampInterruptScrollOffset,
            Layout = layoutInterruptTrackerPanel,
        }
        local refreshController = {
            SyncStepperVisual = syncInterruptStepperVisual,
            RefreshSliderVisual = refreshInterruptSliderVisual,
            RefreshPickerVisual = refreshInterruptPickerVisual,
            SyncSelectionControl = syncInterruptSelectionControl,
            Refresh = refreshInterruptTrackerPanel,
            PassiveSync = passiveSyncInterruptTrackerPanel,
            GetRoute = getInterruptRefreshRoute,
            RunHiddenFullRefresh = runInterruptTrackerHiddenFullRefresh,
            RunVisibleFullLayout = runInterruptTrackerVisibleFullLayout,
            Route = routeInterruptTrackerRefresh,
        }

        self._layout = layoutController.Layout
        self._refresh = refreshController.Refresh
        self._routeInterruptTrackerRefresh = refreshController.Route
        self._runInterruptTrackerVisibleFullLayout = refreshController.RunVisibleFullLayout
        self._invalidateInterruptPreviewRefresh = invalidateInterruptPreviewRefresh
        self._settingsFirstOpenKey = "interrupt"
        self._settingsFirstOpenSizeTarget = scrollFrame
        self._settingsFirstOpenRender = function(panel, source)
            if panel and panel._runInterruptTrackerVisibleFullLayout then
                panel._runInterruptTrackerVisibleFullLayout(source or "on_show")
            elseif panel and panel._routeInterruptTrackerRefresh then
                panel._routeInterruptTrackerRefresh(source or "on_show")
            end
        end
        self._settingsFirstOpenIsReady = interruptTrackerHasFullContent
        registerRefreshCallback(function()
            if shouldSuppressSettingsFirstOpenExternalRefresh(panelRef) then
                return
            end
            if refreshController.Route then
                refreshController.Route("registered_refresh")
            end
        end, panelRef)
        scrollFrame:SetScript("OnSizeChanged", function()
            if handleSettingsFirstOpenSizeReady(panelRef, "size_changed") then
                return
            end
            if shouldSuppressSettingsFirstOpenExternalRefresh(panelRef) then
                return
            end
            if refreshController.Route then
                refreshController.Route("size_changed")
            end
        end)
        self._initialized = true
        settingsSearchRuntime.endDescriptorCapture(self)
        if refreshController.Route and not (self.IsShown and self:IsShown()) then
            refreshController.Route("hidden_refresh")
        end
    end

    panel:SetScript("OnShow", function(self)
        if not self._paAnchored then
            local parent = self:GetParent()
            if parent then
                self:ClearAllPoints()
                self:SetAllPoints(parent)
                self._paAnchored = true
            end
        end
        self._interruptClosing = false
        self:EnsureBuilt()
        if not handleSettingsFirstOpenPanelShow(self) then
            if self._runInterruptTrackerVisibleFullLayout then
                withPanelHydration(self, function()
                    self._runInterruptTrackerVisibleFullLayout("on_show")
                end)
            elseif self._routeInterruptTrackerRefresh then
                withPanelHydration(self, function()
                    self._routeInterruptTrackerRefresh("on_show")
                end)
            end
        end
    end)

    panel:HookScript("OnHide", function(self)
        self._interruptClosing = true
        handleSettingsFirstOpenPanelHide(self)
        if self._invalidateInterruptPreviewRefresh then
            self._invalidateInterruptPreviewRefresh()
        end
        if self.StopGuidedPreviewTicker then
            self:StopGuidedPreviewTicker()
        end
    end)

    return panel
end

local function createKeystoneUtilityPanel()
    local panel = CreateFrame("Frame")
    panel.name = "Keystone Utility"
    panel._paSearchSectionKey = "keystone"
    panel._paSearchSectionName = panel.name
    local ensureKeystonePanelAnchored
    local renderKeystoneWhenReady
    local keystoneHasSizedViewport
    local startKeystoneRenderBootstrap

    panel.EnsureBuilt = function(self)
        if self._initialized and self._layout and self._refresh then return end
        ensureDatabase()
        if not PortalAuthorityDB then
            return
        end
        settingsSearchRuntime.beginDescriptorCapture(self)

        local scrollFrame, scrollChild = createScrollableChild(self)
        if not scrollFrame or not scrollChild then
            settingsSearchRuntime.endDescriptorCapture(self)
            return
        end
        self._sizingFrame = scrollFrame
        self._kuScrollChild = scrollChild
        local widgets = {}
        local panelRef = self

        local function onApply()
            if PortalAuthority and PortalAuthority.ApplyKeystoneUtilitySettings then
                PortalAuthority:ApplyKeystoneUtilitySettings()
            end
            if panelRef and panelRef._refresh then
                panelRef._refresh()
            end
        end

        local header = createStyledFontString(scrollChild, "ARTWORK", "GameFontNormalLarge", 14)
        header:SetText("|cffffd100Keystone Utility|r")
        widgets.sectionDescriptor = createSettingsSectionDescriptor(scrollChild, "Configure keystone assistant behavior and automation.")

        local helperHeader = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlight", 12)
        helperHeader:SetText("Keystone Assistant")

        local function createSubtleCard(parent)
            local card = CreateFrame("Frame", nil, parent, "BackdropTemplate")
            card:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
                insets = { left = 0, right = 0, top = 0, bottom = 0 },
            })
            card:SetBackdropColor(0.06, 0.07, 0.09, 0.42)
            card:SetBackdropBorderColor(0.20, 0.23, 0.29, 0.82)
            return card
        end

        local function createStatusChip(parent, titleText)
            local chip = CreateFrame("Frame", nil, parent, "BackdropTemplate")
            chip:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
                insets = { left = 0, right = 0, top = 0, bottom = 0 },
            })
            chip:SetBackdropColor(0.09, 0.10, 0.13, 0.86)
            chip:SetBackdropBorderColor(0.23, 0.26, 0.31, 0.90)
            chip:SetSize(108, 34)

            chip.title = createStyledFontString(chip, "ARTWORK", "GameFontHighlightSmall", 10)
            chip.title:SetPoint("TOPLEFT", chip, "TOPLEFT", 8, -5)
            chip.title:SetPoint("TOPRIGHT", chip, "TOPRIGHT", -8, -5)
            chip.title:SetJustifyH("LEFT")
            chip.title:SetTextColor(0.72, 0.74, 0.78, 0.94)
            chip.title:SetText(titleText or "")

            chip.value = createStyledFontString(chip, "ARTWORK", "GameFontHighlightSmall", 11)
            chip.value:SetPoint("BOTTOMLEFT", chip, "BOTTOMLEFT", 8, 5)
            chip.value:SetPoint("BOTTOMRIGHT", chip, "BOTTOMRIGHT", -8, 5)
            chip.value:SetJustifyH("LEFT")
            chip.value:SetTextColor(0.86, 0.88, 0.92, 1)
            chip.value:SetText("")

            function chip:SetState(text, tone)
                self.value:SetText(tostring(text or ""))
                if tone == "good" then
                    self.value:SetTextColor(0.74, 0.94, 0.76, 1)
                    self:SetBackdropBorderColor(0.20, 0.39, 0.23, 0.90)
                elseif tone == "warn" then
                    self.value:SetTextColor(0.94, 0.84, 0.58, 1)
                    self:SetBackdropBorderColor(0.44, 0.34, 0.18, 0.90)
                else
                    self.value:SetTextColor(0.86, 0.88, 0.92, 1)
                    self:SetBackdropBorderColor(0.23, 0.26, 0.31, 0.90)
                end
            end

            return chip
        end

        local disabledEnabledChoices = {
            { label = "Disabled", value = false, toggleState = "off" },
            { label = "Enabled", value = true, toggleState = "on" },
        }
        local modifierChoices = {
            { label = "Shift", value = "SHIFT" },
            { label = "Ctrl", value = "CTRL" },
        }

        local function createKUSettingSegment(labelText, choices, getter, setter, opts)
            opts = type(opts) == "table" and opts or {}
            local internalValue = getter and getter() or nil
            local segmented = createPremiumSegmentedChoice(
                scrollChild,
                labelText or "",
                nil,
                choices or {},
                function(value)
                    internalValue = value
                    if setter then
                        setter(value)
                    end
                    onApply()
                end,
                {
                    semantic = opts.semantic or "toggle",
                    normalizeValue = opts.normalizeValue,
                    getValue = function()
                        return internalValue
                    end,
                    setValue = function(value)
                        internalValue = value
                    end,
                    controlHeight = 22,
                    textSize = 11,
                    minWidth = opts.minWidth or 170,
                    segmentGap = opts.segmentGap or 4,
                    segmentMinWidth = opts.segmentMinWidth or 48,
                }
            )
            local spec = {}
            spec.label = segmented.label
            spec.control = segmented.control
            spec.buttons = segmented.buttons
            spec.Layout = function(_, width)
                segmented:Layout(width)
            end
            spec.SetEnabled = function(_, enabled)
                segmented:SetEnabled(enabled and true or false)
            end
            spec.SetVisualSelectedValue = function(_, value)
                internalValue = value
                segmented:SetVisualSelectedValue(value)
            end
            spec.Refresh = function()
                if getter then
                    local v = getter()
                    internalValue = v
                    segmented:SetVisualSelectedValue(v)
                end
            end
            return spec
        end

        widgets.assistantCard = createSubtleCard(scrollChild)
        widgets.releaseCard = createSubtleCard(scrollChild)
        widgets.topSectionDivider = scrollChild:CreateTexture(nil, "ARTWORK")
        widgets.topSectionDivider:SetColorTexture(0.24, 0.27, 0.32, 0.10)

        widgets.statusStrip = CreateFrame("Frame", nil, widgets.assistantCard)
        widgets.statusKeystone = createStatusChip(widgets.statusStrip, "Keystone")
        widgets.statusLeader = createStatusChip(widgets.statusStrip, "Leader/Assist")
        widgets.statusAutomation = createStatusChip(widgets.statusStrip, "Automation")

        widgets.keystoneHelperEnabled = createKUSettingSegment(
            "Enable Keystone Assistant",
            disabledEnabledChoices,
            function() return PA_SafeBool(PortalAuthorityDB and PortalAuthorityDB.keystoneHelperEnabled) end,
            function(value)
                if PortalAuthorityDB then
                    PortalAuthorityDB.keystoneHelperEnabled = PA_SafeBool(value)
                end
            end,
            { semantic = "toggle" }
        )
        local helperDesc = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlightSmall", 11)
        helperDesc:SetText("Adds Readycheck and Pull buttons to the Keystone window.")
        helperDesc:SetTextColor(0.72, 0.72, 0.72, 1)
        helperDesc:SetJustifyH("LEFT")

        widgets.keystoneAutoSlotEnabled = createKUSettingSegment(
            "Auto Slot Keystone",
            disabledEnabledChoices,
            function() return PA_SafeBool(PortalAuthorityDB and PortalAuthorityDB.keystoneAutoSlotEnabled) end,
            function(value)
                if PortalAuthorityDB then
                    PortalAuthorityDB.keystoneAutoSlotEnabled = PA_SafeBool(value)
                end
            end,
            { semantic = "toggle" }
        )
        local autoSlotDesc = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlightSmall", 11)
        autoSlotDesc:SetText("When the keystone receptacle opens, attempts to slot your keystone automatically.")
        autoSlotDesc:SetTextColor(0.72, 0.72, 0.72, 1)
        autoSlotDesc:SetJustifyH("LEFT")

        widgets.keystoneAutoStartEnabled = createKUSettingSegment(
            "Auto Start Key after Pull",
            disabledEnabledChoices,
            function() return PA_SafeBool(PortalAuthorityDB and PortalAuthorityDB.keystoneAutoStartEnabled) end,
            function(value)
                if PortalAuthorityDB then
                    PortalAuthorityDB.keystoneAutoStartEnabled = PA_SafeBool(value)
                end
            end,
            { semantic = "toggle" }
        )
        local autoStartDesc = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlightSmall", 11)
        autoStartDesc:SetText("When a pull countdown ends, attempts to start the key (out of combat).")
        autoStartDesc:SetTextColor(0.72, 0.72, 0.72, 1)
        autoStartDesc:SetJustifyH("LEFT")

        local releaseHeader = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlight", 12)
        releaseHeader:SetText("Release Spirit Rules")

        widgets.releaseGateEnabled = createKUSettingSegment(
            "Hide Release Spirit (Hold-to-Release)",
            disabledEnabledChoices,
            function() return PA_SafeBool(PortalAuthorityDB and PortalAuthorityDB.releaseGateEnabled) end,
            function(value)
                if PortalAuthorityDB then
                    PortalAuthorityDB.releaseGateEnabled = PA_SafeBool(value)
                end
            end,
            { semantic = "toggle" }
        )
        local releaseEnabledDesc = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlightSmall", 11)
        releaseEnabledDesc:SetText("Hides Release Spirit until you hold a modifier. Does not affect resurrection prompts.")
        releaseEnabledDesc:SetTextColor(0.72, 0.72, 0.72, 1)
        releaseEnabledDesc:SetJustifyH("LEFT")

        local function normalizeModifier(value)
            local raw = string.upper(trim(tostring(value or "")))
            if raw == "CTRL" then
                return "CTRL"
            end
            return "SHIFT"
        end

        widgets.releaseGateModifier = createKUSettingSegment(
            "Reveal Modifier",
            modifierChoices,
            function() return normalizeModifier(PortalAuthorityDB and PortalAuthorityDB.releaseGateModifier) end,
            function(value)
                if PortalAuthorityDB then
                    PortalAuthorityDB.releaseGateModifier = normalizeModifier(value)
                end
            end,
            {
                semantic = "selection",
                normalizeValue = normalizeModifier,
                minWidth = 120,
                segmentMinWidth = 54,
            }
        )

        local holdLabel = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlight", 12)
        holdLabel:SetText("Hold (sec)")
        local HOLD_STEP = 0.05
        local HOLD_SHIFT_MULTIPLIER = 5
        local HOLD_MIN = 0.00
        local HOLD_MAX = 5.00
        local holdCurrentValue = nil
        local holdEditing = false
        local holdControlEnabled = true
        widgets.releaseHoldStepper = CreateFrame("Frame", nil, scrollChild)
        widgets.releaseHoldStepper:SetSize(84, 22)

        local holdStepperBg = CreateFrame("Frame", nil, widgets.releaseHoldStepper, "BackdropTemplate")
        holdStepperBg:SetPoint("TOPLEFT", widgets.releaseHoldStepper, "TOPLEFT", 0, 0)
        holdStepperBg:SetPoint("BOTTOMRIGHT", widgets.releaseHoldStepper, "BOTTOMRIGHT", 0, 0)
        holdStepperBg:SetBackdrop({
            bgFile = "Interface\\Buttons\\WHITE8x8",
            edgeFile = "Interface\\Buttons\\WHITE8x8",
            edgeSize = 1,
            insets = { left = 0, right = 0, top = 0, bottom = 0 },
        })
        holdStepperBg:SetBackdropColor(0.10, 0.11, 0.14, 0.95)
        holdStepperBg:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)

        local function createHoldArrow(symbol)
            local btn = CreateFrame("Button", nil, widgets.releaseHoldStepper)
            btn:SetSize(12, 16)
            btn._text = createStyledFontString(btn, "ARTWORK", "GameFontHighlight", 11)
            btn._text:SetPoint("CENTER", btn, "CENTER", 0, 0)
            btn._text:SetText(symbol)
            btn._text:SetTextColor(0.74, 0.74, 0.76, 1)
            btn:SetScript("OnEnter", function(selfBtn)
                selfBtn._text:SetTextColor(0.95, 0.95, 0.98, 1)
            end)
            btn:SetScript("OnLeave", function(selfBtn)
                selfBtn._text:SetTextColor(0.74, 0.74, 0.76, 1)
            end)
            return btn
        end

        local holdMinus = createHoldArrow("<")
        local holdPlus = createHoldArrow(">")
        local holdValueButton = CreateFrame("Button", nil, widgets.releaseHoldStepper)
        holdValueButton:SetSize(40, 16)
        local holdValueText = createStyledFontString(holdValueButton, "ARTWORK", "GameFontHighlightSmall", 11)
        holdValueText:SetPoint("CENTER", holdValueButton, "CENTER", 0, 0)
        holdValueText:SetTextColor(0.86, 0.86, 0.90, 1)
        local holdValueEdit = CreateFrame("EditBox", nil, holdValueButton)
        holdValueEdit:SetAllPoints(holdValueButton)
        holdValueEdit:SetAutoFocus(false)
        holdValueEdit:SetJustifyH("CENTER")
        holdValueEdit:SetTextInsets(0, 0, 0, 0)
        holdValueEdit:SetTextColor(1, 1, 1, 1)
        holdValueEdit:SetHighlightColor(1, 1, 1, 0.25)
        applyGlobalFontToObject(holdValueEdit, 11)
        holdValueEdit:Hide()

        holdMinus:SetPoint("LEFT", widgets.releaseHoldStepper, "LEFT", 6, 0)
        holdValueButton:SetPoint("LEFT", holdMinus, "RIGHT", 4, 0)
        holdPlus:SetPoint("LEFT", holdValueButton, "RIGHT", 4, 0)

        local function normalizeHoldSeconds(value)
            local n = tonumber(value)
            if n == nil then
                local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
                n = tonumber(defaults.releaseGateHoldSeconds) or 1.0
            end
            if n < HOLD_MIN then n = HOLD_MIN end
            if n > HOLD_MAX then n = HOLD_MAX end
            n = math.floor((n / HOLD_STEP) + 0.5) * HOLD_STEP
            n = math.floor((n * 100) + 0.5) / 100
            if n < HOLD_MIN then n = HOLD_MIN end
            if n > HOLD_MAX then n = HOLD_MAX end
            return n
        end

        local function formatHoldSeconds(value)
            return string.format("%.2f", normalizeHoldSeconds(value))
        end

        local function setHoldVisual(value)
            holdCurrentValue = normalizeHoldSeconds(value)
            holdValueText:SetText(formatHoldSeconds(holdCurrentValue))
            if holdEditing then
                holdValueEdit:SetText(formatHoldSeconds(holdCurrentValue))
            end
        end

        local function commitHoldValue(value)
            local clean = normalizeHoldSeconds(value)
            local old = normalizeHoldSeconds(PortalAuthorityDB and PortalAuthorityDB.releaseGateHoldSeconds)
            setHoldVisual(clean)
            if math.abs(clean - old) < 0.0001 then
                return false
            end
            if PortalAuthorityDB then
                PortalAuthorityDB.releaseGateHoldSeconds = clean
            end
            onApply()
            return true
        end

        local function endHoldEdit(commit)
            if not holdEditing then
                return
            end
            holdEditing = false
            if commit then
                local parsed = tonumber(trim(holdValueEdit:GetText() or ""))
                if parsed ~= nil then
                    commitHoldValue(parsed)
                end
            end
            holdValueEdit:Hide()
            holdValueText:Show()
            holdValueEdit:ClearFocus()
            setHoldVisual(holdCurrentValue)
        end

        local function beginHoldEdit()
            if not holdControlEnabled then
                return
            end
            holdEditing = true
            holdValueText:Hide()
            holdValueEdit:SetText(formatHoldSeconds(holdCurrentValue))
            holdValueEdit:Show()
            holdValueEdit:SetFocus()
            holdValueEdit:HighlightText()
        end

        local function setHoldEnabled(enabled)
            holdControlEnabled = enabled and true or false
            widgets.releaseHoldStepper:SetAlpha(holdControlEnabled and 1 or 0.55)
            holdMinus:SetEnabled(holdControlEnabled)
            holdPlus:SetEnabled(holdControlEnabled)
            holdValueButton:SetEnabled(holdControlEnabled)
            if not holdControlEnabled and holdEditing then
                endHoldEdit(false)
            end
        end

        holdMinus:SetScript("OnClick", function()
            if not holdControlEnabled then
                return
            end
            local mult = (IsShiftKeyDown and IsShiftKeyDown()) and HOLD_SHIFT_MULTIPLIER or 1
            commitHoldValue((holdCurrentValue or normalizeHoldSeconds(nil)) - (HOLD_STEP * mult))
        end)
        holdPlus:SetScript("OnClick", function()
            if not holdControlEnabled then
                return
            end
            local mult = (IsShiftKeyDown and IsShiftKeyDown()) and HOLD_SHIFT_MULTIPLIER or 1
            commitHoldValue((holdCurrentValue or normalizeHoldSeconds(nil)) + (HOLD_STEP * mult))
        end)
        holdValueButton:SetScript("OnClick", beginHoldEdit)
        holdValueEdit:SetScript("OnEnterPressed", function(edit)
            endHoldEdit(true)
            edit:ClearFocus()
        end)
        holdValueEdit:SetScript("OnEscapePressed", function(edit)
            endHoldEdit(false)
            edit:ClearFocus()
        end)
        holdValueEdit:SetScript("OnEditFocusLost", function()
            -- Explicit-action only: no commit on focus loss.
            endHoldEdit(false)
        end)

        widgets.releaseHoldStepper.SetEnabled = setHoldEnabled
        widgets.releaseHoldStepper.Refresh = function()
            setHoldVisual(normalizeHoldSeconds(PortalAuthorityDB and PortalAuthorityDB.releaseGateHoldSeconds))
        end
        widgets.releaseHoldStepper.SetVisualValue = setHoldVisual
        setHoldVisual(normalizeHoldSeconds(PortalAuthorityDB and PortalAuthorityDB.releaseGateHoldSeconds))

        local KU_UpdateKeystoneTooltipPreview
        local KU_PositionPreviewTooltip
        local KU_ReadPreviewBodyLeftLines
        local releaseHoldDesc = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlightSmall", 11)
        releaseHoldDesc:SetText("Hold the reveal modifier; after holding for this delay, Release Spirit will auto-trigger. Range: 0.00-5.00s (decimals allowed).")
        releaseHoldDesc:SetTextColor(0.72, 0.72, 0.72, 1)
        releaseHoldDesc:SetJustifyH("LEFT")
        local tooltipHeader = createStyledFontString(scrollChild, "ARTWORK", "GameFontNormalLarge", 14)
        tooltipHeader:SetText("|cffffd100Keystone Tooltip|r")
        local tooltipSubheader = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlight", 12)
        tooltipSubheader:SetText("Tooltip Customization")
        local KEYSTONE_UTILITY_LAYOUT = {
            SCROLL_WIDTH_FUDGE = 8,
            MIN_CONTENT_W = 560,
            HEADER_MIN_W = 220,
            LABEL_MIN_W = 150,
            LABEL_TEXT_PAD = 8,
            LABEL_TO_CONTROL_GAP = 12,
            CONTROL_MIN_W = 170,
            CONTROL_MAX_W = 220,
            CONTROL_WIDTH_RATIO = 0.34,
            DESC_MIN_W = 120,
            DESC_RIGHT_PAD = 10,
            STATUS_CHIP_MIN_W = 92,
