        local function KU_ApplyExternalTooltipSkin(tt)
            if not tt then
                return
            end
            local elv = _G.ElvUI
            local E = nil
            if type(elv) == "table" then
                E = elv[1] or elv
            end
            if E and E.GetModule then
                local okTT, TT = pcall(E.GetModule, E, "Tooltip")
                if okTT and TT and TT.SetStyle then
                    pcall(TT.SetStyle, TT, tt)
                end
            end
        end

        local function refreshTooltipAffixesSwatch()
            local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
            local fallback = defaults.keystoneTooltipAffixesColor or { r = 1, g = 0.82, b = 0, a = 1 }
            local c = PortalAuthorityDB and PortalAuthorityDB.keystoneTooltipAffixesColor or fallback
            local r = tonumber(c and c.r) or fallback.r
            local g = tonumber(c and c.g) or fallback.g
            local b = tonumber(c and c.b) or fallback.b
            local a = tonumber(c and c.a) or fallback.a
            for _, row in ipairs(tooltipBuilder.rows) do
                if row.colorSwatch and row.colorSwatch.SetBackdropColor then
                    row.colorSwatch:SetBackdropColor(r, g, b, a)
                end
            end
        end

        local function openKeystoneTooltipAffixesColorPicker(onChangedFn)
            if not (ColorPickerFrame and ColorPickerFrame.SetupColorPickerAndShow) then
                return
            end
            local defaults = (PortalAuthority and PortalAuthority.defaults) or {}
            local fallback = defaults.keystoneTooltipAffixesColor or { r = 1, g = 0.82, b = 0, a = 1 }
            local cur = PortalAuthorityDB and PortalAuthorityDB.keystoneTooltipAffixesColor or fallback
            local r = tonumber(cur and cur.r) or fallback.r
            local g = tonumber(cur and cur.g) or fallback.g
            local b = tonumber(cur and cur.b) or fallback.b
            local a = tonumber(cur and cur.a) or fallback.a
            ColorPickerFrame:SetupColorPickerAndShow({
                r = r,
                g = g,
                b = b,
                opacity = 1 - a,
                hasOpacity = true,
                swatchFunc = function()
                    local nr, ng, nb = ColorPickerFrame:GetColorRGB()
                    local na = 1 - (OpacitySliderFrame and OpacitySliderFrame:GetValue() or 0)
                    PortalAuthorityDB.keystoneTooltipAffixesColor = { r = nr, g = ng, b = nb, a = na }
                    if onChangedFn then onChangedFn() end
                end,
                opacityFunc = function()
                    local nr, ng, nb = ColorPickerFrame:GetColorRGB()
                    local na = 1 - (OpacitySliderFrame and OpacitySliderFrame:GetValue() or 0)
                    PortalAuthorityDB.keystoneTooltipAffixesColor = { r = nr, g = ng, b = nb, a = na }
                    if onChangedFn then onChangedFn() end
                end,
                cancelFunc = function(prev)
                    PortalAuthorityDB.keystoneTooltipAffixesColor = restoreColorPickerPrevious(prev, fallback)
                    if onChangedFn then onChangedFn() end
                end,
            })
        end

        local function KU_FindFirstKeystoneLinkInBags()
            local firstBag = BACKPACK_CONTAINER or 0
            local lastBag = NUM_TOTAL_EQUIPPED_BAG_SLOTS or 4
            for bag = firstBag, lastBag do
                local slots = 0
                if C_Container and C_Container.GetContainerNumSlots then
                    local okSlots, bagSlots = pcall(C_Container.GetContainerNumSlots, bag)
                    if okSlots then
                        slots = tonumber(bagSlots) or 0
                    end
                end
                for slot = 1, slots do
                    if C_Container and C_Container.GetContainerItemLink then
                        local okLink, link = pcall(C_Container.GetContainerItemLink, bag, slot)
                        if okLink and type(link) == "string" and string.find(link, "|Hkeystone:", 1, true) then
                            return link
                        end
                    end
                end
            end
            return nil
        end

        local function KU_BuildFallbackKeystoneContext()
            local mapID = 0
            local level = 10
            local affixIDs = {}
            local displayName = "Sample Keystone"

            if C_MythicPlus and C_MythicPlus.GetOwnedKeystoneMapID then
                local ok, ownedMapID = pcall(C_MythicPlus.GetOwnedKeystoneMapID)
                if ok then
                    mapID = tonumber(ownedMapID) or mapID
                end
            end
            if mapID <= 0 and C_MythicPlus and C_MythicPlus.GetOwnedKeystoneChallengeMapID then
                local ok, ownedChallengeMapID = pcall(C_MythicPlus.GetOwnedKeystoneChallengeMapID)
                if ok then
                    mapID = tonumber(ownedChallengeMapID) or mapID
                end
            end
            if mapID <= 0 and C_ChallengeMode and C_ChallengeMode.GetActiveChallengeMapID then
                local ok, activeMapID = pcall(C_ChallengeMode.GetActiveChallengeMapID)
                if ok then
                    mapID = tonumber(activeMapID) or mapID
                end
            end
            if mapID <= 0 and C_ChallengeMode and C_ChallengeMode.GetMapTable then
                local ok, mapTable = pcall(C_ChallengeMode.GetMapTable)
                if ok and type(mapTable) == "table" then
                    for _, v in ipairs(mapTable) do
                        local n = tonumber(v) or 0
                        if n > 0 then
                            mapID = n
                            break
                        end
                    end
                end
            end

            if C_MythicPlus and C_MythicPlus.GetOwnedKeystoneLevel then
                local ok, ownedLevel = pcall(C_MythicPlus.GetOwnedKeystoneLevel)
                if ok then
                    local n = tonumber(ownedLevel) or 0
                    if n > 0 then
                        level = n
                    end
                end
            end

            if C_MythicPlus and C_MythicPlus.GetCurrentAffixes then
                local ok, currentAffixes = pcall(C_MythicPlus.GetCurrentAffixes)
                if ok and type(currentAffixes) == "table" then
                    for _, a in ipairs(currentAffixes) do
                        local id = 0
                        if type(a) == "table" then
                            id = tonumber(a.id) or tonumber(a.affixID) or tonumber(a[1]) or 0
                        else
                            id = tonumber(a) or 0
                        end
                        if id > 0 then
                            affixIDs[#affixIDs + 1] = id
                            if #affixIDs >= 3 then
                                break
                            end
                        end
                    end
                end
            end
            if #affixIDs == 0 and C_ChallengeMode and C_ChallengeMode.GetAffixInfo then
                for id = 1, 200 do
                    local ok, name = pcall(C_ChallengeMode.GetAffixInfo, id)
                    if ok and type(name) == "string" and trim(name) ~= "" then
                        affixIDs[#affixIDs + 1] = id
                        if #affixIDs >= 3 then
                            break
                        end
                    end
                end
            end

            if mapID > 0 and C_ChallengeMode and C_ChallengeMode.GetMapUIInfo then
                local ok, name = pcall(C_ChallengeMode.GetMapUIInfo, mapID)
                if ok and type(name) == "string" and trim(name) ~= "" then
                    displayName = trim(name)
                end
            end

            return mapID, level, affixIDs, displayName
        end

        local function KU_BuildFallbackKeystoneHyperlink(mapID, level, affixIDs)
            local safeMapID = tonumber(mapID) or 0
            local safeLevel = tonumber(level) or 10
            if safeLevel <= 0 then
                safeLevel = 10
            end

            local affixParts = {}
            if type(affixIDs) == "table" then
                for i = 1, math.min(#affixIDs, 3) do
                    local n = tonumber(affixIDs[i]) or 0
                    if n > 0 then
                        affixParts[#affixParts + 1] = tostring(n)
                    end
                end
            end
            local affixSuffix = (#affixParts > 0) and (":" .. table.concat(affixParts, ":")) or ""
            return string.format("|cffa335ee|Hkeystone:180653:%d:%d%s|h[Keystone]|h|r", safeMapID, safeLevel, affixSuffix)
        end

        local function KU_SeedFallbackPreviewLines(previewTooltip, displayName, level, affixIDs)
            if not previewTooltip then
                return
            end
            previewTooltip:ClearLines()
            previewTooltip:AddLine("Mythic Keystone", 0.64, 0.21, 0.93)
            previewTooltip:AddLine("Keystone: " .. (displayName or "Sample Keystone"), 1, 1, 1)
            previewTooltip:AddLine("Mythic Level: " .. tostring(math.floor(tonumber(level) or 10)), 1, 1, 1)
            previewTooltip:AddLine("Resilient Level: 2", 1, 1, 1)
            previewTooltip:AddLine("Soulbound", 1, 1, 1)
            previewTooltip:AddLine("Unique", 1, 1, 1)
            previewTooltip:AddLine("Dungeon Modifiers", 1, 1, 1)

            if type(affixIDs) == "table" then
                for i = 1, math.min(#affixIDs, 3) do
                    local affixID = tonumber(affixIDs[i]) or 0
                    if affixID > 0 then
                        local affixName = nil
                        if C_ChallengeMode and C_ChallengeMode.GetAffixInfo then
                            local ok, name = pcall(C_ChallengeMode.GetAffixInfo, affixID)
                            if ok and type(name) == "string" and trim(name) ~= "" then
                                affixName = trim(name)
                            end
                        end
                        previewTooltip:AddLine("- " .. (affixName or ("Affix " .. tostring(affixID))), 1, 1, 1)
                    end
                end
            end

            previewTooltip:AddLine("Duration: 33:00", 1, 1, 1)
            previewTooltip:AddLine("Your fate awaits.", 1, 0.82, 0)
        end

        local function KU_ApplyPreviewWordWrap(tooltip, previewAnchor)
            if not tooltip or not tooltip.GetName then
                return
            end
            local baseName = tooltip:GetName()
            if type(baseName) ~= "string" or baseName == "" then
                return
            end
            local anchorW = 0
            if previewAnchor and previewAnchor.GetWidth then
                anchorW = tonumber(previewAnchor:GetWidth()) or 0
            end
            if tooltipBuilder and tooltipBuilder.previewPane and tooltipBuilder.previewPane.GetWidth then
                local paneW = tonumber(tooltipBuilder.previewPane:GetWidth()) or 0
                if paneW > 0 then
                    anchorW = math.max(anchorW, paneW - 20)
                end
            end
            if anchorW <= 0 then
                anchorW = 280
            end
            local maxW = anchorW - 20
            if maxW < 240 then maxW = 240 end
            if maxW > 280 then maxW = 280 end

            if tooltip.SetWidth then
                pcall(tooltip.SetWidth, tooltip, maxW)
            end
            local textW = maxW - 20
            for i = 1, (tooltip.NumLines and tooltip:NumLines() or 0) do
                local left = _G[baseName .. "TextLeft" .. i]
                local right = _G[baseName .. "TextRight" .. i]
                if left then
                    if left.SetWidth then pcall(left.SetWidth, left, textW) end
                    if left.SetWordWrap then pcall(left.SetWordWrap, left, true) end
                    if left.SetNonSpaceWrap then pcall(left.SetNonSpaceWrap, left, true) end
                end
                if right then
                    if right.SetWidth then pcall(right.SetWidth, right, textW) end
                    if right.SetWordWrap then pcall(right.SetWordWrap, right, true) end
                    if right.SetNonSpaceWrap then pcall(right.SetNonSpaceWrap, right, true) end
                end
            end
        end

        local function KU_FitPreviewTooltipFrameToContent(tooltip)
            if not tooltip or not tooltip.GetName then
                return
            end
            local baseName = tooltip:GetName()
            if type(baseName) ~= "string" or baseName == "" then
                return
            end

            local minLeft, maxRight, minBottom, maxTop
            local sumLineH = 0
            for i = 1, (tooltip.NumLines and tooltip:NumLines() or 0) do
                local left = _G[baseName .. "TextLeft" .. i]
                local right = _G[baseName .. "TextRight" .. i]
                local leftShown = left and left.IsShown and left:IsShown() and trim(left:GetText() or "") ~= ""
                local rightShown = right and right.IsShown and right:IsShown() and trim(right:GetText() or "") ~= ""
                if leftShown then
                    local l, r, t, b = left:GetLeft(), left:GetRight(), left:GetTop(), left:GetBottom()
                    if l and r and t and b then
                        minLeft = minLeft and math.min(minLeft, l) or l
                        maxRight = maxRight and math.max(maxRight, r) or r
                        maxTop = maxTop and math.max(maxTop, t) or t
                        minBottom = minBottom and math.min(minBottom, b) or b
                    end
                end
                if rightShown then
                    local l, r, t, b = right:GetLeft(), right:GetRight(), right:GetTop(), right:GetBottom()
                    if l and r and t and b then
                        minLeft = minLeft and math.min(minLeft, l) or l
                        maxRight = maxRight and math.max(maxRight, r) or r
                        maxTop = maxTop and math.max(maxTop, t) or t
                        minBottom = minBottom and math.min(minBottom, b) or b
                    end
                end
                if leftShown or rightShown then
                    local leftH = (left and left.GetStringHeight and tonumber(left:GetStringHeight())) or 0
                    local rightH = (right and right.GetStringHeight and tonumber(right:GetStringHeight())) or 0
                    local lineH = math.max(leftH, rightH, 12)
                    sumLineH = sumLineH + lineH + 2
                end
            end

            local targetW, targetH
            if minLeft and maxRight and maxTop and minBottom then
                targetW = math.max(1, math.ceil((maxRight - minLeft) + 20))
                targetH = math.max(1, math.ceil((maxTop - minBottom) + 14))
            end
            if sumLineH > 0 then
                local byStringH = math.max(1, math.ceil(sumLineH + 14))
                if targetH then
                    targetH = math.max(targetH, byStringH)
                else
                    targetH = byStringH
                end
            end
            if targetW and tooltip.SetWidth then
                pcall(tooltip.SetWidth, tooltip, targetW)
            end
            if targetH and tooltip.SetHeight then
                pcall(tooltip.SetHeight, tooltip, targetH)
            end
        end

        local function KU_RequestPreviewSettle(tooltip, previewAnchor)
            if not tooltip then
                return
            end
            tooltip._paPreviewSettleAnchor = previewAnchor
            tooltip._paPreviewSettlePasses = 90
            local settleDriver = tooltipBuilder and tooltipBuilder.previewSettleDriver or nil
            if settleDriver then
                settleDriver._elapsed = 0
                settleDriver:Show()
            end
        end

        local function KU_RunPreviewSettleStep(tooltip)
            if not tooltip then
                return
            end
            local anchor = tooltip._paPreviewSettleAnchor or widgets.keystoneTooltipPreviewAnchor
            if not anchor then
                tooltip._paPreviewSettlePasses = 0
                return
            end
            KU_ApplyPreviewWordWrap(tooltip, anchor)
            tooltip:Show()
            KU_FitPreviewTooltipFrameToContent(tooltip)
            KU_PositionPreviewTooltip(tooltip, anchor)
            tooltip._paPreviewSettlePasses = (tonumber(tooltip._paPreviewSettlePasses) or 1) - 1
            if (tooltip._paPreviewSettlePasses or 0) < 0 then
                tooltip._paPreviewSettlePasses = 0
            end
        end

        if not tooltipBuilder.previewSettleDriver then
            local settleDriver = CreateFrame("Frame", nil, tooltipBuilder.previewPane)
            settleDriver:Hide()
            settleDriver:SetScript("OnUpdate", function(selfDriver, elapsed)
                selfDriver._elapsed = (tonumber(selfDriver._elapsed) or 0) + (tonumber(elapsed) or 0)
                if selfDriver._elapsed < 0.08 then
                    return
                end
                selfDriver._elapsed = 0
                if not panelRef or not panelRef.IsShown or not panelRef:IsShown() then
                    selfDriver:Hide()
                    return
                end
                local tt = widgets and widgets.keystoneTooltipPreviewTooltip or nil
                local anchor = widgets and widgets.keystoneTooltipPreviewAnchor or nil
                if tt and tt.IsShown and tt:IsShown() and anchor then
                    if (tonumber(tt._paPreviewSettlePasses) or 0) > 0 then
                        KU_RunPreviewSettleStep(tt)
                    else
                        KU_ApplyPreviewWordWrap(tt, anchor)
                        KU_FitPreviewTooltipFrameToContent(tt)
                        KU_PositionPreviewTooltip(tt, anchor)
                    end
                end
            end)
            tooltipBuilder.previewSettleDriver = settleDriver
            panelRef._kuTooltipPreviewSettleDriver = settleDriver
        end

        KU_UpdateKeystoneTooltipPreview = function()
            local previewAnchor = widgets.keystoneTooltipPreviewAnchor
            local previewTooltip = widgets.keystoneTooltipPreviewTooltip
            if not previewAnchor or not previewTooltip then
                return
            end
            KU_ApplyExternalTooltipSkin(previewTooltip)

            local link = KU_FindFirstKeystoneLinkInBags()
            previewTooltip:SetOwner(previewAnchor, "ANCHOR_NONE")
            previewTooltip:ClearAllPoints()
            previewTooltip:SetPoint("TOPLEFT", previewAnchor, "TOPLEFT", 6, -6)
            previewTooltip:ClearLines()

            if type(link) ~= "string" then
                local mapID, level, affixIDs, displayName = KU_BuildFallbackKeystoneContext()
                local fallbackLink = KU_BuildFallbackKeystoneHyperlink(mapID, level, affixIDs)
                local okSet = false
                if previewTooltip.SetHyperlink and type(fallbackLink) == "string" then
                    okSet = pcall(previewTooltip.SetHyperlink, previewTooltip, fallbackLink)
                end
                if not okSet then
                    KU_SeedFallbackPreviewLines(previewTooltip, displayName, level, affixIDs)
                end
                if PortalAuthority and PortalAuthority.KeystoneTooltip_OnItemTooltip then
                    PortalAuthority:KeystoneTooltip_OnItemTooltip(previewTooltip, { hyperlink = fallbackLink })
                end
                KU_ApplyPreviewWordWrap(previewTooltip, previewAnchor)
                previewTooltip:Show()
                KU_RequestPreviewSettle(previewTooltip, previewAnchor)
                KU_RunPreviewSettleStep(previewTooltip)
                return
            end

            previewTooltip:SetHyperlink(link)
            if PortalAuthority and PortalAuthority.KeystoneTooltip_OnItemTooltip then
                PortalAuthority:KeystoneTooltip_OnItemTooltip(previewTooltip, { hyperlink = link })
            end
            KU_ApplyPreviewWordWrap(previewTooltip, previewAnchor)
            previewTooltip:Show()
            KU_RequestPreviewSettle(previewTooltip, previewAnchor)
            KU_RunPreviewSettleStep(previewTooltip)
        end

        local function KU_Normalize(v)
            local ok, s = pcall(tostring, v)
            if not ok or s == nil then
                return ""
            end
            s = trim(tostring(s))
            if s == "" then
                return ""
            end
            return string.upper(s)
        end

        local KU_RefreshTooltipBuilderVisual = nil
        panelRef._kuHydrateKeystoneTooltipControls = function()
            if KU_RefreshTooltipBuilderVisual then
                KU_RefreshTooltipBuilderVisual()
            end
        end
        panelRef._kuHydrateKeystoneTooltipVisualOnly = panelRef._kuHydrateKeystoneTooltipControls
        panelRef._kuRefreshHoldForce = function()
            if widgets.releaseHoldStepper and widgets.releaseHoldStepper.Refresh then
                widgets.releaseHoldStepper:Refresh()
            end
        end
        panelRef._commitHoldIfDirty = nil

        KU_PositionPreviewTooltip = function(previewTooltip, previewAnchor)
            if not previewTooltip or not previewAnchor then
                return
            end
            local x = 6
            local y = -8
            previewTooltip:ClearAllPoints()
            previewTooltip:SetPoint("TOPLEFT", previewAnchor, "TOPLEFT", x, y)
        end

        if widgets.keystoneTooltipPreviewTooltip
            and widgets.keystoneTooltipPreviewTooltip.HasScript
            and widgets.keystoneTooltipPreviewTooltip:HasScript("OnTooltipSetItem")
        then
            widgets.keystoneTooltipPreviewTooltip:HookScript("OnTooltipSetItem", function(tt)
                local anchor = widgets.keystoneTooltipPreviewAnchor
                if not anchor then return end
                KU_RequestPreviewSettle(tt, anchor)
                KU_RunPreviewSettleStep(tt)
            end)
        end
        if widgets.keystoneTooltipPreviewTooltip
            and widgets.keystoneTooltipPreviewTooltip.HasScript
            and widgets.keystoneTooltipPreviewTooltip:HasScript("OnShow")
        then
            widgets.keystoneTooltipPreviewTooltip:HookScript("OnShow", function(tt)
                local anchor = widgets.keystoneTooltipPreviewAnchor
                if not anchor then return end
                if (tonumber(tt._paPreviewSettlePasses) or 0) <= 0 then
                    KU_RequestPreviewSettle(tt, anchor)
                end
            end)
        end
        if widgets.keystoneTooltipPreviewTooltip
            and widgets.keystoneTooltipPreviewTooltip.HasScript
            and widgets.keystoneTooltipPreviewTooltip:HasScript("OnUpdate")
        then
            widgets.keystoneTooltipPreviewTooltip:HookScript("OnUpdate", function(tt)
                if (tonumber(tt._paPreviewSettlePasses) or 0) > 0 then
                    KU_RunPreviewSettleStep(tt)
                end
            end)
        end
        if widgets.keystoneTooltipPreviewTooltip
            and widgets.keystoneTooltipPreviewTooltip.HasScript
            and widgets.keystoneTooltipPreviewTooltip:HasScript("OnHide")
        then
            widgets.keystoneTooltipPreviewTooltip:HookScript("OnHide", function(tt)
                tt._paPreviewSettlePasses = 0
            end)
        end

        local function KU_SetBuilderStatus(text)
            local value = trim(tostring(text or ""))
            tooltipBuilder.statusText:SetText(value)
        end

        local function KU_ClearBuilderStatus()
            KU_SetBuilderStatus("")
        end

        local function KU_ValuesEqual(a, b)
            if type(a) == "boolean" or type(b) == "boolean" then
                return PA_SafeBool(a) == PA_SafeBool(b)
            end
            return KU_Normalize(a) == KU_Normalize(b)
        end

        local function KU_ResolveVisualChoice(rawValue, choices)
            for _, choice in ipairs(choices or {}) do
                if KU_ValuesEqual(choice.value, rawValue) then
                    return choice.value, choice.label
                end
            end
            for _, choice in ipairs(choices or {}) do
                if KU_Normalize(choice.value) == "NO_CHANGES" then
                    return choice.value, choice.label
                end
            end
            local first = choices and choices[1]
            if first then
                return first.value, first.label
            end
            return nil, ""
        end

        local function KU_SetRowHighlight(row, hovered, selected)
            if not row then
                return
            end
            if selected then
                row.highlightBg:SetAlpha(0.12)
                row.highlightAccent:SetAlpha(0.34)
            elseif hovered then
                row.highlightBg:SetAlpha(0.07)
                row.highlightAccent:SetAlpha(0)
            else
                row.highlightBg:SetAlpha(0)
                row.highlightAccent:SetAlpha(0)
            end
        end

        local function KU_SetOverlayHighlight(overlay, hovered, selected)
            if not overlay then
                return
            end
            if selected then
                overlay._bg:SetAlpha(0.12)
                overlay._accent:SetAlpha(0.34)
            elseif hovered then
                overlay._bg:SetAlpha(0.07)
                overlay._accent:SetAlpha(0)
            else
                overlay._bg:SetAlpha(0)
                overlay._accent:SetAlpha(0)
            end
        end

        local function KU_RefreshLinkedVisuals()
            for _, row in ipairs(tooltipBuilder.rows) do
                KU_SetRowHighlight(row, tooltipBuilder.hoveredLineId == row.lineId, tooltipBuilder.selectedLineId == row.lineId)
            end
            for _, overlay in ipairs(tooltipBuilder.previewOverlays) do
                KU_SetOverlayHighlight(overlay, tooltipBuilder.hoveredLineId == overlay.lineId, tooltipBuilder.selectedLineId == overlay.lineId)
            end
        end

        local function KU_SetHoveredLine(lineId)
            local normalized = lineId
            if normalized and not tooltipBuilder.rowsById[normalized] then
                normalized = nil
            end
            if tooltipBuilder.hoveredLineId ~= normalized then
                tooltipBuilder.hoveredLineId = normalized
                KU_RefreshLinkedVisuals()
            end
        end

        local function KU_ClearHover()
            if tooltipBuilder.hoveredLineId ~= nil then
                tooltipBuilder.hoveredLineId = nil
                KU_RefreshLinkedVisuals()
            end
        end

        local function KU_SelectLine(lineId, fromPreviewClick)
            if lineId and tooltipBuilder.rowsById[lineId] then
                if tooltipBuilder.selectedLineId == lineId then
                    tooltipBuilder.selectedLineId = nil
                else
                    tooltipBuilder.selectedLineId = lineId
                end
                KU_ClearBuilderStatus()
            else
                tooltipBuilder.selectedLineId = nil
            end
            KU_RefreshLinkedVisuals()

            if fromPreviewClick and lineId and tooltipBuilder.rowsById[lineId] then
                -- Non-scrollable layout: no per-row viewport to adjust.
            end
        end

        tooltipBuilder.inspectorPane:EnableMouse(true)
        tooltipBuilder.inspectorPane:SetScript("OnMouseDown", function(_, mouseButton)
            if mouseButton == "LeftButton" then
                KU_SelectLine(nil, false)
            end
        end)
        tooltipBuilder.previewHitLayer:SetScript("OnMouseDown", function(_, mouseButton)
            if mouseButton == "LeftButton" then
                KU_SelectLine(nil, false)
            end
        end)

        local function KU_OnTooltipCommit(lineId, affectsLayout)
            tooltipBuilder._lastCommit = {
                lineId = lineId,
                affectsLayout = affectsLayout and true or false,
            }
            onApply()
        end

        local function KU_ForwardPanelMouseWheel(delta)
            if not scrollFrame then
                return
            end
            local onWheel = scrollFrame.GetScript and scrollFrame:GetScript("OnMouseWheel") or nil
            if type(onWheel) == "function" then
                onWheel(scrollFrame, delta)
            end
        end

        local function KU_CreatePremiumPickerButton(parent, getter, setter, optionsProvider, onCommit, controlOpts)
            controlOpts = type(controlOpts) == "table" and controlOpts or {}
            local cycleEnabled = controlOpts.enableCycle and true or false
            local wheelCycleEnabled = cycleEnabled and not (controlOpts.disableWheelCycle and true or false)
            local noSearch = controlOpts.noSearch and true or false
            local hideTitle = controlOpts.hideTitle and true or false
            local autoHeightToOptions = controlOpts.autoHeightToOptions and true or false
            local cycleGutterW = 18
            local button = CreateFrame("Button", nil, parent, "BackdropTemplate")
            button:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
                insets = { left = 0, right = 0, top = 0, bottom = 0 },
            })
            button:SetBackdropColor(0.10, 0.11, 0.14, 0.95)
            button:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
            button:SetHeight(22)
            button:SetWidth(TOOLTIP_BUILDER_INSPECTOR_PICKER_W)

            local text = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 11)
            local leftTextInset = cycleEnabled and (8 + cycleGutterW) or 8
            local rightTextInset = cycleEnabled and (8 + cycleGutterW) or 18
            text:SetPoint("LEFT", button, "LEFT", leftTextInset, 0)
            text:SetPoint("RIGHT", button, "RIGHT", -rightTextInset, 0)
            text:SetJustifyH(cycleEnabled and "CENTER" or "LEFT")
            text:SetTextColor(0.92, 0.92, 0.92, 1)

            local caret = nil
            local leftChevron = nil
            local rightChevron = nil
            if not cycleEnabled then
                caret = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 10)
                caret:SetPoint("RIGHT", button, "RIGHT", -7, 0)
                caret:SetText("v")
                caret:SetTextColor(0.76, 0.76, 0.78, 1)
            else
                leftChevron = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 10)
                leftChevron:SetPoint("LEFT", button, "LEFT", 8, 0)
                leftChevron:SetText("<")
                leftChevron:SetTextColor(0.62, 0.64, 0.69, 0.95)

                rightChevron = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 10)
                rightChevron:SetPoint("RIGHT", button, "RIGHT", -8, 0)
                rightChevron:SetText(">")
                rightChevron:SetTextColor(0.62, 0.64, 0.69, 0.95)
            end

            local picker = CreatePicker(UIParent, {}, function(value)
                setter(tostring(value or ""))
                if onCommit then
                    onCommit()
                end
            end, {
                title = "Select Tooltip Option",
                searchHint = "Search options",
                width = 380,
                height = 330,
                showSecondary = false,
                showClearButton = false,
                preserveOrder = true,
                noSearch = noSearch,
                hideTitle = hideTitle,
                hideScrollBar = (noSearch and hideTitle),
                minHeight = autoHeightToOptions and 120 or 220,
            })

            local currentButtonLabel = ""
            local function getTextMaxWidth()
                local base = (button:GetWidth() or 0) - (leftTextInset + rightTextInset)
                return math.max(4, base)
            end
            local function setButtonLabel(labelText)
                currentButtonLabel = tostring(labelText or "")
                text:SetWordWrap(false)
                if text.SetMaxLines then
                    text:SetMaxLines(1)
                end
                local maxWidth = getTextMaxWidth()
                text:SetWidth(maxWidth)
                text:SetText(currentButtonLabel)
                if text:GetStringWidth() <= maxWidth then
                    return
                end
                local source = currentButtonLabel
                local cut = string.len(source)
                while cut > 0 do
                    local candidate = string.sub(source, 1, cut) .. "..."
                    text:SetText(candidate)
                    if text:GetStringWidth() <= maxWidth then
                        return
                    end
                    cut = cut - 1
                end
                text:SetText("...")
            end

            local function applyVisual(hovered)
                if hovered then
                    button:SetBackdropColor(0.16, 0.17, 0.20, 0.95)
                    button:SetBackdropBorderColor(0.30, 0.33, 0.38, 1.0)
                    if caret then
                        caret:SetTextColor(0.88, 0.88, 0.90, 1)
                    end
                    if leftChevron then
                        leftChevron:SetTextColor(0.84, 0.85, 0.89, 1.0)
                    end
                    if rightChevron then
                        rightChevron:SetTextColor(0.84, 0.85, 0.89, 1.0)
                    end
                else
                    button:SetBackdropColor(0.10, 0.11, 0.14, 0.95)
                    button:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
                    if caret then
                        caret:SetTextColor(0.76, 0.76, 0.78, 1)
                    end
                    if leftChevron then
                        leftChevron:SetTextColor(0.62, 0.64, 0.69, 0.95)
                    end
                    if rightChevron then
                        rightChevron:SetTextColor(0.62, 0.64, 0.69, 0.95)
                    end
                end
            end

            local function buildPickerOptions()
                local built = {}
                for _, option in ipairs(optionsProvider and optionsProvider() or {}) do
                    built[#built + 1] = {
                        value = tostring(option.value or ""),
                        label = tostring(option.label or option.value or ""),
                        buttonLabel = tostring(option.label or option.value or ""),
                        secondary = "",
                    }
                end
                return built
            end

            local function resolveSelectedValue(options)
                local selectedRaw = getter and getter() or nil
                local selectedValue = tostring(selectedRaw or "")
                local visualValue, visualLabel = KU_ResolveVisualChoice(selectedRaw, options)
                if visualValue ~= nil then
                    selectedValue = tostring(visualValue)
                end
                local selectedIndex = 1
                for i, option in ipairs(options or {}) do
                    if tostring(option.value or "") == selectedValue then
                        selectedIndex = i
                        break
                    end
                end
                return selectedValue, selectedIndex, visualLabel
            end

            local spec = {}
            spec.control = button
            local function applyAutoHeight(options)
                if not autoHeightToOptions or not picker then
                    return
                end
                local optionCount = math.max(1, #(options or {}))
                local rowH = math.max(20, tonumber(picker._rowHeight) or 26)
                local topInset
                if noSearch and hideTitle then
                    topInset = 14
                elseif noSearch then
                    topInset = 34
                else
                    topInset = 72
                end
                local bottomInset = 48
                local targetH = topInset + bottomInset + (optionCount * rowH)
                targetH = math.max(tonumber(picker._minHeight) or 120, targetH)
                picker:SetHeight(math.floor(targetH))
            end
            spec.SetWidth = function(_, width)
                button:SetWidth(math.max(0, math.floor(tonumber(width) or TOOLTIP_BUILDER_INSPECTOR_PICKER_W)))
                setButtonLabel(currentButtonLabel)
            end
            spec.ClosePicker = function()
                if picker and picker.Close and picker.IsShown and picker:IsShown() then
                    picker:Close()
                end
            end
            spec.Refresh = function()
                local options = buildPickerOptions()
                picker:SetOptions(options)
                applyAutoHeight(options)
                local selectedValue, _, selectedLabel = resolveSelectedValue(options)
                if selectedValue ~= nil then
                    picker:SetSelectedValue(tostring(selectedValue))
                end
                setButtonLabel(selectedLabel ~= "" and selectedLabel or "Default")
            end

            local function cycleBy(delta)
                local options = buildPickerOptions()
                if #options <= 0 then
                    return
                end
                local _, selectedIndex = resolveSelectedValue(options)
                local newIndex = ((selectedIndex - 1 + delta) % #options) + 1
                local newValue = tostring(options[newIndex] and options[newIndex].value or "")
                setter(newValue)
                if onCommit then
                    onCommit()
                end
                spec.Refresh()
            end

            button:SetScript("OnEnter", function()
                applyVisual(true)
            end)
            button:SetScript("OnLeave", function()
                applyVisual(false)
            end)
            button:SetScript("OnClick", function(selfButton)
                if cycleEnabled then
                    local cursorX = GetCursorPosition()
                    local scale = selfButton:GetEffectiveScale() or (UIParent and UIParent:GetEffectiveScale()) or 1
                    if scale and scale > 0 then
                        cursorX = cursorX / scale
                    end
                    local left = selfButton:GetLeft() or 0
                    local width = selfButton:GetWidth() or 0
                    local localX = cursorX - left
                    if localX <= cycleGutterW then
                        cycleBy(-1)
                        return
                    elseif localX >= (width - cycleGutterW) then
                        cycleBy(1)
                        return
                    end
                end
                if cycleEnabled and picker and picker.IsShown and picker:IsShown() then
                    picker:Close()
                    return
                end
                spec.Refresh()
                picker:Open(selfButton)
            end)
            button:EnableMouseWheel(true)
            button:SetScript("OnMouseWheel", function(_, delta)
                if not wheelCycleEnabled then
                    KU_ForwardPanelMouseWheel(delta)
                    return
                end
                if delta > 0 then
                    cycleBy(-1)
                elseif delta < 0 then
                    cycleBy(1)
                end
            end)
            button:HookScript("OnSizeChanged", function()
                setButtonLabel(currentButtonLabel)
            end)

            spec.Refresh()
            return spec
        end

        local function KU_CreateSegmentedControl(parent, choices, getter, setter, onCommit, controlOpts)
            local internalValue = getter and getter() or nil
            local segmented = createPremiumSegmentedChoice(parent, "", nil, choices, function(value)
                internalValue = value
                setter(value)
                if onCommit then
                    onCommit()
                end
            end, {
                semantic = "toggle",
                controlHeight = controlOpts and controlOpts.controlHeight or nil,
                textSize = controlOpts and controlOpts.textSize or nil,
                textEllipsis = controlOpts and controlOpts.textEllipsis or nil,
                minWidth = controlOpts and controlOpts.minWidth or 0,
                segmentGap = controlOpts and controlOpts.segmentGap or nil,
                segmentMinWidth = controlOpts and controlOpts.segmentMinWidth or nil,
                getValue = function()
                    return internalValue
                end,
                setValue = function(value)
                    internalValue = value
                end,
            })
            if segmented.label then
                segmented.label:Hide()
            end
            local spec = {}
            spec.control = segmented.control
            spec.Layout = function(_, width)
                segmented:Layout(width)
            end
            spec.SetEnabled = function(_, enabled)
                segmented:SetEnabled(enabled)
            end
            spec.SetChoiceEnabled = function(_, value, enabled)
                segmented:SetChoiceEnabled(value, enabled)
            end
            spec.SetVisualSelectedValue = function(_, value)
                segmented:SetVisualSelectedValue(value)
            end
            spec.Refresh = function()
                local selectedValue = getter and getter() or nil
                local visualValue = KU_ResolveVisualChoice(selectedValue, choices)
                if visualValue ~= nil then
                    internalValue = visualValue
                    segmented:SetVisualSelectedValue(visualValue)
                end
            end
            spec.Refresh()
            return spec
        end

        local function KU_CreateInspectorRow(cfg)
            local row = {}
            row.lineId = cfg.lineId
            row.cfg = cfg
            row.container = CreateFrame("Button", nil, tooltipBuilder.inspectorContent)
            row.container:EnableMouse(true)
            row.container:SetHeight(KEYSTONE_UTILITY_LAYOUT.TOOLTIP.BASE_ROW_H)
            row.container:SetScript("OnEnter", function()
                KU_SetHoveredLine(row.lineId)
            end)
            row.container:SetScript("OnLeave", function()
                KU_SetHoveredLine(nil)
            end)
            row.container:SetScript("OnClick", function()
                KU_SelectLine(row.lineId, false)
            end)

            row.highlightBg = row.container:CreateTexture(nil, "BACKGROUND")
            row.highlightBg:SetAllPoints(row.container)
