        local function KU_GetTooltipBuilderInspectorVisibilityState()
            local db = PortalAuthorityDB or {}
            local levelMode = KU_Normalize(db.keystoneTooltipLevelMode)
            local addToName = PA_SafeBool(db.keystoneTooltipLevelAddToName)
            local levelVisible = true
            if levelMode == "HIDE" then
                levelVisible = false
            elseif addToName and levelMode ~= "" and levelMode ~= "NO_CHANGES" then
                levelVisible = false
            end
            return {
                DungeonName = true,
                Level = levelVisible,
                Resilient = KU_Normalize(db.keystoneTooltipResilientMode) ~= "HIDE",
                Soulbound = KU_Normalize(db.keystoneTooltipSoulboundMode) ~= "HIDE",
                Unique = KU_Normalize(db.keystoneTooltipUniqueMode) ~= "HIDE",
                Modifiers = KU_Normalize(db.keystoneTooltipAffixesMode) ~= "HIDE",
                Duration = KU_Normalize(db.keystoneTooltipDurationMode) ~= "HIDE",
                RPQuote = KU_Normalize(db.keystoneTooltipRPQuoteMode) ~= "HIDE",
            }
        end

        local function KU_GetVisibleInspectorLineIds()
            local visible = KU_GetTooltipBuilderInspectorVisibilityState()
            local ids = {}
            for _, cfg in ipairs(tooltipLineConfigs) do
                if visible[cfg.lineId] then
                    ids[#ids + 1] = cfg.lineId
                end
            end
            return ids
        end

        local function KU_EnsurePreviewOverlay(index)
            if tooltipBuilder.previewOverlays[index] then
                return tooltipBuilder.previewOverlays[index]
            end
            local overlay = CreateFrame("Button", nil, tooltipBuilder.previewHitLayer)
            overlay:SetFrameStrata(tooltipBuilder.previewHitLayer:GetFrameStrata())
            overlay:SetFrameLevel((tooltipBuilder.previewHitLayer:GetFrameLevel() or 0) + 2)
            overlay:RegisterForClicks("LeftButtonUp")
            overlay:EnableMouse(true)
            overlay._bg = overlay:CreateTexture(nil, "BACKGROUND")
            overlay._bg:SetAllPoints(overlay)
            overlay._bg:SetTexture("Interface\\Buttons\\WHITE8x8")
            overlay._bg:SetVertexColor(TOOLTIP_BUILDER_HIGHLIGHT_BG_R, TOOLTIP_BUILDER_HIGHLIGHT_BG_G, TOOLTIP_BUILDER_HIGHLIGHT_BG_B, 0.16)
            overlay._bg:SetAlpha(0)
            overlay._accent = overlay:CreateTexture(nil, "BORDER")
            overlay._accent:SetPoint("TOPLEFT", overlay, "TOPLEFT", 0, 0)
            overlay._accent:SetPoint("BOTTOMLEFT", overlay, "BOTTOMLEFT", 0, 0)
            overlay._accent:SetWidth(1)
            overlay._accent:SetTexture("Interface\\Buttons\\WHITE8x8")
            overlay._accent:SetVertexColor(TOOLTIP_BUILDER_HIGHLIGHT_ACCENT_R, TOOLTIP_BUILDER_HIGHLIGHT_ACCENT_G, TOOLTIP_BUILDER_HIGHLIGHT_ACCENT_B, 0.62)
            overlay._accent:SetAlpha(0)
            overlay:SetScript("OnEnter", function(selfOverlay)
                KU_SetHoveredLine(selfOverlay.lineId)
            end)
            overlay:SetScript("OnLeave", function()
                KU_SetHoveredLine(nil)
            end)
            overlay:SetScript("OnClick", function(selfOverlay)
                if selfOverlay.lineId then
                    KU_SelectLine(selfOverlay.lineId, true)
                end
            end)
            tooltipBuilder.previewOverlays[index] = overlay
            return overlay
        end

        local function KU_HideUnusedPreviewOverlays(fromIndex)
            for i = fromIndex, #tooltipBuilder.previewOverlays do
                local overlay = tooltipBuilder.previewOverlays[i]
                if overlay then
                    overlay:Hide()
                    overlay.lineId = nil
                end
            end
        end

        KU_ReadPreviewBodyLeftLines = function(previewTooltip)
            local lines = {}
            if not previewTooltip or not previewTooltip.GetName then
                return lines
            end
            local baseName = previewTooltip:GetName()
            if type(baseName) ~= "string" or baseName == "" then
                return lines
            end
            local count = previewTooltip:NumLines() or 0
            for i = 1, count do
                local left = _G[baseName .. "TextLeft" .. i]
                if left and left.GetText and left.IsShown and left:IsShown() then
                    local text = trim(left:GetText() or "")
                    if text ~= "" then
                        lines[#lines + 1] = { fs = left, text = text }
                    end
                end
            end
            -- Keep real first lines (e.g. "Keystone: ..."). Only drop the synthetic
            -- fallback header line when the hyperlink path wasn't available.
            if #lines > 0 then
                local firstLower = string.lower(trim(tostring(lines[1].text or "")))
                if string.find(firstLower, "mythic keystone", 1, true) then
                    table.remove(lines, 1)
                end
            end
            return lines
        end

        local function KU_BuildPreviewRegions()
            tooltipBuilder.mappingByLineId = {}
            tooltipBuilder.previewOverlaysByLineId = {}
            tooltipBuilder.visibleInspectorLineIds = KU_GetVisibleInspectorLineIds()
            tooltipBuilder.visiblePreviewLineIds = {}

            local previewTooltip = widgets.keystoneTooltipPreviewTooltip
            local bodyLines = KU_ReadPreviewBodyLeftLines(previewTooltip)
            local total = #bodyLines
            local cursor = 1
            local regions = {}
            local visibility = KU_GetTooltipBuilderInspectorVisibilityState()

            local function addSingle(lineId, matcher)
                if not visibility[lineId] then
                    return
                end
                if cursor <= total then
                    if matcher then
                        local lineText = (bodyLines[cursor] and bodyLines[cursor].text) or ""
                        if not matcher(string.lower(trim(tostring(lineText or "")))) then
                            return
                        end
                    end
                    regions[#regions + 1] = { lineId = lineId, startIndex = cursor, endIndex = cursor }
                    cursor = cursor + 1
                end
            end

            addSingle("DungeonName")
            addSingle("Level")
            addSingle("Resilient", function(lowerText)
                return string.find(lowerText, "resilient", 1, true) ~= nil
            end)
            addSingle("Soulbound", function(lowerText)
                return string.find(lowerText, "soulbound", 1, true) ~= nil
                    or string.find(lowerText, "binds when picked up", 1, true) ~= nil
                    or string.find(lowerText, "binds when equipped", 1, true) ~= nil
            end)
            addSingle("Unique", function(lowerText)
                return string.find(lowerText, "unique", 1, true) == 1
            end)

            if visibility.Modifiers and cursor <= total then
                local trailing = 0
                if visibility.Duration then trailing = trailing + 1 end
                if visibility.RPQuote then trailing = trailing + 1 end
                local modifiersEnd = total - trailing
                if modifiersEnd < cursor then
                    modifiersEnd = cursor
                end
                if modifiersEnd > total then
                    modifiersEnd = total
                end
                regions[#regions + 1] = { lineId = "Modifiers", startIndex = cursor, endIndex = modifiersEnd }
                cursor = modifiersEnd + 1
            end

            addSingle("Duration", function(lowerText)
                return string.find(lowerText, "duration", 1, true) ~= nil
            end)
            addSingle("RPQuote")

            -- Keep inspector<->preview linking based on actual rendered regions so
            -- missing optional lines (e.g. fallback without Resilient) do not shift
            -- subsequent mappings.
            do
                local actualInspectorLineIds = {}
                for _, region in ipairs(regions) do
                    actualInspectorLineIds[#actualInspectorLineIds + 1] = region.lineId
                end
                tooltipBuilder.visibleInspectorLineIds = actualInspectorLineIds
            end

            local overlayIndex = 1
            local visiblePreviewRegions = {}
            for _, region in ipairs(regions) do
                local startLine = bodyLines[region.startIndex]
                local endLine = bodyLines[region.endIndex]
                if startLine and endLine and startLine.fs and endLine.fs then
                    local overlay = KU_EnsurePreviewOverlay(overlayIndex)
                    overlay:ClearAllPoints()
                    overlay:SetPoint("TOPLEFT", startLine.fs, "TOPLEFT", -4, 2)
                    overlay:SetPoint("BOTTOMRIGHT", endLine.fs, "BOTTOMRIGHT", 4, -2)
                    overlay.lineId = region.lineId
                    overlay:Show()
                    tooltipBuilder.previewOverlaysByLineId[region.lineId] = overlay
                    tooltipBuilder.visiblePreviewLineIds[#tooltipBuilder.visiblePreviewLineIds + 1] = region.lineId
                    visiblePreviewRegions[#visiblePreviewRegions + 1] = { lineId = region.lineId, overlay = overlay }
                    overlayIndex = overlayIndex + 1
                end
            end
            KU_HideUnusedPreviewOverlays(overlayIndex)

            local ambiguous = false
            if #tooltipBuilder.visibleInspectorLineIds ~= #tooltipBuilder.visiblePreviewLineIds then
                ambiguous = true
            else
                for _, lineId in ipairs(tooltipBuilder.visibleInspectorLineIds) do
                    if not tooltipBuilder.previewOverlaysByLineId[lineId] then
                        ambiguous = true
                        break
                    end
                end
            end

            if not ambiguous then
                for _, lineId in ipairs(tooltipBuilder.visibleInspectorLineIds) do
                    tooltipBuilder.mappingByLineId[lineId] = tooltipBuilder.previewOverlaysByLineId[lineId]
                end
            else
                tooltipBuilder.mappingByLineId = {}
                local maxZip = math.min(#tooltipBuilder.visibleInspectorLineIds, #visiblePreviewRegions)
                for i = 1, maxZip do
                    local lineId = tooltipBuilder.visibleInspectorLineIds[i]
                    local overlay = visiblePreviewRegions[i] and visiblePreviewRegions[i].overlay or nil
                    if lineId and overlay and overlay:IsShown() then
                        overlay.lineId = lineId
                        tooltipBuilder.mappingByLineId[lineId] = overlay
                    end
                end
            end
        end

        local function KU_RebuildTooltipPreviewLinks(commitInfo)
            local oldHovered = tooltipBuilder.hoveredLineId
            local oldSelected = tooltipBuilder.selectedLineId
            if KU_UpdateKeystoneTooltipPreview then
                KU_UpdateKeystoneTooltipPreview()
            end
            KU_BuildPreviewRegions()

            if oldSelected and not tooltipBuilder.mappingByLineId[oldSelected] then
                tooltipBuilder.selectedLineId = nil
                if commitInfo and commitInfo.affectsLayout then
                    KU_SetBuilderStatus("Line hidden.")
                end
            elseif commitInfo then
                KU_ClearBuilderStatus()
            else
                tooltipBuilder.selectedLineId = oldSelected
            end

            if oldHovered and tooltipBuilder.rowsById[oldHovered] then
                tooltipBuilder.hoveredLineId = oldHovered
            else
                tooltipBuilder.hoveredLineId = nil
            end

            KU_RefreshLinkedVisuals()
        end

        KU_RefreshTooltipBuilderVisual = function()
            if not PortalAuthorityDB then
                ensureDatabase()
                if not PortalAuthorityDB then
                    return
                end
            end
            for _, row in ipairs(tooltipBuilder.rows) do
                if row.main and row.main.Refresh then
                    row.main:Refresh()
                end
                if row.inline and row.inline.Refresh then
                    row.inline:Refresh()
                end
            end
            do
                local levelRow = tooltipBuilder.rowsById and tooltipBuilder.rowsById.Level or nil
                if levelRow and levelRow.inline then
                    local levelMode = KU_Normalize(PortalAuthorityDB and PortalAuthorityDB.keystoneTooltipLevelMode)
                    local forceInlineOff = (levelMode == "HIDE" or levelMode == "NO_CHANGES")
                    local allowInline = not forceInlineOff
                    if levelRow.inline.SetEnabled then
                        levelRow.inline:SetEnabled(allowInline)
                    end
                    if levelRow.inlineLabel then
                        levelRow.inlineLabel:SetAlpha(allowInline and 0.95 or 0.52)
                    end
                    if levelRow.inlineAccent then
                        levelRow.inlineAccent:SetAlpha(allowInline and 0.55 or 0.30)
                    end
                end
            end
            do
                local modifiersRow = tooltipBuilder.rowsById and tooltipBuilder.rowsById.Modifiers or nil
                local mode = KU_Normalize(PortalAuthorityDB and PortalAuthorityDB.keystoneTooltipAffixesMode)
                if modifiersRow and modifiersRow.colorSwatch then
                    modifiersRow.colorSwatch:SetAlpha((mode == "HIDE") and 0.50 or 1.00)
                end
            end
            refreshTooltipAffixesSwatch()
            local commitInfo = tooltipBuilder._lastCommit
            tooltipBuilder._lastCommit = nil
            KU_RebuildTooltipPreviewLinks(commitInfo)
        end

