        local function KU_RoundMetric(value)
            local n = tonumber(value) or 0
            return math.floor(n + 0.5)
        end

        local function KU_GetRowLabel(row)
            if not row then
                return nil
            end
            return row.label or (row.spec and row.spec.label) or nil
        end

        local function KU_GetRowControl(row)
            if not row then
                return nil
            end
            return row.control or (row.spec and row.spec.control) or nil
        end

        local function KU_MeasureFontStringWidth(fs)
            if not (fs and fs.GetStringWidth) then
                return 0
            end
            return math.ceil(tonumber(fs:GetStringWidth()) or 0)
        end

        local function KU_MeasureFontStringHeight(fs, floor)
            local measured = 0
            if fs and fs.GetStringHeight then
                measured = math.ceil(tonumber(fs:GetStringHeight()) or 0)
            end
            return math.max(tonumber(floor) or 0, measured)
        end

        local function KU_MeasureControlHeight(widget, floor)
            local measured = 0
            if widget and widget.GetHeight then
                measured = math.ceil(tonumber(widget:GetHeight()) or 0)
            end
            return math.max(tonumber(floor) or 0, measured)
        end

        local function KU_AppendMetric(parts, key, value)
            parts[#parts + 1] = tostring(key or "") .. "=" .. tostring(KU_RoundMetric(value))
        end

        local function KU_AppendFontMetrics(parts, prefix, fs)
            KU_AppendMetric(parts, tostring(prefix or "") .. "W", KU_MeasureFontStringWidth(fs))
            KU_AppendMetric(parts, tostring(prefix or "") .. "H", KU_MeasureFontStringHeight(fs, 0))
        end

        local function KU_ComputeContentWidth()
            return math.max((scrollFrame:GetWidth() or 0) - KEYSTONE_UTILITY_LAYOUT.SCROLL_WIDTH_FUDGE, KEYSTONE_UTILITY_LAYOUT.MIN_CONTENT_W)
        end

        local function KU_ComputeSectionColumns(cardW, rows)
            local T = KEYSTONE_UTILITY_LAYOUT
            local C = T.CARD
            local innerW = math.max(1, cardW - (C.PAD_X * 2))
            local labelMetricW = T.LABEL_MIN_W
            for _, row in ipairs(rows or {}) do
                labelMetricW = math.max(labelMetricW, KU_MeasureFontStringWidth(KU_GetRowLabel(row)))
            end
            local preferredControlW = math.max(T.CONTROL_MIN_W, math.min(T.CONTROL_MAX_W, math.floor(innerW * T.CONTROL_WIDTH_RATIO)))
            local controlW = math.max(T.CONTROL_MIN_W, math.min(preferredControlW, innerW - T.LABEL_MIN_W - T.LABEL_TO_CONTROL_GAP))
            local controlX = C.PAD_X + innerW - controlW
            local maxLabelAvailW = math.max(T.LABEL_MIN_W, controlX - C.PAD_X - T.LABEL_TO_CONTROL_GAP)
            local labelW = math.max(T.LABEL_MIN_W, math.min(labelMetricW + T.LABEL_TEXT_PAD, maxLabelAvailW))
            local descW = math.max(T.DESC_MIN_W, controlX - C.PAD_X - T.DESC_RIGHT_PAD)
            return {
                labelX = C.PAD_X,
                labelW = labelW,
                controlX = controlX,
                controlW = controlW,
                descX = C.PAD_X,
                descW = descW,
                rowTopY = -C.PAD_TOP,
                rowGap = C.ROW_GAP,
                descGap = C.DESC_GAP,
            }
        end

        local function KU_LayoutRows(parent, rows, columns)
            local T = KEYSTONE_UTILITY_LAYOUT
            local C = T.CARD
            local rowTopY = columns and columns.rowTopY or 0
            for _, row in ipairs(rows or {}) do
                local label = KU_GetRowLabel(row)
                local control = KU_GetRowControl(row)
                local desc = row and row.desc or nil
                local controlW = row and row.controlWidth or columns.controlW
                local controlYOffset = row and row.controlYOffset or C.CONTROL_TOP_NUDGE
                if label then
                    label:ClearAllPoints()
                    label:SetPoint("TOPLEFT", parent, "TOPLEFT", columns.labelX, rowTopY)
                    label:SetWidth(columns.labelW)
                    if label.SetJustifyH then
                        label:SetJustifyH("LEFT")
                    end
                end
                if control then
                    if row and row.spec and row.spec.Layout and not row.noLayout then
                        row.spec:Layout(controlW)
                    elseif control.SetWidth and controlW then
                        control:SetWidth(controlW)
                    end
                    control:ClearAllPoints()
                    control:SetPoint("TOPLEFT", parent, "TOPLEFT", columns.controlX, rowTopY + controlYOffset)
                end
                local labelH = KU_MeasureFontStringHeight(label, C.LABEL_FLOOR)
                local controlH = KU_MeasureControlHeight(control, C.CONTROL_FLOOR)
                local rowBaseH = math.max(C.ROW_FLOOR, labelH, controlH)
                local rowBottomY = rowTopY - rowBaseH
                if desc then
                    desc:ClearAllPoints()
                    desc:SetPoint("TOPLEFT", parent, "TOPLEFT", columns.descX, rowBottomY - columns.descGap)
                    desc:SetWidth(columns.descW)
                    if desc.SetJustifyH then
                        desc:SetJustifyH("LEFT")
                    end
                    local descH = KU_MeasureFontStringHeight(desc, C.HELPER_FLOOR)
                    rowBottomY = rowBottomY - columns.descGap - descH
                end
                rowTopY = rowBottomY - columns.rowGap
            end
            return rowTopY
        end

        local function KU_ComputeTooltipGeometry(contentSpan)
            local T = KEYSTONE_UTILITY_LAYOUT
            local TT = T.TOOLTIP
            local geometry = {
                sideBySide = true,
                rootLeft = 0,
                rootW = math.max(0, contentSpan),
            }
            local thresholdW = TOOLTIP_BUILDER_PREVIEW_MIN_W + TOOLTIP_BUILDER_INSPECTOR_MIN_W + TT.PANE_GAP
            if contentSpan >= thresholdW then
                geometry.inspectorW = math.max(TOOLTIP_BUILDER_INSPECTOR_MIN_W, math.floor(contentSpan * 0.60))
                geometry.previewW = contentSpan - geometry.inspectorW - TT.PANE_GAP
                if geometry.previewW < TOOLTIP_BUILDER_PREVIEW_MIN_W then
                    geometry.inspectorW = contentSpan - TOOLTIP_BUILDER_PREVIEW_MIN_W - TT.PANE_GAP
                    geometry.previewW = TOOLTIP_BUILDER_PREVIEW_MIN_W
                end
            else
                local splitSpan = math.max(0, contentSpan - TT.PANE_GAP)
                geometry.inspectorW = math.floor(splitSpan * 0.60)
                geometry.previewW = splitSpan - geometry.inspectorW
                if geometry.previewW < TOOLTIP_BUILDER_PREVIEW_READABLE_MIN_W then
                    geometry.previewW = math.min(splitSpan, TOOLTIP_BUILDER_PREVIEW_READABLE_MIN_W)
                    geometry.inspectorW = math.max(0, splitSpan - geometry.previewW)
                end
            end
            geometry.previewW = math.max(0, geometry.previewW or 0)
            geometry.inspectorW = math.max(0, geometry.inspectorW or 0)
            geometry.inspectorContentW = math.max(1, geometry.inspectorW - (TT.INSPECTOR_PAD_X * 2))
            local labelMetricW = 0
            for _, row in ipairs(tooltipBuilder.rows or {}) do
                labelMetricW = math.max(labelMetricW, KU_MeasureFontStringWidth(row and row.label or nil))
            end
            geometry.labelColX = 0
            geometry.labelW = math.max(T.TOOLTIP_LABEL_MIN_W, math.min(T.TOOLTIP_LABEL_MAX_W, labelMetricW + T.TOOLTIP_LABEL_TEXT_PAD))
            geometry.controlColX = geometry.labelW + T.TOOLTIP_LABEL_TO_CONTROL_GAP
            geometry.rightInset = TOOLTIP_BUILDER_INSPECTOR_RIGHT_INSET
            local availW = geometry.inspectorContentW - (geometry.controlColX + geometry.rightInset)
            availW = math.max(0, availW)
            if availW >= TOOLTIP_BUILDER_MAIN_MIN_W then
                geometry.mainControlW = math.max(TOOLTIP_BUILDER_MAIN_MIN_W, math.min(availW, TOOLTIP_BUILDER_MAIN_MAX_W))
            else
                geometry.mainControlW = availW
            end
            geometry.mainControlW = math.max(0, math.min(geometry.mainControlW, availW))
            geometry.inlineRegionX = geometry.controlColX + geometry.mainControlW + TT.INLINE_REGION_GAP
            geometry.availableInlineW = geometry.inspectorContentW - geometry.rightInset - geometry.inlineRegionX
            geometry.inlineBlockW = TOOLTIP_BUILDER_INLINE_LABEL_W + TT.INLINE_BLOCK_GAP + TOOLTIP_BUILDER_INLINE_TOGGLE_W
            geometry.previewTitleH = KU_MeasureFontStringHeight(tooltipBuilder.previewTitle, TT.PREVIEW_TITLE_FLOOR)
            if geometry.sideBySide then
                local alignedBorderTopOffset = TT.INSPECTOR_PAD_Y
                    + TT.STATUS_H
                    + TT.STATUS_TO_CONTENT_GAP
                    + TT.MAIN_TOP_PAD
                    - TT.STICKY_TOP_PAD
                local minimumTitleClearance = geometry.previewTitleH + TT.PREVIEW_TITLE_CLEARANCE
                local borderTopOffset = math.max(alignedBorderTopOffset, minimumTitleClearance)
                geometry.previewAnchorTopInset = math.max(0, borderTopOffset - TT.PREVIEW_FRAME_OFFSET_Y)
            else
                geometry.previewAnchorTopInset = TT.TITLE_TOP_PAD + geometry.previewTitleH + TT.PREVIEW_BODY_TOP_GAP
            end
            return geometry
        end

        local function KU_HasSizedLayoutSurface()
            local readyFrame = self._sizingFrame or self
            if not readyFrame then
                return false
            end
            local width = tonumber(readyFrame:GetWidth()) or 0
            local height = tonumber(readyFrame:GetHeight()) or 0
            return width > 1 and height > 1
        end

        local function KU_BuildMetricSignature()
            local parts = {}
            KU_AppendMetric(parts, "viewportW", scrollFrame and scrollFrame:GetWidth() or 0)
            KU_AppendFontMetrics(parts, "Header", header)
            KU_AppendFontMetrics(parts, "AssistantHeader", helperHeader)
            KU_AppendFontMetrics(parts, "ReleaseHeader", releaseHeader)
            KU_AppendFontMetrics(parts, "TooltipSectionHeader", tooltipHeader)
            KU_AppendFontMetrics(parts, "TooltipSubheader", tooltipSubheader)
            for _, row in ipairs(assistantRows) do
                KU_AppendFontMetrics(parts, "Assistant" .. tostring(row.id or ""), KU_GetRowLabel(row))
                if row.desc then
                    KU_AppendFontMetrics(parts, "AssistantDesc" .. tostring(row.id or ""), row.desc)
                end
            end
            for _, row in ipairs(releaseRows) do
                KU_AppendFontMetrics(parts, "Release" .. tostring(row.id or ""), KU_GetRowLabel(row))
                if row.desc then
                    KU_AppendFontMetrics(parts, "ReleaseDesc" .. tostring(row.id or ""), row.desc)
                end
            end
            for index, chip in ipairs(statusChips) do
                KU_AppendFontMetrics(parts, "StatusTitle" .. tostring(index), chip and chip.title or nil)
                KU_AppendFontMetrics(parts, "StatusValue" .. tostring(index), chip and chip.value or nil)
            end
            KU_AppendFontMetrics(parts, "TooltipBuilderHeader", tooltipBuilder.inspectorHeader)
            KU_AppendFontMetrics(parts, "TooltipPreviewTitle", tooltipBuilder.previewTitle)
            for _, row in ipairs(tooltipBuilder.rows or {}) do
                KU_AppendFontMetrics(parts, "TooltipRow" .. tostring(row.lineId or ""), row and row.label or nil)
                if row and row.inlineLabel then
                    KU_AppendFontMetrics(parts, "TooltipInline" .. tostring(row.lineId or ""), row.inlineLabel)
                end
            end
            return table.concat(parts, "|")
        end

        local function invalidateLayout(reason)
            self._kuLayoutDirty = true
            self._kuLayoutDirtyReason = tostring(reason or self._kuLayoutDirtyReason or "layout-dirty")
        end

        local function ensureLayoutCurrent(reason)
            if not self._layout then
                return false
            end
            if not KU_HasSizedLayoutSurface() then
                invalidateLayout(reason or "unsized")
                return false
            end
            local currentSignature = KU_BuildMetricSignature()
            local needsLayout = self._kuLayoutDirty or (self._kuMetricSignatureCache ~= currentSignature)
            if not needsLayout then
                return true
            end
            self._layout(reason or "layout")
            if not KU_HasSizedLayoutSurface() then
                invalidateLayout(reason or "unsized")
                return false
            end
            self._kuMetricSignatureCache = KU_BuildMetricSignature()
            self._kuLayoutDirty = false
            self._kuLayoutDirtyReason = nil
            return true
        end

        local function KU_ReadLeaderOrAssistState()
            local isLeader = (UnitIsGroupLeader and UnitIsGroupLeader("player")) and true or false
            local isAssist = (UnitIsGroupAssistant and UnitIsGroupAssistant("player")) and true or false
            return isLeader or isAssist
        end

        local function KU_ReadKeystoneLevelFromLink(link)
            if type(link) ~= "string" then
                return 0
            end
            local itemString = link:match("|H(keystone:[^|]+)|")
            if type(itemString) ~= "string" then
                return 0
            end
            local _, _, mapIDText, levelText = strsplit(":", itemString)
            local mapID = tonumber(mapIDText) or 0
            local level = tonumber(levelText) or 0
            if mapID > 0 and level > 0 then
                return math.floor(level)
            end
            return 0
        end

        local function KU_ReadOwnedKeystoneLevel()
            if C_MythicPlus and C_MythicPlus.GetOwnedKeystoneLevel then
                local okLevel, ownedLevel = pcall(C_MythicPlus.GetOwnedKeystoneLevel)
                if okLevel then
                    local n = tonumber(ownedLevel) or 0
                    if n > 0 then
                        return math.floor(n)
                    end
                end
            end
            return 0
        end

        local function KU_RefreshStatusStrip()
            if not (widgets.statusKeystone and widgets.statusLeader and widgets.statusAutomation) then
                return
            end
            local keystoneLink = KU_FindFirstKeystoneLinkInBags and KU_FindFirstKeystoneLinkInBags() or nil
            local hasKeystoneInBags = type(keystoneLink) == "string" and keystoneLink ~= ""
            local keystoneLevel = 0
            if hasKeystoneInBags then
                keystoneLevel = KU_ReadKeystoneLevelFromLink(keystoneLink)
                if keystoneLevel <= 0 then
                    keystoneLevel = KU_ReadOwnedKeystoneLevel()
                end
            end
            local leaderOrAssist = KU_ReadLeaderOrAssistState()
            local autoSlotEnabled = PA_SafeBool(PortalAuthorityDB and PortalAuthorityDB.keystoneAutoSlotEnabled)
            local autoStartEnabled = PA_SafeBool(PortalAuthorityDB and PortalAuthorityDB.keystoneAutoStartEnabled)

            local automationText = "Auto: Off"
            local automationTone = "warn"
            if autoSlotEnabled and autoStartEnabled then
                automationText = "Auto: Slot+Start"
                automationTone = "good"
            elseif autoSlotEnabled then
                automationText = "Auto: Slot"
                automationTone = "good"
            elseif autoStartEnabled then
                automationText = "Auto: Start"
                automationTone = "good"
            end

            local keystoneText = "Missing"
            local keystoneTone = "warn"
            if hasKeystoneInBags then
                local levelText = (keystoneLevel > 0) and tostring(keystoneLevel) or "?"
                keystoneText = "In Bags (m+" .. levelText .. ")"
                keystoneTone = "good"
            end

            widgets.statusKeystone:SetState(keystoneText, keystoneTone)
            widgets.statusLeader:SetState(leaderOrAssist and "Yes" or "No", leaderOrAssist and "good" or "warn")
            widgets.statusAutomation:SetState(automationText, automationTone)
        end

        local function refreshVisuals()
            if not PortalAuthorityDB then
                ensureDatabase()
                if not PortalAuthorityDB then
                    return
                end
            end

            if widgets.keystoneHelperEnabled and widgets.keystoneHelperEnabled.Refresh then
                widgets.keystoneHelperEnabled:Refresh()
            end
            if widgets.keystoneAutoSlotEnabled and widgets.keystoneAutoSlotEnabled.Refresh then
                widgets.keystoneAutoSlotEnabled:Refresh()
            end
            if widgets.keystoneAutoStartEnabled and widgets.keystoneAutoStartEnabled.Refresh then
                widgets.keystoneAutoStartEnabled:Refresh()
            end
            if widgets.releaseGateEnabled and widgets.releaseGateEnabled.Refresh then
                widgets.releaseGateEnabled:Refresh()
            end
            if widgets.releaseGateModifier and widgets.releaseGateModifier.Refresh then
                widgets.releaseGateModifier:Refresh()
            end
            if widgets.releaseHoldStepper and widgets.releaseHoldStepper.Refresh then
                widgets.releaseHoldStepper:Refresh()
            end

            local releaseEnabled = PA_SafeBool(PortalAuthorityDB and PortalAuthorityDB.releaseGateEnabled)
            if widgets.releaseGateModifier and widgets.releaseGateModifier.SetEnabled then
                widgets.releaseGateModifier:SetEnabled(releaseEnabled)
            end
            holdLabel:SetTextColor(releaseEnabled and 1 or 0.6, releaseEnabled and 1 or 0.6, releaseEnabled and 1 or 0.6, 1)
            releaseHoldDesc:SetTextColor(releaseEnabled and 0.72 or 0.58, releaseEnabled and 0.72 or 0.58, releaseEnabled and 0.72 or 0.58, 1)
            if widgets.releaseHoldStepper and widgets.releaseHoldStepper.SetEnabled then
                widgets.releaseHoldStepper:SetEnabled(releaseEnabled)
            end

            KU_RefreshStatusStrip()

            if panelRef and panelRef._kuHydrateKeystoneTooltipVisualOnly then
                panelRef._kuHydrateKeystoneTooltipVisualOnly()
            end
        end

        local function refresh()
            refreshVisuals()
        end

        local function fullRefresh(reason)
            local needsBootstrap = not self._kuBootstrapComplete
            if needsBootstrap then
                refreshVisuals()
                local didLayout = ensureLayoutCurrent("bootstrap")
                refreshVisuals()
                if didLayout then
                    self._kuBootstrapComplete = true
                end
                return
            end
            ensureLayoutCurrent(reason or "full-refresh")
            refreshVisuals()
        end

        local function layout()
            local T = KEYSTONE_UTILITY_LAYOUT
            local P = T.PAGE
            local S = T.SECTION
            local C = T.CARD
            local ST = T.STATUS
            local TT = T.TOOLTIP
            local contentW = KU_ComputeContentWidth()
            local useHostedChrome = isPanelUsingCustomSettingsWindowHost(panelRef)
            scrollChild:SetWidth(contentW)

            local contentLeft = P.CONTENT_LEFT
            local contentRight = contentW - P.CONTENT_RIGHT
            local contentSpan = math.max(0, contentRight - contentLeft)
            local headerSpan = math.max(0, contentRight - P.HEADER_LEFT)
            local y = -P.TOP_PAD
            if useHostedChrome then
                y = y - SETTINGS_WINDOW_HOSTED_TOP_RHYTHM_NUDGE
            end

            if useHostedChrome then
                setSettingsWindowChromeVisible(header, false, scrollChild)
                setSettingsWindowChromeVisible(widgets.sectionDescriptor, false, scrollChild)
            else
                setSettingsWindowChromeVisible(header, true)
                setSettingsWindowChromeVisible(widgets.sectionDescriptor, true, scrollChild)
                header:ClearAllPoints()
                header:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", P.HEADER_LEFT, y)
                header:SetWidth(math.max(T.HEADER_MIN_W, headerSpan))
                if header.SetJustifyH then
                    header:SetJustifyH("LEFT")
                end
                local headerH = KU_MeasureFontStringHeight(header, P.TITLE_FLOOR)
                y = y - headerH - P.TITLE_TO_SECTION_GAP
                y = layoutSettingsSectionDescriptor(
                    widgets.sectionDescriptor,
                    scrollChild,
                    P.HEADER_LEFT,
                    y,
                    math.max(T.HEADER_MIN_W, headerSpan)
                )
            end

            helperHeader:ClearAllPoints()
            helperHeader:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", P.CONTENT_LEFT, y)
            helperHeader:SetWidth(math.max(T.HEADER_MIN_W, contentSpan))
            if helperHeader.SetJustifyH then
                helperHeader:SetJustifyH("LEFT")
            end
            local assistantHeaderH = KU_MeasureFontStringHeight(helperHeader, S.SUBHEADER_FLOOR)
            y = y - assistantHeaderH - S.SUBHEADER_GAP

            widgets.assistantCard:ClearAllPoints()
            widgets.assistantCard:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", contentLeft, y)
            widgets.assistantCard:SetWidth(contentSpan)
            local assistantColumns = KU_ComputeSectionColumns(contentSpan, assistantRows)
            local assistantBottomY = KU_LayoutRows(widgets.assistantCard, assistantRows, assistantColumns)
            local assistantRowsBottomY = assistantBottomY + assistantColumns.rowGap

            local statusStripW = math.max(0, contentSpan - (C.PAD_X * 2))
            local chipGap = ST.CHIP_GAP
            local equalChipW = math.max(T.STATUS_CHIP_MIN_W, math.floor((statusStripW - (chipGap * 2)) / 3))
            local chipTextW = T.STATUS_CHIP_MIN_W
            for _, chip in ipairs(statusChips) do
                chipTextW = math.max(
                    chipTextW,
                    KU_MeasureFontStringWidth(chip and chip.title or nil) + T.STATUS_CHIP_TEXT_PAD,
                    KU_MeasureFontStringWidth(chip and chip.value or nil) + T.STATUS_CHIP_TEXT_PAD
                )
            end
            local chipW = math.max(T.STATUS_CHIP_MIN_W, chipTextW, equalChipW)
            if (chipW * 3) + (chipGap * 2) > statusStripW then
                chipW = math.max(T.STATUS_CHIP_MIN_W, math.floor((statusStripW - (chipGap * 2)) / 3))
            end
            local statusTopY = assistantBottomY + ST.STRIP_Y_NUDGE
            widgets.statusStrip:ClearAllPoints()
            widgets.statusStrip:SetPoint("TOPLEFT", widgets.assistantCard, "TOPLEFT", C.PAD_X, statusTopY)
            widgets.statusStrip:SetSize(math.max(0, (chipW * 3) + (chipGap * 2)), ST.CHIP_H)
            for index, chip in ipairs(statusChips) do
                local chipX = (index - 1) * (chipW + chipGap)
                chip:ClearAllPoints()
                chip:SetPoint("TOPLEFT", widgets.statusStrip, "TOPLEFT", chipX, 0)
                chip:SetSize(chipW, ST.CHIP_H)
            end

            local assistantCardBottomY = math.min(assistantRowsBottomY, statusTopY - ST.CHIP_H)
            local assistantCardH = math.abs(assistantCardBottomY) + C.PAD_BOTTOM
            widgets.assistantCard:SetHeight(assistantCardH)
            y = y - assistantCardH - S.STACK_GAP

            widgets.topSectionDivider:ClearAllPoints()
            widgets.topSectionDivider:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", contentLeft, y + S.DIVIDER_Y_OFFSET)
            widgets.topSectionDivider:SetPoint("TOPRIGHT", scrollChild, "TOPLEFT", contentRight, y + S.DIVIDER_Y_OFFSET)
            widgets.topSectionDivider:SetHeight(S.DIVIDER_H)
            widgets.topSectionDivider:Show()

            releaseHeader:ClearAllPoints()
            releaseHeader:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", P.CONTENT_LEFT, y)
            releaseHeader:SetWidth(math.max(T.HEADER_MIN_W, contentSpan))
            if releaseHeader.SetJustifyH then
                releaseHeader:SetJustifyH("LEFT")
            end
            local releaseHeaderH = KU_MeasureFontStringHeight(releaseHeader, S.SUBHEADER_FLOOR)
            y = y - releaseHeaderH - S.SUBHEADER_GAP

            widgets.releaseCard:ClearAllPoints()
            widgets.releaseCard:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", contentLeft, y)
            widgets.releaseCard:SetWidth(contentSpan)
            local releaseColumns = KU_ComputeSectionColumns(contentSpan, releaseRows)
            local releaseBottomY = KU_LayoutRows(widgets.releaseCard, releaseRows, releaseColumns)
            local releaseRowsBottomY = releaseBottomY + releaseColumns.rowGap
            local releaseCardH = math.abs(releaseRowsBottomY) + C.PAD_BOTTOM
            widgets.releaseCard:SetHeight(releaseCardH)
            y = y - releaseCardH - S.RELEASE_TO_TOOLTIP_GAP

            tooltipHeader:ClearAllPoints()
            tooltipHeader:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", P.CONTENT_LEFT, y)
            tooltipHeader:SetWidth(math.max(T.HEADER_MIN_W, contentSpan))
            if tooltipHeader.SetJustifyH then
                tooltipHeader:SetJustifyH("LEFT")
            end
            local tooltipHeaderH = KU_MeasureFontStringHeight(tooltipHeader, S.TITLE_FLOOR)
            y = y - tooltipHeaderH - S.TOOLTIP_TITLE_TO_SUBHEADER_GAP

            tooltipSubheader:ClearAllPoints()
            tooltipSubheader:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", P.CONTENT_LEFT, y)
            tooltipSubheader:SetWidth(math.max(T.HEADER_MIN_W, contentSpan))
            if tooltipSubheader.SetJustifyH then
                tooltipSubheader:SetJustifyH("LEFT")
            end
            local tooltipSubheaderH = KU_MeasureFontStringHeight(tooltipSubheader, S.SUBHEADER_FLOOR)
            y = y - tooltipSubheaderH - S.TOOLTIP_SUBHEADER_TO_CONTENT_GAP

            local tooltipGeo = KU_ComputeTooltipGeometry(contentSpan)
            local inspectorContentW = tooltipGeo.inspectorContentW
            local availableInlineW = tooltipGeo.availableInlineW
            local inlineBlockW = tooltipGeo.inlineBlockW
            local inspectorPaneH = 0

            tooltipBuilder.root:ClearAllPoints()
            tooltipBuilder.root:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", contentLeft, y)
            tooltipBuilder.root:SetWidth(tooltipGeo.rootW)

            tooltipBuilder.inspectorPane:ClearAllPoints()
            tooltipBuilder.inspectorPane:SetPoint("TOPLEFT", tooltipBuilder.root, "TOPLEFT", 0, 0)
            tooltipBuilder.inspectorPane:SetWidth(tooltipGeo.inspectorW)

            tooltipBuilder.statusSlot:ClearAllPoints()
            tooltipBuilder.statusSlot:SetPoint("TOPLEFT", tooltipBuilder.inspectorPane, "TOPLEFT", TT.INSPECTOR_PAD_X, -TT.INSPECTOR_PAD_Y)
            tooltipBuilder.statusSlot:SetPoint("TOPRIGHT", tooltipBuilder.inspectorPane, "TOPRIGHT", -TT.INSPECTOR_PAD_X, -TT.INSPECTOR_PAD_Y)
            tooltipBuilder.statusSlot:SetHeight(TT.STATUS_H)

            tooltipBuilder.inspectorContent:ClearAllPoints()
            tooltipBuilder.inspectorContent:SetPoint("TOPLEFT", tooltipBuilder.statusSlot, "BOTTOMLEFT", 0, -TT.STATUS_TO_CONTENT_GAP)
            tooltipBuilder.inspectorContent:SetPoint("TOPRIGHT", tooltipBuilder.statusSlot, "BOTTOMRIGHT", 0, -TT.STATUS_TO_CONTENT_GAP)

            tooltipBuilder.inspectorHeader:ClearAllPoints()
            tooltipBuilder.inspectorHeader:SetPoint("TOPLEFT", tooltipBuilder.root, "TOPLEFT", TT.INSPECTOR_PAD_X, -TT.TITLE_TOP_PAD)
            tooltipBuilder.inspectorHeader:SetWidth(math.max(1, tooltipGeo.inspectorW - (TT.INSPECTOR_PAD_X * 2)))
            if tooltipBuilder.inspectorHeader.SetJustifyH then
                tooltipBuilder.inspectorHeader:SetJustifyH("LEFT")
            end

            local rowY = 0

            for _, row in ipairs(tooltipBuilder.rows) do
                local rowW = inspectorContentW
                local rowContentYNudge = 0
                local inlineDrop = false
                if row.inline then
                    inlineDrop = availableInlineW < inlineBlockW
                    if row.cfg and row.cfg.inline and row.cfg.inline.layout == "subline" then
                        inlineDrop = true
                    end
                end
                local rowH = inlineDrop and TT.ROW_H_COMPOUND_DROPPED or TT.BASE_ROW_H
                local topAnchoredMain = inlineDrop
                local mainControlH = KU_MeasureControlHeight(row.main and row.main.control or nil, TT.CONTROL_FLOOR)
                local inlineLabelH = 0
                local inlineControlH = 0
                if inlineDrop and row.inline and row.inline.control and row.inlineLabel then
                    inlineLabelH = KU_MeasureFontStringHeight(row.inlineLabel, TT.INLINE_LABEL_FLOOR)
                    inlineControlH = KU_MeasureControlHeight(row.inline.control, TT.CONTROL_FLOOR)
                    rowH = math.max(
                        TT.BASE_ROW_H,
                        TT.DROPPED_ROW_TOP_PAD + mainControlH + TT.SUBLINE_MAIN_TO_LABEL_GAP + inlineLabelH + TT.SUBLINE_LABEL_TO_CONTROL_GAP + inlineControlH + TT.DROPPED_ROW_BOTTOM_PAD
                    )
                end
                local swatchDropped = false
                if row.colorSwatch then
                    local swatchW = tonumber(row.colorSwatch:GetWidth()) or 22
                    local swatchRight = tooltipGeo.controlColX + tooltipGeo.mainControlW + TT.SWATCH_GAP + swatchW
                    if swatchRight > (rowW - 2) then
                        swatchDropped = true
                        rowH = math.max(rowH, TT.ROW_H_SWATCH_DROPPED)
                    end
                end
                row.container:ClearAllPoints()
                row.container:SetPoint("TOPLEFT", tooltipBuilder.inspectorContent, "TOPLEFT", 0, rowY)
                row.container:SetWidth(rowW)
                row.container:SetHeight(rowH)

                row.label:ClearAllPoints()
                if topAnchoredMain then
                    row.label:SetPoint("TOPLEFT", row.container, "TOPLEFT", tooltipGeo.labelColX, -TT.TOP_LABEL_Y_INSET)
                else
                    row.label:SetPoint("LEFT", row.container, "LEFT", tooltipGeo.labelColX, rowContentYNudge)
                end
                row.label:SetWidth(math.max(T.TOOLTIP_LABEL_MIN_W, tooltipGeo.labelW))

                if row.main and row.main.control then
                    row.main.control:ClearAllPoints()
                    if topAnchoredMain then
                        row.main.control:SetPoint("TOPLEFT", row.container, "TOPLEFT", tooltipGeo.controlColX, -TT.MAIN_TOP_PAD)
                    else
                        row.main.control:SetPoint("LEFT", row.container, "LEFT", tooltipGeo.controlColX, rowContentYNudge)
                    end
                    if row.main.SetWidth then
                        row.main:SetWidth(tooltipGeo.mainControlW)
                    elseif row.main.Layout then
                        row.main:Layout(tooltipGeo.mainControlW)
                    end
                end

                if row.inline and row.inline.control and row.inlineLabel then
                    if inlineDrop then
                        if row.inlineAccent then
                            row.inlineAccent:Show()
                        end
                        local droppedLabelY = -(TT.MAIN_TOP_PAD + mainControlH + TT.SUBLINE_MAIN_TO_LABEL_GAP)
                        local inlineControlY = droppedLabelY - inlineLabelH - TT.SUBLINE_LABEL_TO_CONTROL_GAP
                        row.inlineLabel:ClearAllPoints()
                        row.inlineLabel:SetPoint("TOPLEFT", row.container, "TOPLEFT", tooltipGeo.controlColX + TT.SUBLINE_LABEL_X_INSET, droppedLabelY)
                        row.inlineLabel:SetWidth(math.max(TT.SUBLINE_LABEL_MIN_W, rowW - tooltipGeo.controlColX - TT.SUBLINE_LABEL_RIGHT_PAD))
                        if row.inlineAccent then
                            row.inlineAccent:ClearAllPoints()
                            row.inlineAccent:SetPoint("TOPLEFT", row.container, "TOPLEFT", tooltipGeo.controlColX + TT.SUBLINE_ACCENT_X_INSET, droppedLabelY - TT.SUBLINE_ACCENT_Y_NUDGE)
                            row.inlineAccent:SetHeight(math.max(TT.SUBLINE_ACCENT_MIN_H, inlineLabelH + TT.SUBLINE_ACCENT_HEIGHT_PAD))
                        end
                        row.inline.control:ClearAllPoints()
                        row.inline.control:SetPoint("TOPLEFT", row.container, "TOPLEFT", tooltipGeo.controlColX + TT.SUBLINE_LABEL_X_INSET, inlineControlY)
                    else
                        if row.inlineAccent then
                            row.inlineAccent:Hide()
                        end
                        row.inlineLabel:ClearAllPoints()
                        row.inlineLabel:SetPoint("LEFT", row.container, "LEFT", tooltipGeo.inlineRegionX, 0)
                        row.inlineLabel:SetWidth(TOOLTIP_BUILDER_INLINE_LABEL_W)
                        row.inline.control:ClearAllPoints()
                        row.inline.control:SetPoint(
                            "LEFT",
                            row.container,
                            "LEFT",
                            tooltipGeo.inlineRegionX + TOOLTIP_BUILDER_INLINE_LABEL_W + TT.INLINE_BLOCK_GAP,
                            0
                        )
                    end
                    row.inline:Layout(TOOLTIP_BUILDER_INLINE_TOGGLE_W)
                end

                if row.colorSwatch then
                    row.colorSwatch:ClearAllPoints()
                    if swatchDropped then
                        row.colorSwatch:SetPoint("TOPLEFT", row.container, "TOPLEFT", tooltipGeo.controlColX, -(TT.BASE_ROW_H + TT.DROPPED_ROW_BOTTOM_PAD))
                    else
                        row.colorSwatch:SetPoint(
                            "LEFT",
                            row.container,
                            "LEFT",
                            tooltipGeo.controlColX + tooltipGeo.mainControlW + TT.SWATCH_GAP,
                            0
                        )
                    end
                end

                rowY = rowY - rowH - TT.ROW_GAP
            end

            local usedInspectorH = math.max(0, math.abs(rowY) + TT.INSPECTOR_PAD_Y)
            tooltipBuilder.inspectorContent:SetHeight(usedInspectorH)
            inspectorPaneH = TT.STATUS_H + TT.INSPECTOR_PAD_Y + TT.STATUS_TO_CONTENT_GAP + usedInspectorH + TT.INSPECTOR_PAD_Y
            if inspectorPaneH < TOOLTIP_BUILDER_PREVIEW_H then
                inspectorPaneH = TOOLTIP_BUILDER_PREVIEW_H
            end
            tooltipBuilder.inspectorPane:SetHeight(inspectorPaneH)

            if tooltipGeo.sideBySide then
                tooltipBuilder.previewPane:ClearAllPoints()
                tooltipBuilder.previewPane:SetSize(tooltipGeo.previewW, TOOLTIP_BUILDER_PREVIEW_H)
                tooltipBuilder.previewPane:SetPoint("TOPLEFT", tooltipBuilder.root, "TOPLEFT", tooltipGeo.inspectorW + TT.PANE_GAP, -TT.STICKY_TOP_PAD)
                tooltipBuilder.root:SetHeight(math.max(inspectorPaneH, TOOLTIP_BUILDER_PREVIEW_H))
            else
                tooltipBuilder.previewPane:ClearAllPoints()
                tooltipBuilder.previewPane:SetPoint("TOPLEFT", tooltipBuilder.root, "TOPLEFT", 0, -(inspectorPaneH + TT.PANE_GAP))
                tooltipBuilder.previewPane:SetSize(tooltipGeo.previewW, TOOLTIP_BUILDER_PREVIEW_H)
                tooltipBuilder.root:SetHeight(inspectorPaneH + TT.PANE_GAP + TOOLTIP_BUILDER_PREVIEW_H)
            end

            tooltipBuilder.previewTitle:ClearAllPoints()
            if tooltipGeo.sideBySide then
                tooltipBuilder.previewTitle:SetPoint("TOPLEFT", tooltipBuilder.root, "TOPLEFT", tooltipGeo.inspectorW + TT.PANE_GAP + TT.PREVIEW_TITLE_PAD_X, -TT.TITLE_TOP_PAD)
            else
                tooltipBuilder.previewTitle:SetPoint("TOPLEFT", tooltipBuilder.previewPane, "TOPLEFT", TT.PREVIEW_TITLE_PAD_X, -TT.TITLE_TOP_PAD)
            end

            widgets.keystoneTooltipPreviewAnchor:ClearAllPoints()
            widgets.keystoneTooltipPreviewAnchor:SetPoint("TOPLEFT", tooltipBuilder.previewPane, "TOPLEFT", TT.PREVIEW_BODY_PAD_X, -tooltipGeo.previewAnchorTopInset)
            widgets.keystoneTooltipPreviewAnchor:SetPoint("BOTTOMRIGHT", tooltipBuilder.previewPane, "BOTTOMRIGHT", -TT.PREVIEW_BODY_PAD_X, TT.PREVIEW_BODY_BOTTOM_PAD)

            tooltipBuilder.previewHitLayer:ClearAllPoints()
            tooltipBuilder.previewHitLayer:SetPoint("TOPLEFT", widgets.keystoneTooltipPreviewAnchor, "TOPLEFT", 0, 0)
            tooltipBuilder.previewHitLayer:SetPoint("BOTTOMRIGHT", widgets.keystoneTooltipPreviewAnchor, "BOTTOMRIGHT", 0, 0)

            do
                local firstRow = tooltipBuilder.rows and tooltipBuilder.rows[1] or nil
                local firstRowTop = firstRow and firstRow.container and firstRow.container.GetTop and firstRow.container:GetTop() or nil
                if tooltipGeo.sideBySide and firstRowTop and firstRowTop > 0 then
                    tooltipBuilder._desiredPreviewBodyTopAbs = firstRowTop
                else
                    tooltipBuilder._desiredPreviewBodyTopAbs = nil
                end
            end

            y = y - tooltipBuilder.root:GetHeight() - S.TOOLTIP_BOTTOM_GAP

            scrollChild:SetHeight(math.max(scrollFrame:GetHeight(), math.abs(y) + P.BOTTOM_PAD))
            updateScrollBehavior(scrollFrame, scrollChild)
        end

        self._layout = layout
        self._refreshVisuals = refreshVisuals
        self._refresh = refresh
        self._fullRefresh = fullRefresh
        self._invalidateLayout = invalidateLayout
        self._kuBuildMetricSignature = KU_BuildMetricSignature
        invalidateLayout("initial-build")

        if not self._kuTooltipPreviewEventFrame then
            local eventFrame = CreateFrame("Frame")
            eventFrame:SetScript("OnEvent", function(frameEvent)
                local owner = frameEvent._owner
                if not owner or not owner.IsShown or not owner:IsShown() then
                    return
                end
                if owner._refresh then
                    owner._refresh()
                end
            end)
            self._kuTooltipPreviewEventFrame = eventFrame
        end
        self._kuTooltipPreviewEventFrame._owner = self

        if not self._kuMetricWatcher then
            local metricWatcher = CreateFrame("Frame", nil, self)
            metricWatcher:Hide()
            metricWatcher:SetScript("OnUpdate", function(frameWatcher, elapsed)
                local owner = frameWatcher._owner
                if not owner or not owner.IsShown or not owner:IsShown() then
                    frameWatcher:Hide()
                    return
                end
                frameWatcher._elapsed = (tonumber(frameWatcher._elapsed) or 0) + (tonumber(elapsed) or 0)
                if frameWatcher._elapsed < KEYSTONE_UTILITY_LAYOUT.METRIC_WATCH_INTERVAL then
                    return
                end
                frameWatcher._elapsed = 0
                if not (owner._kuBuildMetricSignature and owner._invalidateLayout and owner._fullRefresh) then
                    return
                end
                if not KU_HasSizedLayoutSurface() then
                    owner._invalidateLayout("metric-unsized")
                    return
                end
                local currentSignature = owner._kuBuildMetricSignature()
                if currentSignature ~= owner._kuMetricSignatureCache then
                    owner._invalidateLayout("metric-signature")
                    owner._fullRefresh("metric-signature")
                end
            end)
            metricWatcher:SetScript("OnHide", function(frameWatcher)
                frameWatcher._elapsed = 0
            end)
            self._kuMetricWatcher = metricWatcher
        end
        self._kuMetricWatcher._owner = self

        registerRefreshCallback(function()
            if self._refresh then
                self._refresh()
            end
        end, self)
        scrollFrame:SetScript("OnSizeChanged", function()
            invalidateLayout("size-changed")
            local useHostedFirstOpen = isPanelUsingCustomSettingsWindowHost(self)
            if useHostedFirstOpen and handleSettingsFirstOpenSizeReady(self, "size_changed") then
                return
            end
            if useHostedFirstOpen and shouldSuppressSettingsFirstOpenExternalRefresh(self) then
                return
            end
            if not (self and self.IsShown and self:IsShown()) then
                return
            end
            if self._fullRefresh then
                self._fullRefresh("size-changed")
            end
        end)

        self._settingsFirstOpenKey = "keystone"
        self._settingsFirstOpenSizeTarget = scrollFrame
        self._settingsFirstOpenRender = function(panel)
            ensureKeystonePanelAnchored(panel)
            ensureDatabase()
            if not (panel and panel._initialized and panel._layout and panel._refresh and panel._fullRefresh) then
                if panel and panel.EnsureBuilt then
                    panel:EnsureBuilt()
                end
            end
            if panel and PortalAuthorityDB and panel._initialized and panel._layout and panel._refresh and panel._fullRefresh and keystoneHasSizedViewport(panel) then
                renderKeystoneWhenReady(panel)
                return
            end
            if panel and panel._fullRefresh then
                panel._fullRefresh("bootstrap")
            end
            startKeystoneRenderBootstrap(panel)
        end
        self._settingsFirstOpenIsReady = function(panel)
            return isPanelUsingCustomSettingsWindowHost(panel)
                and panel ~= nil
                and panel._initialized == true
                and type(panel._layout) == "function"
                and type(panel._refresh) == "function"
                and type(panel._fullRefresh) == "function"
                and keystoneHasSizedViewport(panel)
                and panel._kuRenderBootstrapActive ~= true
                and panel._kuScrollChild ~= nil
                and panel._kuScrollChild.IsShown
                and panel._kuScrollChild:IsShown()
        end
        self._initialized = true
        settingsSearchRuntime.endDescriptorCapture(self)
    end

    ensureKeystonePanelAnchored = function(self)
        local p = self:GetParent()
        if not p then
            return false
        end
        if self._paAnchorParent ~= p or not self._paAnchored then
            self:ClearAllPoints()
            self:SetAllPoints(p)
            self._paAnchorParent = p
        end
        self._paAnchored = true
        return true
    end

    renderKeystoneWhenReady = function(self)
        if not self or not self.IsShown or not self:IsShown() then
            return
        end
        if not (self._initialized and self._layout and self._refresh and self._fullRefresh) then
            return
        end
        if not PortalAuthorityDB then
            return
        end
        ensureKeystonePanelAnchored(self)
        if self._sizingFrame and self._sizingFrame.Show then
            self._sizingFrame:Show()
            if self._sizingFrame.SetVerticalScroll then
                self._sizingFrame:SetVerticalScroll(0)
            end
        end
        if self._kuScrollChild and self._kuScrollChild.Show then
            self._kuScrollChild:Show()
        end
        if self._fullRefresh then
            self._fullRefresh("render-ready")
        end
    end

    keystoneHasSizedViewport = function(self)
        local readyFrame = (self and self._sizingFrame) or self
        if not readyFrame then
            return false
        end
        local w = tonumber(readyFrame:GetWidth()) or 0
        local h = tonumber(readyFrame:GetHeight()) or 0
        return (w > 1 and h > 1)
    end

    startKeystoneRenderBootstrap = function(self)
        if not self then
            return
        end
        local watcher = self._kuRenderBootstrapWatcher
        if not watcher then
            watcher = CreateFrame("Frame", nil, self)
            watcher:Hide()
            watcher:SetScript("OnUpdate", function(frameWatcher, elapsed)
                local owner = frameWatcher._owner
                if not owner or not owner.IsShown or not owner:IsShown() then
                    frameWatcher:Hide()
                    return
                end
                frameWatcher._elapsed = (tonumber(frameWatcher._elapsed) or 0) + (tonumber(elapsed) or 0)
                ensureDatabase()
                if not (owner._initialized and owner._layout and owner._refresh and owner._fullRefresh) then
                    owner:EnsureBuilt()
                end
                ensureKeystonePanelAnchored(owner)
                if PortalAuthorityDB and owner._initialized and owner._layout and owner._refresh and owner._fullRefresh and keystoneHasSizedViewport(owner) then
                    renderKeystoneWhenReady(owner)
                    frameWatcher:Hide()
                    return
                end
                -- Intentionally no hard timeout: keep retrying while this panel stays shown,
                -- so first-open can recover without requiring a section switch.
            end)
            watcher:SetScript("OnHide", function(frameWatcher)
                frameWatcher._elapsed = 0
                if frameWatcher._owner then
                    frameWatcher._owner._kuRenderBootstrapActive = false
                end
            end)
            self._kuRenderBootstrapWatcher = watcher
        end
        watcher._owner = self
        watcher._elapsed = 0
        if not self._kuRenderBootstrapActive then
            self._kuRenderBootstrapActive = true
            watcher:Show()
        end
    end

    panel:SetScript("OnShow", function(self)
        ensureKeystonePanelAnchored(self)
        ensureDatabase()
        self:EnsureBuilt()
        if self._kuTooltipPreviewEventFrame then
            self._kuTooltipPreviewEventFrame._owner = self
            self._kuTooltipPreviewEventFrame:RegisterEvent("GET_ITEM_INFO_RECEIVED")
            self._kuTooltipPreviewEventFrame:RegisterEvent("BAG_UPDATE_DELAYED")
            self._kuTooltipPreviewEventFrame:RegisterEvent("CHALLENGE_MODE_MAPS_UPDATE")
            self._kuTooltipPreviewEventFrame:RegisterEvent("PLAYER_ENTERING_WORLD")
        end
        if self._kuMetricWatcher then
            self._kuMetricWatcher._owner = self
            self._kuMetricWatcher._elapsed = 0
            self._kuMetricWatcher:Show()
        end

        if isPanelUsingCustomSettingsWindowHost(self) and self._paFirstOpenState == "pending" then
            resetSettingsFirstOpenPanelState(self)
        end
        if isPanelUsingCustomSettingsWindowHost(self) and handleSettingsFirstOpenPanelShow(self) then
            return
        end

        if PortalAuthorityDB and self._initialized and self._layout and self._refresh and self._fullRefresh and keystoneHasSizedViewport(self) then
            renderKeystoneWhenReady(self)
        else
            if self._fullRefresh then
                self._fullRefresh("bootstrap")
            end
            startKeystoneRenderBootstrap(self)
        end

        if C_Timer and C_Timer.After then
            C_Timer.After(0, function()
                if not self or not self:IsShown() then return end
                ensureDatabase()
                if not (self._initialized and self._layout and self._refresh and self._fullRefresh) then
                    self:EnsureBuilt()
                end
                if PortalAuthorityDB and self._initialized and self._layout and self._refresh and self._fullRefresh and keystoneHasSizedViewport(self) then
                    renderKeystoneWhenReady(self)
                else
                    if self._fullRefresh then
                        self._fullRefresh("bootstrap")
                    end
                    startKeystoneRenderBootstrap(self)
                end
            end)
        end
    end)
    panel:HookScript("OnHide", function(self)
        if isPanelUsingCustomSettingsWindowHost(self) or isSettingsFirstOpenSettlePending(self) then
            handleSettingsFirstOpenPanelHide(self)
        end
        if self and self._kuRenderBootstrapWatcher then
            self._kuRenderBootstrapWatcher:Hide()
        end
        if self and self._kuMetricWatcher then
            self._kuMetricWatcher:Hide()
        end
        if self and self._kuTooltipPreviewEventFrame then
            self._kuTooltipPreviewEventFrame:UnregisterAllEvents()
        end
        if self and self._kuCloseTooltipBuilderPickers then
            self._kuCloseTooltipBuilderPickers()
        end
    end)

    return panel
end

local function createCombatAlertsPanel()
    local panel = CreateFrame("Frame")
    panel.name = "Combat Alerts"
    panel._paSearchSectionKey = "combat"
    panel._paSearchSectionName = panel.name

    panel.EnsureBuilt = function(self)
        -- Only treat as initialized if the panel actually finished wiring layout/refresh.
        if self._initialized and self._layout and self._refresh then return end
        resetSettingsFirstOpenPanelState(self)
        ensureDatabase()
        settingsSearchRuntime.beginDescriptorCapture(self)

        local scrollFrame, scrollChild = createScrollableChild(self)
        if not scrollFrame or not scrollChild then
            settingsSearchRuntime.endDescriptorCapture(self)
            return
        end
        self._sizingFrame = scrollFrame

        local widgets = {}
        local panelRef = self

        local function onApply()
            if PortalAuthority and PortalAuthority.ApplyCombatAlertsSettings then
                PortalAuthority:ApplyCombatAlertsSettings()
            end

            -- If test mode is currently active, immediately re-render the test message so changes are visible live.
            if PortalAuthority
                and PortalAuthority.DeathAlerts_IsTestModeActive
                and PortalAuthority.DeathAlerts_RefreshTestMode
                and PortalAuthority:DeathAlerts_IsTestModeActive()
            then
                PortalAuthority:DeathAlerts_RefreshTestMode()
            end

            if panelRef and panelRef._refresh then
                panelRef._refresh()
            end
        end

        local function getDeathAlertSoundChoices(currentValue)
            local media = getPortalMedia()
            if media and media.GetChoices then
                return media.GetChoices("sound", {
                    includeNone = true,
                    includeBuiltinIDs = true,
                    currentValue = currentValue,
                }) or {}
            end
            return buildFallbackSoundChoices(currentValue, {
                includeNone = true,
                includeBuiltinIDs = true,
            })
        end

        local function previewDeathAlertSound(value)
            if value == nil or value == "" then
                return
            end

            local soundFile = value
            if PortalAuthority and PortalAuthority.GetDeathAlertSoundFile then
                soundFile = PortalAuthority:GetDeathAlertSoundFile(value)
            end
            if not soundFile or soundFile == "" then
                return
            end

            local channel = "Master"
            if PortalAuthorityDB and type(PortalAuthorityDB.deathAlertSoundChannel) == "string" and PortalAuthorityDB.deathAlertSoundChannel ~= "" then
                channel = PortalAuthorityDB.deathAlertSoundChannel
            elseif PortalAuthority and PortalAuthority.defaults and type(PortalAuthority.defaults.deathAlertSoundChannel) == "string" and PortalAuthority.defaults.deathAlertSoundChannel ~= "" then
                channel = PortalAuthority.defaults.deathAlertSoundChannel
            end

            if type(soundFile) == "number" and PlaySound then
                PlaySound(soundFile, channel)
            elseif PlaySoundFile then
                PlaySoundFile(soundFile, channel)
            end
        end

        local function stylePremiumEditBox(edit, textSize)
            if not edit then
                return
            end
            textSize = tonumber(textSize) or 12
            edit:SetAutoFocus(false)
            edit:SetMultiLine(false)
            edit:SetTextInsets(8, 8, 0, 0)
            edit:SetTextColor(1, 1, 1, 1)
            edit:SetHighlightColor(1, 1, 1, 0.25)
            applyGlobalFontToObject(edit, textSize)

            if not edit._paPremiumBg then
                edit._paPremiumBg = edit:CreateTexture(nil, "ARTWORK")
                edit._paPremiumBg:SetAllPoints(edit)
                edit._paPremiumBg:SetTexture("Interface\\Buttons\\WHITE8x8")
                edit._paPremiumBg:SetVertexColor(0.10, 0.11, 0.14, 0.95)

                edit._paPremiumBorder = CreateFrame("Frame", nil, edit, "BackdropTemplate")
                edit._paPremiumBorder:SetPoint("TOPLEFT", edit, "TOPLEFT", -1, 1)
                edit._paPremiumBorder:SetPoint("BOTTOMRIGHT", edit, "BOTTOMRIGHT", 1, -1)
                edit._paPremiumBorder:SetBackdrop({
                    edgeFile = "Interface\\Buttons\\WHITE8x8",
                    edgeSize = 1,
                })
                edit._paPremiumBorder:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
            end

            local function hideTemplateChrome()
                if edit.Left then edit.Left:SetAlpha(0) end
                if edit.Middle then edit.Middle:SetAlpha(0) end
                if edit.Right then edit.Right:SetAlpha(0) end
            end

            local function applyVisual()
                hideTemplateChrome()
                if edit:HasFocus() then
                    edit._paPremiumBg:SetVertexColor(0.12, 0.13, 0.17, 0.95)
                    edit._paPremiumBorder:SetBackdropBorderColor(0.30, 0.33, 0.38, 1.0)
                else
                    edit._paPremiumBg:SetVertexColor(0.10, 0.11, 0.14, 0.95)
                    edit._paPremiumBorder:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
                end
            end

            edit:HookScript("OnShow", applyVisual)
            edit:HookScript("OnEditFocusGained", applyVisual)
            edit:HookScript("OnEditFocusLost", applyVisual)
            applyVisual()
        end

        local function createPremiumPickerButton(parent, labelText, optionsProvider, getter, setter, onApplyCallback, pickerOpts)
            pickerOpts = type(pickerOpts) == "table" and pickerOpts or {}
            local label = createStyledFontString(parent, "ARTWORK", "GameFontHighlight", 12)
            label:SetText(labelText or "")

            local button = CreateFrame("Button", nil, parent, "BackdropTemplate")
            button:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
                insets = { left = 0, right = 0, top = 0, bottom = 0 },
            })
            button:SetBackdropColor(0.10, 0.11, 0.14, 0.95)
            button:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
            button:SetHeight(22)
            button:SetWidth(math.max(132, math.floor(tonumber(pickerOpts.width) or 180)))

            local text = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 11)
            text:SetPoint("LEFT", button, "LEFT", 8, 0)
            text:SetPoint("RIGHT", button, "RIGHT", -18, 0)
            text:SetJustifyH("LEFT")
            text:SetTextColor(0.92, 0.92, 0.92, 1)

            local caret = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 10)
            caret:SetPoint("RIGHT", button, "RIGHT", -7, 0)
            caret:SetText("v")
            caret:SetTextColor(0.76, 0.76, 0.78, 1)
            button._paSelectEnabled = true
            local currentButtonLabel = ""

            local function setButtonLabel(labelText)
                currentButtonLabel = tostring(labelText or "")
                text:SetWordWrap(false)
                if text.SetMaxLines then
                    text:SetMaxLines(1)
                end
                local maxWidth = math.max(20, (button:GetWidth() or 0) - 26)
                text:SetWidth(maxWidth)
                text:SetText(currentButtonLabel)
                if pickerOpts and pickerOpts.ellipsis == false then
                    return
                end
                if text:GetStringWidth() <= maxWidth then
                    return
                end

                local source = currentButtonLabel
                local cut = string.len(source)
                while cut > 0 do
                    local candidate = string.sub(source, 1, cut) .. "..."
                    text:SetText(candidate)
                    if text:GetStringWidth() <= maxWidth then
                        return
                    end
                    cut = cut - 1
                end
                text:SetText("...")
            end

            local picker = CreatePicker(UIParent, {}, function(value)
                local selectedValue = value
                if selectedValue == nil then
                    selectedValue = ""
                end
                if setter then
                    setter(selectedValue)
                end
                if onApplyCallback then
                    onApplyCallback()
                end
            end, {
                title = tostring(pickerOpts.title or "Select Option"),
                searchHint = tostring(pickerOpts.searchHint or "Search"),
                width = tonumber(pickerOpts.pickerWidth) or 420,
                height = tonumber(pickerOpts.pickerHeight) or 360,
                minHeight = tonumber(pickerOpts.minHeight),
                showSecondary = false,
                useOptionFontPreview = pickerOpts.useOptionFontPreview and true or false,
                useOptionTexturePreview = pickerOpts.useOptionTexturePreview and true or false,
                previewFontSize = tonumber(pickerOpts.previewFontSize) or 12,
                rowHeight = tonumber(pickerOpts.rowHeight) or 26,
                showClearButton = false,
                noSearch = pickerOpts.noSearch and true or false,
                hideTitle = pickerOpts.hideTitle and true or false,
                hideScrollBar = pickerOpts.hideScrollBar and true or false,
                onOptionRightClick = pickerOpts.onOptionRightClick,
                footerHint = tostring(pickerOpts.footerHint or ""),
            })

            local function applyVisual(hovered)
                applySettingsWindowSelectButtonChrome(
                    button,
                    text,
                    caret,
                    hovered,
                    false,
                    button._paSelectEnabled ~= false,
                    function()
                        if hovered then
                            button:SetBackdropColor(0.16, 0.17, 0.20, 0.95)
                            button:SetBackdropBorderColor(0.30, 0.33, 0.38, 1.0)
                            caret:SetTextColor(0.88, 0.88, 0.90, 1)
                        else
                            button:SetBackdropColor(0.10, 0.11, 0.14, 0.95)
                            button:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
                            caret:SetTextColor(0.76, 0.76, 0.78, 1)
                        end
                    end
                )
            end

            button:SetScript("OnEnter", function()
                applyVisual(true)
            end)
            button:SetScript("OnLeave", function()
                applyVisual(false)
            end)

            local function buildPickerOptions()
                local built = {}
                for _, option in ipairs(optionsProvider and optionsProvider() or {}) do
                    local value = option.value
                    if value == nil then
                        value = ""
                    end
                    built[#built + 1] = {
                        value = value,
                        label = tostring(option.label or value),
                        buttonLabel = tostring(option.buttonLabel or option.label or value),
                        secondary = tostring(option.secondary or ""),
                        previewFontPath = option.previewFontPath,
                        previewTexturePath = option.previewTexturePath or option.path,
                        aliases = option.aliases,
                    }
                end
                if #built == 0 then
                    built[1] = { value = "", label = "None", buttonLabel = "None", secondary = "" }
                end
                return built
            end

            local function resolveSelection(rawValue, options)
                local selected = rawValue
                if selected == nil then
                    selected = ""
                end
                local selectedKey = tostring(selected)
                local selectedLabel = nil
                local emptyFallbackLabel = tostring(pickerOpts.emptyLabel or "None")
                for _, option in ipairs(options or {}) do
                    if tostring(option.value or "") == selectedKey then
                        selected = option.value
                        selectedLabel = tostring(option.buttonLabel or option.label or selectedKey)
                        break
                    end
                end
                if not selectedLabel then
                    if selectedKey == "" then
                        selected = ""
                        selectedLabel = emptyFallbackLabel
                    else
                        local first = options and options[1] or nil
                        if first then
                            selected = first.value
                            selectedLabel = tostring(first.buttonLabel or first.label or tostring(selected or ""))
                            if setter then
                                setter(selected)
                            end
                        else
                            selected = ""
                            selectedLabel = "None"
                        end
                    end
                end
                return selected, selectedLabel
            end

            local spec = { kind = "picker_button", label = label, control = button, text = text, picker = picker }

            spec.SetWidth = function(_, newWidth)
                button:SetWidth(math.max(132, math.floor(tonumber(newWidth) or pickerOpts.width or 180)))
                setButtonLabel(currentButtonLabel)
            end

            spec.SetEnabled = function(_, enabled)
                local allow = enabled and true or false
                button._paSelectEnabled = allow
                button:EnableMouse(allow)
                button:SetAlpha(allow and 1 or 0.6)
                text:SetAlpha(allow and 1 or 0.65)
                caret:SetAlpha(allow and 1 or 0.65)
                applyVisual(false)
            end

            spec.Refresh = function()
                local options = buildPickerOptions()
                picker:SetOptions(options)
                local selectedValue, selectedLabel = resolveSelection(getter and getter() or "", options)
                picker:SetSelectedValue(selectedValue)
                setButtonLabel(selectedLabel ~= "" and selectedLabel or "None")
            end

            button:SetScript("OnClick", function()
                if picker and picker.IsShown and picker:IsShown() then
                    picker:Close()
                    return
                end
                spec.Refresh()
                picker:Open(button)
            end)
            button:HookScript("OnSizeChanged", function()
                setButtonLabel(currentButtonLabel)
            end)
            registerSettingsWindowVisualRefresh(button, function()
                applyVisual(button.IsMouseOver and button:IsMouseOver() or false)
            end)

            spec.Refresh()
            return spec
        end

        local header = createStyledFontString(scrollChild, "ARTWORK", "GameFontNormalLarge", 14)
        header:SetText("|cffffd100Combat Alerts|r")
        widgets.sectionDescriptor = createSettingsSectionDescriptor(scrollChild, "Control death alerts, audio, and on-screen messaging.")
        local deathHeader = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlight", 12)
        deathHeader:SetText("Death Alerts")
        local deathDesc = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlightSmall", 11)
        deathDesc:SetText("Audio and/or on-screen alerts when a Tank/Healer/DPS (or you) dies in your party/raid.")
        deathDesc:SetTextColor(0.72, 0.72, 0.72, 1)
        deathDesc:SetJustifyH("LEFT")

        widgets.soundColumnLabel = createStyledFontString(scrollChild, "ARTWORK", "GameFontHighlightSmall", 11)
