        local function safeSetDropWidth(dd, w)
            if dd == nil then return end
            local name = dd.GetName and dd:GetName() or nil
            if UIDropDownMenu_SetWidth and name and _G[name .. "Button"] then
                UIDropDownMenu_SetWidth(dd, w)
                return
            end
            if dd.SetWidth then
                dd:SetWidth(w)
            end
        end

        local function setSingleLineEllipsis(fs, fullText, maxWidth)
            if not fs then
                return
            end
            local source = tostring(fullText or "")
            fs:SetWordWrap(false)
            if fs.SetMaxLines then
                fs:SetMaxLines(1)
            end
            fs:SetWidth(maxWidth or 0)
            fs:SetText(source)
            if (maxWidth or 0) <= 0 then
                return
            end
            if (fs.GetStringWidth and fs:GetStringWidth() or 0) <= maxWidth then
                return
            end
            local cut = string.len(source)
            while cut > 0 do
                local candidate = string.sub(source, 1, cut) .. "..."
                fs:SetText(candidate)
                if (fs.GetStringWidth and fs:GetStringWidth() or 0) <= maxWidth then
                    return
                end
                cut = cut - 1
            end
            fs:SetText("...")
        end

        local function measureFontStringHeight(fs, floor)
            local measured = 0
            if fs and fs.GetStringHeight then
                measured = math.ceil(fs:GetStringHeight() or 0)
            end
            return math.max(tonumber(floor) or 0, measured)
        end

        local function measureControlHeight(widget, floor)
            local measured = 0
            if widget and widget.GetHeight then
                measured = math.ceil(widget:GetHeight() or 0)
            end
            return math.max(tonumber(floor) or 0, measured)
        end

        local function setOffscreenTopLeft(frame)
            if not frame then
