            if frame.Hide then
                frame:Hide()
            end
            frame:ClearAllPoints()
            frame:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", COMBAT_ALERTS_LAYOUT.OFFSCREEN_X, COMBAT_ALERTS_LAYOUT.OFFSCREEN_Y)
        end

