                    frame:Show()
                end
            else
                if frame.Hide then
                    frame:Hide()
                end
            end
        end

        local function computeCombatAlertsRoleGeometry(contentW)
            local T = COMBAT_ALERTS_LAYOUT
            local G = {
                contentW = contentW,
                contentLeft = T.CONTENT_LEFT,
                contentRight = contentW - T.CONTENT_RIGHT,
                roleLabelW = T.ROLE_LABEL_PREF_W,
                enableW = T.ENABLE_PREF_W,
                screenW = T.SCREEN_W,
            }
            G.roleX = G.contentLeft
            G.screenX = G.contentRight - G.screenW
            local function recompute()
                G.enableX = G.roleX + G.roleLabelW + T.ROLE_TO_ENABLE_GAP
                G.soundX = G.enableX + G.enableW + T.ENABLE_TO_SOUND_GAP
                G.soundW = G.screenX - T.SOUND_TO_SCREEN_GAP - G.soundX
            end
            recompute()
            if G.soundW < T.SOUND_TARGET_MIN_W then
                G.roleLabelW = T.ROLE_LABEL_MID_W
                recompute()
            end
            if G.soundW < T.SOUND_TARGET_MIN_W then
                G.roleLabelW = T.ROLE_LABEL_MIN_W
                recompute()
            end
            if G.soundW < T.SOUND_TARGET_MIN_W then
                G.enableW = T.ENABLE_NARROW_W
                recompute()
            end
            if G.soundW < T.SOUND_MIN_W then
                G.soundW = T.SOUND_MIN_W
                G.soundX = math.min(G.soundX, G.screenX - T.SOUND_TO_SCREEN_GAP - G.soundW)
            end
            return G
        end

        local function computeCombatAlertsLockGeometry(contentW, lockLabel)
            local T = COMBAT_ALERTS_LAYOUT
            local lockLabelW = lockLabel and math.ceil(lockLabel:GetStringWidth() or 0) or 0
            local lockLabelH = lockLabel and math.ceil(lockLabel:GetStringHeight() or 0) or T.LABEL_FLOOR
            local unit = math.max(1, lockLabelH)
            local lockBtnTextW = 0
            if widgets.lockPosition and type(widgets.lockPosition.buttons) == "table" then
                for _, btn in ipairs(widgets.lockPosition.buttons) do
                    if btn and btn.Text then
                        lockBtnTextW = math.max(lockBtnTextW, math.ceil(btn.Text:GetStringWidth() or 0))
                    end
                end
            end
            lockBtnTextW = math.max(lockBtnTextW, T.LOCK_BUTTON_TEXT_FALLBACK_W)
            local lockToggleWFromContent = ((lockBtnTextW + (T.LOCK_SEGMENT_BUTTON_TEXT_PAD_X * 2)) * 2) + 4
            local lockToggleWMax = math.max(
                T.LOCK_TOGGLE_MIN_W,
                (contentW - T.CONTENT_RIGHT) - (T.CONTENT_LEFT + lockLabelW + T.LOCK_LABEL_TO_TOGGLE_GAP + T.LOCK_TOGGLE_TO_RESET_GAP + T.RESET_W)
            )
            local lockToggleW = math.max(T.LOCK_TOGGLE_MIN_W, math.min(lockToggleWFromContent, lockToggleWMax))
            local toggleX = (lockLabelW > 0) and (lockLabelW + T.LOCK_LABEL_TO_TOGGLE_GAP) or 0
            local resetX = toggleX + lockToggleW + T.LOCK_TOGGLE_TO_RESET_GAP
            return {
                labelW = lockLabelW,
                labelH = lockLabelH,
                helperGap = unit * T.LOCK_HELPER_MULTIPLIER,
                dividerGap = unit * T.LOCK_DIVIDER_MULTIPLIER,
                toggleW = lockToggleW,
                toggleX = toggleX,
                resetX = resetX,
                rowW = math.max(1, contentW - T.CONTENT_RIGHT - T.CONTENT_LEFT),
            }
        end

        local function computeCombatAlertsMessageGeometry(contentW)
            local T = COMBAT_ALERTS_LAYOUT
            local messageAreaW = math.max(T.MESSAGE_AREA_MIN_W, contentW - T.CONTENT_LEFT - T.CONTENT_RIGHT)
            local leftBlockMinW = math.max(T.MESSAGE_INPUT_MIN_W, T.MESSAGE_PREVIEW_MIN_W, T.MESSAGE_INSERT_MIN_W)
            local canSideBySide = messageAreaW >= (leftBlockMinW + T.MESSAGE_RIGHT_RAIL_W + T.MESSAGE_INTER_BLOCK_GAP)
            return {
                areaW = messageAreaW,
                canSideBySide = canSideBySide,
                leftGroupW = canSideBySide and (messageAreaW - T.MESSAGE_RIGHT_RAIL_W - T.MESSAGE_INTER_BLOCK_GAP) or messageAreaW,
                rightRailW = T.MESSAGE_RIGHT_RAIL_W,
                interBlockGap = T.MESSAGE_INTER_BLOCK_GAP,
            }
        end

        local function computeCombatAlertsSettingsGeometry(contentW)
            local T = COMBAT_ALERTS_LAYOUT
            local controlX = T.CONTENT_LEFT + T.SETTINGS_CONTROL_OFFSET
            local dropdownW = math.max(
                T.SETTINGS_DROPDOWN_MIN_W,
                math.min(T.SETTINGS_DROPDOWN_MAX_W, contentW - controlX - T.CONTENT_RIGHT)
            )
            return {
                labelX = T.CONTENT_LEFT,
                controlX = controlX,
                labelW = math.max(T.SETTINGS_LABEL_MIN_W, T.SETTINGS_CONTROL_OFFSET - T.GRID_UNIT),
                rowW = math.max(T.SETTINGS_ROW_MIN_W, contentW - T.CONTENT_LEFT - T.CONTENT_RIGHT),
                dropdownW = dropdownW,
            }
        end

