        local function insertMessageToken(token)
            local edit = widgets.messageEdit
            if not edit then
                return
            end
            local current = tostring(edit:GetText() or "")
            local cursor = edit.GetCursorPosition and edit:GetCursorPosition() or nil
            cursor = tonumber(cursor) or #current
            if cursor < 0 then
                cursor = 0
            elseif cursor > #current then
                cursor = #current
            end
            local updated = string.sub(current, 1, cursor) .. tostring(token or "") .. string.sub(current, cursor + 1)
            edit:SetText(updated)
            if edit.SetCursorPosition then
                edit:SetCursorPosition(cursor + string.len(tostring(token or "")))
            end
            if edit.SetFocus then
                edit:SetFocus()
            end
            upsertMessageTemplateFromText(updated)
            onApply()
        end

