                pressedBg = { 0.05, 0.06, 0.08, 0.96 },
                baseBorder = { 0.17, 0.19, 0.23, 0.54 },
                hoverBorder = { 0.21, 0.24, 0.28, 0.60 },
                pressedBorder = { 0.19, 0.22, 0.26, 0.58 },
                textColor = { 0.78, 0.79, 0.83, 1 },
            })
            chip:SetScript("OnClick", function()
                insertMessageToken(tokenText)
