        local function setDropdownEnabled(spec, enabled)
            if not (spec and spec.control) then return end
            if spec.SetEnabled then
                spec:SetEnabled(enabled)
                return
            end
            local dd = spec.control
            if UIDropDownMenu_EnableDropDown and UIDropDownMenu_DisableDropDown then
                if enabled then UIDropDownMenu_EnableDropDown(dd) else UIDropDownMenu_DisableDropDown(dd) end
            end
            if dd.EnableMouse then dd:EnableMouse(enabled) end
            local alpha = enabled and 1 or 0.6
            dd:SetAlpha(alpha)
            local name = dd.GetName and dd:GetName()
            if name then
                local button = _G[name .. "Button"]
                local text = _G[name .. "Text"]
                if button then
                    button:SetAlpha(alpha)
                    if button.EnableMouse then button:EnableMouse(enabled) end
                    if button.SetEnabled then button:SetEnabled(enabled) end
                end
                if text then
                    text:SetAlpha(alpha)
                end
            end
        end

        local function updateCoordsDisplay()
            if not widgets.coordsEdit then return end
            if widgets._coordsEditing and widgets.coordsEdit:HasFocus() then
                return
            end
            local x = math.floor(tonumber(PortalAuthorityDB and PortalAuthorityDB.deathAlertX) or 0)
            local y = math.floor(tonumber(PortalAuthorityDB and PortalAuthorityDB.deathAlertY) or 0)
            widgets.coordsEdit:SetText(string.format("%d, %d", x, y))
            widgets.coordsEdit:SetJustifyH("CENTER")
            if widgets.coordsEdit.SetCursorPosition then widgets.coordsEdit:SetCursorPosition(0) end
            if widgets.coordsEdit.HighlightText then widgets.coordsEdit:HighlightText(0, 0) end
            widgets.coordsEdit:SetTextColor(0.86, 0.86, 0.88, 1)
            widgets.coordsEdit:SetAlpha(0.90)
            if widgets.coordsEdit.EnableKeyboard then
                widgets.coordsEdit:EnableKeyboard(false)
            end
        end

        local function setCoordsEditMode(editing)
            widgets._coordsEditing = editing and true or false
            if not widgets.coordsEdit then
                return
            end
            if widgets.coordsEdit.EnableKeyboard then
                widgets.coordsEdit:EnableKeyboard(widgets._coordsEditing)
            end
            if widgets._coordsEditing then
                widgets.coordsEdit:SetJustifyH("CENTER")
                widgets.coordsEdit:SetTextColor(1, 1, 1, 1)
                widgets.coordsEdit:SetAlpha(1)
            else
                widgets.coordsEdit:SetJustifyH("CENTER")
                widgets.coordsEdit:SetTextColor(0.86, 0.86, 0.88, 1)
                widgets.coordsEdit:SetAlpha(0.90)
            end
        end

        local function flashCoordsInvalid()
            local border = widgets.coordsEdit and widgets.coordsEdit._paPremiumBorder
            if not border or not border.SetBackdropBorderColor then
                return
            end
            border:SetBackdropBorderColor(0.42, 0.20, 0.20, 1)
            if C_Timer and C_Timer.After then
                C_Timer.After(0.12, function()
                    if not widgets.coordsEdit or (widgets._coordsEditing and widgets.coordsEdit:HasFocus()) then
                        return
                    end
                    if widgets.coordsEdit._paPremiumBorder and widgets.coordsEdit._paPremiumBorder.SetBackdropBorderColor then
                        widgets.coordsEdit._paPremiumBorder:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
                    end
                end)
            end
        end

        local function parseCoordsInput(raw)
            local values = {}
            for token in string.gmatch(tostring(raw or ""), "[-+]?%d+%.?%d*") do
                values[#values + 1] = tonumber(token)
            end
            if #values ~= 2 or not values[1] or not values[2] then
                return nil, nil
            end
            return math.floor(values[1]), math.floor(values[2])
        end

        local function beginCoordsEdit()
            if not widgets.coordsEdit or widgets._coordsEditing then
                return
            end
            setCoordsEditMode(true)
            widgets.coordsEdit:SetFocus()
            if widgets.coordsEdit.HighlightText then
                widgets.coordsEdit:HighlightText()
            end
        end

        local function finishCoordsEdit(commit)
            if not widgets.coordsEdit or not widgets._coordsEditing then
                return
            end

            if commit then
                local x, y = parseCoordsInput(widgets.coordsEdit:GetText())
                if x ~= nil and y ~= nil and PortalAuthorityDB then
                    PortalAuthorityDB.deathAlertX = x
                    PortalAuthorityDB.deathAlertY = y
                    setCoordsEditMode(false)
                    widgets.coordsEdit:ClearFocus()
                    onApply()
                    return
                end
                flashCoordsInvalid()
            end

            setCoordsEditMode(false)
            widgets.coordsEdit:ClearFocus()
            updateCoordsDisplay()
        end

        local function SetRoleIcon(row, role)
            if not row or not row.icon then return end
            if role == "HEALER" then
                if row.icon.SetAtlas then row.icon:SetAtlas(nil) end
                row.icon:SetTexture("Interface\\LFGFrame\\UI-LFG-ICON-ROLES")
                if GetTexCoordsForRole then
                    local l, r, t, b = GetTexCoordsForRole("HEALER")
                    if l and r and t and b then
                        row.icon:SetTexCoord(l, r, t, b)
                    else
                        row.icon:SetTexCoord(0, 1, 0, 1)
                    end
                else
                    row.icon:SetTexCoord(0, 1, 0, 1)
                end
                return
            end
            local atlasName = nil
            if role == "TANK" then
                atlasName = "groupfinder-icon-role-large-tank"
            else
                atlasName = "groupfinder-icon-role-large-dps"
            end

            local atlasOk = false
            if C_Texture and C_Texture.GetAtlasInfo and atlasName then
                atlasOk = (C_Texture.GetAtlasInfo(atlasName) ~= nil)
            end

            if atlasOk and row.icon.SetAtlas then
                row.icon:SetAtlas(atlasName)
                row.icon:SetTexCoord(0, 1, 0, 1)
                return
            end

            if row.icon.SetAtlas then
                row.icon:SetAtlas(nil)
            end
            row.icon:SetTexture("Interface\\LFGFrame\\UI-LFG-ICON-ROLES")
            if GetTexCoordsForRole then
                local l, r, t, b = GetTexCoordsForRole(role)
                if l and r and t and b then
                    row.icon:SetTexCoord(l, r, t, b)
                    return
                end
            end
            row.icon:SetTexCoord(0, 1, 0, 1)
        end

        local function updateSelfVisual(row)
            local playerName = UnitName and UnitName("player") or "Player"
            if Ambiguate then
                playerName = Ambiguate(playerName, "short")
            end
            local _, classFile = nil, nil
            if UnitClass then
                _, classFile = UnitClass("player")
            end
            local classColor = (classFile and RAID_CLASS_COLORS and RAID_CLASS_COLORS[classFile]) or NORMAL_FONT_COLOR
            local helperText = tostring(playerName or "Player")
            row._roleDisplayText = "Player"
            row._roleTextColor = { 0.94, 0.95, 0.97, 1 }
            row._helperFallbackText = helperText
            row._helperFallbackColor = {
                math.max(0, math.min(1, ((classColor and classColor.r) or 1) * 0.80)),
                math.max(0, math.min(1, ((classColor and classColor.g) or 1) * 0.80)),
                math.max(0, math.min(1, ((classColor and classColor.b) or 1) * 0.80)),
                0.85,
            }
            row._roleHelperFullText = helperText
            row._roleHelperColor = {
                row._helperFallbackColor[1],
                row._helperFallbackColor[2],
                row._helperFallbackColor[3],
                row._helperFallbackColor[4],
            }
            local specIndex = GetSpecialization and GetSpecialization()
            if specIndex and GetSpecializationInfo then
                local _, _, _, specIcon = GetSpecializationInfo(specIndex)
                if specIcon then
                    if row.icon.SetAtlas then
                        row.icon:SetAtlas(nil)
                    end
                    row.icon:SetTexture(specIcon)
                    row.icon:SetTexCoord(0, 1, 0, 1)
                    return
                end
            end
            if classFile and CLASS_ICON_TCOORDS and CLASS_ICON_TCOORDS[classFile] then
                if row.icon.SetAtlas then
                    row.icon:SetAtlas(nil)
                end
                row.icon:SetTexture("Interface\\GLUES\\CHARACTERCREATE\\UI-CHARACTERCREATE-CLASSES")
                local coords = CLASS_ICON_TCOORDS[classFile]
                row.icon:SetTexCoord(coords[1], coords[2], coords[3], coords[4])
            else
                if row.icon.SetAtlas then
                    row.icon:SetAtlas(nil)
                end
                row.icon:SetTexture("Interface\\ICONS\\INV_Misc_QuestionMark")
                row.icon:SetTexCoord(0, 1, 0, 1)
            end
        end
        local function updateRoleIcon(row)
            if row.roleKey == "SELF" then
                updateSelfVisual(row)
                return
            end
            row._roleDisplayText = tostring(row.roleLabel or "")
            row._roleTextColor = { 0.94, 0.95, 0.97, 1 }
            row._helperFallbackText = nil
            row._helperFallbackColor = nil
            row._roleHelperFullText = ""
            row._roleHelperColor = nil
            SetRoleIcon(row, row.roleKey)
        end

        local function getRowSoundValue(db, prefix)
            if not db then
                return ""
            end
            local value = db[prefix .. "Sound"]
            if value == nil then
                return ""
            end
            if type(value) == "number" then
                return tostring(value)
            end
            return tostring(value)
        end

        applyOnScreenRuleWrite = function(row, db, enabled)
            if not row or not db then
                return
            end
            local onScreenKey = row.prefix .. "OnScreen"
            local isEnabled = PA_SafeBool(enabled)
            local soundIsNone = (getRowSoundValue(db, row.prefix) == "")
            local isForced = isEnabled and soundIsNone
            local wasForced = row._paWasForcedByNone and true or false

            if not isEnabled then
                db[onScreenKey] = false
                row._paOnScreenForcedByNone = false
                row._paWasForcedByNone = false
                row._onScreenValue = false
                return
            end

            if isForced then
                if (not wasForced) and (not PA_SafeBool(db[onScreenKey])) then
                    db[onScreenKey] = true
                elseif db[onScreenKey] == nil then
                    db[onScreenKey] = true
                end
                row._paOnScreenForcedByNone = true
                row._paWasForcedByNone = true
                row._onScreenValue = true
                return
            end

            if wasForced or row._paOnScreenForcedByNone then
                db[onScreenKey] = false
            end
            db[onScreenKey] = PA_SafeBool(db[onScreenKey])
            row._paOnScreenForcedByNone = false
            row._paWasForcedByNone = false
            row._onScreenValue = PA_SafeBool(db[onScreenKey])
        end

        local function applyOnScreenRuleVisual(row, db, enabled)
            if not row or not db then
                return
            end
            local isEnabled = PA_SafeBool(enabled)
            local soundIsNone = (getRowSoundValue(db, row.prefix) == "")
            local isForced = isEnabled and soundIsNone
            local visualValue = false
            local allowInteraction = isEnabled

            if isForced then
                visualValue = true
                row._paOnScreenForcedByNone = true
                row._paWasForcedByNone = true
            elseif not isEnabled then
                visualValue = false
                row._paOnScreenForcedByNone = false
                row._paWasForcedByNone = false
            else
                visualValue = PA_SafeBool(db[row.prefix .. "OnScreen"])
                row._paOnScreenForcedByNone = false
                row._paWasForcedByNone = false
            end

            row._onScreenValue = visualValue
            if row.onScreen and row.onScreen.SetChoiceEnabled then
                row.onScreen:SetChoiceEnabled(false, not isForced)
                row.onScreen:SetChoiceEnabled(true, true)
            end
            if row.onScreen and row.onScreen.SetVisualSelectedValue then
                row.onScreen:SetVisualSelectedValue(visualValue)
            elseif row.onScreen and row.onScreen.SetSelectedValue then
                row.onScreen:SetSelectedValue(visualValue, false)
            end
            if row.onScreen and row.onScreen.SetEnabled then
                row.onScreen:SetEnabled(allowInteraction)
            end
            if row.onScreenHelper then
                if soundIsNone then
                    row.onScreenHelper:SetText("Required when Sound=None")
                    row.onScreenHelper:SetTextColor(0.58, 0.58, 0.58, 0.92)
                    row._onScreenHelperFullText = "Required when Sound=None"
                else
                    row.onScreenHelper:SetText("")
                    row.onScreenHelper:SetTextColor(0.58, 0.58, 0.58, 0.92)
                    row._onScreenHelperFullText = ""
                end
            end
        end

        local function updateMessagePreviewLine(db)
            if not widgets.messageHelp then
