            elseif spec.SetSelectedValue then
                spec:SetSelectedValue(normalized, false)
            end
        end

        local function applyCombatAlertsModuleEnabledState(moduleEnabled)
            setSettingsControlEnabled(widgets.lockPosition, moduleEnabled)
            setSettingsControlEnabled(widgets.resetAnchor, moduleEnabled)
            setSettingsControlEnabled(widgets.antiSpam, moduleEnabled)
            setSettingsControlEnabled(widgets.showRoleIcon, moduleEnabled)
            setSettingsControlEnabled(widgets.coordsEdit, moduleEnabled)
            setSettingsControlEnabled(widgets.font, moduleEnabled)
            setSettingsControlEnabled(widgets.fontSizeStepper or widgets.fontSizeEdit, moduleEnabled)
            setSettingsControlEnabled(widgets.channel, moduleEnabled)
            setSettingsControlEnabled(widgets.messageEdit, moduleEnabled)
            setSettingsControlEnabled(widgets.tokenChipRole, moduleEnabled)
            setSettingsControlEnabled(widgets.tokenChipName, moduleEnabled)
            setSettingsControlEnabled(widgets.tokenChipClass, moduleEnabled)

            if not moduleEnabled then
                if widgets.messageEdit and widgets.messageEdit.ClearFocus then
                    widgets.messageEdit:ClearFocus()
                end
                if widgets.coordsEdit and widgets.coordsEdit.ClearFocus then
                    widgets.coordsEdit:ClearFocus()
                end
                if widgets.fontSizeEdit and widgets.fontSizeEdit.ClearFocus then
                    widgets.fontSizeEdit:ClearFocus()
                end
            end

            if widgets.lockRowContainer and widgets.lockRowContainer.SetAlpha then
                widgets.lockRowContainer:SetAlpha(moduleEnabled and 1 or 0.55)
            end
            if widgets.messageLeftGroup and widgets.messageLeftGroup.SetAlpha then
                widgets.messageLeftGroup:SetAlpha(moduleEnabled and 1 or 0.55)
            end
            if widgets.messageRightGroup and widgets.messageRightGroup.SetAlpha then
                widgets.messageRightGroup:SetAlpha(moduleEnabled and 1 or 0.55)
            end
            if widgets.coordsRowContainer and widgets.coordsRowContainer.SetAlpha then
                widgets.coordsRowContainer:SetAlpha(moduleEnabled and 1 or 0.55)
            end
            if widgets.fontRowContainer and widgets.fontRowContainer.SetAlpha then
                widgets.fontRowContainer:SetAlpha(moduleEnabled and 1 or 0.55)
            end
            if widgets.channelRowContainer and widgets.channelRowContainer.SetAlpha then
                widgets.channelRowContainer:SetAlpha(moduleEnabled and 1 or 0.55)
            end

            for _, textWidget in ipairs({
                widgets.lockStateHelper,
                widgets.soundColumnLabel,
                widgets.screenColumnLabel,
                widgets.messageLabel,
                widgets.messagePreviewLabel,
                widgets.messageHelp,
                widgets.insertLabel,
                widgets.coordsLabel,
                widgets.fontSizeLabel,
                widgets.channelHint,
            }) do
                setSettingsTextEnabled(textWidget, moduleEnabled)
            end

            for _, row in ipairs(rows) do
                local rowEnabled = row and row.enabledValue and true or false
                local rowInteractive = moduleEnabled
                local subControlInteractive = moduleEnabled and rowEnabled

                setSettingsControlEnabled(row and row.enabled or nil, rowInteractive)
                setSettingsControlEnabled(row and row.sound or nil, subControlInteractive)
                setSettingsControlEnabled(row and row.onScreen or nil, subControlInteractive)

                if row and row.container and row.container.SetAlpha then
                    row.container:SetAlpha(moduleEnabled and 1 or 0.55)
                end
                if row and row.icon then
                    row.icon:SetAlpha((moduleEnabled and rowEnabled) and 1 or 0.55)
                end
                if row and row.roleBadge then
                    row.roleBadge:SetAlpha((moduleEnabled and rowEnabled) and 1 or 0.92)
                end
                if row and row.roleText then
                    row.roleText:SetAlpha((moduleEnabled and rowEnabled) and 1 or 0.88)
                end
                setSettingsTextEnabled(row and row.roleHelper or nil, moduleEnabled)
                setSettingsTextEnabled(row and row.onScreenHelper or nil, moduleEnabled)
            end
        end

        local function refresh()
            if ensureDatabase then ensureDatabase() end
            local db = PortalAuthorityDB or {}
            local moduleEnabled = db.combatAlertsEnabled ~= false

            syncCombatAlertsSelectionControl(widgets.moduleEnabled, moduleEnabled)

            for _, row in ipairs(rows) do
                local prefix = row.prefix
                local enabled = PA_SafeBool(db[prefix .. "Enabled"])
                local rowActive = moduleEnabled and enabled
                row.enabledValue = enabled
                if row.enabled and row.enabled.SetVisualSelectedValue then
                    row.enabled:SetVisualSelectedValue(enabled)
                elseif row.enabled and row.enabled.SetSelectedValue then
                    row.enabled:SetSelectedValue(enabled, false)
                end
                if row.sound and row.sound.Refresh then
                    row.sound:Refresh()
                end
                setDropdownEnabled(row.sound, rowActive)
                updateRoleIcon(row)
                applyOnScreenRuleVisual(row, db, enabled)
                if row.roleText then
                    row.roleText:SetText(row._roleDisplayText or row.roleLabel or "")
                end
                row.icon:SetAlpha(rowActive and 1 or 0.55)
                if row.roleBadge then
                    row.roleBadge:SetAlpha(rowActive and 1 or 0.92)
                end
                row.roleText:SetAlpha(rowActive and 1 or 0.88)
                if row._roleTextColor and row.roleText then
                    row.roleText:SetTextColor(row._roleTextColor[1], row._roleTextColor[2], row._roleTextColor[3], row._roleTextColor[4] or 1)
                end
                if row.roleHelper then
                    local roleHelperText = tostring(row._roleHelperFullText or "")
                    if roleHelperText ~= "" then
                        local c = row._roleHelperColor or { 0.58, 0.58, 0.58, 0.92 }
                        row.roleHelper:SetText(roleHelperText)
                        row.roleHelper:SetTextColor(c[1], c[2], c[3], c[4] or 0.92)
                    else
                        row.roleHelper:SetText("")
                        row.roleHelper:SetTextColor(0.58, 0.58, 0.58, 0.92)
                    end
                end
            end

            syncCombatAlertsSelectionControl(widgets.lockPosition, db.deathAlertLocked)
            if widgets.lockStateHelper then
                if not moduleEnabled then
                    widgets.lockStateHelper:SetText("Combat Alerts are disabled. Re-enable to edit settings.")
                elseif PA_SafeBool(db.deathAlertLocked) then
                    widgets.lockStateHelper:SetText("Combat Alerts are locked.")
                else
                    widgets.lockStateHelper:SetText("Combat Alerts are unlocked - drag to reposition.")
                end
            end
            if widgets.antiSpam and widgets.antiSpam.Refresh then
                widgets.antiSpam:Refresh()
            end
            if widgets.channel and widgets.channel.Refresh then widgets.channel:Refresh() end
            if widgets.font and widgets.font.Refresh then widgets.font:Refresh() end
            if widgets.showRoleIcon and widgets.showRoleIcon.Refresh then
                widgets.showRoleIcon:Refresh()
            end
            updateMessagePreviewLine(db)
            updateCoordsDisplay()

            if widgets.messageEdit and not widgets.messageEdit:HasFocus() then
                widgets.messageEdit:SetText(tostring(db.deathAlertMessageTemplate or (PortalAuthority and PortalAuthority.defaults and PortalAuthority.defaults.deathAlertMessageTemplate) or ""))
                if widgets.messageEdit.HighlightText then
                    widgets.messageEdit:HighlightText(0, 0)
                end
            end

            if widgets.fontSizeStepper and widgets.fontSizeStepper.SetVisualValue then
                local v = math.floor(tonumber(db.deathAlertFontSize) or 36)
                if v < 8 then v = 8 end
                if v > 72 then v = 72 end
                widgets.fontSizeStepper:SetVisualValue(v)
            elseif widgets.fontSizeEdit and not widgets.fontSizeEdit:HasFocus() then
                local v = math.floor(tonumber(db.deathAlertFontSize) or 36)
                widgets.fontSizeEdit:SetText(tostring(v))
                if widgets.fontSizeEdit.SetCursorPosition then widgets.fontSizeEdit:SetCursorPosition(0) end
                if widgets.fontSizeEdit.HighlightText then
                    widgets.fontSizeEdit:HighlightText(0, 0)
                end
                widgets.fontSizeEdit:SetTextColor(1, 1, 1, 1)
            end

            applyCombatAlertsModuleEnabledState(moduleEnabled)
            refreshSettingsWindowHeaderAccessoryIfHosted(panelRef)
        end

        local function layout()
            local T = COMBAT_ALERTS_LAYOUT
            local contentW = scrollFrame:GetWidth()
            if not contentW or contentW <= 1 then
                contentW = self:GetWidth()
            end
            if not contentW or contentW <= 1 then
                contentW = T.FALLBACK_CONTENT_W
            end
            scrollChild:SetWidth(contentW)

            for _, control in ipairs({
                header,
                widgets.masterRowContainer,
                widgets.moduleEnabled and widgets.moduleEnabled.label or nil,
                widgets.moduleEnabled and widgets.moduleEnabled.control or nil,
                widgets.lockRowContainer,
                widgets.lockPosition and widgets.lockPosition.label or nil,
                widgets.lockPosition and widgets.lockPosition.control or nil,
                widgets.resetAnchor,
                widgets.lockStateHelper,
                widgets.settingsDivider,
                deathHeader,
                deathDesc,
                widgets.soundColumnLabel,
                widgets.screenColumnLabel,
                widgets.roleHeaderRow,
                widgets.roleMessageDivider,
                widgets.messageLeftGroup,
                widgets.messageLabel,
                widgets.messageEdit,
                widgets.messagePreviewLabel,
                widgets.messageHelp,
                widgets.insertLabel,
                widgets.tokenChipRole,
                widgets.tokenChipName,
                widgets.tokenChipClass,
                widgets.messageRightGroup,
                widgets.showRoleIcon and widgets.showRoleIcon.label or nil,
                widgets.showRoleIcon and widgets.showRoleIcon.control or nil,
                widgets.antiSpam and widgets.antiSpam.label or nil,
                widgets.antiSpam and widgets.antiSpam.control or nil,
                widgets.coordsRowContainer,
                widgets.coordsLabel,
                widgets.coordsEdit,
                widgets.fontRowContainer,
                widgets.font and widgets.font.label or nil,
                widgets.font and widgets.font.control or nil,
                widgets.fontSizeStepper and widgets.fontSizeStepper.control or widgets.fontSizeEdit,
                widgets.channelRowContainer,
                widgets.channel and widgets.channel.label or nil,
                widgets.channelHint,
                widgets.channel and widgets.channel.control or nil,
            }) do
                setCombatWidgetVisible(control, true)
            end
            for _, row in ipairs(rows) do
                if row then
                    setCombatWidgetVisible(row.container, true)
                    setCombatWidgetVisible(row.roleBadge, true)
                    setCombatWidgetVisible(row.roleText, true)
                    setCombatWidgetVisible(row.enabled and row.enabled.control or nil, true)
                    setCombatWidgetVisible(row.sound and row.sound.control or nil, true)
                    setCombatWidgetVisible(row.onScreen and row.onScreen.control or nil, true)
                    setCombatWidgetVisible(row.roleHelper, true)
                    setCombatWidgetVisible(row.onScreenHelper, true)
                end
            end

            local roleGeo = computeCombatAlertsRoleGeometry(contentW)
            local messageGeo = computeCombatAlertsMessageGeometry(contentW)
            local settingsGeo = computeCombatAlertsSettingsGeometry(contentW)
            local headerWidth = math.max(T.HEADER_MIN_W, contentW - T.HEADER_LEFT - T.CONTENT_RIGHT)
            local useHostedChrome = isPanelUsingCustomSettingsWindowHost(panelRef)
            local y = -T.TOP_PAD
            if useHostedChrome then
                y = y - SETTINGS_WINDOW_HOSTED_TOP_RHYTHM_NUDGE
            end

            if useHostedChrome then
                setCombatWidgetVisible(header, false)
                setCombatWidgetVisible(widgets.sectionDescriptor, false)
                setOffscreenTopLeft(header)
                setOffscreenTopLeft(widgets.sectionDescriptor)
            else
                setCombatWidgetVisible(header, true)
                setCombatWidgetVisible(widgets.sectionDescriptor, true)
                header:ClearAllPoints()
                header:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", T.HEADER_LEFT, y)
                header:SetWidth(headerWidth)
                if header.SetJustifyH then
                    header:SetJustifyH("LEFT")
                end
                local headerH = measureFontStringHeight(header, T.HEADER_FLOOR)
                y = y - headerH - T.HEADER_BOTTOM_GAP
                y = layoutSettingsSectionDescriptor(
                    widgets.sectionDescriptor,
                    scrollChild,
                    T.HEADER_LEFT,
                    y,
                    headerWidth
                )
            end

            local lockLabel = widgets.lockPosition and widgets.lockPosition.label or nil
            local lockGeom = computeCombatAlertsLockGeometry(contentW, lockLabel)
            if useHostedChrome then
                setCombatWidgetVisible(widgets.masterRowContainer, false)
                setCombatWidgetVisible(widgets.moduleEnabled and widgets.moduleEnabled.label or nil, false)
                setCombatWidgetVisible(widgets.moduleEnabled and widgets.moduleEnabled.control or nil, false)
                setOffscreenTopLeft(widgets.masterRowContainer)
                setOffscreenTopLeft(widgets.moduleEnabled and widgets.moduleEnabled.label or nil)
                setOffscreenTopLeft(widgets.moduleEnabled and widgets.moduleEnabled.control or nil)
            else
                setCombatWidgetVisible(widgets.masterRowContainer, true)
                setCombatWidgetVisible(widgets.moduleEnabled and widgets.moduleEnabled.label or nil, true)
                setCombatWidgetVisible(widgets.moduleEnabled and widgets.moduleEnabled.control or nil, true)
                if widgets.moduleEnabled and widgets.moduleEnabled.Layout then
                    widgets.moduleEnabled:Layout(math.max(lockGeom.toggleW, 150))
                end
                local masterLabel = widgets.moduleEnabled and widgets.moduleEnabled.label or nil
                local masterLabelH = measureFontStringHeight(masterLabel, T.LABEL_FLOOR)
                local masterToggleH = measureControlHeight(widgets.moduleEnabled and widgets.moduleEnabled.control, T.RIGHT_CONTROL_FLOOR)
                local masterRowH = math.max(T.LOCK_ROW_FLOOR, masterLabelH, masterToggleH)

                widgets.masterRowContainer:ClearAllPoints()
                widgets.masterRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", T.CONTENT_LEFT, y)
                widgets.masterRowContainer:SetSize(lockGeom.rowW, masterRowH)
                if masterLabel then
                    masterLabel:ClearAllPoints()
                    masterLabel:SetPoint("LEFT", widgets.masterRowContainer, "LEFT", 0, 0)
                end
                if widgets.moduleEnabled and widgets.moduleEnabled.control then
                    widgets.moduleEnabled.control:ClearAllPoints()
                    widgets.moduleEnabled.control:SetPoint("LEFT", widgets.masterRowContainer, "LEFT", lockGeom.toggleX, 0)
                end
                y = y - masterRowH - 4
            end

            if widgets.lockPosition and widgets.lockPosition.Layout then
                widgets.lockPosition:Layout(lockGeom.toggleW)
            end
            local lockToggleH = measureControlHeight(widgets.lockPosition and widgets.lockPosition.control, T.RIGHT_CONTROL_FLOOR)
            local lockRowH = math.max(T.LOCK_ROW_FLOOR, lockGeom.labelH, lockToggleH, T.RESET_H)

            widgets.lockRowContainer:ClearAllPoints()
            widgets.lockRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", T.CONTENT_LEFT, y)
            widgets.lockRowContainer:SetSize(lockGeom.rowW, lockRowH)
            if lockLabel then
                lockLabel:ClearAllPoints()
                lockLabel:SetPoint("LEFT", widgets.lockRowContainer, "LEFT", 0, 0)
            end
            if widgets.lockPosition and widgets.lockPosition.control then
                widgets.lockPosition.control:ClearAllPoints()
                widgets.lockPosition.control:SetPoint("LEFT", widgets.lockRowContainer, "LEFT", lockGeom.toggleX, 0)
            end
            if widgets.resetAnchor then
                widgets.resetAnchor:ClearAllPoints()
                widgets.resetAnchor:SetSize(T.RESET_W, T.RESET_H)
                widgets.resetAnchor:SetPoint("LEFT", widgets.lockRowContainer, "LEFT", lockGeom.resetX, 0)
            end
            y = y - lockRowH

            widgets.lockStateHelper:ClearAllPoints()
            widgets.lockStateHelper:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", T.CONTENT_LEFT, y - lockGeom.helperGap)
            widgets.lockStateHelper:SetWidth(math.max(T.HELPER_MIN_W, contentW - T.CONTENT_LEFT - T.CONTENT_RIGHT))
            if widgets.lockStateHelper.SetJustifyH then widgets.lockStateHelper:SetJustifyH("LEFT") end
            local lockHelperText = tostring(widgets.lockStateHelper:GetText() or "")
            if lockHelperText ~= "" then
                setSingleLineEllipsis(widgets.lockStateHelper, lockHelperText, math.max(T.HELPER_MIN_W, contentW - T.CONTENT_LEFT - T.CONTENT_RIGHT))
            else
            end
            local lockHelperH = measureFontStringHeight(widgets.lockStateHelper, T.HELPER_FLOOR)
            y = y - lockGeom.helperGap - lockHelperH

            if widgets.settingsDivider then
                widgets.settingsDivider:ClearAllPoints()
                local dividerY = y - (lockGeom.dividerGap * 0.5)
                widgets.settingsDivider:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", T.CONTENT_LEFT, dividerY)
                widgets.settingsDivider:SetPoint("TOPRIGHT", scrollChild, "TOPRIGHT", -T.CONTENT_RIGHT, dividerY)
                widgets.settingsDivider:SetHeight(T.DIVIDER_H)
            end
            y = y - lockGeom.dividerGap

            deathHeader:ClearAllPoints()
            deathHeader:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", T.CONTENT_LEFT, y)
            deathHeader:SetWidth(headerWidth)
            if deathHeader.SetJustifyH then
                deathHeader:SetJustifyH("LEFT")
            end
            local deathHeaderH = measureFontStringHeight(deathHeader, T.DEATH_HEADER_FLOOR)
            y = y - deathHeaderH - T.DEATH_HEADER_BOTTOM_GAP

            deathDesc:ClearAllPoints()
            deathDesc:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", T.CONTENT_LEFT, y)
            deathDesc:SetWidth(math.max(T.HEADER_MIN_W, contentW - T.CONTENT_LEFT - T.CONTENT_RIGHT))
            local deathDescH = measureFontStringHeight(deathDesc, T.DEATH_DESC_FLOOR)
            y = y - deathDescH - T.DEATH_DESC_BOTTOM_GAP

            widgets.soundColumnLabel:SetWidth(math.max(T.SOUND_MIN_W, roleGeo.soundW))
            widgets.screenColumnLabel:SetWidth(roleGeo.screenW)
            local roleHeaderH = math.max(
                T.ROLE_HEADER_ROW_FLOOR,
                measureFontStringHeight(widgets.soundColumnLabel, T.HELPER_FLOOR),
                measureFontStringHeight(widgets.screenColumnLabel, T.HELPER_FLOOR)
            )
            widgets.roleHeaderRow:ClearAllPoints()
            widgets.roleHeaderRow:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", 0, y)
            widgets.roleHeaderRow:SetSize(contentW, roleHeaderH)
            widgets.soundColumnLabel:ClearAllPoints()
            widgets.soundColumnLabel:SetPoint("LEFT", widgets.roleHeaderRow, "LEFT", roleGeo.soundX, HEADER_Y_NUDGE)
            widgets.screenColumnLabel:ClearAllPoints()
            widgets.screenColumnLabel:SetPoint("LEFT", widgets.roleHeaderRow, "LEFT", roleGeo.screenX, HEADER_Y_NUDGE)
            y = y - roleHeaderH - T.ROLE_HEADER_BOTTOM_GAP

            local function placeRow(row, topY)
                local badgeW = math.max(T.ROLE_BADGE_MIN_W, roleGeo.roleLabelW)
                if row.enabled and row.enabled.Layout then
                    row.enabled:Layout(roleGeo.enableW)
                end
                if row.onScreen and row.onScreen.Layout then
                    row.onScreen:Layout(roleGeo.screenW)
                end
                if row.sound and row.sound.SetWidth then
                    row.sound:SetWidth(roleGeo.soundW)
                elseif row.sound and row.sound.control then
                    safeSetDropWidth(row.sound.control, roleGeo.soundW)
                end
                if row.sound and row.sound.text then
                    row.sound.text:SetWidth(math.max(T.SOUND_TEXT_MIN_W, roleGeo.soundW - T.SOUND_TEXT_RIGHT_PAD))
                    row.sound.text:SetWordWrap(false)
                    if row.sound.text.SetMaxLines then
                        row.sound.text:SetMaxLines(1)
                    end
                end

                local leftHelperWidth = math.max(T.ROLE_HELPER_MIN_W, badgeW - (T.ROLE_BADGE_TEXT_INSET_X * 2))
                local leftHelperText = tostring(row._roleHelperFullText or "")
                local leftHelperH = 0
                if row.roleHelper then
                    row.roleHelper:SetWidth(leftHelperWidth)
                    row.roleHelper:SetJustifyH("LEFT")
                    row.roleHelper:SetWordWrap(false)
                    if row.roleHelper.SetMaxLines then
                        row.roleHelper:SetMaxLines(1)
                    end
                    if leftHelperText ~= "" then
                        setSingleLineEllipsis(row.roleHelper, leftHelperText, leftHelperWidth)
                        leftHelperH = measureFontStringHeight(row.roleHelper, T.HELPER_FLOOR)
                    else
                        row.roleHelper:SetText("")
                    end
                end

                local rightHelperText = tostring(row._onScreenHelperFullText or "")
                local rightHelperH = 0
                if row.onScreenHelper then
                    row.onScreenHelper:SetWidth(roleGeo.screenW)
                    row.onScreenHelper:SetJustifyH("LEFT")
                    row.onScreenHelper:SetWordWrap(false)
                    if row.onScreenHelper.SetMaxLines then
                        row.onScreenHelper:SetMaxLines(1)
                    end
                    if rightHelperText ~= "" then
                        setSingleLineEllipsis(row.onScreenHelper, rightHelperText, roleGeo.screenW)
                        rightHelperH = measureFontStringHeight(row.onScreenHelper, T.HELPER_FLOOR)
                    else
                        row.onScreenHelper:SetText("")
                    end
                end

                local helperH = math.max(leftHelperH, rightHelperH)
                local rowH = math.max(
                    T.ROLE_ROW_FLOOR,
                    math.max(
                        T.ROLE_BADGE_H,
                        measureControlHeight(row.enabled and row.enabled.control, T.RIGHT_CONTROL_FLOOR),
                        measureControlHeight(row.sound and row.sound.control, T.RIGHT_CONTROL_FLOOR),
                        measureControlHeight(row.onScreen and row.onScreen.control, T.RIGHT_CONTROL_FLOOR)
                    ) + ((helperH > 0) and (helperH + T.ROLE_HELPER_TOP_GAP) or 0)
                )

                row.container:ClearAllPoints()
                row.container:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", 0, topY)
                row.container:SetSize(contentW, rowH)

                if row.icon then
                    row.icon:Hide()
                end

                if row.roleBadge then
                    row.roleBadge:ClearAllPoints()
                    row.roleBadge:SetPoint("LEFT", row.container, "LEFT", roleGeo.roleX, 0)
                    row.roleBadge:SetSize(badgeW, T.ROLE_BADGE_H)
                end
                if row.roleText then
                    row.roleText:ClearAllPoints()
                    row.roleText:SetPoint("LEFT", row.roleBadge or row.container, "LEFT", T.ROLE_BADGE_TEXT_INSET_X, 0)
                    row.roleText:SetPoint("RIGHT", row.roleBadge or row.container, "RIGHT", -T.ROLE_BADGE_TEXT_INSET_X, 0)
                end

                if row.enabled and row.enabled.control then
                    row.enabled.control:ClearAllPoints()
                    row.enabled.control:SetPoint("LEFT", row.container, "LEFT", roleGeo.enableX, 0)
                end

                if row.sound and row.sound.control then
                    row.sound.control:ClearAllPoints()
                    row.sound.control:SetPoint("LEFT", row.container, "LEFT", roleGeo.soundX, 0)
                end

                if row.onScreen and row.onScreen.control then
                    row.onScreen.control:ClearAllPoints()
                    row.onScreen.control:SetPoint("LEFT", row.container, "LEFT", roleGeo.screenX, 0)
                end

                if row.roleHelper then
                    row.roleHelper:ClearAllPoints()
                    if leftHelperText ~= "" then
                        setCombatWidgetVisible(row.roleHelper, true)
                        row.roleHelper:SetPoint("BOTTOMLEFT", row.container, "BOTTOMLEFT", roleGeo.roleX + T.ROLE_BADGE_TEXT_INSET_X, T.ROLE_HELPER_LEFT_Y_NUDGE)
                    else
                        setCombatWidgetVisible(row.roleHelper, false)
                        row.roleHelper:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", T.OFFSCREEN_X, T.OFFSCREEN_Y)
                    end
                end

                if row.onScreenHelper then
                    row.onScreenHelper:ClearAllPoints()
                    if rightHelperText ~= "" then
                        setCombatWidgetVisible(row.onScreenHelper, true)
                        row.onScreenHelper:SetPoint("BOTTOMLEFT", row.container, "BOTTOMLEFT", roleGeo.screenX, T.FORCED_HELPER_Y_NUDGE)
                    else
                        setCombatWidgetVisible(row.onScreenHelper, false)
                        row.onScreenHelper:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", T.OFFSCREEN_X, T.OFFSCREEN_Y)
                    end
                end

                return rowH
            end

            y = y - placeRow(widgets.rowTank, y)
            y = y - placeRow(widgets.rowHealer, y)
            y = y - placeRow(widgets.rowDps, y)
            y = y - placeRow(widgets.rowSelf, y)

            local roleDividerY = y - (T.ROLE_TO_MESSAGE_GAP * 0.5)
            widgets.roleMessageDivider:ClearAllPoints()
            widgets.roleMessageDivider:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", T.CONTENT_LEFT, roleDividerY)
            widgets.roleMessageDivider:SetPoint("TOPRIGHT", scrollChild, "TOPRIGHT", -T.CONTENT_RIGHT, roleDividerY)
            widgets.roleMessageDivider:SetHeight(T.DIVIDER_H)
            y = y - T.ROLE_TO_MESSAGE_GAP

            widgets.messageLeftGroup:ClearAllPoints()
            widgets.messageLeftGroup:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", T.CONTENT_LEFT, y)
            widgets.messageLeftGroup:SetSize(messageGeo.leftGroupW, 1)

            widgets.messageLabel:ClearAllPoints()
            widgets.messageLabel:SetPoint("TOPLEFT", widgets.messageLeftGroup, "TOPLEFT", 0, 0)
            widgets.messageLabel:SetWidth(messageGeo.leftGroupW)
            if widgets.messageLabel.SetJustifyH then widgets.messageLabel:SetJustifyH("LEFT") end
            local messageLabelH = measureFontStringHeight(widgets.messageLabel, T.LABEL_FLOOR)

            widgets.messageEdit:ClearAllPoints()
            widgets.messageEdit:SetPoint("TOPLEFT", widgets.messageLeftGroup, "TOPLEFT", 0, -(messageLabelH + T.GRID_UNIT))
            widgets.messageEdit:SetWidth(messageGeo.leftGroupW)
            local editH = measureControlHeight(widgets.messageEdit, T.MESSAGE_EDIT_FLOOR)

            setOffscreenTopLeft(widgets.tokenChipsLabel)

            local previewRowGap = math.max(T.PREVIEW_ROW_GAP_FLOOR, math.floor(T.GRID_UNIT * 0.5))
            local previewRowY = -(messageLabelH + T.GRID_UNIT + editH + previewRowGap)
            widgets.messagePreviewLabel:ClearAllPoints()
            widgets.messagePreviewLabel:SetPoint("TOPLEFT", widgets.messageLeftGroup, "TOPLEFT", 0, previewRowY)
            local previewLabelW = math.max(T.PREVIEW_LABEL_MIN_W, math.ceil((widgets.messagePreviewLabel.GetStringWidth and widgets.messagePreviewLabel:GetStringWidth()) or 34))
            local previewLabelH = measureFontStringHeight(widgets.messagePreviewLabel, T.HELPER_FLOOR)

            local helpWidth = math.max(T.PREVIEW_HELP_MIN_W, messageGeo.leftGroupW - previewLabelW - T.PREVIEW_HELP_WIDTH_PAD)
            widgets.messageHelp:ClearAllPoints()
            widgets.messageHelp:SetPoint("TOPLEFT", widgets.messageLeftGroup, "TOPLEFT", previewLabelW + T.PREVIEW_LABEL_TO_HELP_GAP, previewRowY)
            setSingleLineEllipsis(widgets.messageHelp, widgets.messageHelp._paFullText, helpWidth)
            local helpH = measureFontStringHeight(widgets.messageHelp, T.HELPER_FLOOR)
            local previewRowH = math.max(previewLabelH, helpH)

            local chipsRowGap = math.max(T.CHIPS_ROW_GAP_FLOOR, math.floor(T.GRID_UNIT * 0.5))
            local insertRowY = previewRowY - previewRowH - chipsRowGap
            widgets.insertLabel:ClearAllPoints()
            widgets.insertLabel:SetPoint("TOPLEFT", widgets.messageLeftGroup, "TOPLEFT", 0, insertRowY)
            local insertLabelW = math.max(T.INSERT_LABEL_MIN_W, math.ceil((widgets.insertLabel.GetStringWidth and widgets.insertLabel:GetStringWidth()) or 0))
            local insertLabelH = measureFontStringHeight(widgets.insertLabel, T.HELPER_FLOOR)

            widgets.tokenChipRole:ClearAllPoints()
            widgets.tokenChipRole:SetPoint("TOPLEFT", widgets.messageLeftGroup, "TOPLEFT", insertLabelW + T.INSERT_LABEL_TO_CHIPS_GAP, insertRowY)
            widgets.tokenChipName:ClearAllPoints()
            widgets.tokenChipName:SetPoint("TOPLEFT", widgets.messageLeftGroup, "TOPLEFT", insertLabelW + T.INSERT_LABEL_TO_CHIPS_GAP + (widgets.tokenChipRole:GetWidth() or 0) + T.TOKEN_CHIP_GAP, insertRowY)
            widgets.tokenChipClass:ClearAllPoints()
            widgets.tokenChipClass:SetPoint(
                "TOPLEFT",
                widgets.messageLeftGroup,
                "TOPLEFT",
                insertLabelW + T.INSERT_LABEL_TO_CHIPS_GAP + (widgets.tokenChipRole:GetWidth() or 0) + T.TOKEN_CHIP_GAP + (widgets.tokenChipName:GetWidth() or 0) + T.TOKEN_CHIP_GAP,
                insertRowY
            )
            local chipH = math.max(
                T.TOKEN_CHIP_H,
                measureControlHeight(widgets.tokenChipRole, T.TOKEN_CHIP_H),
                measureControlHeight(widgets.tokenChipName, T.TOKEN_CHIP_H),
                measureControlHeight(widgets.tokenChipClass, T.TOKEN_CHIP_H)
            )
            local insertRowH = math.max(insertLabelH, chipH)
            local leftBlockH = messageLabelH + T.GRID_UNIT + editH + previewRowGap + previewRowH + chipsRowGap + insertRowH
            widgets.messageLeftGroup:SetSize(messageGeo.leftGroupW, math.max(1, leftBlockH))

            if widgets.showRoleIcon and widgets.showRoleIcon.Layout then
                widgets.showRoleIcon:Layout(T.RIGHT_TOGGLE_W)
            end
            if widgets.antiSpam and widgets.antiSpam.Layout then
                widgets.antiSpam:Layout(T.RIGHT_TOGGLE_W)
            end
            if widgets.showRoleIcon and widgets.showRoleIcon.label then
                widgets.showRoleIcon.label:SetWidth(messageGeo.rightRailW)
                if widgets.showRoleIcon.label.SetJustifyH then widgets.showRoleIcon.label:SetJustifyH("LEFT") end
            end
            if widgets.antiSpam and widgets.antiSpam.label then
                widgets.antiSpam.label:SetWidth(messageGeo.rightRailW)
                if widgets.antiSpam.label.SetJustifyH then widgets.antiSpam.label:SetJustifyH("LEFT") end
            end
            local showLabelH = measureFontStringHeight(widgets.showRoleIcon and widgets.showRoleIcon.label, T.RIGHT_LABEL_FLOOR)
            local showControlH = measureControlHeight(widgets.showRoleIcon and widgets.showRoleIcon.control, T.RIGHT_CONTROL_FLOOR)
            local antiLabelH = measureFontStringHeight(widgets.antiSpam and widgets.antiSpam.label, T.RIGHT_LABEL_FLOOR)
            local antiControlH = measureControlHeight(widgets.antiSpam and widgets.antiSpam.control, T.RIGHT_CONTROL_FLOOR)
            local firstControlTopOffset = -math.max(
                (messageLabelH + T.GRID_UNIT) + (editH * 0.5) - (showControlH * 0.5),
                showLabelH + T.RIGHT_LABEL_GAP
            )
            local antiLabelTopOffset = firstControlTopOffset - showControlH - T.RIGHT_STACK_GAP
            local antiControlTopOffset = antiLabelTopOffset - antiLabelH - T.RIGHT_CONTROL_GAP
            local rightBlockBottomY = antiControlTopOffset - antiControlH
            local rightBlockH = math.max(showLabelH, math.abs(rightBlockBottomY))

            widgets.messageRightGroup:ClearAllPoints()
            if messageGeo.canSideBySide then
                widgets.messageRightGroup:SetPoint(
                    "TOPLEFT",
                    scrollChild,
                    "TOPLEFT",
                    T.CONTENT_LEFT + messageGeo.leftGroupW + messageGeo.interBlockGap,
                    y
                )
            else
                widgets.messageRightGroup:SetPoint(
                    "TOPLEFT",
                    scrollChild,
                    "TOPLEFT",
                    T.CONTENT_LEFT,
                    y - (leftBlockH + T.MESSAGE_BRANCH_STACK_GAP)
                )
            end
            widgets.messageRightGroup:SetSize(messageGeo.rightRailW, rightBlockH)

            if widgets.showRoleIcon and widgets.showRoleIcon.label and widgets.showRoleIcon.control then
                widgets.showRoleIcon.label:ClearAllPoints()
                widgets.showRoleIcon.label:SetPoint("TOPLEFT", widgets.messageRightGroup, "TOPLEFT", 0, 0)
                widgets.showRoleIcon.control:ClearAllPoints()
                widgets.showRoleIcon.control:SetPoint("TOPLEFT", widgets.messageRightGroup, "TOPLEFT", 0, firstControlTopOffset)
            end
            if widgets.antiSpam and widgets.antiSpam.label and widgets.antiSpam.control then
                widgets.antiSpam.label:ClearAllPoints()
                widgets.antiSpam.label:SetPoint("TOPLEFT", widgets.messageRightGroup, "TOPLEFT", 0, antiLabelTopOffset)
                widgets.antiSpam.control:ClearAllPoints()
                widgets.antiSpam.control:SetPoint("TOPLEFT", widgets.messageRightGroup, "TOPLEFT", 0, antiControlTopOffset)
            end

            if messageGeo.canSideBySide then
                y = y - math.max(leftBlockH, rightBlockH)
            else
                y = y - (leftBlockH + T.MESSAGE_BRANCH_STACK_GAP + rightBlockH)
            end

            setOffscreenTopLeft(widgets.settingsHeader)
            y = y - T.MESSAGE_TO_SETTINGS_GAP

            local coordsLabelOffset = settingsGeo.controlX - settingsGeo.labelX

            widgets.coordsLabel:SetWidth(settingsGeo.labelW)
            if widgets.coordsLabel.SetJustifyH then widgets.coordsLabel:SetJustifyH("LEFT") end
            local coordsLabelH = measureFontStringHeight(widgets.coordsLabel, T.LABEL_FLOOR)
            local coordsEditH = measureControlHeight(widgets.coordsEdit, T.RIGHT_CONTROL_FLOOR)
            local coordsRowH = math.max(T.SETTINGS_ROW_FLOOR, coordsLabelH, coordsEditH)
            widgets.coordsRowContainer:ClearAllPoints()
            widgets.coordsRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", settingsGeo.labelX, y)
            widgets.coordsRowContainer:SetSize(settingsGeo.rowW, coordsRowH)
            widgets.coordsLabel:ClearAllPoints()
            widgets.coordsLabel:SetPoint("LEFT", widgets.coordsRowContainer, "LEFT", 0, 0)
            widgets.coordsEdit:ClearAllPoints()
            widgets.coordsEdit:SetPoint("LEFT", widgets.coordsRowContainer, "LEFT", coordsLabelOffset, 0)
            widgets.coordsEdit:SetSize(T.COORDS_W, T.RIGHT_CONTROL_FLOOR)
            y = y - coordsRowH

            if widgets.font and widgets.font.label then
                widgets.font.label:SetWidth(settingsGeo.labelW)
                if widgets.font.label.SetJustifyH then widgets.font.label:SetJustifyH("LEFT") end
            end
            local fontControlW = math.max(T.FONT_CONTROL_MIN_W, settingsGeo.dropdownW - (T.FONT_STEPPER_W + T.GRID_UNIT))
            if widgets.font and widgets.font.SetWidth then
                widgets.font:SetWidth(fontControlW)
            elseif widgets.font and widgets.font.control then
                safeSetDropWidth(widgets.font.control, fontControlW)
            end
            local fontLabelH = measureFontStringHeight(widgets.font and widgets.font.label, T.LABEL_FLOOR)
            local fontControlH = measureControlHeight(widgets.font and widgets.font.control, T.RIGHT_CONTROL_FLOOR)
            local fontSizeH = math.max(
                measureControlHeight(widgets.fontSizeStepper and widgets.fontSizeStepper.control, T.RIGHT_CONTROL_FLOOR),
                measureControlHeight(widgets.fontSizeEdit, T.RIGHT_CONTROL_FLOOR)
            )
            local fontRowH = math.max(T.SETTINGS_ROW_FLOOR, fontLabelH, fontControlH, fontSizeH)
            widgets.fontRowContainer:ClearAllPoints()
            widgets.fontRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", settingsGeo.labelX, y)
            widgets.fontRowContainer:SetSize(settingsGeo.rowW, fontRowH)
            if widgets.font and widgets.font.label then
                widgets.font.label:ClearAllPoints()
                widgets.font.label:SetPoint("LEFT", widgets.fontRowContainer, "LEFT", 0, 0)
            end
            if widgets.font and widgets.font.control then
                widgets.font.control:ClearAllPoints()
                widgets.font.control:SetPoint("LEFT", widgets.fontRowContainer, "LEFT", coordsLabelOffset, 0)
            end
            setOffscreenTopLeft(widgets.fontSizeLabel)
            if widgets.fontSizeStepper and widgets.fontSizeStepper.control then
                widgets.fontSizeStepper.control:ClearAllPoints()
                widgets.fontSizeStepper.control:SetPoint("LEFT", widgets.fontRowContainer, "LEFT", coordsLabelOffset + fontControlW + T.GRID_UNIT, 0)
                if widgets.fontSizeStepper.SetWidth then
                    widgets.fontSizeStepper:SetWidth(T.FONT_STEPPER_W)
                else
                    widgets.fontSizeStepper.control:SetWidth(T.FONT_STEPPER_W)
                end
            elseif widgets.fontSizeEdit then
                widgets.fontSizeEdit:ClearAllPoints()
                widgets.fontSizeEdit:SetPoint("LEFT", widgets.fontRowContainer, "LEFT", coordsLabelOffset + fontControlW + T.GRID_UNIT, 0)
                widgets.fontSizeEdit:SetSize(math.max(T.FONT_SIZE_FALLBACK_MIN_W, T.FONT_STEPPER_W - T.GRID_UNIT), T.RIGHT_CONTROL_FLOOR)
            end
            y = y - fontRowH

            if widgets.channel and widgets.channel.label then
                widgets.channel.label:SetWidth(settingsGeo.labelW)
                if widgets.channel.label.SetJustifyH then widgets.channel.label:SetJustifyH("LEFT") end
            end
            if widgets.channel and widgets.channel.SetWidth then
                widgets.channel:SetWidth(settingsGeo.dropdownW)
            elseif widgets.channel and widgets.channel.control then
                safeSetDropWidth(widgets.channel.control, settingsGeo.dropdownW)
            end
            local channelLabelH = measureFontStringHeight(widgets.channel and widgets.channel.label, T.LABEL_FLOOR)
            local channelControlH = measureControlHeight(widgets.channel and widgets.channel.control, T.RIGHT_CONTROL_FLOOR)
            local channelHintText = tostring(widgets.channelHint and widgets.channelHint:GetText() or "")
            local channelLabelW = math.max(0, math.ceil((widgets.channel and widgets.channel.label and widgets.channel.label.GetStringWidth and widgets.channel.label:GetStringWidth()) or 0))
            local channelHintMaxW = math.max(T.CHANNEL_HINT_MIN_W, settingsGeo.labelW - channelLabelW - T.CHANNEL_HINT_GAP)
            local channelHintH = 0
            if widgets.channelHint and widgets.channelHint:IsShown() and channelHintText ~= "" then
                setSingleLineEllipsis(widgets.channelHint, channelHintText, channelHintMaxW)
                channelHintH = measureFontStringHeight(widgets.channelHint, T.HELPER_FLOOR)
            end
            local channelRowH = math.max(T.SETTINGS_ROW_FLOOR, channelLabelH, channelControlH, channelHintH)
            widgets.channelRowContainer:ClearAllPoints()
            widgets.channelRowContainer:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", settingsGeo.labelX, y)
            widgets.channelRowContainer:SetSize(settingsGeo.rowW, channelRowH)
            if widgets.channel and widgets.channel.label then
                widgets.channel.label:ClearAllPoints()
                widgets.channel.label:SetPoint("LEFT", widgets.channelRowContainer, "LEFT", 0, 0)
            end
            if widgets.channelHint then
                widgets.channelHint:ClearAllPoints()
                widgets.channelHint:SetPoint("LEFT", widgets.channelRowContainer, "LEFT", channelLabelW + T.CHANNEL_HINT_GAP, 0)
                widgets.channelHint:SetWidth(channelHintMaxW)
            end
            if widgets.channel and widgets.channel.control then
                widgets.channel.control:ClearAllPoints()
                widgets.channel.control:SetPoint("LEFT", widgets.channelRowContainer, "LEFT", coordsLabelOffset, 0)
            end
            y = y - channelRowH

            local extentObjects = {
                header,
                widgets.masterRowContainer,
                widgets.lockRowContainer,
                widgets.lockStateHelper,
                widgets.settingsDivider,
                deathHeader,
                deathDesc,
                widgets.roleHeaderRow,
                widgets.rowTank and widgets.rowTank.container or nil,
                widgets.rowHealer and widgets.rowHealer.container or nil,
                widgets.rowDps and widgets.rowDps.container or nil,
                widgets.rowSelf and widgets.rowSelf.container or nil,
                widgets.rowTank and widgets.rowTank.roleHelper or nil,
                widgets.rowHealer and widgets.rowHealer.roleHelper or nil,
                widgets.rowDps and widgets.rowDps.roleHelper or nil,
                widgets.rowSelf and widgets.rowSelf.roleHelper or nil,
                widgets.rowTank and widgets.rowTank.onScreenHelper or nil,
                widgets.rowHealer and widgets.rowHealer.onScreenHelper or nil,
                widgets.rowDps and widgets.rowDps.onScreenHelper or nil,
                widgets.rowSelf and widgets.rowSelf.onScreenHelper or nil,
                widgets.roleMessageDivider,
                widgets.messageLeftGroup,
                widgets.messageRightGroup,
                widgets.messageHelp,
                widgets.coordsRowContainer,
                widgets.fontRowContainer,
                widgets.channelRowContainer,
            }
            local measuredExtent = measureSettingsVisibleContentExtent(scrollChild, extentObjects)
            local visibleExtent = (measuredExtent and math.ceil(measuredExtent)) or nil
            local fallbackExtent = math.abs(y)
            local used = (visibleExtent or fallbackExtent) + T.BOTTOM_PAD
            local contentHeight = math.max(scrollFrame:GetHeight(), used)
            scrollChild:SetHeight(contentHeight)
            updateScrollBehavior(scrollFrame, scrollChild)
        end
        local function commitMessageTemplate()
            if not PortalAuthorityDB then return end
            local raw = widgets.messageEdit:GetText() or ""
            local text = trim(raw)
            if text == "" then
                text = (PortalAuthority and PortalAuthority.defaults and PortalAuthority.defaults.deathAlertMessageTemplate) or "[role] Died: [name]"
            end
            PortalAuthorityDB.deathAlertMessageTemplate = text
            onApply()
        end

        widgets.messageEdit:SetScript("OnTextChanged", function(edit, userInput)
            if not userInput or not PortalAuthorityDB then
                return
            end

            local text = trim(edit:GetText() or "")
            if text == "" then
                text = (PortalAuthority and PortalAuthority.defaults and PortalAuthority.defaults.deathAlertMessageTemplate) or "[role] Died: [name]"
            end
            PortalAuthorityDB.deathAlertMessageTemplate = text

            -- Real-time preview while unlocked.
            if not PA_SafeBool(PortalAuthorityDB.deathAlertLocked) then
                onApply()
            end
        end)

        widgets.messageEdit:SetScript("OnEditFocusGained", function(edit)
            if edit.HighlightText then
                -- Prevent InputBoxTemplate select-all on focus; keep normal cursor editing.
                edit:HighlightText(0, 0)
            end
        end)

        widgets.messageEdit:SetScript("OnEnterPressed", function(edit)
            commitMessageTemplate()
            edit:ClearFocus()
        end)
        widgets.messageEdit:SetScript("OnEditFocusLost", commitMessageTemplate)

        widgets.coordsEdit:SetScript("OnMouseDown", function()
            beginCoordsEdit()
        end)
        widgets.coordsEdit:SetScript("OnEditFocusGained", function(edit)
            if not widgets._coordsEditing then
                edit:ClearFocus()
                return
            end
            if edit.HighlightText then
                edit:HighlightText()
            end
        end)
        widgets.coordsEdit:SetScript("OnEnterPressed", function(edit)
            finishCoordsEdit(true)
            edit:ClearFocus()
        end)
        widgets.coordsEdit:SetScript("OnEscapePressed", function(edit)
            finishCoordsEdit(false)
            edit:ClearFocus()
        end)
        widgets.coordsEdit:SetScript("OnEditFocusLost", function()
            finishCoordsEdit(true)
        end)

        if widgets.fontSizeEdit then
            local function commitFontSize()
                if not PortalAuthorityDB then return end
                local v = tonumber(widgets.fontSizeEdit:GetText())
                if v == nil then
                    widgets.fontSizeEdit:SetText(tostring(PortalAuthorityDB.deathAlertFontSize or 36))
                    return
                end
                v = math.floor(v)
                if v < 8 then v = 8 end
                if v > 72 then v = 72 end
                PortalAuthorityDB.deathAlertFontSize = v
                onApply()
            end

            widgets.fontSizeEdit:SetScript("OnEnterPressed", function(edit)
                commitFontSize()
                edit:ClearFocus()
            end)
            widgets.fontSizeEdit:SetScript("OnEditFocusLost", commitFontSize)
        end

        self._refresh = refresh
        self._layout = layout
        registerRefreshCallback(function()
            if shouldSuppressSettingsFirstOpenExternalRefresh(self) then
                return
            end
            if self._refresh then
                self._refresh()
            end
        end, self)
        scrollFrame:SetScript("OnSizeChanged", function()
            if handleSettingsFirstOpenSizeReady(self, "size_changed") then
                return
            end
            if shouldSuppressSettingsFirstOpenExternalRefresh(self) then
                return
            end
            if self._layout then self._layout() end
            if self._refresh then self._refresh() end
        end)
        self._settingsFirstOpenKey = "combat"
        self._settingsFirstOpenSizeTarget = scrollFrame
        self._settingsFirstOpenRender = function(panel)
            if panel._layout then
                panel._layout()
            end
            if panel._refresh then
                panel._refresh()
            end
        end
        self._settingsFirstOpenIsReady = function(panel)
            return panelHasSizedViewport(scrollFrame)
                and widgets.rowTank ~= nil and widgets.rowTank.container ~= nil and widgets.rowTank.container:IsShown()
                and widgets.rowHealer ~= nil and widgets.rowHealer.container ~= nil and widgets.rowHealer.container:IsShown()
                and widgets.messageEdit ~= nil and widgets.messageEdit:IsShown()
                and widgets.coordsEdit ~= nil and widgets.coordsEdit:IsShown()
                and (tonumber(scrollChild:GetHeight()) or 0) >= math.max(tonumber(scrollFrame:GetHeight()) or 0, 1)
        end

        if PortalAuthority then
            PortalAuthority.DeathAlerts_OnPositionChanged = function(x, y)
                if not panelRef or not panelRef:IsShown() or not widgets.coordsEdit then
                    return
                end
                if widgets._coordsEditing and widgets.coordsEdit:HasFocus() then
                    return
                end
                widgets.coordsEdit:SetText(string.format("%d, %d", math.floor(tonumber(x) or 0), math.floor(tonumber(y) or 0)))
                widgets.coordsEdit:SetTextColor(0.86, 0.86, 0.88, 1)
            end
        end

        layout()
        refresh()

        self._initialized = true
        settingsSearchRuntime.endDescriptorCapture(self)
    end

    panel:SetScript("OnShow", function(self)
        -- Ensure this canvas panel fills the Settings subcategory canvas.
        if not self._paAnchored then
            local p = self:GetParent()
            if p then
                self:ClearAllPoints()
                self:SetAllPoints(p)
                self._paAnchored = true
            end
        end

        self:EnsureBuilt()
        if not handleSettingsFirstOpenPanelShow(self) then
            withPanelHydration(self, function()
                if self._layout then self._layout() end
                if self._refresh then self._refresh() end
            end)
        end
    end)

    panel:HookScript("OnHide", function(self)
        handleSettingsFirstOpenPanelHide(self)
    end)

    return panel
end


local function createProfilesPanel()
    local panel = CreateFrame("Frame")
    panel.name = "Profiles"
    panel._paSearchSectionKey = "profiles"
    panel._paSearchSectionName = panel.name

    panel.EnsureBuilt = function(self)
        if self._initialized then return end
        self._initialized = true
        resetSettingsFirstOpenPanelState(self)
        ensureDatabase()
        settingsSearchRuntime.beginDescriptorCapture(self)

        local scrollFrame, scrollChild = createScrollableChild(self)
        if not scrollFrame or not scrollChild then
            settingsSearchRuntime.endDescriptorCapture(self)
            return
        end
        self._sizingFrame = scrollFrame
        self._profilesScrollFrame = scrollFrame
        self._profilesScrollChild = scrollChild

        -- Profiles-local frozen layout tokens. Preserve values exactly in this pass.
        local PROFILES_LAYOUT = {
            page = {
                min_content_width = 320,
                module_lane_min_width = 320,
                max_module_width = 720,
                top_padding = 20,
                bottom_padding = 52,
                header_left = 16,
                header_bottom_gap = 30,
                content_left = 20,
                content_right = 20,
                module_gap = 12,
                scroll_width_adjust = 6,
            },
            module = {
                accent_width = 2,
                padding_x = 18,
                padding_top = 16,
                padding_bottom = 12,
                title_content_gap = 16,
                helper_min_height = 16,
                helper_pref_width = 300,
                actions_helper_gap = 10,
            },
            controls = {
                min_width = 120,
                segment_width = 240,
                segment_control_height = 24,
                segment_min_width = 92,
                picker_width = 240,
                picker_height = 22,
                shared_picker_menu_height = 220,
                action_button_width = 240,
                danger_button_width = 240,
                button_height = 24,
                button_gap = 8,
                field_gap = 8,
            },
            meta = {
                row_height = 14,
                row_bottom_gap = 8,
                status_size = 6,
                prefix_to_indicator_gap = 8,
                indicator_to_name_gap = 8,
            },
            profile_selection = {
                shared_label_gap = 18,
            },
            actions = {
                status_gap = 10,
                status_min_height = 12,
            },
            danger = {
                title_gap = 18,
                trailing_gap = 2,
            },
            value_button = {
                min_label_width = 20,
                text_left_inset = 8,
                text_right_inset = 18,
                caret_right_inset = 7,
                label_trim_reserve = 26,
            },
            dialog = {
                backdrop_edge_size = 12,
                backdrop_inset = 3,
                width = 476,
                min_height = 196,
                choice_button_width = 260,
                choice_picker_width = 420,
                choice_picker_height = 320,
                confirm_button_width = 140,
                cancel_button_width = 120,
                edit_text_inset_x = 8,
                inner_left = 18,
                inner_right = 18,
                title_top = 14,
                message_top = 40,
                title_body_gap = 14,
                section_gap = 14,
                label_control_gap = 18,
                feedback_gap = 12,
                feedback_min_height = 12,
                edit_height = 22,
                actions_gap = 16,
                button_gap = 10,
                bottom_padding = 18,
                min_title_height = 16,
                min_message_height = 20,
            },
        }

        local widgets = {}
        self._profilesWidgets = widgets
        self._profilesStatusText = ""
        self._profilesStatusColor = { 0.72, 0.72, 0.76, 1 }
        widgets.sectionDescriptor = createSettingsSectionDescriptor(scrollChild, "Manage your saved profiles.")

        local function helperTone(fs, alpha)
            if not fs then return end
            fs:SetTextColor(0.72, 0.72, 0.76, alpha or 1)
        end

        local function setStatus(text, r, g, b, a)
            self._profilesStatusText = tostring(text or "")
            self._profilesStatusColor = {
                tonumber(r) or 0.72,
                tonumber(g) or 0.72,
                tonumber(b) or 0.76,
                tonumber(a) or 1,
            }
            if widgets.status then
                widgets.status:SetText(self._profilesStatusText)
                widgets.status:SetTextColor(unpack(self._profilesStatusColor))
                if self._profilesStatusText == "" then
                    widgets.status:Hide()
                else
                    widgets.status:Show()
                end
            end
            if self._layout then
                self._layout()
            end
        end

        local function createSubtleCard(parent)
            local card = CreateFrame("Frame", nil, parent, "BackdropTemplate")
            card:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
                insets = { left = 0, right = 0, top = 0, bottom = 0 },
            })
            card:SetBackdropColor(0.06, 0.07, 0.09, 0.42)
            card:SetBackdropBorderColor(0.20, 0.23, 0.29, 0.50)
            return card
        end

        local function createCard(parent, titleText, helperText, accentColor, titleColor)
            local card = createSubtleCard(parent)
            settingsSearchRuntime.markTextContainer(card)
            local accent = card:CreateTexture(nil, "BORDER")
            accent:SetTexture("Interface\\Buttons\\WHITE8x8")
            accent:SetPoint("TOPLEFT", card, "TOPLEFT", 0, 0)
            accent:SetPoint("BOTTOMLEFT", card, "BOTTOMLEFT", 0, 0)
            accent:SetWidth(PROFILES_LAYOUT.module.accent_width)
            accent:SetVertexColor(unpack(accentColor or { 0.27, 0.27, 0.27, 1 }))

            local title = createStyledFontString(card, "ARTWORK", "GameFontHighlightSmall", 10)
            title:SetJustifyH("LEFT")
            title:SetTextColor(unpack(titleColor or { 0.75, 0.77, 0.80, 1 }))
            title:SetText(string.upper(tostring(titleText or "")))

            local helper = createStyledFontString(card, "ARTWORK", "GameFontHighlightSmall", 11)
            helper:SetJustifyH("LEFT")
            helper:SetJustifyV("TOP")
            helper:SetWordWrap(true)
            helper:SetText(tostring(helperText or ""))
            helperTone(helper)

            return {
                frame = card,
                accent = accent,
                title = title,
                helper = helper,
            }
        end

        local function createValueButton(parent, width)
            local button = CreateFrame("Button", nil, parent, "BackdropTemplate")
            button:SetBackdrop({
                bgFile = "Interface\\Buttons\\WHITE8x8",
                edgeFile = "Interface\\Buttons\\WHITE8x8",
                edgeSize = 1,
                insets = { left = 0, right = 0, top = 0, bottom = 0 },
            })
            button:SetBackdropColor(0.10, 0.11, 0.14, 0.95)
            button:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
            button:SetSize(width or PROFILES_LAYOUT.controls.picker_width, PROFILES_LAYOUT.controls.picker_height)
            button:RegisterForClicks("LeftButtonUp")

            local text = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 11)
            text:SetPoint("LEFT", button, "LEFT", PROFILES_LAYOUT.value_button.text_left_inset, 0)
            text:SetPoint("RIGHT", button, "RIGHT", -PROFILES_LAYOUT.value_button.text_right_inset, 0)
            text:SetJustifyH("LEFT")
            text:SetTextColor(0.92, 0.92, 0.92, 1)
            text:SetWordWrap(false)
            if text.SetMaxLines then
                text:SetMaxLines(1)
            end

            local caret = createStyledFontString(button, "ARTWORK", "GameFontHighlightSmall", 10)
            caret:SetPoint("RIGHT", button, "RIGHT", -PROFILES_LAYOUT.value_button.caret_right_inset, 0)
            caret:SetText("v")
            caret:SetTextColor(0.76, 0.76, 0.78, 1)

            local function applyVisual(hovered)
                if hovered then
                    button:SetBackdropColor(0.16, 0.17, 0.20, 0.95)
                    button:SetBackdropBorderColor(0.30, 0.33, 0.38, 1.0)
                    caret:SetTextColor(0.88, 0.88, 0.90, 1)
                else
                    button:SetBackdropColor(0.10, 0.11, 0.14, 0.95)
                    button:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
                    caret:SetTextColor(0.76, 0.76, 0.78, 1)
                end
                if not button:IsEnabled() then
                    button:SetBackdropColor(0.08, 0.09, 0.11, 0.85)
                    button:SetBackdropBorderColor(0.18, 0.20, 0.24, 0.90)
                    text:SetTextColor(0.55, 0.55, 0.58, 1)
                    caret:SetTextColor(0.55, 0.55, 0.58, 1)
                else
                    text:SetTextColor(0.92, 0.92, 0.92, 1)
                end
            end

            function button:SetButtonLabel(labelText)
                local raw = tostring(labelText or "")
                local maxWidth = math.max(PROFILES_LAYOUT.value_button.min_label_width, (button:GetWidth() or 0) - PROFILES_LAYOUT.value_button.label_trim_reserve)
                text:SetWidth(maxWidth)
                text:SetText(raw)
                if text:GetStringWidth() <= maxWidth then
                    return
                end
                local cut = string.len(raw)
                while cut > 0 do
                    local candidate = string.sub(raw, 1, cut) .. "..."
                    text:SetText(candidate)
                    if text:GetStringWidth() <= maxWidth then
                        return
                    end
                    cut = cut - 1
                end
                text:SetText("...")
            end

            button:SetScript("OnEnter", function() applyVisual(true) end)
            button:SetScript("OnLeave", function() applyVisual(false) end)
            button:HookScript("OnShow", function() applyVisual(false) end)
            applyVisual(false)
            return button
        end

        local function skinEditBox(edit)
            if not edit then return end
            if not edit._paPremiumBg then
                edit._paPremiumBg = edit:CreateTexture(nil, "BACKGROUND")
                edit._paPremiumBg:SetAllPoints(edit)
                edit._paPremiumBg:SetTexture("Interface\\Buttons\\WHITE8x8")
                edit._paPremiumBorder = CreateFrame("Frame", nil, edit, "BackdropTemplate")
                edit._paPremiumBorder:SetPoint("TOPLEFT", edit, "TOPLEFT", -1, 1)
                edit._paPremiumBorder:SetPoint("BOTTOMRIGHT", edit, "BOTTOMRIGHT", 1, -1)
                edit._paPremiumBorder:SetBackdrop({
                    edgeFile = "Interface\\Buttons\\WHITE8x8",
                    edgeSize = 1,
                })
                edit._paPremiumBorder:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
            end

            local function applyVisual()
                if edit.Left then edit.Left:SetAlpha(0) end
                if edit.Middle then edit.Middle:SetAlpha(0) end
                if edit.Right then edit.Right:SetAlpha(0) end
                if edit:HasFocus() then
                    edit._paPremiumBg:SetVertexColor(0.12, 0.13, 0.17, 0.95)
                    edit._paPremiumBorder:SetBackdropBorderColor(0.30, 0.33, 0.38, 1.0)
                else
                    edit._paPremiumBg:SetVertexColor(0.10, 0.11, 0.14, 0.95)
                    edit._paPremiumBorder:SetBackdropBorderColor(0.24, 0.27, 0.32, 1.0)
                end
            end

            edit:HookScript("OnShow", applyVisual)
            edit:HookScript("OnEditFocusGained", applyVisual)
            edit:HookScript("OnEditFocusLost", applyVisual)
            applyVisual()
        end

