        local function layoutActiveMetadataRow(cardFrame, innerLeft, innerY, rowWidth)
            local row = widgets.activeMetaRow
            local prefix = widgets.activeMetaPrefix
            local indicator = widgets.activeMetaIndicator
            local name = widgets.activeMetaName
            local rowHeight = PROFILES_LAYOUT.meta.row_height

            row:ClearAllPoints()
            row:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", innerLeft, innerY)
            row:SetSize(rowWidth, rowHeight)

            prefix:ClearAllPoints()
            prefix:SetPoint("LEFT", row, "LEFT", 0, 0)
            local prefixWidth = math.ceil(prefix:GetStringWidth() or 0)

            indicator:ClearAllPoints()
            indicator:SetPoint("LEFT", prefix, "RIGHT", PROFILES_LAYOUT.meta.prefix_to_indicator_gap, 0)

            name:ClearAllPoints()
            name:SetPoint("LEFT", indicator, "RIGHT", PROFILES_LAYOUT.meta.indicator_to_name_gap, 0)
            local availableNameWidth = rowWidth
                - prefixWidth
                - PROFILES_LAYOUT.meta.prefix_to_indicator_gap
                - PROFILES_LAYOUT.meta.status_size
                - PROFILES_LAYOUT.meta.indicator_to_name_gap
            if availableNameWidth < 1 then
                availableNameWidth = 1
            end
            name:SetWidth(availableNameWidth)
            if type(setSingleLineEllipsis) == "function" then
                setSingleLineEllipsis(name, tostring(name:GetText() or ""), availableNameWidth)
            end

            return rowHeight
        end

