        local function openSwitchToCharacterDialog()
            if self._profilesDialog and self._profilesDialog.Open then
                self._profilesDialog:Open({
                    title = "Switch to Character Profile",
                    message = "This character will start using its own local settings. Portal Authority will reload the UI.",
                    confirmText = "Switch & Reload",
                    onConfirm = function()
                        return PortalAuthority:Profiles_SwitchToCharacterAndReload()
                    end,
                })
            end
        end

        local function openSwitchToSharedDialog()
            if self._profilesDialog and self._profilesDialog.Open then
                local sharedChoices = PortalAuthority:Profiles_GetSharedChoices()
                local pickerOptions = {}
                local defaultValue = PortalAuthority:GetProfilesCanonicalDefaultID()
                for _, choice in ipairs(sharedChoices) do
                    pickerOptions[#pickerOptions + 1] = {
                        value = choice.id,
                        label = choice.label,
                    }
                end
                self._profilesDialog:Open({
                    title = "Switch to Shared Profile",
                    message = "Choose which shared profile this character should use. Portal Authority will reload the UI.",
                    confirmText = "Switch & Reload",
                    choiceLabel = "Shared Profile",
                    choiceOptions = pickerOptions,
                    choiceValue = defaultValue,
                    onConfirm = function(_, selectedValue)
                        return PortalAuthority:Profiles_SwitchToSharedAndReload(selectedValue)
                    end,
                })
            end
        end

        local function buildModeControl(parent)
            widgets.modeControl = createPremiumSegmentedChoice(parent, "", nil, {
                { label = "Character", value = "character" },
                { label = "Shared", value = "shared" },
            }, function(value)
                local activeInfo = PortalAuthority and PortalAuthority.Profiles_GetActiveInfo and PortalAuthority:Profiles_GetActiveInfo() or nil
                if not activeInfo or value == activeInfo.kind then
                    refreshModeControlDeferred()
                    return
                end

                if value == "character" then
                    openSwitchToCharacterDialog()
                else
                    openSwitchToSharedDialog()
                end

                refreshModeControlDeferred()
            end, {
                getValue = function()
                    local activeInfo = PortalAuthority and PortalAuthority.Profiles_GetActiveInfo and PortalAuthority:Profiles_GetActiveInfo() or nil
                    return activeInfo and activeInfo.kind or "shared"
                end,
                setValue = function() end,
                minWidth = PROFILES_LAYOUT.controls.segment_width,
                controlHeight = PROFILES_LAYOUT.controls.segment_control_height,
                segmentMinWidth = PROFILES_LAYOUT.controls.segment_min_width,
                selectionVariant = "lock_meta",
            })
            if widgets.modeControl and widgets.modeControl.label then
                widgets.modeControl.label:SetText("")
                widgets.modeControl.label:Hide()
            end
        end

