            widgets.sharedPicker = createValueButton(parent, PROFILES_LAYOUT.controls.picker_width)
            widgets.sharedPickerPicker = CreatePicker(UIParent, {}, function(value, option)
                local selectedValue = trim(tostring(value or ""))
                local activeInfo = PortalAuthority:Profiles_GetActiveInfo()
                if selectedValue == "" or selectedValue == tostring(activeInfo and activeInfo.sharedID or "") then
                    return
                end
                local displayName = option and option.label or PortalAuthority:Profiles_GetSharedDisplayName(selectedValue) or "Shared Profile"
                if self._profilesDialog and self._profilesDialog.Open then
                    self._profilesDialog:Open({
                        title = "Switch Shared Profile",
                        message = string.format("Switch this character to \"%s\"? Portal Authority will reload the UI.", tostring(displayName)),
                        confirmText = "Switch & Reload",
                        onConfirm = function()
                            return PortalAuthority:Profiles_SwitchToSharedAndReload(selectedValue)
                        end,
                    })
                end
            end, {
                width = PROFILES_LAYOUT.controls.picker_width,
                height = PROFILES_LAYOUT.controls.shared_picker_menu_height,
                noSearch = true,
                hideTitle = true,
                showClearButton = false,
                showCloseButton = false,
                ellipsizeRows = true,
                footerFlowWithRows = true,
                footerHint = "Only user-facing profile names are shown here.",
            })
            widgets.sharedPicker:SetScript("OnClick", function(btn)
                if ACTIVE_PORTAL_PICKER == widgets.sharedPickerPicker and widgets.sharedPickerPicker:IsShown() then
