        dialog.edit:SetTextColor(1, 1, 1, 1)
        dialog.edit:SetHighlightColor(1, 1, 1, 0.25)
        dialog.edit:SetMaxLetters(80)
        applyGlobalFontToObject(dialog.edit, 11)
