        dialog.feedback = createStyledFontString(dialog, "ARTWORK", "GameFontHighlightSmall", 10)
        dialog.feedback:SetJustifyH("LEFT")
        dialog.feedback:SetWordWrap(true)
        dialog.feedback:SetText("")
        dialog.feedback:Hide()

        dialog.confirm = createActionButtonStyled(dialog, "Confirm", PROFILES_LAYOUT.dialog.confirm_button_width)
        dialog.cancel = createActionButtonStyled(dialog, "Cancel", PROFILES_LAYOUT.dialog.cancel_button_width)

        dialog.choicePicker = CreatePicker(UIParent, {}, function(value, option)
            dialog._selectedChoiceValue = value
            dialog._selectedChoiceLabel = option and option.label or ""
            dialog.choiceButton:SetButtonLabel(dialog._selectedChoiceLabel ~= "" and dialog._selectedChoiceLabel or "Select profile")
            dialog.feedback:Hide()
            if dialog._layout then
                dialog._layout()
            end
        end, {
            title = "Choose Profile",
            searchHint = "Search profiles",
            width = PROFILES_LAYOUT.dialog.choice_picker_width,
            height = PROFILES_LAYOUT.dialog.choice_picker_height,
            footerHint = "Only user-facing profile names are shown here.",
        })

        function dialog:Close()
            if self.choicePicker and self.choicePicker.Close then
                self.choicePicker:Close()
            end
            self._onConfirm = nil
            self._selectedChoiceValue = nil
            self._selectedChoiceLabel = ""
            self.feedback:SetText("")
            self.feedback:Hide()
            self:Hide()
        end

        function dialog:Open(spec)
            spec = type(spec) == "table" and spec or {}
            self._onConfirm = spec.onConfirm
            self._selectedChoiceValue = spec.choiceValue
            self._selectedChoiceLabel = spec.choiceLabelText or ""
            self.title:SetText(tostring(spec.title or "Profiles"))
            self.message:SetText(tostring(spec.message or ""))
            self.confirm:SetText(tostring(spec.confirmText or "Confirm"))
            self.cancel:SetText(tostring(spec.cancelText or "Cancel"))
            if self.confirm.Text then applyGlobalFontToObject(self.confirm.Text, 11) end
            if self.cancel.Text then applyGlobalFontToObject(self.cancel.Text, 11) end

            self._hasChoice = spec.choiceOptions ~= nil
            self._hasEdit = spec.editLabel ~= nil

            if self._hasChoice then
                self.choiceLabel:SetText(tostring(spec.choiceLabel or "Profile"))
                self.choiceLabel:Show()
                self.choiceButton:Show()
                self.choicePicker:SetOptions(type(spec.choiceOptions) == "table" and spec.choiceOptions or {})
                local labelText = tostring(spec.choiceLabelText or "")
                if labelText == "" and spec.choiceValue ~= nil then
                    for _, option in ipairs(spec.choiceOptions or {}) do
                        if option.value == spec.choiceValue then
                            labelText = tostring(option.label or "")
                            break
                        end
                    end
                end
                if labelText == "" then
                    labelText = "Select profile"
                end
                self.choiceButton:SetButtonLabel(labelText)
                self.choiceButton:SetScript("OnClick", function(btn)
                    self.choicePicker:Open(btn)
                end)
            else
                self.choiceLabel:Hide()
                self.choiceButton:Hide()
            end

            if self._hasEdit then
                self.editLabel:SetText(tostring(spec.editLabel or "Name"))
                self.editLabel:Show()
                self.edit:Show()
                self.edit:SetText(tostring(spec.editValue or ""))
                self.edit:SetCursorPosition(string.len(self.edit:GetText() or ""))
                self.edit:SetMaxLetters(math.max(1, tonumber(spec.editMaxLetters) or 80))
            else
                self.editLabel:Hide()
                self.edit:Hide()
                self.edit:SetText("")
            end

            self.feedback:SetText("")
            self.feedback:Hide()
            self:Show()
            if self._hasEdit then
                self.edit:SetFocus()
                self.edit:HighlightText(0, string.len(self.edit:GetText() or ""))
            else
                self.edit:ClearFocus()
            end
            if self._layout then
                self._layout()
            end
        end

        local function layoutDialogChoiceSection(innerLeft, y)
            if not dialog._hasChoice then
                return y
            end
            y = y - PROFILES_LAYOUT.dialog.section_gap
            dialog.choiceLabel:ClearAllPoints()
            dialog.choiceLabel:SetPoint("TOPLEFT", dialog, "TOPLEFT", innerLeft, y)
            y = y - PROFILES_LAYOUT.dialog.label_control_gap
            dialog.choiceButton:ClearAllPoints()
            dialog.choiceButton:SetPoint("TOPLEFT", dialog, "TOPLEFT", innerLeft, y)
            return y - PROFILES_LAYOUT.controls.picker_height
        end

        local function layoutDialogEditSection(innerLeft, width, y)
            if not dialog._hasEdit then
                return y
            end
            y = y - PROFILES_LAYOUT.dialog.section_gap
            dialog.editLabel:ClearAllPoints()
            dialog.editLabel:SetPoint("TOPLEFT", dialog, "TOPLEFT", innerLeft, y)
            y = y - PROFILES_LAYOUT.dialog.label_control_gap
            dialog.edit:ClearAllPoints()
            dialog.edit:SetPoint("TOPLEFT", dialog, "TOPLEFT", innerLeft, y)
            dialog.edit:SetWidth(width)
            dialog.edit:SetHeight(PROFILES_LAYOUT.dialog.edit_height)
            return y - PROFILES_LAYOUT.dialog.edit_height
        end

        local function layoutDialogFeedbackSection(innerLeft, innerRight, y)
            local feedbackText = trim(dialog.feedback:GetText() or "")
            if not dialog.feedback:IsShown() or feedbackText == "" then
                return y
            end
            y = y - PROFILES_LAYOUT.dialog.feedback_gap
            dialog.feedback:ClearAllPoints()
            dialog.feedback:SetPoint("TOPLEFT", dialog, "TOPLEFT", innerLeft, y)
            dialog.feedback:SetPoint("TOPRIGHT", dialog, "TOPRIGHT", -innerRight, y)
            return y - math.max(PROFILES_LAYOUT.dialog.feedback_min_height, dialog.feedback:GetStringHeight())
        end

        dialog._layout = function()
            local innerLeft = PROFILES_LAYOUT.dialog.inner_left
            local innerRight = PROFILES_LAYOUT.dialog.inner_right
            local topPad = PROFILES_LAYOUT.dialog.title_top
            local titleGap = PROFILES_LAYOUT.dialog.title_body_gap
            local actionsGap = PROFILES_LAYOUT.dialog.actions_gap
            local bottomPad = PROFILES_LAYOUT.dialog.bottom_padding
            local minHeight = PROFILES_LAYOUT.dialog.min_height
            local width = (dialog:GetWidth() or PROFILES_LAYOUT.dialog.width) - innerLeft - innerRight
            local titleH = math.max(PROFILES_LAYOUT.dialog.min_title_height, dialog.title:GetStringHeight() or 0)
            local y = -(topPad + titleH + titleGap)

            dialog.message:ClearAllPoints()
            dialog.message:SetPoint("TOPLEFT", dialog, "TOPLEFT", innerLeft, y)
            dialog.message:SetWidth(width)
            local messageH = math.max(PROFILES_LAYOUT.dialog.min_message_height, dialog.message:GetStringHeight())
            y = y - messageH
            y = layoutDialogChoiceSection(innerLeft, y)
            y = layoutDialogEditSection(innerLeft, width, y)
            y = layoutDialogFeedbackSection(innerLeft, innerRight, y)

            local buttonRowH = math.max(
                dialog.confirm:GetHeight() or PROFILES_LAYOUT.controls.button_height,
                dialog.cancel:GetHeight() or PROFILES_LAYOUT.controls.button_height
            )
            local totalHeight = math.max(minHeight, (-y) + actionsGap + buttonRowH + bottomPad)
            dialog:SetHeight(totalHeight)

            dialog.cancel:ClearAllPoints()
            dialog.cancel:SetPoint("BOTTOMRIGHT", dialog, "BOTTOMRIGHT", -innerRight, bottomPad)
            dialog.confirm:ClearAllPoints()
            dialog.confirm:SetPoint("RIGHT", dialog.cancel, "LEFT", -PROFILES_LAYOUT.dialog.button_gap, 0)
        end

        local function wireDialogControls()
            dialog.confirm:SetScript("OnClick", function()
                local rawEditValue = dialog._hasEdit and dialog.edit:GetText() or nil
                local selectedValue = dialog._hasChoice and dialog._selectedChoiceValue or nil
                local ok, err = true, nil
                if dialog._hasChoice and (selectedValue == nil or tostring(selectedValue) == "") then
                    ok, err = false, "Select a profile first."
                elseif dialog._onConfirm then
                    ok, err = dialog._onConfirm(rawEditValue, selectedValue)
                end
                if ok == false then
                    dialog.feedback:SetText(tostring(err or "Profile operation failed."))
                    dialog.feedback:SetTextColor(1.0, 0.36, 0.36, 1)
                    dialog.feedback:Show()
                    if dialog._layout then
                        dialog._layout()
                    end
                    refreshModeControlDeferred()
                    return
                end
                dialog:Close()
                if refreshAndLayoutProfiles then
                    refreshAndLayoutProfiles()
                end
            end)
            dialog.cancel:SetScript("OnClick", function()
                dialog:Close()
                refreshModeControlDeferred()
            end)
            dialog.edit:SetScript("OnEscapePressed", function() dialog.cancel:Click() end)
            dialog.edit:SetScript("OnEnterPressed", function() dialog.confirm:Click() end)
        end

        wireDialogControls()

        local function wireActionButtons()
            widgets.createSharedButton:SetScript("OnClick", function()
                dialog:Open({
                    title = "Create Shared Profile",
                    message = "Save the current runtime settings as a new shared profile. Portal Authority will reload the UI.",
                    confirmText = "Create & Reload",
                    editLabel = "Shared Profile Name",
                    editValue = "",
                    editMaxLetters = 80,
                    onConfirm = function(rawName)
                        return PortalAuthority:Profiles_CreateSharedAndSwitch(rawName)
                    end,
                })
            end)

            widgets.copyFromButton:SetScript("OnClick", function()
                local copyChoices = PortalAuthority:Profiles_GetCopySourceChoices()
                if not copyChoices or #copyChoices == 0 then
                    setStatus("No other profile is available to copy from.", 1.0, 0.36, 0.36, 1)
                    return
                end
                local pickerOptions = {}
                local defaultValue = nil
                for index, choice in ipairs(copyChoices) do
                    local encoded = string.format("%s:%s", tostring(choice.kind or ""), tostring(choice.id or ""))
                    pickerOptions[#pickerOptions + 1] = {
                        value = encoded,
                        label = choice.label,
                    }
                    if index == 1 then
                        defaultValue = encoded
                    end
                end
                dialog:Open({
                    title = "Copy From Another Profile",
                    message = "Copy another profile into the current active profile. Portal Authority will reload the UI.",
                    confirmText = "Copy & Reload",
                    choiceLabel = "Source Profile",
                    choiceOptions = pickerOptions,
                    choiceValue = defaultValue,
                    onConfirm = function(_, encodedValue)
                        local kind, id = tostring(encodedValue or ""):match("^(.-):(.*)$")
                        if kind ~= "shared" and kind ~= "character" then
                            return false, "Source profile is unavailable."
                        end
                        if kind == "character" then
                            id = nil
                        end
                        return PortalAuthority:Profiles_CopyIntoActiveAndReload(kind, id)
                    end,
                })
            end)

            widgets.resetProfileButton:SetScript("OnClick", function()
                local activeInfo = PortalAuthority:Profiles_GetActiveInfo()
                local message = "Reset the current profile to defaults? Portal Authority will reload the UI."
                if activeInfo and activeInfo.isShared then
                    message = "Reset this shared profile to defaults? This affects every character using it, and Portal Authority will reload the UI."
                end
                dialog:Open({
                    title = "Reset Current Profile",
                    message = message,
                    confirmText = "Reset & Reload",
                    onConfirm = function()
                        return PortalAuthority:Profiles_ResetActiveAndReload()
                    end,
                })
            end)

            widgets.renameSharedButton:SetScript("OnClick", function()
                local activeInfo = PortalAuthority:Profiles_GetActiveInfo()
                if not activeInfo or not activeInfo.canRenameShared then
                    return
                end
                dialog:Open({
                    title = "Rename Shared Profile",
                    message = "Update the display name for this shared profile.",
                    confirmText = "Rename",
                    editLabel = "Shared Profile Name",
                    editValue = activeInfo.displayName or "",
                    editMaxLetters = 80,
                    onConfirm = function(rawName)
                        local ok, err = PortalAuthority:Profiles_RenameShared(activeInfo.sharedID, rawName)
                        if ok == false then
                            return false, err
                        end
                        setStatus("Shared profile renamed.", 0.66, 0.86, 0.70, 1)
                        return true
                    end,
                })
            end)

            widgets.deleteSharedButton:SetScript("OnClick", function()
                local activeInfo = PortalAuthority:Profiles_GetActiveInfo()
                if not activeInfo or not activeInfo.canDeleteShared then
                    return
                end
                dialog:Open({
                    title = "Delete Shared Profile",
                    message = string.format("Delete \"%s\"? This character will fall back to Default and Portal Authority will reload the UI.", tostring(activeInfo.displayName or "Shared Profile")),
                    confirmText = "Delete & Reload",
                    onConfirm = function()
                        return PortalAuthority:Profiles_DeleteShared(activeInfo.sharedID)
                    end,
                })
            end)
        end

        wireActionButtons()

        local function refreshSharedPicker(activeInfo)
            if activeInfo.isShared then
                widgets.sharedPickerLabel:Show()
                widgets.sharedPicker:Show()
                widgets.sharedPicker:SetButtonLabel(tostring(activeInfo.displayName or "Default"))
                if widgets.sharedPickerPicker and widgets.sharedPickerPicker.SetSelectedValue then
                    widgets.sharedPickerPicker:SetSelectedValue(activeInfo.sharedID)
                end
            else
                widgets.sharedPickerLabel:Hide()
                widgets.sharedPicker:Hide()
                if ACTIVE_PORTAL_PICKER == widgets.sharedPickerPicker and widgets.sharedPickerPicker and widgets.sharedPickerPicker.Close then
                    widgets.sharedPickerPicker:Close()
                end
            end
        end

        local function refreshProfileSelection(activeInfo)
            updateActiveMetadataRow(activeInfo)
            if activeInfo.isShared then
                widgets.currentCardHelper:SetText("Used by any character assigned to this shared profile.")
            else
                widgets.currentCardHelper:SetText("Stored only for this character.")
            end
            widgets.currentCardHelper:Show()
            refreshSharedPicker(activeInfo)
        end

        local function refreshActionsModule()
            if widgets.actionsCardHelper then
                widgets.actionsCardHelper:SetText("All changes require a UI reload to take effect.")
                widgets.actionsCardHelper:Show()
            end
            if widgets.status then
                widgets.status:SetText(self._profilesStatusText)
                widgets.status:SetTextColor(unpack(self._profilesStatusColor))
                if self._profilesStatusText == "" then
                    widgets.status:Hide()
                else
                    widgets.status:Show()
                end
            end
        end

        local function refreshDangerModule(activeInfo)
            if activeInfo.canDeleteShared then
                widgets.dangerCard:Show()
            else
                widgets.dangerCard:Hide()
            end
            if widgets.dangerCardHelper then
                widgets.dangerCardHelper:SetText("")
                widgets.dangerCardHelper:Hide()
            end
        end

        refreshProfilesBindings = function(activeInfo)
            activeInfo = activeInfo or (PortalAuthority and PortalAuthority.Profiles_GetActiveInfo and PortalAuthority:Profiles_GetActiveInfo() or nil)
            if not activeInfo then
                return nil
            end
            refreshProfileSelection(activeInfo)
            if widgets.modeControl and widgets.modeControl.Refresh then
                widgets.modeControl:Refresh()
            end
            refreshDangerModule(activeInfo)
            refreshActionsModule()
            return activeInfo
        end

        local function ensureProfilesHeader()
            local header = widgets.header
            if not header then
                header = createStyledFontString(scrollChild, "ARTWORK", "GameFontNormalLarge", 14)
                header:SetText("|cffffd100Profiles|r")
                header:SetJustifyH("LEFT")
                widgets.header = header
            end
            return header
        end

        local function computeHelperWidth(innerWidth, controlW)
            return math.max(1, math.min(innerWidth, math.max(controlW, PROFILES_LAYOUT.module.helper_pref_width)))
        end

        local function layoutSharedPickerSection(cardFrame, innerLeft, innerY, controlW, currentInfo)
            if currentInfo and currentInfo.isShared then
                widgets.sharedPickerLabel:ClearAllPoints()
                widgets.sharedPickerLabel:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", innerLeft, innerY)
                widgets.sharedPickerLabel:SetWidth(controlW)
                innerY = innerY - PROFILES_LAYOUT.profile_selection.shared_label_gap
                widgets.sharedPicker:ClearAllPoints()
                widgets.sharedPicker:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", innerLeft, innerY)
                widgets.sharedPicker:SetWidth(controlW)
                widgets.sharedPicker:SetButtonLabel(tostring(currentInfo.displayName or "Default"))
                innerY = innerY - PROFILES_LAYOUT.controls.picker_height - PROFILES_LAYOUT.controls.field_gap
            end
            return innerY
        end

        local function layoutProfileSelectionModule(cardX, cardY, cardW, currentInfo)
            local cardFrame = widgets.currentCard
            local title = widgets.currentCardTitle
            local helper = widgets.currentCardHelper
            local controlW = math.min(
                PROFILES_LAYOUT.controls.segment_width,
                math.max(PROFILES_LAYOUT.controls.min_width, cardW - (PROFILES_LAYOUT.module.padding_x * 2))
            )
            local innerLeft = PROFILES_LAYOUT.module.padding_x
            local innerWidth = cardW - (PROFILES_LAYOUT.module.padding_x * 2)
            local innerY = -PROFILES_LAYOUT.module.padding_top

            cardFrame:ClearAllPoints()
            cardFrame:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", cardX, cardY)
            cardFrame:SetWidth(cardW)

            title:ClearAllPoints()
            title:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", innerLeft, innerY)
            innerY = innerY - PROFILES_LAYOUT.module.title_content_gap

            local metaH = layoutActiveMetadataRow(cardFrame, innerLeft, innerY, math.min(innerWidth, controlW))
            innerY = innerY - metaH - PROFILES_LAYOUT.meta.row_bottom_gap

            widgets.modeControl.control:ClearAllPoints()
            widgets.modeControl.control:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", innerLeft, innerY)
            widgets.modeControl:Layout(controlW)
            innerY = innerY - PROFILES_LAYOUT.controls.segment_control_height - PROFILES_LAYOUT.controls.field_gap

            innerY = layoutSharedPickerSection(cardFrame, innerLeft, innerY, controlW, currentInfo)

            local helperText = trim(helper:GetText() or "")
            if helperText ~= "" then
                local helperW = computeHelperWidth(innerWidth, controlW)
                helper:Show()
                helper:ClearAllPoints()
                helper:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", innerLeft, innerY)
                helper:SetWidth(helperW)
                innerY = innerY - math.max(PROFILES_LAYOUT.module.helper_min_height, helper:GetStringHeight())
            else
                helper:Hide()
            end

            local cardH = (-innerY) + PROFILES_LAYOUT.module.padding_bottom
            cardFrame:SetHeight(cardH)
            return cardH
        end

        local function layoutActionsModule(cardX, cardY, cardW)
            local cardFrame = widgets.actionsCard
            local title = widgets.actionsCardTitle
            local helper = widgets.actionsCardHelper
            local controlW = math.min(
                PROFILES_LAYOUT.controls.action_button_width,
                math.max(PROFILES_LAYOUT.controls.min_width, cardW - (PROFILES_LAYOUT.module.padding_x * 2))
            )
            local innerLeft = PROFILES_LAYOUT.module.padding_x
            local innerY = -PROFILES_LAYOUT.module.padding_top

            cardFrame:ClearAllPoints()
            cardFrame:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", cardX, cardY)
            cardFrame:SetWidth(cardW)

            title:ClearAllPoints()
            title:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", innerLeft, innerY)
            innerY = innerY - PROFILES_LAYOUT.module.title_content_gap

            helper:Show()
            helper:ClearAllPoints()
            helper:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", innerLeft, innerY)
            helper:SetWidth(computeHelperWidth(cardW - (PROFILES_LAYOUT.module.padding_x * 2), controlW))
            innerY = innerY - math.max(PROFILES_LAYOUT.module.helper_min_height, helper:GetStringHeight()) - PROFILES_LAYOUT.module.actions_helper_gap

            widgets.createSharedButton:ClearAllPoints()
            widgets.createSharedButton:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", innerLeft, innerY)
            widgets.createSharedButton:SetWidth(controlW)
            innerY = innerY - PROFILES_LAYOUT.controls.button_height - PROFILES_LAYOUT.controls.button_gap

            widgets.copyFromButton:ClearAllPoints()
            widgets.copyFromButton:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", innerLeft, innerY)
            widgets.copyFromButton:SetWidth(controlW)
            innerY = innerY - PROFILES_LAYOUT.controls.button_height - PROFILES_LAYOUT.controls.button_gap

            widgets.resetProfileButton:ClearAllPoints()
            widgets.resetProfileButton:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", innerLeft, innerY)
            widgets.resetProfileButton:SetWidth(controlW)
            innerY = innerY - PROFILES_LAYOUT.controls.button_height - PROFILES_LAYOUT.actions.status_gap

            widgets.status:ClearAllPoints()
            widgets.status:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", innerLeft, innerY)
            widgets.status:SetWidth(controlW)
            if widgets.status:IsShown() then
                innerY = innerY - math.max(PROFILES_LAYOUT.actions.status_min_height, widgets.status:GetStringHeight())
            end

            local cardH = (-innerY) + PROFILES_LAYOUT.module.padding_bottom
            cardFrame:SetHeight(cardH)
            return cardH
        end

        local function layoutDangerModule(cardX, cardY, cardW, controlX)
            local cardFrame = widgets.dangerCard
            local title = widgets.dangerCardTitle
            local controlW = PROFILES_LAYOUT.controls.danger_button_width
            local innerLeft = PROFILES_LAYOUT.module.padding_x
            local innerY = -PROFILES_LAYOUT.module.padding_top

            cardFrame:ClearAllPoints()
            cardFrame:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", cardX, cardY)
            cardFrame:SetWidth(cardW)

            title:ClearAllPoints()
            title:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", innerLeft, innerY)
            innerY = innerY - PROFILES_LAYOUT.danger.title_gap

            widgets.renameSharedButton:ClearAllPoints()
            widgets.renameSharedButton:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", controlX, innerY)
            widgets.renameSharedButton:SetWidth(controlW)
            innerY = innerY - PROFILES_LAYOUT.controls.button_height - PROFILES_LAYOUT.controls.button_gap

            widgets.deleteSharedButton:ClearAllPoints()
            widgets.deleteSharedButton:SetPoint("TOPLEFT", cardFrame, "TOPLEFT", controlX, innerY)
            widgets.deleteSharedButton:SetWidth(controlW)
            innerY = innerY - PROFILES_LAYOUT.controls.button_height - PROFILES_LAYOUT.danger.trailing_gap

            local cardH = (-innerY) + PROFILES_LAYOUT.module.padding_bottom
            cardFrame:SetHeight(cardH)
            return cardH
        end

        layoutProfiles = function(currentInfo)
            currentInfo = currentInfo or (PortalAuthority and PortalAuthority.Profiles_GetActiveInfo and PortalAuthority:Profiles_GetActiveInfo() or nil)
            local scrollW = (scrollFrame:GetWidth() or 0)
            local contentW = math.max(PROFILES_LAYOUT.page.min_content_width, scrollW - PROFILES_LAYOUT.page.scroll_width_adjust)
            local useHostedChrome = isPanelUsingCustomSettingsWindowHost(self)
            scrollChild:SetWidth(contentW)

            local headerWidth = math.max(1, contentW - PROFILES_LAYOUT.page.header_left - PROFILES_LAYOUT.page.content_right)
            local left = PROFILES_LAYOUT.page.content_left
            local right = PROFILES_LAYOUT.page.content_right
            local sectionSpan = math.max(PROFILES_LAYOUT.page.module_lane_min_width, contentW - left - right)
            local y = -PROFILES_LAYOUT.page.top_padding
            if useHostedChrome then
                y = y - SETTINGS_WINDOW_HOSTED_TOP_RHYTHM_NUDGE
            end

            local header = ensureProfilesHeader()
            if useHostedChrome then
                setSettingsWindowChromeVisible(header, false, scrollChild)
                setSettingsWindowChromeVisible(widgets.sectionDescriptor, false, scrollChild)
            else
                setSettingsWindowChromeVisible(header, true)
                setSettingsWindowChromeVisible(widgets.sectionDescriptor, true, scrollChild)
                header:ClearAllPoints()
                header:SetPoint("TOPLEFT", scrollChild, "TOPLEFT", PROFILES_LAYOUT.page.header_left, y)
                header:SetWidth(headerWidth)
                y = y - math.min(PROFILES_LAYOUT.page.header_bottom_gap, 14)
                y = layoutSettingsSectionDescriptor(
                    widgets.sectionDescriptor,
                    scrollChild,
                    PROFILES_LAYOUT.page.header_left,
                    y,
                    headerWidth
                )
            end

            local cardW = math.min(sectionSpan, PROFILES_LAYOUT.page.max_module_width)
            local currentHeight = layoutProfileSelectionModule(left, y, cardW, currentInfo)
            y = y - currentHeight - PROFILES_LAYOUT.page.module_gap

            local actionsHeight = layoutActionsModule(left, y, cardW)
            y = y - actionsHeight - PROFILES_LAYOUT.page.module_gap

            if widgets.dangerCard:IsShown() then
                layoutDangerModule(left, y, cardW, PROFILES_LAYOUT.module.padding_x)
                y = y - widgets.dangerCard:GetHeight() - PROFILES_LAYOUT.page.module_gap
            end

            scrollChild:SetHeight(math.max(1, -y + PROFILES_LAYOUT.page.bottom_padding))
            updateScrollBehavior(scrollFrame, scrollChild)
        end

        refreshAndLayoutProfiles = function()
            local activeInfo = refreshProfilesBindings()
            if not activeInfo then
                return
            end
            layoutProfiles(activeInfo)
        end

        self._refresh = function()
            local perfStart, perfState = PA_PerfBegin("profiles_refresh")
            local activeInfo = refreshProfilesBindings()
            PA_PerfEnd("profiles_refresh", perfStart, perfState)
            return activeInfo
        end

        self._layout = function(activeInfo)
            local perfStart, perfState = PA_PerfBegin("profiles_layout")
            local result = layoutProfiles(activeInfo)
            PA_PerfEnd("profiles_layout", perfStart, perfState)
            return result
        end

        registerRefreshCallback(function()
            if shouldSuppressSettingsFirstOpenExternalRefresh(self) then
                return
            end
            if not self then
                return
            end
            if self.IsShown and self:IsShown() then
                if refreshAndLayoutProfiles then
                    refreshAndLayoutProfiles()
                end
            elseif self._refresh then
                self._refresh()
            end
        end, self)
        scrollFrame:SetScript("OnSizeChanged", function()
            if handleSettingsFirstOpenSizeReady(self, "size_changed") then
                return
            end
            if shouldSuppressSettingsFirstOpenExternalRefresh(self) then
                return
            end
            if self._layout then self._layout() end
        end)
        self._settingsFirstOpenKey = "profiles"
        self._settingsFirstOpenSizeTarget = scrollFrame
        self._settingsFirstOpenRender = function(panel)
            if panel._refresh and panel._layout then
                local activeInfo = panel._refresh()
                panel._layout(activeInfo)
            elseif panel._layout then
                panel._layout()
            elseif panel._refresh then
                panel._refresh()
            end
        end
        self._settingsFirstOpenIsReady = function(panel)
            return panelHasSizedViewport(scrollFrame)
                and widgets.currentCard ~= nil and widgets.currentCard:IsShown()
                and widgets.actionsCard ~= nil and widgets.actionsCard:IsShown()
                and widgets.modeControl ~= nil and widgets.modeControl.control ~= nil and widgets.modeControl.control:IsShown()
                and (tonumber(scrollChild:GetHeight()) or 0) >= 1
        end
        settingsSearchRuntime.endDescriptorCapture(self)
    end

    panel:SetScript("OnShow", function(self)
        if not self._paAnchored then
            local p = self:GetParent()
            if p then
                self:ClearAllPoints()
                self:SetAllPoints(p)
                self._paAnchored = true
            end
        end

        self:EnsureBuilt()
        if not handleSettingsFirstOpenPanelShow(self) then
            withPanelHydration(self, function()
                if self._refresh and self._layout then
                    local activeInfo = self._refresh()
                    self._layout(activeInfo)
                elseif self._layout then
                    self._layout()
                elseif self._refresh then
                    self._refresh()
                end
            end)
        end
    end)

    panel:HookScript("OnHide", function(self)
        handleSettingsFirstOpenPanelHide(self)
        if self and self._profilesWidgets and self._profilesWidgets.sharedPickerPicker and self._profilesWidgets.sharedPickerPicker.Close then
            self._profilesWidgets.sharedPickerPicker:Close()
        end
        if self and self._profilesDialog and self._profilesDialog.Close then
            self._profilesDialog:Close()
        end
    end)

    return panel
end

local function getPortalAuthorityLandingVersionText()
    local version = nil
    if PortalAuthority and type(PortalAuthority.GetAnnouncementReleaseVersionString) == "function" then
        version = PortalAuthority:GetAnnouncementReleaseVersionString()
    end
    if (type(version) ~= "string" or trim(version) == "") and C_AddOns and C_AddOns.GetAddOnMetadata then
        version = C_AddOns.GetAddOnMetadata("PortalAuthority", "Version")
    end
    if (type(version) ~= "string" or trim(version) == "") and GetAddOnMetadata then
        version = GetAddOnMetadata("PortalAuthority", "Version")
    end

    version = trim(tostring(version or ""))
    if version == "" then
        version = "1.0.0"
    end
    if not version:match("^[vV]") then
        version = "v" .. version
    end
    return version
end

local function createPortalAuthorityLandingDivider(parent, width)
    local divider = parent:CreateTexture(nil, "ARTWORK")
    divider:SetTexture("Interface\\Buttons\\WHITE8x8")
    divider:SetVertexColor(0.27, 0.27, 0.27, 0.60)
    divider:SetSize(width or 40, 1)
    return divider
end

local function configurePortalAuthorityLandingFontString(fontString, size, flags, justifyH)
    if not fontString then
        return nil
    end
    fontString._paLandingFontSize = size
    fontString._paLandingFontFlags = flags
    applyGlobalFontToObject(fontString, size, flags)
    fontString:SetJustifyH(justifyH or "CENTER")
    fontString:SetJustifyV("MIDDLE")
    if fontString.SetWordWrap then
        fontString:SetWordWrap(false)
    end
    if fontString.SetNonSpaceWrap then
        fontString:SetNonSpaceWrap(false)
    end
    if fontString.SetMaxLines then
        fontString:SetMaxLines(1)
    end
    return fontString
end

local function createPortalAuthorityLandingStyledFontString(parent, layer, template, size, justifyH)
    local fontString = createStyledFontString(parent, layer, template, size)
    return configurePortalAuthorityLandingFontString(fontString, size, nil, justifyH)
end

local function createPortalAuthorityLandingRawFontString(parent, layer, template, size, flags, justifyH)
    local fontString = parent:CreateFontString(nil, layer, template)
    return configurePortalAuthorityLandingFontString(fontString, size, flags, justifyH)
end

local function refreshPortalAuthorityLandingFontString(fontString)
    if not fontString or not fontString._paLandingFontSize then
        return
    end
    applyGlobalFontToObject(fontString, fontString._paLandingFontSize, fontString._paLandingFontFlags)
end

local function isOnboardingD3GateEnabled()
    return PortalAuthority
        and PortalAuthority.IsOnboardingD3DevGateEnabled
        and PortalAuthority:IsOnboardingD3DevGateEnabled()
end

local function applyPremiumAuthoredFontToObject(object, size, flags)
    if PortalAuthority and PortalAuthority.ApplyPremiumAuthoredFont then
        PortalAuthority:ApplyPremiumAuthoredFont(object, size, flags)
        return
    end
    if object and object.SetFont then
        object:SetFont("Fonts\\FRIZQT__.TTF", size or select(2, object:GetFont()) or 12, flags or "")
    end
end

local function configurePortalAuthorityPremiumFontString(fontString, size, flags, justifyH)
    if not fontString then
        return nil
    end
    fontString._paPremiumLandingFontSize = size
    fontString._paPremiumLandingFontFlags = flags
    applyPremiumAuthoredFontToObject(fontString, size, flags)
    fontString:SetJustifyH(justifyH or "CENTER")
    fontString:SetJustifyV("MIDDLE")
    if fontString.SetWordWrap then
        fontString:SetWordWrap(false)
    end
    if fontString.SetNonSpaceWrap then
        fontString:SetNonSpaceWrap(false)
    end
    if fontString.SetMaxLines then
        fontString:SetMaxLines(1)
    end
    return fontString
end

local function createPortalAuthorityPremiumStyledFontString(parent, layer, template, size, justifyH)
    local fontString = createStyledFontString(parent, layer, template, size)
    return configurePortalAuthorityPremiumFontString(fontString, size, nil, justifyH)
end

local function createPortalAuthorityPremiumRawFontString(parent, layer, template, size, flags, justifyH)
    local fontString = parent:CreateFontString(nil, layer, template)
    return configurePortalAuthorityPremiumFontString(fontString, size, flags, justifyH)
end

local function refreshPortalAuthorityPremiumFontString(fontString)
    if not fontString or not fontString._paPremiumLandingFontSize then
        return
    end
    applyPremiumAuthoredFontToObject(fontString, fontString._paPremiumLandingFontSize, fontString._paPremiumLandingFontFlags)
end

local function printPortalAuthorityCompatMessage(message)
    message = trim(tostring(message or ""))
    if message == "" then
        return
    end
    print("|cffE88BC7Portal Authority:|r " .. message)
end

local function createPortalAuthorityCompatStubButton(parent, label)
    local button = CreateFrame("Button", nil, parent, "BackdropTemplate")
    button:SetBackdrop({
        bgFile = "Interface\\Buttons\\WHITE8x8",
        edgeFile = "Interface\\Buttons\\WHITE8x8",
        edgeSize = 1,
        insets = { left = 0, right = 0, top = 0, bottom = 0 },
    })

    local text = button:CreateFontString(nil, "ARTWORK", "GameFontHighlight")
    applyPremiumAuthoredFontToObject(text, 12, "")
    text:SetPoint("CENTER")
    text:SetText(label or "Open Settings")
    text:SetTextColor(0.98, 0.96, 0.88, 1.0)
    text:SetShadowOffset(0, -1)
    text:SetShadowColor(0, 0, 0, 0.35)

    button._text = text

    local function setVisual(state)
        local bgR, bgG, bgB, bgA = 0.11, 0.09, 0.06, 0.97
        local borderR, borderG, borderB, borderA = 0.74, 0.60, 0.24, 0.92
        local textR, textG, textB = 0.99, 0.97, 0.90

        if state == "hover" then
            bgR, bgG, bgB = 0.16, 0.12, 0.07
            borderR, borderG, borderB = 0.90, 0.74, 0.32
            textR, textG, textB = 1.0, 0.98, 0.94
        elseif state == "down" then
            bgR, bgG, bgB = 0.09, 0.07, 0.05
            borderR, borderG, borderB = 0.68, 0.52, 0.18
            textR, textG, textB = 0.96, 0.94, 0.86
        end

        button:SetBackdropColor(bgR, bgG, bgB, bgA)
        button:SetBackdropBorderColor(borderR, borderG, borderB, borderA)
        text:SetTextColor(textR, textG, textB, 1.0)
    end

    button:SetSize(164, 36)
    setVisual("idle")

    button:SetScript("OnEnter", function()
        setVisual("hover")
    end)
    button:SetScript("OnLeave", function()
        setVisual("idle")
    end)
    button:SetScript("OnMouseDown", function()
        setVisual("down")
    end)
    button:SetScript("OnMouseUp", function(selfBtn)
        if selfBtn:IsMouseOver() then
            setVisual("hover")
        else
            setVisual("idle")
        end
    end)

    return button
end

local function createBlizzardCompatibilityStubPanel(sectionKey, name)
    local panel = CreateFrame("Frame")
    panel.name = name
    panel._compatStubSectionKey = sectionKey

    panel.EnsureBuilt = function(self)
        if self._initialized then
            return
        end
        self._initialized = true

        local widgets = {}
        self._compatStubWidgets = widgets

        widgets.group = CreateFrame("Frame", nil, self)

        widgets.banner = widgets.group:CreateTexture(nil, "ARTWORK")
        widgets.banner:SetTexture("Interface\\AddOns\\PortalAuthority\\Media\\Images\\01.PA_banner_wow_1024x256_centered.png")
        widgets.banner:SetTexCoord(0, 1, 0, 1)

        widgets.button = createPortalAuthorityCompatStubButton(widgets.group, "Open Settings")
        widgets.button:SetScript("OnClick", function()
            if not PortalAuthority or type(PortalAuthority.OpenSettingsWindowFromBlizzardStub) ~= "function" then
                printPortalAuthorityCompatMessage("Settings window is unavailable.")
                return
            end

            local ok, err = PortalAuthority:OpenSettingsWindowFromBlizzardStub(self._compatStubSectionKey)
            if not ok and err then
                printPortalAuthorityCompatMessage(err)
            end
        end)

        self._layout = function(frame)
            local stub = frame and frame._compatStubWidgets or nil
            if not stub then
                return
            end

            local panelWidth = tonumber(frame:GetWidth()) or 0
            if panelWidth <= 1 and frame.GetParent then
                local parent = frame:GetParent()
                panelWidth = parent and tonumber(parent:GetWidth()) or 0
            end

            local bannerWidth = math.min(480, math.max(1, panelWidth - 64))
            local bannerHeight = math.max(1, math.floor((bannerWidth / 4) + 0.5))
            local buttonWidth = math.max(156, math.ceil((stub.button._text:GetStringWidth() or 0) + 28))
            local buttonHeight = 36
            local groupWidth = math.max(bannerWidth, buttonWidth)
            local groupHeight = bannerHeight + 18 + buttonHeight

            stub.group:SetSize(groupWidth, groupHeight)
            stub.group:ClearAllPoints()
            stub.group:SetPoint("CENTER", frame, "CENTER", 0, 0)

            stub.banner:SetSize(bannerWidth, bannerHeight)
            stub.banner:ClearAllPoints()
            stub.banner:SetPoint("TOP", stub.group, "TOP", 0, 0)

            stub.button:SetSize(buttonWidth, buttonHeight)
            stub.button:ClearAllPoints()
            stub.button:SetPoint("TOP", stub.banner, "BOTTOM", 0, -18)
        end

        self._refresh = function(frame)
            if frame and frame._layout then
                frame._layout(frame)
            end
        end
    end

    panel:SetScript("OnShow", function(self)
        self:EnsureBuilt()
        if self._refresh then
            self._refresh(self)
        end
    end)

    panel:SetScript("OnSizeChanged", function(self)
        if self._initialized and self._layout then
            self._layout(self)
        end
    end)

    return panel
end

local root = CreateFrame("Frame")
root.name = "Portal Authority"
debugSettingsLog("create frame:", root.name)
root.EnsureBuilt = function(self)
    debugSettingsLog("EnsureBuilt:", self.name, "initialized=", self._initialized and "true" or "false")
    if self._initialized then return end
    self._initialized = true
    resetSettingsFirstOpenPanelState(self)
    ensureDatabase()
    self._sizingFrame = self

    local widgets = {}
    self._landingWidgets = widgets

    local PORTAL_AUTHORITY_LANDING_PERCEPTUAL_CENTER_RATIO = 0.45
    local PORTAL_AUTHORITY_LANDING_MIN_TOP_INSET = 20

    local function getPortalAuthorityLandingElementHeight(element, fallback)
        fallback = math.max(0, tonumber(fallback) or 0)
        if not element then
            return fallback
        end

        local objectType = element.GetObjectType and element:GetObjectType() or nil
        if objectType == "FontString" and element.GetStringHeight then
            local stringHeight = tonumber(element:GetStringHeight()) or 0
            if stringHeight > 0 then
                return math.max(fallback, math.ceil(stringHeight))
            end
        end

        local height = tonumber(element.GetHeight and element:GetHeight()) or 0
        if height > 0 then
            return math.max(fallback, math.ceil(height))
        end

        return fallback
    end

    local function getPortalAuthorityLandingGroupTopOffset(panel, items)
        if type(items) ~= "table" or #items <= 0 then
            return -PORTAL_AUTHORITY_LANDING_MIN_TOP_INSET
        end

        local groupHeight = 0
        for i = 1, #items do
            local item = items[i]
            if type(item) == "table" then
                groupHeight = groupHeight + getPortalAuthorityLandingElementHeight(item.ref, item.fallback)
                groupHeight = groupHeight + math.max(0, tonumber(item.gapAfter) or 0)
            end
        end

        if groupHeight <= 0 then
            return -PORTAL_AUTHORITY_LANDING_MIN_TOP_INSET
        end

        local panelHeight = tonumber(panel and panel.GetHeight and panel:GetHeight()) or 0
        if panelHeight <= 1 then
            return -PORTAL_AUTHORITY_LANDING_MIN_TOP_INSET
        end

        local topInset = (panelHeight * PORTAL_AUTHORITY_LANDING_PERCEPTUAL_CENTER_RATIO) - (groupHeight * 0.5)
        topInset = math.max(PORTAL_AUTHORITY_LANDING_MIN_TOP_INSET, topInset)
        return -math.floor(topInset + 0.5)
    end

    if isOnboardingD3GateEnabled() then
        widgets.banner = self:CreateTexture(nil, "ARTWORK")
        widgets.banner:SetTexture("Interface\\AddOns\\PortalAuthority\\Media\\Images\\01.PA_banner_wow_1024x256_centered.png")
        widgets.banner:SetTexCoord(0, 1, 0, 1)
        widgets.banner:SetSize(460, 115)

        widgets.separator1 = createPortalAuthorityLandingDivider(self, 80)

        widgets.dedicatedLabel = createPortalAuthorityPremiumStyledFontString(self, "ARTWORK", "GameFontNormalSmall", 12)
        widgets.dedicatedLabel:SetText("DEDICATED TO")
        widgets.dedicatedLabel:SetTextColor(1.0, 0.82, 0.0, 1.0)

        widgets.characterName = createPortalAuthorityPremiumRawFontString(self, "ARTWORK", "GameFontHighlight", 15)
        widgets.characterName:SetText("|cFF33937FImbabyuwu|r|cFF555555-Illidan|r")

        widgets.alias = createPortalAuthorityPremiumStyledFontString(self, "ARTWORK", "GameFontHighlightSmall", 12)
        widgets.alias:SetText("Navarone")
        widgets.alias:SetTextColor(0.54, 0.54, 0.56, 1.0)

        widgets.separator2 = createPortalAuthorityLandingDivider(self, 40)

        widgets.inspiredLabel = createPortalAuthorityPremiumStyledFontString(self, "ARTWORK", "GameFontNormalSmall", 12)
        widgets.inspiredLabel:SetText("INSPIRED BY")
        widgets.inspiredLabel:SetTextColor(1.0, 0.82, 0.0, 1.0)

        widgets.guildRow = CreateFrame("Button", nil, self)
        widgets.guildRow:SetSize(1, 28)
        widgets.guildRow:SetHitRectInsets(-8, -8, -4, -4)

        widgets.guildLogo = widgets.guildRow:CreateTexture(nil, "ARTWORK")
        widgets.guildLogo:SetTexture("Interface\\AddOns\\PortalAuthority\\Media\\Images\\overclock_logo_wow_64x64.png")
        widgets.guildLogo:SetTexCoord(0, 1, 0, 1)
        widgets.guildLogo:SetSize(28, 28)

        widgets.guildName = createPortalAuthorityPremiumStyledFontString(widgets.guildRow, "ARTWORK", "GameFontHighlight", 15, "LEFT")
        widgets.guildName:SetText("Overclock")
        widgets.guildName:SetTextColor(1.0, 1.0, 1.0, 1.0)

        widgets.separator3 = createPortalAuthorityLandingDivider(self, 40)

        widgets.author = createPortalAuthorityPremiumRawFontString(self, "ARTWORK", "GameFontNormal", 12)
        widgets.author:SetText("|cFF999999by |r|cFF3FC7EBStormyeyes|r|cFF555555-Mal'Ganis|r")

        widgets.version = createPortalAuthorityPremiumStyledFontString(self, "ARTWORK", "GameFontHighlightSmall", 11)
        widgets.version:SetTextColor(0.34, 0.34, 0.36, 1.0)

        widgets.showMeAround = CreateFrame("Button", nil, self)
