    self._refresh()
end

local function ensureRootPanelAnchored(self)
    local parent = self and self:GetParent() or nil
    if not parent then
        return false
    end
    if self._paAnchorParent ~= parent or not self._paAnchored then
        self:ClearAllPoints()
        self:SetAllPoints(parent)
        self._paAnchorParent = parent
    end
    self._paAnchored = true
    return true
end

root:SetScript("OnShow", function(self)
    debugSettingsLog("OnShow:", self.name)
    ensureRootPanelAnchored(self)
    self:EnsureBuilt()
    if not handleSettingsFirstOpenPanelShow(self) then
        withPanelHydration(self, function()
            if self._refresh then
                self._refresh()
            elseif self._layout then
                self._layout()
            end
        end)
    end
end)

root:HookScript("OnHide", function(self)
    handleSettingsFirstOpenPanelHide(self)
end)

