local function initializeDeferredSettingsPanelHidden(panel)
    if not panel or not panel.Hide or not panel.IsShown then
        return
    end
    if panel:IsShown() then
        panel:Hide()
    end
end

-- These panels were being created in the shown state, which means their first
-- real selection never produced an OnShow transition. Starting them hidden
-- makes first selection own the initial build/show path instead of relying on
-- later click-away/click-back or background priming.
local rootCategory = Settings.RegisterCanvasLayoutCategory(rootCategoryPanel, root.name, root.name)
Settings.RegisterAddOnCategory(rootCategory)
debugSettingsLog("register category:", root.name, "id=", rootCategory and rootCategory.GetID and rootCategory:GetID() or "nil")

initializeDeferredSettingsPanelHidden(root)
initializeDeferredSettingsPanelHidden(announcementsPanel)
initializeDeferredSettingsPanelHidden(dockPanel)
initializeDeferredSettingsPanelHidden(timersPanel)
initializeDeferredSettingsPanelHidden(interruptTrackerPanel)
initializeDeferredSettingsPanelHidden(combatAlertsPanel)
initializeDeferredSettingsPanelHidden(profilesPanel)

-- Direct settings panels now build on demand when opened for the first time.

local function bootstrapKeystoneUtilityPanelBuild(attempt)
    if not keystoneUtilityPanel then
        return
    end
    if keystoneUtilityPanel._initialized and keystoneUtilityPanel._layout and keystoneUtilityPanel._refresh and keystoneUtilityPanel._fullRefresh then
        return
    end

    ensureDatabase()
    if PortalAuthorityDB then
        keystoneUtilityPanel:EnsureBuilt()
        if keystoneUtilityPanel._fullRefresh then
            keystoneUtilityPanel._fullRefresh("bootstrap-eager")
        end
        return
    end

    local n = tonumber(attempt) or 0
    if n >= 180 then
        return
    end
    if C_Timer and C_Timer.After then
        C_Timer.After(0, function()
            bootstrapKeystoneUtilityPanelBuild(n + 1)
        end)
    end
end

if PortalAuthority and PortalAuthority.SetSettingsKeystoneBootstrapState then
    if settingsEagerBuildGateEnabled then
        PortalAuthority:SetSettingsKeystoneBootstrapState("suppressed")
    else
        PortalAuthority:SetSettingsKeystoneBootstrapState("unknown")
    end
end

if settingsEagerBuildGateEnabled then
    -- The eager-build gate suppresses the delayed bootstrap kickoff entirely.
elseif C_Timer and C_Timer.After then
    if PortalAuthority and PortalAuthority.SetSettingsKeystoneBootstrapState then
        PortalAuthority:SetSettingsKeystoneBootstrapState("scheduled")
    end
    C_Timer.After(0, function()
        if PortalAuthority and PortalAuthority.SetSettingsKeystoneBootstrapState then
            PortalAuthority:SetSettingsKeystoneBootstrapState("ran")
        end
        bootstrapKeystoneUtilityPanelBuild(0)
    end)
end

